#!/bin/bash
sh_v="1.6.4.1"

list_color_init() {
    export gl_hui=$'\033[38;5;59m'   # 灰色
    export gl_hong=$'\033[38;5;9m'   # 红色
    export gl_lv=$'\033[38;5;10m'    # 绿色
    export gl_huang=$'\033[38;5;11m' # 黄色
    export gl_lan=$'\033[38;5;32m'   # 蓝色
    export gl_bai=$'\033[38;5;15m'   # 白色
    export gl_zi=$'\033[38;5;13m'    # 紫色
    export gl_bufan=$'\033[38;5;14m' # 亮青色
    export reset=$'\033[0m'          # 重置
}
list_color_init

log_info() { echo -e "${gl_lan}[信息]${gl_bai} $*"; }
log_ok() { echo -e "${gl_lv}[成功]${gl_bai} $*"; }
log_warn() { echo -e "${gl_huang}[警告]${gl_bai} $*"; }
log_error() { echo -e "${gl_hong}[错误]${gl_bai} $*" >&2; }

sleep_fractional() {
    local seconds=$1
    if sleep "$seconds" 2>/dev/null; then return 0; fi
    if command -v perl >/dev/null 2>&1; then perl -e "select(undef, undef, undef, $seconds)"; return 0; fi
    if command -v python3 >/dev/null 2>&1; then python3 -c "import time; time.sleep($seconds)"; return 0; fi
    if command -v python >/dev/null 2>&1; then python -c "import time; time.sleep($seconds)"; return 0; fi
    local int_seconds=$(echo "$seconds" | awk '{print int($1+0.999)}')
    sleep "$int_seconds"
}

###### 退出动画函数
exit_animation() {
    echo -ne "${gl_lv}即将退出 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.5
    echo -ne "${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.6
    echo ""
}

###### 按任意键继续...
break_end() {
    echo -e "${gl_lv}操作完成${gl_bai}"
    echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    read -r -n 1 -s -r -p ""
    echo ""
    clear
}

###### 无效的输入,请重新输入!
handle_invalid_input() {
    echo -ne "\r${gl_hong}无效的输入，请重新输入 ${gl_zi} 2 ${gl_hong}秒后返回 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.3
    echo -ne "\r${gl_huang}无效的输入，请重新输入 ${gl_zi} 1 ${gl_huang}秒后返回 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.3
    echo -e "\r${gl_lv}无效的输入，请重新输入 ${gl_zi} 0 ${gl_lv}秒后返回 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.6
    return 2 # 2 表示“输入非法”
}

###### 无效的输入,请输入(y或N)。
handle_y_n() {
    echo -ne "\r${gl_hong}无效的选择，请输入 ${gl_bai}(${gl_lv}y${gl_bai}或${gl_hong}N${gl_bai}) ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.3
    echo -ne "\r${gl_huang}无效的选择，请输入 ${gl_bai}(${gl_lv}y${gl_bai}或${gl_hong}N${gl_bai}) ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.3
    echo -ne "\r${gl_lv}无效的选择，请输入 ${gl_bai}(${gl_lv}y${gl_bai}或${gl_hong}N${gl_bai}) ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.6
    return 2 # 2 表示“输入非法”
}

###### 退出脚本
exit_script() {
    echo ""
    echo -ne "${gl_hong}感谢使用，再见！${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.5
    echo -ne "${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.6
    clear
    exit 0
}

###### 空输入提示
cancel_empty() {
    local menu_name="${1:-上一级选单}"
    echo -e "${gl_hong}空输入，返回 ${gl_huang}${menu_name} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.5
    echo -ne "${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.6
    echo ""
    clear
}

###### 输入0返回提示
cancel_return() {
    local menu_name="${1:-上一级选单}"
    echo -ne "${gl_lv}即将返回 ${gl_huang}${menu_name} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.5
    echo -ne "${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.6
    echo ""
    clear
}

################################### 列表美化 ########################################

###### 列表公用颜色变量
list_color_init() {
    export gl_hui=$'\033[38;5;59m'
    export gl_hong=$'\033[38;5;9m'
    export gl_lv=$'\033[38;5;10m'
    export gl_huang=$'\033[38;5;11m'
    export gl_lan=$'\033[38;5;32m'
    export gl_bai=$'\033[38;5;15m'
    export gl_zi=$'\033[38;5;13m'
    export gl_bufan=$'\033[38;5;14m'
    export reset=$'\033[0m'
}
list_color_init

###### 用于替代 column 命令的函数
column_if_available() {
    # 检查系统是否存在 column 命令
    if command -v column &> /dev/null; then
        # 如果存在，正常使用
        column -t -s $'\t'
    else
        # 如果不存在，直接输出（不对齐），避免报错
        cat
    fi
}

###### 美化端口占用状态列表
list_beautify_lsof_listen() {
    {
        # 表头（中文）
        printf "%s%-20s\t%-8s\t%-12s\t%-6s\t%-6s\t%-12s\t%-8s\t%-6s\t%-30s%s\n" \
            "$gl_hui" "程序名" "PID" "用户" "FD" "类型" "设备" "大小" "节点" "监听地址" "$reset"
        printf "%s%-20s\t%-8s\t%-12s\t%-6s\t%-6s\t%-12s\t%-8s\t%-6s\t%-30s%s\n" \
            "$gl_hui" "--------------------" "--------" "------------" "------" "------" "------------" "--------" "------" "------------------------------" "$reset"

        # 执行 lsof，过滤 LISTEN，去重（保留首次出现）
        lsof -i -P -n 2>/dev/null | awk '
        /LISTEN/ && !seen[$0]++ {
            command = $1
            pid = $2
            user = $3
            fd = $4
            type = $5
            device = $6
            size = $7
            node = $8
            name = substr($0, index($0, $9))
            print command, pid, user, fd, type, device, size, node, name
        }' | awk -v green="$gl_lv" -v yellow="$gl_huang" -v blue="$gl_lan" -v cyan="$gl_bufan" \
            -v purple="$gl_zi" -v gray="$gl_hui" -v white="$gl_bai" -v reset="$reset" '
        BEGIN {FS=" "; OFS="\t"}
        {
            print green $1 reset,
                  yellow $2 reset,
                  blue $3 reset,
                  cyan $4 reset,
                  purple $5 reset,
                  gray $6 reset,
                  gray $7 reset,
                  gray $8 reset,
                  white $9 reset
        }'
    } | column_if_available
}

###### 美化 CPU 详细信息列表
list_beautify_cpu_info() {
    {
        # 获取 lscpu 输出
        lscpu_output=$(lscpu)
        
        # 提取函数
        extract_value() {
            local key="$1"
            echo "$lscpu_output" | grep -i "$key" | sed 's/^[^:]*:[[:space:]]*//' | head -1
        }
        
        # 获取所有信息
        architecture=$(extract_value "架构\|Architecture")
        cpu_op_modes=$(extract_value "CPU 操作模式\|CPU op-mode")
        byte_order=$(extract_value "字节序\|Byte Order")
        address_sizes=$(extract_value "地址大小\|Address sizes")
        vendor_id=$(extract_value "Vendor ID\|制造厂商")
        model_name=$(extract_value "型号名称\|Model name")
        cpu_family=$(extract_value "CPU 系列\|CPU family")
        model=$(extract_value "型号\|Model")
        stepping=$(extract_value "步进\|Stepping")
        cpu_mhz=$(extract_value "CPU MHz")
        cpu_max_mhz=$(extract_value "CPU max MHz")
        cpu_min_mhz=$(extract_value "CPU min MHz")
        bogomips=$(extract_value "BogoMIPS")
        l1d_cache=$(extract_value "L1d cache")
        l1i_cache=$(extract_value "L1i cache")
        l2_cache=$(extract_value "L2 cache")
        l3_cache=$(extract_value "L3 cache")
        sockets=$(extract_value "Socket(s)")
        cores_per_socket=$(extract_value "Core(s) per socket")
        threads_per_core=$(extract_value "Thread(s) per core")
        cpu_total=$(extract_value "^CPU(s):")
        virtualization=$(extract_value "Virtualization\|虚拟化")
        numa_nodes=$(extract_value "NUMA node(s)")
        
        # 美化表格显示函数
        show_row() {
            local label="$1"
            local value="$2"
            local value_color="$3"
            
            if [ -n "$value" ]; then
                printf "%s%s\t%s%s%s\n" "$gl_lan" "$label" "$reset" "$value_color" "$value"
            fi
        }
        
        # 表头
        printf "%s%s\t%s%s\n" "$gl_hui" "CPU 信息" "值" "$reset"
        printf "%s%s\t%s%s\n" "$gl_hui" "----------------" "-----------------------------------------" "$reset"
        printf "\n"
        
        # 显示所有信息
        show_row "架构" "$architecture" "$gl_huang"
        show_row "CPU 操作模式" "$cpu_op_modes" "$gl_bufan"
        show_row "字节序" "$byte_order" "$gl_lv"
        show_row "地址大小" "$address_sizes" "$gl_bufan"
        
        printf "\n"
        
        show_row "制造商" "$vendor_id" "$gl_lv"
        show_row "型号名称" "$model_name" "$gl_huang"
        show_row "CPU 系列" "$cpu_family" "$gl_bufan"
        show_row "型号" "$model" "$gl_zi"
        show_row "步进" "$stepping" "$gl_bufan"
        
        printf "\n"
        
        if [ -n "$cpu_mhz" ]; then
            show_row "CPU 频率" "${cpu_mhz} MHz" "$gl_hong"
        fi
        if [ -n "$cpu_max_mhz" ]; then
            show_row "最大频率" "${cpu_max_mhz} MHz" "$gl_huang"
        fi
        if [ -n "$cpu_min_mhz" ]; then
            show_row "最小频率" "${cpu_min_mhz} MHz" "$gl_lv"
        fi
        if [ -n "$bogomips" ]; then
            show_row "BogoMIPS" "$bogomips" "$gl_bufan"
        fi
        
        printf "\n"
        
        if [ -n "$l1d_cache" ]; then
            show_row "L1d 缓存" "$l1d_cache" "$gl_bufan"
        fi
        if [ -n "$l1i_cache" ]; then
            show_row "L1i 缓存" "$l1i_cache" "$gl_bufan"
        fi
        if [ -n "$l2_cache" ]; then
            show_row "L2 缓存" "$l2_cache" "$gl_huang"
        fi
        if [ -n "$l3_cache" ]; then
            show_row "L3 缓存" "$l3_cache" "$gl_zi"
        fi
        
        printf "\n"
        
        if [ -n "$cpu_total" ]; then
            show_row "逻辑处理器数" "$cpu_total" "$gl_hong"
        fi
        if [ -n "$sockets" ] && [ -n "$cores_per_socket" ]; then
            total_cores=$((sockets * cores_per_socket))
            show_row "物理核心数" "$total_cores" "$gl_huang"
        fi
        if [ -n "$sockets" ]; then
            show_row "插槽数" "$sockets" "$gl_bufan"
        fi
        if [ -n "$cores_per_socket" ]; then
            show_row "每插槽核心数" "$cores_per_socket" "$gl_huang"
        fi
        if [ -n "$threads_per_core" ]; then
            show_row "每核心线程数" "$threads_per_core" "$gl_lv"
        fi
        
        printf "\n"
        
        if [ -n "$virtualization" ]; then
            show_row "虚拟化" "$virtualization" "$gl_lv"
        fi
        if [ -n "$numa_nodes" ]; then
            show_row "NUMA 节点数" "$numa_nodes" "$gl_huang"
        fi
        
    } | column_if_available
}


###### Docker 镜像列表
list_beautify_docker_images() {
    {
        # 表头
        printf "%s%s\t%s\t%s\t%s\t%s%s\n" "$gl_hui" "仓库" "标签" "镜像ID" "创建时间" "大小" "$reset"
        # 分割线
        printf "%s%s\t%s\t%s\t%s\t%s%s\n" "$gl_hui" "----------" "----------" "----------" "----------" "----------" "$reset"
        
        # 镜像数据
        docker image ls --format "{{.Repository}}\t{{.Tag}}\t{{.ID}}\t{{.CreatedSince}}\t{{.Size}}" | \
        awk -v green="$gl_lv" -v yellow="$gl_huang" -v cyan="$gl_bufan" -v blue="$gl_lan" -v white="$gl_bai" -v reset="$reset" '
        BEGIN {FS="\t"; OFS="\t"}
        {
            id = substr($3, 1, 12)
            time = $4
            gsub(/ years ago/, "年前", time)
            gsub(/ year ago/, "年前", time)
            gsub(/ months ago/, "个月前", time)
            gsub(/ month ago/, "个月前", time)
            gsub(/ weeks ago/, "周前", time)
            gsub(/ week ago/, "周前", time)
            gsub(/ days ago/, "天前", time)
            gsub(/ day ago/, "天前", time)
            gsub(/ hours ago/, "小时前", time)
            gsub(/ hour ago/, "小时前", time)
            gsub(/ minutes ago/, "分钟前", time)
            gsub(/ minute ago/, "分钟前", time)
            gsub(/ seconds ago/, "秒前", time)
            gsub(/ second ago/, "秒前", time)
            gsub(/About /, "", time)
            
            print green $1 reset, yellow $2 reset, cyan id reset, blue time reset, white $5 reset
        }'
    } | column_if_available
}

###### 美化SSH配置列表
list_beautify_sshd_config() {
    {
        grep -vE '^#|^$' /etc/ssh/sshd_config | awk -v gray="$gl_hui" -v green="$gl_lv" \
            -v yellow="$gl_huang" -v blue="$gl_lan" -v purple="$gl_zi" -v reset="$reset" '
        BEGIN {
            info["Port"] = "SSH服务端口"
            info["ListenAddress"] = "监听IP地址"
            info["Protocol"] = "SSH协议版本"
            info["HostKey"] = "主机密钥文件路径"
            info["PermitRootLogin"] = "是否允许root登录"
            info["PasswordAuthentication"] = "是否开启密码认证"
            info["PubkeyAuthentication"] = "是否开启公钥认证"
            info["AuthorizedKeysFile"] = "公钥授权文件位置"
            info["Subsystem"] = "系统子服务（一般为SFTP）"
            info["UsePAM"] = "是否启用PAM认证"
            info["X11Forwarding"] = "是否开启图形界面转发"
            info["PrintMotd"] = "登录是否显示提示信息"
            info["ClientAliveInterval"] = "客户端心跳检测间隔(秒)"
            info["ClientAliveCountMax"] = "客户端最大心跳超时次数"
            info["AllowUsers"] = "允许登录的用户列表"
            info["DenyUsers"] = "禁止登录的用户列表"
            info["AllowGroups"] = "允许登录的用户组"
            info["DenyGroups"] = "禁止登录的用户组"
            info["ChallengeResponseAuthentication"] = "挑战响应式认证"
            info["GSSAPIAuthentication"] = "GSSAPI统一认证"
            info["KerberosAuthentication"] = "Kerberos票据认证"
            info["LogLevel"] = "日志记录级别"
            info["MaxAuthTries"] = "最大密码错误次数"
            info["MaxSessions"] = "最大同时连接会话数"
            info["TCPKeepAlive"] = "是否开启TCP连接保活"
            info["PermitEmptyPasswords"] = "是否允许空密码登录"
            info["StrictModes"] = "是否开启权限严格检查"
            info["AcceptEnv"] = "允许接收的客户端环境变量"
            info["Ciphers"] = "SSH加密算法套件"
            info["MACs"] = "消息校验算法"
            info["KexAlgorithms"] = "密钥交换算法"
            info["Match"] = "条件匹配规则配置"

            print gray "配置项名称\t参数值\t中文说明" reset
            print gray "----------\t--------\t-------------------------" reset
        }
        {
            key = $1
            val = substr($0, index($0, $2))
            gsub(/^[ \t]+|[ \t]+$/, "", val)

            if (key == "Port" || key == "ListenAddress") color = purple
            else color = green

            desc = (key in info) ? info[key] : "其他SSH配置项"

            print color key "\t" yellow val "\t" blue desc reset
        }' | column_if_available
    }
}

###### 美化Linux最近系统日志
list_beautify_journal_log() {
    {
        LINE=${1:-50}

        journalctl -n $LINE --no-pager 2>/dev/null | awk -v gray="$gl_hui" -v green="$gl_lv" \
        -v yellow="$gl_huang" -v purple="$gl_zi" -v red="$gl_hong" -v reset="$reset" '
        BEGIN {
            OFS = "\t"
            print gray "时间\t主机名\t服务进程\t日志信息" reset
            print gray "----------\t----------\t----------\t----------------------------------------" reset
        }
        /^$/ { next }
        {
            time = $1 " " $2 " " $3
            host = $4
            service = $5
            gsub(/:$/, "", service)
            msg = substr($0, index($0, $6))

            color = yellow
            if (msg ~ /error|Error|ERROR|fail|Fail|FAIL|warning|Warning|WARNING/) color = red

            print gray time reset, purple host reset, green service reset, color msg reset
        }' | column_if_available
    }
}

###### Docker磁盘使用列表
list_beautify_docker_system() {
    {
        docker system df | awk -v gray="$gl_hui" -v green="$gl_lv" -v yellow="$gl_huang" \
            -v blue="$gl_lan" -v cyan="$gl_bufan" -v reset="$reset" '
        BEGIN {
            print gray "类型\t总数\t活跃\t大小\t可回收" reset
            print gray "----------\t--------\t--------\t----------\t----------" reset
        }
        NR > 1 {
            type = $1
            total = $2
            active = $3
            size = $4
            reclaim = $5
            if (type == "Local") {
                type = $1 " " $2
                total = $3
                active = $4
                size = $5
                reclaim = $6
            }
            if (type == "Images") color = green
            else if (type == "Containers") color = yellow
            else if (type == "Local Volumes") color = blue
            else if (type == "Build Cache") color = cyan
            else color = reset
            print color type "\t" total "\t" active "\t" size "\t" reclaim reset
        }' | column_if_available
    }
}

###### 美化iptables中INPUT链规则列表（最终完美对齐版）
list_beautify_iptables_input() {
    local chain="${1:-INPUT}"
    if ! iptables -L "$chain" -n --line-numbers &>/dev/null; then
        echo -e "\033[1;31m错误: 需要 root 权限或链 $chain 不存在\033[0m" >&2
        return 1
    fi
    local policy_line policy policy_display policy_color
    policy_line=$(iptables -L "$chain" -n 2>/dev/null | head -n1)
    if [[ "$policy_line" =~ \(policy\ ([A-Z]+)\) ]]; then
        policy="${BASH_REMATCH[1]}"
    else
        policy="自定义"
    fi
    case "$policy" in
        ACCEPT) policy_display="允许"; policy_color="\033[1;32m" ;;
        DROP)   policy_display="丢弃"; policy_color="\033[1;31m" ;;
        REJECT) policy_display="拒绝"; policy_color="\033[1;31m" ;;
        自定义) policy_display="自定义"; policy_color="\033[1;33m" ;;
        *)      policy_display="$policy"; policy_color="\033[1;33m" ;;
    esac
    echo -e "\033[1;34m链: $chain\033[0m  策略: ${policy_color}${policy_display}\033[0m\n"

    iptables -L "$chain" -n --line-numbers 2>/dev/null | awk -v green="\033[1;32m" -v red="\033[1;31m" -v yellow="\033[1;33m" -v cyan="\033[1;36m" -v blue="\033[1;34m" -v reset="\033[0m" '
    /^[0-9]/ {
        num = $1; target = $2; prot = $3; source = $5; dest = $6
        port_info = ""
        for (i=7; i<=NF; i++) {
            if ($i ~ /^dpt:/) { port_info = $i; break }
            else if ($i ~ /^spt:/) { port_info = $i; break }
            else if ($i ~ /^multiport/) { port_info = $i; break }
        }
        if (port_info ~ /^dpt:/) port = "→" substr(port_info,4)
        else if (port_info ~ /^spt:/) port = "←" substr(port_info,4)
        else if (port_info ~ /^multiport/) port = "多端口"
        else port = ""

        if (target == "ACCEPT") { t = "允许"; c = green }
        else if (target == "DROP") { t = "丢弃"; c = red }
        else if (target == "REJECT") { t = "拒绝"; c = red }
        else if (target ~ /^f2b-/) { t = "⛓封禁(" substr(target,5) ")"; c = red }
        else { t = target; c = yellow }

        if (prot == "tcp") proto = "TCP"
        else if (prot == "udp") proto = "UDP"
        else if (prot == "all") proto = "全部"
        else proto = prot

        s = (source == "0.0.0.0/0") ? "任意" : source
        d = (dest == "0.0.0.0/0") ? "任意" : dest

        printf "%s%2d%s|%s%-14s%s|%s%-6s%s|%s%-18s%s|%s%-18s%s|%s%-10s%s\n",
            yellow, num, reset,
            c, t, reset,
            cyan, proto, reset,
            blue, s, reset,
            blue, d, reset,
            yellow, port, reset
    }' | sed 's/|/\t/g' | column_if_available
}

###### 美化iptables所有规则列表
list_beautify_iptables_all() {
    {
        if ! iptables -L -n --line-numbers &>/dev/null; then
            echo -e "${gl_hong}错误: 需要 root 权限运行 iptables${reset}"
            return 1
        fi
        
        output=$(iptables -L -n --line-numbers 2>/dev/null)
        if [ -z "$output" ]; then
            echo -e "${gl_huang}iptables 规则为空${reset}"
            return 0
        fi
        
        echo "$output" | awk -v green="$gl_lv" -v red="$gl_hong" -v yellow="$gl_huang" \
            -v cyan="$gl_bufan" -v blue="$gl_lan" -v reset="$reset" '
        /^Chain / {
            chain = $2
            policy = ""
            for (i=4; i<=NF; i++) {
                if ($i == "(policy") {
                    policy = $(i+1)
                    gsub(/[()]/, "", policy)
                    break
                }
            }
            if (policy == "") {
                for (i=4; i<=NF; i++) {
                    if ($i == "references" || $i ~ /^[0-9]+$/) {
                        policy = "自定义"
                        break
                    }
                }
            }
            if (chain == "INPUT") {
                chain_display = "入站"
                chain_color = blue
            } else if (chain == "OUTPUT") {
                chain_display = "出站"
                chain_color = blue
            } else if (chain == "FORWARD") {
                chain_display = "转发"
                chain_color = blue
            } else if (chain ~ /^f2b-/) {
                chain_display = "⛓" chain
                chain_color = red
            } else if (chain ~ /^DOCKER/) {
                chain_display = "🐳" chain
                chain_color = cyan
            } else {
                chain_display = "🔗" chain
                chain_color = blue
            }
            if (policy == "ACCEPT") {
                policy_display = "允许"
                policy_color = green
            } else if (policy == "DROP") {
                policy_display = "丢弃"
                policy_color = red
            } else if (policy == "REJECT") {
                policy_display = "拒绝"
                policy_color = red
            } else if (policy == "1" || policy == "references" || policy == "自定义") {
                policy_display = "自定义"
                policy_color = yellow
            } else {
                policy_display = policy
                policy_color = yellow
            }
            printf "%s%s%s  策略: %s%s%s\n\n", chain_color, chain_display, reset, policy_color, policy_display, reset
        }
        
        /^[0-9]/ && NF >= 6 {
            num = $1
            target = $2
            source = $5
            dest = $6
            
            ports = ""
            for (i=7; i<=NF; i++) {
                if ($i ~ /dpt:[0-9]+/) {
                    match($i, /dpt:[0-9]+/)
                    ports = substr($i, RSTART+4, RLENGTH-4)
                    break
                } else if ($i ~ /multiport/) {
                    ports = "多端口"
                    break
                }
            }
            
            if (source == "0.0.0.0/0" && dest == "0.0.0.0/0" && ports == "" && target == "ACCEPT") {
                next
            }
            
            if (target == "ACCEPT") {
                target_display = "✓允许"
                target_color = green
            } else if (target == "DROP") {
                target_display = "✗丢弃"
                target_color = red
            } else if (target == "REJECT") {
                target_display = "✗拒绝"
                target_color = red
            } else if (target == "LOG") {
                target_display = "📋日志"
                target_color = cyan
            } else if (target == "RETURN") {
                target_display = "↩返回"
                target_color = yellow
            } else if (target ~ /DNAT|SNAT|MASQUERADE/) {
                target_display = "↔NAT"
                target_color = cyan
            } else if (target ~ /^f2b-/) {
                target_display = "⛓封禁"
                target_color = red
            } else if (target ~ /^DOCKER-/) {
                target_display = "🐳Docker"
                target_color = cyan
            } else {
                target_display = "•" target
                target_color = yellow
            }
            
            if (source == "0.0.0.0/0") source = ""
            if (dest == "0.0.0.0/0") dest = ""
            if (source != "" && dest != "") {
                addr = source "→" dest
            } else if (source != "") {
                addr = source
            } else if (dest != "") {
                addr = "→" dest
            } else {
                addr = ""
            }
            
            if (ports != "") {
                ports_display = "端口:" ports
            } else {
                ports_display = ""
            }
            
            printf "  %s%2s%s\t", yellow, num, reset
            printf "%s%-8s%s\t", target_color, target_display, reset
            printf "%s%s%s\t", cyan, addr, reset
            if (ports_display != "") {
                printf "%s%s%s", yellow, ports_display, reset
            } else {
                printf "%s", reset
            }
            printf "\n"
        }'
        
    } | column_if_available
}

