###### 美化Linux用户列表
list_beautify_user_info() {
    {
        printf "%s%-24s\t%-34s\t%-20s\t%-10s%s\n" "$gl_hui" "用户名" "用户权限" "用户组" "sudo权限" "$reset"
        printf "%s%-24s\t%-34s\t%-20s\t%-10s%s\n" "$gl_hui" "------------------------" "----------------------------------" "--------------------" "----------" "$reset"

        while IFS=: read -r username _ _ _ _ homedir shell; do
            groups_info=$(groups "$username" 2>/dev/null | cut -d: -f2- | sed 's/^ //')
            [ -z "$groups_info" ] && groups_info="(无组信息)"

            sudo_status="No"
            sudo_output=$(sudo -n -lU "$username" 2>/dev/null)
            if [ -n "$sudo_output" ]; then
                if echo "$sudo_output" | grep -qE '\(ALL( : ALL)?\) ALL'; then
                    sudo_status="Yes"
                fi
            fi

            printf "%s\t%s\t%s\t%s\n" "$username" "$homedir" "$groups_info" "$sudo_status"
        done </etc/passwd | awk -v green="$gl_lv" -v yellow="$gl_huang" -v blue="$gl_lan" -v cyan="$gl_bufan" -v reset="$reset" '
        BEGIN {FS="\t"; OFS="\t"}
        {
            print green $1 reset, yellow $2 reset, blue $3 reset, cyan $4 reset
        }'
    } | column_if_available
}

###### 美化 lspci 命令的函数
list_beautify_pci_info() {
    {
        printf "%s%s\t%s\t%s%s\n" "$gl_hui" "总线号" "设备类型" "设备描述" "$reset"
        printf "%s%s\t%s\t%s%s\n" "$gl_hui" "-------" "----------------" "-------------------------------------------" "$reset"
        
        data=$(lspci 2>/dev/null)
        
        if [ -z "$data" ]; then
            printf "%s%s\t%s\t%s%s\n" "$gl_hong" "(错误)" "(错误)" "无法执行 lspci 命令" "$reset"
        else
            total_devices=$(echo "$data" | wc -l)
            
            echo "$data" | while IFS= read -r line; do
                bus_id=$(echo "$line" | cut -d' ' -f1)
                device_desc=$(echo "$line" | cut -d' ' -f2-)
                
                device_type=$(echo "$device_desc" | cut -d: -f1)
                device_detail=$(echo "$device_desc" | cut -d: -f2- | sed 's/^ //')
                
                if [ -z "$device_detail" ]; then
                    device_detail="$device_desc"
                    device_type="未知"
                fi
                
                case "$device_type" in
                    "Host bridge"|"主机桥")
                        type_color=$gl_lan
                        type_display="${type_color}主机桥$reset"
                        ;;
                    "VGA compatible controller"|"VGA兼容控制器")
                        type_color=$gl_zi
                        type_display="${type_color}VGA控制器$reset"
                        ;;
                    "Ethernet controller"|"以太网控制器")
                        type_color=$gl_lv
                        type_display="${type_color}以太网卡$reset"
                        ;;
                    "Network controller"|"网络控制器")
                        type_color=$gl_bufan
                        type_display="${type_color}网络控制器$reset"
                        ;;
                    "USB controller"|"USB控制器")
                        type_color=$gl_huang
                        type_display="${type_color}USB控制器$reset"
                        ;;
                    "SATA controller"|"SATA控制器")
                        type_color=$gl_hong
                        type_display="${type_color}SATA控制器$reset"
                        ;;
                    "Audio device"|"音频设备")
                        type_color=$gl_bufan
                        type_display="${type_color}音频设备$reset"
                        ;;
                    "PCI bridge"|"PCI桥")
                        type_color=$gl_hui
                        type_display="${type_color}PCI桥$reset"
                        ;;
                    "Non-Volatile memory controller"|"非易失性内存控制器")
                        type_color=$gl_hong
                        type_display="${type_color}NVMe控制器$reset"
                        ;;
                    "SCSI storage controller"|"SCSI存储控制器")
                        type_color=$gl_zi
                        type_display="${type_color}SCSI控制器$reset"
                        ;;
                    "SMBus"|"系统管理总线")
                        type_color=$gl_hui
                        type_display="${type_color}系统管理总线$reset"
                        ;;
                    "Communication controller"|"通信控制器")
                        type_color=$gl_bufan
                        type_display="${type_color}通信控制器$reset"
                        ;;
                    *)
                        type_color=$gl_huang
                        type_display="${type_color}$device_type$reset"
                        ;;
                esac
                
                if [ ${#device_detail} -gt 50 ]; then
                    device_detail="${device_detail:0:47}..."
                fi
                
                printf "%s%s%s\t%s\t%s%s%s\n" \
                    "$gl_lan" "$bus_id" "$reset" \
                    "$type_display" \
                    "$type_color" "$device_detail" "$reset"
            done
            
            printf "\n"
            printf "%sPCI设备%s%s%s个%s\n" "$gl_hui" "$gl_lv" "$total_devices" "$gl_hui" "$reset"
        fi
        
    } | column_if_available
}

###### 美化登录日志 last -n 10（中文彩色 + 严格对齐）
list_beautify_login_log() {
    {
        # 中文表头（严格对齐）
        printf "%s%-12s\t%-10s\t%-18s\t%-25s\t%-20s%s\n" \
            "$gl_hui" "用户名" "终端" "来源IP" "登录时间" "状态" "$reset"
        printf "%s%-12s\t%-10s\t%-18s\t%-25s\t%-20s%s\n" \
            "$gl_hui" "------------" "----------" "------------------" "-------------------------" "--------------------" "$reset"

        # 获取 last -n 10 并美化 + 中文翻译
        last -n 10 2>/dev/null | awk '
        NF >= 8 && $1 != "reboot" && $1 != "wtmp" {
            user = $1
            tty  = $2
            from = ($3 ~ /^[0-9]/ || $3 ~ /:/) ? $3 : "本地"
            time = $4" "$5" "$6" "$7
            stat = "已登录"
            if ($0 ~ /still logged in/) stat = "在线中"
            else if ($0 ~ /gone/) stat = "已退出"
            print user, tty, from, time, stat
        }' | awk -v green="$gl_lv" \
            -v yellow="$gl_huang" \
            -v blue="$gl_lan" \
            -v cyan="$gl_bufan" \
            -v purple="$gl_zi" \
            -v gray="$gl_hui" \
            -v white="$gl_bai" \
            -v reset="$reset" '
        BEGIN { FS=" "; OFS="\t" }
        {
            printf "%s%-12s%s\t", green,    $1, reset
            printf "%s%-10s%s\t", yellow,  $2, reset
            printf "%s%-18s%s\t", blue,    $3, reset
            printf "%s%-25s%s\t", cyan,    $4" "$5" "$6" "$7, reset
            printf "%s%-20s%s\n", white,   $8, reset
        }'
    } | column_if_available
}

###### 美化安全日志（支持传统 syslog 和 journald/ISO8601 格式）
list_beautify_secure_log() {
    local log_file=""
    if [ -f /var/log/secure ]; then
        log_file="/var/log/secure"
    elif [ -f /var/log/auth.log ]; then
        log_file="/var/log/auth.log"
    else
        echo -e "${gl_huang}未找到安全日志文件${reset}"
        return 1
    fi

    {
        # 表头（中文）
        printf "%s%-24s\t%-12s\t%-15s\t%-20s\t%-60s%s\n" \
            "$gl_hui" "时间" "主机名" "进程" "事件类型" "详细信息" "$reset"
        printf "%s%-24s\t%-12s\t%-15s\t%-20s\t%-60s%s\n" \
            "$gl_hui" "------------------------" "------------" "---------------" "--------------------" "------------------------------------------------------------" "$reset"

        tail -n 20 "$log_file" 2>/dev/null | awk -v gray="$gl_hui" \
            -v purple="$gl_zi" -v green="$gl_lv" \
            -v yellow="$gl_huang" -v red="$gl_hong" \
            -v blue="$gl_lan" -v reset="$reset" '
        {
            # 检测日志格式
            # 格式1：ISO8601时间戳 (2026-03-27T13:17:01.720196+08:00)
            if ($1 ~ /^[0-9][0-9][0-9][0-9]-[0-9][0-9]-[0-9][0-9]T/) {
                time = $1
                host = $2
                # 进程字段（如 CRON[445066]:）
                proc_field = $3
                gsub(/:$/, "", proc_field)  # 去掉末尾冒号
                # 消息从第4个字段开始
                msg = ""
                for (i=4; i<=NF; i++) {
                    if (i>4) msg = msg " "
                    msg = msg $i
                }
                # 去除消息开头的冒号（如果有）
                gsub(/^[: ]+/, "", msg)
            }
            # 格式2：传统syslog格式（月 日 时:分:秒）
            else if (NF >= 5 && $1 ~ /^[A-Za-z]{3}/ && $2 ~ /^[0-9]{1,2}/ && $3 ~ /^[0-9]{2}:[0-9]{2}:[0-9]{2}/) {
                time = $1 " " $2 " " $3
                host = $4
                proc_field = $5
                gsub(/:$/, "", proc_field)
                msg = ""
                for (i=6; i<=NF; i++) {
                    if (i>6) msg = msg " "
                    msg = msg $i
                }
                gsub(/^[: ]+/, "", msg)
            } else {
                next  # 无法识别的格式跳过
            }

            # 提取进程名（去掉 [pid]）
            proc_name = proc_field
            gsub(/\[[0-9]+\]/, "", proc_name)

            # 初始化颜色和内容
            event = ""
            event_color = blue
            detail = msg
            detail_color = reset

            # 事件匹配（按优先级）
            # 失败密码
            if (msg ~ /Failed password/) {
                event = "密码失败"
                event_color = red
                detail = ""
                if (match(msg, /for invalid user ([^ ]+)/)) {
                    user = substr(msg, RSTART+15, RLENGTH-15)
                    detail = "无效用户 " user
                } else if (match(msg, /for user ([^ ]+)/)) {
                    user = substr(msg, RSTART+9, RLENGTH-9)
                    detail = "用户 " user
                } else {
                    detail = "认证失败"
                }
                if (match(msg, /from ([0-9.]+)/)) {
                    ip = substr(msg, RSTART+5, RLENGTH-5)
                    detail = detail " 来自 " ip
                }
                if (match(msg, /port ([0-9]+)/)) {
                    port = substr(msg, RSTART+5, RLENGTH-5)
                    detail = detail " 端口 " port
                }
                detail_color = red
            }
            # 登录成功
            else if (msg ~ /Accepted/) {
                event = "登录成功"
                event_color = green
                detail = ""
                if (match(msg, /for ([^ ]+)/)) {
                    user = substr(msg, RSTART+4, RLENGTH-4)
                    detail = "用户 " user
                } else {
                    detail = "认证成功"
                }
                if (match(msg, /from ([0-9.]+)/)) {
                    ip = substr(msg, RSTART+5, RLENGTH-5)
                    detail = detail " 来自 " ip
                }
                if (match(msg, /port ([0-9]+)/)) {
                    port = substr(msg, RSTART+5, RLENGTH-5)
                    detail = detail " 端口 " port
                }
            }
            # 无效用户
            else if (msg ~ /Invalid user/) {
                event = "无效用户"
                event_color = yellow
                detail = ""
                if (match(msg, /Invalid user ([^ ]+)/)) {
                    user = substr(msg, RSTART+13, RLENGTH-13)
                    detail = "用户名 " user
                }
                if (match(msg, /from ([0-9.]+)/)) {
                    ip = substr(msg, RSTART+5, RLENGTH-5)
                    detail = detail " 来自 " ip
                }
                detail_color = yellow
            }
            # 认证失败（pam）
            else if (msg ~ /authentication failure/) {
                event = "认证失败"
                event_color = red
                detail = ""
                if (match(msg, /user=([^ ]+)/)) {
                    user = substr(msg, RSTART+5, RLENGTH-5)
                    detail = "用户 " user
                } else {
                    detail = "认证失败"
                }
                detail_color = red
            }
            # 会话开启
            else if (msg ~ /session opened/) {
                event = "会话开启"
                event_color = green
                detail = ""
                if (match(msg, /for user ([^ ]+)/)) {
                    user = substr(msg, RSTART+9, RLENGTH-9)
                    detail = "用户 " user
                } else {
                    detail = msg
                }
            }
            # 会话关闭
            else if (msg ~ /session closed/) {
                event = "会话关闭"
                event_color = yellow
                detail = ""
                if (match(msg, /for user ([^ ]+)/)) {
                    user = substr(msg, RSTART+9, RLENGTH-9)
                    detail = "用户 " user
                } else {
                    detail = msg
                }
            }
            # 断开连接
            else if (msg ~ /Disconnected/) {
                event = "断开连接"
                event_color = yellow
                detail = msg
            }
            # 其他消息
            else {
                split(msg, words, " ")
                event = words[1]
                for (i=2; i<=3 && i<=length(words); i++) {
                    event = event " " words[i]
                }
                event = substr(event, 1, 20)
                detail = msg
                detail_color = reset
            }

            # 截断过长的详细信息（避免撑破表格）
            if (length(detail) > 60) {
                detail = substr(detail, 1, 57) "..."
            }

            # 输出带颜色的制表符分隔行
            printf "%s%-24s%s\t", gray, time, reset
            printf "%s%-12s%s\t", purple, host, reset
            printf "%s%-15s%s\t", green, proc_name, reset
            printf "%s%-20s%s\t", event_color, event, reset
            printf "%s%-60s%s\n", detail_color, detail, reset
        }'
    } | column_if_available
}

###### 美化系统内存/交换分区信息（修复兼容版）
list_beautify_mem_info() {
    {
        printf "%s%-18s\t%-12s\t%-12s\t%-12s\t%-12s%s\n" \
            "$gl_hui" "内存类型" "总大小(MB)" "已用(MB)" "空闲(MB)" "使用率" "$reset"
        printf "%s%-18s\t%-12s\t%-12s\t%-12s\t%-12s%s\n" \
            "$gl_hui" "------------------" "------------" "------------" "------------" "------------" "$reset"

        free -m | awk -v green="$gl_lv" -v yellow="$gl_huang" \
            -v blue="$gl_lan" -v red="$gl_hong" -v reset="$reset" '
        function percent(u,t) { return t+0 == 0 ? "0%" : sprintf("%.1f%%", u*100/t) }
        NR==2 {   # 物理内存行
            total=$2; used=$3; free=$4
            printf "%s%-18s%s\t%s%-12s%s\t%s%-12s%s\t%s%-12s%s\t%s%-12s%s\n",
                blue, "物理内存", reset,
                yellow, total, reset,
                red, used, reset,
                green, free, reset,
                red, percent(used, total), reset
        }
        NR==3 {   # 交换分区行
            total=$2; used=$3; free=$4
            printf "%s%-18s%s\t%s%-12s%s\t%s%-12s%s\t%s%-12s%s\t%s%-12s%s\n",
                blue, "交换分区", reset,
                yellow, total, reset,
                red, used, reset,
                green, free, reset,
                red, percent(used, total), reset
        }'
    } | column_if_available
}

###### 美化系统负载/CPU平均负载
list_beautify_load_avg() {
    {
        printf "%s%-18s\t%-10s\t%-10s\t%-10s\t%-20s%s\n" \
            "$gl_hui" "负载指标" "1分钟" "5分钟" "15分钟" "CPU逻辑核心数" "$reset"
        printf "%s%-18s\t%-10s\t%-10s\t%-10s\t%-20s%s\n" \
            "$gl_hui" "------------------" "----------" "----------" "----------" "--------------------" "$reset"

        cpu_num=$(grep -c '^processor' /proc/cpuinfo 2>/dev/null || echo "未知")

        uptime | awk -v cpu="$cpu_num" -v green="$gl_lv" -v yellow="$gl_huang" \
            -v red="$gl_hong" -v blue="$gl_lan" -v reset="$reset" '
        {
            m1 = $(NF-2); gsub(/,/, "", m1)
            m5 = $(NF-1); gsub(/,/, "", m5)
            m15 = $(NF);   gsub(/,/, "", m15)

            c1 = green; if (m1+0 > cpu+0) c1 = red
            c5 = green; if (m5+0 > cpu+0) c5 = red
            c15= green; if (m15+0> cpu+0) c15= red

            printf "%s%-18s%s\t%s%-10s%s\t%s%-10s%s\t%s%-10s%s\t%s%-20s%s\n",
                blue, "系统平均负载", reset,
                c1, m1, reset,
                c5, m5, reset,
                c15, m15, reset,
                yellow, cpu, reset
        }'
    } | column_if_available
}

###### 美化系统开机时间/运行时长
list_beautify_uptime() {
    {
        printf "%s%-18s\t%-30s\t%-20s%s\n" \
            "$gl_hui" "开机时间" "运行时长" "当前时间" "$reset"
        printf "%s%-18s\t%-30s\t%-20s%s\n" \
            "$gl_hui" "------------------" "------------------------------" "--------------------" "$reset"

        # 获取开机时间（兼容旧版）
        boot_time=$(uptime -s 2>/dev/null || who -b 2>/dev/null | awk '{print $3,$4}')
        # 获取运行时长并转换为中文
        up_time=$(uptime -p 2>/dev/null | sed 's/up //' \
            | sed -E 's/ years?/年/g' \
            | sed -E 's/ months?/月/g' \
            | sed -E 's/ weeks?/周/g' \
            | sed -E 's/ days?/天/g' \
            | sed -E 's/ hours?/小时/g' \
            | sed -E 's/ minutes?/分钟/g' \
            | sed -E 's/ seconds?/秒/g' \
            | sed 's/,/，/g')
        # 获取当前时间
        now_time=$(date +"%Y-%m-%d %H:%M:%S")

        printf "%s%-18s%s\t%s%-30s%s\t%s%-20s%s\n" \
            "$gl_lan" "${boot_time:-未知}" "$reset" \
            "$gl_huang" "${up_time:-未知}" "$reset" \
            "$gl_lv" "${now_time}" "$reset"
    } | column_if_available
}

###### 美化系统所有服务（systemd）状态
list_beautify_systemd_services() {
    {
        printf "%s%-20s\t%-15s\t%-15s\t%-30s%s\n" "$gl_hui" "服务名" "状态" "启动类型" "描述" "$reset"
        printf "%s%-20s\t%-15s\t%-15s\t%-30s%s\n" "$gl_hui" "--------------------" "---------------" "---------------" "------------------------------" "$reset"

        systemctl list-units --type=service --no-pager 2>/dev/null | awk '
        NR>1 && /\.service/ && !/systemd-/ {
            srv=$1
            stat=$3
            startup=$2
            desc=substr($0, index($0,$5))
            gsub(/\.service/, "", srv)
            print srv, stat, startup, desc
        }' | head -20 | awk -v green="$gl_lv" -v red="$gl_hong" -v yellow="$gl_huang" -v blue="$gl_lan" -v reset="$reset" '
        BEGIN {OFS="\t"}
        {
            c=green; if ($2=="failed") c=red; if ($2=="exited") c=yellow
            printf "%s%-20s%s\t%s%-15s%s\t%s%-15s%s\t%s%-30s%s\n",
                blue, $1, reset,
                c, $2, reset,
                yellow, $3, reset,
                green, substr($0,index($0,$4)), reset
        }'
    } | column_if_available
}

###### 美化系统环境变量（常用）
list_beautify_env() {
    {
        printf "%s%-20s\t%-50s%s\n" "$gl_hui" "变量名" "变量值" "$reset"
        printf "%s%-20s\t%-50s%s\n" "$gl_hui" "-----------------" "---------------------------------------------------" "$reset"

        env | grep -E '^(PATH|USER|HOME|SHELL|PWD|LANG|HOSTNAME|TERM)' | sort | \
            awk -v green="$gl_lv" -v blue="$gl_lan" -v reset="$reset" '
        BEGIN {FS="="; OFS="\t"}
        {
            key = $1
            val = substr($0, index($0, $2))
            printf "%s%-20s%s\t%s%-50s%s\n",
                blue, key, reset,
                green, val, reset
        }'
    } | column_if_available
}


###### 美化crontab定时任务（当前用户）
list_beautify_crontab() {
    {
        printf "%s%-12s\t%-8s\t%-8s\t%-8s\t%-12s\t%-40s%s\n" \
            "$gl_hui" "分钟" "小时" "日期" "月份" "星期" "执行命令" "$reset"
        printf "%s%-12s\t%-8s\t%-8s\t%-8s\t%-12s\t%-40s%s\n" \
            "$gl_hui" "------------" "--------" "--------" "--------" "------------" "----------------------------------------" "$reset"

        crontab -l 2>/dev/null | grep -v '^#' | awk NF | \
            awk -v green="$gl_lv" -v yellow="$gl_huang" \
                -v blue="$gl_lan" -v reset="$reset" '
        BEGIN {OFS="\t"}
        {
            # 如果第一个字段是 @reboot 等特殊字符串，则将其放入分钟列，其余字段留空
            if ($1 ~ /^@/) {
                minute = $1
                hour = ""
                day = ""
                month = ""
                week = ""
                cmd = substr($0, index($0, $2))
            } else {
                minute = $1
                hour = $2
                day = $3
                month = $4
                week = $5
                cmd = substr($0, index($0, $6))
            }
            printf "%s%-12s%s\t%s%-8s%s\t%s%-8s%s\t%s%-8s%s\t%s%-12s%s\t%s%-40s%s\n",
                blue, minute, reset,
                yellow, hour, reset,
                blue, day, reset,
                yellow, month, reset,
                blue, week, reset,
                green, cmd, reset
        }'
    } | column_if_available
}

###### 美化打开文件数（系统限制）
list_beautify_file_limit() {
    {
        printf "%s%-22s\t%-20s\t%-20s%s\n" "$gl_hui" "限制类型" "软限制" "硬限制" "$reset"
        printf "%s%-22s\t%-20s\t%-20s%s\n" "$gl_hui" "----------------------" "--------------------" "--------------------" "$reset"

        # 当前进程最大打开数
        soft_limit=$(ulimit -n)
        hard_limit=$(ulimit -Hn)
        # 系统全局最大打开数
        sys_max=$(cat /proc/sys/fs/file-max 2>/dev/null || echo "未知")
        # 已使用的文件句柄数（粗略估计）
        used_fds=$(ls /proc/[0-9]*/fd 2>/dev/null | wc -l)

        printf "%s%-22s%s\t%s%-20s%s\t%s%-20s%s\n" \
            "$gl_lan" "当前进程最大打开数" "$reset" \
            "$gl_huang" "$soft_limit" "$reset" \
            "$gl_hong" "$hard_limit" "$reset"

        printf "%s%-22s%s\t%s%-20s%s\t%s%-20s%s\n" \
            "$gl_lan" "系统全局最大打开数" "$reset" \
            "$gl_huang" "$sys_max" "$reset" \
            "$gl_hong" "无" "$reset"

        printf "%s%-22s%s\t%s%-20s%s\t%s%-20s%s\n" \
            "$gl_lan" "当前已使用文件句柄" "$reset" \
            "$gl_lv" "$used_fds" "$reset" \
            "$gl_hong" "$sys_max" "$reset"
    } | column_if_available
}

###### 美化系统所有挂载点
list_beautify_mounts() {
    {
        printf "%s%-25s\t%-25s\t%-15s\t%-20s%s\n" \
            "$gl_hui" "设备" "挂载点" "文件系统" "权限" "$reset"
        printf "%s%-25s\t%-25s\t%-15s\t%-20s%s\n" \
            "$gl_hui" "-------------------------" "-------------------------" "---------------" "--------------------" "$reset"

        mount | grep -E '^/dev/' | grep -v 'loop' | sort | \
            awk -v green="$gl_lv" -v yellow="$gl_huang" \
                -v blue="$gl_lan" -v reset="$reset" '
        BEGIN {OFS="\t"}
        {
            dev = $1
            mp = $3
            fs = $5
            perm = $6
            gsub(/[()]/, "", perm)
            printf "%s%-25s%s\t%s%-25s%s\t%s%-15s%s\t%s%-20s%s\n",
                blue, dev, reset,
                yellow, mp, reset,
                green, fs, reset,
                green, perm, reset
        }'
    } | column_if_available
}

###### 美化系统所有用户组（前30个）
list_beautify_group_info() {
