        printf "%s%-20s\t%-10s\t%-30s%s\n" "$gl_hui" "--------------------" "----------" "------------------------------" "$reset"

        cat /etc/group 2>/dev/null | head -30 | \
            awk -v green="$gl_lv" -v yellow="$gl_huang" \
                -v blue="$gl_lan" -v reset="$reset" '
        BEGIN {FS=":"; OFS="\t"}
        {
            printf "%s%-20s%s\t%s%-10s%s\t%s%-30s%s\n",
                blue, $1, reset,
                yellow, $3, reset,
                green, $4, reset
        }'
    } | column_if_available
}

###### 美化系统所有Shell列表
list_beautify_shell_list() {
