###### 公用函数_检查软件是否安装
check_and_install() {
    [[ $# -eq 0 ]] && { log_error "未提供包名"; return 2; }

    local pkg failed=()
    
    for pkg in "$@"; do
        # 检查是否已安装（命令存在 或 包管理器中存在）
        if command -v "$pkg" &>/dev/null || \
           { command -v dpkg-query &>/dev/null && dpkg-query -W "$pkg" &>/dev/null; } || \
           { command -v rpm &>/dev/null && rpm -q "$pkg" &>/dev/null; }; then
            # 已安装：完全静默，直接跳过
            continue
        fi

        # 未安装：显示提示并安装
        printf '%b即将自动安装 %s%b\n' "$gl_huang" "$pkg" "$gl_bai"
        
        if ! install "$pkg"; then
            failed+=("$pkg")
        fi
    done

    # 返回结果
    [[ ${#failed[@]} -eq 0 ]] && return 0
    log_error "以下包安装失败: ${failed[*]}"
    return 1
}

# 显示目录列表函数
# 用法: show_directory_list [基础路径] [每行显示数量] [是否显示隐藏目录] [空目录是否退出]
# show_directory_list "/path/to/projects" 4 false # 不显示隐藏目录
# show_directory_list "/path/to/projects" 4 true # 显示隐藏目录
# 返回值: 打印目录列表，返回0表示成功，1表示无目录
# 修改 show_directory_list 函数，添加全局变量
# 空目录时不退出，继续执行
# show_directory_list "/empty/dir" 4 false false
# show_directory_list "/empty/dir" 4 false true
show_directory_list() {
    local base_path="${1:-.}"
    local items_per_line="${2:-4}"
    local show_hidden="${3:-false}"
    local exit_on_empty="${4:-true}"  # 新增：控制是否在空目录时退出
    local return_array_var="$5"  # 第5个参数是返回数组变量名

    local dir_array=()
    for dir in "$base_path"/*/; do
        [[ -d "$dir" ]] || continue
        local dir_name
        dir_name=$(basename "$dir")

        if [[ "$show_hidden" == "true" || "$show_hidden" == "1" ]]; then
            dir_array+=("$dir_name")
        elif [[ ! "$dir_name" =~ ^\. ]]; then
            dir_array+=("$dir_name")
        fi
    done

    if [[ ${#dir_array[@]} -eq 0 ]]; then
        echo -e "${gl_huang}当前目录为空${gl_bai}"
        # 只有当 exit_on_empty 为 true 时才退出
        if [[ "$exit_on_empty" == "true" || "$exit_on_empty" == "1" ]]; then
            # 空目录时也需要设置返回数组
            if [[ -n "$return_array_var" ]]; then
                eval "$return_array_var=()"
            fi
            return 0
        fi
    fi

    mapfile -t dir_array < <(printf '%s\n' "${dir_array[@]}" | sort)

    # 安全返回数组
    if [[ -n "$return_array_var" ]]; then
        eval "$return_array_var=($(printf '%q ' "${dir_array[@]}"))"
    fi

    # 更精确的字符宽度计算
    get_display_width() {
        local str="$1"
        local width=0
        local len=${#str}

        for ((i = 0; i < len; i++)); do
            local char="${str:i:1}"
            local code=$(printf '%d' "'$char")

            # 判断字符宽度
            if [[ $code -lt 128 ]]; then
                # ASCII字符（英文、数字、符号）：宽度1
                ((width++))
            elif [[ $code -ge 0x4E00 && $code -le 0x9FFF ]] ||
                [[ $code -ge 0x3400 && $code -le 0x4DBF ]] ||
                [[ $code -ge 0x20000 && $code -le 0x2A6DF ]] ||
                [[ $code -ge 0x2A700 && $code -le 0x2B73F ]] ||
                [[ $code -ge 0x2B740 && $code -le 0x2B81F ]] ||
                [[ $code -ge 0x2B820 && $code -le 0x2CEAF ]] ||
                [[ $code -ge 0xF900 && $code -le 0xFAFF ]] ||
                [[ $code -ge 0x2F800 && $code -le 0x2FA1F ]]; then
                # CJK统一表意文字：宽度2
                ((width += 2))
            elif [[ $code -ge 0x3000 && $code -le 0x303F ]] ||
                [[ $code -ge 0xFF00 && $code -le 0xFFEF ]]; then
                # CJK符号和标点、全角ASCII/拉丁文/数字/假名：宽度2
                ((width += 2))
            else
                # 其他Unicode字符（如全角括号）：宽度2
                ((width += 2))
            fi
        done

        echo $width
    }

    # 计算最大显示宽度
    local max_display_width=0
    for d in "${dir_array[@]}"; do
        local width
        width=$(get_display_width "$d")
        (($width > max_display_width)) && max_display_width=$width
    done

    # 设置每列的宽度
    local column_width=$((max_display_width + 4))

    # 显示目录列表
    local count=0
    for i in "${!dir_array[@]}"; do
        count=$((i + 1))

        # 格式化序号
        local index_str
        printf -v index_str "%2d." "$count"

        # 获取当前目录名的显示宽度
        local current_width
        current_width=$(get_display_width "${dir_array[i]}")

        # 计算需要填充的空格数
        local padding=$((column_width - current_width))

        # 显示序号和目录名
        printf "${gl_bufan}%s${gl_bai} %s" "$index_str" "${dir_array[i]}"

        # 填充空格
        for ((s = 0; s < padding; s++)); do
            printf " "
        done

        # 每行显示指定数量的项目后换行
        if (((i + 1) % items_per_line == 0)); then
            echo
        fi
    done

    # 如果最后一行不满，则补换行
    if ((count % items_per_line != 0)); then
        echo
    fi
    return 0
}

###### 函数_mobufan.sh提示更新
mobufan_sh_update() {
    # 快速探测网络：3 秒 TCP 握手
    timeout 3 bash -c ': </dev/tcp/gitee.com/443' &>/dev/null || {
        return
    }

    # 获取本地版本号 - 从当前脚本文件提取
    local local_version
    local script_path
    script_path="$(realpath "$0")"

    # 从当前脚本中提取版本号
    local_version=$(grep -E '^sh_v="[0-9]+\.[0-9]+\.[0-9]+"' "$script_path" 2>/dev/null |
        head -1 | sed -E 's/^sh_v="([0-9]+\.[0-9]+\.[0-9]+)".*/\1/')

    # 如果无法提取，使用默认版本
    [ -z "$local_version" ] && local_version="0.0.0"

    # 获取远程版本号
    local remote_version
    remote_version=$(curl -m 5 -s https://gitee.com/meimolihan/sh/raw/master/mobufan.sh |
        grep -E '^sh_v="[0-9]+\.[0-9]+\.[0-9]+"' | head -1 | cut -d '"' -f2)

    # 检查版本号是否有效
    if [ -z "$remote_version" ]; then
        return
    fi

    # 比较版本号
    compare_versions() {
        local v1=$1 v2=$2
        [ "$v1" = "$v2" ] && return 0

        # 提取主版本、次版本、修订号
        local v1_major v1_minor v1_patch v2_major v2_minor v2_patch
        v1_major=$(echo "$v1" | cut -d. -f1)
        v1_minor=$(echo "$v1" | cut -d. -f2)
        v1_patch=$(echo "$v1" | cut -d. -f3)
        v2_major=$(echo "$v2" | cut -d. -f1)
        v2_minor=$(echo "$v2" | cut -d. -f2)
        v2_patch=$(echo "$v2" | cut -d. -f3)

        # 比较版本
        [ "$v1_major" -gt "$v2_major" ] && return 0
        [ "$v1_major" -lt "$v2_major" ] && return 1
        [ "$v1_minor" -gt "$v2_minor" ] && return 0
        [ "$v1_minor" -lt "$v2_minor" ] && return 1
        [ "$v1_patch" -gt "$v2_patch" ] && return 0
        [ "$v1_patch" -lt "$v2_patch" ] && return 1
        return 0
    }

    # 如果本地版本 >= 远程版本，不需要更新
    if compare_versions "$local_version" "$remote_version"; then
        return
    fi

    echo

    # 发现新版本，显示更新提示
    echo -e "${gl_huang}发现新版本！${gl_bai}"

    # 计算显示宽度（去除颜色代码，计算实际占用的列数）
    calc_display_width() {
        echo "$1" | sed 's/\x1B\[[0-9;]*[a-zA-Z]//g' | wc -L
    }

    local current_text="${gl_bai}当前版本 ${gl_huang}v$local_version"
    local latest_text="${gl_bai}最新版本 ${gl_lv}v$remote_version"
    local input_text="${gl_bai}请输入${gl_huang} 666 "
    local update_text="${gl_bai}更新到最新版"

    # 计算每列的最大显示宽度
    local col1_width1 col2_width1 col1_width2 col2_width2
    col1_width1=$(calc_display_width "$current_text")
    col2_width1=$(calc_display_width "$latest_text")
    col1_width2=$(calc_display_width "$input_text")
    col2_width2=$(calc_display_width "$update_text")

    # 找出两列各自的最大宽度
    local max_col1_width=$((col1_width1 > col1_width2 ? col1_width1 : col1_width2))
    local max_col2_width=$((col2_width1 > col2_width2 ? col2_width1 : col2_width2))

    # 计算每行需要填充的空格数
    local pad_col1_1=$((max_col1_width - col1_width1))
    local pad_col2_1=$((max_col2_width - col2_width1))
    local pad_col1_2=$((max_col1_width - col1_width2))
    local pad_col2_2=$((max_col2_width - col2_width2))

    # 输出对齐后的内容
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${current_text}$(printf '%*s' $pad_col1_1)    ${latest_text}$(printf '%*s' $pad_col2_1)${gl_bai}"
    echo -e "${input_text}$(printf '%*s' $pad_col1_2)    ${update_text}$(printf '%*s' $pad_col2_2)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
}

###### 智能获取本机IPv4和IPv6地址的网络信息收集函数。
ip_address() {

get_public_ip() {
    curl -s https://ipinfo.io/ip && echo
}

get_local_ip() {
    ip route get 8.8.8.8 2>/dev/null | grep -oP 'src \K[^ ]+' || \
    hostname -I 2>/dev/null | awk '{print $1}' || \
    ifconfig 2>/dev/null | grep -E 'inet [0-9]' | grep -v '127.0.0.1' | awk '{print $2}' | head -n1
}

public_ip=$(get_public_ip)
isp_info=$(curl -s --max-time 3 http://ipinfo.io/org)


if echo "$isp_info" | grep -Eiq 'mobile|unicom|telecom'; then
    ipv4_address=$(get_local_ip)
else
    ipv4_address="$public_ip"
fi


# ipv4_address=$(curl -s https://ipinfo.io/ip && echo)
ipv6_address=$(curl -s --max-time 1 https://v6.ipinfo.io/ip && echo)

}

###### 跨Linux发行版的通用软件包安装函数
install() {
    [[ $# -eq 0 ]] && {
        log_error "未提供软件包参数!"
        return 1
    }

    local pkg mgr ver cmd_ver pkg_ver installed=false
    for pkg in "$@"; do
        installed=false
        ver=""
        
        # 1. 首先检查是否已安装（通用方法）
        if command -v "$pkg" &>/dev/null; then
            cmd_ver=$("$pkg" --version 2>/dev/null | head -n1 | tr -cd '[:print:]' | grep -oE '[0-9]+(\.[0-9]+)+' | head -n1 || echo "")
            [[ -n "$cmd_ver" ]] && ver="$cmd_ver"
            installed=true
        fi
        
        # 2. 特殊处理：检查7zip（命令是7z而不是7zip）
        if [[ "$pkg" == "7zip" || "$pkg" == "7z" ]]; then
            if command -v 7z &>/dev/null; then
                ver=$(7z 2>&1 | grep -oE '[0-9]+(\.[0-9]+)+' | head -n1 || echo "")
                [[ -n "$ver" ]] && installed=true
            fi
        fi
        
        # 3. 检查包管理器是否已安装（针对不同包管理器）
        if [[ "$installed" == false ]]; then
            if command -v opkg &>/dev/null; then
                # OpenWrt/iStoreOS的opkg检查
                if opkg list-installed | grep -q "^${pkg} "; then
                    installed=true
                    ver=$(opkg list-installed | grep "^${pkg} " | awk '{print $3}' 2>/dev/null || echo "")
                fi
            elif command -v dpkg-query &>/dev/null; then
                # Debian/Ubuntu
                if dpkg-query -W -f='${Status}' "$pkg" 2>/dev/null | grep -q "install ok installed"; then
                    installed=true
                    ver=$(dpkg-query -W -f='${Version}' "$pkg" 2>/dev/null || echo "")
                fi
            elif command -v rpm &>/dev/null; then
                # RedHat/CentOS
                if rpm -q "$pkg" &>/dev/null; then
                    installed=true
                    ver=$(rpm -q --qf '%{VERSION}' "$pkg" 2>/dev/null || echo "")
                fi
            elif command -v apk &>/dev/null; then
                # Alpine
                if apk info "$pkg" 2>/dev/null | grep -q "^installed"; then
                    installed=true
                    ver=$(apk info -a "$pkg" 2>/dev/null | grep -oE '[0-9]+(\.[0-9]+)+' | head -n1 || echo "")
                fi
            elif command -v pacman &>/dev/null; then
                # Arch/Manjaro
                if pacman -Qi "$pkg" &>/dev/null; then
                    installed=true
                    ver=$(pacman -Qi "$pkg" 2>/dev/null | grep -i "version" | grep -oE '[0-9]+(\.[0-9]+)+' | head -n1 || echo "")
                fi
            fi
        fi
        
        # 4. 已安装则提示并跳过
        if [[ "$installed" == true ]]; then
            echo -e "${gl_huang}${pkg}${gl_bai} ${gl_lv}已安装${gl_bai}" \
                "$([[ -n "$ver" ]] && echo "版本 ${gl_lv}${ver}${gl_bai}")"
            continue
        fi
        
        # 5. 未安装则开始安装
        echo -e ""
        echo -e "${gl_huang}开始安装：${gl_bai}${pkg}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        local install_success=false
        
        for mgr in opkg dnf yum apt apk pacman zypper pkg; do
            if ! command -v "$mgr" &>/dev/null; then
                continue
            fi
            
            case $mgr in
            opkg)
                echo -e "${gl_bai}使用包管理器: ${gl_zi}opkg (OpenWrt/iStoreOS)${gl_bai}"
                # OpenWrt需要特殊处理7zip
                if [[ "$pkg" == "7zip" || "$pkg" == "7z" ]]; then
                    echo -e "${gl_bai}正在安装: ${gl_lv}p7zip${gl_bai}"
                    opkg update && opkg install p7zip && install_success=true
                else
                    opkg update && opkg install "$pkg" && install_success=true
                fi
                ;;
            dnf)
                echo -e "${gl_bai}使用包管理器: ${gl_zi}dnf (Fedora/RHEL)${gl_bai}"
                dnf -y update && dnf install -y "$pkg" && install_success=true
                ;;
            yum)
                echo -e "${gl_bai}使用包管理器: ${gl_zi}yum (CentOS/RHEL)${gl_bai}"
                yum -y update && yum install -y "$pkg" && install_success=true
                ;;
            apt)
                echo -e "${gl_bai}使用包管理器: ${gl_zi}apt (Debian/Ubuntu)${gl_bai}"
                apt update -y && apt install -y "$pkg" && install_success=true
                ;;
            apk)
                echo -e "${gl_bai}使用包管理器: ${gl_zi}apk (Alpine)${gl_bai}"
                apk update && apk add "$pkg" && install_success=true
                ;;
            pacman)
                echo -e "${gl_bai}使用包管理器: ${gl_zi}pacman (Arch/Manjaro)${gl_bai}"
                pacman -Syu --noconfirm && pacman -S --noconfirm "$pkg" && install_success=true
                ;;
            zypper)
                echo -e "${gl_bai}使用包管理器: ${gl_zi}zypper (openSUSE)${gl_bai}"
                zypper refresh && zypper install -y "$pkg" && install_success=true
                ;;
            pkg)
                echo -e "${gl_bai}使用包管理器: ${gl_zi}pkg (FreeBSD)${gl_bai}"
                pkg update && pkg install -y "$pkg" && install_success=true
                ;;
            esac
            
            [[ "$install_success" == true ]] && break
        done
        
        if [[ "$install_success" == true ]]; then
            echo -e "${gl_lv}✓ ${pkg} 安装成功${gl_bai}"
        else
            echo -e "${gl_hong}✗ ${pkg} 安装失败${gl_bai}"
        fi
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    done
}

check_disk_space() {
    local required_gb=$1
    local path=${2:-/}

    mkdir -p "$path"

    local required_space_mb
    required_space_mb=$((required_gb * 1024))
    local available_space_mb
    available_space_mb=$(df -m "$path" | awk 'NR==2 {print $4}')

    if [ "$available_space_mb" -lt "$required_space_mb" ]; then
        echo -e "${gl_huang}提示: ${gl_bai}磁盘空间不足！"
        echo "当前可用空间: $((available_space_mb / 1024))G"
        echo "最小需求空间: ${required_gb}G"
        echo "无法继续安装，请清理磁盘空间后重试。"
        break_end
        mobufan
    fi
}

install_dependency() {
    switch_mirror false false
    install wget unzip tar jq grep
    check_swap
    auto_optimize_dns
    prefer_ipv4
    check_port
}

remove() {
    if [ $# -eq 0 ]; then
        echo "未提供软件包参数!"
        return 1
    fi

    for package in "$@"; do
        echo -e ""
        echo -e "${gl_huang}>>> 正在卸载： ${gl_huang}$package ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        if command -v dnf &>/dev/null; then
            dnf remove -y "$package"
        elif command -v yum &>/dev/null; then
            yum remove -y "$package"
        elif command -v apt &>/dev/null; then
            apt purge -y "$package"
        elif command -v apk &>/dev/null; then
            apk del "$package"
        elif command -v pacman &>/dev/null; then
            pacman -Rns --noconfirm "$package"
        elif command -v zypper &>/dev/null; then
            zypper remove -y "$package"
        elif command -v opkg &>/dev/null; then
            opkg remove "$package"
        elif command -v pkg &>/dev/null; then
            pkg delete -y "$package"
        else
            echo -e "${gl_huang}未知的包管理器!${gl_bai}"
            return 1
        fi
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    done
}

# 通用 systemctl 函数，适用于各种发行版
# shellcheck disable=SC2032
systemctl() {
    local COMMAND="$1"
    local SERVICE_NAME="$2"

    if command -v apk &>/dev/null; then
        service "$SERVICE_NAME" "$COMMAND"
    else
        /bin/systemctl "$COMMAND" "$SERVICE_NAME"
    fi
}

# 重启服务
restart() {
    if systemctl restart "$1"; then
        log_ok "${gl_huang}$1${gl_bai} 服务已重启。"
    else
        log_error "重启 ${gl_huang}$1${gl_bai}  服务失败。"
    fi
}

# 启动服务
start() {
    if systemctl start "$1"; then
        log_ok "${gl_huang}$1${gl_bai} 服务已启动。"
    else
        log_error "启动 ${gl_huang}$1${gl_bai} 服务失败。"
    fi
}

# 停止服务
stop() {
    systemctl stop "$1"
    if cmd; then
        echo "${gl_huang}$1${gl_bai} 服务已停止。"
    else
        echo "停止 ${gl_huang}$1${gl_bai} 服务失败。"
    fi
}

# 查看服务状态
status() {
    systemctl status "$1"
    if cmd; then
        echo "$1 服务状态已显示。"
    else
        echo "错误：无法显示 $1 服务状态。"
    fi
}

enable() {
    local SERVICE_NAME="$1"
    if command -v apk &>/dev/null; then
        rc-update add "$SERVICE_NAME" default
    else
        /bin/systemctl enable "$SERVICE_NAME"
    fi

    log_ok "${gl_huang}$SERVICE_NAME ${gl_bai}已设置为开机自启。"
}

# ============================================================
# 功能：横向彩色列出目录内容
# 参数：$1 - 是否显示隐藏文件（1=显示，0或不传=不显示）
#            $2 - 每行列数（可选，默认自动计算）
#      list_dir_colorful             # 不显示隐藏文件，自动列数
#      list_dir_colorful 1           # 显示隐藏文件，自动列数
#      list_dir_colorful 0 4         # 不显示隐藏文件，每行4列
#      list_dir_colorful 1 3         # 显示隐藏文件，每行3列
# ============================================================
list_dir_colorful() {
    # ---- 参数处理 ----
    local show_hidden="${1:-0}"
    local user_cols="${2:-0}"
    local files=()
    local has_content=0
    local item
    
    # 文件类型 → 颜色 关联表（使用你定义的颜色变量）
    declare -A type_color=(
        [dir]="${gl_bufan}"      # 目录
        [exe]="${gl_lv}"         # 可执行文件
        [link]="${gl_zi}"        # 软链接
        [archive]="${gl_hong}"   # 压缩包
        [image]="${gl_huang}"    # 图片
        [code]="${gl_lan}"       # 代码文件
        [text]="${gl_bai}"       # 普通文本
        [else]="${gl_hui}"       # 其他
    )
    
    # 获取文件列表（兼容旧版 Bash）
    if [[ "${show_hidden}" -eq 1 ]]; then
        # 显示隐藏文件：使用 ls -A 再过滤，或逐个检查
        while IFS= read -r item; do
            [[ -e "${item}" || -L "${item}" ]] && {
                files+=("${item}")
                has_content=1
            }
        done < <(ls -A 2>/dev/null)
    else
        # 不显示隐藏文件
        for item in *; do
            [[ -e "${item}" || -L "${item}" ]] && {
                files+=("${item}")
                has_content=1
            }
        done 2>/dev/null
    fi
    
    # 输出标题
    echo -e "${gl_huang}>>> 当前目录文件列表：${gl_bai}(${gl_lv}$(pwd)${gl_bai})"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 空目录处理
    if [[ ${has_content} -eq 0 ]]; then
        echo -e "${gl_huang}当前目录为空${gl_bai}"
        return 0
    fi
    
    # ---- 预计算文件信息 ----
    local file_info=()
    local max_display_width=0
    
    for item in "${files[@]}"; do
        local color="" suffix=""
        
        # 判断文件类型
        if [[ -L "${item}" ]]; then
            color="${type_color[link]}"
            suffix="@"
        elif [[ -d "${item}" ]]; then
            color="${type_color[dir]}"
            suffix="/"
        elif [[ -x "${item}" ]]; then
            color="${type_color[exe]}"
            suffix="*"
        else
            local ext="${item##*.}"
            if [[ "${ext}" != "${item}" ]]; then
                case "${ext,,}" in
                    tar|gz|bz2|xz|zip|7z|rar|zst|tgz|tbz2|txz) 
                        color="${type_color[archive]}" ;;
                    jpg|jpeg|png|gif|bmp|webp|svg|ico|tiff|avif) 
                        color="${type_color[image]}" ;;
                    sh|py|pl|rb|go|cpp|c|h|hpp|js|ts|jsx|tsx|java|php|rs|swift|kt|lua|vim) 
                        color="${type_color[code]}" ;;
                    txt|md|log|conf|cfg|yml|yaml|json|xml|ini|csv|toml) 
                        color="${type_color[text]}" ;;
                    *) 
                        color="${type_color[else]}" ;;
                esac
            else
                if [[ -b "${item}" || -c "${item}" ]]; then
                    color="${type_color[else]}"
                else
                    color="${type_color[text]}"
                fi
            fi
        fi
        
        local display_str="${item}${suffix}"
        local display_width
        
        # 计算显示宽度（正确处理中文等宽字符）
        if command -v wc &>/dev/null; then
            display_width=$(printf "%s" "${display_str}" | wc -L 2>/dev/null || echo "${#display_str}")
        else
            display_width=${#display_str}
        fi
        
        (( display_width > max_display_width )) && max_display_width=${display_width}
        
        # 存储：0=原名, 1=颜色, 2=后缀, 3=显示宽度, 4=完整显示串
        file_info+=("${item}" "${color}" "${suffix}" "${display_width}" "${display_str}")
    done
    
    # ---- 计算布局 ----
    local term_width
    term_width=$(tput cols 2>/dev/null || echo 80)
    
    # 列宽 = 最大显示宽度 + 4字符间隔
    local col_width=$((max_display_width + 4))
    
    # 确定列数
    local items_per_line
    if [[ ${user_cols} -gt 0 ]]; then
        items_per_line=${user_cols}
        # 检查是否超出终端宽度，如果是则调整为最大可用列数
        local needed_width=$((items_per_line * col_width - 4))
        if (( needed_width > term_width )); then
            items_per_line=$(( (term_width + 4) / col_width ))
            (( items_per_line < 1 )) && items_per_line=1
        fi
    else
        items_per_line=$((term_width / col_width))
        (( items_per_line < 1 )) && items_per_line=1
    fi
    
    (( items_per_line > ${#files[@]} )) && items_per_line=${#files[@]}
    
    local total_items=${#files[@]}
    local rows=$(( (total_items + items_per_line - 1) / items_per_line ))
    
    # ---- 输出文件（行优先：横向阅读顺序） ----
    local row col index idx_base file_name file_color file_suffix file_width padding
    
    for ((row = 0; row < rows; row++)); do
        for ((col = 0; col < items_per_line; col++)); do
            index=$((row * items_per_line + col))
            
            if ((index < total_items)); then
                idx_base=$((index * 5))
                file_name="${file_info[idx_base]}"
                file_color="${file_info[idx_base+1]}"
                file_suffix="${file_info[idx_base+2]}"
                file_width="${file_info[idx_base+3]}"
                
                # 计算填充空格数
                padding=$((col_width - file_width))
                
                # 输出彩色文件名（颜色码不占用显示宽度）
                printf "%b%s%b" "${file_color}" "${file_name}${file_suffix}" "${gl_bai}"
                
                # 填充空格（最后一列不填充间隔）
                if ((col < items_per_line - 1 && index < total_items - 1)); then
                    printf "%*s" "${padding}" ""
                fi
            fi
        done
        echo
    done
    
    # ---- 统计信息 ----
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    local total=${#files[@]}
    local dir_count=0 file_count=0 link_count=0
    for item in "${files[@]}"; do
        if [[ -L "${item}" ]]; then
            ((link_count++))
        elif [[ -d "${item}" ]]; then
            ((dir_count++))
        else
            ((file_count++))
        fi
    done
    
    echo -e "${gl_bai}总计: ${gl_lv}${total}${gl_bai} 项    ${gl_bufan}目录: ${dir_count}${gl_bai}    文件: ${file_count}${gl_bai}    ${gl_zi}链接: ${link_count}${gl_bai}"
    
    if [[ ${user_cols} -gt 0 ]]; then
        echo -e "${gl_hui}布局: ${gl_lv}${rows}${gl_hui} 行 ${gl_huang}× ${gl_lv}${items_per_line}${gl_hui} 列${gl_bai}"
    else
        echo -e "${gl_hui}布局: ${gl_lv}${rows}${gl_hui} 行 ${gl_huang}× ${gl_lv}${items_per_line}${gl_hui} 列 (${gl_huang}自动计算${gl_hui})${gl_bai}"
    fi
    
    return 0
}

###### 自定义仓库克隆函数
clone_custom_repo() {
    local repoUrl cleanUrl repoName overwrite
    local empty_count=0  # 记录连续空输入次数

    # 显示标题
    clear
    echo -e ""
    echo -e "${gl_zi}>>> Git仓库克隆${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "当前目录: ${gl_huang}$(pwd)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 获取用户输入（使用循环直到输入不为空）
    while true; do
        # 每次循环重新生成提示文本
        local prompt_text="${gl_bai}请输入Git仓库的${gl_lv}URL${gl_bai}或${gl_lv}git clone${gl_bai}命令(${gl_huang}0 ${gl_bai}返回): "

        read -r -e -p "$(echo -e "${prompt_text}")" repoUrl

        # 检查输入是否为0
        [ "$repoUrl" = "0" ] && { cancel_return "上一级选单"; return 1; }   # break 或 continue 或 return ，视上下文而定

        # 检查输入是否为空
        if [ -z "$repoUrl" ]; then
            empty_count=$((empty_count + 1))

            # 如果是第一次空输入，显示提示
            if [ $empty_count -eq 1 ]; then
                echo -e "${gl_hong}输入不能为空，请重新输入。${gl_bai}"
                sleep_fractional 1

                # 清除提示和输入行
                tput cuu1  # 光标上移一行
                tput el    # 清除整行
                tput cuu1  # 光标再上移一行
                tput el    # 清除整行
            else
                # 连续空输入，只清除当前行
                tput cuu1  # 光标上移一行
                tput el    # 清除整行
            fi

            continue
        fi

        # 重置空输入计数
        empty_count=0
        
        # 输入有效，跳出循环
        break
    done

    # 清理URL（移除git clone前缀和引号）
    cleanUrl=${repoUrl#*git clone }
    cleanUrl=${cleanUrl//[\"\'\']/}

    # 验证清理后的URL
    if [ -z "$cleanUrl" ]; then
        echo -e "${gl_hong}错误：无法解析URL${gl_bai}"
        return 1
    fi

    # 从URL提取仓库名称
    repoName=$(basename "$cleanUrl" .git)

    # 显示克隆信息
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}即将克隆仓库: ${gl_huang}$repoName${gl_bai}"
    echo -e "${gl_bai}仓库地址: ${gl_lv}$cleanUrl${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查目录是否已存在
    if [ -d "$repoName" ]; then
        echo -e ""
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}警告：仓库目录 ${gl_lv}'$repoName' ${gl_huang}已存在${gl_bai}"
        echo -e "${gl_bai}输入${gl_huang}0 ${gl_bai}返回，${gl_bai}输入${gl_lv}y ${gl_bai}强制重新克隆，输入其他任意键跳过${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入你的选择: ${gl_bai}")" overwrite

        if [ "$overwrite" = "0" ]; then
            cancel_return
            return 3
        elif [[ ${overwrite,,} != "y" ]]; then
            echo -e "${gl_lv}已跳过克隆${gl_bai}"
            exit_animation    # 即将退出动画
            return 2
        fi
        rm -rf "$repoName"
    fi

    # 执行git clone
    echo -e ""
    echo -e "${gl_huang}>>> 正在克隆仓库，请稍候 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    git clone "$cleanUrl"
    local clone_status=$?

    # 显示结果
    if [ $clone_status -ne 0 ]; then
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_hong}仓库 ${gl_lv}'$repoName' ${gl_huang}克隆失败，请检查URL是否正确或网络连接。${gl_bai}"
    else
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lv}仓库 ${gl_huang}'$repoName'${gl_lv} 克隆成功！${gl_bai}"
    fi
    read -r -e -p "$(echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
    return $clone_status
}

safe_rm() {
    local target_dir="${1:-.}" # 允许指定目标目录，默认为当前目录
    local force_mode=false
    local interactive_mode=false

    # 解析参数
    while [[ $# -gt 0 ]]; do
        case $1 in
        -f | --force)
            force_mode=true
            shift
            ;;
        -i | --interactive)
            interactive_mode=true
            shift
            ;;
        *)
            target_dir="$1"
            shift
            ;;
        esac
    done

    # 检查目录是否存在
    if [[ ! -d "$target_dir" ]]; then
        echo -e "${gl_huang}错误: 目录 ${gl_lv}'$target_dir' ${gl_huang}不存在${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 切换到目标目录
    pushd "$target_dir" >/dev/null || return 1

    # 检查目录是否为空
    local file_count=$(ls -A | wc -l)
    if [[ $file_count -eq 0 ]]; then
        echo -e "${gl_huang}当前目录 ${gl_lv}$(pwd) ${gl_huang}为空，无需删除${gl_bai}"
        # echo -e "${gl_huang}目录 ${gl_hong}$target_dir ${gl_huang}为空，无需删除${gl_bai}"
        popd >/dev/null
        exit_animation    # 即将退出动画
        return 0
    fi

    echo -e "${gl_bai}当前目录: ${gl_lv}$(pwd)${gl_bai}"
    echo -e "${gl_bai}文件数量: ${gl_lv}$file_count${gl_bai}"
    echo -e ""
    echo -e "${gl_huang}>>> 即将删除的文件和文件夹:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    ls -la

    # 交互式模式：逐个文件确认
    if [[ "$interactive_mode" == true ]]; then
        echo -e "\n=== 交互式删除模式 ==="
        for item in * .*; do
            if [[ "$item" != "." && "$item" != ".." && -e "$item" ]]; then
                read -p "删除 '$item'? [y/N]: " confirm
                if [[ "$confirm" =~ ^[Yy]$ ]]; then
                    if rm -rf "$item" 2>/dev/null; then
                        echo -e "${gl_lv}已删除: ${gl_huang}$item${gl_bai}"
                    else
                        echo -e "${gl_hong}删除失败: ${gl_huang}$item${gl_bai}"
                    fi
                else
                    echo -e "${gl_huang}跳过: ${gl_lv}$item${gl_bai}"
                fi
            fi
        done
        popd >/dev/null
        return 0
    fi

    # 强制模式：直接删除
    if [[ "$force_mode" == true ]]; then
        echo -e "${gl_bai}强制删除模式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        rm -rf ./*
        rm -rf ./..* 2>/dev/null # 尝试删除隐藏文件，忽略错误
        popd >/dev/null
        echo -e "${gl_lv}删除完成${gl_bai}"
        exit_animation    # 即将退出动画
        return 0
    fi

    # 普通模式：确认提示
    echo -e "\n⚠️  ${gl_huang}警告：${gl_bai}此操作将永久删除以上所有文件！"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确认删除当前目录所有文件？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

    case "${confirm,,}" in
    y | yes)
        echo -e ""
        echo -e "正在删除 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        rm -rf ./*
        find . -maxdepth 1 -name ".*" ! -name "." ! -name ".." -exec rm -rf {} + 2>/dev/null
        echo -e "${gl_lv}删除完成${gl_bai}"
        ;;
    n | no | "")
        echo -e ""
        echo -e "${gl_huang}操作已取消${gl_bai}"
        ;;
    0) cancel_return; return 2 ;;
    *)
        echo -e "${gl_bai}错误：请输入 ${gl_lv}y ${gl_bai}或 ${gl_hong}N${gl_bai}"
        exit 1
        ;;
    esac

    popd >/dev/null
}

# ========== 新增：下载文件到本地函数 ==========
rz_download_files_to_local() {
    # 默认目录为当前目录
    local target_dir="${1:-.}"
    local show_hidden=0
    install lrzsz
    
    # 先显示目录内容
    echo -e ""
    echo -e "${gl_zi}>>> 下载文件到本地 (sz)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 如果没有指定目录参数，让用户选择
    if [[ $# -eq 0 ]]; then
        echo -e "${gl_bai}当前目录: ${gl_huang}$(pwd)${gl_bai}"
        echo -e "${gl_hui}输入完整路径或相对路径，回车使用当前目录${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        read -r -e -p "$(echo -e "${gl_bai}请输入目录路径(${gl_huang}0${gl_bai}返回): ")" user_input
        
        [ "$user_input" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
        
        if [[ -n "$user_input" ]]; then
            target_dir="$user_input"
        fi
    fi
    
    # 检查目录是否存在
    if [[ ! -d "$target_dir" ]]; then
        log_error "目录不存在: $target_dir"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 进入目标目录
    cd "$target_dir" || {
        log_error "无法进入目录: $target_dir"
        exit_animation    # 即将退出动画
        return 1
    }
    
    clear
    # 显示文件列表
    if ! list_files "." "0" 2; then
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    echo -e "${gl_bai}支持的输入方式:${gl_bai}"
    echo -e "  ${gl_bufan}• ${gl_bai}序号: ${gl_huang}1${gl_bai}, ${gl_huang}1 3 5${gl_bai}, ${gl_huang}1-5${gl_bai}"
    echo -e "  ${gl_bufan}• ${gl_bai}文件名: ${gl_huang}file.txt${gl_bai}, ${gl_huang}file1.txt file2.log${gl_bai}"
    echo -e "  ${gl_bufan}• ${gl_bai}通配符: ${gl_huang}*.txt${gl_bai}, ${gl_huang}file*.log${gl_bai}, ${gl_huang}config.*${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    read -r -e -p "$(echo -e "${gl_bai}请输入文件选择(${gl_huang}0${gl_bai}返回): ")" user_input
    
    [ "$user_input" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
    
    if [[ -z "$user_input" ]]; then
        log_error "请输入有效的选择"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    local selected_files=()
    local all_files=("${LIST_FILES_ARRAY[@]}")
    local total_count="$LIST_FILES_COUNT"
    
    # 自动判断输入类型
    if [[ "$user_input" =~ ^[0-9]+(-[0-9]+)?$ ]] || [[ "$user_input" =~ ^[0-9]+(\ [0-9]+)*$ ]]; then
        # 情况1: 序号输入（单个、范围、空格分隔）
        process_sequential_input() {
            local input="$1"
            local selected_indices=()
            
            if [[ "$input" =~ ^[0-9]+$ ]]; then
                # 单个数字
                selected_indices+=("$input")
            elif [[ "$input" =~ ^[0-9]+-[0-9]+$ ]]; then
                # 范围
                local start=$(echo "$input" | cut -d'-' -f1)
                local end=$(echo "$input" | cut -d'-' -f2)
                for ((i=start; i<=end; i++)); do
                    selected_indices+=("$i")
                done
            else
                # 多个用空格分隔
                read -ra selected_indices <<< "$input"
            fi
            
            # 验证并收集文件
            for idx in "${selected_indices[@]}"; do
                local file_idx=$((idx - 1))
                if [[ $file_idx -ge 0 && $file_idx -lt $total_count ]]; then
                    selected_files+=("${all_files[$file_idx]}")
                else
                    log_warn "忽略无效的文件序号: $idx"
                fi
            done
        }
        
        process_sequential_input "$user_input"
        
    elif [[ "$user_input" =~ \* ]] || [[ "$user_input" =~ \? ]] || [[ "$user_input" =~ \[.*\] ]]; then
        # 情况2: 包含通配符
        echo -e "${gl_bai}使用通配符匹配文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        
        # 使用find查找匹配的文件
        while IFS= read -r -d $'\0' file; do
            local filename=$(basename "$file")
            selected_files+=("$filename")
        done < <(find . -maxdepth 1 -type f -name "$user_input" -print0 2>/dev/null)
        
        # 如果没有找到文件，尝试查找目录
        if [[ ${#selected_files[@]} -eq 0 ]]; then
            while IFS= read -r -d $'\0' file; do
                local filename=$(basename "$file")
                selected_files+=("$filename")
            done < <(find . -maxdepth 1 -type d -name "$user_input" -print0 2>/dev/null)
        fi
        
    else
        # 情况3: 文件名（可能多个用空格分隔）
        process_filename_input() {
            local input="$1"
            read -ra name_array <<< "$input"
            
            for name in "${name_array[@]}"; do
                if [[ -e "$name" ]]; then
                    selected_files+=("$name")
                else
                    # 尝试在当前目录文件列表中查找
                    local found=0
                    for file in "${all_files[@]}"; do
                        if [[ "$file" == "$name" ]]; then
                            selected_files+=("$file")
                            found=1
                            break
                        fi
                    done
                    
                    if [[ $found -eq 0 ]]; then
                        log_warn "文件不存在: $name"
                    fi
                fi
            done
        }
        
        process_filename_input "$user_input"
    fi
    
    if [[ ${#selected_files[@]} -eq 0 ]]; then
        log_error "没有找到匹配的文件"
        echo -e "${gl_bai}输入格式说明:${gl_bai}"
        echo -e "  ${gl_hui}• 序号: 1-5 (范围), 1 3 5 (多个)${gl_bai}"
        echo -e "  ${gl_hui}• 文件名: file.txt, config.ini${gl_bai}"
        echo -e "  ${gl_hui}• 通配符: *.txt, file*.log${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
        read -r -n 1 -s -r -p ""
        return 1
    fi
    
    # 去重
    local unique_files=()
    for file in "${selected_files[@]}"; do
        if [[ ! " ${unique_files[@]} " =~ " $file " ]]; then
            unique_files+=("$file")
        fi
    done
    selected_files=("${unique_files[@]}")
    
    # 显示选择的文件
    echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}找到 ${gl_huang}${#selected_files[@]}${gl_bai} 个匹配文件:${gl_bai}"
    for i in "${!selected_files[@]}"; do
        local file="${selected_files[$i]}"
        local file_size
        if [[ -d "$file" ]]; then
            file_size=$(du -sh "$file" 2>/dev/null | cut -f1 || echo "目录")
        else
            file_size=$(du -h "$file" 2>/dev/null | cut -f1 || echo "未知")
        fi
        
        local file_type=""
        if [[ -d "$file" ]]; then
            file_type="${gl_zi}[目录]${gl_bai}"
        elif [[ "$file" == .* ]]; then
            file_type="${gl_hui}[隐藏]${gl_bai}"
        else
            file_type="${gl_lv}[文件]${gl_bai}"
        fi
        
        echo -e "  ${gl_bufan}$((i+1)). ${gl_bai}${file_type} $file ${gl_huang}(${file_size})${gl_bai}"
    done
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    read -r -e -p "$(echo -e "${gl_bai}确认下载这些文件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    
    case "$confirm" in
    [Yy])
        # 检查 sz 命令是否可用
        if ! command -v sz &>/dev/null; then
            log_error "未找到 sz 命令，请安装 lrzsz 包"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
            read -r -n 1 -s -r -p ""
            return 1
        fi

        echo -e "${gl_huang}请在本地客户端接收文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        
        for i in {3..1}; do
            echo -ne "${gl_huang}将在 ${gl_lv}$i${gl_bai} 秒后开始传输 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\r"
            sleep_fractional 1
        done
        echo ""

        echo -e "${gl_bai}开始传输 ${gl_huang}${#selected_files[@]}${gl_bai} 个文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        if sz "${selected_files[@]}"; then
            echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_ok "✅ 文件下载成功!"
            echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
            read -r -n 1 -s -r -p ""
        else
            local exit_code=$?
            echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            if [[ $exit_code -eq 130 ]]; then
                log_info "下载被用户取消"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                read -r -n 1 -s -r -p ""
            else
                log_warn "文件传输可能被中断 (退出码: $exit_code)"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                read -r -n 1 -s -r -p ""
            fi
        fi
        ;;
    [Nn]|"")
        log_info "取消下载操作"
        ;;
    0) cancel_return; return 1 ;;
    *) handle_y_n ;;        # 无效的输入,请输入(y或N)。
    esac
    return 0
}

# 函数_文件搜索并处理
manual_file_search_and_process() {
    # 检查是否提供了搜索路径
    local search_path="${1:-.}"
    # 检查当前目录是否为空，如果为空则显示提示并返回错误
    check_directory_empty "." "文件搜索并处理" "true" || return

    clear

    if [ -z "$(ls -A 2>/dev/null)" ]; then
        echo -e "${gl_huang}>>> 当前目录文件列表：${gl_bai}(${gl_lv}$(pwd)${gl_bai})"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}当前目录为空${gl_bai}"
    else
        list_dir_colorful 0 4
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e ""
    echo -e "${gl_zi}>>> 文件搜索并处理${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 交互式获取文件名或模式
    echo -e "${gl_huang}文件搜索支持以下模式：${gl_bai}"
    echo -e "${gl_bai}1. 精确文件名: ${gl_lv}example.txt${gl_bai}"
    echo -e "${gl_bai}2. 通配符搜索: ${gl_lv}*.txt${gl_bai} 或 ${gl_lv}test-*.jpg${gl_bai}"
    echo -e "${gl_bai}3. 部分匹配: ${gl_lv}*test*${gl_bai} 或 ${gl_lv}*.log*${gl_bai}"
    echo -e "${gl_bai}4. 模糊搜索: ${gl_lv}example${gl_bai} (包含此关键词的所有文件)"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请输入要搜索的文件名、模式或关键词 (${gl_huang}0${gl_bai}返回): ")" pattern

    case "$pattern" in
    0) cancel_return; return 1 ;;
    esac

    if [[ -z "$pattern" ]]; then
        log_error "搜索模式不能为空！"
        return 1
    fi

    # 查找符合条件的文件
    echo -e ""
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}正在搜索模式 ${gl_huang}${pattern}${gl_bai} 的文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    local files=()

    # 先尝试通配符搜索
    if [[ "$pattern" =~ [\*\?\[\]] ]]; then
        # 包含通配符，使用通配符搜索
        while IFS= read -r -d $'\0' file; do
            files+=("$file")
        done < <(find "$search_path" -name "$pattern" -type f -print0 2>/dev/null)
    else
        # 不包含通配符，尝试模糊搜索
        echo -e "${gl_bai}使用模糊搜索模式: 搜索包含 \"${gl_huang}${pattern}${gl_bai}\" 的文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 使用 find 的 -iname 进行不区分大小写的模糊搜索
        while IFS= read -r -d $'\0' file; do
            files+=("$file")
        done < <(find "$search_path" -type f -iname "*${pattern}*" -print0 2>/dev/null)

        # 如果没找到，尝试使用 grep 进行内容搜索
        if [[ ${#files[@]} -eq 0 ]]; then
            echo -e "${gl_bai}尝试深度模糊搜索 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            while IFS= read -r -d $'\0' file; do
                files+=("$file")
            done < <(find "$search_path" -type f -exec grep -l "$pattern" {} \; -print0 2>/dev/null)
        fi
    fi

    # 检查是否找到文件
    if [[ ${#files[@]} -eq 0 ]]; then
        log_warn "未找到任何匹配 ${gl_bufan}${pattern}${gl_bai} 的文件！"

        # 提供扩展建议
        echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}搜索建议：${gl_bai}"
        echo -e "${gl_bai}1. 尝试不同的关键词或模式"
        echo -e "${gl_bai}2. 使用通配符: ${gl_lv}*${pattern}*${gl_bai} 或 ${gl_lv}${pattern}*${gl_bai}"
        echo -e "${gl_bai}3. 尝试搜索当前目录: ${gl_lv}.${gl_bai}"
        echo -e "${gl_bai}4. 使用更广泛的搜索路径"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        break_end
        return 1
    fi

    # 对搜索结果进行排序（按文件名）
    mapfile -t sorted_files < <(printf '%s\n' "${files[@]}" | sort)
    files=("${sorted_files[@]}")

    # ========== 新增：处理菜单循环 ==========
    while true; do
        clear
        echo -e "${gl_huang}>>> 找到 ${gl_lv}${#files[@]} ${gl_huang}个匹配 ${gl_bufan}${pattern}${gl_huang} 的文件:${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 显示文件列表
        for i in "${!files[@]}"; do
            # 获取绝对路径
            local abs_path=$(readlink -f "${files[$i]}" 2>/dev/null || realpath "${files[$i]}" 2>/dev/null || echo "${files[$i]}")
            local file_size=$(du -h "${files[$i]}" 2>/dev/null | cut -f1)
            local file_date=$(date -r "${files[$i]}" "+%Y-%m-%d %H:%M" 2>/dev/null)

            # 截断过长的路径（超过60字符显示前30 后30）
            if [[ ${#abs_path} -gt 60 ]]; then
