                    echo -e "${gl_bai}文件名: ${gl_lv}$(basename "$info_file")${gl_bai}"
                    echo -e "${gl_bai}完整路径: ${gl_bufan}$info_file${gl_bai}"
                    echo -e "${gl_bai}文件大小: ${gl_zi}$(du -h "$info_file" 2>/dev/null | cut -f1)${gl_bai}"
                    echo -e "${gl_bai}文件类型: ${gl_bufan}$(file -b "$info_file" 2>/dev/null)${gl_bai}"
                    echo -e "${gl_bai}权限: ${gl_lv}$(stat -c "%A" "$info_file" 2>/dev/null)${gl_bai}"
                    echo -e "${gl_bai}所有者: ${gl_huang}$(stat -c "%U:%G" "$info_file" 2>/dev/null)${gl_bai}"
                    echo -e "${gl_bai}创建时间: ${gl_zi}$(stat -c "%w" "$info_file" 2>/dev/null)${gl_bai}"
                    echo -e "${gl_bai}修改时间: ${gl_zi}$(stat -c "%y" "$info_file" 2>/dev/null)${gl_bai}"
                    echo -e "${gl_bai}访问时间: ${gl_zi}$(stat -c "%x" "$info_file" 2>/dev/null)${gl_bai}"
                else
                    # 如果 stat 不可用，使用 ls
                    ls -la "$info_file" 2>/dev/null
                fi

                # 如果是文本文件，显示编码
                if [[ "$info_file" =~ \.(txt|sh|bash|zsh|py|js|html|css|json|xml|md|yml|yaml)$ ]]; then
                    echo -e "${gl_bai}文件编码: ${gl_lv}$(file -bi "$info_file" 2>/dev/null | grep -oP 'charset=\K[^;]+' || echo "未知")${gl_bai}"
                fi

                echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                read -r -n 1 -s -r -p ""
            else
                echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                handle_y_n        # 无效的输入,请输入(y或N)。
                continue # 返回菜单
            fi
            continue # 查看完成后返回菜单
            ;;
        9) # 批量重命名文件
            echo -e ""
            echo -e "${gl_zi}>>> 批量重命名文件${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}重命名模式：${gl_bai}"
            echo -e "${gl_bufan}1. ${gl_bai}添加前缀${gl_bai}        ${gl_bufan}2. ${gl_bai}添加后缀${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}3. ${gl_bai}替换字符串${gl_bai}      ${gl_bufan}4. ${gl_bai}序号重命名${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}请选择重命名模式 (${gl_huang}0${gl_bai}返回): ")" rename_mode

            case "$rename_mode" in
            0) cancel_return "处理搜索到的文件"; continue ;;
            1) # 添加前缀
                read -r -e -p "$(echo -e "${gl_bai}请输入要添加的前缀: ")" prefix
                local rename_count=0
                for file in "${files[@]}"; do
                    local filename=$(basename "$file")
                    local dir=$(dirname "$file")
                    local newname="${dir}/${prefix}${filename}"
                    if mv "$file" "$newname" 2>/dev/null; then
                        log_ok "已重命名: ${gl_bufan}${filename}${gl_bai} -> ${gl_lv}${prefix}${filename}${gl_bai}"
                        ((rename_count++))
                    fi
                done
                ;;
            2) # 添加后缀
                read -r -e -p "$(echo -e "${gl_bai}请输入要添加的后缀 (不含扩展名): ")" suffix
                local rename_count=0
                for file in "${files[@]}"; do
                    local filename=$(basename "$file")
                    local dir=$(dirname "$file")
                    local ext="${filename##*.}"
                    local name="${filename%.*}"
                    local newname="${dir}/${name}${suffix}.${ext}"
                    if [[ "$filename" == "$ext" ]]; then
                        newname="${dir}/${filename}${suffix}"
                    fi
                    if mv "$file" "$newname" 2>/dev/null; then
                        log_ok "已重命名: ${gl_bufan}${filename}${gl_bai} -> ${gl_lv}$(basename "$newname")${gl_bai}"
                        ((rename_count++))
                    fi
                done
                ;;
            3) # 替换字符串
                read -r -e -p "$(echo -e "${gl_bai}请输入要替换的字符串: ")" old_str
                read -r -e -p "$(echo -e "${gl_bai}请输入替换为的字符串: ")" new_str
                local rename_count=0
                for file in "${files[@]}"; do
                    local filename=$(basename "$file")
                    local dir=$(dirname "$file")
                    local newname="${dir}/${filename//$old_str/$new_str}"
                    if [[ "$filename" != "$(basename "$newname")" ]]; then
                        if mv "$file" "$newname" 2>/dev/null; then
                            log_ok "已重命名: ${gl_bufan}${filename}${gl_bai} -> ${gl_lv}$(basename "$newname")${gl_bai}"
                            ((rename_count++))
                        fi
                    fi
                done
                ;;
            4) # 序号重命名
                read -r -e -p "$(echo -e "${gl_bai}请输入文件名模板 (如: file-###.txt, ### 将被替换为序号): ")" template
                local rename_count=0
                local idx=1
                for file in "${files[@]}"; do
                    local dir=$(dirname "$file")
                    local ext="${file##*.}"
                    local newname="${dir}/${template//###/$(printf "%03d" $idx)}"
                    if [[ "$template" != *"###"* ]]; then
                        newname="${dir}/${template}_${idx}.${ext}"
                    fi
                    if mv "$file" "$newname" 2>/dev/null; then
                        log_ok "已重命名: ${gl_bufan}$(basename "$file")${gl_bai} -> ${gl_lv}$(basename "$newname")${gl_bai}"
                        ((rename_count++))
                    fi
                    ((idx++))
                done
                ;;
            *) handle_invalid_input ;;
            esac

            if [[ $rename_count -gt 0 ]]; then
                log_ok "成功重命名 ${rename_count} 个文件"
                # 重新搜索以更新文件列表
                files=()
                while IFS= read -r -d $'\0' file; do
                    files+=("$file")
                done < <(find "$search_path" -name "$pattern" -type f -print0 2>/dev/null)
                mapfile -t sorted_files < <(printf '%s\n' "${files[@]}" | sort)
                files=("${sorted_files[@]}")
            fi
            echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
            read -r -n 1 -s -r -p ""
            continue
            ;;
        10) # 文件权限批量修改
            echo -e ""
            echo -e "${gl_zi}>>> 批量修改文件权限${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}权限设置：${gl_bai}"
            echo -e "${gl_bai}1. ${gl_lv}755${gl_bai} (rwxr-xr-x) - 可执行文件"
            echo -e "${gl_bai}2. ${gl_lv}644${gl_bai} (rw-r--r--) - 普通文件"
            echo -e "${gl_bai}3. ${gl_lv}600${gl_bai} (rw-------) - 敏感文件"
            echo -e "${gl_bai}4. ${gl_lv}777${gl_bai} (rwxrwxrwx) - 完全开放"
            echo -e "${gl_bai}5. ${gl_lv}自定义${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}请选择权限模式 (${gl_huang}0${gl_bai}返回): ")" perm_mode

            local chmod_val=""
            case "$perm_mode" in
            0) cancel_return "处理搜索到的文件"; continue ;;
            1) chmod_val="755" ;;
            2) chmod_val="644" ;;
            3) chmod_val="600" ;;
            4) chmod_val="777" ;;
            5)
                read -r -e -p "$(echo -e "${gl_bai}请输入权限值 (如: 755, 644): ")" chmod_val
                ;;
            *)
                handle_invalid_input
                continue
                ;;
            esac

            if [[ -n "$chmod_val" ]]; then
                local chmod_count=0
                for file in "${files[@]}"; do
                    if chmod "$chmod_val" "$file" 2>/dev/null; then
                        log_info "已修改权限: ${gl_bufan}$(basename "$file")${gl_bai} -> ${gl_lv}$chmod_val${gl_bai}"
                        ((chmod_count++))
                    else
                        log_error "修改失败: ${gl_bufan}$file${gl_bai}"
                    fi
                done
                if [[ $chmod_count -gt 0 ]]; then
                    log_ok "成功修改 ${chmod_count}/${#files[@]} 个文件的权限"
                fi
            fi
            echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
            read -r -n 1 -s -r -p ""
            continue
            ;;
        11) # 切换到文件目录
            echo -e ""
            echo -e "${gl_zi}>>> 切换到文件所在目录${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}请输入要切换目录的文件编号 (${gl_huang}0${gl_bai}返回): ")" idx

            case "$idx" in
            0) cancel_return "处理搜索到的文件"; continue ;;
            esac

            local file_idx=$((idx - 1))
            if [[ $file_idx -ge 0 && $file_idx -lt ${#files[@]} ]]; then
                local target_file="${files[$file_idx]}"
                # 获取绝对路径
                local abs_path=$(readlink -f "$target_file" 2>/dev/null || realpath "$target_file" 2>/dev/null || echo "$target_file")
                local target_dir=$(dirname "$abs_path")

                if cd "$target_dir" 2>/dev/null; then
                    log_ok "已切换到目录: ${gl_lv}$target_dir${gl_bai}"
                else
                    log_error "切换目录失败: ${gl_huang}$target_dir${gl_bai}"
                fi
            else
                log_error "无效的文件编号！"
            fi
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            list_dir_colorful 0 4
            continue # 返回菜单
            ;;
        12) rz_download_files_to_local; continue ;;             # 下载文件到本地
        13) linux_file "." "处理搜索到的文件" "处理搜索到的文件";; # 文件管理工具
        14) image_converter_main "处理搜索到的文件" ;;            # 图片格式转换工具
        0) cancel_return; break ;;                              # 返回上一级选单
        00 | 000 | 0000) exit_script ;;
        *) handle_invalid_input ;;
        esac
    done
    # ========== 循环结束 ==========

    return 0
}

# 函数_文件去重工具
remove_duplicate_files() {
    # 默认设置
    local search_path="."
    local method="md5"
    local total_files_count=0
    local duplicate_files_count=0
    local total_duplicate_size=0
    declare -gA duplicate_groups

    # 显示主菜单
    while true; do

        # 检查当前目录是否为空，如果为空则显示提示并返回错误
        check_directory_empty "." "文件去重工具" "true" || return

        clear
        # 显示当前目录
        if [ -z "$(ls -A "$search_path" 2>/dev/null)" ]; then
            echo -e "${gl_huang}当前目录为空${gl_bai}"
        else
            cd ${search_path} && list_dir_colorful 0 4
        fi
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e ""
        echo -e "${gl_zi}>>> 文件去重工具${gl_bai}"

        # echo -e "${gl_bai}当前去重方法: ${gl_huang}${method}${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}扫描重复文件      ${gl_bufan}2.  ${gl_bai}交互式删除重复文件"
        echo -e "${gl_bufan}3.  ${gl_bai}自动删除重复文件  ${gl_bufan}4.  ${gl_bai}切换去重方法 (当前: ${gl_lv}${method}${gl_bai})"
        echo -e "${gl_bufan}5.  ${gl_bai}设置搜索路径      ${gl_bufan}6.  ${gl_bai}查看扫描统计"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单    ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "$(echo -e "${gl_bai}请输入你的选择: ")" choice

        case $choice in
        1) scan_duplicate_files ;;
        2) interactive_remove_duplicates ;;
        3) auto_remove_duplicates ;;
        4) switch_duplicate_method ;;
        5) set_duplicate_search_path ;;
        6) show_scan_statistics ;;
        0) cancel_return; break ;;                        # 返回上一级选单
        00 | 000 | 0000) exit_script ;;
        *) handle_invalid_input ;;
        esac
    done
}

# 扫描重复文件
scan_duplicate_files() {
    echo -e "${gl_bai}正在扫描重复文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e ""

    # 检查必要的命令
    if [[ "$method" == "md5" ]] && ! command -v md5sum &>/dev/null; then
        log_error "md5sum 命令未找到，请安装 coreutils 或使用其他去重方法"
        exit_animation    # 即将退出动画
        return 1
    elif [[ "$method" == "sha1" ]] && ! command -v sha1sum &>/dev/null; then
        log_error "sha1sum 命令未找到，请安装 coreutils 或使用其他去重方法"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 获取重复文件组
    get_duplicate_groups

    echo -e ""
    echo -e "${gl_zi}>>> 重复文件扫描结果${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if [[ ${#duplicate_groups[@]} -eq 0 ]]; then
        log_ok "未发现重复文件！"
        echo -e "${gl_bai}扫描路径: ${gl_lv}${search_path}${gl_bai}"
        echo -e "${gl_bai}去重方法: ${gl_huang}${method}${gl_bai}"
        echo -e "${gl_bai}文件总数: ${gl_lv}${total_files_count}${gl_bai}"
    else
        echo -e "${gl_bai}扫描路径: ${gl_lv}${search_path}${gl_bai}"
        echo -e "${gl_bai}去重方法: ${gl_huang}${method}${gl_bai}"
        echo -e "${gl_bai}文件总数: ${gl_lv}${total_files_count}${gl_bai}"
        echo -e "${gl_bai}重复文件: ${gl_hong}${duplicate_files_count}${gl_bai}"

        if [[ $duplicate_files_count -gt 0 ]]; then
            local duplicate_size_mb=$(echo "scale=2; $total_duplicate_size / 1024 / 1024" | bc 2>/dev/null || echo "0")
            echo -e "${gl_bai}浪费空间: ${gl_hong}${duplicate_size_mb} MB${gl_bai}"
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 显示重复文件组
        local group_count=0
        for checksum in "${!duplicate_groups[@]}"; do
            IFS='|' read -ra files <<<"${duplicate_groups[$checksum]}"
            if [[ ${#files[@]} -gt 1 ]]; then
                group_count=$((group_count + 1))
                echo -e "${gl_huang}第 ${group_count} 组重复文件 (${#files[@]} 个):${gl_bai}"

                for i in "${!files[@]}"; do
                    local file="${files[$i]}"
                    if [[ -f "$file" ]]; then
                        local file_size=$(stat -c%s "$file" 2>/dev/null || echo 0)
                        local size_human=$(numfmt --to=iec --suffix=B "$file_size" 2>/dev/null || echo "${file_size}B")
                        local mtime=$(stat -c "%y" "$file" 2>/dev/null | cut -d'.' -f1 2>/dev/null || echo "未知")

                        if [[ $i -eq 0 ]]; then
                            echo -e "  ${gl_lv}✓ ${file}${gl_bai} (${size_human}, ${mtime}) - ${gl_lv}[保留建议]${gl_bai}"
                        else
                            echo -e "  ${gl_hui}${i}. ${file}${gl_bai} (${size_human}, ${mtime})"
                        fi
                    else
                        echo -e "  ${gl_hong}× ${file}${gl_bai} (文件不存在或无法访问)"
                    fi
                done
                echo -e ""
            fi
        done

        if [[ $group_count -eq 0 ]]; then
            log_ok "未发现重复文件！"
        else
            echo -e "${gl_bai}共发现 ${gl_hong}${group_count}${gl_bai} 组重复文件"
        fi
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
    read -r -n 1 -s -r -p ""
}

# 交互式删除重复文件
interactive_remove_duplicates() {
    echo -e "${gl_bai}正在扫描重复文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e ""

    # 获取重复文件组
    get_duplicate_groups

    if [[ ${#duplicate_groups[@]} -eq 0 ]]; then
        log_ok "未发现重复文件！"
        exit_animation    # 即将退出动画
        return 0
    fi

    local group_keys=("${!duplicate_groups[@]}")
    local total_groups=${#group_keys[@]}
    local current_group=0
    local deleted_count=0
    local skipped_count=0

    for checksum in "${group_keys[@]}"; do
        IFS='|' read -ra files <<<"${duplicate_groups[$checksum]}"

        # 过滤掉不存在的文件
        local valid_files=()
        for file in "${files[@]}"; do
            if [[ -f "$file" ]] && [[ -r "$file" ]]; then
                valid_files+=("$file")
            fi
        done

        if [[ ${#valid_files[@]} -gt 1 ]]; then
            current_group=$((current_group + 1))

            while true; do
                echo -e ""
                echo -e "${gl_zi}>>> 交互式删除重复文件${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_bai}第 ${gl_huang}${current_group}${gl_bai}/${gl_lv}${total_groups}${gl_bai} 组 (${#valid_files[@]} 个重复文件)${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                for i in "${!valid_files[@]}"; do
                    local file="${valid_files[$i]}"
                    if [[ -f "$file" ]]; then
                        local file_size=$(stat -c%s "$file" 2>/dev/null || echo 0)
                        local size_human=$(numfmt --to=iec --suffix=B "$file_size" 2>/dev/null || echo "${file_size}B")
                        local mtime=$(stat -c "%y" "$file" 2>/dev/null | cut -d'.' -f1 2>/dev/null || echo "未知")

                        if [[ $i -eq 0 ]]; then
                            echo -e "${gl_lv}[保留建议]${gl_bai} ${file} (${size_human}, ${mtime})"
                        else
                            echo -e "${gl_hui}[删除候选]${gl_bai} ${file} (${size_human}, ${mtime})"
                        fi
                    else
                        echo -e "${gl_hong}[文件无效]${gl_bai} ${file} (文件不存在或无法访问)"
                    fi
                done

                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_bufan}1.  ${gl_bai}保留第一个，删除其他    ${gl_bufan}2.  ${gl_bai}手动选择保留"
                echo -e "${gl_bufan}3.  ${gl_bai}跳过此组                ${gl_bufan}4.  ${gl_bai}删除全部"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单          ${gl_hong}00. ${gl_bai}退出脚本"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                read -r -e -p "$(echo -e "${gl_bai}请选择操作: ")" action

                case $action in
                1) # 保留第一个，删除其他
                    local keep_file="${valid_files[0]}"
                    local delete_count=0

                    for ((i = 1; i < ${#valid_files[@]}; i++)); do
                        local file="${valid_files[$i]}"
                        if [[ -f "$file" ]] && [[ -w "$file" ]]; then
                            if rm -f "$file"; then
                                delete_count=$((delete_count + 1))
                                deleted_count=$((deleted_count + 1))
                                log_info "已删除: ${gl_bufan}$file${gl_bai}"
                            else
                                log_error "删除失败: ${gl_bufan}$file${gl_bai}"
                            fi
                        else
                            log_warn "无法删除: ${gl_bufan}$file${gl_bai} (权限不足或文件不存在)"
                        fi
                    done

                    if [[ $delete_count -gt 0 ]]; then
                        log_ok "已保留: ${gl_lv}$keep_file${gl_bai}，删除了 ${delete_count} 个重复文件"
                    else
                        log_warn "没有文件被删除"
                    fi
                    echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                    read -r -n 1 -s -r -p ""
                    break
                    ;;
                2) # 手动选择保留
                    echo -e "${gl_bai}请选择要保留的文件 (输入编号 1-${#valid_files[@]})："
                    for i in "${!valid_files[@]}"; do
                        local file="${valid_files[$i]}"
                        if [[ -f "$file" ]]; then
                            local file_size=$(stat -c%s "$file" 2>/dev/null || echo 0)
                            local size_human=$(numfmt --to=iec --suffix=B "$file_size" 2>/dev/null || echo "${file_size}B")
                            echo -e "  ${gl_huang}$((i + 1))${gl_bai}) ${file} (${size_human})"
                        else
                            echo -e "  ${gl_hong}$((i + 1))${gl_bai}) ${file} (文件无效)"
                        fi
                    done

                    read -r -e -p "$(echo -e "${gl_bai}你的选择: ")" keep_index

                    if [[ $keep_index =~ ^[0-9]+$ ]] && [[ $keep_index -ge 1 ]] && [[ $keep_index -le ${#valid_files[@]} ]]; then
                        local keep_file="${valid_files[$((keep_index - 1))]}"
                        local delete_count=0

                        for i in "${!valid_files[@]}"; do
                            if [[ $i -ne $((keep_index - 1)) ]]; then
                                local file="${valid_files[$i]}"
                                if [[ -f "$file" ]] && [[ -w "$file" ]]; then
                                    if rm -f "$file"; then
                                        delete_count=$((delete_count + 1))
                                        deleted_count=$((deleted_count + 1))
                                        log_info "已删除: ${gl_bufan}$file${gl_bai}"
                                    else
                                        log_error "删除失败: ${gl_bufan}$file${gl_bai}"
                                    fi
                                else
                                    log_warn "无法删除: ${gl_bufan}$file${gl_bai}"
                                fi
                            fi
                        done

                        if [[ $delete_count -gt 0 ]]; then
                            log_ok "已保留: ${gl_lv}$keep_file${gl_bai}，删除了 ${delete_count} 个重复文件"
                        else
                            log_warn "没有文件被删除"
                        fi
                    else
                        log_error "无效的选择"
                    fi
                    echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                    read -r -n 1 -s -r -p ""
                    break
                    ;;
                3) # 跳过此组
                    skipped_count=$((skipped_count + 1))
                    log_warn "已跳过第 ${current_group} 组重复文件"
                    echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                    read -r -n 1 -s -r -p ""
                    break
                    ;;
                4) # 删除全部
                    read -r -e -p "$(echo -e "${gl_bai}确认删除此组所有文件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
                    case "$confirm" in
                    [Yy])
                        local delete_count=0
                        for file in "${valid_files[@]}"; do
                            if [[ -f "$file" ]] && [[ -w "$file" ]]; then
                                if rm -f "$file"; then
                                    delete_count=$((delete_count + 1))
                                    deleted_count=$((deleted_count + 1))
                                    log_info "已删除: ${gl_bufan}$file${gl_bai}"
                                else
                                    log_error "删除失败: ${gl_bufan}$file${gl_bai}"
                                fi
                            else
                                log_warn "无法删除: ${gl_bufan}$file${gl_bai}"
                            fi
                        done

                        if [[ $delete_count -gt 0 ]]; then
                            log_ok "已删除此组全部 ${delete_count} 个文件"
                        else
                            log_warn "没有文件被删除"
                        fi
                        ;;
                    [Nn])
                        log_warn "操作已取消"
                        ;;
                    *)
                        handle_y_n        # 无效的输入,请输入(y或N)。
                        ;;
                    esac
                    echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                    read -r -n 1 -s -r -p ""
                    break
                    ;;
                0) cancel_return; break ;;                        # 返回上一级选单
                00 | 000 | 0000) exit_script ;;
                *) handle_invalid_input ;;
                esac
            done
        fi
    done

    echo -e ""
    echo -e "${gl_zi}>>> 交互式删除完成${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}处理组数: ${gl_lv}${current_group}${gl_bai}"
    echo -e "${gl_bai}删除文件: ${gl_lv}${deleted_count}${gl_bai}"
    echo -e "${gl_bai}跳过组数: ${gl_huang}${skipped_count}${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
    read -r -n 1 -s -r -p ""
}

# 自动删除重复文件
auto_remove_duplicates() {
    echo -e "${gl_bai}正在扫描重复文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e ""

    read -r -e -p "$(echo -e "${gl_bai}请选择保留策略: ${gl_bufan}1.${gl_bai}保留最早的  ${gl_bufan}2.${gl_bai}保留最新的  (${gl_huang}0${gl_bai}返回): ")" strategy

    case "$strategy" in
    0) cancel_return; return ;;
    1 | 2) ;;
    *)
        handle_invalid_input
        return
        ;;
    esac

    read -r -e -p "$(echo -e "${gl_bai}确认自动删除重复文件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

    case "$confirm" in
    [Yy]) ;;
    [Nn])
        log_warn "操作已取消"
        exit_animation    # 即将退出动画
        return
        ;;
    *) handle_y_n; return ;;      # 无效的输入,请输入(y或N)。
    esac

    # 获取重复文件组
    get_duplicate_groups

    local deleted_count=0
    local saved_space=0
    local error_count=0

    for checksum in "${!duplicate_groups[@]}"; do
        IFS='|' read -ra files <<<"${duplicate_groups[$checksum]}"
        if [[ ${#files[@]} -gt 1 ]]; then
            # 过滤有效的文件
            local valid_files=()
            for file in "${files[@]}"; do
                if [[ -f "$file" ]] && [[ -r "$file" ]]; then
                    valid_files+=("$file")
                fi
            done

            if [[ ${#valid_files[@]} -gt 1 ]]; then
                # 根据策略确定要保留的文件
                local keep_file="${valid_files[0]}"

                if [[ $strategy -eq 1 ]]; then
                    # 保留最早的（修改时间最旧）
                    local oldest_mtime=$(stat -c "%Y" "${valid_files[0]}" 2>/dev/null || echo 0)
                    for file in "${valid_files[@]:1}"; do
                        local file_mtime=$(stat -c "%Y" "$file" 2>/dev/null || echo 0)
                        if [[ $file_mtime -lt $oldest_mtime ]]; then
                            keep_file="$file"
                            oldest_mtime=$file_mtime
                        fi
                    done
                else
                    # 保留最新的（修改时间最新）
                    local newest_mtime=$(stat -c "%Y" "${valid_files[0]}" 2>/dev/null || echo 0)
                    for file in "${valid_files[@]:1}"; do
                        local file_mtime=$(stat -c "%Y" "$file" 2>/dev/null || echo 0)
                        if [[ $file_mtime -gt $newest_mtime ]]; then
                            keep_file="$file"
                            newest_mtime=$file_mtime
                        fi
                    done
                fi

                # 删除其他文件
                for file in "${valid_files[@]}"; do
                    if [[ "$file" != "$keep_file" ]]; then
                        if [[ -f "$file" ]] && [[ -w "$file" ]]; then
                            local file_size=$(stat -c%s "$file" 2>/dev/null || echo 0)
                            if rm -f "$file"; then
                                deleted_count=$((deleted_count + 1))
                                saved_space=$((saved_space + file_size))
                                log_info "已删除: ${gl_bufan}$file${gl_bai}"
                            else
                                error_count=$((error_count + 1))
                                log_error "删除失败: ${gl_bufan}$file${gl_bai}"
                            fi
                        fi
                    fi
                done
            fi
        fi
    done

    # clear
    echo -e ""
    if [[ $deleted_count -eq 0 ]] && [[ $error_count -eq 0 ]]; then
        log_ok "未发现需要删除的重复文件"
    else
        local saved_mb=$(echo "scale=2; $saved_space / 1024 / 1024" | bc 2>/dev/null || echo "0")
        log_ok "自动删除完成！"
        echo -e "${gl_bai}删除文件数: ${gl_lv}${deleted_count}${gl_bai}"
        echo -e "${gl_bai}节省空间: ${gl_lv}${saved_mb} MB${gl_bai}"
        if [[ $error_count -gt 0 ]]; then
            echo -e "${gl_bai}删除失败: ${gl_hong}${error_count}${gl_bai}"
        fi
    fi

    echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
    read -r -n 1 -s -r -p ""
}

# 获取重复文件组（辅助函数）
get_duplicate_groups() {
    # 清空全局变量
    unset duplicate_groups
    declare -gA duplicate_groups
    total_files_count=0
    duplicate_files_count=0
    total_duplicate_size=0

    # 查找所有文件
    local all_files=()
    while IFS= read -r -d $'\0' file; do
        all_files+=("$file")
    done < <(find "$search_path" -type f -print0 2>/dev/null)

    total_files_count=${#all_files[@]}

    if [[ $total_files_count -eq 0 ]]; then
        return
    fi

    # 计算校验和并分组
    for file in "${all_files[@]}"; do
        if [[ ! -f "$file" ]] || [[ ! -r "$file" ]]; then
            continue
        fi

        local checksum
        case "$method" in
        "md5")
            checksum=$(md5sum "$file" 2>/dev/null | cut -d' ' -f1)
            ;;
        "sha1")
            checksum=$(sha1sum "$file" 2>/dev/null | cut -d' ' -f1)
            ;;
        "size")
            checksum=$(stat -c%s "$file" 2>/dev/null || echo 0)
            ;;
        *)
            checksum=$(md5sum "$file" 2>/dev/null | cut -d' ' -f1)
            ;;
        esac

        if [[ -n "$checksum" ]]; then
            if [[ -z "${duplicate_groups[$checksum]}" ]]; then
                duplicate_groups["$checksum"]="$file"
            else
                duplicate_groups["$checksum"]="${duplicate_groups[$checksum]}|$file"
                duplicate_files_count=$((duplicate_files_count + 1))
                local file_size=$(stat -c%s "$file" 2>/dev/null || echo 0)
                total_duplicate_size=$((total_duplicate_size + file_size))
            fi
        fi
    done

    # 移除没有重复的组
    for checksum in "${!duplicate_groups[@]}"; do
        IFS='|' read -ra files <<<"${duplicate_groups[$checksum]}"
        if [[ ${#files[@]} -le 1 ]]; then
            unset duplicate_groups["$checksum"]
        fi
    done
}

# 切换去重方法
switch_duplicate_method() {
    while true; do
        echo -e ""
        echo -e "${gl_zi}>>> 切换去重方法${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}MD5 校验 (最准确，速度较慢)${gl_bai}"
        echo -e "${gl_bufan}2.  ${gl_bai}SHA1 校验 (更安全，速度慢)${gl_bai}"
        echo -e "${gl_bufan}3.  ${gl_bai}文件大小 (最快，可能有误判)${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单${gl_bai}"
        echo -e "${gl_hong}0.  ${gl_bai}退出脚本${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "$(echo -e "${gl_bai}请选择去重方法: ")" method_choice

        case $method_choice in
        1)
            method="md5"
            break
            ;;
        2)
            method="sha1"
            break
            ;;
        3)
            method="size"
            break
            ;;
        0) cancel_return; break ;;                        # 返回上一级选单
        00 | 000 | 0000) exit_script ;;
        *) handle_invalid_input ;;
        esac
    done
}

# 设置搜索路径
set_duplicate_search_path() {
    echo -e ""
    echo -e "${gl_zi}>>> 设置搜索路径${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入搜索路径 (${gl_huang}0${gl_bai}返回当前目录): ")" new_path

    case "$new_path" in
    0) cancel_return; return ;;
    "") cancel_empty; return ;;
    *)
        if [[ -d "$new_path" ]]; then
            search_path="$new_path"
            log_ok "搜索路径已设置为: ${gl_bufan}${search_path}${gl_bai}"
        else
            log_error "路径不存在: ${gl_bufan}$new_path${gl_bai}"
        fi
        ;;
    esac
}

# 查看扫描统计
show_scan_statistics() {
    clear
    echo -e "${gl_zi}>>> 扫描统计信息${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 统计文件信息
    local total_files=0
    local total_size=0
    declare -A file_types
    declare -A size_ranges

    while IFS= read -r -d $'\0' file; do
        if [[ -f "$file" ]] && [[ -r "$file" ]]; then
            total_files=$((total_files + 1))
            local size=$(stat -c%s "$file" 2>/dev/null || echo 0)
            total_size=$((total_size + size))

            # 统计文件类型
            local filename=$(basename "$file")
            if [[ "$filename" == *.* ]]; then
                local ext="${filename##*.}"
                ext=$(echo "$ext" | tr '[:upper:]' '[:lower:]')
                ((file_types["$ext"]++))
            else
                ((file_types["无扩展名"]++))
            fi

            # 统计文件大小范围
            if [[ $size -lt 1024 ]]; then
                ((size_ranges["<1KB"]++))
            elif [[ $size -lt 1048576 ]]; then
                ((size_ranges["1KB-1MB"]++))
            elif [[ $size -lt 10485760 ]]; then
                ((size_ranges["1MB-10MB"]++))
            elif [[ $size -lt 104857600 ]]; then
                ((size_ranges["10MB-100MB"]++))
            else
                ((size_ranges[">100MB"]++))
            fi
        fi
    done < <(find "$search_path" -type f -print0 2>/dev/null)

    echo -e "${gl_bai}扫描路径: ${gl_lv}${search_path}${gl_bai}"
    echo -e "${gl_bai}去重方法: ${gl_huang}${method}${gl_bai}"
    echo -e "${gl_bai}文件总数: ${gl_lv}${total_files}${gl_bai}"

    if [[ $total_files -gt 0 ]]; then
        local total_mb=$(echo "scale=2; $total_size / 1024 / 1024" | bc 2>/dev/null || echo "0")
        echo -e "${gl_bai}总大小: ${gl_lv}${total_mb} MB${gl_bai}"

        # 显示文件大小分布
        echo -e "${gl_bai}文件大小分布:${gl_bai}"
        for range in "<1KB" "1KB-1MB" "1MB-10MB" "10MB-100MB" ">100MB"; do
            local count=${size_ranges["$range"]:-0}
            if [[ $count -gt 0 ]]; then
                local percentage=$((count * 100 / total_files))
                echo -e "  ${gl_huang}${range}${gl_bai}: ${gl_lv}${count}${gl_bai} 个 (${percentage}%)"
            fi
        done

        # 显示主要文件类型
        echo -e "${gl_bai}主要文件类型:${gl_bai}"
        local type_count=0
        for ext in "${!file_types[@]}"; do
            local count=${file_types["$ext"]}
            if [[ $count -gt 0 ]]; then
                local percentage=$((count * 100 / total_files))
                echo -e "  ${gl_huang}${ext}${gl_bai}: ${gl_lv}${count}${gl_bai} 个 (${percentage}%)"
                type_count=$((type_count + 1))
                if [[ $type_count -ge 10 ]]; then
                    echo -e " ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} 和其他 $((${#file_types[@]} - 10)) 种类型${gl_bai}"
                    break
                fi
            fi
        done
    else
        log_warn "未找到任何文件"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 文件预览工具函数
preview_file_content() {
    # 获取当前目录所有文件
    local files_in_dir=()
    local file_count=0
    echo -e ""
    if [[ $file_count -eq 0 ]]; then
        echo -e "${gl_huang}当前目录为空${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi
    clear
    echo -e "${gl_zi}>>> 文件预览工具${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 使用 nullglob 避免通配符不匹配时报错
    shopt -s nullglob

    # 获取当前目录所有非隐藏文件
    for f in *; do
        if [[ -f "$f" ]]; then
            files_in_dir+=("$f")
            ((file_count++))
        fi
    done

    # 计算最长文件名长度（用于动态调整列宽）
    local max_filename_len=0
    for f in "${files_in_dir[@]}"; do
        local len=${#f}
        if [[ $len -gt $max_filename_len ]]; then
            max_filename_len=$len
        fi
    done

    # 文件名列宽度 = 最长文件名 + 4个英文字符间隔
    local filename_col_width=$((max_filename_len + 4))

    # 分页显示文件列表
    local page_size=20
    local current_page=0
    local total_pages=$(((file_count + page_size - 1) / page_size))

    while true; do
        clear
        echo -e "${gl_zi}>>> 文件预览工具${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_lv}第 $((current_page + 1))/$total_pages 页${gl_bai} | ${gl_lv}共 $file_count 个文件${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 计算当前页的起始和结束索引
        local start_index=$((current_page * page_size))
        local end_index=$((start_index + page_size - 1))
        if [[ $end_index -ge $file_count ]]; then
            end_index=$((file_count - 1))
        fi

        # 显示当前页的文件
        for ((i = start_index; i <= end_index; i++)); do
            local file="${files_in_dir[$i]}"
            local file_size=$(du -h "$file" 2>/dev/null | cut -f1)
            local file_date=$(date -r "$file" "+%Y-%m-%d %H:%M" 2>/dev/null)

            # 文件类型图标
            local icon="📄"
            if [[ "$file" == *.sh ]] || [[ "$file" == *.bash ]]; then
                icon="📜"
            elif [[ "$file" == *.txt ]] || [[ "$file" == *.md ]]; then
                icon="📝"
            elif [[ "$file" == *.png ]] || [[ "$file" == *.jpg ]] || [[ "$file" == *.jpeg ]] || [[ "$file" == *.gif ]]; then
                icon="🖼️"
            elif [[ "$file" == *.zip ]] || [[ "$file" == *.tar ]] || [[ "$file" == *.gz ]]; then
                icon="📦"
            fi

            # 判断是否需要截断（超过终端宽度时截断，这里设定最大显示宽度为终端宽度-30）
            local term_width=$(tput cols 2>/dev/null || echo 100)
            local max_display_len=$((term_width - 50))
            
            if [[ ${#file} -gt $max_display_len && $max_display_len -gt 40 ]]; then
                # 截断并添加彩色省略号
                local part_len=$((max_display_len / 2 - 2))
                local part1="${file:0:$part_len}"
                local part2="${file: -$part_len}"
                # 计算截断后的填充宽度，保持对齐
                local display_width=$((part_len * 2 + 3))  # 3个彩色点
                local padding=$((filename_col_width - display_width))
                [[ $padding -lt 0 ]] && padding=0
                
                printf "${gl_huang}%3d.${gl_bai} ${gl_zi}%s ${gl_lv}%s ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}%*s${gl_huang}%8s${gl_bai}    ${gl_zi}%s${gl_bai}\n" \
                    $((i + 1)) \
                    "$icon" \
                    "$part1" \
                    "$part2" \
                    "$padding" "" \
                    "${file_size:-N/A}" \
                    "${file_date:-N/A}"
            else
                # 未截断，使用动态宽度保持对齐
                printf "${gl_huang}%3d${gl_bai}. ${gl_zi}%s ${gl_lv}%-*s${gl_bai}${gl_huang}%8s${gl_bai}    ${gl_zi}%s${gl_bai}\n" \
                    $((i + 1)) \
                    "$icon" \
                    "$filename_col_width" \
                    "$file" \
                    "${file_size:-N/A}" \
                    "${file_date:-N/A}"
            fi
        done

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}操作: ${gl_huang}数字${gl_lv}=${gl_bai}选择文件 ${gl_hong}| ${gl_huang}n${gl_bai}/${gl_huang}p${gl_lv}=${gl_bai}翻页 ${gl_hong}| ${gl_huang}q${gl_bai}/${gl_haung}0${gl_lv}=${gl_bai}返回"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        if [[ $total_pages -gt 1 ]]; then
            echo -e "  ${gl_lv}翻页控制${gl_bai}: [${gl_huang}n${gl_bai}下一页] [${gl_huang}p${gl_bai}上一页] [${gl_huang}q${gl_bai}返回]"
        fi

        read -r -e -p "$(echo -e "${gl_bai}请选择 (${gl_lv}1${gl_bai}-${gl_huang}$file_count${gl_bai}) 或操作键(${gl_huang}0${gl_bai}返回): ")" input

        # 处理翻页命令
        case "$input" in
        n | N)
            if [[ $((current_page + 1)) -lt $total_pages ]]; then
                ((current_page++))
            else
                log_warn "已经是最后一页"
                sleep_fractional 0.5
            fi
            continue
            ;;
        p | P)
            if [[ $current_page -gt 0 ]]; then
                ((current_page--))
            else
                log_warn "已经是第一页"
                sleep_fractional 0.5
            fi
            continue
            ;;
        q | Q | 0) cancel_return; break ;;
        esac

        # 检查是否为数字
        if [[ ! "$input" =~ ^[0-9]+$ ]]; then
            log_error "请输入有效的数字！"
            exit_animation    # 即将退出动画
            continue
        fi

        local idx="$input"
        local file_idx=$((idx - 1))

        if [[ $file_idx -ge 0 && $file_idx -lt $file_count ]]; then
            local preview_file="${files_in_dir[$file_idx]}"
            clear
            echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}文件: ${gl_huang}$preview_file${gl_bai}"
            echo -e "${gl_bai}路径: ${gl_huang}$(pwd)/$preview_file${gl_bai}"
            echo -e "${gl_bai}文件大小: ${gl_lv}$(du -h "$preview_file" 2>/dev/null | cut -f1)${gl_bai}"
            echo -e "${gl_bai}最后修改: ${gl_zi}$(date -r "$preview_file" "+%Y-%m-%d %H:%M:%S" 2>/dev/null)${gl_bai}"
            echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            # 获取文件类型
            local file_type=$(file -b "$preview_file" 2>/dev/null)
            echo -e "${gl_bai}文件类型: ${gl_bufan}${file_type:-未知}${gl_bai}"

            # 获取权限信息
            local permissions=$(ls -la "$preview_file" 2>/dev/null | awk '{print $1}')
            echo -e "${gl_bai}文件权限: ${gl_zi}$permissions${gl_bai}"

            # 获取文件行数和字符数
            local line_count=$(wc -l <"$preview_file" 2>/dev/null)
            local word_count=$(wc -w <"$preview_file" 2>/dev/null)
            local char_count=$(wc -m <"$preview_file" 2>/dev/null)
            echo -e "${gl_bai}统计信息: ${gl_lv}行数:${line_count:-0} 单词:${word_count:-0} 字符:${char_count:-0}${gl_bai}"

            echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            # 根据文件类型选择预览方式
            if [[ "$preview_file" =~ \.(png|jpg|jpeg|gif|bmp|tiff|tif|webp)$ ]]; then
                # 图片文件
                if command -v identify &>/dev/null; then
                    echo -e "${gl_bai}图片信息:${gl_bai}"
                    identify "$preview_file" 2>/dev/null | head -5
                else
                    echo -e "${gl_bai}图片文件 (使用 file 命令获取信息):${gl_bai}"
                    file "$preview_file" 2>/dev/null
                fi
                echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_huang}[提示] 这是图片文件，无法在终端直接预览${gl_bai}"
                echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                exit_animation    # 即将退出动画
                continue
            elif [[ "$preview_file" =~ \.(zip|tar|gz|bz2|xz|7z|rar)$ ]]; then
                # 压缩文件
                echo -e "${gl_bai}压缩文件内容:${gl_bai}"
                if [[ "$preview_file" =~ \.zip$ ]] && command -v unzip &>/dev/null; then
                    unzip -l "$preview_file" 2>/dev/null | head -20
                elif [[ "$preview_file" =~ \.tar$ ]] && command -v tar &>/dev/null; then
                    tar -tvf "$preview_file" 2>/dev/null | head -20
                elif [[ "$preview_file" =~ \.tar\.gz$ ]] && command -v tar &>/dev/null; then
                    tar -tzvf "$preview_file" 2>/dev/null | head -20
                else
                    file "$preview_file" 2>/dev/null
                fi
                echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                exit_animation    # 即将退出动画
                continue
            fi

            # 对于可执行文件和文本文件，显示完整内容
            if [[ -x "$preview_file" ]]; then
                echo -e "${gl_bai}可执行文件 - 显示完整内容:${gl_bai}"
            else
                echo -e "${gl_bai}文件完整内容:${gl_bai}"
            fi

            # 检查文件大小，如果太大则询问是否继续
            local file_size_kb=$(du -k "$preview_file" 2>/dev/null | cut -f1)
            if [[ $file_size_kb -gt 1024 ]]; then
                # 文件超过1MB
                local file_size_mb=$((file_size_kb / 1024))
                echo -e ""
                log_warn "文件较大 (${file_size_mb}MB)，显示全部内容可能需要较长时间"
                echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "$(echo -e "${gl_bai}是否继续显示完整内容？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

                if [[ ! "$confirm" =~ ^[Yy]$ ]]; then
                    log_ok "操作已取消"
                    exit_animation    # 即将退出动画
                    continue
                fi
            fi

            # 分页显示文件内容
            local content_page=0
            local total_lines=$line_count
            local page_size=50
            local total_content_pages=$(((total_lines + page_size - 1) / page_size))

            if [[ $total_lines -eq 0 ]]; then
                log_warn "（空文件）"
            else
                # 逐页显示文件内容
                while true; do
                    clear
                    echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    echo -e "${gl_bai}文件: ${gl_huang}$preview_file${gl_bai}"
                    echo -e "${gl_bai}路径: ${gl_huang}$(pwd)/$preview_file${gl_bai}"
                    echo -e "${gl_bai}行数: ${gl_lv}${total_lines:-0}${gl_bai} | ${gl_bai}当前页: ${gl_lv}$((content_page + 1))/$total_content_pages${gl_bai}"
                    echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                    # 计算当前页的起始和结束行
                    local start_line=$((content_page * page_size + 1))
                    local end_line=$((start_line + page_size - 1))
                    if [[ $end_line -gt $total_lines ]]; then
                        end_line=$total_lines
                    fi

                    # 显示行号和内容
                    echo -e "${gl_bai}行 ${start_line} - ${end_line}:${gl_bai}"
                    echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                    # 使用 sed 显示指定范围的行
                    sed -n "${start_line},${end_line}p" "$preview_file" 2>/dev/null
                    # echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                    if [[ $total_content_pages -gt 1 ]]; then
                        echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        echo -e "${gl_bai}操作: ${gl_lv}n${gl_bai}=下一页 | ${gl_lv}p${gl_bai}=上一页 | ${gl_lv}q${gl_bai}=退出预览"
                        echo -e "${gl_bai}快捷键: ${gl_lv}s${gl_bai}=搜索 | ${gl_lv}h${gl_bai}=文件头 | ${gl_lv}t${gl_bai}=文件尾 | ${gl_lv}j${gl_bai}=跳转到行"
                        echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    fi

                    read -r -e -p "$(echo -e "${gl_bai}请输入你的选择 (${gl_huang}0${gl_bai}返回): ")" content_input

                    case "$content_input" in
                    n | N)
                        if [[ $((content_page + 1)) -lt $total_content_pages ]]; then
                            ((content_page++))
                        else
                            log_warn "已经是最后一页"
                            exit_animation    # 即将退出动画
                        fi
                        ;;
                    p | P)
                        if [[ $content_page -gt 0 ]]; then
                            ((content_page--))
                        else
                            log_warn "已经是第一页"
                            sleep_fractional 0.5
                        fi
                        ;;
                    h | H)
                        content_page=0
                        ;;
                    t | T)
                        if [[ $total_content_pages -gt 0 ]]; then
                            content_page=$((total_content_pages - 1))
                        fi
                        ;;
                    j | J)
                        read -r -e -p "$(echo -e "${gl_bai}请输入要跳转的行号 (1-$total_lines): ")" jump_line
                        if [[ "$jump_line" =~ ^[0-9]+$ ]] && [[ $jump_line -ge 1 ]] && [[ $jump_line -le $total_lines ]]; then
                            content_page=$(((jump_line - 1) / page_size))
                        else
                            log_error "无效的行号！"
                            sleep_fractional 1
                        fi
                        ;;
                    s | S)
                        clear
                        echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        echo -e "${gl_bai}搜索文件内容: ${gl_huang}$preview_file${gl_bai}"
                        echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        read -r -e -p "$(echo -e "${gl_bai}请输入搜索关键词: ")" search_term
                        if [[ -n "$search_term" ]]; then
                            echo -e "${gl_bai}搜索 '${gl_huang}${search_term}${gl_bai}' 的结果:${gl_bai}"
                            echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                            grep -n "$search_term" "$preview_file" 2>/dev/null | head -20
                            echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                            echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                            read -r -n 1 -s -r -p ""
                        fi
                        ;;
                    q | Q | 0) cancel_return; break ;;
                    *)
                        if [[ "$content_input" =~ ^[0-9]+$ ]]; then
                            local jump_page=$((content_input - 1))
                            if [[ $jump_page -ge 0 ]] && [[ $jump_page -lt $total_content_pages ]]; then
                                content_page=$jump_page
                            else
                                log_error "无效的页码！"
                                sleep_fractional 1
                            fi
                        fi
                        ;;
                    esac
                done
            fi

            echo -e "${gl_bai}${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_ok "预览结束"
            echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
            read -r -n 1 -s -r -p ""
        else
            log_error "无效的文件编号！"
            sleep_fractional 1
        fi
    done
}

# 函数_脚本管理工具
linux_script_manager() {
    local menu_name="${1:-上一级选单}"
    # 全局变量
    local SCRIPT_DIR="/opt/scripts"
    local SCRIPT_URLS=(
        ["1"]="https://gitee.com/meimolihan/script/raw/master/docker/docker-update-all.sh"
        ["2"]="https://gitee.com/meimolihan/script/raw/master/sh/backup/universal_backup.sh"
    )
    local SCRIPT_NAMES=(
        ["1"]="Docker更新脚本 (docker-update-all.sh)"
        ["2"]="备份文件脚本 (universal_backup.sh)"
    )

    # 函数：显示 Docker 更新脚本下载界面
    show_docker_update_menu() {
        echo -e ""
        echo -e "${gl_zi}>>> 下载Docker更新脚本${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}使用方法：${gl_lv}/root/scripts/docker-update-all.sh /vol1/1000/compose${gl_bai}"
        echo -e "${gl_bai}Compose项目目录：${gl_lv}/vol1/1000/compose${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        download_script "1"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # 函数：显示备份脚本下载界面
    show_backup_menu() {
        echo -e ""
        echo -e "${gl_zi}>>> 下载备份文件脚本${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}使用方法：${gl_lv}/root/scripts/docker-update-all.sh /vol1/1000/compose /vol2/1000/阿里云盘/教程文件/FnOS/backup/compose 7${gl_bai}"
        echo -e "${gl_hong}/vol1/1000/compose${gl_bai}同步到${gl_huang}/vol2/1000/阿里云盘/教程文件/FnOS/backup/compose${gl_bai}保存数量${gl_lv}7"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        download_script "2"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # 初始化脚本目录
    init_script_dir() {
        if [ ! -d "$SCRIPT_DIR" ]; then
            log_info "创建脚本目录: $SCRIPT_DIR"
            mkdir -p "$SCRIPT_DIR"
            chmod 755 "$SCRIPT_DIR"
        fi
    }

    # 下载指定脚本
    download_script() {
        local script_num="$1"
        local url="${SCRIPT_URLS[$script_num]}"
        local script_name=$(basename "$url")
        local target_path="$SCRIPT_DIR/$script_name"

        if [ -z "$url" ]; then
            log_error "无效的脚本编号"
            exit_animation    # 即将退出动画
            return 1
        fi

        log_info "正在下载: ${SCRIPT_NAMES[$script_num]}"

        if wget -q --timeout=10 --tries=2 -O "$target_path" "$url"; then
            chmod +x "$target_path"
            log_ok "下载成功: $script_name"
            return 0
        else
            log_error "下载失败: $script_name"
            rm -f "$target_path" 2>/dev/null
            exit_animation    # 即将退出动画
            return 1
        fi
    }

    # 列出已下载的脚本
    list_downloaded_scripts() {
        local scripts=()
        local i=1

        if [ -d "$SCRIPT_DIR" ]; then
            for script in "$SCRIPT_DIR"/*.sh; do
                if [ -f "$script" ] && [ -x "$script" ]; then
                    local name=$(basename "$script")
                    scripts+=("$name")
                fi
            done
        fi

        # 返回脚本数组
        echo "${scripts[@]}"
    }

    # 显示已下载脚本列表
    show_downloaded_scripts() {
        local scripts=($(list_downloaded_scripts))
        local i=1

        echo -e "${gl_huang}>>> 已保存的脚本${gl_bai}(${gl_lv}$SCRIPT_DIR${gl_bai})"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        if [ ${#scripts[@]} -eq 0 ]; then
            echo -e "${gl_hui}暂无脚本${gl_bai}"
        else
            for script in "${scripts[@]}"; do
                echo -e "${gl_bufan}$i. ${gl_bai}$script"
                ((i++))
            done
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    }

    # 添加到定时任务
    add_to_cron() {
        local scripts=($(list_downloaded_scripts))

        if [ ${#scripts[@]} -eq 0 ]; then
            log_warn "没有可添加到定时任务的脚本"
            exit_animation    # 即将退出动画
            return
        fi

        clear
        echo -e "${gl_huang}>>> 选择要添加到定时任务的脚本${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        local i=1
        for script in "${scripts[@]}"; do
            echo -e "${gl_bufan}$i. ${gl_bai}$script"
            ((i++))
        done
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "$(echo -e "${gl_bai}请输入脚本序号 (${gl_huang}0${gl_bai}返回): ")" choice

        case "$choice" in
        0) cancel_return; return ;;
        [1-9]*)
            if [ "$choice" -le "${#scripts[@]}" ] 2>/dev/null && [ "$choice" -gt 0 ] 2>/dev/null; then
                local selected_script="${scripts[$((choice - 1))]}"
                local full_path="$SCRIPT_DIR/$selected_script"

                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_bai}当前cron表达式示例:${gl_bai}"
                echo -e "${gl_hui}* * * * * 每分钟执行"
                echo -e "${gl_hui}0 * * * * 每小时执行"
                echo -e "${gl_hui}0 2 * * * 每天2点执行"
                echo -e "${gl_hui}0 2 * * 0 每周日2点执行"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                read -r -e -p "$(echo -e "${gl_bai}请输入cron表达式 (${gl_huang}例如: 0 2 * * *${gl_bai}): ")" cron_expr

                if [ -n "$cron_expr" ]; then
                    (
                        crontab -l 2>/dev/null | grep -v " $full_path$"
                        echo "$cron_expr $full_path"
                    ) | crontab -
                    if [ $? -eq 0 ]; then
                        log_ok "已添加定时任务: $selected_script"
                    else
                        log_error "添加定时任务失败"
                    fi
                else
                    log_warn "cron表达式不能为空"
                fi
            else
                handle_invalid_input
            fi
            ;;
        *)
            handle_invalid_input
            ;;
        esac
    }

    # 删除定时任务
    remove_from_cron() {
        clear
        echo -e "${gl_huang}>>> 当前定时任务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        local cron_jobs=$(crontab -l 2>/dev/null | grep "$SCRIPT_DIR" || true)

        if [ -z "$cron_jobs" ]; then
            echo -e "${gl_hui}暂无定时任务${gl_bai}"
        else
            echo "$cron_jobs"
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        if [ -n "$cron_jobs" ]; then
            read -r -e -p "$(echo -e "${gl_bai}确定要删除所有脚本定时任务吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" choice

            case "$choice" in
            [Yy])
                crontab -l 2>/dev/null | grep -v "$SCRIPT_DIR" | crontab -
                if [ $? -eq 0 ]; then
                    log_ok "已删除所有脚本定时任务"
                else
                    log_error "删除定时任务失败"
                fi
                ;;
            [Nn])
                log_info "已取消操作"
                ;;
            *)
                handle_y_n        # 无效的输入,请输入(y或N)。
                ;;
            esac
        fi
    }

    # 执行脚本目录下的脚本
    execute_script() {
        # 检查脚本目录是否存在
        if [ ! -d "$SCRIPT_DIR" ] || [ -z "$(ls -A "$SCRIPT_DIR"/*.sh 2>/dev/null)" ]; then
            log_warn "脚本目录 ${gl_huang}$SCRIPT_DIR${gl_bai} 为空或不存在"
            exit_animation    # 即将退出动画
            return
        fi

        while true; do
            clear
            echo -e "${gl_zi}>>> 执行脚本文件${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            # 列出脚本
            local scripts=()
            local i=1

            for script in "$SCRIPT_DIR"/*.sh; do
                if [ -f "$script" ]; then
                    local script_name=$(basename "$script")
                    scripts+=("$script_name")

                    # 检查执行权限
                    if [ -x "$script" ]; then
                        echo -e "${gl_bufan}$i. ${gl_bai}$script_name ${gl_lv}[可执行]${gl_bai}"
                    else
                        echo -e "${gl_bufan}$i. ${gl_bai}$script_name ${gl_hong}[无执行权限]${gl_bai}"
                    fi
                    ((i++))
                fi
            done

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            # 使用read -e启用行编辑和补全
            read -e -p "$(echo -e "${gl_bai}请输入脚本序号或脚本名 (支持tab补全)(${gl_huang}0${gl_bai}返回): ")" script_input

            # 重置颜色
            echo -e "${gl_bai}"

            case "$script_input" in
            0) cancel_return; return ;;
            [1-9]*)
                # 通过序号选择
                if [ "$script_input" -le "${#scripts[@]}" ] 2>/dev/null && [ "$script_input" -gt 0 ] 2>/dev/null; then
                    local selected_script="${scripts[$((script_input - 1))]}"
                    local script_path="$SCRIPT_DIR/$selected_script"

                    # 检查执行权限
                    if [ ! -x "$script_path" ]; then
                        read -r -e -p "$(echo -e "${gl_bai}脚本无执行权限，是否添加? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" add_perm

                        case "$add_perm" in
                        [Yy] | [Yy][Ee][Ss])
                            chmod +x "$script_path"
                            if [ $? -eq 0 ]; then
                                log_ok "已添加执行权限: $selected_script"
                            else
                                log_error "添加执行权限失败"
                                break_end
                                continue
                            fi
                            ;;
                        *)
                            log_info "已取消"
                            break_end
                            continue
                            ;;
                        esac
                    fi

                    # 执行脚本前的确认
                    read -r -e -p "$(echo -e "${gl_bai}确认要执行脚本 ${gl_huang}$selected_script${gl_bai} 吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_exec

                    case "$confirm_exec" in
                    [Yy] | [Yy][Ee][Ss])
                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        echo -e "${gl_bai}开始执行脚本: ${gl_huang}$selected_script${gl_bai}"
                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                        # 执行脚本
                        bash "$script_path"

                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        echo -e "${gl_lv}脚本执行完成${gl_bai}"
                        break_end
                        ;;
                    *)
                        log_info "已取消执行"
                        break_end
                        ;;
                    esac
                else
                    handle_invalid_input
                fi
                ;;
            *.sh)
                # 通过完整脚本名选择
                if [ -f "$SCRIPT_DIR/$script_input" ]; then
                    local script_path="$SCRIPT_DIR/$script_input"

                    # 检查执行权限
                    if [ ! -x "$script_path" ]; then
                        read -r -e -p "$(echo -e "${gl_bai}脚本无执行权限，是否添加? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" add_perm

                        case "$add_perm" in
                        [Yy] | [Yy][Ee][Ss])
                            chmod +x "$script_path"
                            if [ $? -eq 0 ]; then
                                log_ok "已添加执行权限: $script_input"
                            else
                                log_error "添加执行权限失败"
                                break_end
                                continue
                            fi
                            ;;
                        *)
                            log_info "已取消"
                            break_end
                            continue
                            ;;
                        esac
                    fi

                    # 执行脚本前的确认
                    read -r -e -p "$(echo -e "${gl_bai}确认要执行脚本 ${gl_huang}$script_input${gl_bai} 吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_exec

                    case "$confirm_exec" in
                    [Yy] | [Yy][Ee][Ss])
                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        echo -e "${gl_bai}开始执行脚本: ${gl_huang}$script_input${gl_bai}"
                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                        # 执行脚本
                        bash "$script_path"

                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        echo -e "${gl_lv}脚本执行完成${gl_bai}"
                        break_end
                        ;;
                    *)
                        log_info "已取消执行"
                        break_end
                        ;;
                    esac
                else
                    log_error "脚本不存在: $script_input"
                    break_end
                fi
                ;;
            *)
                if [ -n "$script_input" ]; then
                    # 尝试补全 .sh 后缀
                    if [ -f "$SCRIPT_DIR/$script_input.sh" ]; then
                        local script_input="$script_input.sh"
                        local script_path="$SCRIPT_DIR/$script_input"

                        # 检查执行权限
                        if [ ! -x "$script_path" ]; then
                            read -r -e -p "$(echo -e "${gl_bai}脚本无执行权限，是否添加? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" add_perm

                            case "$add_perm" in
                            [Yy] | [Yy][Ee][Ss])
                                chmod +x "$script_path"
                                if [ $? -eq 0 ]; then
                                    log_ok "已添加执行权限: $script_input"
                                else
                                    log_error "添加执行权限失败"
                                    break_end
                                    continue
                                fi
                                ;;
                            *)
                                log_info "已取消"
                                break_end
                                continue
                                ;;
                            esac
                        fi

                        # 执行脚本前的确认
                        read -r -e -p "$(echo -e "${gl_bai}确认要执行脚本 ${gl_huang}$script_input${gl_bai} 吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_exec

                        case "$confirm_exec" in
                        [Yy] | [Yy][Ee][Ss])
                            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                            echo -e "${gl_bai}开始执行脚本: ${gl_huang}$script_input${gl_bai}"
                            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                            # 执行脚本
                            bash "$script_path"

                            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                            echo -e "${gl_lv}脚本执行完成${gl_bai}"
                            break_end
                            ;;
                        *)
                            log_info "已取消执行"
                            break_end
                            ;;
                        esac
                    else
                        # 查找匹配的脚本
                        local found_scripts=()
                        for script in "$SCRIPT_DIR"/*.sh; do
                            if [ -f "$script" ]; then
                                local script_name=$(basename "$script")
                                if [[ "$script_name" == *"$script_input"* ]]; then
                                    found_scripts+=("$script_name")
                                fi
                            fi
                        done

                        if [ ${#found_scripts[@]} -eq 1 ]; then
                            # 只有一个匹配项
                            local selected_script="${found_scripts[0]}"
                            local script_path="$SCRIPT_DIR/$selected_script"

                            # 检查执行权限
                            if [ ! -x "$script_path" ]; then
                                read -r -e -p "$(echo -e "${gl_bai}脚本无执行权限，是否添加? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" add_perm

                                case "$add_perm" in
                                [Yy] | [Yy][Ee][Ss])
                                    chmod +x "$script_path"
                                    if [ $? -eq 0 ]; then
                                        log_ok "已添加执行权限: $selected_script"
                                    else
                                        log_error "添加执行权限失败"
                                        break_end
                                        continue
                                    fi
                                    ;;
                                *)
                                    log_info "已取消"
                                    break_end
                                    continue
                                    ;;
                                esac
                            fi

                            # 执行脚本前的确认
                            read -r -e -p "$(echo -e "${gl_bai}确认要执行脚本 ${gl_huang}$selected_script${gl_bai} 吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_exec

                            case "$confirm_exec" in
                            [Yy] | [Yy][Ee][Ss])
                                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                                echo -e "${gl_bai}开始执行脚本: ${gl_huang}$selected_script${gl_bai}"
                                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                                # 执行脚本
                                bash "$script_path"

                                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                                echo -e "${gl_lv}脚本执行完成${gl_bai}"
                                break_end
                                ;;
                            *)
                                log_info "已取消执行"
                                break_end
                                ;;
                            esac
                        elif [ ${#found_scripts[@]} -gt 1 ]; then
                            # 多个匹配项
                            log_info "找到多个匹配的脚本:"
                            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                            for i in "${!found_scripts[@]}"; do
                                echo -e "${gl_bufan}$(($i + 1)). ${gl_bai}${found_scripts[$i]}"
                            done
                            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                            break_end
                        else
                            handle_invalid_input
                        fi
                    fi
                else
                    handle_invalid_input
                fi
                ;;
            esac
        done
    }

    # 脚本管理主菜单
    while true; do
        clear
        init_script_dir

        # 显示已下载脚本
        show_downloaded_scripts
        echo -e ""
        echo -e "${gl_zi}>>> 脚本管理工具${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        show_crontab_status
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}Docker更新脚本         ${gl_bufan}2.  ${gl_bai}备份文件脚本"
        echo -e "${gl_bufan}3.  ${gl_bai}URL脚本下载工具        ${gl_bufan}4.  ${gl_bai}脚本目录管理"
        echo -e "${gl_bufan}5.  ${gl_bai}创建脚本文件           ${gl_bufan}6.  ${gl_bai}执行脚本文件"
        echo -e "${gl_bufan}7.  ${gl_bai}删除脚本文件           ${gl_bufan}8.  ${gl_bai}修改脚本权限"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}9.  ${gl_bai}添加到定时任务         ${gl_bufan}10. ${gl_bai}删除定时任务"
        echo -e "${gl_bufan}11. ${gl_bai}编辑cron文件           ${gl_bufan}12. ${gl_bai}清空cron任务"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单         ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "请输入你的选择: " choice

        case $choice in
        1)  show_docker_update_menu ;;                                          # Docker更新脚本
        2)  show_backup_menu ;;                                                 # 备份文件脚本
        3)  cd "$SCRIPT_DIR" && download_file ;;                                # 文件下载工具
        4)  cd "$SCRIPT_DIR" && linux_file "." "脚本管理工具" "脚本管理工具" ;;   # 脚本目录管理
        5)  cd "$SCRIPT_DIR" && create_script_in_opt ;;                         # 创建脚本文件
        6)  execute_script ;;                                                   # 执行脚本文件
        7)  cd "$SCRIPT_DIR" && delete_files ;;                                 # 删除脚本文件
        8)  cd "$SCRIPT_DIR" && file_chmod "脚本管理工具" ;;                     # 修改脚本权限
        9)  add_to_cron; break_end ;;                                           # 添加到定时任务
        10) remove_from_cron; break_end ;;                                      # 删除定时任务
        11) edit_crontab ;;                                                     # 编辑cron文件
        12) clear_crontab ;;                                                    # 清空cron任务
        0)  cancel_return "$menu_name"; break ;;                                # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;                                         # 感谢使用，再见！
        *) handle_invalid_input ;;                                              # 无效的输入,请重新输入!
        esac
    done
}

# 函数_电视剧集重命名
tv_rename_ultimate() {

    # 快速重命名功能（增强版）
    quick_rename() {
        clear
        echo -e "${gl_zi}>>> 快速重命名（智能识别版）${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        # 支持的视频文件扩展名
        local VIDEO_EXTS=("mp4" "mkv" "avi" "mov" "wmv" "flv" "webm" "m4v" "mpg" "mpeg" "kvm")
        
        # 生成扩展名匹配字符串
        local ext_pattern=""
        for ext in "${VIDEO_EXTS[@]}"; do
            if [ -z "$ext_pattern" ]; then
                ext_pattern="-name \"*.$ext\""
            else
                ext_pattern="$ext_pattern -o -name \"*.$ext\""
            fi
        done
        
        # 收集文件
        log_info "扫描当前目录视频文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        local files=()
        while IFS= read -r file; do
            if [ -f "$file" ]; then
                files+=("$file")
            fi
        done < <(eval "find . -maxdepth 1 -type f \( $ext_pattern \) 2>/dev/null" | sort -V)
        
        if [ ${#files[@]} -eq 0 ]; then
            log_error "未找到视频文件！"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi
        
        echo -e "${gl_bai}找到 ${#files[@]} 个视频文件:${gl_bai}"
        for ((i = 0; i < ${#files[@]}; i++)); do
            local filename=$(basename -- "${files[$i]}")
            echo -e "  ${gl_bufan}$(safe_printf "%02d" $((i + 1))).${gl_bai} $filename"
        done
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        # ========== 自动识别电视剧信息 ==========
        echo -e "${gl_huang}正在智能识别剧集信息 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        # 1. 自动识别剧集前缀
        local prefix=""
        local season="01"
        local start_ep="1"
        local detected_info=0
        
        # 从文件名中提取前缀候选
        local candidates=()
        local counts=()
        local total_files=${#files[@]}
        
        for file in "${files[@]}"; do
            local filename=$(basename -- "$file")
            # 使用已有的 extract_prefix_candidate 函数
            if command -v extract_prefix_candidate >/dev/null 2>&1; then
                local candidate=$(extract_prefix_candidate "$filename")
            else
                # 简化版前缀提取
                local basename="${filename%.*}"
                # 移除常见的剧集标识符
                local candidate=$(echo "$basename" | sed -E 's/[._ -]*[Ss][0-9]{1,2}[Ee][0-9]{1,3}[._ -]*//g')
                candidate=$(echo "$candidate" | sed -E 's/[._ -]*[Ee][Pp][0-9]{1,3}[._ -]*//g')
                candidate=$(echo "$candidate" | sed -E 's/[._ -]*第[0-9]{1,3}[集話话][._ -]*//g')
                candidate=$(echo "$candidate" | sed 's/^[._ -]*//;s/[._ -]*$//')
            fi
            
            if [ -n "$candidate" ] && [ ${#candidate} -ge 2 ]; then
                # 检查是否已存在
                local found=-1
                for idx in "${!candidates[@]}"; do
                    if [ "${candidates[$idx]}" = "$candidate" ]; then
                        found=$idx
                        break
                    fi
                done
                if [ $found -ge 0 ]; then
                    counts[$found]=$((counts[$found] + 1))
                else
                    candidates+=("$candidate")
                    counts+=(1)
                fi
            fi
        done
        
        # 选择出现频率最高的前缀
        if [ ${#candidates[@]} -gt 0 ]; then
            local best_idx=0
            for i in "${!candidates[@]}"; do
                if [ ${counts[$i]} -gt ${counts[$best_idx]} ]; then
                    best_idx=$i
                fi
            done
            prefix="${candidates[$best_idx]}"
            detected_info=1
            log_ok "自动识别剧集前缀: ${gl_lv}$prefix${gl_bai}"
        else
            prefix="电视剧"
            log_warn "无法识别剧集前缀，使用默认值: ${gl_lv}电视剧${gl_bai}"
        fi
        
        # 2. 自动识别季号
        local season_array=()
        local season_count_array=()
        
        for file in "${files[@]}"; do
            local filename=$(basename -- "$file")
            # 尝试匹配 S01E26 格式
            if [[ "$filename" =~ [Ss]([0-9]{1,2})[Ee] ]]; then
                local s="${BASH_REMATCH[1]}"
                local found=0
                for i in "${!season_array[@]}"; do
                    if [ "${season_array[i]}" = "$s" ]; then
                        season_count_array[i]=$((season_count_array[i] + 1))
                        found=1
                        break
                    fi
                done
                if [ $found -eq 0 ]; then
                    season_array+=("$s")
                    season_count_array+=(1)
                fi
            fi
        done
        
        if [ ${#season_array[@]} -gt 0 ]; then
            local best_idx=0
            for i in "${!season_array[@]}"; do
                if [ ${season_count_array[i]} -gt ${season_count_array[$best_idx]} ]; then
                    best_idx=$i
                fi
            done
            season=$(safe_printf "%02d" "${season_array[$best_idx]}")
            detected_info=1
            log_ok "自动识别季号: ${gl_lv}S$season${gl_bai}"
        else
            log_info "使用默认季号: ${gl_lv}S$season${gl_bai}"
        fi
        
        # 3. 自动识别起始集数
        # 扫描所有文件，找到最小的集数
        local min_episode=999
        for file in "${files[@]}"; do
            local filename=$(basename -- "$file")
            # 尝试多种格式匹配
            if [[ "$filename" =~ [Ss][0-9]{1,2}[Ee]([0-9]{1,3}) ]]; then
                local ep="${BASH_REMATCH[1]}"
                ep=$(echo "$ep" | sed 's/^0*//')
                [ -z "$ep" ] && ep=0
                if [ "$ep" -lt "$min_episode" ] && [ "$ep" -gt 0 ]; then
                    min_episode="$ep"
                fi
            elif [[ "$filename" =~ [Ee][Pp]([0-9]{1,3}) ]]; then
                local ep="${BASH_REMATCH[1]}"
                ep=$(echo "$ep" | sed 's/^0*//')
                [ -z "$ep" ] && ep=0
                if [ "$ep" -lt "$min_episode" ] && [ "$ep" -gt 0 ]; then
                    min_episode="$ep"
                fi
            elif [[ "$filename" =~ 第([0-9]{1,3})[集話话] ]]; then
                local ep="${BASH_REMATCH[1]}"
                ep=$(echo "$ep" | sed 's/^0*//')
                [ -z "$ep" ] && ep=0
                if [ "$ep" -lt "$min_episode" ] && [ "$ep" -gt 0 ]; then
                    min_episode="$ep"
                fi
            fi
        done
        
        if [ "$min_episode" -ne 999 ]; then
            start_ep="$min_episode"
            detected_info=1
            log_ok "自动识别起始集数: ${gl_lv}E$(safe_printf "%02d" "$start_ep")${gl_bai}"
        else
            log_info "使用默认起始集数: ${gl_lv}E$(safe_printf "%02d" "$start_ep")${gl_bai}"
        fi
        
        if [ $detected_info -eq 1 ]; then
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_lv}✓ 智能识别完成${gl_bai}"
        fi
        
        # ========== 直接预览重命名结果 ==========
        clear
        echo -e "${gl_zi}>>> 预览重命名结果${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        echo -e "${gl_bai}自动识别设置:${gl_bai}"
        echo -e "  ${gl_bufan}剧集前缀:${gl_bai} $prefix"
        echo -e "  ${gl_bufan}季号:${gl_bai} S$season"
        echo -e "  ${gl_bufan}起始集数:${gl_bai} E$(safe_printf "%02d" "$start_ep")"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        echo -e "${gl_bai}重命名预览 (共 ${#files[@]} 个文件):${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        local preview_files=()
        for ((i = 0; i < ${#files[@]}; i++)); do
            local file="${files[$i]}"
            local filename=$(basename -- "$file")
            local extension="${filename##*.}"
            local episode=$((start_ep + i))
            local formatted_ep=$(safe_printf "%02d" "$episode")
            local new_name="${prefix}-S${season}E${formatted_ep}.${extension}"
            
            preview_files+=("$file:$new_name")
            
            echo -e "  ${gl_bufan}[$(safe_printf "%02d" $((i + 1)))]${gl_bai}"
            echo -e "    原文件: ${gl_hui}$filename${gl_bai}"
            echo -e "    新文件: ${gl_lv}$new_name${gl_bai}"
            echo ""
        done
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        # ========== 提示用户是否修改 ==========
        echo -e "${gl_bai}是否修改设置?${gl_bai}"
        echo -e "  ${gl_bufan}1.${gl_bai} 直接重命名 (使用当前设置)"
        echo -e "  ${gl_bufan}2.${gl_bai} 修改剧集前缀"
        echo -e "  ${gl_bufan}3.${gl_bai} 修改季号"
        echo -e "  ${gl_bufan}4.${gl_bai} 修改起始集数"
        echo -e "  ${gl_bufan}5.${gl_bai} 进入详细设置"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        read -r -e -p "$(echo -e "${gl_bai}请输入你的选择: ")" choice
        
        case $choice in
        1)
            # 直接重命名
            log_info "开始重命名 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            local success_count=0
            
            for item in "${preview_files[@]}"; do
                IFS=':' read -r old_file new_name <<<"$item"
                local old_filename=$(basename -- "$old_file")
                
                if mv -- "$old_file" "./$new_name" 2>/dev/null; then
                    echo -e "  ${gl_lv}✓ $old_filename → $new_name${gl_bai}"
                    ((success_count++))
                else
                    echo -e "  ${gl_hong}✗ 重命名失败: $old_filename${gl_bai}"
                fi
            done
            
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_ok "重命名完成！成功 $success_count 个文件"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        
        2)
            # 修改剧集前缀
            clear
            echo -e "${gl_zi}>>> 修改剧集前缀${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            echo -e "${gl_bai}当前前缀: ${gl_lv}$prefix${gl_bai}"
            echo -e "${gl_bai}示例: ${gl_bufan}庆余年${gl_bai} → ${gl_bufan}庆余年-S${season}E01.mkv${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            read -r -e -p "$(echo -e "${gl_bai}请输入新的剧集前缀 (回车保持原值): ")" new_prefix
            
            if [ -n "$new_prefix" ]; then
                prefix="$new_prefix"
                log_ok "剧集前缀已修改为: $prefix"
            else
                log_info "保持原剧集前缀: $prefix"
            fi
            
            # 重新显示预览
            quick_rename_preview "${files[@]}" "$prefix" "$season" "$start_ep"
            ;;
        
        3)
            # 修改季号
            clear
            echo -e "${gl_zi}>>> 修改季号${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            echo -e "${gl_bai}当前季号: ${gl_lv}S$season${gl_bai}"
            echo -e "${gl_bai}示例: ${gl_bufan}01${gl_bai} 表示第 ${gl_bufan}1${gl_bai} 季 (将显示为 S01)"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            read -r -e -p "$(echo -e "${gl_bai}请输入新的季号 (回车保持原值): ")" new_season
            
            if [ -n "$new_season" ]; then
                if [[ "$new_season" =~ ^[0-9]{1,2}$ ]]; then
                    season=$(safe_printf "%02d" "$new_season")
                    log_ok "季号已修改为: S$season"
                else
                    log_error "请输入有效的数字 (1-99)！"
                fi
            else
                log_info "保持原季号: S$season"
            fi
            
            # 重新显示预览
            quick_rename_preview "${files[@]}" "$prefix" "$season" "$start_ep"
            ;;
        
        4)
            # 修改起始集数
            clear
            echo -e "${gl_zi}>>> 修改起始集数${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            echo -e "${gl_bai}当前起始集数: ${gl_lv}E$(safe_printf "%02d" "$start_ep")${gl_bai}"
            echo -e "${gl_bai}示例: ${gl_bufan}26${gl_bai} 表示从第 ${gl_bufan}26${gl_bai} 集开始编号"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            read -r -e -p "$(echo -e "${gl_bai}请输入新的起始集数 (回车保持原值): ")" new_start
            
            if [ -n "$new_start" ]; then
                if [[ "$new_start" =~ ^[0-9]{1,3}$ ]] && [ "$new_start" -ge 1 ]; then
                    start_ep="$new_start"
                    log_ok "起始集数已修改为: E$(safe_printf "%02d" "$start_ep")"
                else
                    log_error "请输入有效的集数 (1-999)！"
                fi
            else
                log_info "保持原起始集数: E$(safe_printf "%02d" "$start_ep")"
            fi
            
            # 重新显示预览
            quick_rename_preview "${files[@]}" "$prefix" "$season" "$start_ep"
            ;;
        
        5)
            # 进入详细设置（调用原有的详细重命名函数）
            rename_tv_files_ultimate
            ;;
        0) cancel_return; return ;;     # 返回到上一级菜单
        *) handle_invalid_input ;;      # 无效的输入,请重新输入!
        esac
    }

    # 辅助函数：显示预览
    quick_rename_preview() {
        local files=("${@:1:${#@}-3}")
        local prefix="${@: -3:1}"
        local season="${@: -2:1}"
        local start_ep="${@: -1}"
        
        clear
        echo -e "${gl_zi}>>> 预览重命名结果${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        echo -e "${gl_bai}当前设置:${gl_bai}"
        echo -e "  ${gl_bufan}剧集前缀:${gl_bai} $prefix"
        echo -e "  ${gl_bufan}季号:${gl_bai} S$season"
        echo -e "  ${gl_bufan}起始集数:${gl_bai} E$(safe_printf "%02d" "$start_ep")"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        echo -e "${gl_bai}重命名预览:${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        for ((i = 0; i < ${#files[@]}; i++)); do
            local file="${files[$i]}"
            local filename=$(basename -- "$file")
            local extension="${filename##*.}"
            local episode=$((start_ep + i))
            local formatted_ep=$(safe_printf "%02d" "$episode")
            local new_name="${prefix}-S${season}E${formatted_ep}.${extension}"
            
            echo -e "  ${gl_bufan}[$(safe_printf "%02d" $((i + 1)))]${gl_bai}"
            echo -e "    原文件: ${gl_hui}$filename${gl_bai}"
            echo -e "    新文件: ${gl_lv}$new_name${gl_bai}"
            echo ""
        done
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        read -r -e -p "$(echo -e "${gl_bai}是否执行重命名? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
        
        case "$confirm" in
        [Yy])
            log_info "开始重命名 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            local success_count=0
            
            for ((i = 0; i < ${#files[@]}; i++)); do
                local file="${files[$i]}"
                local filename=$(basename -- "$file")
                local extension="${filename##*.}"
                local episode=$((start_ep + i))
                local formatted_ep=$(safe_printf "%02d" "$episode")
                local new_name="${prefix}-S${season}E${formatted_ep}.${extension}"
                
                if mv -- "$file" "./$new_name" 2>/dev/null; then
                    echo -e "  ${gl_lv}✓ $filename → $new_name${gl_bai}"
                    ((success_count++))
                else
                    echo -e "  ${gl_hong}✗ 重命名失败: $filename${gl_bai}"
                fi
            done
            
            log_ok "重命名完成！成功 $success_count 个文件"
            ;;
        
        [Nn])
            log_info "已取消重命名操作"
            ;;
        
        *)
            log_error "无效的选择！"
            ;;
        esac
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # 安全的 printf 函数，处理以0开头的数字
    safe_printf() {
        local format="$1"
        local number="$2"

        # 如果是十进制格式，去除前导零
        if [[ "$format" == "%d" ]] || [[ "$format" == "%02d" ]] || [[ "$format" == "%03d" ]]; then
            # 去除前导零，避免被解释为八进制
            number=$(echo "$number" | sed 's/^0*//')
            if [ -z "$number" ]; then
                number=0
            fi
        fi

        printf "$format" "$number"
    }

    # 增强的智能提取集数函数 - 返回所有可能的识别结果
    enhanced_extract_episode_info() {
        local filename="$1"
        local results=()

        # 1. 尝试匹配 S01E26 格式
        if [[ "$filename" =~ [Ss]([0-9]{1,2})[Ee]([0-9]{1,3}) ]]; then
            local season="${BASH_REMATCH[1]}"
            local episode="${BASH_REMATCH[2]}"
            results+=("S${season}E${episode}:${season}:${episode}:SxE格式")
        fi

        # 2. 匹配 EP26 或 EP26- 格式
        if [[ "$filename" =~ [Ee][Pp]([0-9]{1,3})[^0-9] ]]; then
            local episode="${BASH_REMATCH[1]}"
            results+=("EP${episode}:01:${episode}:EP格式")
        fi

        # 3. 匹配 第26集 格式
        if [[ "$filename" =~ 第([0-9]{1,3})[集話话] ]]; then
            local episode="${BASH_REMATCH[1]}"
            results+=("第${episode}集:01:${episode}:中文第X集")
        fi

        # 4. 匹配 -26- 或 .26. 格式
        if [[ "$filename" =~ [^0-9]([0-9]{1,3})[^0-9] ]]; then
            local num="${BASH_REMATCH[1]}"
            # 排除年份（通常是4位数）
            if [ "$num" -lt 1000 ] || [ "$num" -gt 2100 ]; then
                results+=("${num}:01:${num}:数字格式")
            fi
        fi

        # 5. 匹配文件名开头的数字
        if [[ "$filename" =~ ^([0-9]{1,3}) ]]; then
            local episode="${BASH_REMATCH[1]}"
            results+=("${episode}:01:${episode}:开头数字")
        fi

        # 6. 匹配文件名结尾的数字
        if [[ "$filename" =~ ([0-9]{1,3})\.[^.]*$ ]]; then
            local episode="${BASH_REMATCH[1]}"
            results+=("${episode}:01:${episode}:结尾数字")
        fi

        # 如果没有识别结果，返回默认
        if [ ${#results[@]} -eq 0 ]; then
            results+=("0:01:1:未识别")
        fi

        # 返回所有结果
        printf "%s\n" "${results[@]}"
    }

    # 分析文件名模式
    analyze_filename_patterns() {
        local files=("$@")

        echo -e "${gl_zi}>>> 智能模式分析${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 使用普通数组统计模式
        local pattern_array=()
        local example_array=()
        local count_array=()

        for file in "${files[@]}"; do
            local filename=$(basename -- "$file")
            local results=($(enhanced_extract_episode_info "$filename"))

            for result in "${results[@]}"; do
                IFS=':' read -r pattern season episode type <<<"$result"
                if [ "$type" != "未识别" ]; then
                    # 查找是否已存在该类型
                    local found=0
                    for i in "${!pattern_array[@]}"; do
                        if [ "${pattern_array[i]}" = "$type" ]; then
                            count_array[i]=$((count_array[i] + 1))
                            found=1
                            break
                        fi
                    done

                    if [ $found -eq 0 ]; then
                        pattern_array+=("$type")
                        example_array+=("$filename")
                        count_array+=(1)
                    fi
                    break
                fi
            done
        done

        # 显示模式统计
        if [ ${#pattern_array[@]} -eq 0 ]; then
            echo -e "${gl_huang}未检测到有效的剧集编号模式${gl_bai}"
        else
            echo -e "${gl_bai}检测到的剧集编号模式:${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            for ((i = 0; i < ${#pattern_array[@]}; i++)); do
                local type="${pattern_array[i]}"
                local count="${count_array[i]}"
                local example="${example_array[i]}"
                local percentage=$((count * 100 / ${#files[@]}))
                local index=$((i + 1))

                if [ $percentage -ge 50 ]; then
                    echo -e "  ${gl_lv}${index}.${gl_bai} ${gl_bufan}${type}${gl_bai} (${percentage}% 文件)"
                else
                    echo -e "  ${gl_huang}${index}.${gl_bai} ${gl_bufan}${type}${gl_bai} (${percentage}% 文件)"
                fi
                echo -e "     示例: ${gl_hui}${example}${gl_bai}"
            done
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        return 0
    }

    # 自动检测最佳重命名方案
    auto_detect_rename_plan() {
        local files=("$@")
        local plans=()
        clear
        echo -e "${gl_zi}>>> 自动检测重命名方案${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 方案1: 保持原季号（如果检测到）
        local season_array=()
        local season_count_array=()

        for file in "${files[@]}"; do
            local filename=$(basename -- "$file")
            if [[ "$filename" =~ [Ss]([0-9]{1,2})[Ee] ]]; then
                local season="${BASH_REMATCH[1]}"

                local found=0
                for i in "${!season_array[@]}"; do
                    if [ "${season_array[i]}" = "$season" ]; then
                        season_count_array[i]=$((season_count_array[i] + 1))
                        found=1
                        break
                    fi
                done

                if [ $found -eq 0 ]; then
                    season_array+=("$season")
                    season_count_array+=(1)
                fi
            fi
        done

        if [ ${#season_array[@]} -gt 0 ]; then
            local best_season=""
            local best_count=0
            for i in "${!season_array[@]}"; do
                if [ ${season_count_array[i]} -gt $best_count ]; then
                    best_count=${season_count_array[i]}
                    best_season="${season_array[i]}"
                fi
            done

            if [ -n "$best_season" ]; then
                local formatted_season=$(safe_printf "%02d" "$best_season")
                plans+=("保持原季号|S${formatted_season}|检测到S${formatted_season}格式|高")
            fi
        fi

        # 方案2: 从文件名提取前缀
        if [ ${#files[@]} -gt 0 ]; then
            local sample_file=$(basename -- "${files[0]}")

            # 尝试提取中文剧名
            if [[ "$sample_file" =~ ^([^0-9.-[:space:]]+)[^0-9]* ]]; then
                local chinese_name="${BASH_REMATCH[1]}"
                chinese_name=$(echo "$chinese_name" | sed 's/^[[:space:][:punct:]]*//;s/[[:space:][:punct:]]*$//')
                if [ -n "$chinese_name" ] && [ ${#chinese_name} -ge 2 ]; then
                    plans+=("中文剧名|${chinese_name}|从文件名提取中文名|中")
                fi
            fi

            # 尝试提取英文剧名
            if [[ "$sample_file" =~ \.([A-Za-z][A-Za-z. ]+?)[^A-Za-z] ]]; then
                local english_name="${BASH_REMATCH[1]}"
                english_name=$(echo "$english_name" | sed 's/\./ /g;s/ $//')
                if [ -n "$english_name" ]; then
                    plans+=("英文剧名|${english_name}|从文件名提取英文名|中")
                fi
            fi
        fi

        # 显示检测到的方案
        if [ ${#plans[@]} -eq 0 ]; then
            echo -e "${gl_huang}未检测到有效的重命名方案${gl_bai}"
            return 1
        fi

        echo -e "${gl_bai}检测到的重命名方案:${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        for ((i = 0; i < ${#plans[@]}; i++)); do
            IFS='|' read -r type value description confidence <<<"${plans[$i]}"
            local index=$((i + 1))

            case $confidence in
            高) color="${gl_lv}" ;;
            中) color="${gl_huang}" ;;
            *) color="${gl_hong}" ;;
            esac

            echo -e "  ${gl_bufan}${index}.${gl_bai} ${color}${type}${gl_bai}"
            echo -e "     值: ${gl_bufan}${value}${gl_bai}"
            echo -e "     说明: ${gl_hui}${description}${gl_bai}"
            echo -e "     置信度: ${color}${confidence}${gl_bai}"
            echo ""
        done

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        return 0
    }

    # 电视剧文件重命名函数（终极版）
    rename_tv_files_ultimate() {
        # 支持的视频文件扩展名
        local VIDEO_EXTS=("mp4" "mkv" "avi" "mov" "wmv" "flv" "webm" "m4v" "mpg" "mpeg" "kvm")
        local PREFIX=""
        local SEASON="01"
        local START_EP="1"
        local preview_mode=1
        local rename_count=0
        local auto_detected=0
        local detection_results=()

        # 扫描文件函数
        scan_video_files() {
            local -n files_ref=$1
            local -n episode_info_ref=$2
            local -n pattern_types_ref=$3

            # 生成扩展名匹配字符串
            local ext_pattern=""
            for ext in "${VIDEO_EXTS[@]}"; do
                if [ -z "$ext_pattern" ]; then
                    ext_pattern="-name \"*.$ext\""
                else
                    ext_pattern="$ext_pattern -o -name \"*.$ext\""
                fi
            done

            # 收集文件
            while IFS= read -r file; do
                if [ -f "$file" ]; then
                    local filename=$(basename -- "$file")
                    local extension="${filename##*.}"

                    # 获取所有可能的识别结果
                    local results=($(enhanced_extract_episode_info "$filename"))
                    local found=0

                    for result in "${results[@]}"; do
                        IFS=':' read -r pattern season episode type <<<"$result"
                        if [ "$episode" != "0" ] && { [ "$episode" != "1" ] || [ "$type" != "未识别" ]; }; then
                            files_ref+=("$file")
                            episode_info_ref+=("$episode:$season:$type")
                            pattern_types_ref+=("$type")
                            found=1
                            break
                        fi
                    done

                    if [ $found -eq 0 ]; then
                        # 无法识别集数的文件
                        log_warn "无法识别集数: $filename"
                    fi
                fi
            done < <(eval "find . -maxdepth 1 -type f \( $ext_pattern \) 2>/dev/null" | sort -V)
        }

        while true; do
            clear
            echo -e "${gl_zi}>>> 电视剧文件重命名（终极版）${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            # 显示当前设置
            if [ -n "$PREFIX" ]; then
                echo -e "${gl_bufan}当前设置:${gl_bai}"
                echo -e "  ${gl_bufan}剧集前缀:${gl_bai} $PREFIX"
                echo -e "  ${gl_bufan}季号:${gl_bai} S$SEASON"
                echo -e "  ${gl_bufan}起始集数:${gl_bai} E$(safe_printf "%02d" $START_EP)"
                if [ $auto_detected -eq 1 ]; then
                    echo -e "  ${gl_lv}✓ 智能检测已应用${gl_bai}"
                fi
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            fi

            # 扫描文件
            log_info "扫描当前目录视频文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            local files=()
            local episode_info=()
            local pattern_types=()

            scan_video_files files episode_info pattern_types

            if [ ${#files[@]} -eq 0 ]; then
                log_error "未找到可识别的视频文件！"
                echo -e "${gl_bai}支持格式: ${gl_bufan}${VIDEO_EXTS[*]}${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "$(echo -e "${gl_bai}请按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} ")" -n 1
                return
            fi

            # 按集数排序文件
            if [ ${#files[@]} -gt 0 ]; then
                # 创建临时数组用于排序
                local sorted_files=()
                local sorted_episodes=()

                # 按集数排序
                while IFS= read -r line; do
                    IFS=':' read -r episode season type <<<"$line"
                    for i in "${!files[@]}"; do
                        if [[ "${episode_info[$i]}" == "$line" ]]; then
                            sorted_episodes+=("$episode:$season:$type")
                            sorted_files+=("${files[$i]}")
                            break
                        fi
                    done
                done < <(printf "%s\n" "${episode_info[@]}" | sort -t: -k1,1n)

                files=("${sorted_files[@]}")
                episode_info=("${sorted_episodes[@]}")
            fi

            # 显示找到的文件
            echo -e "${gl_bufan}找到 ${#files[@]} 个可识别文件:${gl_bai}"
            for ((i = 0; i < ${#files[@]}; i++)); do
                local filename=$(basename -- "${files[$i]}")
                IFS=':' read -r episode season type <<<"${episode_info[$i]}"
                echo -e "  ${gl_bufan}$(safe_printf "%02d" $((i + 1))).${gl_bai} E$(safe_printf "%02d" "$episode") [${type}] - $filename"
            done

            # 分析文件模式
            if [ $auto_detected -eq 0 ] && [ ${#files[@]} -gt 0 ]; then
                echo -e ""
                echo -e "${gl_bai}检测到的模式分布:${gl_bai}"

                # 使用普通数组统计
                local pattern_array=()
                local count_array=()

                for pattern in "${pattern_types[@]}"; do
                    local found=0
                    for i in "${!pattern_array[@]}"; do
                        if [ "${pattern_array[i]}" = "$pattern" ]; then
                            count_array[i]=$((count_array[i] + 1))
                            found=1
                            break
                        fi
                    done

                    if [ $found -eq 0 ]; then
                        pattern_array+=("$pattern")
                        count_array+=(1)
                    fi
                done

                for i in "${!pattern_array[@]}"; do
                    local pattern="${pattern_array[i]}"
                    local count="${count_array[i]}"
                    local percentage=$((count * 100 / ${#files[@]}))
                    echo -e "  ${gl_bufan}${pattern}:${gl_bai} ${count} 文件 (${percentage}%)"
                done
            fi

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            # 菜单选项
            echo -e "${gl_bufan}1.  ${gl_bai}智能检测最佳方案"
            echo -e "${gl_bufan}2.  ${gl_bai}设置剧集前缀"
            echo -e "${gl_bufan}3.  ${gl_bai}设置季号"
            echo -e "${gl_bufan}4.  ${gl_bai}设置起始集数"
            echo -e "${gl_bufan}5.  ${gl_bai}详细模式分析"
            echo -e "${gl_bufan}6.  ${gl_bai}预览重命名结果"

            if [ $preview_mode -eq 1 ] && [ -n "$PREFIX" ]; then
                echo -e "${gl_bufan}7.  ${gl_lv}执行重命名${gl_bai}"
            else
                echo -e "${gl_bufan}7.  ${gl_bai}执行重命名"
            fi

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
            echo -e "${gl_hong}00. ${gl_bai}退出脚本"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            read -r -e -p "$(echo -e "${gl_bai}请输入你的选择: ")" choice

            case $choice in
            1)
                clear
                echo -e "${gl_zi}>>> 智能检测最佳方案${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                # 运行自动检测
                auto_detect_rename_plan "${files[@]}"

                if [ $? -eq 0 ]; then
                    echo -e ""
                    echo -e "${gl_bai}是否应用检测到的方案?${gl_bai}"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                    read -r -e -p "$(echo -e "${gl_bai}应用检测结果? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" apply_choice

                    case "$apply_choice" in
                    [Yy])
                        auto_detected=1

                        # 尝试自动提取剧名前缀
                        if [ ${#files[@]} -gt 0 ]; then
                            local sample_file=$(basename -- "${files[0]}")

                            # 尝试提取中文名
                            if [[ "$sample_file" =~ ^([^0-9.-[:space:]]+)[^0-9]* ]]; then
                                local extracted_prefix="${BASH_REMATCH[1]}"
                                extracted_prefix=$(echo "$extracted_prefix" | sed 's/[[:space:][:punct:]]*$//')
                                if [ ${#extracted_prefix} -ge 2 ]; then
                                    PREFIX="$extracted_prefix"
                                    log_ok "自动设置剧集前缀: $PREFIX"
                                fi
                            fi

                            # 自动检测季号
                            local season_array=()
                            local season_count_array=()

                            for info in "${episode_info[@]}"; do
                                IFS=':' read -r episode season type <<<"$info"
                                if [ "$season" != "01" ]; then
                                    local found=0
                                    for i in "${!season_array[@]}"; do
                                        if [ "${season_array[i]}" = "$season" ]; then
                                            season_count_array[i]=$((season_count_array[i] + 1))
                                            found=1
                                            break
                                        fi
                                    done

                                    if [ $found -eq 0 ]; then
                                        season_array+=("$season")
                                        season_count_array+=(1)
                                    fi
                                fi
                            done

                            if [ ${#season_array[@]} -gt 0 ]; then
                                local best_season=""
                                local best_count=0
                                for i in "${!season_array[@]}"; do
                                    if [ ${season_count_array[i]} -gt $best_count ]; then
                                        best_count=${season_count_array[i]}
                                        best_season="${season_array[i]}"
                                    fi
                                done

                                if [ -n "$best_season" ]; then
                                    SEASON=$(safe_printf "%02d" "$best_season")
                                    log_ok "自动设置季号: S$SEASON"
                                fi
                            fi
                        fi

                        log_ok "智能检测已应用！"
                        preview_mode=0
                        ;;

                    [Nn])
                        log_info "已取消应用检测结果"
                        ;;

                    *) handle_y_n ;;        # 无效的输入,请输入(y或N)。
                    esac
                fi
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;

            2)
                clear
                echo -e "${gl_zi}>>> 设置剧集前缀${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                # ========== 新增：从所有文件中提取前缀候选并统计频率 ==========
                # 定义提取前缀候选的函数
                extract_prefix_candidate() {
                    local filename="$1"
                    local basename="${filename%.*}" # 去掉扩展名
                    # 获取第一个识别的集数模式（如果有）
                    local results=($(enhanced_extract_episode_info "$filename"))
                    if [ ${#results[@]} -gt 0 ]; then
                        IFS=':' read -r pattern season episode type <<<"${results[0]}"
                        if [ "$type" != "未识别" ] && [ -n "$pattern" ]; then
                            # 将模式中的特殊字符转义，用于sed
                            # 简单处理：直接移除匹配到的模式及其前后的常见分隔符
                            # 使用sed替换，注意模式中可能包含点、括号等
                            # 这里简化：将pattern作为普通字符串移除，并去掉前后的分隔符
                            local cleaned=$(echo "$basename" | sed -E "s/[._ -]*${pattern}[._ -]*//g")
                            # 如果清理后为空，则回退到basename
                            if [ -n "$cleaned" ]; then
                                # 去除首尾多余分隔符
                                cleaned=$(echo "$cleaned" | sed 's/^[._ -]*//;s/[._ -]*$//')
                                # 去除可能残留的分辨率标签（如1080p、2160p等），但为了简单，不做了
                                if [ -n "$cleaned" ] && [ ${#cleaned} -ge 2 ]; then
                                    echo "$cleaned"
                                    return
                                fi
                            fi
                        fi
                    fi
                    # 如果没有识别到集数或清理后为空，则直接返回basename（但去掉开头结尾的杂音）
                    local fallback=$(echo "$basename" | sed 's/^[._ -]*//;s/[._ -]*$//')
                    if [ -n "$fallback" ] && [ ${#fallback} -ge 2 ]; then
                        echo "$fallback"
                    else
                        # 极短或无，返回空
                        echo ""
                    fi
                }

                # 收集所有候选
                local candidates=()
                local counts=()
                local total_files=${#files[@]}

                for file in "${files[@]}"; do
                    local filename=$(basename -- "$file")
                    local candidate=$(extract_prefix_candidate "$filename")
                    if [ -z "$candidate" ]; then
                        continue
                    fi
                    # 检查是否已存在
                    local found=-1
                    for idx in "${!candidates[@]}"; do
                        if [ "${candidates[$idx]}" = "$candidate" ]; then
                            found=$idx
                            break
                        fi
                    done
                    if [ $found -ge 0 ]; then
                        counts[$found]=$((counts[$found] + 1))
                    else
                        candidates+=("$candidate")
                        counts+=(1)
                    fi
                done

                # 如果没有提取到任何候选，使用默认值
                if [ ${#candidates[@]} -eq 0 ]; then
                    candidates=("电视剧")
                    counts=($total_files)
                    log_warn "无法自动识别前缀，使用默认值: 电视剧"
                fi

                # 按计数降序排序（简单冒泡，候选不多）
                # 同时保持关联
                for ((i = 0; i < ${#candidates[@]} - 1; i++)); do
                    for ((j = i + 1; j < ${#candidates[@]}; j++)); do
                        if [ ${counts[$j]} -gt ${counts[$i]} ]; then
                            # 交换
                            tmp_c="${candidates[$i]}"
                            tmp_n="${counts[$i]}"
                            candidates[$i]="${candidates[$j]}"
                            counts[$i]="${counts[$j]}"
                            candidates[$j]="$tmp_c"
                            counts[$j]="$tmp_n"
                        fi
                    done
                done

                # 限制显示前10个（太多用户不好选）
                local display_limit=10
                if [ ${#candidates[@]} -gt $display_limit ]; then
                    candidates=("${candidates[@]:0:$display_limit}")
                    counts=("${counts[@]:0:$display_limit}")
                fi

                # 显示候选列表
                echo -e "${gl_bai}从文件名中提取到的剧名前缀:${gl_bai}"
                for i in "${!candidates[@]}"; do
                    local idx=$((i + 1))
                    local percentage=$((counts[i] * 100 / total_files))
                    echo -e "  ${gl_bufan}${idx}.${gl_bai} ${gl_lv}${candidates[$i]}${gl_bai} (出现 ${counts[$i]} 次, ${percentage}%)"
                done
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_bai}推荐: ${gl_lv}${candidates[0]}${gl_bai} (${gl_huang}回车直接使用推荐${gl_bai})"
                echo -e "${gl_bai}示例: ${gl_bufan}${candidates[0]}-S${SEASON}E01.扩展名${gl_bai}"
                echo -e "${gl_bai}指定: ${gl_bai}手动输入自定义前缀"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                read -r -e -p "$(echo -e "${gl_bai}请输入序号或自定义前缀 (${gl_huang}0${gl_bai}返回): ")" input_prefix

                [[ "$input_prefix" == "0" ]] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定

                # 检查输入是否为数字（序号）
                if [[ "$input_prefix" =~ ^[0-9]+$ ]] && [ "$input_prefix" -ge 1 ] && [ "$input_prefix" -le ${#candidates[@]} ]; then
                    # 选择序号
                    PREFIX="${candidates[$((input_prefix - 1))]}"
                    log_ok "剧集前缀已设置为: $PREFIX (通过序号选择)"
                elif [ -z "$input_prefix" ]; then
                    # 回车使用推荐
                    PREFIX="${candidates[0]}"
                    log_ok "剧集前缀已设置为: $PREFIX (使用推荐)"
                else
                    # 手动输入
                    PREFIX="$input_prefix"
                    log_ok "剧集前缀已设置为: $PREFIX (手动输入)"
                fi

                preview_mode=0
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;

            3)
                echo -e ""
                echo -e "${gl_zi}>>> 设置季号${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                # 显示检测到的季号统计
                local season_array=()
                local season_count_array=()

                for info in "${episode_info[@]}"; do
                    IFS=':' read -r episode season type <<<"$info"
                    if [ "$season" != "01" ]; then
                        local found=0
                        for i in "${!season_array[@]}"; do
                            if [ "${season_array[i]}" = "$season" ]; then
                                season_count_array[i]=$((season_count_array[i] + 1))
                                found=1
                                break
                            fi
                        done

                        if [ $found -eq 0 ]; then
                            season_array+=("$season")
                            season_count_array+=(1)
                        fi
                    fi
                done

                if [ ${#season_array[@]} -gt 0 ]; then
                    echo -e "${gl_bai}从文件名检测到季号:${gl_bai}"
                    for i in "${!season_array[@]}"; do
                        local season="${season_array[i]}"
                        local count="${season_count_array[i]}"
                        local percentage=$((count * 100 / ${#files[@]}))
                        echo -e "  ${gl_bufan}S${season}:${gl_bai} ${count} 文件 (${percentage}%)"
                    done
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                fi

                echo -e "${gl_bai}当前季号: ${gl_bufan}S${SEASON}${gl_bai}"
                echo -e "${gl_bai}示例: ${gl_bufan}01${gl_bai} 表示第 ${gl_bufan}1${gl_bai} 季 (将显示为 S01)"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "$(echo -e "${gl_bai}请输入季号 (当前: ${gl_lv}S${SEASON}${gl_bai}，回车保持，${gl_huang}0${gl_bai}返回): ")" input_season

                [[ "$input_season" == "0" ]] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定

                if [ -z "$input_season" ]; then
                    # 回车保持
                    echo -e "${gl_bai}保持当前季号: S${SEASON}${gl_bai}"
                    continue
                fi

                if [[ "$input_season" =~ ^[0-9]{1,2}$ ]]; then
                    SEASON=$(safe_printf "%02d" "$input_season")
                    log_ok "季号已设置为: S$SEASON"
                    preview_mode=0
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                else
                    log_error "请输入有效的数字 (1-99)！"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                fi
                ;;

            4)
                echo -e ""
                echo -e "${gl_zi}>>> 设置起始集数${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                # 显示识别的集数范围
                if [ ${#episode_info[@]} -gt 0 ]; then
                    local first_info="${episode_info[0]}"
                    local last_info="${episode_info[-1]}"
                    IFS=':' read -r first_ep first_season first_type <<<"$first_info"
                    IFS=':' read -r last_ep last_season last_type <<<"$last_info"

                    echo -e "${gl_bai}识别的集数范围:${gl_bai}"
                    echo -e "  ${gl_bufan}最小:${gl_bai} E$(safe_printf "%02d" "$first_ep") (${first_type})"
                    echo -e "  ${gl_bufan}最大:${gl_bai} E$(safe_printf "%02d" "$last_ep") (${last_type})"
                    echo -e "  ${gl_bufan}建议:${gl_bai} 从 E$(safe_printf "%02d" "$first_ep") 开始"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                fi

                echo -e "${gl_bai}当前起始集数: ${gl_bufan}E$(safe_printf "%02d" "$START_EP")${gl_bai}"
                echo -e "${gl_bai}示例: ${gl_bufan}26${gl_bai} 表示从第 ${gl_bufan}26${gl_bai} 集开始编号"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "$(echo -e "${gl_bai}请输入起始集数 (当前: ${gl_lv}E$(safe_printf "%02d" "$START_EP")${gl_bai}，回车保持，${gl_huang}0${gl_bai}返回): ")" input_start

                [[ "$input_start" == "0" ]] && { cancel_return "上一级选单"; continue; } # break 或 continue 或 return ，视上下文而定

                if [ -z "$input_start" ]; then
                    # 回车保持
                    echo -e "${gl_bai}保持当前起始集数: E$(safe_printf "%02d" "$START_EP")${gl_bai}"
                    continue
                fi

                if [[ "$input_start" =~ ^[0-9]{1,3}$ ]] && [ "$input_start" -ge 1 ]; then
                    START_EP="$input_start"
                    log_ok "起始集数已设置为: E$(safe_printf "%02d" "$START_EP")"
                    preview_mode=0
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                else
                    log_error "请输入有效的集数 (1-999)！"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                fi
                ;;

            5)
                clear
                analyze_filename_patterns "${files[@]}"

                # 显示详细的文件分析
                echo -e ""
                echo -e "${gl_zi}>>> 详细文件分析${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                echo -e "${gl_bai}文件分析详情:${gl_bai}"
                for ((i = 0; i < ${#files[@]} && i < 10; i++)); do
                    local filename=$(basename -- "${files[$i]}")
                    IFS=':' read -r episode season type <<<"${episode_info[$i]}"
                    echo -e "  ${gl_bufan}$(safe_printf "%02d" $((i + 1))).${gl_bai} $filename"
                    echo -e "      识别为: ${type}"
                    echo -e "      季号: S${season}"
                    echo -e "      集数: E$(safe_printf "%02d" "$episode")"
                    echo ""
                done

                if [ ${#files[@]} -gt 10 ]; then
                    echo -e " ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} 还有 $((${#files[@]} - 10)) 个文件未显示${gl_bai}"
                fi

                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;

            6)
                if [ -z "$PREFIX" ]; then
                    log_error "请先设置剧集前缀！"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    exit_animation    # 即将退出动画
                    continue
                fi

                clear
                echo -e "${gl_zi}>>> 预览重命名结果${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_bufan}当前设置:${gl_bai}"
                echo -e "  ${gl_bufan}剧集前缀:${gl_bai} $PREFIX"
                echo -e "  ${gl_bufan}季号:${gl_bai} S$SEASON"
                echo -e "  ${gl_bufan}起始集数:${gl_bai} E$(safe_printf "%02d" "$START_EP")"
                if [ $auto_detected -eq 1 ]; then
                    echo -e "  ${gl_lv}✓ 智能检测已应用${gl_bai}"
                fi
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                local current_ep=$START_EP
                detection_results=()
                local summary_array=()
                local summary_count_array=()

                echo -e "${gl_bai}重命名预览:${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                for ((i = 0; i < ${#files[@]}; i++)); do
                    local file="${files[$i]}"
                    local filename=$(basename -- "$file")
                    local extension="${filename##*.}"
                    IFS=':' read -r original_ep original_season type <<<"${episode_info[$i]}"
                    local formatted_ep=$(safe_printf "%02d" "$current_ep")
                    local new_name="${PREFIX}-S${SEASON}E${formatted_ep}.${extension}"

                    # 记录统计信息
                    local found=0
                    for j in "${!summary_array[@]}"; do
                        if [ "${summary_array[j]}" = "$type" ]; then
                            summary_count_array[j]=$((summary_count_array[j] + 1))
                            found=1
                            break
                        fi
                    done

                    if [ $found -eq 0 ]; then
                        summary_array+=("$type")
                        summary_count_array+=(1)
                    fi

                    echo -e "  ${gl_bufan}[$(safe_printf "%02d" $((i + 1)))]${gl_bai}"
                    echo -e "    原文件: ${gl_hui}$filename${gl_bai}"
                    echo -e "    识别为: ${type} (E$(safe_printf "%02d" "$original_ep"))"
                    echo -e "    新文件: ${gl_lv}$new_name${gl_bai}"
                    echo ""

                    detection_results+=("$file:$new_name:$type:$original_ep")
                    ((current_ep++))
                done

                # 显示统计信息
                if [ ${#summary_array[@]} -gt 0 ]; then
                    echo -e "${gl_bai}识别模式统计:${gl_bai}"
                    for i in "${!summary_array[@]}"; do
                        local type="${summary_array[i]}"
                        local count="${summary_count_array[i]}"
                        local percentage=$((count * 100 / ${#files[@]}))
                        echo -e "  ${gl_bufan}${type}:${gl_bai} ${count} 文件 (${percentage}%)"
                    done
                fi

                preview_mode=1
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                # 计算识别准确率
                local accurate_count=0
                for i in "${!summary_array[@]}"; do
                    local type="${summary_array[i]}"
                    if [[ "$type" == "SxE格式" ]] || [[ "$type" == "EP格式" ]] || [[ "$type" == "中文第X集" ]]; then
                        accurate_count=$((accurate_count + summary_count_array[i]))
                    fi
                done

                local accuracy=0
                if [ ${#files[@]} -gt 0 ]; then
                    accuracy=$((accurate_count * 100 / ${#files[@]}))
                fi

                log_info "预览完成，共 ${#detection_results[@]} 个文件"
                if [ ${#files[@]} -gt 0 ]; then
                    log_info "识别准确率: ${accuracy}%"
                fi
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;

            7)
                if [ $preview_mode -eq 0 ]; then
                    log_error "请先预览重命名结果！"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    exit_animation    # 即将退出动画
                    continue
                fi

                if [ ${#detection_results[@]} -eq 0 ]; then
                    log_error "没有可重命名的文件！"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    exit_animation    # 即将退出动画
                    continue
                fi

                clear
                echo -e "${gl_zi}>>> 确认重命名${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                # 显示重命名统计
                local type_array=()
                local type_count_array=()

                for item in "${detection_results[@]}"; do
                    IFS=':' read -r old_file new_name type original_ep <<<"$item"

                    local found=0
                    for i in "${!type_array[@]}"; do
                        if [ "${type_array[i]}" = "$type" ]; then
                            type_count_array[i]=$((type_count_array[i] + 1))
                            found=1
                            break
                        fi
                    done

                    if [ $found -eq 0 ]; then
                        type_array+=("$type")
                        type_count_array+=(1)
                    fi
                done

                echo -e "${gl_bai}重命名统计:${gl_bai}"
                echo -e "  ${gl_bufan}总文件数:${gl_bai} ${#detection_results[@]}"
                for i in "${!type_array[@]}"; do
                    local type="${type_array[i]}"
                    local count="${type_count_array[i]}"
                    echo -e "  ${gl_bufan}${type}:${gl_bai} ${count} 文件"
                done
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                read -r -e -p "$(echo -e "${gl_bai}确定要执行重命名吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

                case "$confirm" in
                [Yy])
                    log_info "开始重命名 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    rename_count=0
                    local success_count=0
                    local fail_count=0

                    for item in "${detection_results[@]}"; do
                        IFS=':' read -r old_file new_name type original_ep <<<"$item"

                        if [ -f "$old_file" ]; then
                            echo -e "${gl_bai}处理: ${gl_hui}$(basename "$old_file")${gl_bai}"
                            echo -e "  识别: ${type} (E$(safe_printf "%02d" "$original_ep"))"

                            if mv -- "$old_file" "./$new_name" 2>/dev/null; then
                                echo -e "  ${gl_lv}✓ 重命名为: $new_name${gl_bai}"
                                ((success_count++))
                            else
                                echo -e "  ${gl_hong}✗ 重命名失败${gl_bai}"
                                ((fail_count++))
                            fi
                        else
                            echo -e "${gl_huang}⚠ 文件不存在: $(basename "$old_file")${gl_bai}"
                            ((fail_count++))
                        fi
                        echo ""
                    done

                    rename_count=$success_count
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    echo -e "${gl_lv}成功:${gl_bai} $success_count 个文件"
                    echo -e "${gl_hong}失败:${gl_bai} $fail_count 个文件"
                    log_ok "重命名完成！"

                    preview_mode=0
                    auto_detected=0
                    detection_results=()
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                    ;;

                [Nn])
                    log_info "已取消重命名操作"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                    ;;

                *)
                    handle_y_n        # 无效的输入,请输入(y或N)。
                    ;;
                esac
                ;;

            0)
                if [ $rename_count -gt 0 ]; then
                    log_ok "操作完成，已重命名 $rename_count 个文件"
                fi
                cancel_return
                return
                ;;
            00 | 000 | 0000) exit_script ;; # 感谢使用，再见！
            *) handle_invalid_input ;;      # 无效的输入,请重新输入!
            esac
        done
    }

    # 批量测试不同识别模式
    test_all_recognition_modes() {
        clear
        echo -e "${gl_zi}>>> 批量测试识别模式${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 测试用例
        local test_cases=(
            "电视剧集.How.Dare.You.S01E26.2026.2160p.IQ.WEB-DL.H265.DDP5.1-ColorWEB.mkv|SxE格式|S01E26"
            "EP26-剧情发展.mp4|EP格式|EP26"
            "第26集.电视剧名.avi|中文第X集|第26集"
            "26-剧集名.mov|数字格式|26"
            "01.第一集.mkv|开头数字|01"
            "S1E1.测试.mkv|SxE格式|S1E1"
            "Episode.1.mkv|EP格式|EP1"
            "test-26-video.mkv|数字格式|26"
            "2026.2160p.WEB-DL.mkv|未识别|未识别"
            "电影名.1080p.mp4|未识别|未识别"
        )

        echo -e "${gl_bai}测试识别引擎准确性:${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        local total_cases=${#test_cases[@]}
        local correct_cases=0
        local partially_correct=0

        for test_case in "${test_cases[@]}"; do
            IFS='|' read -r filename expected_type expected_pattern <<<"$test_case"

            echo -e "  ${gl_bufan}测试文件:${gl_bai} ${gl_hui}$filename${gl_bai}"

            # 运行识别
            local results=($(enhanced_extract_episode_info "$filename"))
            local first_result="${results[0]}"
            IFS=':' read -r pattern season episode type <<<"$first_result"

            if [ "$type" = "$expected_type" ]; then
                echo -e "  ${gl_lv}✓ 正确识别: ${type} (${pattern})${gl_bai}"
                ((correct_cases++))
            elif [ "$type" != "未识别" ] && [ "$expected_type" != "未识别" ]; then
                echo -e "  ${gl_huang}⚠ 部分识别: ${type} (预期: ${expected_type})${gl_bai}"
                ((partially_correct++))
            else
                echo -e "  ${gl_hong}✗ 识别错误: ${type} (预期: ${expected_type})${gl_bai}"
            fi

            # 显示所有可能的识别结果
            if [ ${#results[@]} -gt 1 ]; then
                echo -e "  ${gl_bai}所有可能的识别:${gl_bai}"
                for result in "${results[@]}"; do
                    IFS=':' read -r p s e t <<<"$result"
                    echo -e "    - ${t}: ${p} (S${s}E${e})"
                done
            fi

            echo ""
        done

        local accuracy=0
        local partial_accuracy=0
        if [ $total_cases -gt 0 ]; then
            accuracy=$((correct_cases * 100 / total_cases))
            partial_accuracy=$(((correct_cases + partially_correct) * 100 / total_cases))
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}识别准确率统计:${gl_bai}"
        echo -e "  ${gl_bufan}测试用例:${gl_bai} $total_cases 个"
        echo -e "  ${gl_lv}完全正确:${gl_bai} $correct_cases 个"
        echo -e "  ${gl_huang}部分正确:${gl_bai} $partially_correct 个"
        echo -e "  ${gl_bufan}完全准确率:${gl_bai} ${accuracy}%"
        echo -e "  ${gl_bufan}部分准确率:${gl_bai} ${partial_accuracy}%"

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # 创建多种格式测试文件
    create_mixed_test_files() {
        echo -e ""
        echo -e "${gl_zi}>>> 创建多种格式测试文件${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "$(echo -e "${gl_bai}要创建多少个测试文件? (默认: ${gl_lv}16${gl_bai}, ${gl_huang}0${gl_bai}返回): ")" file_count

        [[ "$file_count" == "0" ]] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定

        # 处理空输入，使用默认值16
        if [ -z "$file_count" ]; then
            file_count=16
            log_info "使用默认值: ${gl_lv}16${gl_bai} 个文件"
        fi

        if ! [[ "$file_count" =~ ^[0-9]+$ ]] || [ "$file_count" -lt 1 ]; then
            log_error "请输入有效的数字！"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi

        log_info "${gl_bai}正在创建 ${gl_huang}$file_count ${gl_bai}个测试文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        for i in $(seq 1 $file_count); do
            case $((i % 6)) in
            0) filename="S01E$(printf "%02d" $i).2026.2160p.WEB-DL.mkv" ;;
            1) filename="EP$(printf "%02d" $i)-剧情发展.mp4" ;;
            2) filename="第$(printf "%d" $i)集.电视剧名.avi" ;;
            3) filename="$(printf "%02d" $i)-剧集名.mov" ;;
            4) filename="电视剧.S01E$(printf "%02d" $i).WEBRip.wmv" ;;
            5) filename="test$(printf "%d" $i).480p.mpeg" ;;
            esac

            touch "$filename"
            echo -e "  ${gl_lv}创建:${gl_bai} $filename"
        done

        log_ok "${gl_bai}创建完成！共创建 ${gl_lv}$file_count ${gl_bai}个测试文件"
        log_info "包含多种识别格式"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # 查看当前文件函数
    show_current_files() {

        # echo -e "${gl_bufan}视频文件:${gl_bai}"
        local video_count=0

        for ext in mp4 mkv avi mov wmv flv webm m4v mpg mpeg kvm; do
            for file in *."$ext"; do
                if [ -f "$file" ]; then
                    echo -e "  ${gl_bufan}▶${gl_bai} $file"
                    ((video_count++))
                fi
            done 2>/dev/null || true
        done

        if [ $video_count -eq 0 ]; then
            echo -e "  ${gl_huang}无视频文件${gl_bai}"
        fi

        echo -e ""
        echo -e "${gl_huang}文件统计:${gl_bai}"
        echo -e "  ${gl_bai}视频文件:${gl_lv} $video_count ${gl_bai}个"
    }

    # 删除测试文件函数
    delete_test_files() {
        echo -e ""
        echo -e "${gl_zi}>>> 删除测试文件${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "$(echo -e "${gl_bai}确定要删除所有测试文件吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

        case "$confirm" in
        [Yy])
            local count=0
            for ext in mp4 mkv avi mov wmv flv webm m4v mpg mpeg kvm; do
                for file in *."$ext"; do
                    if [ -f "$file" ]; then
                        rm -f "$file"
                        echo -e "  ${gl_hong}删除:${gl_bai} $file"
                        ((count++))
                    fi
                done 2>/dev/null || true
            done

            if [ $count -gt 0 ]; then
                log_ok "删除完成！共删除 $count 个文件"
            else
                log_warn "没有找到测试文件"
            fi
            ;;

        [Nn])
            log_info "已取消删除操作"
            ;;

        *) handle_y_n ;;        # 无效的输入,请输入(y或N)。
        esac
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # 快速重命名功能
    quick_rename() {
        clear
        echo -e "${gl_zi}>>> 快速重命名${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 支持的视频文件扩展名
        local VIDEO_EXTS=("mp4" "mkv" "avi" "mov" "wmv" "flv" "webm" "m4v" "mpg" "mpeg" "kvm")

        # 生成扩展名匹配字符串
        local ext_pattern=""
        for ext in "${VIDEO_EXTS[@]}"; do
            if [ -z "$ext_pattern" ]; then
                ext_pattern="-name \"*.$ext\""
            else
                ext_pattern="$ext_pattern -o -name \"*.$ext\""
            fi
        done

        # 收集文件
        log_info "扫描当前目录视频文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        local files=()
        while IFS= read -r file; do
            if [ -f "$file" ]; then
                files+=("$file")
            fi
        done < <(eval "find . -maxdepth 1 -type f \( $ext_pattern \) 2>/dev/null" | sort -V)

        if [ ${#files[@]} -eq 0 ]; then
            log_error "未找到视频文件！"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi

        echo -e "${gl_bai}找到 ${#files[@]} 个视频文件:${gl_bai}"
        for ((i = 0; i < ${#files[@]}; i++)); do
            local filename=$(basename -- "${files[$i]}")
            echo -e "  ${gl_bufan}$(safe_printf "%02d" $((i + 1))).${gl_bai} $filename"
        done

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 询问重命名格式
        echo -e "${gl_bai}请选择重命名方式:${gl_bai}"
        echo -e "  ${gl_bufan}1.${gl_bai} 自动识别剧集编号并重命名"
        echo -e "  ${gl_bufan}2.${gl_bai} 手动输入前缀和起始集数"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "$(echo -e "${gl_bai}请输入你的选择 (${gl_huang}0${gl_bai}返回): ")" rename_method

        [[ "$rename_method" == "0" ]] && { cancel_return; return 1; }

        case $rename_method in
        1)
            # 自动识别模式
            rename_tv_files_ultimate
            ;;
        2)
            # 手动模式
            clear
            echo -e "${gl_zi}>>> 手动重命名设置${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            read -r -e -p "$(echo -e "${gl_bai}请输入剧集前缀: ")" prefix
            if [ -z "$prefix" ]; then
                log_error "剧集前缀不能为空！"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                exit_animation    # 即将退出动画
                return
            fi

            read -r -e -p "$(echo -e "${gl_bai}请输入季号 (默认 ${gl_lv}01${gl_bai}): ")" season
            season="${season:-01}"

            read -r -e -p "$(echo -e "${gl_bai}请输入起始集数 (默认 ${gl_lv}1${gl_bai}): ")" start_ep
            start_ep="${start_ep:-1}"

            # 预览
            clear
            echo -e "${gl_zi}>>> 预览重命名结果${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}将重命名 ${#files[@]} 个文件:${gl_bai}"

            for ((i = 0; i < ${#files[@]}; i++)); do
                local file="${files[$i]}"
                local filename=$(basename -- "$file")
                local extension="${filename##*.}"
                local episode=$((start_ep + i))
                local formatted_ep=$(safe_printf "%02d" "$episode")
                local new_name="${prefix}-S${season}E${formatted_ep}.${extension}"

                echo -e "  ${gl_hui}$filename${gl_bai}"
                echo -e "  ${gl_lv}→ $new_name${gl_bai}"
                echo ""
            done

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}确定要执行重命名吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

            case "$confirm" in
            [Yy])
                log_info "开始重命名 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                local success_count=0

                for ((i = 0; i < ${#files[@]}; i++)); do
                    local file="${files[$i]}"
                    local filename=$(basename -- "$file")
                    local extension="${filename##*.}"
                    local episode=$((start_ep + i))
                    local formatted_ep=$(safe_printf "%02d" "$episode")
                    local new_name="${prefix}-S${season}E${formatted_ep}.${extension}"

                    if mv -- "$file" "./$new_name" 2>/dev/null; then
                        echo -e "  ${gl_lv}✓ $filename → $new_name${gl_bai}"
                        ((success_count++))
                    else
                        echo -e "  ${gl_hong}✗ 重命名失败: $filename${gl_bai}"
                    fi
                done

                log_ok "重命名完成！成功 $success_count 个文件"
                ;;

            [Nn])
                log_info "已取消重命名操作"
                ;;

            *) handle_y_n ;;       # 无效的输入,请重新输入!
            esac

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;

        *) handle_y_n; return ;;       # 无效的输入,请重新输入!
        esac
    }

    # 交互式移动视频文件函数
    move_videos_interactive() {
        clear
        # 检查当前目录是否为空，如果为空则显示提示并返回错误
        check_directory_empty "." "移动视频文件" "true" || return

        local source_dir="$(pwd)"
        echo -e "${gl_huang}>>> 当前目录文件列表：${gl_bai}(${gl_lv}${source_dir}${gl_bai})"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        show_current_files
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e ""
        echo -e "${gl_zi}>>> 移动视频文件${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}将移动${gl_lv}${source_dir}${gl_huang}目录下的所有视频文件${gl_bai}"
        echo -e "${gl_lv}/vol2/1000/media/电视剧集/国产剧/xxx/Season 1${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 2. 询问目标目录
        while true; do
            read -r -e -p "$(echo -e "${gl_bai}请输入目标目录 (${gl_huang}0${gl_bai}返回): ")" target_dir

            # 检查是否返回
            [[ "$target_dir" == "0" ]] && { cancel_return; return 1; }

            # 检查输入是否为空
            if [ -z "$target_dir" ]; then
                log_error "目标目录不能为空, 请重新输入"
                continue
            fi
            break
        done

        # 检查是否需要创建目录
        if [ ! -d "$target_dir" ]; then
            read -r -e -p "$(echo -e "${gl_bai}目录不存在, 是否创建? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" create_dir
            case "$create_dir" in
            [Yy])
                mkdir -p "$target_dir"
                if [ $? -ne 0 ]; then
                    log_error "创建目录失败！"
                    exit_animation    # 即将退出动画
                    return 1
                fi
                log_ok "目录已创建: ${target_dir}"
                ;;
            [Nn] | "")
                log_error "操作取消: 目录不存在"
                exit_animation    # 即将退出动画
                return 1
                ;;
            *)
                handle_y_n        # 无效的输入,请输入(y或N)。
                return 1
                ;;
            esac
        else
            log_info "目标目录已存在: ${target_dir}"
        fi

        clear
        echo -e "${gl_huang}>>> 将移动${gl_lv}${source_dir}${gl_huang}目录下的所有视频文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 3. 扫描视频文件
        log_info "正在扫描视频文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 视频文件扩展名数组
        local video_extensions=("mp4" "avi" "mkv" "mov" "wmv" "flv" "webm"
            "m4v" "mpg" "mpeg" "3gp" "mts" "m2ts"
            "ts" "vob" "ogg" "ogv" "divx" "f4v")

        local found_files=()
        local found_count=0

        # 查找视频文件
        for ext in "${video_extensions[@]}"; do
            while IFS= read -r -d '' file; do
                if [ -f "$file" ]; then
                    found_files+=("$file")
                    ((found_count++))
                fi
            done < <(find "$source_dir" -maxdepth 1 -type f -iname "*.$ext" -print0 2>/dev/null)
        done

        if [ $found_count -eq 0 ]; then
            log_warn "未找到任何视频文件"
            return 0
        fi

        # 显示找到的文件
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}找到的文件${gl_bai}"

        for file in "${found_files[@]}"; do
            filename=$(basename "$file")
            echo -e "  ${gl_hui}${filename}${gl_bai}"
        done

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lv}共找到 ${gl_huang}${found_count} ${gl_lv}个视频文件${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 4. 确认移动
        read -r -e -p "$(echo -e "${gl_bai}确认移动到 '${gl_huang}${target_dir}${gl_bai}'目录吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_move
        case "$confirm_move" in
        [Yy])
            echo -e "${gl_bai}正在移动文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            ;;
        [Nn] | "")
            log_info "操作已取消"
            exit_animation    # 即将退出动画
            return 0
            ;;
        *)
            handle_y_n        # 无效的输入,请输入(y或N)。
            return 1
            ;;
        esac

        # 5. 执行移动操作
        local moved_count=0
        local failed_count=0

        for file in "${found_files[@]}"; do
            if [ -f "$file" ]; then
                filename=$(basename "$file")

                # 检查目标文件是否已存在
                if [ -f "$target_dir/$filename" ]; then
                    log_warn "目标文件已存在, 跳过: ${filename}"
                    ((failed_count++))
                    continue
                fi

                # 移动文件
                if mv "$file" "$target_dir/" 2>/dev/null; then
                    ((moved_count++))
                    echo -e "  ${gl_lv}✓${gl_bai} 移动: ${filename}"
                else
                    log_error "移动失败: ${filename}"
                    ((failed_count++))
                fi
            fi
        done

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 6. 显示结果
        if [ $moved_count -gt 0 ]; then
            log_ok "移动完成!"
            echo -e "${gl_lv}移动成功: ${moved_count} 个文件${gl_bai}"
            echo -e "${gl_lan}目标目录: ${target_dir}${gl_bai}"

            if [ $failed_count -gt 0 ]; then
                echo -e "${gl_huang}移动失败: ${failed_count} 个文件${gl_bai}"
            fi

            # 询问是否打开目录
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}是否切换到目标目录? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" open_dir
            case "$open_dir" in
            [Yy])
                clear
                cd "$target_dir"
                local source_dir="$(pwd)"
                echo -e "${gl_huang}>>> 当前目录文件列表：${gl_bai}(${gl_lv}${source_dir}${gl_bai})"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                show_current_files
                ;;
            esac
        else
            log_error "没有文件被移动"
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # 主菜单
    main_menu() {
        while true; do
            clear
            echo -e "${gl_zi}>>> 刮削目录结构示例${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}庆余年/${gl_bai}                      ${gl_hui}<-- ${gl_lan}电视剧根目录${gl_hui} (可含年份：庆余年 (2024))${gl_bai}"
            echo -e "${gl_bufan}     ├──${gl_lv}Season 01/${gl_bai}           ${gl_hui}<-- ${gl_lan}第一季文件夹${gl_hui} (标准命名：Season XX)${gl_bai}"
            echo -e "${gl_bufan}     │   ├──${gl_huang}庆余年-S01E01.mkv${gl_bai}"
            echo -e "${gl_bufan}     │   ├──${gl_huang}庆余年-S01E02.mkv${gl_bai}"
            echo -e "${gl_bufan}     │   └── ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}     └──${gl_lv}Season 02/${gl_bai}           ${gl_hui}<-- ${gl_lan}第二季文件夹${gl_hui} (标准命名：Season XX)${gl_bai}"
            echo -e "${gl_bufan}         ├──${gl_huang}庆余年-S02E01.mkv${gl_bai}"
            echo -e "${gl_bufan}         ├──${gl_huang}庆余年-S02E02.mkv${gl_bai}"
            echo -e "${gl_bufan}         └── ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e ""
            local source_dir="$(pwd)"
            echo -e "${gl_huang}>>> 当前目录文件列表：${gl_bai}(${gl_lv}${source_dir}${gl_bai})"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            # ls --color=auto -xA
            show_current_files
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e ""
            echo -e "${gl_zi}>>> 电视剧文件重命名${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}1.  ${gl_bai}进入指定目录         ${gl_bufan}2.  ${gl_bai}返回上一级目录"
            echo -e "${gl_bufan}3.  ${gl_bai}快速重命名           ${gl_bufan}4.  ${gl_bai}详细重命名"
            echo -e "${gl_bufan}5.  ${gl_bai}创建测试文件         ${gl_bufan}6.  ${gl_bai}删除测试文件"
            echo -e "${gl_bufan}7.  ${gl_bai}移动视频文件         ${gl_bufan}8.  ${gl_bai}测试识别模式"
            echo -e "${gl_bufan}9.  ${gl_bai}常用目录管理         ${gl_bufan}10. ${gl_bai}批量重命名"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单       ${gl_hong}00. ${gl_bai}退出脚本"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            read -r -e -p "$(echo -e "${gl_bai}请输入你的选择: ")" choice

            case $choice in
            1)  enter_directory "电视剧文件重命名" ;;                  # 进入指定目录
            2)  go_parent_directory ;;                               # 返回上一级目录
            3)  quick_rename ;;                                      # 快速重命名
            4)  rename_tv_files_ultimate ;;                          # 详细重命名
            5)  create_mixed_test_files ;;                           # 创建测试文件
            6)  delete_test_files ;;                                 # 删除测试文件
            7)  move_videos_interactive ;;                           # 移动视频文件
            8)  test_all_recognition_modes ;;                        # 测试识别模式
            9)  manage_backup_files_simple "tv_rename_ultimate" ;;   # 常用目录管理
            10) batch_rename_files ;;                                # 批量重命名
            0)  cancel_return; break ;;                              # 返回到上一级菜单
            00 | 000 | 0000) exit_script ;;                          # 感谢使用，再见！
            *) handle_invalid_input ;;                               # 无效的输入,请重新输入!
            esac
        done
    }

    # 进入主菜单
    main_menu
}

# 格式化并复制脚本函数
format_and_copy_script() {
    local script_path="/root/mobufan.sh"
    local target_dir="/mnt/tmp"
    
    # 检查脚本文件是否存在
    if [[ ! -f "$script_path" ]]; then
        echo -e "${gl_hong}错误: 脚本文件 $script_path 不存在${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 检查目标目录是否存在
    if [[ ! -d "$target_dir" ]]; then
        echo -e "${gl_huang}目标目录不存在，正在创建: $target_dir${gl_bai}"
        if mkdir -p "$target_dir" 2>/dev/null; then
            echo -e "${gl_lv}✓ 目标目录已创建${gl_bai}"
        else
            echo -e "${gl_hong}错误: 无法创建目标目录 $target_dir${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        fi
    fi
    
    install shfmt lrzsz
    clear
    echo -e "${gl_zi}>>> 开始格式化脚本 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 备份原始文件
    local backup_path="${script_path}.backup.$(date +%Y%m%d%H%M%S)"
    if cp "$script_path" "$backup_path"; then
        echo -e "${gl_bai}原始脚本已备份到: ${gl_huang}${backup_path}${gl_bai}"
    else
        echo -e "${gl_huang}警告: 无法备份原始脚本，继续格式化 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    fi
    
    # 格式化脚本
    echo -e "${gl_bai}正在格式化脚本 ${gl_huang}${script_path} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if shfmt -i 4 -w "$script_path"; then
        echo -e "${gl_lv}✓ 脚本格式化完成${gl_bai}"
        
        # 显示格式化前后对比
        echo -e "${gl_bai}格式化前后行数对比:${gl_bai}"
        original_lines=$(wc -l < "$backup_path")
        formatted_lines=$(wc -l < "$script_path")
        echo -e "  ${gl_bai}原始: ${gl_huang}${original_lines}${gl_bai} 行"
        echo -e "  ${gl_bai}格式化后: ${gl_lv}${formatted_lines}${gl_bai} 行"
    else
        echo -e "${gl_hong}错误: 脚本格式化失败${gl_bai}"
        return 1
    fi
    
    # 复制到目标目录
    echo -e "${gl_bai}复制脚本到 ${gl_lv}${target_dir} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if cp "$script_path" "$target_dir/"; then
        echo -e "${gl_lv}✓ 脚本已复制到 ${target_dir}/${gl_bai}"
        
        # 显示目标文件信息
        local target_file="${target_dir}/$(basename "$script_path")"
        if [[ -f "$target_file" ]]; then
            echo -e "${gl_bai}目标文件信息:${gl_bai}"
            echo -e "  ${gl_bai}路径: ${gl_lv}${target_file}${gl_bai}"
            echo -e "  ${gl_bai}大小: ${gl_huang}$(ls -lh "$target_file" | awk '{print $5}')${gl_bai}"
            echo -e "  ${gl_bai}权限: ${gl_zi}$(ls -lh "$target_file" | awk '{print $1}')${gl_bai}"
            echo -e "  ${gl_bai}修改时间: ${gl_bai}$(stat -c %y "$target_file" | cut -d. -f1)${gl_bai}"
        fi
    else
        echo -e "${gl_hong}错误: 复制脚本失败${gl_bai}"
        return 1
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_lv}✓ 脚本格式化并复制完成!${gl_bai}"
    echo -e "${gl_bai}原始文件备份: ${gl_huang}${backup_path}${gl_bai}"
    echo -e "${gl_bai}格式化后文件: ${gl_lv}${script_path}${gl_bai}"
    echo -e "${gl_bai}复制目标位置: ${gl_lv}${target_dir}/$(basename "$script_path")${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 询问是否下载到本地
    echo ""
    echo -e "${gl_huang}>>> 是否下载脚本到本地Windows？${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}是否使用sz命令下载脚本到本地? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" download_choice
    
    if [[ "$download_choice" == "y" || "$download_choice" == "Y" ]]; then
        echo ""
        echo -e "${gl_bai}正在下载脚本 ${gl_huang}${script_path} ${gl_bai}到本地Windows ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_huang}请确保您的终端支持Zmodem协议${gl_bai}"
        echo -e "${gl_bai}支持的终端: MobaXterm, Xshell, SecureCRT等${gl_bai}"
        echo -e "${gl_huang}注意: PuTTY不支持Zmodem协议${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        # 检查sz命令是否可用
        if command -v sz >/dev/null 2>&1; then
            echo -e "${gl_bai}执行命令: ${gl_zi}sz \"${script_path}\"${gl_bai}"
            echo ""
            
            # 显示文件信息
            echo -e "${gl_bai}文件信息:${gl_bai}"
            echo -e "  ${gl_bai}文件名: ${gl_huang}$(basename "$script_path")${gl_bai}"
            echo -e "  ${gl_bai}大小: ${gl_huang}$(ls -lh "$script_path" | awk '{print $5}')${gl_bai}"
            echo -e "  ${gl_bai}路径: ${gl_lv}${script_path}${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            # 倒计时提示
            for i in {2..1}; do
                echo -ne "${gl_huang}将在 ${gl_lv}$i${gl_bai} 秒后开始下载，请准备好接收文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\r"
                sleep_fractional 1
            done
            echo ""
            
            # 执行sz命令
            sz "$script_path"
            
            if [[ $? -eq 0 ]]; then
                echo -e "${gl_lv}✓ 文件传输完成!${gl_bai}"
                echo -e "${gl_bai}脚本已保存到Windows下载目录${gl_bai}"
            else
                echo -e "${gl_huang}⚠ 文件传输可能被中断或取消${gl_bai}"
                echo -e "${gl_huang}如果下载失败，可尝试以下方法:${gl_bai}"
                echo -e "  ${gl_bufan}1. ${gl_bai}检查终端是否支持Zmodem"
                echo -e "  ${gl_bufan}2. ${gl_bai}使用其他下载方法:"
                echo -e "      ${gl_zi}scp root@服务器IP:${script_path} .${gl_bai}"
                echo -e "      ${gl_zi}wget http://服务器IP:8000/$(basename "$script_path")${gl_bai}"
            fi
        else
            echo -e "${gl_hong}错误: sz命令不可用${gl_bai}"
            echo -e "${gl_huang}尝试安装lrzsz:${gl_bai}"
            echo -e "${gl_bai}Ubuntu/Debian: ${gl_zi}sudo apt install lrzsz${gl_bai}"
            echo -e "${gl_bai}CentOS/RHEL: ${gl_zi}sudo yum install lrzsz${gl_bai}"
            echo -e "${gl_huang}或使用其他下载方法:${gl_bai}"
            echo -e "${gl_bai}1. 通过SCP: ${gl_zi}scp root@服务器IP:${script_path} .${gl_bai}"
            echo -e "${gl_bai}2. 通过HTTP: ${gl_zi}python3 -m http.server 8000${gl_bai}"
        fi
    else
        echo -e "${gl_bai}跳过下载到本地${gl_bai}"
        echo -e "${gl_huang}提示: 您可以使用以下命令手动下载:${gl_bai}"
        echo -e "  ${gl_zi}sz /root/mobufan.sh${gl_bai}"
        echo -e "  ${gl_zi}scp root@$(hostname -I | awk '{print $1}'):/root/mobufan.sh .${gl_bai}"
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_lv}✓ 所有操作完成!${gl_bai}"
    echo -e "${gl_bai}脚本位置: ${gl_huang}${script_path}${gl_bai}"
    echo -e "${gl_bai}备份位置: ${gl_huang}${backup_path}${gl_bai}"
    echo -e "${gl_bai}复制位置: ${gl_lv}${target_dir}/$(basename "$script_path")${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    break_end
    return 0
}

###### 上传文件到服务器
rz_upload_file() {
    install lrzsz
    clear
    if ! list_files "." 0 4; then
        return
    fi
    echo -e ""
    echo -e "${gl_zi}>>> 上传文件到服务器 (rz)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "准备接收来自本地的文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bai}终端支持检测:${gl_bai}"
    echo -e "${gl_bai}支持的终端: ${gl_lv}MobaXterm, Xshell, SecureCRT, Tabby, WindTerm${gl_bai}"
    echo -e "${gl_huang}注意: PuTTY 不支持Zmodem协议${gl_bai}"
    echo -e "${gl_huang}注意: Windows Terminal 需安装lrzsz并配置${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    echo -e "${gl_huang}请在本地客户端选择要上传的文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    
    for i in {2..1}; do
        echo -ne "${gl_huang}将在 ${gl_lv}$i${gl_bai} 秒后弹出文件选择对话框${gl_bai}\r"
        sleep_fractional 1
    done
    echo ""
    
    if command -v rz >/dev/null 2>&1; then
        echo -e "${gl_bai}执行命令: ${gl_zi}rz${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}提示: 按${gl_lv}Ctrl+C${gl_bai}取消上传${gl_bai}"
        
        if rz; then
            log_ok "文件上传成功!"
            echo -e "${gl_bai}上传的文件:${gl_bai}"
            ls -lth | head -5
        else
            if [[ $? -eq 130 ]]; then
                log_info "上传被用户取消"
            else
                log_warn "文件上传失败，请检查终端是否支持Zmodem"
            fi
        fi
    else
        log_error "rz命令不可用，请先安装lrzsz"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 上传文件夹
# 上传文件夹函数（支持压缩上传）
rz_upload_compressed_file() {
    clear
    echo -e "${gl_zi}>>> 上传文件夹到服务器 (压缩上传)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "此功能将本地文件夹压缩后上传到服务器"
    echo -e "${gl_bai}支持格式:${gl_bai}"
    echo -e "  ${gl_bufan}1. ${gl_bai}通过rz上传ZIP/TAR压缩包"
    echo -e "  ${gl_bufan}2. ${gl_bai}自动解压到当前目录"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 记录上传前的文件列表
    local -a files_before
    files_before=(*)
    
    read -r -e -p "$(echo -e "${gl_bai}是否自动解压? (${gl_lv}y${gl_bai}/${gl_hong}n${gl_bai}): ")" extract_choice
    
    for i in {2..1}; do
        echo -ne "${gl_huang}将在 ${gl_lv}$i${gl_bai} 秒后开始上传 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\r"
        sleep_fractional 1
    done
    echo ""
    
    if ! command -v rz >/dev/null 2>&1; then
        log_error "rz命令不可用，请先安装 lrzsz"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    echo -e "${gl_huang}提示: 按${gl_lv}Ctrl+C${gl_bai}取消上传${gl_bai}"
    echo -e "${gl_lv}请在选择文件对话框中选择要上传的压缩包 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    
    if ! rz; then
        local exit_code=$?
        if [[ $exit_code -eq 130 ]]; then
            log_info "上传被用户取消"
        else
            log_warn "文件上传失败，请检查终端是否支持Zmodem"
        fi
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # ========== 智能检测新上传的文件 ==========
    local -a files_after
    local -a new_files
    files_after=(*)
    new_files=()
    
    # 找出新增的文件
    for f in "${files_after[@]}"; do
        local is_new=true
        for old in "${files_before[@]}"; do
            [[ "$f" == "$old" ]] && is_new=false && break
        done
        [[ "$is_new" == true ]] && new_files+=("$f")
    done
    
    # 检查是否找到新文件
    if [[ ${#new_files[@]} -eq 0 ]]; then
        log_warn "未检测到新上传的文件"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 如果上传了多个，取第一个（或让用户选择）
    local zip_file
    if [[ ${#new_files[@]} -eq 1 ]]; then
        zip_file="${new_files[0]}"
        log_ok "检测到上传文件: ${gl_huang}${zip_file}${gl_bai} (${gl_lv}$(du -h "$zip_file" 2>/dev/null | cut -f1)${gl_bai})"
    else
        log_info "检测到多个新文件:"
        local i=1
        for f in "${new_files[@]}"; do
            echo -e "  ${gl_lv}${i}.${gl_bai} $f ${gl_huang}($(du -h "$f" 2>/dev/null | cut -f1)${gl_bai})"
            ((i++))
        done
        read -r -e -p "$(echo -e "${gl_bai}请选择要处理的文件编号 [1-${#new_files[@]}]: ")" choice
        if [[ "$choice" =~ ^[0-9]+$ ]] && (( choice >= 1 && choice <= ${#new_files[@]} )); then
            zip_file="${new_files[$((choice-1))]}"
        else
            log_error "无效选择"
            exit_animation    # 即将退出动画
            return 1
        fi
    fi
    
    # ========== 解压逻辑 ==========
    if [[ "$extract_choice" == "y" || "$extract_choice" == "Y" ]]; then
        log_info "正在解压: ${gl_huang}${zip_file}${gl_bai}"
        local extract_success=false
        
        # ZIP
        if [[ "$zip_file" == *.zip ]]; then
            if command -v unzip >/dev/null 2>&1; then
                if unzip -o "$zip_file" 2>/dev/null; then
                    log_ok "ZIP解压完成 → 当前目录"
                    extract_success=true
                else
                    log_error "ZIP解压失败"
                fi
            else
                log_error "缺少unzip命令: apt install unzip / yum install unzip"
            fi
            
        # TAR.GZ / TGZ
        elif [[ "$zip_file" == *.tar.gz || "$zip_file" == *.tgz ]]; then
            if [[ -f "$zip_file" ]] && file "$zip_file" | grep -q "gzip compressed data"; then
                if tar -xzf "$zip_file" 2>/dev/null; then
                    log_ok "TAR.GZ解压完成 → 当前目录"
                    extract_success=true
                else
                    log_error "TAR.GZ解压失败，可能是文件损坏或权限问题"
                fi
            else
                log_error "文件格式不匹配或文件已损坏"
            fi
            
        # TAR.BZ2
        elif [[ "$zip_file" == *.tar.bz2 ]]; then
            if [[ -f "$zip_file" ]] && (file "$zip_file" | grep -q "bzip2 compressed data" || file "$zip_file" | grep -q "tar archive"); then
                if tar -xjf "$zip_file" 2>/dev/null; then
                    log_ok "TAR.BZ2解压完成 → 当前目录"
                    extract_success=true
                else
                    log_error "TAR.BZ2解压失败，可能是文件损坏或权限问题"
                fi
            else
                log_error "文件格式不匹配或文件已损坏"
            fi
            
        # TAR.XZ
        elif [[ "$zip_file" == *.tar.xz ]]; then
            if [[ -f "$zip_file" ]] && (file "$zip_file" | grep -q "XZ compressed data" || file "$zip_file" | grep -q "tar archive"); then
                if tar -xJf "$zip_file" 2>/dev/null; then
                    log_ok "TAR.XZ解压完成 → 当前目录"
                    extract_success=true
                else
                    log_error "TAR.XZ解压失败，可能是文件损坏或权限问题"
                fi
            else
                log_error "文件格式不匹配或文件已损坏"
            fi
            
        # TAR
        elif [[ "$zip_file" == *.tar ]]; then
            if [[ -f "$zip_file" ]] && (file "$zip_file" | grep -q "tar archive" || file "$zip_file" | grep -q "POSIX tar archive"); then
                if tar -xf "$zip_file" 2>/dev/null; then
                    log_ok "TAR解压完成 → 当前目录"
                    extract_success=true
                else
                    log_error "TAR解压失败，可能是文件损坏或权限问题"
                fi
            else
                log_error "文件格式不匹配或文件已损坏"
            fi
            
        # GZ (非tar)
        elif [[ "$zip_file" == *.gz && ! "$zip_file" == *.tar.gz ]]; then
            if [[ -f "$zip_file" ]] && (file "$zip_file" | grep -q "gzip compressed data"); then
                if gunzip -f "$zip_file" 2>/dev/null; then
                    log_ok "GZ解压完成 → 当前目录"
                    extract_success=true
                else
                    log_error "GZ解压失败，可能是文件损坏或权限问题"
                fi
            else
                log_error "文件格式不匹配或文件已损坏"
            fi
            
        else
            log_warn "不支持的格式: ${gl_huang}${zip_file##*.}${gl_bai}，请手动解压"
        fi
        
        # 询问是否删除压缩包
        if [[ "$extract_success" == true ]]; then
            read -r -e -p "$(echo -e "${gl_bai}是否删除压缩包? (${gl_lv}y${gl_bai}/${gl_hong}n${gl_bai}): ")" delete_choice
            if [[ "$delete_choice" == "y" || "$delete_choice" == "Y" ]]; then
                rm -f "$zip_file" 2>/dev/null && log_ok "已删除压缩包" || log_warn "删除失败"
            fi
        fi
    else
        # 不解压，只显示信息
        if [[ -f "$zip_file" ]]; then
            log_info "文件已保存: ${gl_huang}$(pwd)/${zip_file}${gl_bai}"
        else
            log_warn "文件不存在或已被移动"
        fi
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 下载文件夹
# 下载文件夹函数（压缩下载）
rz_download_folder() {
    clear
    echo -e "${gl_zi}>>> 下载文件夹到本地 (压缩下载)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 列出当前目录的文件夹
    local dir_index=1
    local dir_array=()
    local dir_names=()
    
    echo -e "${gl_bai}当前目录文件夹列表:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 使用数组安全地存储目录名
    while IFS= read -r -d '' dir; do
        if [[ -d "$dir" ]] && [[ "$dir" != "." ]] && [[ "$dir" != ".." ]] && [[ ! -L "$dir" ]]; then
            dir_array+=("$dir")
            dir_names+=("$(basename "$dir")")
            ((dir_index++))
        fi
    done < <(find . -maxdepth 1 -type d -not -name ".*" -print0 2>/dev/null | sort -zV)
    
    if [[ ${#dir_array[@]} -eq 0 ]]; then
        echo -e "${gl_huang}当前目录没有可下载的文件夹"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 显示文件夹列表
    for i in "${!dir_array[@]}"; do
        local idx=$((i + 1))
        local dir="${dir_array[$i]}"
        local dir_name="${dir_names[$i]}"
        local dir_size
        dir_size=$(du -sh "$dir" 2>/dev/null | cut -f1 || echo "未知")
        local file_count
        file_count=$(find "$dir" -type f 2>/dev/null | wc -l)
        
        printf "${gl_bufan}%3d. ${gl_bai}%-30s ${gl_huang}大小: %-8s ${gl_lv}文件数: %d\n" \
               "$idx" "$dir_name" "$dir_size" "$file_count"
    done
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入要下载的文件夹序号 (${gl_huang}0${gl_bai})返回: ")" dir_choice
    
    [ "$dir_choice" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
    
    if ! [[ "$dir_choice" =~ ^[0-9]+$ ]] || \
       [[ "$dir_choice" -lt 1 ]] || \
       [[ "$dir_choice" -gt ${#dir_array[@]} ]]; then
        log_error "无效的文件夹序号"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    local selected_dir="${dir_array[$((dir_choice-1))]}"
    local dir_name="${dir_names[$((dir_choice-1))]}"
    local timestamp
    timestamp=$(date +%Y%m%d_%H%M%S)
    local zip_file="${dir_name}_${timestamp}"
    
    echo -e "${gl_bai}选择的文件夹: ${gl_huang}${dir_name}${gl_bai}"
    echo -e "${gl_bai}文件夹大小: ${gl_huang}$(du -sh "$selected_dir" 2>/dev/null | cut -f1)${gl_bai}"
    
    echo -e "${gl_huang}>>> 请选择压缩格式${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bufan}1.${gl_bai} tar.gz (推荐)"
    echo -e "${gl_bufan}2.${gl_bai} zip"
    echo -e "${gl_bufan}3.${gl_bai} tar.bz2"
    echo -e "${gl_bufan}4.${gl_bai} tar.xz"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入你的选择 ${gl_bai}[${gl_lv}1${gl_bai}-${gl_huang}4${gl_bai}]: ")" format_choice
    
    case $format_choice in
        1)
            zip_file="${zip_file}.tar.gz"
            echo -e ""
            echo -e "${gl_huang}>>> 正在压缩为tar.gz格式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            if tar -czf "$zip_file" "$dir_name" 2>/dev/null; then
                log_ok "文件夹压缩完成: ${gl_huang}$(du -h "$zip_file" 2>/dev/null | cut -f1)${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            else
                log_error "文件夹压缩失败"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                return 1
            fi
            ;;
        2)
            zip_file="${zip_file}.zip"
            if command -v zip >/dev/null 2>&1; then
                echo -e ""
                echo -e "${gl_huang}>>> 正在压缩为zip格式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                if zip -rq "$zip_file" "$dir_name" 2>/dev/null; then
                    log_ok "文件夹压缩完成: ${gl_huang}$(du -h "$zip_file" 2>/dev/null | cut -f1)${gl_bai}"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                else
                    log_error "文件夹压缩失败"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                    return 1
                fi
            else
                log_error "未找到zip命令，使用tar.gz格式"
                zip_file="${dir_name}_${timestamp}.tar.gz"
                tar -czf "$zip_file" "$dir_name" 2>/dev/null
            fi
            ;;
        3)
            zip_file="${zip_file}.tar.bz2"
            echo -e ""
            echo -e "${gl_huang}>>> 正在压缩为tar.bz2格式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            if tar -cjf "$zip_file" "$dir_name" 2>/dev/null; then
                log_ok "文件夹压缩完成: ${gl_huang}$(du -h "$zip_file" 2>/dev/null | cut -f1)${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            else
                log_error "文件夹压缩失败"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                return 1
            fi
            ;;
        4)
            zip_file="${zip_file}.tar.xz"
            echo -e ""
            echo -e "${gl_huang}>>> 正在压缩为tar.xz格式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            if tar -cJf "$zip_file" "$dir_name" 2>/dev/null; then
                log_ok "文件夹压缩完成: ${gl_huang}$(du -h "$zip_file" 2>/dev/null | cut -f1)${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            else
                log_error "文件夹压缩失败"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                return 1
            fi
            ;;
        *)
            log_warn "无效选择，使用默认tar.gz格式"
            zip_file="${zip_file}.tar.gz"
            tar -czf "$zip_file" "$dir_name" 2>/dev/null
            ;;
    esac
    
    if [[ -f "$zip_file" ]]; then
        read -r -e -p "$(echo -e "${gl_bai}是否下载压缩包? (${gl_lv}y${gl_bai}/${gl_hong}n${gl_bai}): ")" download_choice
        if [[ "$download_choice" == "y" || "$download_choice" == "Y" ]]; then
            echo -e "${gl_bai}使用命令: ${gl_zi}sz \"${zip_file}\"${gl_bai}"
            echo -e "${gl_huang}请在本地客户端接收文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            
            for i in {2..1}; do
                echo -ne "${gl_huang}将在 ${gl_lv}$i${gl_bai} 秒后开始下载${gl_bai}\r"
                sleep_fractional 1
            done
            echo ""
            
            if sz "$zip_file"; then
                log_ok "文件夹下载成功!"
            else
                if [[ $? -eq 130 ]]; then
                    log_info "下载被用户取消"
                else
                    log_warn "文件传输可能被中断"
                fi
            fi
        fi
        
        read -r -e -p "$(echo -e "${gl_bai}是否删除临时压缩包? (${gl_lv}y${gl_bai}/${gl_hong}n${gl_bai}): ")" delete_choice
        if [[ "$delete_choice" == "y" || "$delete_choice" == "Y" ]]; then
            if rm -f "$zip_file" 2>/dev/null; then
                log_ok "已删除临时压缩包"
            else
                log_warn "删除临时压缩包失败"
            fi
        fi
    else
        log_error "压缩文件创建失败"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 选择文件下载
rz_download_files_interactive() {
    clear
    echo -e "${gl_zi}>>> 选择文件下载 (交互式)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    local search_pattern
    read -r -e -p "$(echo -e "${gl_bai}请输入文件搜索模式 (如: *.txt, *.sh, 留空显示所有): ")" search_pattern
    
    if [[ -z "$search_pattern" ]]; then
        search_pattern="*"
    fi
    
    local file_list=()
    while IFS= read -r -d '' file; do
        file_list+=("$file")
    done < <(find . -maxdepth 1 -type f -name "$search_pattern" 2>/dev/null | sort -zV)
    
    if [[ ${#file_list[@]} -eq 0 ]]; then
        log_warn "未找到匹配的文件: ${gl_huang}${search_pattern}${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    echo -e "${gl_bai}找到以下文件:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    local file_index=1
    local interactive_files=()
    
    for file in "${file_list[@]}"; do
        if [[ -f "$file" ]]; then
            local file_size
            file_size=$(stat -c%s "$file" 2>/dev/null || echo "0")
            local size_display
            
            if [[ $file_size -ge 1073741824 ]]; then
                size_display=$(echo "scale=2; $file_size/1073741824" | bc)G
            elif [[ $file_size -ge 1048576 ]]; then
                size_display=$(echo "scale=2; $file_size/1048576" | bc)M
            elif [[ $file_size -ge 1024 ]]; then
                size_display=$(echo "scale=2; $file_size/1024" | bc)K
            else
                size_display="${file_size}B"
            fi
            
            printf "${gl_bufan}%3d. ${gl_bai}%-40s ${gl_huang}%8s\n" \
                   "$file_index" "$(basename "$file")" "$size_display"
            interactive_files+=("$file")
            ((file_index++))
        fi
    done
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}输入: ${gl_huang}单个序号${gl_bai} 或 ${gl_huang}多个序号用逗号分隔${gl_bai} 或 ${gl_huang}范围如1-5${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请选择要下载的文件 (${gl_huang}0${gl_bai})返回: ")" file_choices
    
    [ "$file_choices" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
    
    if [[ -z "$file_choices" ]]; then
        log_error "请输入有效的文件序号"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    local selected_files=()
    
    # 处理输入格式
    if [[ "$file_choices" =~ ^[0-9]+$ ]]; then
        # 单个数字
        if [[ "$file_choices" -ge 1 && "$file_choices" -le ${#interactive_files[@]} ]]; then
            selected_files+=("${interactive_files[$((file_choices-1))]}")
        else
            log_error "无效的文件序号: $file_choices"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        fi
    elif [[ "$file_choices" =~ ^[0-9]+-[0-9]+$ ]]; then
        # 范围
        local start
        start=$(echo "$file_choices" | cut -d'-' -f1)
        local end
        end=$(echo "$file_choices" | cut -d'-' -f2)
        
        if [[ $start -ge 1 && $end -le ${#interactive_files[@]} && $start -le $end ]]; then
            for ((i=start; i<=end; i++)); do
                selected_files+=("${interactive_files[$((i-1))]}")
            done
        else
            log_error "无效的文件范围: $file_choices"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        fi
    else
        # 多个用逗号分隔
        IFS=',' read -ra choices <<< "$file_choices"
        for choice in "${choices[@]}"; do
            choice=$(echo "$choice" | tr -d '[:space:]')
            if [[ "$choice" =~ ^[0-9]+$ ]] && \
               [[ "$choice" -ge 1 && "$choice" -le ${#interactive_files[@]} ]]; then
                selected_files+=("${interactive_files[$((choice-1))]}")
            fi
        done
    fi
    
    if [[ ${#selected_files[@]} -eq 0 ]]; then
        log_error "没有选择有效的文件"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    echo -e "${gl_bai}选择的文件:${gl_bai}"
    for file in "${selected_files[@]}"; do
        local file_size
        file_size=$(stat -c%s "$file" 2>/dev/null || echo "0")
        local size_display
        
        if [[ $file_size -ge 1073741824 ]]; then
            size_display=$(echo "scale=2; $file_size/1073741824" | bc)G
        elif [[ $file_size -ge 1048576 ]]; then
            size_display=$(echo "scale=2; $file_size/1048576" | bc)M
        elif [[ $file_size -ge 1024 ]]; then
            size_display=$(echo "scale=2; $file_size/1024" | bc)K
        else
            size_display="${file_size}B"
        fi
        
        echo -e "  ${gl_bufan}• ${gl_bai}$(basename "$file") (${gl_huang}$size_display${gl_bai})"
    done
    
    read -r -e -p "$(echo -e "${gl_bai}确认下载 ${gl_huang}${#selected_files[@]} ${gl_bai}个文件? (${gl_lv}y${gl_bai}/${gl_hong}n${gl_bai}): ")" confirm
    if [[ "$confirm" == "y" || "$confirm" == "Y" ]]; then
        log_info "开始批量下载文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_huang}请在本地客户端接收文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        
        for i in {2..1}; do
            echo -ne "${gl_huang}将在 ${gl_lv}$i${gl_bai} 秒后开始${gl_bai}\r"
            sleep_fractional 1
        done
        echo ""
        
        if sz "${selected_files[@]}"; then
            log_ok "批量下载完成!"
        else
            if [[ $? -eq 130 ]]; then
                log_info "下载被用户取消"
            else
                log_warn "批量下载可能被中断"
            fi
        fi
    else
        log_info "取消下载操作"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 批量上传多个文件
rz_upload_files_batch() {
    clear
    echo -e "${gl_zi}>>> 批量上传多个文件${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "可以一次选择多个文件上传"
    echo -e "${gl_bai}支持批量上传多个文件到当前目录${gl_bai}"
    echo -e "${gl_huang}注意: 请确保终端支持Zmodem批量上传${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    read -r -e -p "$(echo -e "${gl_bai}是否继续? (${gl_lv}y${gl_bai}/${gl_hong}n${gl_bai}): ")" confirm
    if [[ "$confirm" == "y" || "$confirm" == "Y" ]]; then
        echo -e "${gl_bai}使用命令: ${gl_zi}rz -bye${gl_bai}"
        echo -e "${gl_huang}请在本地客户端选择多个文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_huang}提示: 按${gl_bai}Ctrl+C${gl_huang}取消上传${gl_bai}"
        
        for i in {2..1}; do
            echo -ne "${gl_huang}将在 ${gl_lv}$i${gl_bai} 秒后弹出文件选择对话框${gl_bai}\r"
            sleep_fractional 1
        done
        echo ""
        
        if command -v rz >/dev/null 2>&1; then
            # 尝试使用rz的批量上传参数
            if rz -bye 2>/dev/null; then
                log_ok "批量上传完成!"
                
                # 显示上传的文件
                echo -e "${gl_bai}最近上传的文件:${gl_bai}"
                ls -lt --color=always 2>/dev/null | head -6
            else
                if [[ $? -eq 130 ]]; then
                    log_info "上传被用户取消"
                else
                    log_warn "批量上传失败，尝试普通上传模式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    if rz; then
                        log_ok "文件上传完成!"
                    else
                        log_warn "文件上传可能被取消"
                    fi
                fi
            fi
        else
            log_error "rz命令不可用"
        fi
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 检查终端Zmodem支持函数
rz_check_zmodem_support() {
    clear
    echo -e "${gl_zi}>>> 检查终端Zmodem支持${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    echo -e "${gl_bai}Zmodem协议支持检测:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 检查工具安装
    if command -v sz >/dev/null 2>&1 && command -v rz >/dev/null 2>&1; then
        echo -e "  ${gl_lv}✓ ${gl_bai}lrzsz已安装: ${gl_huang}$(sz --version 2>&1 | head -1)${gl_bai}"
    else
        echo -e "  ${gl_hong}✗ ${gl_bai}lrzsz未安装"
    fi
    
    # 检查当前终端
    if [[ -n "$SSH_TTY" ]]; then
        echo -e "  ${gl_lv}✓ ${gl_bai}通过SSH连接${gl_bai}"
    else
        echo -e "  ${gl_huang}⚠ ${gl_bai}非SSH连接，Zmodem可能不可用${gl_bai}"
    fi
    
    # 终端支持列表
    echo -e "${gl_bai}支持的终端软件:${gl_bai}"
    echo -e "  ${gl_bufan}• ${gl_lv}MobaXterm${gl_bai} - 内置完美支持"
    echo -e "  ${gl_bufan}• ${gl_lv}Xshell${gl_bai} - 需要启用ZMODEM选项"
    echo -e "  ${gl_bufan}• ${gl_lv}SecureCRT${gl_bai} - 需要配置ZMODEM"
    echo -e "  ${gl_bufan}• ${gl_lv}Tabby${gl_bai} - 需要安装Zmodem插件"
    echo -e "  ${gl_bufan}• ${gl_lv}WindTerm${gl_bai} - 内置支持"
    echo -e "  ${gl_bufan}• ${gl_lv}FinalShell${gl_bai} - 内置支持"
    echo -e "  ${gl_huang}⚠ ${gl_bai}PuTTY${gl_bai} - 不支持Zmodem协议"
    echo -e "  ${gl_huang}⚠ ${gl_bai}Windows Terminal${gl_bai} - 需要额外配置"
    
    # 快速测试
    echo -e "${gl_bai}快速测试:${gl_bai}"
    echo -e "  ${gl_bufan}1. ${gl_bai}上传测试: ${gl_zi}echo 'test' > test.txt && sz test.txt${gl_bai}"
    echo -e "  ${gl_bufan}2. ${gl_bai}下载测试: ${gl_zi}rz (然后选择文件)${gl_bai}"
    
    echo -e "${gl_bai}其他传输方式:${gl_bai}"
    echo -e "  ${gl_bufan}• ${gl_bai}SCP: ${gl_zi}scp user@host:file .${gl_bai}"
    echo -e "  ${gl_bufan}• ${gl_bai}SFTP: ${gl_zi}sftp user@host${gl_bai}"
    echo -e "  ${gl_bufan}• ${gl_bai}HTTP: ${gl_zi}python3 -m http.server${gl_bai}"
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}是否创建测试文件? (${gl_lv}y${gl_bai}/${gl_hong}n${gl_bai}): ")" test_choice
    if [[ "$test_choice" == "y" || "$test_choice" == "Y" ]]; then
        echo "这是一个Zmodem传输测试文件，创建于: $(date)" > zmodem_test.txt
        echo "文件大小: 1KB" >> zmodem_test.txt
        echo "用于测试Zmodem文件传输功能" >> zmodem_test.txt
        # 填充到1KB
        dd if=/dev/zero bs=1k count=1 2>/dev/null >> zmodem_test.txt
        log_ok "测试文件已创建: ${gl_huang}zmodem_test.txt${gl_bai}"
        echo -e "${gl_bai}使用命令测试: ${gl_zi}sz zmodem_test.txt${gl_bai}"
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 查看传输历史记录函数
rz_view_transfer_history() {
    clear
    echo -e "${gl_zi}>>> 查看传输历史记录${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 检查最近修改的文件
    echo -e "${gl_bai}最近修改的文件 (可能是上传的文件):${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    find . -maxdepth 1 -type f -printf "%T+ %p\n" 2>/dev/null | sort -r | head -10 | while read -r line; do
        local file_date file_name
        file_date=$(echo "$line" | awk '{print $1" "$2}' | cut -d'.' -f1)
        file_name=$(echo "$line" | awk '{for(i=2;i<=NF;i++) printf $i" "}' | sed 's/ $//')
        local file_size
        file_size=$(stat -c%s "$file_name" 2>/dev/null || echo "0")
        local size_display
        
        if [[ $file_size -ge 1073741824 ]]; then
            size_display=$(echo "scale=2; $file_size/1073741824" | bc)G
        elif [[ $file_size -ge 1048576 ]]; then
            size_display=$(echo "scale=2; $file_size/1048576" | bc)M
        elif [[ $file_size -ge 1024 ]]; then
            size_display=$(echo "scale=2; $file_size/1024" | bc)K
        else
            size_display="${file_size}B"
        fi
        
        printf "${gl_bai}%-20s ${gl_huang}%8s ${gl_lv}%s\n" "$file_date" "$size_display" "$(basename "$file_name")"
    done
    
    # 检查大文件
    echo -e "${gl_bai}当前目录中大文件 (>10MB):${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    find . -maxdepth 1 -type f -size +10M 2>/dev/null | while read -r file; do
        local file_size
        file_size=$(stat -c%s "$file" 2>/dev/null || echo "0")
        local size_display
        
        if [[ $file_size -ge 1073741824 ]]; then
            size_display=$(echo "scale=2; $file_size/1073741824" | bc)G
        elif [[ $file_size -ge 1048576 ]]; then
            size_display=$(echo "scale=2; $file_size/1048576" | bc)M
        fi
        
        printf "${gl_bai}%-40s ${gl_huang}%8s\n" "$(basename "$file")" "$size_display"
    done | head -5
    
    # 统计文件信息
    local total_size
    total_size=$(find . -maxdepth 1 -type f -exec stat -c%s {} \; 2>/dev/null | awk '{sum+=$1} END {print sum}')
    local total_files
    total_files=$(find . -maxdepth 1 -type f 2>/dev/null | wc -l)
    local total_size_display
    
    if [[ $total_size -ge 1073741824 ]]; then
        total_size_display=$(echo "scale=2; $total_size/1073741824" | bc)GB
    elif [[ $total_size -ge 1048576 ]]; then
        total_size_display=$(echo "scale=2; $total_size/1048576" | bc)MB
    elif [[ $total_size -ge 1024 ]]; then
        total_size_display=$(echo "scale=2; $total_size/1024" | bc)KB
    else
        total_size_display="${total_size}B"
    fi
    
    echo -e "${gl_bai}统计信息:${gl_bai}"
    echo -e "  ${gl_bufan}• ${gl_bai}文件总数: ${gl_huang}${total_files}${gl_bai} 个"
    echo -e "  ${gl_bufan}• ${gl_bai}总大小: ${gl_huang}${total_size_display}${gl_bai}"
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}按回车键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
    break_end
}

###### 清理临时文件
rz_clean_temp_files() {
    clear
    echo -e "${gl_zi}>>> 清理临时文件${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 查找常见的临时文件
    echo -e "${gl_bai}正在查找临时文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    local temp_files=()
    while IFS= read -r -d '' file; do
        temp_files+=("$file")
    done < <(find . -maxdepth 1 -type f \( -name "*.tmp" -o -name "*.temp" -o -name "*.swp" -o -name "*.swo" -o -name "*~" -o -name ".#*" \) -print0 2>/dev/null)
    
    if [[ ${#temp_files[@]} -gt 0 ]]; then
        echo -e "${gl_bai}找到以下临时文件:${gl_bai}"
        for file in "${temp_files[@]}"; do
            local file_size
            file_size=$(stat -c%s "$file" 2>/dev/null || echo "0")
            local size_display
            
            if [[ $file_size -ge 1048576 ]]; then
                size_display=$(echo "scale=2; $file_size/1048576" | bc)M
            elif [[ $file_size -ge 1024 ]]; then
                size_display=$(echo "scale=2; $file_size/1024" | bc)K
            else
                size_display="${file_size}B"
            fi
            
            printf "  ${gl_bufan}• ${gl_bai}%-40s ${gl_huang}%8s\n" "$(basename "$file")" "$size_display"
        done
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}是否删除这些临时文件? (${gl_lv}y${gl_bai}/${gl_hong}n${gl_bai}): ")" delete_choice
        
        if [[ "$delete_choice" == "y" || "$delete_choice" == "Y" ]]; then
            local deleted_count=0
            local deleted_size=0
            
            for file in "${temp_files[@]}"; do
                local file_size
                file_size=$(stat -c%s "$file" 2>/dev/null || echo "0")
                if rm -f "$file" 2>/dev/null; then
                    ((deleted_count++))
                    deleted_size=$((deleted_size + file_size))
                fi
            done
            
            local deleted_size_display
            if [[ $deleted_size -ge 1048576 ]]; then
                deleted_size_display=$(echo "scale=2; $deleted_size/1048576" | bc)MB
            elif [[ $deleted_size -ge 1024 ]]; then
                deleted_size_display=$(echo "scale=2; $deleted_size/1024" | bc)KB
            else
                deleted_size_display="${deleted_size}B"
            fi
            
            log_ok "已删除 ${gl_huang}${deleted_count}${gl_bai} 个临时文件，释放空间: ${gl_huang}${deleted_size_display}${gl_bai}"
        else
            log_info "取消删除临时文件"
        fi
    else
        log_info "未找到临时文件"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 创建测试文件
rz_create_test_files() {
    clear
    echo -e "${gl_zi}>>> 创建测试文件${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    echo -e "${gl_bai}创建测试文件用于测试Zmodem传输:${gl_bai}"
    echo -e "${gl_bufan}1. ${gl_bai}创建小文件 (1KB)"
    echo -e "${gl_bufan}2. ${gl_bai}创建中文件 (1MB)"
    echo -e "${gl_bufan}3. ${gl_bai}创建大文件 (10MB)"
    echo -e "${gl_bufan}4. ${gl_bai}创建随机文件"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    read -r -e -p "$(echo -e "${gl_bai}请选择 [1-4]: ")" test_choice
    
    case $test_choice in
        1)
            echo "Zmodem测试文件 - 小文件 (1KB)" > test_small.txt
            echo "创建时间: $(date)" >> test_small.txt
            dd if=/dev/zero bs=1k count=1 2>/dev/null >> test_small.txt
            log_ok "已创建测试文件: ${gl_huang}test_small.txt${gl_bai} (1KB)"
            ;;
        2)
            echo "Zmodem测试文件 - 中文件 (1MB)" > test_medium.txt
            echo "创建时间: $(date)" >> test_medium.txt
            dd if=/dev/zero bs=1M count=1 2>/dev/null >> test_medium.txt
            log_ok "已创建测试文件: ${gl_huang}test_medium.txt${gl_bai} (1MB)"
            ;;
        3)
            echo "Zmodem测试文件 - 大文件 (10MB)" > test_large.txt
            echo "创建时间: $(date)" >> test_large.txt
            dd if=/dev/zero bs=1M count=10 2>/dev/null >> test_large.txt
            log_ok "已创建测试文件: ${gl_huang}test_large.txt${gl_bai} (10MB)"
            ;;
        4)
            read -r -e -p "$(echo -e "${gl_bai}请输入文件大小 (如: 1K, 1M, 10M): ")" size
            echo "Zmodem测试文件 - 随机文件 (${size})" > "test_random_${size}.txt"
            echo "创建时间: $(date)" >> "test_random_${size}.txt"
            
            if dd if=/dev/urandom bs="${size}" count=1 2>/dev/null >> "test_random_${size}.txt"; then
                log_ok "已创建测试文件: ${gl_huang}test_random_${size}.txt${gl_bai} (${size})"
            else
                log_error "创建文件失败，请检查输入格式 (如: 1K, 1M, 10M)"
            fi
            ;;
        0) cancel_return; return ;;    # 返回到上一级菜单
        *) handle_invalid_input ;;      # 无效的输入,请重新输入!
    esac
    
    if [[ -f "test_"*".txt" ]]; then
        echo -e "${gl_bai}测试文件信息:${gl_bai}"
        ls -lh test_*.txt 2>/dev/null
        
        read -r -e -p "$(echo -e "${gl_bai}是否立即测试下载? (${gl_lv}y${gl_bai}/${gl_hong}n${gl_bai}): ")" download_test
        if [[ "$download_test" == "y" || "$download_test" == "Y" ]]; then
            for i in {2..1}; do
                echo -ne "${gl_huang}将在 ${gl_lv}$i${gl_bai} 秒后开始下载测试文件${gl_bai}\r"
                sleep_fractional 1
            done
            echo ""
            
            sz test_*.txt
        fi
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 文件传输管理器 - 支持sz/rz本地与服务器互传
