###### 清空临时目录
clear_temp_directory() {
    local default_dir="/mnt/tmp"
    cd "$default_dir"
    echo -e ""
    echo -e "${gl_zi}>>> 清空临时目录${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_warn "${gl_bai}这将清空 (${gl_lv}$default_dir${gl_hong}${gl_bai}) 目录下的所有文件！${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确认要清空 (${gl_lv}$default_dir${gl_bai}) 目录吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

    case "$confirm" in
    [yY] | [yY][eE][sS])
        # 回到初始目录进行清理
        cd "$default_dir" && safe_rm
        # 清理后重置当前目录
        current_dir="$default_dir"
        log_ok "目录已清空"
        ;;
    0) cancel_return; return 1 ;;    # 返回到上一级菜单
    *) handle_invalid_input ;;
    esac

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 返回上一级目录
go_parent_directory() {
    if [[ "$(pwd)" != "/" ]]; then
        local current_path="$(pwd)"
        cd ..
        echo -e "${gl_lv}已返回上级目录: ${gl_huang}$(pwd) ${gl_bai}"
        exit_animation    # 即将退出动画
    else
        echo -e "${gl_huang}已经在根目录: ${gl_hong}/ ${gl_bai}"
        exit_animation    # 即将退出动画
    fi
}

