install_add_docker_guanfang() {
    local country
    country=$(curl -s ipinfo.io/country)
    if [ "$country" = "CN" ]; then
        cd ~
        curl -sS -O ${gh_proxy}raw.githubusercontent.com/kejilion/docker/main/install && chmod +x install
        sh install --mirror Aliyun
        rm -f install
    else
        curl -fsSL https://get.docker.com | sh
    fi
    install_add_docker_cn

}

install_add_docker() {
    clear
    echo -e "${gl_zi}>>> 安装${gl_huang}docker${gl_zi}环境 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确定要安装${gl_huang}docker${gl_bai}环境吗？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
	[ "$confirm" = "0" ] && { cancel_return "上一级选单"; return 1; }   # break 或 continue 或 return ，视上下文而定
	[ -z "$confirm" ] && { cancel_empty "上一级选单"; return 1; }        # break 或 continue 或 return ，视上下文而定
    if [[ ! $confirm =~ ^[Yy]$ ]]; then
        echo -e "${gl_huang}已取消卸载操作${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    if [ -f /etc/os-release ] && grep -q "Fedora" /etc/os-release; then
        install_add_docker_guanfang
    elif command -v dnf &>/dev/null; then
        dnf update -y
        dnf install -y yum-utils device-mapper-persistent-data lvm2
        rm -f /etc/yum.repos.d/docker*.repo >/dev/null
        country=$(curl -s ipinfo.io/country)
        arch=$(uname -m)
        if [ "$country" = "CN" ]; then
            curl -fsSL https://mirrors.aliyun.com/docker-ce/linux/centos/docker-ce.repo | tee /etc/yum.repos.d/docker-ce.repo >/dev/null
        else
            yum-config-manager --add-repo https://download.docker.com/linux/centos/docker-ce.repo >/dev/null
        fi
        dnf install -y docker-ce docker-ce-cli containerd.io
        install_add_docker_cn

    elif [ -f /etc/os-release ] && grep -q "Kali" /etc/os-release; then
        apt update
        apt upgrade -y
        apt install -y apt-transport-https ca-certificates curl gnupg lsb-release
        rm -f /usr/share/keyrings/docker-archive-keyring.gpg
        local country
        country=$(curl -s ipinfo.io/country)
        local arch
        arch=$(uname -m)
        if [ "$country" = "CN" ]; then
            if [ "$arch" = "x86_64" ]; then
                sed -i '/^deb \[arch=amd64 signed-by=\/etc\/apt\/keyrings\/docker-archive-keyring.gpg\] https:\/\/mirrors.aliyun.com\/docker-ce\/linux\/debian bullseye stable/d' /etc/apt/sources.list.d/docker.list >/dev/null
                mkdir -p /etc/apt/keyrings
                curl -fsSL https://mirrors.aliyun.com/docker-ce/linux/debian/gpg | gpg --dearmor -o /etc/apt/keyrings/docker-archive-keyring.gpg >/dev/null
                echo "deb [arch=amd64 signed-by=/etc/apt/keyrings/docker-archive-keyring.gpg] https://mirrors.aliyun.com/docker-ce/linux/debian bullseye stable" | tee /etc/apt/sources.list.d/docker.list >/dev/null
            elif [ "$arch" = "aarch64" ]; then
                sed -i '/^deb \[arch=arm64 signed-by=\/etc\/apt\/keyrings\/docker-archive-keyring.gpg\] https:\/\/mirrors.aliyun.com\/docker-ce\/linux\/debian bullseye stable/d' /etc/apt/sources.list.d/docker.list >/dev/null
                mkdir -p /etc/apt/keyrings
                curl -fsSL https://mirrors.aliyun.com/docker-ce/linux/debian/gpg | gpg --dearmor -o /etc/apt/keyrings/docker-archive-keyring.gpg >/dev/null
                echo "deb [arch=arm64 signed-by=/etc/apt/keyrings/docker-archive-keyring.gpg] https://mirrors.aliyun.com/docker-ce/linux/debian bullseye stable" | tee /etc/apt/sources.list.d/docker.list >/dev/null
            fi
        else
            if [ "$arch" = "x86_64" ]; then
                sed -i '/^deb \[arch=amd64 signed-by=\/usr\/share\/keyrings\/docker-archive-keyring.gpg\] https:\/\/download.docker.com\/linux\/debian bullseye stable/d' /etc/apt/sources.list.d/docker.list >/dev/null
                mkdir -p /etc/apt/keyrings
                curl -fsSL https://download.docker.com/linux/debian/gpg | gpg --dearmor -o /etc/apt/keyrings/docker-archive-keyring.gpg >/dev/null
                echo "deb [arch=amd64 signed-by=/etc/apt/keyrings/docker-archive-keyring.gpg] https://download.docker.com/linux/debian bullseye stable" | tee /etc/apt/sources.list.d/docker.list >/dev/null
            elif [ "$arch" = "aarch64" ]; then
                sed -i '/^deb \[arch=arm64 signed-by=\/usr\/share\/keyrings\/docker-archive-keyring.gpg\] https:\/\/download.docker.com\/linux\/debian bullseye stable/d' /etc/apt/sources.list.d/docker.list >/dev/null
                mkdir -p /etc/apt/keyrings
                curl -fsSL https://download.docker.com/linux/debian/gpg | gpg --dearmor -o /etc/apt/keyrings/docker-archive-keyring.gpg >/dev/null
                echo "deb [arch=arm64 signed-by=/etc/apt/keyrings/docker-archive-keyring.gpg] https://download.docker.com/linux/debian bullseye stable" | tee /etc/apt/sources.list.d/docker.list >/dev/null
            fi
        fi
        apt update
        apt install -y docker-ce docker-ce-cli containerd.io
        install_add_docker_cn

    elif command -v apt &>/dev/null || command -v yum &>/dev/null; then
        install_add_docker_guanfang
    else
        install docker docker-compose
        install_add_docker_cn

    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

install_docker() {
    if ! command -v docker &>/dev/null; then
        install_add_docker
    fi
}

###### Docker容器管理函数集合
# 1) 创建新的容器
docker_container_create() {
    echo ""
    echo -e "${gl_zi}>>> 创建新的容器${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入创建命令(${gl_huang}0${gl_bai}返回): ")" dockername
    [ "$dockername" = "0" ] && { cancel_return "容器操作"; return 1; }
    $dockername
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 2) 启动指定容器
docker_container_start() {
    echo ""
    echo -e "${gl_zi}>>> 启动指定容器${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入容器名（多个容器名请用空格分隔）(${gl_huang}0${gl_bai}返回): ")" dockername
    [ "$dockername" = "0" ] && { cancel_return "容器操作"; return 1; }
    echo -ne "${gl_huang}正在启动 ${gl_lv}$dockername ${gl_huang}容器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.5
    echo -ne " ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.5
    echo ""
    docker start "$dockername"
    if [ $? -eq 0 ]; then
        echo -e "${gl_lv}容器启动成功！${gl_bai}"
    else
        echo -e "${gl_hong}容器启动失败！${gl_bai}"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 3) 停止指定容器
docker_container_stop() {
    echo ""
    echo -e "${gl_zi}>>> 停止指定容器${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入容器名（多个容器名请用空格分隔）(${gl_huang}0${gl_bai}返回): ")" dockername
    [ "$dockername" = "0" ] && { cancel_return "容器操作"; return 1; }
    echo -ne "${gl_huang}正在停止 ${gl_lv}$dockername ${gl_huang}容器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.5
    echo -ne " ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
    sleep_fractional 0.5
    echo ""
    docker stop "$dockername"
    if [ $? -eq 0 ]; then
        echo -e "${gl_lv}容器停止成功！${gl_bai}"
    else
        echo -e "${gl_hong}容器停止失败！${gl_bai}"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 4) 删除指定容器
docker_container_remove() {
    echo ""
    echo -e "${gl_zi}>>> 删除指定容器${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入容器名（多个容器名请用空格分隔）(${gl_huang}0${gl_bai}返回): ")" dockername
    [ "$dockername" = "0" ] && { cancel_return "容器操作"; return 1; }
    echo -e ""
    read -r -e -p "$(echo -e "${gl_hong}确定删除 ${gl_lv}$dockername ${gl_hong}容器吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai})(${gl_huang}0${gl_bai}返回): ")" choice
    case "$choice" in
        [Yy])
            echo -ne "${gl_huang}正在删除 ${gl_lv}$dockername ${gl_huang}容器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
            sleep_fractional 0.5
            echo -ne " ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
            sleep_fractional 0.5
            echo ""
            docker rm -f "$dockername"
            if [ $? -eq 0 ]; then
                echo -e "${gl_lv}删除成功！${gl_bai}"
            else
                echo -e "${gl_hong}删除失败！${gl_bai}"
            fi
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        0) cancel_return "容器操作"; return 1 ;; 
        *) handle_y_n ;;                        # 无效的输入,请输入(y或N)。
    esac
}

# 5) 重启指定容器
docker_container_restart() {
    echo ""
    echo -e "${gl_zi}>>> 重启指定容器${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入容器名（多个容器名请用空格分隔）(${gl_huang}0${gl_bai}返回): ")" dockername
    [ "$dockername" = "0" ] && { cancel_return "容器操作"; return 1; }
    
    if [ -z "$dockername" ]; then
        echo -e "${gl_hong}未输入容器名，操作已取消${gl_bai}"
    else
        echo -ne "${gl_huang}正在重启 ${gl_lv}$dockername ${gl_huang}容器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
        sleep_fractional 0.8
        echo -ne " ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
        sleep_fractional 0.8
        echo ""
        docker restart "$dockername"
        if [ $? -eq 0 ]; then
            echo -e "${gl_lv}容器重启成功！${gl_bai}"
        else
            echo -e "${gl_hong}容器重启失败！${gl_bai}"
        fi
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 6) 启动所有容器
docker_container_start_all() {
    echo ""
    echo -e "${gl_zi}>>> 启动所有容器${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确定启动所有容器吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai})(${gl_huang}0${gl_bai}返回): ")" choice
    case "$choice" in
        [Yy])
            echo -ne "${gl_huang}正在启动已停止的容器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
            sleep_fractional 0.8
            echo -ne " ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
            sleep_fractional 0.8
            echo ""
            if docker start $(docker ps -a -q) 2>&1; then
                echo -e "${gl_lv}所有容器启动成功！${gl_bai}"
            else
                echo -e "${gl_hong}所有容器启动失败！${gl_bai}"
            fi
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        0) cancel_return "容器操作"; return 1 ;; 
        *) handle_y_n ;;        # 无效的输入,请输入(y或N)。
    esac
}

# 7) 停止所有容器
docker_container_stop_all() {
    echo ""
    echo -e "${gl_zi}>>> 停止所有容器${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确定停止所有容器吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai})(${gl_huang}0${gl_bai}返回): ")" choice
    case "$choice" in
        [Yy])
            running_containers=$(docker ps -q)
            if [ -z "$running_containers" ]; then
                echo -e "${gl_huang}没有正在运行的容器。${gl_bai}"
            else
                echo -ne "${gl_huang}正在停止运行中的容器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
                sleep_fractional 0.8
                echo -ne " ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
                sleep_fractional 0.8
                echo ""
                docker stop $running_containers
                if [ $? -eq 0 ]; then
                    echo -e "${gl_lv}所有容器停止成功！${gl_bai}"
                else
                    echo -e "${gl_hong}所有容器停止失败！${gl_bai}"
                fi
            fi
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        0) cancel_return "容器操作"; return 1 ;; 
        *) handle_y_n ;;        # 无效的输入,请输入(y或N)。
    esac
}

# 8) 删除所有容器
docker_container_remove_all() {
    echo ""
    echo -e "${gl_zi}>>> 删除所有容器${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确定删除所有容器吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai})(${gl_huang}0${gl_bai}返回): ")" choice
    case "$choice" in
        [Yy])
            echo -ne "${gl_huang}正在删除所有容器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
