# 15) 开启容器端口访问
docker_container_open_port() {
    echo ""
    echo -e "${gl_zi}>>> 开启容器端口访问${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入容器名(${gl_huang}0${gl_bai}返回): ")" docker_name
    [ "$docker_name" = "0" ] && { cancel_return "容器操作"; return 1; } # break 或 continue 或 return ，视上下文而定
    ip_address
    clear_container_rules "$docker_name" "$ipv4_address"
    local docker_port
    docker_port=$(docker port "$docker_name" | awk -F'[:]' '/->/ {print $NF}' | uniq)
    check_docker_app_ip
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

