    ip_address
    block_container_port "$docker_name" "$ipv4_address"
    local docker_port=$(docker port "$docker_name" | awk -F'[:]' '/->/ {print $NF}' | uniq)
    check_docker_app_ip
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

