        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}15. ${gl_bai}开启容器端口访问         ${gl_bufan}16. ${gl_bai}关闭容器端口访问"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单           ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " sub_choice
        case $sub_choice in
        1)  docker_container_create ;;              # 创建新的容器
        2)  docker_container_start ;;               # 启动指定容器
        3)  docker_container_stop ;;                # 停止指定容器
        4)  docker_container_remove ;;              # 删除指定容器
        5)  docker_container_restart ;;             # 重启指定容器
        6)  docker_container_start_all ;;           # 启动所有容器
        7)  docker_container_stop_all ;;            # 停止所有容器
        8)  docker_container_remove_all ;;          # 删除所有容器
        9)  docker_container_restart_all ;;         # 重启所有容器
        11) docker_container_exec ;;                # 进入指定容器
        12) docker_container_logs ;;                # 查看容器日志
        13) docker_container_network ;;             # 查看容器网络
        14) docker_container_stats ;;               # 查看容器列表
        15) docker_container_open_port ;;           # 开启容器端口访问
        16) docker_container_close_port ;;          # 关闭容器端口访问
        0) cancel_return "$menu_name"; break ;;     # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;             # 感谢使用，再见！
        *) handle_invalid_input ;;                  # 无效的输入,请重新输入!
        esac
    done
}

# Docker镜像清理函数集合
# 1) 清理悬空镜像
docker_image_cleanup_dangling() {
    echo -e ""
    echo -e "${gl_zi}>>> 正在清理悬空镜像 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    local out
    out=$(docker image prune -f)
    echo -e "$out" && echo -e "${gl_lv}✓ 清理完成${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 2) 删除悬空 + 无用普通镜像
docker_image_cleanup_unused() {
    echo -e ""
    echo -e "${gl_zi}>>> 删除悬空 + 无用普通镜像 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_huang}即将删除未被任何容器使用的镜像！${gl_bai} 继续？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" sure
    [[ "$sure" =~ ^[Yy]$ ]] || continue
    docker image prune -a -f && echo -e "${gl_lv}✓ 清理完成${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 3) 删除镜像+容器+网络+构建缓存
docker_image_cleanup_system() {
    echo -e ""
    echo -e "${gl_zi}>>> 删除镜像+容器+网络+构建缓存 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_hong}终极清理：镜像+容器+网络+构建缓存！${gl_bai} 继续？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" sure
    [[ "$sure" =~ ^[Yy]$ ]] || continue
    docker system prune -a -f && echo -e "${gl_lv}✓ 清理完成${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

