        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}仅删悬空镜像 (dangling) ${gl_lv}安全${gl_bai}"
        echo -e "${gl_bufan}2.  ${gl_bai}悬空 + 无用普通镜像 ${gl_huang}较激进${gl_bai}"
        echo -e "${gl_bufan}3.  ${gl_bai}镜像+容器+网络+构建缓存 ${gl_hong}终极清理${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
        echo -e "${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入你的选择: ")" psel

        case $psel in
        1) docker_image_cleanup_dangling ;;     # 清理悬空镜像
        2) docker_image_cleanup_unused ;;       # 删除悬空 + 无用普通镜像
        3) docker_image_cleanup_system ;;       # 删除镜像+容器+网络+构建缓存
        0) cancel_return; break ;;              # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;         # 感谢使用，再见！
        *) handle_invalid_input ;;              # 无效的输入,请重新输入!
        esac
    done
}

# ============================================
# 帮助函数（移到外部）
# ============================================
# Docker 镜像下载并加载函数
_docker_download_load_help() {
    echo -e "${gl_huang}Docker镜像下载并加载工具${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo "用法: docker_download_load [选项] [URL]"
    echo
    echo "选项:"
    echo "  -i, --interactive   交互模式（不提供URL时自动进入）"
    echo "  -k, --keep          保留下载的文件（默认不保留）"
    echo "  -s, --save PATH     指定文件保存路径（默认: 当前目录）"
    echo "  -y, --yes           自动确认所有提示"
    echo "  -q, --quiet         安静模式，减少输出"
    echo "  -h, --help          显示此帮助信息"
    echo
    echo "示例:"
    echo "  m urlload -k -s /backup https://example.com/image.tar.gz"
    echo "  m urlload -i                                                # 交互模式"
    echo "  m urlload -q -y https://example.com/image.tar.gz            # 静默自动模式"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
}

docker_download_load() {
    local download_url=""
    local interactive_mode=false
    local keep_file=false
    local save_path=""
    local auto_confirm=false
    local quiet_mode=false
    local temp_dir=""
    local downloaded_file=""
    local return_code=0

    # 解析参数
    while [[ $# -gt 0 ]]; do
        case "$1" in
            -i|--interactive)
                interactive_mode=true
                shift
                ;;
            -k|--keep)
                keep_file=true
                shift
                ;;
            -s|--save)
                if [[ -n "$2" && "$2" != -* ]]; then
                    save_path="$2"
                    shift 2
                else
                    echo -e "${gl_hong}错误: --save 选项需要指定路径${gl_bai}" >&2
                    return 1
                fi
                ;;
            -y|--yes)
                auto_confirm=true
                shift
                ;;
            -q|--quiet)
                quiet_mode=true
                shift
                ;;
            -h|--help)
                _docker_download_load_help
                return 0
                ;;
            http://*|https://*)
                download_url="$1"
                shift
                ;;
            -*)
                echo -e "${gl_hong}错误: 未知选项 $1${gl_bai}" >&2
                echo "使用 -h 或 --help 查看帮助" >&2
                return 1
                ;;
            *)
                # 如果还没设置URL，将非选项参数当作URL
                if [[ -z "$download_url" ]]; then
                    download_url="$1"
                fi
                shift
                ;;
        esac
    done

    # 确认提示函数
    _ddl_confirm() {
        local prompt="$1"
        local default="${2:-N}"
        
        if [[ "$auto_confirm" == true ]]; then
            return 0
        fi
        
        local confirm
        read -r -e -p "$(echo -e "${prompt} (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
        [[ "$confirm" =~ ^[Yy]$ ]]
    }

    # ==================== 交互模式或验证 URL ====================
    if [[ "$interactive_mode" == true || -z "$download_url" ]]; then
        clear 2>/dev/null || true
        echo -e "${gl_zi}>>> Docker 镜像下载并加载${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}请输入镜像压缩包的下载链接${gl_bai}"
        echo -e "${gl_bai}支持的格式: .tar, .tar.gz, .tgz${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        read -r -e -p "$(echo -e "${gl_bai}请输入镜像压缩包的下载链接(${gl_huang}0${gl_bai}返回): ")" download_url
        
        [ "$download_url" == "0" ] && { cancel_return; return 1; }  # break 或 continue 或 return ，视上下文而定
        [ -z "$download_url" ] && { cancel_empty "上一级选单"; return 1; }       # break 或 continue 或 return ，视上下文而定
    fi

    # 验证 URL
    if [[ -z "$download_url" ]]; then
        echo -e "${gl_hong}✗ 错误: 未提供下载链接${gl_bai}" >&2
        return 1
    fi

    if [[ ! "$download_url" =~ ^https?:// ]]; then
        echo -e "${gl_hong}✗ 错误: 无效的下载链接，必须以 http:// 或 https:// 开头${gl_bai}" >&2
        return 1
    fi

    # 检查文件扩展名（非强制）
    if [[ ! "$download_url" =~ \.(tar|tar\.gz|tgz)(\?.*)?$ ]]; then
        echo -e "${gl_huang}⚠ 警告: URL 似乎不是标准的 .tar/.tar.gz/.tgz 格式${gl_bai}"
        if [[ "$auto_confirm" != true ]]; then
            if ! _ddl_confirm "是否继续下载" "N"; then
                echo -e "${gl_huang}已取消操作${gl_bai}"
                exit_animation    # 即将退出动画
                return 0
            fi
        fi
    fi

    # ==================== 准备下载 ====================
    temp_dir=$(mktemp -d /tmp/docker_dl.XXXXXX)
    if [[ $? -ne 0 ]]; then
        echo -e "${gl_hong}✗ 错误: 无法创建临时目录${gl_bai}" >&2
        exit_animation    # 即将退出动画
        return 1
    fi

    # 提取文件名
    local file_name=$(basename "$download_url" | sed 's/[?#].*$//')
    if [[ -z "$file_name" || "$file_name" == "/" ]]; then
        file_name="docker_image_$(date +%Y%m%d_%H%M%S).tar"
    fi
    downloaded_file="${temp_dir}/${file_name}"

    # 确定最终保存路径
    if [[ -n "$save_path" ]]; then
        if [[ -d "$save_path" ]]; then
            save_path="${save_path%/}/${file_name}"
        fi
    else
        save_path="./${file_name}"
    fi

    local file_size=""
    local curl_status=0

    echo -e ""
    echo -e "${gl_huang}>>> 镜像下载信息:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "  链接地址: ${gl_lv}${download_url}${gl_bai}"
    echo -e "  临时路径: ${gl_huang}${downloaded_file}${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if [[ "$keep_file" == true ]]; then
        echo -e "  保存路径: ${gl_huang}${save_path}${gl_bai}"
    fi
    echo -e ""

    # 确认下载
    if ! _ddl_confirm "确认开始下载"; then
        echo -e "${gl_huang}已取消下载${gl_bai}"
        rm -rf "$temp_dir"
        exit_animation    # 即将退出动画
        return 0
    fi

    # ==================== 执行下载 ====================
    echo -e ""
    echo -e "${gl_huang}>>> 开始下载镜像文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if [[ "$quiet_mode" == true ]]; then
        curl -fsSL -o "$downloaded_file" "$download_url" > /dev/null 2>&1 || curl_status=$?
    else
        echo ""
        curl -fSL --progress-bar -o "$downloaded_file" "$download_url" 2>&1 || curl_status=$?
        echo ""
    fi

    # 检查下载结果
    if [[ $curl_status -ne 0 ]]; then
        echo -e "${gl_hong}✗ 下载失败 (错误码: ${curl_status})${gl_bai}" >&2
        if [[ "$quiet_mode" != true ]]; then
            echo -e "${gl_hong}可能的原因:${gl_bai}" >&2
            echo -e "  1. 网络连接问题" >&2
            echo -e "  2. URL 无效或文件不存在" >&2
            echo -e "  3. 服务器拒绝访问" >&2
            echo -e "  4. 磁盘空间不足" >&2
        fi
        rm -rf "$temp_dir"
        return 2
    fi

    # 验证文件
    if [[ ! -f "$downloaded_file" ]]; then
        echo -e "${gl_hong}✗ 错误: 下载文件未找到${gl_bai}" >&2
        rm -rf "$temp_dir"
        exit_animation    # 即将退出动画
        return 2
    fi

    # 验证文件完整性
    echo -e "${gl_bai}验证文件完整性{gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if ! tar -tzf "$downloaded_file" >/dev/null 2>&1 && ! tar -tf "$downloaded_file" >/dev/null 2>&1; then
        if file "$downloaded_file" | grep -q "gzip compressed data"; then
            echo -e "${gl_lv}✓ 文件是gzip压缩格式${gl_bai}"
        else
            echo -e "${gl_huang}⚠ 警告: 文件可能不是有效的tar压缩包${gl_bai}"
            if ! _ddl_confirm "文件可能已损坏，是否继续尝试加载" "N"; then
                echo -e "${gl_huang}已取消操作${gl_bai}"
                rm -rf "$temp_dir"
                exit_animation    # 即将退出动画
                return 1
            fi
        fi
    else
        echo -e "${gl_lv}✓ 文件校验通过${gl_bai}"
    fi

    file_size=$(du -h "$downloaded_file" | cut -f1)
    echo -e "${gl_lv}✓ 下载完成${gl_bai} (${file_size})"

    # ==================== 执行加载 ====================
    if ! _ddl_confirm "确认加载此镜像"; then
        echo -e "${gl_huang}已取消加载${gl_bai}"
        
        if _ddl_confirm "是否保留下载的文件"; then
            mv "$downloaded_file" "$save_path" 2>/dev/null
            rm -rf "$temp_dir"
            echo -e "${gl_lv}✓ 文件已保存到: ${save_path}${gl_bai}"
        else
            rm -rf "$temp_dir"
            echo -e "${gl_bai}临时文件已清理${gl_bai}"
        fi
        return 0
    fi

    echo -e "${gl_bai}正在加载镜像 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # ---------- 加载前诊断 ----------
    if [[ "$quiet_mode" != true ]]; then
        echo -e "${gl_bai}[诊断] 检查Docker服务状态{gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if ! systemctl is-active --quiet docker 2>/dev/null && ! pgrep -f "dockerd" >/dev/null; then
            echo -e "${gl_huang}⚠  Docker服务可能未运行，尝试启动{gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            if command -v sudo &>/dev/null && sudo systemctl start docker 2>/dev/null; then
                sleep 3
                echo -e "${gl_lv}✓  Docker服务已启动${gl_bai}"
            else
                echo -e "${gl_huang}⚠  无法启动Docker服务，请手动检查${gl_bai}"
            fi
        else
            echo -e "${gl_lv}✓  Docker服务运行正常${gl_bai}"
        fi

        echo -e "${gl_bai}[诊断] 检查磁盘空间{gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        local avail_space
        if avail_space=$(df -h / 2>/dev/null | awk 'NR==2 {print $4}'); then
            echo -e "${gl_bai}  / 分区可用空间: ${gl_huang}${avail_space}${gl_bai}"
        fi
        
        # 检查/vol1分区是否存在
        if df -h /vol1 2>/dev/null | grep -q "^/"; then
            avail_space=$(df -h /vol1 2>/dev/null | awk 'NR==2 {print $4}')
            echo -e "${gl_bai}  /vol1分区可用空间: ${gl_huang}${avail_space}${gl_bai}"
        fi
    fi

    # 加载动画
    local anim_pid=""
    if [[ "$quiet_mode" != true ]]; then
        (
            local chars=("⠋" "⠙" "⠹" "⠸" "⠼" "⠴" "⠦" "⠧" "⠇" "⠏")
            while true; do
                for char in "${chars[@]}"; do
                    echo -ne "\r${gl_lv}${char}${gl_bai} 加载中 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    sleep_fractional 0.1
                done
            done
        ) &
        anim_pid=$!
    fi

    # 执行加载
    local load_output
    local load_status=0
    load_output=$(docker load -i "$downloaded_file" 2>&1) || load_status=$?

    # 停止动画
    if [[ -n "$anim_pid" ]]; then
        kill $anim_pid 2>/dev/null
        wait $anim_pid 2>/dev/null
        echo -ne "\r\033[K"
    fi

    # ==================== 处理结果 ====================
    if [[ $load_status -eq 0 ]]; then
        echo -e "${gl_lv}✓ 镜像加载成功${gl_bai}"
        
        local loaded_image=$(echo "$load_output" | grep -oP "Loaded image: \K.*" || echo "")
        if [[ -n "$loaded_image" ]]; then
            echo -e "${gl_bai}加载的镜像: ${gl_huang}${loaded_image}${gl_bai}"
        fi

        # 处理文件保留
        if [[ "$keep_file" == true ]]; then
            mv "$downloaded_file" "$save_path" 2>/dev/null
            rm -rf "$temp_dir"
            echo -e "${gl_lv}✓ 文件已保存到: ${save_path}${gl_bai}"
        else
            if [[ "$auto_confirm" != true && "$quiet_mode" != true ]]; then
                echo -e ""
                echo -e "${gl_huang}>>> 删除下载的临时文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                if _ddl_confirm "是否删除下载的临时文件" "Y"; then
                    rm -rf "$temp_dir"
                    echo -e "${gl_lv}✓ 临时文件已清理${gl_bai}"
                else
                    mv "$downloaded_file" "$save_path" 2>/dev/null
                    rm -rf "$temp_dir"
                    echo -e "${gl_lv}✓ 文件已保存到: ${save_path}${gl_bai}"
                fi
            else
                rm -rf "$temp_dir"
            fi
        fi
        
        return_code=0
    else
        echo -e "${gl_hong}✗ 镜像加载失败 (错误码: ${load_status})${gl_bai}" >&2
        if [[ "$quiet_mode" != true ]]; then
            echo -e "${gl_bai}错误信息:${gl_bai}" >&2
            echo -e "${gl_huang}${load_output}${gl_bai}" >&2
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}>>> 问题诊断与建议:${gl_bai}" >&2

            # 针对性的诊断
            if echo "$load_output" | grep -q "no such file or directory.*/vol1/docker/tmp"; then
                echo -e "  ${gl_hong}● 根本原因: Docker临时目录问题${gl_bai}" >&2
                echo -e "  ${gl_bai}可能原因及修复:${gl_bai}" >&2
                echo -e "    1. ${gl_huang}磁盘空间不足${gl_bai}: 请检查 /vol1 分区空间" >&2
                echo -e "       ${gl_lv}命令: df -h /vol1${gl_bai}" >&2
                echo -e "    2. ${gl_huang}目录权限问题${gl_bai}: Docker无权写入 /vol1/docker/tmp/" >&2
                echo -e "       ${gl_lv}命令: sudo ls -la /vol1/docker/tmp/ 2>/dev/null || echo '目录不存在'${gl_bai}" >&2
                echo -e "    3. ${gl_huang}尝试修复目录${gl_bai}: 创建并设置正确的权限" >&2
                echo -e "       ${gl_lv}命令: sudo mkdir -p /vol1/docker/tmp && sudo chmod 777 /vol1/docker/tmp${gl_bai}" >&2
                echo -e "    4. ${gl_huang}更改Docker存储目录${gl_bai} (谨慎操作):" >&2
                echo -e "       修改 /etc/docker/daemon.json，添加: {\"data-root\": \"/新的/路径\"}" >&2
                echo -e "       然后执行: sudo systemctl restart docker${gl_bai}" >&2
            elif echo "$load_output" | grep -q "no space left on device"; then
                echo -e "  ${gl_hong}● 根本原因: 磁盘空间已满${gl_bai}" >&2
                echo -e "      请清理 /vol1 分区空间${gl_bai}" >&2
            elif echo "$load_output" | grep -q "file format not recognized\|invalid tar format\|unexpected EOF"; then
                echo -e "  ${gl_hong}● 根本原因: 文件损坏或格式错误${gl_bai}" >&2
                echo -e "      1. 下载的文件可能不完整" >&2
                echo -e "      2. 文件格式不正确" >&2
                echo -e "      3. 网络传输中断" >&2
                echo -e "      ${gl_lv}建议重新下载文件${gl_bai}" >&2
            elif echo "$load_output" | grep -q "permission denied"; then
                echo -e "  ${gl_hong}● 根本原因: 权限不足${gl_bai}" >&2
                echo -e "      当前用户可能没有运行docker的权限" >&2
                echo -e "      ${gl_lv}命令: sudo usermod -aG docker $USER${gl_bai}" >&2
                echo -e "      然后重新登录或重启系统${gl_bai}" >&2
            elif echo "$load_output" | grep -q "docker daemon is not running"; then
                echo -e "  ${gl_hong}● 根本原因: Docker服务未运行${gl_bai}" >&2
                echo -e "      ${gl_lv}命令: sudo systemctl start docker${gl_bai}" >&2
            else
                echo -e "  ${gl_hong}● 未知错误，请检查以下内容:${gl_bai}" >&2
                echo -e "      1. Docker服务状态: systemctl status docker" >&2
                echo -e "      2. 磁盘空间: df -h" >&2
                echo -e "      3. 文件完整性: file ${downloaded_file}" >&2
                echo -e "      4. Docker日志: journalctl -u docker --since '5 minutes ago'" >&2
            fi
        fi

        # 文件保留询问
        if [[ "$auto_confirm" != true && "$quiet_mode" != true ]]; then
            if _ddl_confirm "是否保留下载的文件以供检查"; then
                mv "$downloaded_file" "${save_path}.failed" 2>/dev/null
                rm -rf "$temp_dir"
                echo -e "${gl_lv}✓ 文件已保存到: ${save_path}.failed${gl_bai}"
            else
                rm -rf "$temp_dir"
            fi
        else
            rm -rf "$temp_dir"
        fi
        return_code=3
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
    return $return_code
}

docker_image() {
    local menu_name="${1:-上一级选单}"
    while true; do
        check_and_install_docker || return 1
        clear
        echo -e "${gl_huang}>>> Docker镜像列表${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        list_beautify_docker_images
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo ""
        echo -e "${gl_zi}>>> 镜像操作${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}获取指定镜像             ${gl_bufan}2.  ${gl_bai}更新指定镜像"
        echo -e "${gl_bufan}3.  ${gl_bai}删除指定镜像             ${gl_bufan}4.  ${gl_bai}删除所有镜像"
        echo -e "${gl_bufan}5.  ${gl_bai}打包指定镜像             ${gl_bufan}6.  ${gl_bai}加载指定镜像"
        echo -e "${gl_bufan}7.  ${gl_bai}为镜像打标签             ${gl_bufan}8.  ${gl_bai}加载 URL镜像"
        echo -e "${gl_bufan}9.  ${gl_bai}清理悬空镜像             ${gl_bufan}10. ${gl_bai}上传加载镜像"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单           ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " sub_choice
        case $sub_choice in
        1)
            echo -e ""
            echo -e "${gl_huang}>>> 获取指定镜像${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入镜像名（多个镜像名请用空格分隔）: " imagenames
            [ "$imagenames" = "0" ] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定
            for name in $imagenames; do
                echo -e "${gl_huang}正在获取镜像: $name${gl_bai}"
                docker pull "$name"
            done
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        2)
            echo -e ""
            echo -e "${gl_huang}>>> 更新指定镜像${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入镜像名（多个镜像名请用空格分隔）: " imagenames
            [ "$imagenames" = "0" ] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定
            for name in $imagenames; do
                echo -e "${gl_huang}正在更新镜像: $name${gl_bai}"
                docker pull "$name"
            done
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        3)
            clear
            echo -e "${gl_huang}>>> Docker镜像列表${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            list_beautify_docker_images
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo ""
            echo -e "${gl_zi}>>> 删除指定镜像${gl_bai}"
            echo -e "${gl_bai}删除指定镜像：可输入 ${gl_huang}nginx:tag${gl_bai} 或 ${gl_huang}镜像ID${gl_bai}（多个用空格分隔）"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}请输入你的选择 (${gl_huang}0${gl_bai}返回): ")" img_list

            [[ -z "$img_list" ]] && { cancel_empty "上一级选单"; continue; }         # break 或 continue 或 return ，视上下文而定
            [[ "$img_list" == "0" ]] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定

            for img in $img_list; do
                containers=$(docker ps -aq --filter ancestor="$img")
                [[ -n $containers ]] && {
                    echo -e "${gl_huang}→ 先删除依赖容器 $containers ${gl_bai}"
                    docker rm -f "$containers"
                }
                echo -e "${gl_bai}→ 删除镜像 $img ${gl_bai}"
                docker rmi -f "$img" && echo -e "${gl_lv}✓ $img 已删除${gl_bai}" || echo -e "${gl_hong}✗ $img 删除失败${gl_bai}"
            done

            # 释放空间摘要
            reclaimed=$(docker image prune -f 2>&1 | awk '/Total reclaimed space/ {print $4,$5}')
            [[ -n "$reclaimed" ]] && echo -e "${gl_lv}本次共释放 ${gl_huang}$reclaimed${gl_bai}"

            # 验证残留
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}验证：剩余镜像"
            [[ -n "$img_list" ]] &&
                docker images | grep -Fw -f <(echo "$img_list" | tr ' ' '\n') || echo -e "${gl_lv}✓ 已无任何匹配镜像${gl_bai}"
            break_end
            ;;
        4)
            # 删除所有镜像（强制删除）
            echo -e ""
            echo -e "${gl_huang}>>> 删除所有镜像${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_hong}警告: ${gl_bai}这将删除所有镜像，包括被容器使用的镜像。确定吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
            if [[ "$confirm" =~ ^[Yy]$ ]]; then
                # 先停止并删除所有容器
                [ -z "$confirm" ] && { cancel_empty "上一级选单"; return 1; }        # break 或 continue 或 return ，视上下文而定
                [ "$confirm" = "0" ] && { cancel_return "上一级选单"; return 1; }   # break 或 continue 或 return ，视上下文而定
                echo -e "${gl_bai}正在停止并删除所有容器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                docker stop $(docker ps -aq) 2>/dev/null || true
                docker rm -f $(docker ps -aq) 2>/dev/null || true

                # 删除所有镜像
                echo -e "${gl_bai}正在删除所有镜像 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                images=$(docker images -q)
                if [[ -n "$images" ]]; then
                    docker rmi -f $images
                    echo -e "${gl_lv}✓ 已删除所有镜像${gl_bai}"
                else
                    echo -e "${gl_huang}没有镜像可删除${gl_bai}"
                fi
            else
                echo -e "${gl_huang}已取消${gl_bai}"
            fi
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        5) docker_image_pack ;;
        6)
            # 加载单个镜像
            # 扫描备份目录
            local backup_files=()
            local i=1

            echo -e "${gl_bai}正在扫描备份目录 当前目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

            # 查找当前目录下所有 .tar 和 .tar.gz 文件
            while IFS= read -r -d $'\0' file; do
                backup_files+=("$file")
            done < <(find "." -maxdepth 1 -type f \( -name "*.tar" -o -name "*.tar.gz" -o -name "*.tgz" \) -print0 2>/dev/null | sort -z)

            if [[ ${#backup_files[@]} -eq 0 ]]; then
                echo -e "${gl_huang}在当前目录中没有找到备份文件${gl_bai}"
                echo -e "${gl_bai}支持的格式: .tar, .tar.gz, .tgz${gl_bai}"
                exit_animation    # 即将退出动画
                continue
            fi

            clear
            echo -e "${gl_huang}>>> 可加载的备份文件列表${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_lv}编号\t文件大小\t最后修改\t文件名${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            # 显示文件列表
            for i in "${!backup_files[@]}"; do
                local file="${backup_files[i]}"
                local file_name=$(basename "$file")
                local file_size=$(du -h "$file" | cut -f1)
                local mod_time=$(stat -c "%y" "$file" | cut -d' ' -f1,2 | cut -d'.' -f1)
                local file_num=$((i + 1))

                printf "${gl_huang}%3d${gl_bai}\t%-8s\t%s\t${gl_lv}%s${gl_bai}\n" \
                    "$file_num" \
                    "$file_size" \
                    "$mod_time" \
                    "$file_name"
            done

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e ""
            echo -e "${gl_zi}>>> 请输入要加载的备份文件编号:${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}请输入你的选择(${gl_huang}0${gl_bai}返回): ")" file_num

            [[ -z "$file_num" ]] && { cancel_empty "上一级选单"; continue; }         # break 或 continue 或 return ，视上下文而定
            [[ "$file_num" == "0" ]] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定

            if [[ ! "$file_num" =~ ^[0-9]+$ ]] || [[ $file_num -lt 1 ]] || [[ $file_num -gt ${#backup_files[@]} ]]; then
                echo -e "${gl_hong}✗ 无效的编号${gl_bai}"
                exit_animation    # 即将退出动画
                continue
            fi

            local selected_file="${backup_files[$((file_num - 1))]}"
            local file_size=$(du -h "$selected_file" | cut -f1)
            local file_name=$(basename "$selected_file")

            echo -e ""
            echo -e "${gl_bai}选择的文件: ${gl_huang}${file_name}${gl_bai}"
            echo -e "${gl_bai}文件大小: ${gl_huang}${file_size}${gl_bai}"
            echo -e "${gl_bai}完整路径: ${gl_huang}${selected_file}${gl_bai}"
            echo -e ""

            # 确认加载
            read -r -e -p "$(echo -e "确认加载此镜像? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_load
            if [[ ! "$confirm_load" =~ ^[Yy]$ ]]; then
                echo -e "${gl_huang}已取消加载${gl_bai}"
                exit_animation    # 即将退出动画
                continue
            fi

            echo -e "${gl_bai}正在加载镜像，请稍候 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

            # 显示加载进度
            echo -n "["
            for i in {1..20}; do
                echo -n " "
            done
            echo -n "]"

            # 加载镜像
            local load_output=$(docker load -i "$selected_file" 2>&1)
            local load_status=$?

            # 清除进度条
            echo -ne "\r\033[K"

            if [[ $load_status -eq 0 ]]; then
                echo -e "${gl_lv}✓ 镜像加载成功${gl_bai}"

                # 提取加载的镜像名称
                local loaded_image=$(echo "$load_output" | grep -oP "Loaded image: \K.*" || echo "")

                if [[ -n "$loaded_image" ]]; then
                    echo -e "${gl_bai}加载的镜像: ${gl_huang}${loaded_image}${gl_bai}"

                    # 显示新加载的镜像
                    echo -e ""
                    echo -e "${gl_bai}当前镜像列表中的最新镜像:${gl_bai}"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    docker images --format "table {{.Repository}}\t{{.Tag}}\t{{.ID}}\t{{.Size}}" | head -n 6
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                else
                    echo -e "${gl_bai}加载的输出: ${gl_huang}${load_output}${gl_bai}"
                fi

                # 询问是否删除原文件
                echo -e ""
                read -r -e -p "$(echo -e "是否删除备份文件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" delete_file
                if [[ "$delete_file" =~ ^[Yy]$ ]]; then
                    if rm -f "$selected_file"; then
                        echo -e "${gl_lv}✓ 备份文件已删除${gl_bai}"
                    else
                        echo -e "${gl_hong}✗ 文件删除失败${gl_bai}"
                    fi
                fi
            else
                echo -e "${gl_hong}✗ 镜像加载失败${gl_bai}"
                echo -e "${gl_bai}错误信息:${gl_bai}"
                echo -e "${gl_huang}${load_output}${gl_bai}"
                echo -e ""
                echo -e "${gl_huang}可能的原因:${gl_bai}"
                echo -e "  1. 文件损坏或不完整"
                echo -e "  2. 磁盘空间不足"
                echo -e "  3. Docker 服务异常"
                echo -e "  4. 权限不足"
                echo -e "  5. 镜像格式不正确"
            fi
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        7)
            while true; do
                clear
                echo ""
                echo -e "${gl_huang}本地镜像列表：${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                docker images --format "table {{.Repository}}:{{.Tag}}\t{{.ID}}\t{{.Size}}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e ""
                echo -e "${gl_zi}>> 为镜像打标签${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "$(echo -e "${gl_bai}请输入源镜像名称 (格式: ${gl_lv}nginx:tag${gl_bai} 或 ${gl_lv}image_id${gl_bai})(${gl_huang}0${gl_bai}返回): ")" source_image

                # 输入 0 返回上级菜单
                [[ "$source_image" == "0" ]] && { cancel_return "上一级选单"; break; }    # break 或 continue 或 return ，视上下文而定
                [[ -z "$source_image" ]] && { cancel_empty "重新输入"; continue; }        # break 或 continue 或 return ，视上下文而定

                # 验证源镜像是否存在
                if ! docker image inspect "$source_image" &>/dev/null; then
                    echo -ne "\r${gl_hong}错误:${gl_bai} 源镜像 ${gl_hong}'$source_image'${gl_bai} 不存在! "
                    continue # 继续循环，重新显示当前界面
                fi

                # 输入目标镜像信息
                read -r -e -p "$(echo -e "${gl_bai}请输入目标镜像名称 (${gl_huang}不含标签${gl_bai}): ")" target_name
                read -r -e -p "$(echo -e "${gl_bai}请输入目标镜像标签 [${gl_huang}默认: latest]${gl_bai}: ")" target_tag
                target_tag=${target_tag:-latest}

                # 完整的目标镜像名称
                target_image="$target_name:$target_tag"

                echo ""
                echo "即将执行: docker tag $source_image $target_image"
                read -r -e -p "$(echo -e "${gl_bai}确认执行? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

                if [[ $confirm == "y" || $confirm == "Y" ]]; then
                    if docker tag "$source_image" "$target_image"; then
                        echo -e "${gl_lv}标签创建成功!"
                        echo -e "${gl_bufan}新镜像: $target_image"
                    else
                        echo -e "${gl_hong}标签创建失败!"
                    fi
                else
                    echo "操作已取消"
                fi

                # 操作完成后询问是否继续
                echo ""
                break_end
            done
            ;;
        8)
            # 加载URL镜像
            docker_download_load -i
            ;;
        9)
            # 清理悬空镜像
            show_prune_menu
            ;;
        10)
            # 上传加载镜像
            clear
            echo -e "${gl_zi}>>> 上传 Docker 镜像到服务器${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_info "准备接收来自本地的 Docker 镜像文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bai}终端支持检测:${gl_bai}"
            echo -e "${gl_bai}支持的终端: ${gl_lv}MobaXterm, Xshell, SecureCRT, Tabby, WindTerm${gl_bai}"
            echo -e "${gl_huang}注意: PuTTY 不支持Zmodem协议${gl_bai}"
            echo -e "${gl_huang}注意: Windows Terminal 需安装lrzsz并配置${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            # 创建临时上传目录
            local upload_dir="/tmp/docker_upload_$(date +%Y%m%d_%H%M%S)_$$"
            mkdir -p "$upload_dir"
            
            echo -e "${gl_huang}文件将上传到: ${gl_lv}${upload_dir}${gl_bai}"
            echo -e "${gl_bai}支持的格式: ${gl_lv}.tar, .tar.gz, .tgz${gl_bai}"
            echo -e ""
            echo -e "${gl_huang}请在本地客户端选择要上传的 Docker 镜像文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            
            for i in {3..1}; do
                echo -ne "${gl_huang}将在 ${gl_lv}$i${gl_bai} 秒后弹出文件选择对话框${gl_bai}\r"
                sleep_fractional 1
            done
            echo ""
            
            if ! command -v rz >/dev/null 2>&1; then
                log_error "rz命令不可用，请先安装lrzsz"
                echo -e "${gl_bai}安装命令: ${gl_lv}apt-get install lrzsz${gl_bai} (Debian/Ubuntu)"
                echo -e "${gl_bai}安装命令: ${gl_lv}yum install lrzsz${gl_bai} (CentOS/RHEL)"
                rm -rf "$upload_dir"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                continue
            fi
            
            echo -e "${gl_bai}执行命令: ${gl_zi}rz -y -E${gl_bai} (覆盖模式)"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}提示: 按${gl_lv}Ctrl+C${gl_bai}取消上传${gl_bai}"
            echo -e ""
            
            # 进入上传目录执行rz
            cd "$upload_dir" || {
                log_error "无法进入上传目录: $upload_dir"
                rm -rf "$upload_dir"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                continue
            }
            
            local rz_status=0
            rz -y -E || rz_status=$?
            
            # 返回原目录
            cd - >/dev/null 2>&1 || true
            
            if [[ $rz_status -eq 130 ]] || [[ $rz_status -eq 1 ]]; then
                log_info "上传被用户取消"
                rm -rf "$upload_dir"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                continue
            fi
            
            # 检查上传的文件
            local uploaded_files=()
            while IFS= read -r -d $'\0' file; do
                uploaded_files+=("$file")
            done < <(find "$upload_dir" -maxdepth 1 -type f \( -name "*.tar" -o -name "*.tar.gz" -o -name "*.tgz" \) -print0 2>/dev/null)
            
            if [[ ${#uploaded_files[@]} -eq 0 ]]; then
                log_warn "未找到有效的 Docker 镜像文件"
                echo -e "${gl_bai}上传目录: ${gl_huang}${upload_dir}${gl_bai}"
                echo -e "${gl_bai}请确保上传的文件格式为: ${gl_lv}.tar, .tar.gz, .tgz${gl_bai}"
                
                # 显示实际上传的文件（如果有）
                local all_files=("$upload_dir"/*)
                if [[ -f "${all_files[0]}" ]]; then
                    echo -e ""
                    echo -e "${gl_huang}实际上传的文件:${gl_bai}"
                    ls -lh "$upload_dir"
                fi
                
                read -r -e -p "$(echo -e "是否保留上传的文件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" keep_files
                if [[ ! "$keep_files" =~ ^[Yy]$ ]]; then
                    rm -rf "$upload_dir"
                    log_info "临时文件已清理"
                else
                    log_info "文件保留在: $upload_dir"
                fi
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                continue
            fi
            
            log_ok "文件上传成功!"
            echo -e ""
            echo -e "${gl_huang}>>> 上传的镜像文件列表:${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_lv}编号\t文件大小\t文件名${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            local i=1
            local file_list=()
            for file in "${uploaded_files[@]}"; do
                local file_name=$(basename "$file")
                local file_size=$(du -h "$file" | cut -f1)
                file_list+=("$file")
                printf "${gl_lv}%2d${gl_bai}\t%-8s\t${gl_huang}%s${gl_bai}\n" "$i" "$file_size" "$file_name"
                ((i++))
            done
            
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e ""
            
            # 选择要加载的文件
            local selected_idx=1
            if [[ ${#uploaded_files[@]} -gt 1 ]]; then
                read -r -e -p "$(echo -e "请选择要加载的镜像文件编号 [${gl_lv}1-${#uploaded_files[@]}${gl_bai}] (默认: 1, ${gl_hong}0${gl_bai}跳过): ")" selected_idx
                selected_idx=${selected_idx:-1}
                
                if [[ "$selected_idx" == "0" ]]; then
                    log_info "跳过加载镜像"
                    echo -e ""
                    read -r -e -p "$(echo -e "是否保留上传的文件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" keep_files
                    if [[ "$keep_files" =~ ^[Yy]$ ]]; then
                        log_info "文件保留在: $upload_dir"
                    else
                        rm -rf "$upload_dir"
                        log_info "临时文件已清理"
                    fi
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                    continue
                fi
                
                if [[ ! "$selected_idx" =~ ^[0-9]+$ ]] || [[ $selected_idx -lt 1 ]] || [[ $selected_idx -gt ${#uploaded_files[@]} ]]; then
                    log_warn "无效的编号，默认选择第1个"
                    selected_idx=1
                fi
            fi
            
            local selected_file="${file_list[$((selected_idx - 1))]}"
            local file_name=$(basename "$selected_file")
            local file_size=$(du -h "$selected_file" | cut -f1)
            
            echo -e ""
            echo -e "${gl_bai}选择的文件: ${gl_huang}${file_name}${gl_bai}"
            echo -e "${gl_bai}文件大小: ${gl_huang}${file_size}${gl_bai}"
            echo -e "${gl_bai}完整路径: ${gl_huang}${selected_file}${gl_bai}"
            echo -e ""
            
            # 询问是否加载镜像
            read -r -e -p "$(echo -e "是否立即加载此 Docker 镜像? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_load
            
            if [[ ! "$confirm_load" =~ ^[Yy]$ ]]; then
                log_info "跳过加载镜像"
                echo -e ""
                read -r -e -p "$(echo -e "是否保留上传的文件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" keep_files
                if [[ "$keep_files" =~ ^[Yy]$ ]]; then
                    # 移动到当前目录
                    local target_path="./${file_name}"
                    mv "$selected_file" "$target_path" 2>/dev/null && {
                        log_ok "文件已移动到: $target_path"
                    } || {
                        log_info "文件保留在: $upload_dir"
                    }
                    # 清理临时目录（如果已移动则目录为空）
                    rm -rf "$upload_dir" 2>/dev/null
                else
                    rm -rf "$upload_dir"
                    log_info "临时文件已清理"
                fi
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                continue
            fi
            
            # 执行加载
            echo -e ""
            echo -e "${gl_huang}>>> 正在加载 Docker 镜像 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}加载中，请稍候 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            
            # 加载动画
            echo -n "["
            for i in {1..20}; do
                echo -n " "
            done
            echo -n "]"
            
            (
                while true; do
                    echo -ne "\r["
                    for ((j=1; j<=20; j++)); do
                        if [[ $((j % 4)) -eq 0 ]]; then
                            echo -ne "${gl_lv}=${gl_bai}"
                        else
                            echo -ne " "
                        fi
                    done
                    echo -ne "]"
                    sleep_fractional 0.5
                done
            ) &
            local anim_pid=$!
            
            # 加载镜像
            local load_output
            local load_status=0
            load_output=$(docker load -i "$selected_file" 2>&1) || load_status=$?
            
            # 停止动画
            kill $anim_pid 2>/dev/null
            wait $anim_pid 2>/dev/null
            echo -ne "\r\033[K"
            
            if [[ $load_status -eq 0 ]]; then
                log_ok "镜像加载成功!"
                
                # 提取镜像名称
                local loaded_image=$(echo "$load_output" | grep -oP "Loaded image: \K.*" || echo "")
                if [[ -n "$loaded_image" ]]; then
                    echo -e "${gl_bai}加载的镜像: ${gl_lv}${loaded_image}${gl_bai}"
                fi
                
                echo -e ""
                echo -e "${gl_bai}当前镜像列表中的最新镜像:${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                docker images --format "table {{.Repository}}\t{{.Tag}}\t{{.ID}}\t{{.Size}}" | head -n 6
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                
                # 询问是否删除原文件
                echo -e ""
                read -r -e -p "$(echo -e "是否删除上传的镜像文件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" delete_file
                if [[ "$delete_file" =~ ^[Yy]$ ]]; then
                    rm -rf "$upload_dir"
                    log_ok "临时文件已清理"
                else
                    # 移动到当前目录
                    local target_path="./${file_name}"
                    if mv "$selected_file" "$target_path" 2>/dev/null; then
                        rm -rf "$upload_dir" 2>/dev/null
                        log_ok "文件已保存到: $target_path"
                    else
                        log_info "文件保留在: $upload_dir"
                    fi
                fi
            else
                log_error "镜像加载失败"
                echo -e "${gl_bai}错误信息:${gl_bai}"
                echo -e "${gl_huang}${load_output}${gl_bai}"
                echo -e ""
                echo -e "${gl_huang}可能的原因:${gl_bai}"
                echo -e "  1. 文件损坏或不完整"
                echo -e "  2. 文件格式不正确（非 Docker 镜像格式）"
                echo -e "  3. Docker 服务异常"
                echo -e "  4. 磁盘空间不足"
                echo -e "  5. 权限不足"
                
                echo -e ""
                read -r -e -p "$(echo -e "是否保留下传的文件以供检查? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" keep_failed
                if [[ "$keep_failed" =~ ^[Yy]$ ]]; then
                    local target_path="./failed_${file_name}"
                    mv "$selected_file" "$target_path" 2>/dev/null && {
                        rm -rf "$upload_dir" 2>/dev/null
                        log_info "文件已保存到: $target_path"
                    } || {
                        log_info "文件保留在: $upload_dir"
                    }
                else
                    rm -rf "$upload_dir"
                    log_info "临时文件已清理"
                fi
            fi

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        0) cancel_return "$menu_name"; break ;;     # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;             # 感谢使用，再见！
        *) handle_invalid_input ;;                  # 无效的输入,请重新输入!
        esac
    done
}

###### 检查 crontab 是否已安装，如果未安装则自动安装。
check_crontab_installed() {
    if ! command -v crontab >/dev/null 2>&1; then
        install_crontab
    fi
}

install_crontab() {

    if [ -f /etc/os-release ]; then
        . /etc/os-release
        case "$ID" in
        ubuntu | debian | kali)
            apt update
            apt install -y cron
            systemctl enable cron
            systemctl start cron
            ;;
        centos | rhel | almalinux | rocky | fedora)
            yum install -y cronie
            systemctl enable crond
            systemctl start crond
            ;;
        alpine)
            apk add --no-cache cronie
            rc-update add crond
            rc-service crond start
            ;;
        arch | manjaro)
            pacman -S --noconfirm cronie
            systemctl enable cronie
            systemctl start cronie
            ;;
        opensuse | suse | opensuse-tumbleweed)
            zypper install -y cron
            systemctl enable cron
            systemctl start cron
            ;;
        iStoreOS | openwrt | ImmortalWrt | lede)
            opkg update
            opkg install cron
            /etc/init.d/cron enable
            /etc/init.d/cron start
            ;;
        FreeBSD)
            pkg install -y cronie
            sysrc cron_enable="YES"
            service cron start
            ;;
        *)
            echo "不支持的发行版: $ID"
            return
            ;;
        esac
    else
        echo "无法确定操作系统。"
        return
    fi

    echo -e "${gl_lv}crontab 已安装且 cron 服务正在运行。${gl_bai}"
}

docker_ipv6_on() {
    root_use
    install jq
    echo ""
    echo -e "${gl_zi}>>> 开启Docker-ipv6访问${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确定要开启Docker-ipv6访问吗？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
	[ "$confirm" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
	[ -z "$confirm" ] && { cancel_empty "上一级选单"; return 1; }        # break 或 continue 或 return ，视上下文而定
    if [[ ! $confirm =~ ^[Yy]$ ]]; then
        echo -e "${gl_huang}已取消卸载操作${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    local CONFIG_FILE="/etc/docker/daemon.json"
    local REQUIRED_IPV6_CONFIG='{"ipv6": true, "fixed-cidr-v6": "2001:db8:1::/64"}'

    # 检查配置文件是否存在，如果不存在则创建文件并写入默认设置
    if [ ! -f "$CONFIG_FILE" ]; then
        echo "$REQUIRED_IPV6_CONFIG" | jq . >"$CONFIG_FILE"
        restart docker
    else
        # 使用jq处理配置文件的更新
        local ORIGINAL_CONFIG
        ORIGINAL_CONFIG=$(<"$CONFIG_FILE")

        # 检查当前配置是否已经有 ipv6 设置
        local CURRENT_IPV6
        CURRENT_IPV6=$(echo "$ORIGINAL_CONFIG" | jq '.ipv6 // false')

        # 更新配置，开启 IPv6
        if [[ "$CURRENT_IPV6" == "false" ]]; then
            UPDATED_CONFIG=$(echo "$ORIGINAL_CONFIG" | jq '. + {ipv6: true, "fixed-cidr-v6": "2001:db8:1::/64"}')
        else
            UPDATED_CONFIG=$(echo "$ORIGINAL_CONFIG" | jq '. + {"fixed-cidr-v6": "2001:db8:1::/64"}')
        fi

        # 对比原始配置与新配置
        if [[ "$ORIGINAL_CONFIG" == "$UPDATED_CONFIG" ]]; then
            echo -e "${gl_huang}当前已开启ipv6访问${gl_bai}"
        else
            echo "$UPDATED_CONFIG" | jq . >"$CONFIG_FILE"
            restart docker
        fi
    fi
}

docker_ipv6_off() {
    root_use
    install jq

    echo ""
    echo -e "${gl_zi}>>> 关闭Docker-ipv6访问${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确定要关闭Docker-ipv6访问吗？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
	[ "$confirm" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
	[ -z "$confirm" ] && { cancel_empty "上一级选单"; return 1; }        # break 或 continue 或 return ，视上下文而定
    if [[ ! $confirm =~ ^[Yy]$ ]]; then
        echo -e "${gl_huang}已取消卸载操作${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    local CONFIG_FILE="/etc/docker/daemon.json"

    # 检查配置文件是否存在
    if [ ! -f "$CONFIG_FILE" ]; then
        echo -e "${gl_hong}配置文件不存在${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 读取当前配置
    local ORIGINAL_CONFIG
    ORIGINAL_CONFIG=$(<"$CONFIG_FILE")

    # 使用jq处理配置文件的更新
    local UPDATED_CONFIG
    UPDATED_CONFIG=$(echo "$ORIGINAL_CONFIG" | jq 'del(.["fixed-cidr-v6"]) | .ipv6 = false')

    # 检查当前的 ipv6 状态
    local CURRENT_IPV6
    CURRENT_IPV6=$(echo "$ORIGINAL_CONFIG" | jq -r '.ipv6 // false')

    # 对比原始配置与新配置
    if [[ "$CURRENT_IPV6" == "false" ]]; then
        echo -e "${gl_huang}当前已关闭ipv6访问${gl_bai}"
    else
        echo "$UPDATED_CONFIG" | jq . >"$CONFIG_FILE"
        restart docker
        echo -e "${gl_huang}已成功关闭ipv6访问${gl_bai}"
    fi
}

save_iptables_rules() {
    mkdir -p /etc/iptables
    touch /etc/iptables/rules.v4
    iptables-save >/etc/iptables/rules.v4
    check_crontab_installed
    crontab -l | grep -v 'iptables-restore' | crontab - >/dev/null 2>&1
    (
        crontab -l
        echo '@reboot iptables-restore < /etc/iptables/rules.v4'
    ) | crontab - >/dev/null 2>&1

}

iptables_open() {
    install iptables
    save_iptables_rules
    iptables -P INPUT ACCEPT
    iptables -P FORWARD ACCEPT
    iptables -P OUTPUT ACCEPT
    iptables -F

    ip6tables -P INPUT ACCEPT
    ip6tables -P FORWARD ACCEPT
    ip6tables -P OUTPUT ACCEPT
    ip6tables -F
}

open_port() {
    local ports=("$@") # 将传入的参数转换为数组
    if [ ${#ports[@]} -eq 0 ]; then
        echo "请提供至少一个端口号"
        exit_animation    # 即将退出动画
        return 1
    fi

    install iptables

    for port in "${ports[@]}"; do
        # 删除已存在的关闭规则
        iptables -D INPUT -p tcp --dport "$port" -j DROP 2>/dev/null
        iptables -D INPUT -p udp --dport "$port" -j DROP 2>/dev/null

        # 添加打开规则
        if ! iptables -C INPUT -p tcp --dport "$port" -j ACCEPT 2>/dev/null; then
            iptables -I INPUT 1 -p tcp --dport "$port" -j ACCEPT
        fi

        if ! iptables -C INPUT -p udp --dport "$port" -j ACCEPT 2>/dev/null; then
            iptables -I INPUT 1 -p udp --dport "$port" -j ACCEPT
            echo "已打开端口 ${port}"
        fi
    done
    save_iptables_rules
}

close_port() {
    local ports=("$@") # 将传入的参数转换为数组
    if [ ${#ports[@]} -eq 0 ]; then
        echo "请提供至少一个端口号"
        exit_animation    # 即将退出动画
        return 1
    fi

    install iptables

    for port in "${ports[@]}"; do
        # 删除已存在的打开规则
        iptables -D INPUT -p tcp --dport "$port" -j ACCEPT 2>/dev/null
        iptables -D INPUT -p udp --dport "$port" -j ACCEPT 2>/dev/null

        # 添加关闭规则
        if ! iptables -C INPUT -p tcp --dport "$port" -j DROP 2>/dev/null; then
            iptables -I INPUT 1 -p tcp --dport "$port" -j DROP
        fi

        if ! iptables -C INPUT -p udp --dport "$port" -j DROP 2>/dev/null; then
            iptables -I INPUT 1 -p udp --dport "$port" -j DROP
            echo "已关闭端口 $port"
        fi
    done

    # 删除已存在的规则（如果有）
    iptables -D INPUT -i lo -j ACCEPT 2>/dev/null
    iptables -D FORWARD -i lo -j ACCEPT 2>/dev/null

    # 插入新规则到第一条
    iptables -I INPUT 1 -i lo -j ACCEPT
    iptables -I FORWARD 1 -i lo -j ACCEPT

    save_iptables_rules
}

allow_ip() {
    local ips=("$@") # 将传入的参数转换为数组
    if [ ${#ips[@]} -eq 0 ]; then
        echo "请提供至少一个IP地址或IP段"
        exit_animation    # 即将退出动画
        return 1
    fi

    install iptables

    for ip in "${ips[@]}"; do
        # 删除已存在的阻止规则
        iptables -D INPUT -s "$ip" -j DROP 2>/dev/null

        # 添加允许规则
        if ! iptables -C INPUT -s "$ip" -j ACCEPT 2>/dev/null; then
            iptables -I INPUT 1 -s "$ip" -j ACCEPT
            echo "已放行IP $ip"
        fi
    done

    save_iptables_rules
}

block_ip() {
    local ips=("$@") # 将传入的参数转换为数组
    if [ ${#ips[@]} -eq 0 ]; then
        echo "请提供至少一个IP地址或IP段"
        exit_animation    # 即将退出动画
        return 1
    fi

    install iptables

    for ip in "${ips[@]}"; do
        # 删除已存在的允许规则
        iptables -D INPUT -s "$ip" -j ACCEPT 2>/dev/null

        # 添加阻止规则
        if ! iptables -C INPUT -s "$ip" -j DROP 2>/dev/null; then
            iptables -I INPUT 1 -s "$ip" -j DROP
            echo "已阻止IP $ip"
        fi
    done

    save_iptables_rules
}

enable_ddos_defense() {
    # 开启防御 DDoS
    iptables -A DOCKER-USER -p tcp --syn -m limit --limit 500/s --limit-burst 100 -j ACCEPT
    iptables -A DOCKER-USER -p tcp --syn -j DROP
    iptables -A DOCKER-USER -p udp -m limit --limit 3000/s -j ACCEPT
    iptables -A DOCKER-USER -p udp -j DROP
    iptables -A INPUT -p tcp --syn -m limit --limit 500/s --limit-burst 100 -j ACCEPT
    iptables -A INPUT -p tcp --syn -j DROP
    iptables -A INPUT -p udp -m limit --limit 3000/s -j ACCEPT
    iptables -A INPUT -p udp -j DROP
}

###### 关闭DDoS防御
disable_ddos_defense() {
    iptables -D DOCKER-USER -p tcp --syn -m limit --limit 500/s --limit-burst 100 -j ACCEPT 2>/dev/null
    iptables -D DOCKER-USER -p tcp --syn -j DROP 2>/dev/null
    iptables -D DOCKER-USER -p udp -m limit --limit 3000/s -j ACCEPT 2>/dev/null
    iptables -D DOCKER-USER -p udp -j DROP 2>/dev/null
    iptables -D INPUT -p tcp --syn -m limit --limit 500/s --limit-burst 100 -j ACCEPT 2>/dev/null
    iptables -D INPUT -p tcp --syn -j DROP 2>/dev/null
    iptables -D INPUT -p udp -m limit --limit 3000/s -j ACCEPT 2>/dev/null
    iptables -D INPUT -p udp -j DROP 2>/dev/null
}

###### 管理国家IP规则的函数
manage_country_rules() {
    local action="$1"
    shift # 去掉第一个参数，剩下的全是国家代码

    install ipset

    for country_code in "$@"; do
        local ipset_name="${country_code,,}_block"
        local download_url="http://www.ipdeny.com/ipblocks/data/countries/${country_code,,}.zone"

        case "$action" in
        block)
            if ! ipset list "$ipset_name" &>/dev/null; then
                ipset create "$ipset_name" hash:net
            fi

            if ! wget -q "$download_url" -O "${country_code,,}.zone"; then
                echo "错误：下载 $country_code 的 IP 区域文件失败"
                exit_animation    # 即将退出动画
                return
            fi

            while IFS= read -r -r ip; do
                ipset add "$ipset_name" "$ip" 2>/dev/null
            done <"${country_code,,}.zone"

            iptables -I INPUT -m set --match-set "$ipset_name" src -j DROP

            echo "已成功阻止 $country_code 的 IP 地址"
            rm "${country_code,,}.zone"
            ;;

        allow)
            if ! ipset list "$ipset_name" &>/dev/null; then
                ipset create "$ipset_name" hash:net
            fi

            if ! wget -q "$download_url" -O "${country_code,,}.zone"; then
                echo "错误：下载 $country_code 的 IP 区域文件失败"
                exit_animation    # 即将退出动画
                return
            fi

            ipset flush "$ipset_name"
            while IFS= read -r -r ip; do
                ipset add "$ipset_name" "$ip" 2>/dev/null
            done <"${country_code,,}.zone"

            iptables -P INPUT DROP
            iptables -A INPUT -m set --match-set "$ipset_name" src -j ACCEPT

            echo "已成功允许 $country_code 的 IP 地址"
            rm "${country_code,,}.zone"
            ;;

        unblock)
            iptables -D INPUT -m set --match-set "$ipset_name" src -j DROP 2>/dev/null

            if ipset list "$ipset_name" &>/dev/null; then
                ipset destroy "$ipset_name"
            fi

            echo "已成功解除 $country_code 的 IP 地址限制"
            ;;
        *)
            echo -e "${gl_bai}用法: ${gl_lv}manage_country_rules {block|allow|unblock} <country_code${gl_hong}.${gl_huang}.${gl_lv}.>${gl_bai}"
            ;;
        esac
    done
}

