            fix_phpfpm_conf php74

            # mysql调优
            wget -O /home/custom_mysql_config.cnf ${gh_proxy}raw.githubusercontent.com/kejilion/sh/main/custom_mysql_config-1.cnf
            docker cp /home/custom_mysql_config.cnf mysql:/etc/mysql/conf.d/
