    fi

    # 清除封禁所有其他 IP 访问的规则
    if iptables -C INPUT -p udp --dport "$port" -j DROP &>/dev/null; then
        iptables -D INPUT -p udp --dport "$port" -j DROP
    fi

    # 清除允许本机访问的规则
    if iptables -C INPUT -p udp --dport "$port" -s 127.0.0.0/8 -j ACCEPT &>/dev/null; then
