    cd /etc/nginx/html
    mkdir "$yuming"
    cd "$yuming"
    wget -O latest.zip ${gh_proxy}github.com/kejilion/Website_source_code/raw/refs/heads/main/wp-latest.zip
    unzip latest.zip
