}

check_frp_app() {

    if [ -d "/home/frp/" ]; then
        check_frp="${gl_lv}已安装${gl_bai}"
    else
        check_frp="${gl_hui}未安装${gl_bai}"
    fi

}

donlond_frp() {
    role="$1"
    config_file="/home/frp/${role}.toml"

    docker run -d \
        --name "$role" \
        --restart=always \
        --network host \
        -v "$config_file":"/frp/${role}.toml" \
        kjlion/frp:alpine \
        "/frp/${role}" -c "/frp/${role}.toml"

}

generate_frps_config() {

    # 生成随机端口和凭证
    local bind_port=8055
    local dashboard_port=8056
    local token
    token=$(openssl rand -hex 16)
    local dashboard_user
    dashboard_user="user_$(openssl rand -hex 4)"
    local dashboard_pwd
    dashboard_pwd=$(openssl rand -hex 8)

    mkdir -p /home/frp
    touch /home/frp/frps.toml
    cat <<EOF >/home/frp/frps.toml
[common]
bind_port = $bind_port
authentication_method = token
token = $token
dashboard_port = $dashboard_port
dashboard_user = $dashboard_user
dashboard_pwd = $dashboard_pwd
EOF

    donlond_frp frps

    # 输出生成的信息
    ip_address
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo "客户端部署时需要用的参数"
    echo "服务IP: $ipv4_address"
    echo "token: $token"
    echo
    echo "FRP面板信息"
    echo "FRP面板地址: http://$ipv4_address:$dashboard_port"
    echo "FRP面板用户名: $dashboard_user"
    echo "FRP面板密码: $dashboard_pwd"
    echo

    open_port 8055 8056

}

configure_frpc() {
    read -r -e -p "请输入外网对接IP: " server_addr
    [ "$server_addr" = "0" ] && { cancel_return "上一级选单"; return 1; }       # break 或 continue 或 return ，视上下文而定
    [ -z "$server_addr" ] && { cancel_empty "上一级选单"; return 1; }           # break 或 continue 或 return ，视上下文而定

    read -r -e -p "请输入外网对接token: " token
    [ "$token" = "0" ] && { cancel_return "上一级选单"; return 1; }             # break 或 continue 或 return ，视上下文而定
    [ -z "$token" ] && { cancel_empty "上一级选单"; return 1; }                 # break 或 continue 或 return ，视上下文而定
    echo

    mkdir -p /home/frp
    touch /home/frp/frpc.toml
    cat <<EOF >/home/frp/frpc.toml
[common]
server_addr = ${server_addr}
server_port = 8055
token = ${token}

EOF

    donlond_frp frpc

    open_port 8055

}

add_forwarding_service() {
    # 提示用户输入服务名称和转发信息
    read -r -e -p "请输入服务名称: " service_name
    [ "$service_name" = "0" ] && { cancel_return "上一级选单"; return 1; }     # break 或 continue 或 return ，视上下文而定
    [ -z "$service_name" ] && { cancel_empty "上一级选单"; return 1; }         # break 或 continue 或 return ，视上下文而定

    read -r -e -p "请输入转发类型 (tcp/udp) [回车默认tcp]: " service_type
    [ "$service_type" = "0" ] && { cancel_return "上一级选单"; return 1; }     # break 或 continue 或 return ，视上下文而定
    [ -z "$service_type" ] && { cancel_empty "上一级选单"; return 1; }         # break 或 continue 或 return ，视上下文而定

    local service_type=${service_type:-tcp}
    read -r -e -p "请输入内网IP [回车默认127.0.0.1]: " local_ip
    [ "$local_ip" = "0" ] && { cancel_return "上一级选单"; return 1; }         # break 或 continue 或 return ，视上下文而定
    [ -z "$local_ip" ] && { cancel_empty "上一级选单"; return 1; }             # break 或 continue 或 return ，视上下文而定

    local local_ip=${local_ip:-127.0.0.1}
    read -r -e -p "请输入内网端口: " local_port
    [ "$local_port" = "0" ] && { cancel_return "上一级选单"; return 1; }       # break 或 continue 或 return ，视上下文而定
    [ -z "$local_port" ] && { cancel_empty "上一级选单"; return 1; }           # break 或 continue 或 return ，视上下文而定

    read -r -e -p "请输入外网端口: " remote_port
    [ "$remote_port" = "0" ] && { cancel_return "上一级选单"; return 1; }      # break 或 continue 或 return ，视上下文而定
    [ -z "$remote_port" ] && { cancel_empty "上一级选单"; return 1; }          # break 或 continue 或 return ，视上下文而定
    # 将用户输入写入配置文件
    cat <<EOF >>/home/frp/frpc.toml
[$service_name]
type = ${service_type}
local_ip = ${local_ip}
local_port = ${local_port}
remote_port = ${remote_port}

EOF

    # 输出生成的信息
    echo "服务 $service_name 已成功添加到 frpc.toml"

    docker restart frpc

    open_port "$local_port"

}

delete_forwarding_service() {
    # 提示用户输入需要删除的服务名称
    read -r -e -p "请输入需要删除的服务名称: " service_name
    [ "$service_name" = "0" ] && { cancel_return "上一级选单"; return 1; }     # break 或 continue 或 return ，视上下文而定
    [ -z "$service_name" ] && { cancel_empty "上一级选单"; return 1; }         # break 或 continue 或 return ，视上下文而定
    # 使用 sed 删除该服务及其相关配置
    sed -i "/\[$service_name\]/,/^$/d" /home/frp/frpc.toml
    echo "服务 $service_name 已成功从 frpc.toml 删除"

    docker restart frpc

}

list_forwarding_services() {
    local config_file="$1"

    # 打印表头
    printf "%-20s %-25s %-30s %-10s\n" "服务名称" "内网地址" "外网地址" "协议"

    awk '
    BEGIN {
        server_addr=""
        server_port=""
        current_service=""
    }

    /^server_addr = / {
        gsub(/"|'"'"'/, "", $3)
        server_addr=$3
    }

    /^server_port = / {
        gsub(/"|'"'"'/, "", $3)
        server_port=$3
    }

    /^\[.*\]/ {
        # 如果已有服务信息，在处理新服务之前打印当前服务
        if (current_service != "" && current_service != "common" && local_ip != "" && local_port != "") {
            printf "%-16s %-21s %-26s %-10s\n", \
                current_service, \
                local_ip ":" local_port, \
                server_addr ":" remote_port, \
                type
        }

        # 更新当前服务名称
        if ($1 != "[common]") {
            gsub(/[\[\]]/, "", $1)
            current_service=$1
            # 清除之前的值
            local_ip=""
            local_port=""
            remote_port=""
            type=""
        }
    }

    /^local_ip = / {
        gsub(/"|'"'"'/, "", $3)
        local_ip=$3
    }

    /^local_port = / {
        gsub(/"|'"'"'/, "", $3)
        local_port=$3
    }

    /^remote_port = / {
        gsub(/"|'"'"'/, "", $3)
        remote_port=$3
    }

    /^type = / {
        gsub(/"|'"'"'/, "", $3)
        type=$3
    }

    END {
        # 打印最后一个服务的信息
        if (current_service != "" && current_service != "common" && local_ip != "" && local_port != "") {
            printf "%-16s %-21s %-26s %-10s\n", \
                current_service, \
                local_ip ":" local_port, \
                server_addr ":" remote_port, \
                type
        }
    }' "$config_file"
}

# 获取 FRP 服务端端口
get_frp_ports() {
    mapfile -t ports < <(ss -tulnape | grep frps | awk '{print $5}' | awk -F':' '{print $NF}' | sort -u)
}

# 生成访问地址
generate_access_urls() {
    # 首先获取所有端口
    get_frp_ports

    # 检查是否有非 8055/8056 的端口
    local has_valid_ports=false
    for port in "${ports[@]}"; do
        if [[ "$port" != "8055" && "$port" != "8056" ]]; then
            has_valid_ports=true
            break
        fi
    done

    # 只在有有效端口时显示标题和内容
    if [ "$has_valid_ports" = true ]; then
        echo "FRP服务对外访问地址:"

        # 处理 IPv4 地址
        for port in "${ports[@]}"; do
            if [[ "$port" != "8055" && "$port" != "8056" ]]; then
                echo "http://${ipv4_address}:${port}"
            fi
        done

        # 处理 IPv6 地址（如果存在）
        if [ -n "$ipv6_address" ]; then
            for port in "${ports[@]}"; do
                if [[ "$port" != "8055" && "$port" != "8056" ]]; then
                    echo "http://[${ipv6_address}]:${port}"
                fi
            done
        fi

        # 处理 HTTPS 配置
        for port in "${ports[@]}"; do
            if [[ "$port" != "8055" && "$port" != "8056" ]]; then
                local frps_search_pattern="${ipv4_address}:${port}"
                local frps_search_pattern2="127.0.0.1:${port}"
                for file in /etc/nginx/conf.d/*.conf; do
                    if [ -f "$file" ]; then
                        if grep -q "$frps_search_pattern" "$file" 2>/dev/null || grep -q "$frps_search_pattern2" "$file" 2>/dev/null; then
                            echo "https://$(basename "$file" .conf)"
                        fi
                    fi
                done
            fi
        done
    fi
}

frps_main_ports() {
    ip_address
    generate_access_urls
}

