            [ -z "$frps_port" ] && { cancel_empty "上一级选单"; continue; }      # break 或 continue 或 return ，视上下文而定
            clear_host_port_rules "$frps_port" "$ipv4_address"
            ;;
        8)
            echo "如果你已经反代域名访问了，可用此功能阻止IP+端口访问，这样更安全。"
            read -r -e -p "请输入需要阻止的端口: " frps_port
            [ "$frps_port" = "0" ] && { cancel_return "上一级选单"; continue; }  # break 或 continue 或 return ，视上下文而定
            [ -z "$frps_port" ] && { cancel_empty "上一级选单"; continue; }      # break 或 continue 或 return ，视上下文而定
            block_host_port "$frps_port" "$ipv4_address"
            ;;
        00)
            echo "已经刷新FRP服务状态"
            ;;
        0) cancel_return; break ;;      # 返回到上一级菜单
        *) handle_invalid_input ;;      # 无效的输入,请重新输入!
        esac
    done
}

