        *) handle_invalid_input ;;      # 无效的输入,请重新输入!
        esac
    done
}

current_timezone() {
    if grep -q 'Alpine' /etc/issue; then
        date +"%Z %z"
    else
        timedatectl | grep "Time zone" | awk '{print $3}'
    fi

}

set_timedate() {
    local shiqu="$1"
    if grep -q 'Alpine' /etc/issue; then
        install tzdata
        cp /usr/share/zoneinfo/"${shiqu}" /etc/localtime
        hwclock --systohc
    else
        timedatectl set-timezone "${shiqu}"
    fi
}

# 修复dpkg中断问题
fix_dpkg() {
    pkill -9 -f 'apt|dpkg'
    rm -f /var/lib/dpkg/lock-frontend /var/lib/dpkg/lock
    DEBIAN_FRONTEND=noninteractive dpkg --configure -a
}

linux_update() {
    exit_if_fnos_system || return 1  # 是FnOS退出
    clear
    root_use
    echo ""
    echo -e "${gl_zi}>>> 正在系统更新 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if command -v dnf &>/dev/null; then
        dnf -y update
    elif command -v yum &>/dev/null; then
        yum -y update
    elif command -v apt &>/dev/null; then
        fix_dpkg
        DEBIAN_FRONTEND=noninteractive apt update -y
        DEBIAN_FRONTEND=noninteractive apt full-upgrade -y
    elif command -v apk &>/dev/null; then
        apk update && apk upgrade
    elif command -v pacman &>/dev/null; then
        pacman -Syu --noconfirm
    elif command -v zypper &>/dev/null; then
        zypper refresh
        zypper update
    elif command -v opkg &>/dev/null; then
        opkg update
    else
        echo "未知的包管理器!"
        return
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

linux_clean() {
    exit_if_fnos_system || return 1  # 是FnOS退出
    clear
    echo ""
    echo -e "${gl_zi}>>> 正在系统清理 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if command -v dnf &>/dev/null; then
        log_info "使用 dnf 进行系统清理"
        rpm --rebuilddb
        dnf autoremove -y
        dnf clean all
        dnf makecache
        journalctl --rotate
        journalctl --vacuum-time=1s
        journalctl --vacuum-size=500M
        log_ok "dnf 系统清理完成"

    elif command -v yum &>/dev/null; then
        log_info "使用 yum 进行系统清理"
        rpm --rebuilddb
        yum autoremove -y
        yum clean all
        yum makecache
        journalctl --rotate
        journalctl --vacuum-time=1s
        journalctl --vacuum-size=500M
        log_ok "yum 系统清理完成"

    elif command -v apt &>/dev/null; then
        log_info "使用 apt 进行系统清理"
        # 这里需要先定义或检查 fix_dpkg 函数
        if type fix_dpkg &>/dev/null; then
            fix_dpkg
        else
            log_warn "未找到 fix_dpkg 函数，跳过此步骤"
        fi
        apt autoremove --purge -y
        apt clean -y
        apt autoclean -y
        journalctl --rotate
        journalctl --vacuum-time=1s
        journalctl --vacuum-size=500M
        log_ok "apt 系统清理完成"

    elif command -v apk &>/dev/null; then
        log_info "使用 apk 进行系统清理"
        log_info "清理包管理器缓存"
        apk cache clean
        log_info "删除系统日志"
        rm -rf /var/log/*
        log_info "删除APK缓存"
        rm -rf /var/cache/apk/*
        log_info "删除临时文件"
        rm -rf /tmp/*
        log_ok "apk 系统清理完成"

    elif command -v pacman &>/dev/null; then
        log_info "使用 pacman 进行系统清理"
        pacman -Rns "$(pacman -Qdtq)" --noconfirm
        pacman -Scc --noconfirm
        journalctl --rotate
        journalctl --vacuum-time=1s
        journalctl --vacuum-size=500M
        log_ok "pacman 系统清理完成"

    elif command -v zypper &>/dev/null; then
        log_info "使用 zypper 进行系统清理"
        zypper clean --all
        zypper refresh
        journalctl --rotate
        journalctl --vacuum-time=1s
        journalctl --vacuum-size=500M
        log_ok "zypper 系统清理完成"

    elif command -v opkg &>/dev/null; then
        log_info "使用 opkg 进行系统清理"
        log_info "删除系统日志"
        rm -rf /var/log/*
        log_info "删除临时文件"
        rm -rf /tmp/*
        log_ok "opkg 系统清理完成"

    elif command -v pkg &>/dev/null; then
        log_info "使用 pkg 进行系统清理"
        log_info "清理未使用的依赖"
        pkg autoremove -y
        log_info "清理包管理器缓存"
        pkg clean -y
        log_info "删除系统日志"
        rm -rf /var/log/*
        log_info "删除临时文件"
        rm -rf /tmp/*
        log_ok "pkg 系统清理完成"

    else
        log_error "未知的包管理器!"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
        return
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

bbr_on() {

    cat >/etc/sysctl.conf <<EOF
net.ipv4.tcp_congestion_control=bbr
EOF
    sysctl -p

}

set_dns() {

    ip_address

    chattr -i /etc/resolv.conf
    rm /etc/resolv.conf
    touch /etc/resolv.conf

    if [ -n "$ipv4_address" ]; then
        echo "nameserver $dns1_ipv4" >>/etc/resolv.conf
        echo "nameserver $dns2_ipv4" >>/etc/resolv.conf
    fi

    if [ -n "$ipv6_address" ]; then
        echo "nameserver $dns1_ipv6" >>/etc/resolv.conf
        echo "nameserver $dns2_ipv6" >>/etc/resolv.conf
    fi

    chattr +i /etc/resolv.conf

}

