        sed -i '/^PS1=/d' ~/.bashrc
        echo "${bianse}" >>~/.bashrc
    else
        sed -i '/^PS1=/d' ~/.profile
        echo "${bianse}" >>~/.profile
        # source ~/.profile
    fi
    echo -e "${gl_lv}变更完成。重新连接SSH后可查看变化！${gl_bai}"

    hash -r
    break_end

}

