# 创建备份
create_backup() {
    local TIMESTAMP=$(date +"%Y%m%d%H%M%S")

    echo -e "${gl_zi}>>> 创建备份${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "创建备份示例："
    log_info "  - 备份单个目录: /var/www"
    log_info "  - 备份多个目录: /etc /home /var/log"
    log_info "  - 直接回车将使用默认目录 (/etc /usr /home)"

    read -r -e -p "$(echo -e "${gl_bai}请输入要备份的目录 (多个目录用空格分隔，直接回车则使用默认目录) (${gl_huang}0${gl_bai}返回): ")" input

    [[ "$input" == "0" ]] && { cancel_return "上一级选单"; break; }      # break 或 continue 或 return ，视上下文而定

    # 如果用户没有输入目录，则使用默认目录
    if [[ -z "$input" ]]; then
        BACKUP_PATHS=(
            "/etc"  # 配置文件和软件包配置
            "/usr"  # 已安装的软件文件
            "/home" # 用户数据
        )
    else
        # 将用户输入的目录按空格分隔成数组
        IFS=' ' read -r -a BACKUP_PATHS <<<"$input"
    fi

    # 生成备份文件前缀
    local PREFIX=""
    for path in "${BACKUP_PATHS[@]}"; do
        # 提取目录名称并去除斜杠
        dir_name=$(basename "$path")
        PREFIX+="${dir_name}_"
    done

    # 去除最后一个下划线
    local PREFIX=${PREFIX%_}

    # 生成备份文件名
    local BACKUP_NAME="${PREFIX}_$TIMESTAMP.tar.gz"

    # 打印用户选择的目录
    log_info "您选择的备份目录为："
    for path in "${BACKUP_PATHS[@]}"; do
        echo -e "  ${gl_bai}- $path"
    done

    # 创建备份
    log_info "正在创建备份 ${gl_bufan}$BACKUP_NAME${gl_bai} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    install tar
    tar -czvf "$BACKUP_DIR/$BACKUP_NAME" "${BACKUP_PATHS[@]}"

    # 检查命令是否成功
    if [[ $? -eq 0 ]]; then
        log_ok "备份创建成功: $BACKUP_DIR/$BACKUP_NAME"
    else
        log_error "备份创建失败！"
        exit 1
    fi

    break_end
}

# 恢复备份
restore_backup() {
    echo -e "${gl_zi}>>> 恢复备份${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 显示可用的备份
    log_info "可用的备份文件："
    ls -1 "$BACKUP_DIR" | while read -r file; do
        echo -e "  ${gl_bai}- $file"
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入要恢复的备份文件名 (${gl_huang}0${gl_bai}返回): ")" BACKUP_NAME

    [[ "$BACKUP_NAME" == "0" ]] && { cancel_return "上一级选单"; break; }    # break 或 continue 或 return ，视上下文而定

    # 检查备份文件是否存在
    if [[ ! -f "$BACKUP_DIR/$BACKUP_NAME" ]]; then
        log_error "备份文件不存在！"
        exit_animation    # 即将退出动画
        return 1
    fi

    read -r -e -p "$(echo -e "${gl_bai}确认要恢复备份 ${gl_bufan}$BACKUP_NAME${gl_bai} 吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" choice
    case "$choice" in
    y | Y)
        log_info "正在恢复备份 ${gl_bufan}$BACKUP_NAME${gl_bai} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        tar -xzvf "$BACKUP_DIR/$BACKUP_NAME" -C /

        if [[ $? -eq 0 ]]; then
            log_ok "备份恢复成功！"
        else
            log_error "备份恢复失败！"
            exit_animation    # 即将退出动画
            return 1
        fi
        ;;
    *)
        log_info "已取消恢复操作"
        ;;
    esac

    break_end
}

# 列出备份
list_backups() {
    log_info "可用的备份文件："
    if [[ -d "$BACKUP_DIR" ]]; then
        local count=0
        ls -1 "$BACKUP_DIR" | while read -r file; do
            echo -e "  ${gl_bai}- $file"
            ((count++))
        done
        if [[ $count -eq 0 ]]; then
            echo -e "  ${gl_bai}暂无备份文件"
        fi
    else
        echo -e "  ${gl_bai}备份目录不存在"
    fi
}

# 删除备份
delete_backup() {
    echo -e "${gl_zi}>>> 删除备份${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 显示可用的备份
    list_backups

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入要删除的备份文件名 (${gl_huang}0${gl_bai}返回): ")" BACKUP_NAME

    [[ "$BACKUP_NAME" == "0" ]] && { cancel_return "上一级选单"; break; }    # break 或 continue 或 return ，视上下文而定

    # 检查备份文件是否存在
    if [[ ! -f "$BACKUP_DIR/$BACKUP_NAME" ]]; then
        log_error "备份文件不存在！"
        exit_animation    # 即将退出动画
        return 1
    fi

    read -r -e -p "$(echo -e "${gl_bai}确认要删除备份 ${gl_bufan}$BACKUP_NAME${gl_bai} 吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" choice
    case "$choice" in
    y | Y)
        # 删除备份
        rm -f "$BACKUP_DIR/$BACKUP_NAME"

        if [[ $? -eq 0 ]]; then
            log_ok "备份删除成功！"
        else
            log_error "备份删除失败！"
            exit_animation    # 即将退出动画
            return 1
        fi
        ;;
    0) cancel_return; return;;    # 返回到上一级菜单
    *)
        log_info "已取消删除操作"
        exit_animation    # 即将退出动画
        ;;
    esac

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 备份主菜单
linux_backup() {
    BACKUP_DIR="/backups"
    mkdir -p "$BACKUP_DIR"

    while true; do
        clear
        echo -e "${gl_zi}>>> 系统备份功能${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 显示备份文件列表
        list_backups

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}创建备份${gl_bai}"
        echo -e "${gl_bufan}2.  ${gl_bai}恢复备份${gl_bai}"
        echo -e "${gl_bufan}3.  ${gl_bai}删除备份${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
        echo -e "${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " choice

        case $choice in
        1) create_backup ;;
        2) restore_backup ;;
        3) delete_backup ;;
        0) cancel_return "系统工具"; break ;;
        00 | 000 | 0000) exit_script ;;
        *) handle_invalid_input ;;
        esac
    done
}

