# 格式化分区
format_partition() {
    echo ""
    echo -e "${gl_zi}>>> 格式化分区"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入要格式化的分区名称（例如 ${gl_huang}sda1${gl_bai})(${gl_huang}0${gl_bai}返回): ")" PARTITION
    [ "$PARTITION" = "0" ] && { cancel_return "硬盘分区管理"; return 1; }

    # 检查分区是否存在
    if ! lsblk -o NAME | grep -w "$PARTITION" >/dev/null; then
        log_error "分区不存在！"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 检查分区是否已经挂载
    if lsblk -o MOUNTPOINT | grep -w "$PARTITION" >/dev/null; then
        log_warn "分区已经挂载，请先卸载！"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 选择文件系统类型
    echo "请选择文件系统类型："
    echo -e "${gl_bufan}1. ${gl_bai}ext4"
    echo -e "${gl_bufan}2. ${gl_bai}xfs"
    echo -e "${gl_bufan}3. ${gl_bai}ntfs"
    echo -e "${gl_bufan}4. ${gl_bai}vfat"
    read -r -e -p "请输入你的选择: " FS_CHOICE

    case $FS_CHOICE in
    1) FS_TYPE="ext4" ;;
    2) FS_TYPE="xfs" ;;
    3) FS_TYPE="ntfs" ;;
    4) FS_TYPE="vfat" ;;
    *)
        log_error "无效的选择！"
        exit_animation    # 即将退出动画
        return
        ;;
    esac

    # 确认格式化
    read -r -e -p "$(echo -e "${gl_bai}确认格式化分区 ${gl_huang}/dev/$PARTITION${gl_bai} 为 ${gl_lv}$FS_TYPE ${gl_bai}吗？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai})(${gl_huang}0${gl_bai}返回): ")" CONFIRM
    [ "$CONFIRM" = "0" ] && { cancel_return "硬盘分区管理"; return 1; }

    if [ "$CONFIRM" != "y" ]; then
        log_info "操作已取消。"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 格式化分区
    echo -e "正在格式化分区 ${gl_huang}/dev/$PARTITION${gl_bai} 为 ${gl_lv}$FS_TYPE ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    mkfs.$FS_TYPE "/dev/$PARTITION"

    if cmd; then
        log_ok "分区格式化成功！"
    else
        log_error "分区格式化失败！"
    fi
    break_end
}

# 格式化硬盘
format_disk() {
    echo ""
    echo -e "${gl_zi}>>> 格式化硬盘"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 列出所有磁盘
    echo -e "${gl_bai}可用的硬盘列表："
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    lsblk -d -o NAME,SIZE,TYPE,MOUNTPOINT | grep -E "^(NAME|sd|nvme|vd)" | grep -v loop
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请输入要格式化的硬盘名称（例如 ${gl_huang}sde${gl_bai}，不含/dev/）(${gl_huang}0${gl_bai}返回): ")" DISK
    [ "$DISK" = "0" ] && { cancel_return "硬盘分区管理"; return 1; }    # break 或 continue 或 return ，视上下文而定

    # 检查硬盘是否存在
    if [ ! -b "/dev/$DISK" ]; then
        log_error "硬盘 /dev/$DISK 不存在！"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 检查是否是硬盘（不是分区）
    DISK_TYPE=$(lsblk -d -o NAME,TYPE "/dev/$DISK" 2>/dev/null | tail -1 | awk '{print $2}')
    if [ "$DISK_TYPE" != "disk" ]; then
        log_error "/dev/$DISK 不是一个硬盘，请输入硬盘名称（如 sde）！"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 显示硬盘信息
    echo ""
    echo -e "${gl_bai}硬盘信息："
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    fdisk -l "/dev/$DISK" 2>/dev/null | head -20
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 列出该硬盘的所有分区
    PARTITIONS=$(lsblk -o NAME,TYPE "/dev/$DISK" 2>/dev/null | grep "part$" | awk '{print $1}')
    MOUNTED_PARTS=""
    MOUNT_POINTS=""

    if [ -n "$PARTITIONS" ]; then
        echo -e "${gl_bai}找到以下分区："
        for part in $PARTITIONS; do
            mountpoint=$(lsblk -o NAME,MOUNTPOINT "/dev/$part" 2>/dev/null | grep "$part" | awk '{print $2}')
            if [ -n "$mountpoint" ] && [ "$mountpoint" != "" ]; then
                MOUNTED_PARTS="$MOUNTED_PARTS $part"
                MOUNT_POINTS="$MOUNT_POINTS $mountpoint"
                echo -e "  ${gl_hong}${part}${gl_bai} - 已挂载到 ${gl_huang}${mountpoint}${gl_bai}"

                # 检查是否有进程占用
                if lsof "$mountpoint" 2>/dev/null | head -5; then
                    echo -e "  ${gl_hong}警告：有进程正在使用此挂载点！${gl_bai}"
                fi
            else
                echo -e "  ${gl_lv}${part}${gl_bai} - 未挂载"
            fi
        done
    else
        echo -e "${gl_bai}该硬盘没有分区。"
    fi

    # 选择文件系统类型
    echo ""
    echo "请选择文件系统类型："
    echo -e "${gl_bufan}1. ${gl_bai}ext4 (Linux推荐)"
    echo -e "${gl_bufan}2. ${gl_bai}xfs (高性能文件系统)"
    echo -e "${gl_bufan}3. ${gl_bai}ntfs (Windows兼容)"
    echo -e "${gl_bufan}4. ${gl_bai}vfat (FAT32，通用格式)"
    echo -e "${gl_bufan}5. ${gl_bai}btrfs (高级文件系统)"
    read -r -e -p "请输入你的选择 [1-5]: " FS_CHOICE

    case $FS_CHOICE in
    1)
        FS_TYPE="ext4"
        FS_DESC="Linux ext4 文件系统"
        ;;
    2)
        FS_TYPE="xfs"
        FS_DESC="XFS 高性能文件系统"
        ;;
    3)
        FS_TYPE="ntfs"
        FS_DESC="NTFS (Windows兼容)"
        ;;
    4)
        FS_TYPE="vfat"
        FS_DESC="FAT32 (通用格式)"
        ;;
    5)
        FS_TYPE="btrfs"
        FS_DESC="Btrfs 高级文件系统"
        ;;
    *)
        log_error "无效的选择！"
        return
        ;;
    esac

    # 分区表类型
    echo ""
    echo "请选择分区表类型："
    echo -e "${gl_bufan}1. ${gl_bai}GPT (推荐，支持2TB以上硬盘)"
    echo -e "${gl_bufan}2. ${gl_bai}MBR (传统BIOS引导)"
    read -r -e -p "请输入你的选择 [1-2]: " TABLE_CHOICE

    case $TABLE_CHOICE in
    1) TABLE_TYPE="gpt" ;;
    2) TABLE_TYPE="msdos" ;;
    *)
        log_error "无效的选择！"
        exit_animation    # 即将退出动画
        return
        ;;
    esac

    # 确认操作
    echo ""
    echo -e "${gl_hong}警告：此操作将销毁硬盘 /dev/$DISK 上的所有数据！${gl_bai}"
    echo -e "将执行以下操作："
    echo -e "  1. 卸载所有已挂载的分区"
    echo -e "  2. 删除所有现有分区"
    echo -e "  3. 创建新的 $TABLE_TYPE 分区表"
    echo -e "  4. 创建单个分区占用整个硬盘"
    echo -e "  5. 格式化为 $FS_DESC"

    if [ -n "$MOUNTED_PARTS" ]; then
        echo -e "${gl_hong}注意：以下分区将被卸载：$MOUNTED_PARTS${gl_bai}"
    fi

    read -r -e -p "$(echo -e "${gl_bai}确认格式化硬盘 ${gl_huang}/dev/$DISK ${gl_bai}吗？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" CONFIRM1
    [ "$CONFIRM1" = "0" ] && { cancel_return "上一级选单"; return 1; }      # break 或 continue 或 return ，视上下文而定
    if [ "$CONFIRM1" != "y" ] && [ "$CONFIRM1" != "Y" ]; then
        log_info "操作已取消。"
        exit_animation    # 即将退出动画
        return
    fi

    read -r -e -p "$(echo -e "${gl_huang}再次确认，输入 ${gl_lv}YES${gl_huang} 继续: ${gl_bai}")" CONFIRM2
     [ "$CONFIRM2" = "0" ] && { cancel_return "上一级选单"; return 1; }      # break 或 continue 或 return ，视上下文而定
    if [ "$CONFIRM2" != "YES" ]; then
        log_info "操作已取消。"
        exit_animation    # 即将退出动画
        return
    fi

    # 卸载所有已挂载的分区
    if [ -n "$MOUNTED_PARTS" ]; then
        echo ""
        echo -e "${gl_bai}步骤1: 卸载分区 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        for part in $PARTITIONS; do
            mountpoint=$(lsblk -o NAME,MOUNTPOINT "/dev/$part" 2>/dev/null | grep "$part" | awk '{print $2}')
            if [ -n "$mountpoint" ] && [ "$mountpoint" != "" ]; then
                echo -e "卸载分区 ${gl_huang}/dev/$part${gl_bai} (挂载点: $mountpoint)"

                # 先尝试正常卸载
                umount "/dev/$part" 2>/dev/null

                # 检查是否卸载成功
                if mountpoint -q "$mountpoint" 2>/dev/null; then
                    echo -e "  ${gl_hong}正常卸载失败，尝试强制卸载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    umount -f "/dev/$part" 2>/dev/null

                    if mountpoint -q "$mountpoint" 2>/dev/null; then
                        echo -e "  ${gl_hong}强制卸载失败，尝试延迟卸载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                        umount -l "/dev/$part" 2>/dev/null

                        if mountpoint -q "$mountpoint" 2>/dev/null; then
                            log_error "无法卸载 $mountpoint，可能有进程正在使用"
                            echo -e "  ${gl_bai}尝试查找占用进程 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                            lsof "$mountpoint" 2>/dev/null | head -10
                            read -r -e -p "$(echo -e "${gl_hong}是否终止占用进程？(y/N): ")" KILL_PROC
                            if [ "$KILL_PROC" = "y" ] || [ "$KILL_PROC" = "Y" ]; then
                                fuser -km "$mountpoint" 2>/dev/null
                                sleep_fractional 2
                                umount "/dev/$part" 2>/dev/null
                            else
                                log_error "无法卸载分区，操作终止。"
                                exit_animation    # 即将退出动画
                                return
                            fi
                        fi
                    fi
                fi

                echo -e "  ${gl_lv}✓ 卸载成功${gl_bai}"
            fi
        done
    fi

    # 删除所有分区并创建新分区
    echo ""
    echo -e "${gl_bai}步骤2: 创建新分区表 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 清除磁盘签名
    echo -e "正在清除磁盘签名 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    wipefs -a "/dev/$DISK" 2>/dev/null
    if [ $? -ne 0 ]; then
        echo -e "  ${gl_hong}wipefs 失败，尝试使用 dd 清除 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        dd if=/dev/zero of="/dev/$DISK" bs=1M count=100 2>/dev/null
    fi

    # 使用 parted 创建分区表和新分区
    echo -e "正在创建 $TABLE_TYPE 分区表 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if ! parted -s "/dev/$DISK" mklabel $TABLE_TYPE 2>/dev/null; then
        log_error "创建分区表失败！"
        exit_animation    # 即将退出动画
        return
    fi

    echo -e "正在创建分区 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if [ "$TABLE_TYPE" = "gpt" ]; then
        # 对于GPT，创建单个分区
        if ! parted -s "/dev/$DISK" mkpart primary 0% 100% 2>/dev/null; then
            log_error "创建分区失败！"
            exit_animation    # 即将退出动画
            return
        fi
    else
        # 对于MBR，创建主分区
        if ! parted -s "/dev/$DISK" mkpart primary 0% 100% 2>/dev/null; then
            log_error "创建分区失败！"
            exit_animation    # 即将退出动画
            return
        fi
        # 设置分区为可启动（可选）
        parted -s "/dev/$DISK" set 1 boot on 2>/dev/null
    fi

    # 让内核重新读取分区表
    echo -e "更新内核分区表 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    partprobe "/dev/$DISK" 2>/dev/null
    sleep_fractional 3

    # 获取新创建的分区
    # 尝试不同的分区命名方式
    if [ -b "/dev/${DISK}1" ]; then
        NEW_PARTITION="${DISK}1"
    elif [ -b "/dev/${DISK}p1" ]; then
        NEW_PARTITION="${DISK}p1"
    else
        # 等待一下，让系统识别新分区
        echo -e "等待系统识别新分区 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        sleep_fractional 2

        # 重新扫描SCSI总线
        echo 1 >/sys/class/block/"${DISK}"/device/rescan 2>/dev/null

        # 再次尝试
        if [ -b "/dev/${DISK}1" ]; then
            NEW_PARTITION="${DISK}1"
        elif [ -b "/dev/${DISK}p1" ]; then
            NEW_PARTITION="${DISK}p1"
        else
            # 如果没有找到分区，尝试列出所有分区
            echo -e "${gl_bai}查找新创建的分区 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            lsblk -o NAME,TYPE "/dev/$DISK" | grep "part"
            read -r -e -p "请输入新分区的名称（如 ${DISK}1）: " NEW_PARTITION
            [ "$NEW_PARTITION" = "0" ] && { cancel_return "上一级选单"; return 1; }      # break 或 continue 或 return ，视上下文而定

            if [ ! -b "/dev/$NEW_PARTITION" ]; then
                log_error "无法找到新分区，请手动检查！"
                echo -e "${gl_bai}当前硬盘分区状态："
                fdisk -l "/dev/$DISK" 2>/dev/null
                exit_animation    # 即将退出动画
                return
            fi
        fi
    fi

    echo -e "  ${gl_lv}✓ 创建分区: /dev/$NEW_PARTITION${gl_bai}"

    # 格式化分区
    echo ""
    echo -e "${gl_bai}步骤3: 格式化分区 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "正在格式化分区 ${gl_huang}/dev/$NEW_PARTITION${gl_bai} 为 ${gl_lv}$FS_TYPE${gl_bai}"

    # 根据文件系统类型使用不同的格式化命令
    FORMAT_SUCCESS=false

    case $FS_TYPE in
    ext4)
        echo -e "创建 ext4 文件系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_hong}这可能需要几分钟，请稍候 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 使用timeout命令设置超时
        if timeout 300 mkfs.ext4 -F "/dev/$NEW_PARTITION" 2>&1; then
            FORMAT_SUCCESS=true
        else
            if [ $? -eq 124 ]; then
                log_error "格式化超时！可能需要更多时间或硬盘有问题。"
            else
                log_error "格式化失败！"
            fi
        fi
        ;;

    xfs)
        echo -e "创建 XFS 文件系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_hong}这可能需要几分钟，请稍候 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        if timeout 300 mkfs.xfs -f "/dev/$NEW_PARTITION" 2>&1; then
            FORMAT_SUCCESS=true
        else
            if [ $? -eq 124 ]; then
                log_error "格式化超时！"
            else
                log_error "格式化失败！"
            fi
        fi
        ;;

    ntfs)
        echo -e "创建 NTFS 文件系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        # 检查是否有 mkfs.ntfs
        if command -v mkfs.ntfs >/dev/null 2>&1; then
            if timeout 300 mkfs.ntfs -f "/dev/$NEW_PARTITION" 2>&1; then
                FORMAT_SUCCESS=true
            else
                if [ $? -eq 124 ]; then
                    log_error "格式化超时！"
                else
                    log_error "格式化失败！"
                fi
            fi
        elif command -v mkntfs >/dev/null 2>&1; then
            if timeout 300 mkntfs -f "/dev/$NEW_PARTITION" 2>&1; then
                FORMAT_SUCCESS=true
            else
                if [ $? -eq 124 ]; then
                    log_error "格式化超时！"
                else
                    log_error "格式化失败！"
                fi
            fi
        else
            log_error "未找到 ntfs 格式化工具，请安装 ntfs-3g 或 ntfsprogs"
            echo -e "${gl_bai}可以运行以下命令安装："
            echo -e "  Ubuntu/Debian: sudo apt-get install ntfs-3g"
            echo -e "  RHEL/CentOS: sudo yum install ntfs-3g"
            exit_animation    # 即将退出动画
            return
        fi
        ;;

    vfat)
        echo -e "创建 FAT32 文件系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if timeout 60 mkfs.vfat -F 32 "/dev/$NEW_PARTITION" 2>&1; then
            FORMAT_SUCCESS=true
        else
            if [ $? -eq 124 ]; then
                log_error "格式化超时！"
            else
                log_error "格式化失败！"
            fi
        fi
        ;;

    btrfs)
        echo -e "创建 Btrfs 文件系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_hong}这可能需要几分钟，请稍候 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        if timeout 300 mkfs.btrfs -f "/dev/$NEW_PARTITION" 2>&1; then
            FORMAT_SUCCESS=true
        else
            if [ $? -eq 124 ]; then
                log_error "格式化超时！"
            else
                log_error "格式化失败！"
            fi
        fi
        ;;
    esac

    if [ "$FORMAT_SUCCESS" = true ]; then
        echo ""
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lv}✓ 硬盘格式化成功！${gl_bai}"
        echo -e "${gl_bai}硬盘: ${gl_huang}/dev/$DISK${gl_bai}"
        echo -e "${gl_bai}分区: ${gl_huang}/dev/$NEW_PARTITION${gl_bai}"
        echo -e "${gl_bai}文件系统: ${gl_lv}$FS_TYPE${gl_bai}"
        echo -e "${gl_bai}分区表: ${gl_lv}$TABLE_TYPE${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 显示新分区信息
        echo ""
        echo -e "${gl_bai}新分区信息："
        lsblk -o NAME,FSTYPE,SIZE,MOUNTPOINT,LABEL,UUID "/dev/$NEW_PARTITION" 2>/dev/null

        # 获取文件系统信息
        echo ""
        echo -e "${gl_bai}文件系统详情："
        if [ "$FS_TYPE" = "ext4" ]; then
            tune2fs -l "/dev/$NEW_PARTITION" 2>/dev/null | grep -E "Filesystem volume name|Filesystem UUID|Block count|Block size|Reserved block count"
        elif [ "$FS_TYPE" = "xfs" ]; then
            xfs_info "/dev/$NEW_PARTITION" 2>/dev/null
        fi

        # 询问是否要挂载分区
        echo ""
        read -r -e -p "$(echo -e "${gl_bai}是否要挂载新分区？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" MOUNT_CONFIRM
        if [ "$MOUNT_CONFIRM" = "y" ] || [ "$MOUNT_CONFIRM" = "Y" ]; then
            # 提供默认挂载点
            DEFAULT_MOUNT="/mnt/${NEW_PARTITION}"
            read -r -e -p "$(echo -e "${gl_bai}请输入挂载点路径（默认为 ${gl_huang}${DEFAULT_MOUNT}${gl_bai}）: ")" MOUNT_POINT
            MOUNT_POINT=${MOUNT_POINT:-$DEFAULT_MOUNT}

            if [ -n "$MOUNT_POINT" ]; then
                # 创建挂载点目录
                mkdir -p "$MOUNT_POINT" 2>/dev/null

                if [ $? -ne 0 ]; then
                    echo -e "${gl_hong}无法创建目录 $MOUNT_POINT，尝试使用sudo ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    sudo mkdir -p "$MOUNT_POINT" 2>/dev/null
                fi

                # 尝试挂载
                echo -e "挂载分区到 ${gl_huang}$MOUNT_POINT ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                mount "/dev/$NEW_PARTITION" "$MOUNT_POINT" 2>/dev/null

                if [ $? -eq 0 ]; then
                    echo -e "${gl_lv}✓ 分区已成功挂载到 $MOUNT_POINT${gl_bai}"

                    # 显示磁盘使用情况
                    echo ""
                    echo -e "${gl_bai}磁盘使用情况："
                    df -h "/dev/$NEW_PARTITION" 2>/dev/null

                    # 询问是否添加到fstab
                    read -r -e -p "$(echo -e "${gl_bai}是否添加到 /etc/fstab 实现开机自动挂载？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" FSTAB_CONFIRM
                    if [ "$FSTAB_CONFIRM" = "y" ] || [ "$FSTAB_CONFIRM" = "Y" ]; then
                        # 获取分区的UUID
                        UUID=$(blkid -s UUID -o value "/dev/$NEW_PARTITION" 2>/dev/null)
                        if [ -n "$UUID" ]; then
                            # 备份fstab
                            cp /etc/fstab "/etc/fstab.backup.$(date +%Y%m%d%H%M%S)" 2>/dev/null

                            # 添加到fstab
                            echo "# /dev/$NEW_PARTITION $(date)" | sudo tee -a /etc/fstab >/dev/null
                            echo "UUID=$UUID $MOUNT_POINT $FS_TYPE defaults 0 2" | sudo tee -a /etc/fstab >/dev/null
                            echo -e "${gl_lv}✓ 已添加到 /etc/fstab${gl_bai}"
                        else
                            echo -e "${gl_hong}警告：无法获取分区UUID，已使用设备路径代替${gl_bai}"
                            echo "# /dev/$NEW_PARTITION $(date)" | sudo tee -a /etc/fstab >/dev/null
                            echo "/dev/$NEW_PARTITION $MOUNT_POINT $FS_TYPE defaults 0 2" | sudo tee -a /etc/fstab >/dev/null
                            echo -e "${gl_lv}✓ 已添加到 /etc/fstab${gl_bai}"
                        fi
                    fi
                else
                    log_error "挂载失败，请检查！"
                    echo -e "${gl_bai}尝试使用sudo挂载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    sudo mount "/dev/$NEW_PARTITION" "$MOUNT_POINT" 2>/dev/null
                    if [ $? -eq 0 ]; then
                        echo -e "${gl_lv}✓ 分区已成功挂载到 $MOUNT_POINT${gl_bai}"
                    else
                        echo -e "${gl_hong}挂载失败，请手动挂载：${gl_bai}"
                        echo -e "  sudo mount /dev/$NEW_PARTITION $MOUNT_POINT"
                    fi
                fi
            fi
        fi
    else
        log_error "格式化失败！"
        echo -e "${gl_bai}尝试检查硬盘状态 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        smartctl -H "/dev/$DISK" 2>/dev/null | grep -i "test" || echo "无法检查硬盘健康状况"
    fi
    break_end
}



# 添加到fstab实现开机自动挂载
add_to_fstab() {
    echo ""
    echo -e "${gl_zi}>>> 添加到开机自动挂载"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    # 读取要添加的分区
    read -r -e -p "$(echo -e "${gl_bai}请输入分区名称（例如 ${gl_huang}sda1${gl_bai}）(${gl_huang}0 ${gl_bai}返回): ")" PARTITION

    [ "$PARTITION" = "0" ] && { cancel_return "硬盘分区管理"; return 1; }   # break 或 continue 或 return ，视上下文而定

    # 检查分区是否存在
    if [ ! -b "/dev/$PARTITION" ]; then
        log_error "分区 /dev/$PARTITION 不存在！"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 检查分区是否已挂载
    MOUNT_POINT=$(findmnt -n -o TARGET "/dev/$PARTITION" 2>/dev/null)
    if [ -z "$MOUNT_POINT" ]; then
        read -r -e -p "$(echo -e "${gl_bai}分区未挂载，请输入挂载点路径: ")" MOUNT_POINT
        if [ -z "$MOUNT_POINT" ]; then
            log_error "挂载点不能为空！"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi

        # 创建挂载点目录
        mkdir -p "$MOUNT_POINT" 2>/dev/null

        # 尝试挂载
        echo -e "正在挂载分区 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        mount "/dev/$PARTITION" "$MOUNT_POINT" 2>/dev/null
        if [ $? -ne 0 ]; then
            log_error "挂载失败，请检查分区状态！"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi
    fi

    # 获取分区信息
    UUID=$(blkid -s UUID -o value "/dev/$PARTITION" 2>/dev/null)
    FSTYPE=$(blkid -s TYPE -o value "/dev/$PARTITION" 2>/dev/null | tr -d '"')

    if [ -z "$UUID" ] || [ -z "$FSTYPE" ]; then
        log_error "无法获取分区UUID或文件系统类型！"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    echo -e "${gl_bai}分区信息："
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "设备: ${gl_huang}/dev/$PARTITION${gl_bai}"
    echo -e "UUID: ${gl_lv}$UUID${gl_bai}"
    echo -e "文件系统: ${gl_lv}$FSTYPE${gl_bai}"
    echo -e "挂载点: ${gl_huang}$MOUNT_POINT${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 选择挂载选项
    echo -e ""
    echo -e "${gl_huang}>>> 挂载选项：${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bufan}1. ${gl_bai}默认选项 (defaults)"
    echo -e "${gl_bufan}2. ${gl_bai}读写选项 (rw,defaults)"
    echo -e "${gl_bufan}3. ${gl_bai}用户可读写 (users,rw,defaults)"
    echo -e "${gl_bufan}4. ${gl_bai}自定义选项"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "请输入你的选择: " OPT_CHOICE

    case $OPT_CHOICE in
    1) MOUNT_OPTS="defaults" ;;
    2) MOUNT_OPTS="rw,defaults" ;;
    3) MOUNT_OPTS="users,rw,defaults" ;;
    4)
        read -r -e -p "请输入自定义选项: " MOUNT_OPTS
        if [ -z "$MOUNT_OPTS" ]; then
            MOUNT_OPTS="defaults"
        fi
        ;;
    0) cancel_return "硬盘分区管理" ; return 1 ;;   # break 或 continue 或 return ，视上下文而定
    *) MOUNT_OPTS="defaults" ;;
    esac

    # 确认添加
    echo ""
    echo -e "${gl_hong}将要添加到 /etc/fstab 的内容："
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "UUID=$UUID  $MOUNT_POINT  $FSTYPE  $MOUNT_OPTS  0  2"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}确认添加到 /etc/fstab 吗？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" CONFIRM
    if [ "$CONFIRM" != "y" ] && [ "$CONFIRM" != "Y" ]; then
        log_info "操作已取消。"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 备份原fstab文件
    FSTAB_BACKUP="/etc/fstab.backup.$(date +%Y%m%d%H%M%S)"
    cp /etc/fstab "$FSTAB_BACKUP"
    echo -e "${gl_bai}已备份 /etc/fstab 到 $FSTAB_BACKUP"

    # 添加注释和条目
    echo "" >>/etc/fstab
    echo "# Added by disk_manager script on $(date)" >>/etc/fstab
    echo "UUID=$UUID  $MOUNT_POINT  $FSTYPE  $MOUNT_OPTS  0  2" >>/etc/fstab

    if [ $? -eq 0 ]; then
        log_ok "已成功添加到 /etc/fstab！"

        # 测试挂载
        echo -e "${gl_bai}测试挂载配置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        mount -a 2>/dev/null
        if [ $? -eq 0 ]; then
            log_ok "fstab配置测试通过！"
        else
            log_warn "fstab配置测试失败，请检查配置！"
        fi
    else
        log_error "添加失败，请检查权限！"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 编辑fstab文件
disk_edit_fstab() {
    install nano
    root_use
    nano /etc/fstab

    echo -e ""
    echo -e "${gl_bai}检测到 ${gl_huang}/etc/fstab ${gl_bai}文件已被修改。"

    while true; do
        read -r -e -p "$(echo -e "${gl_bai}是否应用更改？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" choice
        [ "$choice" = "0" ] && { cancel_return "硬盘分区管理"; return; }   # break 或 continue 或 return ，视上下文而定

        case "$choice" in
        y | Y)
            echo -e "正在检查 fstab 语法 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            if sudo mount -a --fake; then
                echo -e "${gl_lv}语法检查通过。${gl_bai}"
                echo -e "${gl_bai}正在应用更改 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                if sudo mount -a; then
                    echo -e "${gl_lv}✓ fstab 更改已成功应用。${gl_bai}"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                else
                    echo -e "${gl_huang}✗ 应用更改时出错。${gl_bai}"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                fi
            else
                echo -e "${gl_hong}✗ fstab 语法检查失败。${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
            fi
            break
            ;;
        n | N)
            echo -e ""
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_lv}已跳过应用更改。${gl_bai}"
            exit_animation    # 即将退出动画
            break
            ;;
        *)
            echo "无效输入，请输入 y 或 n。"
            ;;
        esac
    done
}

# 主菜单
linux_disk_manager() {
    local menu_name="${1:-上一级选单}"
    while true; do
        clear
        echo -e "${gl_zi}>>> 硬盘分区管理工具${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        list_beautify_disk_simple
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}挂载分区             ${gl_bufan}2.  ${gl_bai}卸载分区"
        echo -e "${gl_bufan}3.  ${gl_bai}挂载Video分区        ${gl_bufan}4.  ${gl_bai}卸载Video分区"
        echo -e "${gl_bufan}5.  ${gl_bai}挂载USB分区          ${gl_bufan}6.  ${gl_bai}卸载USB分区"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}7.  ${gl_bai}格式化分区           ${gl_bufan}8.  ${gl_bai}格式化硬盘"
        echo -e "${gl_bufan}9.  ${gl_bai}查看已挂载分区       ${gl_bufan}10. ${gl_bai}检查分区状态"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}11. ${gl_bai}添加到自动挂载       ${gl_bufan}12. ${gl_bai}编辑fstab文件"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单       ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " choice
        case $choice in
        1)  mount_partition ;;                                  # 挂载分区 
        2)  unmount_partition ;;                                # 卸载分区
        3)  mount_fnos_partition ;;                             # 挂载Video分区
        4)  unmount_by_path "/vol2/1000/mydisk/Video" ;;        # 卸载Video分区
        5)  mount_usb_partition ;;                              # 挂载USB分区 
        6)  unmount_by_path "/vol2/1000/mydisk/USB" ;;          # 卸载USB分区
        7)  format_partition ;;                                 # 格式化分区
        8)  format_disk ;;                                      # 格式化硬盘
        9)  list_mounted_partitions ;;                          # 查看已挂载分区
        10) check_partition ;;                                  # 检查分区状态
        11) add_to_fstab ;;                                     # 添加到自动挂载
        12) disk_edit_fstab ;;                                  # 编辑fstab文件
        0)  cancel_return "$menu_name"; break ;;                # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;                         # 感谢使用，再见！
        *) handle_invalid_input ;;                              # 无效的输入,请重新输入!
        esac
    done
}

# 显示任务列表
list_tasks() {
    echo "已保存的远程同步任务:"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if [[ ! -f "$CONFIG_FILE" ]]; then
        echo -e "${gl_huang}配置文件不存在，暂无同步任务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        return 0
    fi

    if [[ ! -s "$CONFIG_FILE" ]]; then
        echo -e "${gl_huang}暂无同步任务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        return 0
    fi

    local line_num=1
    while IFS='|' read -r name local_path remote remote_path port options auth_method password_or_key; do
        # 格式化输出：编号、任务名称(黄)、本地目录(黄)、远程地址(蓝)、远程目录(绿)
        printf "${gl_bufan}%3d. ${gl_bai}- ${gl_zi}%-10s${gl_bai} ( ${gl_huang}%s${gl_bai} -> ${gl_tian}%s${gl_bai}:${gl_lv}%s${gl_bai} )\n" \
            "$line_num" "$name" "$local_path" "$remote" "$remote_path"
        ((line_num++))
    done <"$CONFIG_FILE"

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
}

# 添加新任务
remote_add_task() {
    clear
    echo ""
    echo -e "${gl_huang}>>> 创建新任务 (远程同步)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo "创建新同步任务示例："
    echo -e "  ${gl_bai}- 任务名称: ${gl_huang}backup_www${gl_bai}"
    echo -e "  ${gl_bai}- 本地目录: ${gl_huang}/var/www${gl_bai}"
    echo -e "  ${gl_bai}- 远程地址: ${gl_huang}user@192.168.1.100${gl_bai}"
    echo -e "  ${gl_bai}- 远程目录: ${gl_huang}/backup/www${gl_bai}"
    echo -e "  ${gl_bai}- 端口号  : ${gl_huang}(默认 22)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "请输入任务名称 (${gl_huang}0${gl_bai}返回): ")" name
    [[ -z "$name" ]] && { cancel_empty "上一级选单"; return 1; }
    [[ "$name" == "0" ]] && { cancel_return "上一级选单"; return 1; }

    read -r -e -p "$(echo -e "请输入本地目录 (${gl_huang}0${gl_bai}返回): ")" local_path
    [[ -z "$local_path" ]] && { cancel_empty "上一级选单"; return 1; }
    [[ "$local_path" == "0" ]] && { cancel_return "上一级选单"; return 1; }

    read -r -e -p "$(echo -e "请输入远程用户@IP (${gl_huang}0${gl_bai}返回): ")" remote
    [[ -z "$remote" ]] && { cancel_empty "上一级选单"; return 1; }
    [[ "$remote" == "0" ]] && { cancel_return "上一级选单"; return 1; }

    read -r -e -p "$(echo -e "请输入远程目录 (${gl_huang}0${gl_bai}返回): ")" remote_path
    [[ -z "$remote_path" ]] && { cancel_empty "上一级选单"; return 1; }
    [[ "$remote_path" == "0" ]] && { cancel_return "上一级选单"; return 1; }

    read -r -e -p "$(echo -e "请输入 SSH 端口 (默认 22, ${gl_huang}0${gl_bai}返回): ")" port
    [[ "$port" == "0" ]] && { cancel_return "上一级选单"; return 1; }  # break 或 continue 或 return ，视上下文而定
    port=${port:-22}

    # 规范化目录路径，确保以斜杠结尾
    local_path="${local_path%/}/"
    remote_path="${remote_path%/}/"

    echo ""
    echo -e "${gl_huang}>>> 请选择身份验证方式${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bufan}1. ${gl_bai}密码"
    echo -e "${gl_bufan}2. ${gl_bai}密钥"
    echo -e "${gl_bufan}0. ${gl_bai}返回"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "请输入你的选择: " auth_choice
    [[ -z "$auth_choice" ]] && { cancel_empty "上一级选单"; continue; }          # break 或 continue 或 return ，视上下文而定
    [[ "$auth_choice" == "0" ]] && { cancel_return "上一级选单"; continue; }     # break 或 continue 或 return ，视上下文而定

    case $auth_choice in
    1)
        read -r -s -p "请输入密码 (输入0并回车可返回): " password_or_key
        echo # 换行
        if [[ "$password_or_key" == "0" ]]; then return; fi
        auth_method="password"
        ;;
    2)
        echo "请粘贴密钥内容 (粘贴完成后按两次回车，输入0并回车可返回)："
        # 先读第一行，检查是否为0
        IFS= read -r first_line
        if [[ "$first_line" == "0" ]]; then return; fi

        local password_or_key="$first_line"$'\n'
        while IFS= read -r line; do
            # 如果输入为空行且密钥内容已经包含了开头，则结束输入
            if [[ -z "$line" && "$password_or_key" == *"-----BEGIN"* ]]; then
                break
            fi
            # 如果是第一行或已经开始输入密钥内容，则继续添加
            if [[ -n "$line" || "$password_or_key" == *"-----BEGIN"* ]]; then
                password_or_key+="${line}"$'\n'
            fi
        done

        # 检查是否是密钥内容
        if [[ "$password_or_key" == *"-----BEGIN"* && "$password_or_key" == *"PRIVATE KEY-----"* ]]; then
            local key_file="$KEY_DIR/${name}_sync.key"
            echo -n "$password_or_key" >"$key_file"
            chmod 600 "$key_file"
            password_or_key="$key_file"
            auth_method="key"
        else
            echo -e "${gl_hong}无效的密钥内容！${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi
        ;;
    *)
        echo -e "${gl_hong}无效的选择！${gl_bai}"
        exit_animation    # 即将退出动画
        return
        ;;
    esac

    echo ""
    echo -e "${gl_huang}>>> 请选择同步模式${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bufan}1. ${gl_bai}标准模式 (-avz)"
    echo -e "${gl_bufan}2. ${gl_bai}删除目标文件 (-avz --progress --delete-delay)"
    echo -e "${gl_bufan}0. ${gl_bai}返回"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "请输入你的选择: " mode
    if [[ "$mode" == "0" ]]; then return; fi
    case $mode in
    1) options="-avz" ;;
    2) options="-avz --progress --delete-delay" ;;
    *)
        echo "无效选择，使用默认 -avz"
        exit_animation    # 即将退出动画
        options="-avz"
        ;;
    esac

    echo "$name|$local_path|$remote|$remote_path|$port|$options|$auth_method|$password_or_key" >>"$CONFIG_FILE"

    echo -e "${gl_lv}任务已保存!${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 删除任务
remote_delete_task() {
    echo ""
    echo -e "${gl_zi}>>> 删除远程同步任务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入要删除的任务编号(${gl_huang}0${gl_bai}返回): ")" num

    [ "$num" = "0" ] && { cancel_return "Rsync远程同步工具"; return 1; }    # break 或 continue 或 return ，视上下文而定
    [ -z "$num" ] && { cancel_empty "上一级选单"; return 1; }                            # break 或 continue 或 return ，视上下文而定

    local task
    task=$(sed -n "${num}p" "$CONFIG_FILE")
    if [[ -z "$task" ]]; then
        echo -e "${gl_hong}错误：未找到对应的任务。${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    IFS='|' read -r -r name local_path remote remote_path port options auth_method password_or_key <<<"$task"

    # 如果任务使用的是密钥文件，则删除该密钥文件
    if [[ "$auth_method" == "key" && "$password_or_key" == "$KEY_DIR"* ]]; then
        rm -f "$password_or_key"
    fi

    sed -i "${num}d" "$CONFIG_FILE"
    echo -e "${gl_lv}任务已删除!${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

remote_run_task() {
    echo ""
    echo -e "${gl_zi}>>> 执行同步任务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    CONFIG_FILE="$HOME/.remote_rsync_tasks"
    CRON_FILE="$HOME/.remote_rsync_cron"

    # 解析参数
    local direction="push" # 默认是推送到远端
    local num

    if [[ "$1" == "push" || "$1" == "pull" ]]; then
        direction="$1"
        num="$2"
    else
        num="$1"
    fi

    # 如果没有传入任务编号，提示用户输入
    read -r -e -p "$(echo -e "${gl_bai}请输入要执行的任务编号(${gl_huang}0${gl_bai}返回): ")" num

    [ "$num" = "0" ] && { cancel_return "Rsync远程同步工具"; return 1; }    # break 或 continue 或 return ，视上下文而定
    [ -z "$num" ] && { cancel_empty "上一级选单"; return 1; }                            # break 或 continue 或 return ，视上下文而定

    local task=$(sed -n "${num}p" "$CONFIG_FILE")
    if [[ -z "$task" ]]; then
        echo -e "${gl_hong}错误: 未找到该任务!${gl_bai}"
        return
    fi

    IFS='|' read -r name local_path remote remote_path port options auth_method password_or_key <<<"$task"

    # 根据同步方向调整源和目标路径
    if [[ "$direction" == "pull" ]]; then
        echo -e ""
        echo -e "${gl_zi}>>> 正在拉取同步到本地: ${gl_huang}$remote:$remote_path ${gl_bai}-> ${gl_lv}$local_path ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        source="$remote:$remote_path" # 远程:远程路径
        destination="$local_path"     # 本地路径
    else
        echo -e ""
        echo -e "${gl_zi}>>> 正在推送同步到远端: ${gl_huang}$local_path ${gl_bai}-> ${gl_lv}$remote:$remote_path ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        source="$local_path"
        destination="$remote:$remote_path"
    fi

    # 添加 SSH 连接通用参数
    local ssh_options="-p $port -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null"

    if [[ "$auth_method" == "password" ]]; then
        if ! command -v sshpass &>/dev/null; then
            echo -e "${gl_hong}错误：未安装 ${gl_haung}sshpass${gl_hong}，请先安装 ${gl_haung}sshpass${gl_hong}。${gl_bai}"
            echo "安装方法："
            echo -e "  - ${gl_haung}Ubuntu/Debian: ${gl_lv}apt install sshpass${gl_bai}"
            echo -e "  - ${gl_haung}CentOS/RHEL: ${gl_lv}yum install sshpass${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi
        sshpass -p "$password_or_key" rsync $options -e "ssh $ssh_options" "$source" "$destination"
    else
        # 检查密钥文件是否存在和权限是否正确
        if [[ ! -f "$password_or_key" ]]; then
            echo -e "${gl_hong}错误：密钥文件不存在：${gl_huang}$password_or_key${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi

        if [[ "$(stat -c %a "$password_or_key")" != "600" ]]; then
            echo -e "${gl_huang}警告：密钥文件权限不正确，正在修复 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            chmod 600 "$password_or_key"
        fi

        rsync $options -e "ssh -i $password_or_key $ssh_options" "$source" "$destination"
    fi

    if [[ $? -eq 0 ]]; then
        echo -e "${gl_lv}同步完成!${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    else
        echo -e ""
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_hong}同步失败! 请检查以下内容：${gl_bai}"
        echo -e "${gl_bufan}1. ${gl_bai}网络连接是否正常"
        echo -e "${gl_bufan}2. ${gl_bai}远程主机是否可访问"
        echo -e "${gl_bufan}3. ${gl_bai}认证信息是否正确"
        echo -e "${gl_bufan}4. ${gl_bai}本地和远程目录是否有正确的访问权限"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    fi
}

# 创建定时任务
remote_schedule_task() {
    echo -e ""
    echo -e "${gl_zi}>>> 创建远程定时任务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入要定时同步的任务编号(${gl_huang}0${gl_bai}返回): ")" num

    [ "$num" = "0" ] && { cancel_return "Rsync远程同步工具"; return 1; }    # break 或 continue 或 return ，视上下文而定
    [ -z "$num" ] && { cancel_empty "上一级选单"; return 1; }                            # break 或 continue 或 return ，视上下文而定

    if ! [[ "$num" =~ ^[0-9]+$ ]]; then
        echo "错误: 请输入有效的任务编号！"
        exit_animation    # 即将退出动画
        return
    fi

    # 从配置文件中获取任务名称
    local task_name=""
    if [[ -f "$CONFIG_FILE" ]]; then
        task_name=$(sed -n "${num}p" "$CONFIG_FILE" 2>/dev/null | cut -d'|' -f1)
    fi
    
    if [[ -z "$task_name" ]]; then
        echo -e "${gl_hong}错误: 未找到编号为 ${gl_huang}$num ${gl_hong}的任务！${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    echo ""
    echo -e "${gl_huang}>>> 请选择定时执行间隔${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bufan}1. ${gl_bai}每小时执行一次"
    echo -e "${gl_bufan}2. ${gl_bai}每天执行一次"
    echo -e "${gl_bufan}3. ${gl_bai}每周执行一次"
    echo -e "${gl_bufan}4. ${gl_bai}每月执行一次"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "请输入你的选项: " interval

    local random_minute
    random_minute=$(shuf -i 0-59 -n 1) # 生成 0-59 之间的随机分钟数
    local cron_time=""
    case "$interval" in
    1) cron_time="$random_minute * * * *" ;; # 每小时，随机分钟执行
    2) cron_time="$random_minute 0 * * *" ;; # 每天，随机分钟执行
    3) cron_time="$random_minute 0 * * 1" ;; # 每周，随机分钟执行
    4) cron_time="$random_minute 4 1 * *" ;; # 每月1号凌晨4点，随机分钟执行
    *)
        echo "错误: 请输入有效的选项！"
        exit_animation    # 即将退出动画
        return
        ;;
    esac

    local cron_job="$cron_time m remote_rsync_run $num"

    # 检查是否已存在相同任务
    if crontab -l | grep -q "m remote_rsync_run $num"; then
        echo -e "${gl_hong}错误: 该任务的定时同步已存在！${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 创建到用户的 crontab
    (
        crontab -l 2>/dev/null
        echo "# 远程Rsync定时任务: $task_name"
        echo "$cron_job"
        echo ""
    ) | crontab -
    echo -e "${gl_lv}✓ 定时任务已创建：${gl_huang}$cron_job${gl_bai}"
    echo -e "${gl_bai}任务名称: ${gl_huang}$task_name${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 查看定时任务 - 增强版（显示详细信息）
view_tasks() {
    echo "当前的定时任务:"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查是否有定时任务
    if ! crontab -l >/dev/null 2>&1; then
        echo -e "${gl_huang}当前用户暂无定时任务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        return 0
    fi

    # 获取定时任务并过滤出包含"m remote_rsync_run"的任务
    local crontab_content
    crontab_content=$(crontab -l 2>/dev/null)
    local task_count=0

    while IFS= read -r line; do
        # 跳过空行
        [[ -z "$line" ]] && continue

        # 检查是否是rsync定时任务（包含"m remote_rsync_run"）
        if [[ "$line" == *"m remote_rsync_run"* ]]; then
            ((task_count++))
            # 提取任务编号
            local task_num=$(echo "$line" | grep -oE "m remote_rsync_run [0-9]+" | awk '{print $3}')

            # 尝试从注释行获取任务名称
            local task_name=""
            local local_path=""
            local remote=""
            local remote_path=""
            local options=""
            
            # 查找前一行注释（如果有）
            local prev_line=$(echo "$crontab_content" | sed -n "/^#.*远程Rsync定时任务:.*任务编号: $task_num\$/p" | head -1)
            if [[ -n "$prev_line" ]]; then
                # 从注释中提取任务名称
                task_name=$(echo "$prev_line" | sed -n 's/^#.*远程Rsync定时任务: \(.*\) (任务编号: [0-9]*)$/\1/p')
            fi
            
            # 如果注释中没有找到，尝试从配置文件中获取
            if [[ -z "$task_name" ]] && [[ -n "$task_num" ]] && [[ -f "$CONFIG_FILE" ]]; then
                local task_line=$(sed -n "${task_num}p" "$CONFIG_FILE" 2>/dev/null)
                if [[ -n "$task_line" ]]; then
                    IFS='|' read -r task_name local_path remote remote_path port options auth_method password_or_key <<<"$task_line"
                fi
            fi

            # 格式化输出详细信息
            echo -e "${gl_bufan}${task_count}. ${gl_bai}Cron表达式: ${gl_zi}${line}${gl_bai}"
            if [[ -n "$task_name" ]]; then
                echo -e "   任务名称: ${gl_huang}${task_name}${gl_bai}"
                echo -e "   任务编号: ${gl_huang}${task_num}${gl_bai}"
                if [[ -n "$local_path" ]]; then
                    echo -e "   本地目录: ${gl_huang}${local_path}${gl_bai}"
                    echo -e "   远程地址: ${gl_lv}${remote}:${remote_path}${gl_bai}"
                    echo -e "   端口号:   ${gl_bai}${port}${gl_bai}"
                    echo -e "   同步选项: ${gl_zi}${options}${gl_bai}"
                    echo -e "   认证方式: ${gl_huang}${auth_method}${gl_bai}"
                fi
            else
                echo -e "   ${gl_hong}警告: 无法获取任务详细信息（可能对应的同步任务已被删除）${gl_bai}"
            fi
            echo ""
        fi
    done <<<"$crontab_content"

    if [[ $task_count -eq 0 ]]; then
        echo -e "${gl_huang}暂无定时同步任务${gl_bai}"
    else
        echo -e "${gl_bai}共找到 ${gl_huang}${task_count} ${gl_bai}个定时任务${gl_bai}"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
}

# 删除定时任务
remote_delete_task_schedule() {
    echo ""
    echo -e "${gl_zi}>>> 删除定时任务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 步骤2：检查是否有定时任务
    local crontab_content
    crontab_content=$(crontab -l 2>/dev/null)
    
    if [[ $? -ne 0 ]] || [[ -z "$crontab_content" ]]; then
        echo -e "${gl_huang}当前用户暂无定时任务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 0
    fi
    
    # 统计远程同步任务数量
    local remote_task_count=0
    while IFS= read -r line; do
        [[ -z "$line" ]] && continue
        if [[ "$line" == *"m remote_rsync_run"* ]]; then
            ((remote_task_count++))
        fi
    done <<<"$crontab_content"
    
    if [[ $remote_task_count -eq 0 ]]; then
        echo -e "${gl_huang}暂无远程同步定时任务，无需删除。${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 0
    fi
    
    # 步骤3：有任务时，提示用户输入要删除的编号
    echo -e "${gl_bai}提示: 请输入要删除的任务在列表中的序号 (1~${remote_task_count})${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入要删除的任务编号(${gl_huang}0${gl_bai}返回): ")" num

    [ "$num" = "0" ] && { cancel_return "Rsync远程同步工具"; return 1; }    # break 或 continue 或 return ，视上下文而定
    [ -z "$num" ] && { cancel_empty "上一级选单"; return 1; }                            # break 或 continue 或 return ，视上下文而定

    if ! [[ "$num" =~ ^[0-9]+$ ]]; then
        echo "错误: 请输入有效的任务编号！"
        exit_animation    # 即将退出动画
        return
    fi

    # 步骤4：验证输入的任务编号是否在有效范围内
    if [[ "$num" -lt 1 ]] || [[ "$num" -gt "$remote_task_count" ]]; then
        echo -e "${gl_hong}错误: 请输入有效的任务编号 (1~${remote_task_count})！${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 步骤5：找到对应的cron行
    local current_task=0
    local target_line=""
    local target_comment_line=""
    local line_num=0
    
    # 读取crontab内容，找到第num个远程同步任务
    while IFS= read -r line; do
        ((line_num++))
        [[ -z "$line" ]] && continue
        
        if [[ "$line" == *"m remote_rsync_run"* ]]; then
            ((current_task++))
            if [[ $current_task -eq $num ]]; then
                target_line="$line"
                # 检查前一行是否是注释
                if [[ $line_num -gt 1 ]]; then
                    local prev_line_num=$((line_num - 1))
                    local prev_line=$(echo "$crontab_content" | sed -n "${prev_line_num}p")
                    if [[ "$prev_line" =~ ^#.*远程Rsync定时任务 ]]; then
                        target_comment_line="$prev_line"
                    fi
                fi
                break
            fi
        fi
    done <<<"$crontab_content"

    if [[ -z "$target_line" ]]; then
        echo -e "${gl_hong}错误: 无法找到对应的定时任务${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 步骤6：显示要删除的任务并确认
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}即将删除的任务:${gl_bai}"
    if [[ -n "$target_comment_line" ]]; then
        echo -e "  ${gl_huang}注释行: $target_comment_line${gl_bai}"
    fi
    echo -e "  ${gl_zi}任务行: $target_line${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    read -r -e -p "$(echo -e "${gl_bai}确认删除吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    [ "$confirm" = "0" ] && { cancel_return "上一级选单"; return 1; }      # break 或 continue 或 return ，视上下文而定
    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
        echo -e "${gl_huang}取消删除操作${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 步骤7：执行删除
    # 创建临时文件
    local temp_file
    temp_file=$(mktemp)
    
    # 从crontab中删除目标行
    if [[ -n "$target_comment_line" ]]; then
        # 删除注释行和任务行
        crontab -l 2>/dev/null | grep -vF "$target_comment_line" | grep -vF "$target_line" > "$temp_file"
    else
        # 只删除任务行
        crontab -l 2>/dev/null | grep -vF "$target_line" > "$temp_file"
    fi
    
    # 安装新的crontab
    crontab "$temp_file"
    rm -f "$temp_file"
    
    echo -e "${gl_lv}定时任务已删除!${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 显示任务详细信息
remote_show_task_details() {
    echo ""
    echo -e "${gl_zi}>>> 查看远程任务详细信息${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    if [[ ! -f "$CONFIG_FILE" ]]; then
        echo -e "${gl_huang}配置文件不存在，暂无同步任务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 0
    fi
    
    if [[ ! -s "$CONFIG_FILE" ]]; then
        echo -e "${gl_huang}暂无同步任务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 0
    fi
    
    echo -e "${gl_bai}提示: 直接${gl_lv}回车${gl_bai}查看全部任务，输入${gl_huang}0${gl_bai}返回${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "请输入要查看的任务编号: " num

    [ "$num" = "0" ] && { cancel_return "Rsync远程同步工具"; return 1; }    # break 或 continue 或 return ，视上下文而定
    
    # 如果用户直接回车，则查看所有任务
    if [[ -z "$num" ]]; then
        echo ""
        echo -e "${gl_zi}>>> 所有同步任务详情${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        local line_num=1
        while IFS='|' read -r name local_path remote remote_path port options auth_method password_or_key; do
            echo -e "${gl_bufan}任务 #${line_num}${gl_bai}"
            echo -e "  ${gl_bai}任务名称: ${gl_zi}$name${gl_bai}"
            echo -e "  ${gl_bai}本地目录: ${gl_huang}$local_path${gl_bai}"
            echo -e "  ${gl_bai}远程地址: ${gl_tian}$remote${gl_bai}"
            echo -e "  ${gl_bai}远程目录: ${gl_lv}$remote_path${gl_bai}"
            echo -e "  ${gl_bai}SSH 端口: ${gl_bai}$port"
            echo -e "  ${gl_bai}同步选项: ${gl_zi}$options${gl_bai}"
            echo -e "  ${gl_bai}认证方式: ${gl_huang}$auth_method${gl_bai}"
            
            if [[ "$auth_method" == "password" ]]; then
                echo -e "  ${gl_bai}密码: ${gl_hong}****** (已加密)${gl_bai}"
            elif [[ "$auth_method" == "key" ]]; then
                echo -e "  ${gl_bai}密钥文件: ${gl_lv}$password_or_key${gl_bai}"
                if [[ -f "$password_or_key" ]]; then
                    local key_perms=$(stat -c "%a" "$password_or_key" 2>/dev/null)
                    echo -e "  ${gl_bai}密钥权限: ${gl_bai}${key_perms}"
                    
                    # 检查密钥权限是否安全
                    if [[ "$key_perms" != "600" ]]; then
                        echo -e "  ${gl_hong}警告: 密钥文件权限不安全!${gl_bai}"
                    fi
                else
                    echo -e "  ${gl_hong}警告: 密钥文件不存在!${gl_bai}"
                fi
            fi
            
            # 检查本地目录是否存在
            if [[ -d "$local_path" ]]; then
                local local_size=$(du -sh "$local_path" 2>/dev/null | cut -f1)
                echo -e "  ${gl_bai}本地目录大小: ${gl_bai}${local_size:-未知}"
            else
                echo -e "  ${gl_hong}警告: 本地目录不存在!${gl_bai}"
            fi
            
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            ((line_num++))
        done <"$CONFIG_FILE"
        
        echo -e "${gl_lv}共找到 $((line_num-1)) 个同步任务${gl_bai}"
        
    else
        # 显示单个任务详情
        local task=$(sed -n "${num}p" "$CONFIG_FILE" 2>/dev/null)
        if [[ -z "$task" ]]; then
            echo -e "${gl_hong}错误: 未找到任务 #$num${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi
        
        IFS='|' read -r name local_path remote remote_path port options auth_method password_or_key <<<"$task"
        
        echo ""
        echo -e "${gl_zi}>>> 任务 #$num 详情${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_bai}任务名称: ${gl_zi}$name${gl_bai}"
        echo -e "  ${gl_bai}本地目录: ${gl_huang}$local_path${gl_bai}"
        echo -e "  ${gl_bai}远程地址: ${gl_tian}$remote${gl_bai}"
        echo -e "  ${gl_bai}远程目录: ${gl_lv}$remote_path${gl_bai}"
        echo -e "  ${gl_bai}SSH 端口: ${gl_bai}$port"
        echo -e "  ${gl_bai}同步选项: ${gl_zi}$options${gl_bai}"
        echo -e "  ${gl_bai}认证方式: ${gl_huang}$auth_method${gl_bai}"
        
        if [[ "$auth_method" == "password" ]]; then
            echo -e "  ${gl_bai}密码: ${gl_hong}****** (已加密)${gl_bai}"
        elif [[ "$auth_method" == "key" ]]; then
            echo -e "  ${gl_bai}密钥文件: ${gl_lv}$password_or_key${gl_bai}"
            if [[ -f "$password_or_key" ]]; then
                local key_perms=$(stat -c "%a" "$password_or_key" 2>/dev/null)
                echo -e "  ${gl_bai}密钥权限: ${gl_bai}${key_perms}"
                
                # 检查密钥权限
                if [[ "$key_perms" != "600" ]]; then
                    echo -e "  ${gl_hong}警告: 密钥文件权限不安全! 建议执行:${gl_bai}"
                    echo -e "  ${gl_bai}chmod 600 \"$password_or_key\"${gl_bai}"
                fi
                
                # 显示密钥文件信息
                echo -e "  ${gl_bai}密钥文件信息:${gl_bai}"
                if file "$password_or_key" | grep -q "PEM RSA private key"; then
                    echo -e "  ${gl_bai}  - 类型: RSA 私钥"
                elif file "$password_or_key" | grep -q "PEM EC private key"; then
                    echo -e "  ${gl_bai}  - 类型: EC 私钥"
                elif file "$password_or_key" | grep -q "PEM DSA private key"; then
                    echo -e "  ${gl_bai}  - 类型: DSA 私钥"
                elif file "$password_or_key" | grep -q "OpenSSH private key"; then
                    echo -e "  ${gl_bai}  - 类型: OpenSSH 私钥"
                else
                    echo -e "  ${gl_bai}  - 类型: 未知"
                fi
            else
                echo -e "  ${gl_hong}错误: 密钥文件不存在!${gl_bai}"
            fi
        fi
        
        # 检查本地目录
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_bai}本地目录检查:${gl_bai}"
        if [[ -d "$local_path" ]]; then
            local local_size=$(du -sh "$local_path" 2>/dev/null | cut -f1)
            local file_count=$(find "$local_path" -type f 2>/dev/null | wc -l)
            echo -e "  ${gl_bai}  - 存在: ${gl_lv}是${gl_bai}"
            echo -e "  ${gl_bai}  - 大小: ${gl_bai}${local_size:-未知}"
            echo -e "  ${gl_bai}  - 文件数: ${gl_bai}${file_count}"
        else
            echo -e "  ${gl_bai}  - 存在: ${gl_hong}否${gl_bai}"
        fi
        
        # 测试连接
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_bai}连接测试:${gl_bai}"
        echo -e "  ${gl_bai}正在测试 SSH 连接 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        
        local ssh_test_cmd=""
        if [[ "$auth_method" == "password" ]]; then
            if command -v sshpass &>/dev/null; then
                ssh_test_cmd="sshpass -p '$password_or_key' ssh -p $port -o StrictHostKeyChecking=no -o ConnectTimeout=5 $remote 'echo connected' 2>&1"
            else
                echo -e "  ${gl_hong}  - sshpass 未安装，无法测试密码连接${gl_bai}"
            fi
        else
            ssh_test_cmd="ssh -i '$password_or_key' -p $port -o StrictHostKeyChecking=no -o ConnectTimeout=5 $remote 'echo connected' 2>&1"
        fi
        
        if [[ -n "$ssh_test_cmd" ]]; then
            local ssh_output
            ssh_output=$(eval "$ssh_test_cmd" 2>&1)
            if echo "$ssh_output" | grep -q "connected"; then
                echo -e "  ${gl_bai}  - SSH 连接: ${gl_lv}成功${gl_bai}"
            else
                echo -e "  ${gl_bai}  - SSH 连接: ${gl_hong}失败${gl_bai}"
                echo -e "  ${gl_bai}  - 错误信息: ${gl_hong}$ssh_output${gl_bai}"
            fi
        fi
        
        # 检查远程目录权限
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_bai}执行同步命令:${gl_bai}"
        if [[ "$auth_method" == "password" ]]; then
            if command -v sshpass &>/dev/null; then
                echo -e "  ${gl_bai}  - 推送到远端: ${gl_zi}sshpass -p '******' rsync $options -e \"ssh -p $port -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null\" \"$local_path\" \"$remote:$remote_path\"${gl_bai}"
                echo -e "  ${gl_bai}  - 从远端拉取: ${gl_zi}sshpass -p '******' rsync $options -e \"ssh -p $port -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null\" \"$remote:$remote_path\" \"$local_path\"${gl_bai}"
            else
                echo -e "  ${gl_hong}  - sshpass 未安装，请先安装${gl_bai}"
            fi
        else
            echo -e "  ${gl_bai}  - 推送到远端: ${gl_zi}rsync $options -e \"ssh -i '$password_or_key' -p $port -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null\" \"$local_path\" \"$remote:$remote_path\"${gl_bai}"
            echo -e "  ${gl_bai}  - 从远端拉取: ${gl_zi}rsync $options -e \"ssh -i '$password_or_key' -p $port -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null\" \"$remote:$remote_path\" \"$local_path\"${gl_bai}"
        fi
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 批量执行所有任务（推送到远端）
remote_run_all_tasks_push() {
    echo ""
    echo -e "${gl_huang}>>> 批量推送所有任务（推送到远端）${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    if [[ ! -f "$CONFIG_FILE" ]]; then
        echo -e "${gl_huang}配置文件不存在，暂无同步任务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 0
    fi
    
    if [[ ! -s "$CONFIG_FILE" ]]; then
        echo -e "${gl_huang}暂无同步任务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 0
    fi
    
    # 统计任务总数
    local total_tasks=$(wc -l <"$CONFIG_FILE")
    echo -e "${gl_bai}找到 ${gl_huang}${total_tasks} ${gl_bai}个同步任务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 确认提示
    echo -e "${gl_hong}⚠ 警告：即将批量执行所有任务，这可能会花费较长时间${gl_bai}"
    echo -e "${gl_huang}请确保网络连接稳定，且远程服务器可访问${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    read -r -e -p "$(echo -e "${gl_bai}确认执行批量推送吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
        echo -e "${gl_huang}已取消批量执行${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi
    
    echo -e "${gl_bai}开始批量执行推送任务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    local success_count=0
    local failed_count=0
    local current_task=0
    
    # 逐行读取任务配置并执行
    while IFS='|' read -r name local_path remote remote_path port options auth_method password_or_key; do
        ((current_task++))
        
        echo ""
        echo -e "${gl_bai}[${gl_lv}${current_task}${gl_bai}/${gl_huang}${total_tasks}${gl_bai}] 执行任务: ${gl_huang}${name}${gl_bai}"
        echo -e "${gl_bai}同步方向: ${gl_huang}${local_path} ${gl_hong}-> ${gl_lv}${remote}:${remote_path}${gl_bai}"
        
        # 检查本地目录是否存在
        if [[ ! -d "$local_path" ]]; then
            echo -e "${gl_hong}✗ 失败: 本地目录不存在${gl_bai}"
            ((failed_count++))
            exit_animation    # 即将退出动画
            continue
        fi
        
        # 检查sshpass是否已安装（如果需要）
        if [[ "$auth_method" == "password" ]] && ! command -v sshpass &>/dev/null; then
            echo -e "${gl_hong}✗ 失败: sshpass 未安装${gl_bai}"
            ((failed_count++))
            exit_animation    # 即将退出动画
            continue
        fi
        
        # 检查密钥文件（如果需要）
        if [[ "$auth_method" == "key" ]] && [[ ! -f "$password_or_key" ]]; then
            echo -e "${gl_hong}✗ 失败: 密钥文件不存在${gl_bai}"
            ((failed_count++))
            exit_animation    # 即将退出动画
            continue
        fi
        
        # 添加 SSH 连接通用参数
        local ssh_options="-p $port -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null"
        
        # 执行推送
        local output_file
        output_file=$(mktemp)
        local sync_result=0
        
        if [[ "$auth_method" == "password" ]]; then
            sshpass -p "$password_or_key" rsync $options -e "ssh $ssh_options" "$local_path" "$remote:$remote_path" >"$output_file" 2>&1
            sync_result=$?
        else
            # 检查密钥文件权限
            if [[ "$(stat -c %a "$password_or_key")" != "600" ]]; then
                chmod 600 "$password_or_key" 2>/dev/null
            fi
            
            rsync $options -e "ssh -i $password_or_key $ssh_options" "$local_path" "$remote:$remote_path" >"$output_file" 2>&1
            sync_result=$?
        fi
        
        # 检查执行结果
        if [[ $sync_result -eq 0 ]]; then
            echo -e "${gl_lv}✓ 推送成功${gl_bai}"
            ((success_count++))
        else
            echo -e "${gl_hong}✗ 推送失败 (错误代码: $sync_result)${gl_bai}"
            echo -e "${gl_bai}错误信息:"
            tail -5 "$output_file" 2>/dev/null || echo "无法获取错误信息"
            ((failed_count++))
        fi
        
        # 清理临时文件
        rm -f "$output_file"
        
    done <"$CONFIG_FILE"
    
    echo ""
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}批量执行完成:${gl_bai}"
    echo -e "  ${gl_lv}✓ 成功: ${success_count}${gl_bai}"
    echo -e "  ${gl_hong}✗ 失败: ${failed_count}${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    if [[ $failed_count -eq 0 ]]; then
        echo -e "${gl_lv}✓ 所有任务执行成功!${gl_bai}"
    elif [[ $success_count -eq 0 ]]; then
        echo -e "${gl_hong}✗ 所有任务执行失败!${gl_bai}"
    else
        echo -e "${gl_huang}⚠ 部分任务执行失败，请检查错误信息${gl_bai}"
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
    
    # 如果至少有一个失败，返回非0状态码
    if [[ $failed_count -gt 0 ]]; then
        return 1
    fi
    return 0
}

# 任务管理主菜单
remote_rsync_manager() {
    local menu_name="${1:-上一级选单}"
    CONFIG_FILE="$HOME/.remote_rsync_tasks"
    CRON_FILE="$HOME/.remote_rsync_cron"
    install sshpass rsync
    while true; do
        clear
        list_tasks
        echo
        view_tasks
        echo -e ""
        echo -e "${gl_zi}>>> Rsync远程同步工具${gl_bai}"
        echo "远程目录之间同步，支持增量同步，高效稳定。"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}创建新任务            ${gl_bufan}2.  ${gl_bai}查看任务详情"
        echo -e "${gl_bufan}3.  ${gl_bai}执行本地同步到远端    ${gl_bufan}4.  ${gl_bai}执行远端同步到本地"
        echo -e "${gl_bufan}5.  ${gl_bai}批量推送所有任务      ${gl_bufan}6.  ${gl_bai}删除同步任务"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}7.  ${gl_bai}创建定时任务          ${gl_bufan}8.  ${gl_bai}删除定时任务"
        echo -e "${gl_bufan}9.  ${gl_bai}编辑cron文件          ${gl_bufan}10. ${gl_bai}查看cron文件"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单        ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " choice
        case $choice in
        1)  remote_add_task ;;                      # 创建新任务
        2)  remote_show_task_details ;;             # 查看任务详情
        3)  remote_run_task push ;;                 # 执行本地同步到远端
        4)  remote_run_task pull ;;                 # 执行远端同步到本地
        5)  remote_run_all_tasks_push ;;            # 批量推送所有任务
        6)  remote_delete_task ;;                   # 删除任务
        7)  remote_schedule_task ;;                 # 创建定时任务
        8)  remote_delete_task_schedule ;;          # 删除定时任务
        9)  edit_crontab; continue ;;               # 编辑cron文件
        10) view_raw_crontab ;;                     # 查看cron文件
        0)  cancel_return "$menu_name"; break ;;    # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;             # 感谢使用，再见！
        *) handle_invalid_input ;;                  # 无效的输入,请重新输入!
        esac
    done
}

###### 修复nano
fix_nano_config() {
    local nano_version nano_vendor
    local distro_id distro_version
    local env_files_updated="0"

    echo -e ""
    echo -e "${gl_zi}开始修复 nano 配置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检测发行版
    if [ -f /etc/os-release ]; then
        . /etc/os-release
        distro_id="${ID:-unknown}"
        distro_version="${VERSION_ID:-unknown}"
        echo -e "${gl_lv}检测到系统: $PRETTY_NAME${gl_bai}"
    else
        distro_id=$(uname -s)
        distro_version=$(uname -r)
        echo -e "${gl_huang}警告: 无法检测发行版，使用通用配置${gl_bai}"
    fi

    # 获取 nano 版本信息
    if command -v nano &>/dev/null; then
        nano_version=$(nano --version 2>/dev/null | head -n1 | grep -oE '[0-9]+\.[0-9]+(\.[0-7]+)?' | head -n1)
        echo -e "${gl_lv}nano 版本: ${nano_version:-未知}${gl_bai}"
    else
        echo -e "${gl_hong}错误: nano 未安装${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 设置中文环境变量
    echo -e ""
    echo -e "${gl_huang}>>> 设置中文环境变量 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 创建所有需要的配置文件，确保它们存在
    touch ~/.profile ~/.bash_profile ~/.bashrc

    # 清理可能重复的环境变量设置
    # 从 ~/.profile 中移除旧的 nano 相关环境变量
    sed -i '/^export LANG=.*/d' ~/.profile 2>/dev/null
    sed -i '/^export LANGUAGE=.*/d' ~/.profile 2>/dev/null
    sed -i '/^export LC_ALL=.*/d' ~/.profile 2>/dev/null
    sed -i '/^# Nano.*/d' ~/.profile 2>/dev/null

    # 从 ~/.bash_profile 中移除旧的 nano 相关环境变量
    sed -i '/^export LANG=.*/d' ~/.bash_profile 2>/dev/null
    sed -i '/^export LANGUAGE=.*/d' ~/.bash_profile 2>/dev/null
    sed -i '/^export LC_ALL=.*/d' ~/.bash_profile 2>/dev/null
    sed -i '/^# Nano.*/d' ~/.bash_profile 2>/dev/null

    # 从 ~/.bashrc 中移除旧的 nano 相关环境变量
    sed -i '/^export LANG=.*/d' ~/.bashrc 2>/dev/null
    sed -i '/^export LANGUAGE=.*/d' ~/.bashrc 2>/dev/null
    sed -i '/^export LC_ALL=.*/d' ~/.bashrc 2>/dev/null
    sed -i '/^# Nano.*/d' ~/.bashrc 2>/dev/null

    # 添加新的环境变量设置
    echo -e "" >>~/.profile
    echo -e "# Nano 中文环境设置（由 fix_nano_config 添加）" >>~/.profile
    echo 'export LANG=zh_CN.UTF-8' >>~/.profile
    echo 'export LANGUAGE=zh_CN:zh' >>~/.profile
    echo 'export LC_ALL=zh_CN.UTF-8' >>~/.profile

    echo -e "" >>~/.bash_profile
    echo -e "# Nano 中文环境设置（由 fix_nano_config 添加）" >>~/.bash_profile
    echo 'export LANG=zh_CN.UTF-8' >>~/.bash_profile
    echo 'export LANGUAGE=zh_CN:zh' >>~/.bash_profile
    echo 'export LC_ALL=zh_CN.UTF-8' >>~/.bash_profile

    echo -e "" >>~/.bashrc
    echo -e "# Nano 中文环境设置（由 fix_nano_config 添加）" >>~/.bashrc
    echo 'export LANG=zh_CN.UTF-8' >>~/.bashrc
    echo 'export LANGUAGE=zh_CN:zh' >>~/.bashrc
    echo 'export LC_ALL=zh_CN.UTF-8' >>~/.bashrc

    # 确保 ~/.bashrc 在 ~/.profile 中被加载
    if ! grep -q "\. ~/.bashrc" ~/.profile 2>/dev/null && ! grep -q "source ~/.bashrc" ~/.profile 2>/dev/null; then
        echo 'if [ -n "$BASH_VERSION" ]; then' >>~/.profile
        echo '    if [ -f "$HOME/.bashrc" ]; then' >>~/.profile
        echo '        . "$HOME/.bashrc"' >>~/.profile
        echo '    fi' >>~/.profile
        echo 'fi' >>~/.profile
    fi

    # 确保 ~/.bashrc 在 ~/.bash_profile 中被加载
    if ! grep -q "\. ~/.bashrc" ~/.bash_profile 2>/dev/null && ! grep -q "source ~/.bashrc" ~/.bash_profile 2>/dev/null; then
        echo 'if [ -f ~/.bashrc ]; then' >>~/.bash_profile
        echo '    . ~/.bashrc' >>~/.bash_profile
        echo 'fi' >>~/.bash_profile
    fi

    # 设置当前 shell 的环境变量
    export LANG=zh_CN.UTF-8
    export LANGUAGE=zh_CN:zh
    export LC_ALL=zh_CN.UTF-8

    echo -e "${gl_lv}✓ 中文环境变量已写入配置文件${gl_bai}"
    echo -e "${gl_huang}注意: 需要手动执行以下命令使环境变量立即生效:${gl_bai}"
    echo -e "  ${gl_lv}source ~/.bashrc${gl_bai}"

    # 创建 nano 配置
    echo -e ""
    echo -e "${gl_huang}>>> 创建 nano 配置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 创建新的 nano 配置
    echo -e "${gl_lv}正在创建 nano 配置文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    cat >~/.nanorc <<EOF
# Nano 配置 - 自动修复版
# 生成时间: $(date +"%Y-%m-%d %H:%M:%S")
# 系统: $distro_id $distro_version
# Nano版本: $nano_version

# 关闭自动缩进（解决粘贴问题）
unset autoindent

# 基本编辑设置
set tabsize 4
set tabstospaces
set nowrap
set mouse
EOF

    # 根据 nano 版本添加兼容选项
    if [[ -n "$nano_version" ]]; then
        # 如果版本 >= 2.7.0，添加更多功能
        if [[ $(echo "$nano_version 2.7.0" | tr ' ' '\n' | sort -V | head -n1) == "2.7.0" ]]; then
            cat >>~/.nanorc <<'EOF'
# 高级功能（nano >= 2.7.0）
set linenumbers
set constantshow
set indicator
set smarthome
EOF
        else
            # 旧版本，只添加基本功能
            cat >>~/.nanorc <<'EOF'
# 基本功能（旧版 nano）
# 注释掉可能导致错误的选项
# set linenumbers
# set constantshow
# set indicator
# set smarthome
EOF
        fi
    else
        # 未知版本，尝试添加但可能会失败
        cat >>~/.nanorc <<'EOF'
# 尝试启用高级功能（如果支持）
set linenumbers
# set constantshow
# set indicator
# set smarthome
EOF
    fi

    # 通用功能设置
    cat >>~/.nanorc <<'EOF'
# 功能设置
set historylog
set backup
EOF

    # 添加语法高亮（根据发行版和文件存在性）
    add_syntax_highlight() {
        local syntax_paths=(
            "/usr/share/nano"
            "/usr/share/nano/extra"
            "/etc/nano"
            "/usr/local/share/nano"
            "/opt/nano/share/nano"
        )

        local syntax_added=0
        for path in "${syntax_paths[@]}"; do
            if [[ -d "$path" ]] && ls "$path"/*.nanorc &>/dev/null; then
                # 检查是否已包含此路径
                if ! grep -q "include.*$path" ~/.nanorc 2>/dev/null; then
                    echo "include \"$path/*.nanorc\"" >>~/.nanorc
                    echo -e "${gl_lv}已添加语法高亮: $path${gl_bai}"
                    syntax_added=$((syntax_added + 1))
                fi
            fi
        done

        if [[ $syntax_added -eq 0 ]]; then
            echo "# 未找到语法高亮文件" >>~/.nanorc
            echo -e "${gl_huang}警告: 未找到语法高亮文件${gl_bai}"
        fi
    }

    add_syntax_highlight

    # 验证配置
    echo -e ""
    echo -e "${gl_huang}>>> 验证配置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查配置语法
    if nano --rcfile=~/.nanorc --version &>/dev/null; then
        echo -e "${gl_lv}✓ 配置语法检查通过${gl_bai}"
    else
        # 如果有错误，创建最小配置
        echo -e "${gl_hong}✗ 配置有错误，创建最小配置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        cat >~/.nanorc <<'EOF'
# 最小安全配置
unset autoindent
set tabsize 4
set nowrap
set mouse
EOF
    fi

    # 显示最终配置摘要
    echo -e ""
    echo -e "${gl_huang}>>> 配置摘要:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_lv}✓ nano 配置文件已创建: ~/.nanorc${gl_bai}"
    echo -e "${gl_lv}✓ 文件大小: $(wc -l <~/.nanorc) 行${gl_bai}"

    # 清理旧的 nano 别名
    sed -i '/^# Nano 别名/d' ~/.bashrc 2>/dev/null
    sed -i '/^alias nano=/d' ~/.bashrc 2>/dev/null
    sed -i '/^alias nanopaste=/d' ~/.bashrc 2>/dev/null
    sed -i '/^alias nanoraw=/d' ~/.bashrc 2>/dev/null
    sed -i '/^# 中文环境测试命令/d' ~/.bashrc 2>/dev/null
    sed -i '/^alias nano-zh=/d' ~/.bashrc 2>/dev/null

    # 添加新的别名
    cat >>~/.bashrc <<'EOF'

# Nano 别名（由 fix_nano_config 添加）
alias nano='nano -i'  # 默认关闭自动缩进
alias nanopaste='nano -i -w'  # 适合粘贴的模式
alias nanoraw='nano -I'  # 忽略所有配置文件

# 中文环境测试命令
alias nano-zh='LANG=zh_CN.UTF-8 LANGUAGE=zh_CN:zh LC_ALL=zh_CN.UTF-8 nano'
EOF

    echo -e "${gl_lv}✓ Nano 别名已添加到 ~/.bashrc${gl_bai}"
    echo -e "${gl_lv}✓ 中文测试命令已添加：nano-zh${gl_bai}"

    echo -e ""
    echo -e "${gl_huang}>>> 修复完成 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_lv}✓ nano 配置修复完成！${gl_bai}"
    echo -e ""
    echo -e "${gl_huang}重要提示:${gl_bai}"
    echo -e "  1. ${gl_lv}请手动执行以下命令使配置立即生效:${gl_bai}"
    echo -e "     ${gl_zi}source ~/.bashrc${gl_bai}"
    echo -e "  2. 重启终端后配置将自动生效"
    echo -e "  3. 测试中文显示: ${gl_lv}nano-zh 文件名${gl_bai}"
    echo -e "  4. 测试粘贴功能: ${gl_lv}nanopaste 文件名${gl_bai}"
    echo -e "  5. 如果仍有问题: ${gl_lv}nanoraw 文件名${gl_bai}（忽略所有配置）"
    echo -e ""
    echo -e "${gl_huang}配置已应用到以下文件:${gl_bai}"
    echo -e "  ${gl_lv}~/.nanorc${gl_bai} - nano 主配置文件"
    echo -e "  ${gl_lv}~/.bashrc${gl_bai} - 环境变量和别名"
    echo -e "  ${gl_lv}~/.profile${gl_bai} - 登录环境变量"
    echo -e "  ${gl_lv}~/.bash_profile${gl_bai} - 登录环境变量"
    echo -e ""
    echo -e "${gl_huang}如需在新终端中生效，请执行:${gl_bai}"
    echo -e "  ${gl_zi}source ~/.bashrc${gl_bai}"
    echo -e ""
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    return 0
}

