        32) tools_install_yellow ;;             # 全部安装 (黄色序号软件) ★
        33) tools_remove_all ;;                 # 全部卸载
        34) tools_remove_yellow ;;              # 全部卸载 (黄色序号软件) ★
        41) tools_install_custom ;;             # 安装指定工具
        42) tools_remove_custom ;;              # 卸载指定工具
        00 | 000 | 0000) exit_script ;;         # 感谢使用，再见！
        0) cancel_return "主菜单"; mobufan ;;   # 返回到主菜单
        *) handle_invalid_input ;;              # 无效的输入,请重新输入!
        esac
    done
}

linux_bbr() {
    clear
    if [ -f "/etc/alpine-release" ]; then
        while true; do
            clear
            local congestion_algorithm=$(sysctl -n net.ipv4.tcp_congestion_control)
            local queue_algorithm=$(sysctl -n net.core.default_qdisc)
            echo "当前TCP阻塞算法: $congestion_algorithm $queue_algorithm"
            echo ""
            echo -e "${gl_zi}>>> BBR管理${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}1.  ${gl_bai}开启BBRv3              ${gl_bufan}2.  ${gl_bai}关闭BBRv3（会重启）"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单        ${gl_hong}00. ${gl_bai}退出脚本"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入你的选择: " sub_choice

            case $sub_choice in
            1) bbr_on ;;
            2)
                sed -i '/net.ipv4.tcp_congestion_control=bbr/d' /etc/sysctl.conf
                sysctl -p
                server_reboot
                ;;
            0) cancel_return; break ;;      # 返回到上一级菜单
            00 | 000 | 0000) exit_script ;; # 感谢使用，再见！
            *) handle_invalid_input ;;      # 无效的输入,请重新输入!
            esac
        done
    else
        install wget
        wget --no-check-certificate -O tcpx.sh ${gh_proxy}raw.githubusercontent.com/ylx2016/Linux-NetSpeed/master/tcpx.sh
        chmod +x tcpx.sh
        ./tcpx.sh
    fi
}

docker_ssh_migration() {
    is_compose_container() {
        local container=$1
        docker inspect "$container" | jq -e '.[0].Config.Labels["com.docker.compose.project"]' >/dev/null 2>&1
    }

    list_backups() {
        local BACKUP_ROOT="/tmp"
        echo -e "${gl_bufan}当前备份列表:${gl_bai}"
        ls -1dt ${BACKUP_ROOT}/docker_backup_* 2>/dev/null || echo "无备份"
    }

    # ----------------------------
    # 备份
    # ----------------------------
    backup_docker() {

        echo -e "${gl_zi}>>> 备份 Docker 容器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        docker ps --format '{{.Names}}' | while read name; do printf "\033[32m%s\033[0m\n" "$name"; done
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入要备份的容器名（多个空格分隔，回车备份全部运行中容器）(${gl_huang}0${gl_bai}返回)"：)" containers
        [ "$containers" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
        [ -z "$containers" ] && { cancel_empty "上一级选单"; return 1; }         # break 或 continue 或 return ，视上下文而定

        install tar jq gzip
        install_docker

        local BACKUP_ROOT="/tmp"
        local DATE_STR=$(date +%Y%m%d_%H%M%S)
        local TARGET_CONTAINERS=()
        if [ -z "$containers" ]; then
            mapfile -t TARGET_CONTAINERS < <(docker ps --format '{{.Names}}')
        else
            read -r -ra TARGET_CONTAINERS <<<"$containers"
        fi
        [[ ${#TARGET_CONTAINERS[@]} -eq 0 ]] && {
            echo -e "${gl_huang}没有找到容器${gl_bai}"
            return
        }

        local BACKUP_DIR="${BACKUP_ROOT}/docker_backup_${DATE_STR}"
        mkdir -p "$BACKUP_DIR"

        local RESTORE_SCRIPT="${BACKUP_DIR}/docker_restore.sh"
        echo "#!/bin/bash" >"$RESTORE_SCRIPT"
        echo "set -e" >>"$RESTORE_SCRIPT"
        echo "# 自动生成的还原脚本" >>"$RESTORE_SCRIPT"

        # 记录已打包过的 Compose 项目路径，避免重复打包
        declare -A PACKED_COMPOSE_PATHS=()

        for c in "${TARGET_CONTAINERS[@]}"; do
            echo -e "${gl_lv}备份容器: $c${gl_bai}"
            local inspect_file="${BACKUP_DIR}/${c}_inspect.json"
            docker inspect "$c" >"$inspect_file"

            if is_compose_container "$c"; then
                echo -e "${gl_bufan}检测到 $c 是 docker-compose 容器${gl_bai}"
                local project_dir=$(docker inspect "$c" | jq -r '.[0].Config.Labels["com.docker.compose.project.working_dir"] // empty')
                local project_name=$(docker inspect "$c" | jq -r '.[0].Config.Labels["com.docker.compose.project"] // empty')

                if [ -z "$project_dir" ]; then
                    read -r -e -p "未检测到 compose 目录，请手动输入路径: " project_dir
                fi

                # 如果该 Compose 项目已经打包过，跳过
                if [[ -n "${PACKED_COMPOSE_PATHS[$project_dir]}" ]]; then
                    echo -e "${gl_bufan}Compose 项目 [$project_name] 已备份过，跳过重复打包 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    exit_animation    # 即将退出动画
                    return
                fi

                if [ -f "$project_dir/docker-compose.yml" ]; then
                    echo "compose" >"${BACKUP_DIR}/backup_type_${project_name}"
                    echo "$project_dir" >"${BACKUP_DIR}/compose_path_${project_name}.txt"
                    tar -czf "${BACKUP_DIR}/compose_project_${project_name}.tar.gz" -C "$project_dir" .
                    echo "# docker-compose 恢复: $project_name" >>"$RESTORE_SCRIPT"
                    echo "cd \"$project_dir\" && docker compose up -d" >>"$RESTORE_SCRIPT"
                    PACKED_COMPOSE_PATHS["$project_dir"]=1
                    echo -e "${gl_lv}Compose 项目 [$project_name] 已打包: ${project_dir}${gl_bai}"
                else
                    echo -e "${gl_huang}未找到 docker-compose.yml，跳过此容器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                fi
            else
                # 普通容器备份卷
                local VOL_PATHS
                VOL_PATHS=$(docker inspect "$c" --format '{{range .Mounts}}{{.Source}} {{end}}')
                for path in $VOL_PATHS; do
                    echo "打包卷: $path"
                    tar -czpf "${BACKUP_DIR}/${c}_$(basename "$path").tar.gz" -C / "$(echo "$path" | sed 's/^\///')"
                done

                # 端口
                local PORT_ARGS=""
                mapfile -t PORTS < <(jq -r '.[0].HostConfig.PortBindings | to_entries[] | "\(.value[0].HostPort):\(.key | split("/")[0])"' "$inspect_file" 2>/dev/null)
                for p in "${PORTS[@]}"; do PORT_ARGS+="-p $p "; done

                # 环境变量
                local ENV_VARS=""
                mapfile -t ENVS < <(jq -r '.[0].Config.Env[] | @sh' "$inspect_file")
                for e in "${ENVS[@]}"; do ENV_VARS+="-e $e "; done

                # 卷映射
                local VOL_ARGS=""
                for path in $VOL_PATHS; do VOL_ARGS+="-v $path:$path "; done

                # 镜像
                local IMAGE
                IMAGE=$(jq -r '.[0].Config.Image' "$inspect_file")

                echo -e "\n# 还原容器: $c" >>"$RESTORE_SCRIPT"
                echo "docker run -d --name $c $PORT_ARGS $VOL_ARGS $ENV_VARS $IMAGE" >>"$RESTORE_SCRIPT"
            fi
        done

        # 备份 /home/docker 下的所有文件（不含子目录）
        if [ -d "/home/docker" ]; then
            echo -e "${gl_bufan}备份 /home/docker 下的文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            find /home/docker -maxdepth 1 -type f | tar -czf "${BACKUP_DIR}/home_docker_files.tar.gz" -T -
            echo -e "${gl_lv}/home/docker 下的文件已打包到: ${BACKUP_DIR}/home_docker_files.tar.gz${gl_bai}"
        fi

        chmod +x "$RESTORE_SCRIPT"
        echo -e "${gl_lv}备份完成: ${BACKUP_DIR}${gl_bai}"
        echo -e "${gl_lv}可用还原脚本: ${RESTORE_SCRIPT}${gl_bai}"

    }

    # ----------------------------
    # 还原
    # ----------------------------
    restore_docker() {

        read -r -e -p "请输入要还原的备份目录: " BACKUP_DIR
        [[ ! -d "$BACKUP_DIR" ]] && {
            echo -e "${gl_huang}备份目录不存在${gl_bai}"
            exit_animation    # 即将退出动画
            return
        }

        install tar jq gzip
        install_docker
        clear
        echo -e ""
        echo -e "${gl_zi}>>> 开始执行还原操作 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # --------- 优先还原 Compose 项目 ---------
        for f in "$BACKUP_DIR"/backup_type_*; do
            [[ ! -f "$f" ]] && continue
            if grep -q "compose" "$f"; then
                project_name=$(basename "$f" | sed 's/backup_type_//')
                path_file="$BACKUP_DIR/compose_path_${project_name}.txt"
                [[ -f "$path_file" ]] && original_path=$(cat "$path_file") || original_path=""
                [[ -z "$original_path" ]] && read -r -e -p "未找到原始路径，请输入还原目录路径: " original_path

                # 检查该 compose 项目的容器是否已经在运行
                running_count=$(docker ps --filter "label=com.docker.compose.project=$project_name" --format '{{.Names}}' | wc -l)
                if [[ "$running_count" -gt 0 ]]; then
                    echo -e "${gl_bufan}Compose 项目 [$project_name] 已有容器在运行，跳过还原 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    exit_animation    # 即将退出动画
                    return
                fi

                read -r -e -p "$(echo -e "${gl_bai}确认还原 Compose 项目 [$project_name] 到路径 [$original_path] ? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
                [[ "$confirm" != "y" ]] && read -r -e -p "请输入新的还原路径: " original_path

                mkdir -p "$original_path"
                tar -xzf "$BACKUP_DIR/compose_project_${project_name}.tar.gz" -C "$original_path"
                echo -e "${gl_lv}Compose 项目 [$project_name] 已解压到: $original_path${gl_bai}"

                cd "$original_path" || return
                docker compose down || true
                docker compose up -d
                echo -e "${gl_lv}Compose 项目 [$project_name] 还原完成！${gl_bai}"
            fi
        done

        # --------- 继续还原普通容器 ---------
        echo -e "${gl_bufan}检查并还原普通 Docker 容器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        local has_container=false
        for json in "$BACKUP_DIR"/*_inspect.json; do
            [[ ! -f "$json" ]] && continue
            has_container=true
            container=$(basename "$json" | sed 's/_inspect.json//')
            echo -e "${gl_lv}处理容器: $container${gl_bai}"

            # 检查容器是否已经存在且正在运行
            if docker ps --format '{{.Names}}' | grep -q "^${container}$"; then
                echo -e "${gl_bufan}容器 [$container] 已在运行，跳过还原 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                exit_animation    # 即将退出动画
                return
            fi

            IMAGE=$(jq -r '.[0].Config.Image' "$json")
            [[ -z "$IMAGE" || "$IMAGE" == "null" ]] && {
                echo -e "${gl_huang}未找到镜像信息，跳过: $container${gl_bai}"
                exit_animation    # 即将退出动画
                return
            }

            # 端口映射
            PORT_ARGS=""
            mapfile -t PORTS < <(jq -r '.[0].HostConfig.PortBindings | to_entries[]? | "\(.value[0].HostPort):\(.key | split("/")[0])"' "$json")
            for p in "${PORTS[@]}"; do
                [[ -n "$p" ]] && PORT_ARGS="$PORT_ARGS -p $p"
            done

            # 环境变量
            ENV_ARGS=""
            mapfile -t ENVS < <(jq -r '.[0].Config.Env[]' "$json")
            for e in "${ENVS[@]}"; do
                ENV_ARGS="$ENV_ARGS -e \"$e\""
            done

            # 卷映射 + 卷数据恢复
            VOL_ARGS=""
            mapfile -t VOLS < <(jq -r '.[0].Mounts[] | "\(.Source):\(.Destination)"' "$json")
            for v in "${VOLS[@]}"; do
                VOL_SRC=$(echo "$v" | cut -d':' -f1)
                VOL_DST=$(echo "$v" | cut -d':' -f2)
                mkdir -p "$VOL_SRC"
                VOL_ARGS="$VOL_ARGS -v $VOL_SRC:$VOL_DST"

                VOL_FILE="$BACKUP_DIR/${container}_$(basename "$VOL_SRC").tar.gz"
                if [[ -f "$VOL_FILE" ]]; then
                    echo "恢复卷数据: $VOL_SRC"
                    tar -xzf "$VOL_FILE" -C /
                fi
            done

            # 删除已存在但未运行的容器
            if docker ps -a --format '{{.Names}}' | grep -q "^${container}$"; then
                echo -e "${gl_bufan}容器 [$container] 存在但未运行，删除旧容器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                docker rm -f "$container"
            fi

            # 启动容器
            echo "执行还原命令: docker run -d --name \"$container\" $PORT_ARGS $VOL_ARGS $ENV_ARGS \"$IMAGE\""
            eval "docker run -d --name \"$container\" $PORT_ARGS $VOL_ARGS $ENV_ARGS \"$IMAGE\""
        done

        [[ "$has_container" == false ]] && echo -e "${gl_bufan}未找到普通容器的备份信息${gl_bai}"

        # 还原 /home/docker 下的文件
        if [ -f "$BACKUP_DIR/home_docker_files.tar.gz" ]; then
            echo -e "${gl_bufan}正在还原 /home/docker 下的文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            mkdir -p /home/docker
            tar -xzf "$BACKUP_DIR/home_docker_files.tar.gz" -C /
            echo -e "${gl_lv}/home/docker 下的文件已还原完成${gl_bai}"
        else
            echo -e "${gl_bufan}未找到 /home/docker 下文件的备份，跳过 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        fi

    }

    # ----------------------------
    # 迁移
    # ----------------------------
    migrate_docker() {
        install jq
        read -r -e -p "请输入要迁移的备份目录: " BACKUP_DIR
        [[ ! -d "$BACKUP_DIR" ]] && {
            echo -e "${gl_huang}备份目录不存在${gl_bai}"
            return
        }

        read -r -e -p "目标服务器IP: " TARGET_IP
        read -r -e -p "目标服务器SSH用户名: " TARGET_USER
        read -r -e -p "目标服务器SSH端口 [默认22]: " TARGET_PORT
        local TARGET_PORT=${TARGET_PORT:-22}

        local LATEST_TAR="$BACKUP_DIR"

        echo -e "${gl_bufan}传输备份中 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if [[ -z "$TARGET_PASS" ]]; then
            # 使用密钥登录
            scp -P "$TARGET_PORT" -o StrictHostKeyChecking=no -r "$LATEST_TAR" "$TARGET_USER@$TARGET_IP:/tmp/"
        fi

    }

    # ----------------------------
    # 删除备份
    # ----------------------------
    delete_backup() {
        #
        read -r -e -p "请输入要删除的备份目录: " BACKUP_DIR
        [[ ! -d "$BACKUP_DIR" ]] && {
            echo -e "${gl_huang}备份目录不存在${gl_bai}"
            exit_animation    # 即将退出动画
            return
        }
        rm -rf "$BACKUP_DIR"
        echo -e "${gl_lv}已删除备份: ${BACKUP_DIR}${gl_bai}"
    }

    # ----------------------------
    # 主菜单
    # ----------------------------
    main_menu() {
        while true; do
            clear
            echo -e "${gl_zi}>>> Docker备份/迁移/还原工具${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            list_backups
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}1.  ${gl_bai}备份docker项目"
            echo -e "${gl_bufan}2.  ${gl_bai}迁移docker项目"
            echo -e "${gl_bufan}3.  ${gl_bai}还原docker项目"
            echo -e "${gl_bufan}4.  ${gl_bai}删除docker项目的备份文件"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}0.  ${gl_bai}返回主菜单"
            echo -e "${gl_huang}0.  ${gl_bai}返回上一级菜单"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入你的选择: " choice
            case $choice in
            1) backup_docker ;;
            2) migrate_docker ;;
            3) restore_docker ;;
            4) delete_backup ;;
            0) cancel_return; break ;;      # 返回到上一级菜单
            00 | 000 | 0000) exit_script ;; # 感谢使用，再见！
            *) handle_invalid_input ;;      # 无效的输入,请重新输入!
            esac
            break_end
        done
    }

    main_menu
}

# 函数：检查占用空间最大的三个应用层
check_top3_docker_layers() {
    clear
    echo -e "${gl_zi}>>> Docker 占用空间 TOP 3 容器分析${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 临时文件
    local tmp_dir="/tmp/docker_layer_check_$$"
    mkdir -p "$tmp_dir"

    # 自动获取 overlay2 中最大的 3 个层
    log_info "正在扫描 overlay2 存储层 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    du -sh /vol1/docker/overlay2/*/ 2>/dev/null | sort -rh | head -3 | while read size layer_path; do
        layer_id=$(basename "$layer_path")
        echo "$size $layer_id" >>"$tmp_dir/top_layers.txt"
    done

    # 显示 TOP 3 大层概览
    echo -e "${gl_huang}>>> overlay2 存储层 TOP 3${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    nl "$tmp_dir/top_layers.txt" | while read rank size layer_id; do
        echo -e "${gl_zi}$rank.${gl_bai} 层ID: ${gl_huang}${layer_id:0:12} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} 大小: ${gl_hong}$size${gl_bai}"

        # 查找使用该层的容器
        container_info=$(docker inspect $(docker ps -q) --format '{{.Name}}: {{.GraphDriver.Data.LowerDir}} {{.GraphDriver.Data.UpperDir}}' 2>/dev/null | grep "$layer_id" | head -1)
        if [ -n "$container_info" ]; then
            container_name=$(echo "$container_info" | cut -d: -f1)
            echo -e "    所属容器: ${gl_lv}$container_name${gl_bai}"
        else
            echo -e "    ${gl_huang}未找到使用此层的容器（可能是孤儿层）${gl_bai}"
        fi
        echo ""
    done

    # 详细分析 TOP 3
    echo -e "${gl_huang}>>> TOP 3 详细存储分析${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    while read size layer_id; do
        echo -e "${gl_bai}层ID: ${gl_huang}$layer_id${gl_bai} 大小: ${gl_hong}$size${gl_bai}"

        # 查找使用该层的容器详细信息
        container_match=$(docker inspect $(docker ps -q) --format '{{.Name}} {{.GraphDriver.Data.LowerDir}} {{.GraphDriver.Data.UpperDir}} {{.Id}}' 2>/dev/null | grep "$layer_id" | head -1)

        if [ -n "$container_match" ]; then
            container_name=$(echo "$container_match" | awk '{print $1}')
            container_id=$(echo "$container_match" | awk '{print $4}')

            log_info "所属容器: ${gl_lv}$container_name${gl_bai}"

            # 获取完整容器信息
            full_container=$(docker ps -q --filter "name=^/${container_name#/}$" | head -1)
            if [ -n "$full_container" ]; then
                # 镜像信息
                image=$(docker inspect "$full_container" --format '{{.Config.Image}}' 2>/dev/null)
                log_info "使用镜像: ${gl_lv}$image${gl_bai}"

                # 容器存储统计
                container_size=$(docker inspect "$full_container" --format '{{.SizeRw}}' 2>/dev/null)
                if [ "$container_size" != "<no value>" ] && [ -n "$container_size" ]; then
                    human_size=$(numfmt --to=iec-i --suffix=B "$container_size" 2>/dev/null || echo "$container_size bytes")
                    log_info "容器可写层: ${gl_hong}$human_size${gl_bai}"
                fi

                # 层类型判断
                layer_dirs=$(docker inspect "$full_container" --format '{{.GraphDriver.Data.LowerDir}} {{.GraphDriver.Data.UpperDir}}' 2>/dev/null)
                if echo "$layer_dirs" | grep -q "$layer_id"; then
                    if echo "$layer_dirs" | grep "UpperDir" | grep -q "$layer_id"; then
                        log_info "层类型: ${gl_lv}UpperDir (可写层)${gl_bai}"
                    else
                        log_info "层类型: ${gl_lan}LowerDir (镜像层)${gl_bai}"
                    fi
                fi

                # 显示该容器的所有层结构
                log_info "容器完整层结构:"
                echo -e "${gl_hui}  层ID              类型        大小${gl_bai}"

                # UpperDir
                upper_dir=$(docker inspect "$full_container" --format '{{.GraphDriver.Data.UpperDir}}' 2>/dev/null)
                if [ -n "$upper_dir" ]; then
                    upper_layer=$(basename $(dirname "$upper_dir"))
                    upper_size=$(du -sh "$upper_dir" 2>/dev/null | awk '{print $1}')
                    if [ "$upper_layer" = "$layer_id" ]; then
                        echo -e "  ${gl_hong}*${upper_layer:0:12} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} ${gl_lv}UpperDir${gl_bai}  ${gl_huang}$upper_size${gl_bai} ${gl_hong}<<< 当前层${gl_bai}"
                    else
                        echo -e "  ${gl_hui}${upper_layer:0:12} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} ${gl_lv}UpperDir${gl_bai}  ${gl_huang}$upper_size${gl_bai}"
                    fi
                fi

                # LowerDir
                docker inspect "$full_container" --format '{{.GraphDriver.Data.LowerDir}}' 2>/dev/null | tr ':' '\n' | while read dir; do
                    if [ -d "$dir" ]; then
                        lower_layer=$(basename $(dirname "$dir"))
                        lower_size=$(du -sh "$dir" 2>/dev/null | awk '{print $1}')
                        if [ "$lower_layer" = "$layer_id" ]; then
                            echo -e "  ${gl_hong}*${lower_layer:0:12} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} ${gl_lan}LowerDir${gl_bai}  ${gl_huang}$lower_size${gl_bai} ${gl_hong}<<< 当前层${gl_bai}"
                        else
                            echo -e "  ${gl_hui}${lower_layer:0:12} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} ${gl_lan}LowerDir${gl_bai}  ${gl_huang}$lower_size${gl_bai}"
                        fi
                    fi
                done | sort -k3 -rh | head -5
            fi
        else
            log_warn "未找到使用此层的容器"
            # 检查是否是孤儿层
            if [ -d "/vol1/docker/overlay2/$layer_id" ]; then
                log_info "层路径: /vol1/docker/overlay2/$layer_id"
                log_info "内容预览:"
                ls -la "/vol1/docker/overlay2/$layer_id/" 2>/dev/null | head -5
            fi
        fi
        echo ""
    done <"$tmp_dir/top_layers.txt"

    # 清理临时文件
    rm -rf "$tmp_dir"

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_ok "分析完成"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 添加用户到Docker组
add_user_to_docker() {
    clear
    echo -e "${gl_zi}>>> 添加用户到Docker组${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 1. 检查当前用户是否已在docker组中
    log_info "检查当前用户在 Docker 组中的状态 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    if getent group docker | grep -q "\b${USER}\b"; then
        log_ok "当前用户 ${USER} 已在 docker 组中"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 0
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 2. 显示当前docker组信息
    log_info "当前 Docker 组成员:"
    getent group docker || echo -e "  ${gl_huang}Docker 组不存在${gl_bai}"

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 3. 确认是否添加到docker组
    read -r -e -p "$(echo -e "${gl_bai}是否将当前用户 ${gl_lv}${USER}${gl_bai} 添加到 docker 组? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_add

    [ "$confirm_add" = "0" ] && { cancel_return "上一级选单"; return 1; }   # break 或 continue 或 return ，视上下文而定

    case "$confirm_add" in
    [Yy])
        echo -e "${gl_bai}正在执行添加操作 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        ;;
    *) handle_y_n; return 1 ;;       # 无效的输入,请重新输入!
    esac

    # 4. 执行添加命令
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "执行命令: sudo usermod -aG docker ${USER}"

    if sudo usermod -aG docker "$USER"; then
        log_ok "已成功将用户 ${USER} 添加到 docker 组"

        # 显示更新后的组信息
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_info "更新后的 Docker 组成员:"
        getent group docker

        # 提示需要重新登录
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}重要提示:${gl_bai}"
        echo -e "  ${gl_huang}• 需要重新登录或执行以下命令使更改生效:${gl_bai}"
        echo -e "  ${gl_lv}  newgrp docker${gl_bai}"
        echo -e "  ${gl_huang}• 或者注销后重新登录系统${gl_bai}"

        # 询问是否立即应用更改
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}是否立即应用更改? (执行 ${gl_lv}newgrp docker${gl_bai}) (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" apply_now
        case "$apply_now" in
        [Yy])
            log_info "正在应用更改 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            newgrp docker
            ;;
        esac
    else
        log_error "添加用户到 docker 组失败"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
    clear
}

# 从Docker组移除用户
remove_user_from_docker() {
    echo -e ""
    echo -e "${gl_zi}>>> 从Docker组移除用户${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 1. 检查当前用户是否在docker组中
    log_info "检查当前用户在 Docker 组中的状态 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    if ! getent group docker | grep -q "\b${USER}\b"; then
        log_warn "当前用户 ${USER} 不在 docker 组中"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 0
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 2. 显示当前docker组信息
    log_info "当前 Docker 组成员:"
    getent group docker

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 3. 确认是否从docker组移除
    read -r -e -p "$(echo -e "${gl_bai}是否从 docker 组中移除用户 ${gl_lv}${USER}${gl_bai}? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_remove
    [ "$confirm_remove" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
    case "$confirm_remove" in
    [Yy])
        echo -e "${gl_bai}正在执行移除操作 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        ;;
    *) handle_y_n; return 1 ;;       # 无效的输入,请重新输入!
    esac

    # 4. 询问移除方式
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}请选择移除方式:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bufan}1.  ${gl_bai}使用 sudo gpasswd -d 命令 (推荐)"
    echo -e "${gl_bufan}2.  ${gl_bai}使用 sudo deluser 命令"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_huang}0.  ${gl_bai}返回"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "请选择 (${gl_bai}1${gl_bai}-${gl_bai}2${gl_bai}/${gl_huang}0${gl_bai}返回): " remove_method

    case "$remove_method" in
    1)
        # 使用 gpasswd 命令
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_info "执行命令: sudo gpasswd -d ${USER} docker"

        if sudo gpasswd -d "$USER" docker; then
            log_ok "已成功从 docker 组移除用户 ${USER}"
        else
            log_error "移除用户失败"
        fi
        ;;
    2)
        # 使用 deluser 命令
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_info "执行命令: sudo deluser ${USER} docker"

        if sudo deluser "$USER" docker; then
            log_ok "已成功从 docker 组移除用户 ${USER}"
        else
            log_error "移除用户失败"
        fi
        ;;
    0) cancel_return; return 0 ;;
    *) handle_invalid_input; return 1 ;;
    esac

    # 5. 显示更新后的组信息
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "更新后的 Docker 组成员:"
    getent group docker || echo -e "  ${gl_huang}Docker 组不存在或为空${gl_bai}"

    # 6. 提示重新登录
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_warn "注意: 更改可能需要重新登录或新会话才能生效"

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
    read -r -n 1 -s
    clear
}

