        clear
        echo -e "邮局服务 $check_docker $update_status"
        echo "poste.io 是一个开源的邮件服务器解决方案，"
        echo "视频介绍: https://www.bilibili.com/video/BV1wv421C71t?t=0.1"

        echo ""
        echo "端口检测"
        port=25
        timeout=3
        if echo "quit" | timeout $timeout telnet smtp.qq.com "$port" | grep 'Connected'; then
            echo -e "${gl_lv}端口 "$port" 当前可用${gl_bai}"
        else
            echo -e "${gl_hong}端口 "$port" 当前不可用${gl_bai}"
        fi
        echo ""

        if docker ps -a --format '{{.Names}}' 2>/dev/null | grep -q "$docker_name"; then
            yuming=$(cat /home/docker/mail.txt)
            echo "访问地址: "
            echo "https://$yuming"
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}安装"
        echo -e "${gl_bufan}2.  ${gl_bai}更新"
        echo -e "${gl_bufan}3.  ${gl_bai}卸载"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
        echo -e "${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "输入你的选择: " choice

        case $choice in
        1)
            setup_docker_dir
            check_disk_space 2 /home/docker
            read -r -e -p "请设置邮箱域名 例如 mail.yuming.com : " yuming
            mkdir -p /home/docker
            echo "$yuming" >/home/docker/mail.txt
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            ip_address
            echo "先解析这些DNS记录"
            echo "A           mail            $ipv4_address"
            echo "CNAME       imap            "$yuming""
            echo "CNAME       pop             "$yuming""
            echo "CNAME       smtp            "$yuming""
            echo "MX          @               "$yuming""
            echo "TXT         @               v=spf1 mx ~all"
            echo "TXT         ?               ?"
            echo ""
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
            read -r -n 1 -s -r -p ""

            install jq
            docker_install_docker

            docker run \
                --net=host \
                -e TZ=Europe/Prague \
                -v /home/docker/mail:/data \
                --name "mailserver" \
                -h "$yuming" \
                --restart=always \
                -d analogic/poste.io

            add_app_id

            clear
            echo "poste.io已经安装完成"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo "您可以使用以下地址访问poste.io:"
            echo "https://$yuming"
            echo ""
            ;;

        2)
            docker rm -f mailserver
            docker rmi -f analogic/poste.i
            yuming=$(cat /home/docker/mail.txt)
            docker run \
                --net=host \
                -e TZ=Europe/Prague \
                -v /home/docker/mail:/data \
                --name "mailserver" \
                -h "$yuming" \
                --restart=always \
                -d analogic/poste.i

            add_app_id

            clear
            echo "poste.io已经安装完成"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo "您可以使用以下地址访问poste.io:"
            echo "https://$yuming"
            echo ""
            ;;
        3)
            docker rm -f mailserver
            docker rmi -f analogic/poste.io
            rm /home/docker/mail.txt
            rm -rf /home/docker/mail

            sed -i "/\b${app_id}\b/d" /home/docker/appno.txt
            echo "应用已卸载"
            ;;
        0) cancel_return; break ;;
        00 | 000 | 0000) exit_script ;;
        *) handle_invalid_input ;;
        esac
    done
}

###### 安装Rocket.Chat聊天系统
docker_install_rocketchat() {
    local app_id="10"
    local app_name="Rocket.Chat聊天系统"
    local app_text="Rocket.Chat 是一个开源的团队通讯平台，支持实时聊天、音视频通话、文件共享等多种功能，"
    local app_url="官方介绍: https://www.rocket.chat/"
    local docker_name="rocketchat"
    local docker_port="3897"
    local app_size="2"

    docker_app_install() {
        docker run --name db -d --restart=always \
            -v /home/docker/mongo/dump:/dump \
            mongo:latest --replSet rs5 --oplogSize 256
        sleep_fractional 1
        docker exec -it db mongosh --eval "printjson(rs.initiate())"
        sleep_fractional 5
        docker run --name rocketchat --restart=always -p "${docker_port}":3000 --link db --env ROOT_URL=http://localhost --env MONGO_OPLOG_URL=mongodb://db:27017/rs5 -d rocket.chat

        clear
        ip_address
        echo "已经安装完成"
        check_docker_app_ip
    }

    docker_app_update() {
        docker rm -f rocketchat
        docker rmi -f rocket.chat:latest
        docker run --name rocketchat --restart=always -p "${docker_port}":3000 --link db --env ROOT_URL=http://localhost --env MONGO_OPLOG_URL=mongodb://db:27017/rs5 -d rocket.chat
        clear
        ip_address
        echo "rocket.chat已经安装完成"
        check_docker_app_ip
    }

    docker_app_uninstall() {
        docker rm -f rocketchat
        docker rmi -f rocket.chat
        docker rm -f db
        docker rmi -f mongo:latest
        rm -rf /home/docker/mongo
        echo "应用已卸载"
    }

    docker_app_plus
}

