###### 安装雷池WAF面板
docker_install_safeline() {
    local app_id="19"
    local docker_name=safeline-mgt
    local docker_port=9443
    
    while true; do
        check_docker_app
        clear
        echo -e "${gl_zi}>>> 雷池服务 $check_docker${gl_bai}"
        echo "雷池是长亭科技开发的WAF站点防火墙程序面板，可以反代站点进行自动化防御"
        echo "视频介绍: https://www.bilibili.com/video/BV1mZ421T74c?t=0.1"
        if docker ps -a --format '{{.Names}}' 2>/dev/null | grep -q "$docker_name"; then
            check_docker_app_ip
        fi
        echo ""

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}安装           ${gl_bufan}2.  ${gl_bai}更新"
        echo -e "${gl_bufan}3.  ${gl_bai}重置密码           ${gl_bufan}4.  ${gl_bai}卸载"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单     ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "输入你的选择: " choice

        case $choice in
        1)
            docker_install_docker
            check_disk_space 5
            bash -c "$(curl -fsSLk https://waf-ce.chaitin.cn/release/latest/setup.sh)"

            add_app_id
            clear
            echo "雷池WAF面板已经安装完成"
            check_docker_app_ip
            docker exec safeline-mgt resetadmin
            ;;
        2)
            bash -c "$(curl -fsSLk https://waf-ce.chaitin.cn/release/latest/upgrade.sh)"
            docker rmi "$(docker images | grep "safeline" | grep "none" | awk '{print $3}')"
            echo ""

            add_app_id
            clear
            echo "雷池WAF面板已经更新完成"
            check_docker_app_ip
            ;;
        3)
            docker exec safeline-mgt resetadmin
            ;;
        4)
            cd /data/safeline
            docker compose down --rmi all

            sed -i "/\b${app_id}\b/d" /home/docker/appno.txt
            echo "如果你是默认安装目录那现在项目已经卸载。如果你是自定义安装目录你需要到安装目录下自行执行:"
            echo "docker compose down && docker compose down --rmi all"
            ;;
        0) cancel_return; break ;;
        00 | 000 | 0000) exit_script ;;
        *) handle_invalid_input ;;
        esac
        break_end
    done
}

