###### 安装WireGuard VPN服务端
docker_install_wireguard_server() {
    local app_id="97"
    local docker_name="wireguard"
    local docker_img="lscr.io/linuxserver/wireguard:latest"
    local docker_port=8097

    docker_rum() {
        read -r -e -p "请输入组网的客户端数量 (默认 5): " COUNT
        COUNT=${COUNT:-5}
        read -r -e -p "请输入 WireGuard 网段 (默认 10.13.13.0): " NETWORK
        NETWORK=${NETWORK:-10.13.13.0}
        PEERS=$(seq -f "wg%02g" 1 "$COUNT" | paste -sd,)
        ip link delete wg0 &>/dev/null
        ip_address
        docker run -d \
            --name=wireguard \
            --network host \
            --cap-add=NET_ADMIN \
            --cap-add=SYS_MODULE \
            -e PUID=1000 \
            -e PGID=1000 \
            -e TZ=Etc/UTC \
            -e SERVERURL="${ipv4_address}" \
            -e SERVERPORT=51820 \
            -e PEERS="${PEERS}" \
            -e INTERNAL_SUBNET="${NETWORK}" \
            -e ALLOWEDIPS="${NETWORK}"/24 \
            -e PERSISTENTKEEPALIVE_PEERS=all \
            -e LOG_CONFS=true \
            -v /home/docker/wireguard/config:/config \
            -v /lib/modules:/lib/modules \
            --restart=always \
            lscr.io/linuxserver/wireguard:latest
        sleep_fractional 3
        docker exec wireguard sh -c " f='/config/wg_confs/wg0.conf' sed -i 's/51820/${docker_port}/g' \$f "
        docker exec wireguard sh -c " for d in /config/peer_*; do sed -i 's/51820/${docker_port}/g' \$d/*.conf done "
        docker exec wireguard sh -c ' for d in /config/peer_*; do sed -i "/^DNS/d" "$d"/*.conf done '
        docker exec wireguard sh -c ' for d in /config/peer_*; do for f in "$d"/*.conf; do grep -q "^PersistentKeepalive" "$f" || \ sed -i "/^AllowedIPs/ a PersistentKeepalive = 25" "$f" done done '
        docker exec -it wireguard bash -c ' for d in /config/peer_*; do cd "$d" || continue conf_file=$(ls *.conf) base_name="${conf_file%.conf}" qrencode -o "$base_name.png" < "$conf_file" done '
        docker restart wireguard
        sleep_fractional 2
        echo
        echo -e "${gl_huang}所有客户端二维码配置: ${gl_bai}"
        docker exec -it wireguard bash -c 'for i in $(ls /config | grep peer_ | sed "s/peer_//"); do echo "--- $i ---"; /app/show-peer $i; done'
        sleep_fractional 2
        echo
        echo -e "${gl_huang}所有客户端配置代码: ${gl_bai}"
        docker exec wireguard sh -c 'for d in /config/peer_*; do echo "# $(basename $d) "; cat $d/*.conf; echo; done'
        sleep_fractional 2
        echo -e "${gl_lv}${COUNT}个客户端配置全部输出，使用方法如下：${gl_bai}"
        echo -e "${gl_lv}1. 手机下载wg的APP，扫描上方二维码，可以快速连接网络${gl_bai}"
        echo -e "${gl_lv}2. Windows下载客户端，复制配置代码连接网络。${gl_bai}"
        echo -e "${gl_lv}3. Linux用脚本部署WG客户端，复制配置代码连接网络。${gl_bai}"
        echo -e "${gl_lv}官方客户端下载方式: ${gl_bai}https://www.wireguard.com/install/${gl_bai}"
        break_end
    }
    # 根据链接20补全描述
    local docker_describe="现代化、高性能的虚拟专用网络工具，使用先进的加密技术，配置简单，性能高效。"
    local docker_url="${gl_bai}官网介绍: ${gl_lv}https://www.wireguard.com/${gl_bai}"
    local docker_use=""
    local docker_passwd=""
    local app_size="1"
    docker_app
}

###### 安装WireGuard客户端
docker_install_wireguard_client() {
    local app_id="98"
    local docker_name="wireguardc"
    local docker_img="kjlion/wireguard:alpine"
    local docker_port=51820

    docker_rum() {
        mkdir -p /home/docker/wireguard/config/
        local CONFIG_FILE="/home/docker/wireguard/config/wg0.conf"
        mkdir -p "$(dirname "$CONFIG_FILE")"
        echo "请粘贴你的客户端配置，连续按两次回车保存："
        input=""
        empty_line_count=0
        while IFS= read -r -r line; do
            if [[ -z "$line" ]]; then
                ((empty_line_count++))
                if [[ $empty_line_count -ge 2 ]]; then
                    break
                fi
            else
                empty_line_count=0
                input+="$line"$'\n'
            fi
        done
        echo "$input" >"$CONFIG_FILE"
        echo "客户端配置已保存到 $CONFIG_FILE"
        ip link delete wg0 &>/dev/null
        docker run -d \
            --name wireguardc \
            --network host \
            --cap-add NET_ADMIN \
            --cap-add SYS_MODULE \
            -v /home/docker/wireguard/config:/config \
            -v /lib/modules:/lib/modules:ro \
            --restart=always \
            kjlion/wireguard:alpine
        sleep_fractional 3
        docker logs wireguardc
        break_end
    }
    # 根据链接20补全描述
    local docker_describe="WireGuard客户端，用于连接WireGuard VPN服务器，提供安全加密的网络连接。"
    local docker_url="${gl_bai}官网介绍: ${gl_lv}https://www.wireguard.com/${gl_bai}"
    local docker_use=""
    local docker_passwd=""
    local app_size="1"
    docker_app
}

