#-------------------- 公共收尾（优化版 - 防重复）-----------------------------
_common_zh_post() {
    local os_id="$1"

    echo -e ""
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "刷新字体缓存 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    fc-cache -fv &>/dev/null

    log_info "设置时区为 Asia/Shanghai ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    timedatectl set-timezone Asia/Shanghai 2>/dev/null ||
        ln -sf /usr/share/zoneinfo/Asia/Shanghai /etc/localtime
    hwclock --systohc &>/dev/null || true

    # 根据发行版设置环境变量
    case "$os_id" in
    debian | ubuntu | pve | fnos | linuxmint | devuan | kali)
        log_info "使用 update-locale 持久化locale设置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        
        # 先清除可能存在的 LC_ALL，避免它覆盖其他设置
        update-locale LC_ALL= 2>/dev/null || true
        
        # 确保 /etc/default/locale 文件存在
        touch /etc/default/locale 2>/dev/null
        
        # 使用 update-locale 设置（不设置 LC_ALL）
        update-locale LANG=zh_CN.UTF-8 LANGUAGE="zh_CN:zh" LC_MESSAGES=zh_CN.UTF-8
        
        # 【防重复】创建 profile.d 脚本
        log_info "创建增强的locale配置脚本 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        
        if [[ -f /etc/profile.d/99-locale-zh.sh ]]; then
            log_warn "/etc/profile.d/99-locale-zh.sh 已存在，跳过创建"
        else
            cat > /etc/profile.d/99-locale-zh.sh << 'EOF'
#!/bin/bash
# 强制设置中文locale，覆盖所有可能的客户端设置
# 此脚本优先级最高（99），在最后执行

# 1. 首先清除任何可能干扰的变量
unset LC_ALL 2>/dev/null || true

# 2. 强制设置核心中文环境变量
export LANG=zh_CN.UTF-8
export LANGUAGE=zh_CN:zh
export LC_MESSAGES=zh_CN.UTF-8

# 3. 设置所有LC_*变量为中文（避免混合locale）
export LC_CTYPE=zh_CN.UTF-8
export LC_NUMERIC=zh_CN.UTF-8
export LC_TIME=zh_CN.UTF-8
export LC_COLLATE=zh_CN.UTF-8
export LC_MONETARY=zh_CN.UTF-8
export LC_PAPER=zh_CN.UTF-8
export LC_NAME=zh_CN.UTF-8
export LC_ADDRESS=zh_CN.UTF-8
export LC_TELEPHONE=zh_CN.UTF-8
export LC_MEASUREMENT=zh_CN.UTF-8
export LC_IDENTIFICATION=zh_CN.UTF-8

# 4. 阻止SSH客户端的环境变量覆盖
if [ -n "$SSH_CONNECTION" ]; then
    # 明确拒绝SSH客户端转发的locale相关变量
    for var in LANG LANGUAGE LC_CTYPE LC_NUMERIC LC_TIME LC_COLLATE LC_MONETARY LC_MESSAGES LC_PAPER LC_NAME LC_ADDRESS LC_TELEPHONE LC_MEASUREMENT LC_IDENTIFICATION LC_ALL; do
        unset $var 2>/dev/null || true
    done
    # 重新应用我们的设置
    export LANG=zh_CN.UTF-8
    export LANGUAGE=zh_CN:zh
    export LC_MESSAGES=zh_CN.UTF-8
fi
EOF
            chmod 644 /etc/profile.d/99-locale-zh.sh
            sed -i 's/\r$//' /etc/profile.d/99-locale-zh.sh 2>/dev/null || true
            log_ok "已创建 /etc/profile.d/99-locale-zh.sh"
        fi
        
        # 【防重复】配置 .bash_profile
        log_info "配置 .bash_profile 确保登录时加载 .bashrc ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        
        # 为当前sudo用户配置 .bash_profile
        if [[ -n "$SUDO_USER" ]] && [[ "$SUDO_USER" != "root" ]]; then
            local user_home=$(eval echo ~$SUDO_USER)
            if [[ -d "$user_home" ]]; then
                # 检查是否已由本脚本配置过
                if [[ -f "$user_home/.bash_profile" ]] && grep -q "由set_locales_zh脚本添加" "$user_home/.bash_profile" 2>/dev/null; then
                    log_warn "用户 $SUDO_USER 的 .bash_profile 已配置，跳过"
                else
                    # 如果 .bash_profile 不存在，创建它
                    if [[ ! -f "$user_home/.bash_profile" ]]; then
                        cat > "$user_home/.bash_profile" << 'EOF'
# ~/.bash_profile: executed by bash(1) for login shells.
# 由set_locales_zh脚本添加

# 加载 .bashrc（如果存在）
if [ -f "$HOME/.bashrc" ]; then
    . "$HOME/.bashrc"
fi
EOF
                        chown $SUDO_USER:$SUDO_USER "$user_home/.bash_profile"
                        log_ok "已为用户 $SUDO_USER 创建 .bash_profile"
                    else
                        # 存在但未由本脚本配置，检查是否已有加载逻辑
                        if ! grep -q "\.bashrc" "$user_home/.bash_profile" 2>/dev/null; then
                            echo '' >> "$user_home/.bash_profile"
                            echo '# 由set_locales_zh脚本添加' >> "$user_home/.bash_profile"
                            echo 'if [ -f "$HOME/.bashrc" ]; then' >> "$user_home/.bash_profile"
                            echo '    . "$HOME/.bashrc"' >> "$user_home/.bash_profile"
                            echo 'fi' >> "$user_home/.bash_profile"
                            chown $SUDO_USER:$SUDO_USER "$user_home/.bash_profile"
                            log_ok "已为用户 $SUDO_USER 更新 .bash_profile"
                        else
                            log_warn "用户 $SUDO_USER 的 .bash_profile 已有.bashrc加载逻辑，跳过"
                        fi
                    fi
                fi
            fi
        fi
        
        # 【防重复】为root用户配置 .bash_profile
        if [[ -f /root/.bash_profile ]] && grep -q "由set_locales_zh脚本添加" /root/.bash_profile 2>/dev/null; then
            log_warn "root 的 .bash_profile 已配置，跳过"
        else
            if [[ ! -f /root/.bash_profile ]]; then
                cat > /root/.bash_profile << 'EOF'
# ~/.bash_profile: executed by bash(1) for login shells.
# 由set_locales_zh脚本添加

# 加载 .bashrc（如果存在）
if [ -f "$HOME/.bashrc" ]; then
    . "$HOME/.bashrc"
fi
EOF
                log_ok "已为root用户创建 .bash_profile"
            else
                if ! grep -q "\.bashrc" /root/.bash_profile 2>/dev/null; then
                    echo '' >> /root/.bash_profile
                    echo '# 由set_locales_zh脚本添加' >> /root/.bash_profile
                    echo 'if [ -f "$HOME/.bashrc" ]; then' >> /root/.bash_profile
                    echo '    . "$HOME/.bashrc"' >> /root/.bash_profile
                    echo 'fi' >> /root/.bash_profile
                    log_ok "已为root用户更新 .bash_profile"
                else
                    log_warn "root 的 .bash_profile 已有.bashrc加载逻辑，跳过"
                fi
            fi
        fi
        
        # 【防重复】为用户创建个人配置
        log_info "为用户创建个人locale配置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        
        # 为当前sudo用户配置 .bashrc
        if [[ -n "$SUDO_USER" ]] && [[ "$SUDO_USER" != "root" ]]; then
            local user_home=$(eval echo ~$SUDO_USER)
            if [[ -d "$user_home" ]]; then
                if grep -q "中文环境强制设置（由set_locales_zh脚本添加）" "$user_home/.bashrc" 2>/dev/null; then
                    log_warn "用户 $SUDO_USER 的 .bashrc 已配置中文环境，跳过"
                else
                    cat >> "$user_home/.bashrc" << 'EOF'

# ===== 中文环境强制设置（由set_locales_zh脚本添加）=====
# 此部分设置会覆盖系统默认值，确保中文环境始终生效
if [ -f /etc/default/locale ]; then
    . /etc/default/locale
fi

# 强制设置中文环境变量
export LANG=zh_CN.UTF-8
export LANGUAGE=zh_CN:zh
export LC_MESSAGES=zh_CN.UTF-8
unset LC_ALL 2>/dev/null || true

# 如果是SSH会话，明确拒绝客户端转发的locale设置
if [ -n "$SSH_CONNECTION" ]; then
    for var in LANG LANGUAGE LC_CTYPE LC_NUMERIC LC_TIME LC_COLLATE LC_MONETARY LC_MESSAGES LC_PAPER LC_NAME LC_ADDRESS LC_TELEPHONE LC_MEASUREMENT LC_IDENTIFICATION LC_ALL; do
        unset $var 2>/dev/null || true
    done
    export LANG=zh_CN.UTF-8
    export LANGUAGE=zh_CN:zh
    export LC_MESSAGES=zh_CN.UTF-8
fi
EOF
                    chown $SUDO_USER:$SUDO_USER "$user_home/.bashrc"
                    log_ok "已为用户 $SUDO_USER 配置 .bashrc"
                fi
            fi
        fi
        
        # 【防重复】为root用户配置 .bashrc
        if grep -q "中文环境强制设置（由set_locales_zh脚本添加）" /root/.bashrc 2>/dev/null; then
            log_warn "root 的 .bashrc 已配置中文环境，跳过"
        else
            cat >> /root/.bashrc << 'EOF'

# ===== 中文环境强制设置（由set_locales_zh脚本添加）=====
# 此部分设置会覆盖系统默认值，确保中文环境始终生效
if [ -f /etc/default/locale ]; then
    . /etc/default/locale
fi

# 强制设置中文环境变量
export LANG=zh_CN.UTF-8
export LANGUAGE=zh_CN:zh
export LC_MESSAGES=zh_CN.UTF-8
unset LC_ALL 2>/dev/null || true

# 如果是SSH会话，明确拒绝客户端转发的locale设置
if [ -n "$SSH_CONNECTION" ]; then
    for var in LANG LANGUAGE LC_CTYPE LC_NUMERIC LC_TIME LC_COLLATE LC_MONETARY LC_MESSAGES LC_PAPER LC_NAME LC_ADDRESS LC_TELEPHONE LC_MEASUREMENT LC_IDENTIFICATION LC_ALL; do
        unset $var 2>/dev/null || true
    done
    export LANG=zh_CN.UTF-8
    export LANGUAGE=zh_CN:zh
    export LC_MESSAGES=zh_CN.UTF-8
fi
EOF
            log_ok "已为root用户配置 .bashrc"
        fi
        
        # 【防重复】配置SSH服务器
        log_info "配置SSH服务器拒绝客户端locale转发 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if [ -f /etc/ssh/sshd_config ]; then
            if grep -q "由set_locales_zh脚本添加" /etc/ssh/sshd_config 2>/dev/null; then
                log_warn "SSH配置已修改，跳过"
            else
                # 备份原始配置
                cp -f /etc/ssh/sshd_config /etc/ssh/sshd_config.bak.$(date +%Y%m%d%H%M%S) 2>/dev/null || true
                
                # 注释掉AcceptEnv相关行
                sed -i 's/^AcceptEnv/#AcceptEnv/g' /etc/ssh/sshd_config
                
                # 添加标记和配置
                echo "" >> /etc/ssh/sshd_config
                echo "# 由set_locales_zh脚本添加：拒绝客户端转发的locale环境变量" >> /etc/ssh/sshd_config
                echo "AcceptEnv LANG LC_*" >> /etc/ssh/sshd_config
                
                # 重启SSH服务
                if systemctl is-active sshd &>/dev/null; then
                    systemctl restart sshd
                    log_ok "SSH服务已重启，配置生效"
                fi
            fi
        fi
        
        # 【防重复】创建 /etc/environment
        log_info "创建PAM环境配置文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        
        if [[ -f /etc/environment ]] && grep -q "由set_locales_zh脚本管理" /etc/environment 2>/dev/null; then
            log_warn "/etc/environment 已由本脚本管理，重新写入以确保配置正确"
        fi
        
        cat > /etc/environment << 'EOF'
# 系统全局环境变量设置（由set_locales_zh脚本管理）
LANG=zh_CN.UTF-8
LANGUAGE=zh_CN:zh
LC_MESSAGES=zh_CN.UTF-8
LC_CTYPE=zh_CN.UTF-8
LC_NUMERIC=zh_CN.UTF-8
LC_TIME=zh_CN.UTF-8
LC_COLLATE=zh_CN.UTF-8
LC_MONETARY=zh_CN.UTF-8
LC_PAPER=zh_CN.UTF-8
LC_NAME=zh_CN.UTF-8
LC_ADDRESS=zh_CN.UTF-8
LC_TELEPHONE=zh_CN.UTF-8
LC_MEASUREMENT=zh_CN.UTF-8
LC_IDENTIFICATION=zh_CN.UTF-8
EOF
        
        chmod 644 /etc/environment
        log_ok "已更新 /etc/environment"
        
        ;;
    *)
        # 其他发行版的通用处理
        if [[ -f /etc/locale.conf ]] && grep -q "由set_locales_zh脚本添加" /etc/locale.conf 2>/dev/null; then
            log_warn "/etc/locale.conf 已配置，跳过"
        else
            echo "# 由set_locales_zh脚本添加" >> /etc/locale.conf 2>/dev/null || true
            echo "LANG=zh_CN.UTF-8" >> /etc/locale.conf 2>/dev/null || true
        fi
        
        # 尝试写入 /etc/sysconfig/i18n（旧版RHEL系）
        if [[ -f /etc/sysconfig/i18n ]] && grep -q "由set_locales_zh脚本添加" /etc/sysconfig/i18n 2>/dev/null; then
            log_warn "/etc/sysconfig/i18n 已配置，跳过"
        else
            echo "# 由set_locales_zh脚本添加" >> /etc/sysconfig/i18n 2>/dev/null || true
            echo "LANG=zh_CN.UTF-8" >> /etc/sysconfig/i18n 2>/dev/null || true
        fi
        ;;
    esac

    # 立即应用环境变量
    unset LC_ALL 2>/dev/null || true
    export LANG=zh_CN.UTF-8
    export LANGUAGE=zh_CN:zh
    export LC_MESSAGES=zh_CN.UTF-8
    export LC_CTYPE=zh_CN.UTF-8
    export LC_TIME=zh_CN.UTF-8

    log_info "当前locale与日期："
    locale
    date +"%Y年%m月%d日 %H时%M分%S秒 %Z"

    echo -e "\n${gl_huang}测试包管理器中文显示：${gl_bai}"
    case "$os_id" in
    debian | ubuntu | pve | fnos | linuxmint | devuan | kali)
        apt update --assume-no 2>&1 | head -5 || true
        ;;
    esac

    log_ok "中文环境已就绪！"
    echo -e "${gl_huang}重要提示：要使更改完全生效，请重新登录或重启系统。${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    echo -e "\n${gl_lv}增强的持久化措施已启用：${gl_bai}"
    echo -e "1. 创建了增强的 /etc/profile.d/99-locale-zh.sh 脚本（防重复）"
    echo -e "2. 配置了用户 .bashrc 强制设置（防重复）"
    echo -e "3. 配置了 .bash_profile 确保登录时加载 .bashrc（防重复）"
    echo -e "4. 配置了SSH服务器拒绝客户端locale转发（防重复）"
    echo -e "5. 更新了 /etc/environment 系统环境文件（防重复）"
    echo -e ""
    echo -e "${gl_lv}使用建议：${gl_bai}"
    echo -e "1. 执行 ${gl_huang}source ~/.bashrc${gl_bai} 立即生效（当前用户）"
    echo -e "2. 或重新登录SSH会话（推荐，确保完全生效）"
    echo -e "3. 测试命令：${gl_huang}locale${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}


###### Samba挂载管理器

###### 安装Samba服务
install_samba() {
    log_info "正在检查并安装 Samba 服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 检查Samba是否已安装
    if command -v smbd &>/dev/null || command -v samba &>/dev/null; then
        log_info "Samba 已安装，版本信息："
        if command -v smbd &>/dev/null; then
            smbd --version 2>&1 | head -1
        fi
        log_warn "是否需要重新安装？[y/N]"
        read -r reinstall_choice
        if [[ ! "$reinstall_choice" =~ ^[Yy]$ ]]; then
            log_info "跳过Samba安装"
            return 0
        fi
    fi

    local package_manager=""
    local install_cmd=""
    local packages=""
    local update_cmd=""

    # 识别包管理器并设置相应参数
    if command -v apt &>/dev/null; then
        package_manager="apt"
        update_cmd="apt update"
        packages="samba samba-common-bin"
        install_cmd="apt install -y"

    elif command -v yum &>/dev/null; then
        package_manager="yum"
        update_cmd="yum makecache fast"
        packages="samba samba-client samba-common"
        install_cmd="yum install -y"

    elif command -v dnf &>/dev/null; then
        package_manager="dnf"
        update_cmd="dnf makecache"
        packages="samba samba-client samba-common"
        install_cmd="dnf install -y"

    elif command -v pacman &>/dev/null; then
        package_manager="pacman"
        update_cmd="pacman -Sy"
        packages="samba"
        install_cmd="pacman -S --noconfirm --needed"

    elif command -v zypper &>/dev/null; then
        package_manager="zypper"
        update_cmd="zypper refresh"
        packages="samba samba-client"
        install_cmd="zypper install -y"

    else
        log_error "不支持的包管理器，请手动安装 Samba"
        return 1
    fi

    log_info "检测到包管理器: ${package_manager}"

    # 更新软件源
    log_info "正在更新软件源 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if ! $update_cmd &>/dev/null; then
        log_warn "软件源更新失败，尝试继续安装 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    else
        log_ok "软件源更新完成"
    fi

    # 安装Samba
    log_info "正在安装 Samba 包: ${packages}"

    # 使用临时变量保存退出状态
    local install_result=0
    $install_cmd $packages || install_result=$?

    if [ $install_result -eq 0 ]; then
        # 验证安装
        if command -v smbd &>/dev/null || command -v samba &>/dev/null; then
            log_ok "Samba 服务安装完成"

            # 显示版本信息
            log_info "Samba 安装详情："
            if command -v smbd &>/dev/null; then
                smbd --version 2>&1 | head -1
            fi

            return 0
        else
            log_error "Samba 安装后验证失败"
            return 1
        fi
    else
        log_error "Samba 安装失败 (退出码: $install_result)"

        # 如果是apt，尝试单独安装samba
        if [ "$package_manager" = "apt" ]; then
            log_info "尝试备选安装方案: 只安装samba主包 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            if apt install -y samba; then
                if command -v smbd &>/dev/null; then
                    log_warn "使用精简安装成功，部分功能可能受限"
                    return 0
                else
                    log_error "备选安装方案也失败了"
                    return 1
                fi
            fi
        fi

        return 1
    fi
}

# 检查并启动Samba服务
check_samba_service() {
    log_info "检查Samba服务状态 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 等待一会儿让systemd识别新服务
    sleep_fractional 2

    # 检查服务文件是否存在
    if [ -f /lib/systemd/system/smbd.service ] || [ -f /usr/lib/systemd/system/smbd.service ]; then
        local service_name="smbd"
    elif [ -f /lib/systemd/system/smb.service ] || [ -f /usr/lib/systemd/system/smb.service ]; then
        local service_name="smb"
    elif [ -f /lib/systemd/system/samba.service ] || [ -f /usr/lib/systemd/system/samba.service ]; then
        local service_name="samba"
    else
        log_error "未找到Samba服务文件，尝试手动启动 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        # 尝试直接启动smbd
        if systemctl start smbd 2>/dev/null; then
            log_ok "Samba 服务启动成功"
            return 0
        fi
        return 1
    fi

    log_info "检测到Samba服务: ${service_name}"

    # 重载systemd配置
    if systemctl daemon-reload &>/dev/null; then
        log_info "已重载systemd配置"
    fi

    # 检查服务状态
    if systemctl is-active --quiet "$service_name"; then
        log_ok "Samba 服务正在运行"
    else
        log_warn "Samba 服务未运行，正在启动 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if systemctl start "$service_name"; then
            log_ok "Samba 服务启动成功"
        else
            log_error "Samba 服务启动失败，尝试启动smbd和nmbd ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            systemctl start smbd nmbd 2>/dev/null && {
                log_ok "Samba 服务启动成功"
                return 0
            }
            return 1
        fi
    fi

    # 设置开机自启
    if ! systemctl is-enabled --quiet "$service_name"; then
        log_info "设置Samba开机自启 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if systemctl enable "$service_name"; then
            log_ok "Samba 开机自启已设置"
        else
            log_warn "Samba 开机自启设置失败，尝试启用smbd和nmbd ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            systemctl enable smbd nmbd 2>/dev/null || log_warn "开机自启设置失败"
        fi
    else
        log_ok "Samba 已设置开机自启"
    fi

    return 0
}

###### 卸载Samba服务
uninstall_samba() {
    log_info "正在卸载 Samba 服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 先停止Samba服务
    if systemctl is-active --quiet smbd 2>/dev/null ||
        systemctl is-active --quiet smb 2>/dev/null ||
        systemctl is-active --quiet samba 2>/dev/null; then
        log_info "停止Samba服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        systemctl stop smbd smb nmb samba winbind 2>/dev/null
    fi

    # 根据包管理器卸载
    local uninstall_success=1

    if command -v apt &>/dev/null; then
        apt remove --purge samba samba-common-bin samba-vfs-modules samba-dsdb-modules -y
        apt autoremove --purge -y
        uninstall_success=$?

    elif command -v yum &>/dev/null; then
        yum remove samba samba-client samba-common samba-libs -y
        uninstall_success=$?

    elif command -v dnf &>/dev/null; then
        dnf remove samba samba-client samba-common samba-libs -y
        uninstall_success=$?

    elif command -v pacman &>/dev/null; then
        pacman -Rns samba --noconfirm
        uninstall_success=$?

    elif command -v zypper &>/dev/null; then
        zypper remove samba samba-client samba-winbind -y
        uninstall_success=$?

    else
        log_error "不支持的包管理器，请手动卸载 Samba"
        return 1
    fi

    # 清理配置文件和数据目录
    if [ $uninstall_success -eq 0 ]; then
        log_info "清理Samba配置文件和目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 配置文件
        rm -rf /etc/samba /etc/samba.conf 2>/dev/null

        # 系统服务文件
        rm -f /etc/systemd/system/samba*.service 2>/dev/null
        rm -f /lib/systemd/system/samba*.service 2>/dev/null

        # 日志文件
        rm -f /var/log/samba/* 2>/dev/null
        rm -rf /var/log/samba 2>/dev/null

        # 运行时文件
        rm -rf /var/run/samba 2>/dev/null
        rm -rf /var/lock/samba 2>/dev/null
        rm -rf /var/cache/samba 2>/dev/null

        # 共享目录锁文件
        rm -f /var/lib/samba/*.tdb 2>/dev/null
        rm -rf /var/lib/samba 2>/dev/null

        # 重新加载systemd
        if systemctl daemon-reload 2>/dev/null; then
            log_info "已重新加载systemd配置"
        fi

        log_ok "Samba 服务已完全卸载"
        return 0
    else
        log_error "Samba 卸载失败"
        return 1
    fi
}

# 选择性卸载（保留配置文件）
uninstall_samba_keep_configs() {
    log_info "正在卸载 Samba 服务（保留配置文件） ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 先停止Samba服务
    if systemctl is-active --quiet smbd 2>/dev/null; then
        systemctl stop smbd nmb
    fi

    # 禁用服务
    systemctl disable smbd nmb 2>/dev/null

    local uninstall_success=1

    if command -v apt &>/dev/null; then
        apt remove samba samba-common-bin -y
        uninstall_success=$?

    elif command -v yum &>/dev/null; then
        yum remove samba samba-client -y
        uninstall_success=$?

    elif command -v dnf &>/dev/null; then
        dnf remove samba samba-client -y
        uninstall_success=$?

    elif command -v pacman &>/dev/null; then
        pacman -R samba --noconfirm
        uninstall_success=$?

    elif command -v zypper &>/dev/null; then
        zypper remove samba samba-client -y
