        29) cleanup_services ;;                 # 清理无效CIFS服务
        30) force_clean_all ;;                  # 强制清理所有 CIFS 相关
        0) cancel_return "系统工具"; break ;;    # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;         # 感谢使用，再见！
        *) handle_invalid_input ;;              # 无效的输入,请重新输入!
        esac
    done
}

###### Linux静态IP配置工具
# 检测网络管理工具
detect_network_manager() {
    if command -v nmcli &>/dev/null && nmcli -t -f DEVICE device status 2>/dev/null | grep -q "."; then
        echo "NetworkManager"
    elif [ -d /etc/netplan ] && ls /etc/netplan/*.yaml 2>/dev/null | grep -q "."; then
        echo "netplan"
    elif [ -f /etc/network/interfaces ]; then
        echo "ifupdown"
    elif command -v wicked &>/dev/null; then
        echo "wicked"
    elif [ -d /etc/sysconfig/network-scripts ] && ls /etc/sysconfig/network-scripts/ifcfg-* 2>/dev/null | grep -q "."; then
        echo "network-scripts"
    elif command -v systemctl &>/dev/null && systemctl is-active --quiet systemd-networkd 2>/dev/null; then
        echo "systemd-networkd"
    else
        echo "unknown"
    fi
}

# 检测是否使用systemd-resolved
detect_resolved() {
    if systemctl is-active --quiet systemd-resolved 2>/dev/null; then
        echo "yes"
    else
        echo "no"
    fi
}

# 显示系统信息
show_system_info() {
    echo -e "${gl_huang}>>> 系统信息${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检测发行版
    if [ -f /etc/os-release ]; then
        . /etc/os-release
        echo -e "${gl_bai}系统版本:  ${gl_lv}$PRETTY_NAME${gl_bai}"
    else
        echo -e "${gl_bai}系统版本:  ${gl_lv}未知${gl_bai}"
    fi

    # 检测网络管理工具
    local net_manager=$(detect_network_manager)
    echo -e "${gl_bai}网络管理:  ${gl_lv}$net_manager${gl_bai}"

    # 检测是否使用systemd-resolved
    if [ "$(detect_resolved)" = "yes" ]; then
        echo -e "${gl_bai}DNS服务:   ${gl_lv}systemd-resolved${gl_bai}"
    fi

    # 内核版本
    echo -e "${gl_bai}内核版本:  ${gl_lv}$(uname -r)${gl_bai}"
    echo -e "${gl_bai}IPV4地址:  ${gl_lv}$(get_internal_ip)${gl_bai}"
    echo -e "${gl_bai}默认网关:  ${gl_lv}$(get_default_gateway)${gl_bai}"
    echo -e "${gl_bai}DNS 配置:  ${gl_lv}$(get_dns_servers)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
}

# 显示网络信息
show_network_info() {
    echo -e ""
    echo -e "${gl_huang}网络接口信息${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    local interfaces=$(ip -o link show | awk -F': ' '{print $2}')
    if [ -z "$interfaces" ]; then
        log_error "无法获取网络接口"
        exit_animation    # 即将退出动画
        return 1
    fi

    echo -e "${gl_bai}检测到网络接口:${gl_bai}"
    for iface in $interfaces; do
        if [ "$iface" != "lo" ]; then
            local state=$(cat /sys/class/net/$iface/operstate 2>/dev/null || echo "未知")
            local mac=$(cat /sys/class/net/$iface/address 2>/dev/null || echo "未知")
            local ipv4=$(ip -4 addr show $iface 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.\d+){3}/\d+' || echo "无IP")
            echo -e "${gl_bufan}接口:${gl_bai} ${gl_bai}$iface${gl_bai}"
            echo -e "  ${gl_bufan}状态:${gl_bai} ${gl_bai}$state${gl_bai}"
            echo -e "  ${gl_bufan}MAC:${gl_bai} ${gl_bai}$mac${gl_bai}"
            echo -e "  ${gl_bufan}IPv4:${gl_bai} ${gl_bai}$ipv4${gl_bai}"
            echo ""
        fi
    done
}

# 显示当前DNS配置
show_dns_info() {
    echo -e "${gl_bai}DNS配置:${gl_bai}"

    # 检查systemd-resolved状态
    if [ "$(detect_resolved)" = "yes" ]; then
        echo -e "  ${gl_bufan}systemd-resolved 状态:${gl_bai} ${gl_lv}启用${gl_bai}"
        echo -e "  ${gl_bufan}全局DNS:${gl_bai}"
        resolvectl status 2>/dev/null | grep -A5 "Global" | grep "DNS Server" | awk '{print "    "$3}' | while read dns; do
            echo -e "    ${gl_bai}$dns${gl_bai}"
        done
    else
        if [ -f /etc/resolv.conf ]; then
            grep -E '^nameserver' /etc/resolv.conf 2>/dev/null |
                awk '{print "  " NR ". " $2}' |
                while read line; do
                    echo -e "${gl_bai}  $line${gl_bai}"
                done
        else
            echo -e "  ${gl_huang}无DNS配置${gl_bai}"
        fi
    fi
}

# 显示当前IP配置
show_current_ip_config() {
    echo -e "${gl_huang}当前IP配置${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 显示默认网关
    local gateway=$(ip route | grep default | awk '{print $3}' | head -1)
    if [ -n "$gateway" ]; then
        echo -e "${gl_bai}默认网关:  ${gl_lv}$gateway${gl_bai}"
    else
        echo -e "${gl_bai}默认网关:  ${gl_huang}未设置${gl_bai}"
    fi

    # 显示DNS配置
    show_dns_info

    # 显示路由表
    echo -e "${gl_bai}路由表:${gl_bai}"
    ip route | head -10 | while read line; do
        echo -e "  ${gl_bufan}$line${gl_bai}"
    done

    echo ""
}

# 清理Netplan锁文件
clean_netplan_locks() {
    local lock_files=(
        "/run/netplan/netplan-try.ready"
        "/run/netplan/netplan-try.pid"
        "/run/netplan/ethernets"
    )

    for lock_file in "${lock_files[@]}"; do
        if [ -f "$lock_file" ] || [ -d "$lock_file" ]; then
            log_info "清理锁文件: $lock_file"
            rm -rf "$lock_file" 2>/dev/null || true
        fi
    done
}

# 配置静态IP - Netplan (Ubuntu) - 修复版本
configure_static_ip_netplan() {
    local interface=$1
    local ip_address=$2
    local gateway=$3
    local dns_servers=$4

    echo ""
    log_info "检测到Ubuntu系统使用Netplan配置网络"

    # 检查systemd-resolved状态
    local use_resolved="false"
    if [ "$(detect_resolved)" = "yes" ]; then
        log_warn "检测到systemd-resolved服务正在运行"
        log_info "Ubuntu 25.04默认使用systemd-resolved管理DNS"
        log_info "建议使用127.0.0.53作为DNS服务器以利用缓存功能"
        echo ""

        read -r -e -p "$(echo -e "${gl_bai}是否使用systemd-resolved (127.0.0.53) 作为DNS? (${gl_lv}Y${gl_bai}/${gl_hong}n${gl_bai}) [默认: Y]: ")" use_resolved_choice

        if [[ ! "$use_resolved_choice" =~ ^[Nn]$ ]]; then
            use_resolved="true"
            dns_servers="127.0.0.53"
            log_info "将使用 systemd-resolved (127.0.0.53) 作为DNS服务器"
        else
            log_info "将使用自定义DNS服务器: $dns_servers"
        fi
    fi

    # 查看Netplan配置文件
    log_info "查找Netplan配置文件"

    local config_files=$(ls /etc/netplan/*.yaml 2>/dev/null)
    if [ -z "$config_files" ]; then
        # 如果没有配置文件，创建一个默认的
        local config_file="/etc/netplan/01-network.yaml"
        log_info "未找到现有配置文件，创建新的: $config_file"
    else
        local file_list=($config_files)
        if [ ${#file_list[@]} -eq 1 ]; then
            local config_file="${file_list[0]}"
            log_info "找到配置文件: $config_file"
        else
            log_info "找到多个配置文件:"
            for i in "${!file_list[@]}"; do
                echo -e "${gl_bufan}$(($i + 1)).${gl_bai} ${gl_bai}${file_list[$i]}${gl_bai}"
            done

            while true; do
                read -r -e -p "$(echo -e "${gl_bai}请选择要修改的配置文件编号 (1-${#file_list[@]}) (${gl_huang}0${gl_bai}返回): ")" file_choice
                case "$file_choice" in
                0) cancel_return; return 1 ;;
                *)
                    if [[ "$file_choice" =~ ^[0-9]+$ ]] && [ "$file_choice" -ge 1 ] && [ "$file_choice" -le ${#file_list[@]} ]; then
                        local config_file="${file_list[$((file_choice - 1))]}"
                        break
                    else
                        log_error "选择无效!"
                    fi
                    ;;
                esac
            done
        fi
    fi

    # 备份原始配置文件
    local backup_file="${config_file}.backup.$(date +%Y%m%d%H%M%S)"
    log_info "备份配置文件到: $backup_file"
    cp "$config_file" "$backup_file" 2>/dev/null || true

    # 读取现有配置
    if [ -f "$config_file" ] && [ -s "$config_file" ]; then
        log_info "读取现有配置文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    else
        log_info "创建新的配置文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    fi

    # 清理Netplan锁文件
    clean_netplan_locks

    # 生成新的配置文件
    log_info "生成新的Netplan配置"
    local temp_config=$(mktemp)

    # 解析DNS服务器
    local dns_array=()
    if [ "$use_resolved" = "true" ]; then
        dns_array=("127.0.0.53")
    else
        IFS=',' read -ra dns_array <<<"$dns_servers"
    fi

    # 生成Netplan配置
    cat >"$temp_config" <<EOF
# Netplan configuration generated by network configuration script
network:
  version: 2
  renderer: networkd
  ethernets:
    $interface:
      dhcp4: false
      dhcp6: false
      addresses:
        - $ip_address
EOF

    # 添加网关配置
    if [ -n "$gateway" ]; then
        cat >>"$temp_config" <<EOF
      routes:
        - to: default
          via: $gateway
EOF
    fi

    # 添加DNS配置
    if [ ${#dns_array[@]} -gt 0 ]; then
        cat >>"$temp_config" <<EOF
      nameservers:
        addresses:
EOF
        for dns in "${dns_array[@]}"; do
            echo "          - $(echo $dns | xargs)" >>"$temp_config"
        done
    fi

    # 显示配置内容
    echo ""
    echo -e "${gl_zi}>>> 生成的Netplan配置${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    cat "$temp_config"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo ""

    read -r -e -p "$(echo -e "${gl_bai}确认上述配置? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    if [[ ! "$confirm" =~ ^[Yy]$ ]]; then
        rm -f "$temp_config"
        log_info "配置已取消"
        return 0
    fi

    # 应用配置
    cp "$temp_config" "$config_file"
    chmod 600 "$config_file"

    # 验证配置语法
    echo ""
    log_info "验证Netplan配置语法 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 清理旧的锁文件
    clean_netplan_locks

    # 测试netplan generate
    if netplan generate 2>&1 | tee /tmp/netplan-generate.log; then
        log_ok "Netplan配置语法正确"
    else
        log_error "Netplan配置语法错误!"
        echo -e "${gl_bai}错误信息:${gl_bai}"
        cat /tmp/netplan-generate.log
        rm -f "$temp_config" /tmp/netplan-generate.log
        return 1
    fi

    rm -f "$temp_config" /tmp/netplan-generate.log

    # 应用配置
    echo ""
    log_info "应用Netplan配置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    if netplan apply 2>&1 | tee /tmp/netplan-apply.log; then
        log_ok "Netplan配置应用成功"

        # 重启systemd-resolved（如果使用）
        if [ "$use_resolved" = "true" ]; then
            log_info "重新启动systemd-resolved服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            systemctl restart systemd-resolved 2>/dev/null || true
        fi

        # 等待网络稳定
        sleep_fractional 3

        return 0
    else
        log_error "Netplan配置应用失败"
        echo -e "${gl_bai}错误信息:${gl_bai}"
        cat /tmp/netplan-apply.log

        # 恢复备份
        if [ -f "$backup_file" ]; then
            log_info "正在恢复备份配置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            cp "$backup_file" "$config_file"
            netplan apply
            log_info "已恢复原始配置"
        fi

        rm -f /tmp/netplan-apply.log
        return 1
    fi
}

# 简化版Netplan配置（备用方案）
configure_static_ip_netplan_simple() {
    local interface=$1
    local ip_address=$2
    local gateway=$3
    local dns_servers=$4
    local config_file=$5

    # 解析DNS服务器
    local dns_array=()
    IFS=',' read -ra dns_array <<<"$dns_servers"

    # 创建简单的YAML配置
    local temp_config=$(mktemp)

    cat >"$temp_config" <<EOF
network:
  version: 2
  ethernets:
    $interface:
      dhcp4: false
      addresses: [$ip_address]
EOF

    if [ -n "$gateway" ]; then
        cat >>"$temp_config" <<EOF
      gateway4: $gateway
EOF
    fi

    if [ ${#dns_array[@]} -gt 0 ]; then
        local dns_str="["
        for dns in "${dns_array[@]}"; do
            dns_str+="\"$(echo $dns | xargs)\", "
        done
        dns_str="${dns_str%, }]"

        cat >>"$temp_config" <<EOF
      nameservers:
        addresses: $dns_str
EOF
    fi

    # 应用配置
    cp "$temp_config" "$config_file"
    chmod 600 "$config_file"
    rm -f "$temp_config"

    return 0
}

# 主静态IP配置函数
configure_static_ip() {
    clear
    echo -e "${gl_zi}>>> Linux静态IP配置工具${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 显示当前网络信息
    show_network_info
    show_current_ip_config

    while true; do
        echo ""
        echo -e "${gl_zi}>>> 选择要配置的网络接口"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        # 选择要配置的网卡
        echo -e "${gl_huang}可用的网络接口${gl_bai}"
        local interfaces=$(ip -o link show | awk -F': ' '{print $2}' | grep -v lo | grep -v docker | grep -v br- | grep -v veth)

        [ -z "$interfaces" ] && interfaces=$(ip -o link show | awk -F': ' '{print $2}' | grep -v lo)
        if [ -z "$interfaces" ]; then
            log_error "没有可用的网络接口"
            return 1
        fi

        local iface_list=($interfaces)
        for i in "${!iface_list[@]}"; do
            local iface="${iface_list[$i]}"
            local ip=$(ip -4 addr show $iface 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.\d+){3}/\d+' || echo "无IP")
            local state=$(cat /sys/class/net/$iface/operstate 2>/dev/null || echo "未知")
            echo -e "${gl_bufan}$(($i + 1)).${gl_bai} ${gl_bai}$iface${gl_bai} (IP: ${gl_lv}$ip${gl_bai}, 状态: ${gl_bai}$state${gl_bai})"
        done
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请选择接口编号(${gl_huang}1${gl_bai}-${gl_hong}${#iface_list[@]}${gl_bai})或输入接口名(${gl_huang}0${gl_bai}返回): ")" choice

        [[ "$choice" == "0" ]] && { cancel_return; return 1; }

        local interface=""
        if [[ "$choice" =~ ^[0-9]+$ ]] && [ "$choice" -ge 1 ] && [ "$choice" -le ${#iface_list[@]} ]; then
            interface="${iface_list[$((choice - 1))]}"
        elif echo "$interfaces" | grep -q "^$choice$"; then
            interface="$choice"
        else
            log_error "无效的选择!"
            continue
        fi

        [ -d "/sys/class/net/$interface" ] && break || log_error "接口 '$interface' 不存在!"
    done

    echo ""
    echo -e "${gl_zi}>>> 配置IP地址信息${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    local current_ip=$(ip -4 addr show $interface 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.\d+){3}/\d+' | head -1)

    # 获取IP地址（CIDR格式）
    while true; do
        if [ -n "$current_ip" ]; then
            read -r -e -p "$(echo -e "${gl_bai}请输入IP地址和子网掩码 (格式: 192.168.1.100/24) [当前: ${gl_huang}$current_ip${gl_bai}]: ")" ip_address
        else
            read -r -e -p "$(echo -e "${gl_bai}请输入IP地址和子网掩码 (格式: 192.168.1.100/24): ")" ip_address
        fi

        [ -z "$ip_address" ] && [ -n "$current_ip" ] && ip_address="$current_ip"
        [ -z "$ip_address" ] && log_error "IP地址不能为空!" && continue

        if [[ "$ip_address" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+/[0-9]+$ ]]; then
            local ip_part=$(echo "$ip_address" | cut -d'/' -f1)
            local prefix=$(echo "$ip_address" | cut -d'/' -f2)

            [ "$prefix" -lt 1 ] || [ "$prefix" -gt 32 ] && log_error "子网掩码必须在1-32之间!" && continue

            IFS='.' read -r -a ip_parts <<<"$ip_part"
            local valid=1
            for part in "${ip_parts[@]}"; do
                [ "$part" -lt 0 ] || [ "$part" -gt 255 ] && valid=0 && break
            done

            [ $valid -eq 1 ] && break || log_error "IP地址格式不正确! 每个部分必须在0-255之间"
        else
            log_error "IP地址格式不正确! 示例: 192.168.1.100/24"
        fi
    done

    # 获取网关
    local current_gateway=$(ip route | grep default | awk '{print $3}' | head -1)
    while true; do
        echo ""
        if [ -n "$current_gateway" ]; then
            read -r -e -p "$(echo -e "${gl_bai}请输入网关地址 [当前: ${gl_huang}$current_gateway${gl_bai}]: ")" gateway
        else
            read -r -e -p "$(echo -e "${gl_bai}请输入网关地址: ")" gateway
        fi

        [ -z "$gateway" ] && [ -n "$current_gateway" ] && gateway="$current_gateway"
        [ -z "$gateway" ] && log_error "网关地址不能为空!" && continue

        if [[ "$gateway" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
            IFS='.' read -r -a gateway_parts <<<"$gateway"
            local valid=1
            for part in "${gateway_parts[@]}"; do
                [ "$part" -lt 0 ] || [ "$part" -gt 255 ] && valid=0 && break
            done
            [ $valid -eq 1 ] && break || log_error "网关地址格式不正确! 每个部分必须在0-255之间"
        else
            log_error "网关地址格式不正确!"
        fi
    done

    # DNS 配置（systemd-resolved 检测）
    local resolved_used="no"
    if [ "$(detect_resolved)" = "yes" ]; then
        echo ""
        log_warn "检测到systemd-resolved服务"
        log_info "Ubuntu 25.04默认使用systemd-resolved管理DNS"
        log_info "建议使用127.0.0.53作为DNS服务器"
        echo ""

        read -r -e -p "$(echo -e "${gl_bai}是否使用systemd-resolved (127.0.0.53) 作为DNS? (${gl_lv}Y${gl_bai}/${gl_hong}n${gl_bai}) [默认: Y]: ")" use_resolved

        if [[ ! "$use_resolved" =~ ^[Nn]$ ]]; then
            resolved_used="yes"
            dns_servers="127.0.0.53"
            log_info "将使用 systemd-resolved (127.0.0.53) 作为DNS服务器"
        fi
    fi

    if [ "$resolved_used" = "no" ]; then
        echo ""
        echo -e "${gl_zi}>>> 配置DNS服务器${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}阿里DNS: 223.5.5.5, 223.6.6.6${gl_bai}"
        echo -e "${gl_bufan}2.  ${gl_bai}谷歌DNS: 8.8.8.8, 8.8.4.4${gl_bai}"
        echo -e "${gl_bufan}3.  ${gl_bai}Cloudflare: 1.1.1.1, 1.0.0.1${gl_bai}"
        echo -e "${gl_bufan}4.  ${gl_bai}使用当前DNS${gl_bai}"
        echo -e "${gl_bufan}5.  ${gl_bai}自定义输入${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        while true; do
            read -r -e -p "$(echo -e "${gl_bai}请选择DNS选项 (${gl_huang}1${gl_bai}-${gl_hong}5${gl_bai}): ")" dns_choice

            case "$dns_choice" in
            1)
                dns_servers="223.5.5.5,223.6.6.6"
                log_info "已选择: 阿里DNS"
                break
                ;;
            2)
                dns_servers="8.8.8.8,8.8.4.4"
                log_info "已选择: 谷歌DNS"
                break
                ;;
            3)
                dns_servers="1.1.1.1,1.0.0.1"
                log_info "已选择: Cloudflare DNS"
                break
                ;;
            4)
                dns_servers=""
                [ -f /etc/resolv.conf ] && dns_servers=$(grep -E '^nameserver' /etc/resolv.conf 2>/dev/null | awk '{print $2}' | tr '\n' ',' | sed 's/,$//')
                [ -z "$dns_servers" ] && dns_servers="127.0.0.53"
                [ -n "$dns_servers" ] && log_info "使用当前DNS: $dns_servers" && break || log_error "未找到当前DNS配置"
                ;;
            5)
                read -r -e -p "$(echo -e "${gl_bai}请输入DNS服务器,多个用逗号分隔 (如: 8.8.8.8,1.1.1.1): ")" custom_dns
                if [ -n "$custom_dns" ]; then
                    dns_servers=$(echo "$custom_dns" | tr -d ' ')
                    local valid=1
                    IFS=',' read -ra dns_array <<<"$dns_servers"
                    for dns in "${dns_array[@]}"; do
                        [[ ! "$dns" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]] && valid=0 && break
                    done
                    [ $valid -eq 1 ] && break || log_error "DNS服务器格式不正确!"
                else
                    log_error "DNS服务器不能为空!"
                fi
                ;;
            0) cancel_return; return 0 ;;
            *) handle_invalid_input ;;
            esac
        done
    fi

    # 计算子网掩码
    local ip_part=$(echo "$ip_address" | cut -d'/' -f1)
    local prefix=$(echo "$ip_address" | cut -d'/' -f2)
    local netmask=""
    case $prefix in
    8) netmask="255.0.0.0" ;;
    16) netmask="255.255.0.0" ;;
    24) netmask="255.255.255.0" ;;
    32) netmask="255.255.255.255" ;;
    *)
        local full=$((0xffffffff << (32 - $prefix) & 0xffffffff))
        netmask="$((full >> 24 & 0xff)).$((full >> 16 & 0xff)).$((full >> 8 & 0xff)).$((full & 0xff))"
        ;;
    esac

    # 配置摘要与确认
    echo ""
    echo -e "${gl_zi}>>> 配置摘要${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}网络接口:   ${gl_lv}$interface${gl_bai}"
    echo -e "${gl_bai}IP地址:     ${gl_lv}$ip_address${gl_bai}"
    echo -e "${gl_bai}网关:       ${gl_lv}$gateway${gl_bai}"
    if [ "$resolved_used" = "yes" ]; then
        echo -e "${gl_bai}DNS服务器:  ${gl_lv}127.0.0.53 (systemd-resolved)${gl_bai}"
    else
        echo -e "${gl_bai}DNS服务器:  ${gl_lv}$dns_servers${gl_bai}"
    fi
    echo -e "${gl_bai}子网掩码:   ${gl_lv}$netmask${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}是否确认上述配置? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    [[ ! "$confirm" =~ ^[Yy]$ ]] && log_info "配置已取消" && return 0
    echo ""

    # ------------------------------------------------------------
    # 内部函数：ifupdown 静态IP配置
    _configure_static_ip_ifupdown() {
        local iface="$1"
        local ip_cidr="$2"
        local gw="$3"
        local dns="$4"
        local nm="$5"
        local interfaces_file="/etc/network/interfaces"
        local backup_file="${interfaces_file}.bak.$(date +%Y%m%d%H%M%S)"
        local tmp_file="${interfaces_file}.tmp"

        # 备份
        cp "$interfaces_file" "$backup_file"
        log_info "已备份原文件到: $backup_file"

        # 逐行过滤，彻底删除该接口所有相关行
        local in_block=0
        >"$tmp_file" # 清空临时文件

        while IFS= read -r line || [ -n "$line" ]; do
            # 检测是否进入目标接口块
            if [[ "$line" =~ ^[[:space:]]*(auto|allow-hotplug)[[:space:]]+$iface([[:space:]]|$) ]]; then
                # 跳过 auto/allow-hotplug 行
                continue
            fi
            if [[ "$line" =~ ^[[:space:]]*iface[[:space:]]+$iface[[:space:]]+inet[[:space:]]+(static|dhcp) ]]; then
                in_block=1
                continue
            fi

            # 如果在接口块内，跳过所有缩进行（以空格或tab开头）
            if [ $in_block -eq 1 ]; then
                if [[ "$line" =~ ^[[:space:]]+ ]]; then
                    continue
                else
                    # 遇到非缩进行，表示块结束
                    in_block=0
                fi
            fi

            # 不在目标块内，正常写入
            echo "$line" >>"$tmp_file"
        done <"$interfaces_file"

        # 追加新配置块
        {
            echo ""
            echo "# 静态IP配置 by configure_static_ip ($(date '+%Y-%m-%d %H:%M:%S'))"
            echo "auto $iface"
            echo "iface $iface inet static"
            echo "    address ${ip_cidr%/*}"
            echo "    netmask $nm"
            echo "    gateway $gw"

            # DNS处理：检测是否支持 dns-nameservers
            if [ -n "$dns" ]; then
                if command -v resolvconf &>/dev/null; then
                    IFS=',' read -ra dns_array <<<"$dns"
                    echo -n "    dns-nameservers"
                    for dns_ip in "${dns_array[@]}"; do
                        echo -n " $dns_ip"
                    done
                    echo ""
                else
                    log_warn "未安装 resolvconf，dns-nameservers 选项将被忽略"
                    log_warn "将直接写入 /etc/resolv.conf（临时生效）"
                    if [ -f /etc/resolv.conf ] && [ ! -f /etc/resolv.conf.bak ]; then
                        cp /etc/resolv.conf /etc/resolv.conf.bak
                    fi
                    >/etc/resolv.conf
                    IFS=',' read -ra dns_array <<<"$dns"
                    for dns_ip in "${dns_array[@]}"; do
                        echo "nameserver $dns_ip" >>/etc/resolv.conf
                    done
                fi
            fi
        } >>"$tmp_file"

        # 用临时文件替换原文件
        mv "$tmp_file" "$interfaces_file"
        log_ok "接口 $iface 静态配置已写入 $interfaces_file"

        # 重启网络
        local restart_ok=1
        if systemctl list-unit-files 2>/dev/null | grep -q networking.service; then
            log_info "重启 networking 服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            systemctl restart networking && restart_ok=0
        else
            if command -v ifdown &>/dev/null && command -v ifup &>/dev/null; then
                log_info "执行 ifdown $iface && ifup $iface ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                ifdown "$iface" 2>/dev/null || true
                ifup "$iface" && restart_ok=0
            else
                log_error "ifdown/ifup 命令不可用"
            fi
        fi

        [ $restart_ok -eq 0 ] && log_ok "网络服务重启成功" || log_error "网络服务重启失败，请手动执行: systemctl restart networking 或 ifdown $iface && ifup $iface"
        return $restart_ok
    }

    # ------------------------------------------------------------
    # 内部函数：CentOS/RHEL/Fedora network-scripts 配置
    _configure_static_ip_network_scripts() {
        local iface="$1"
        local ip_cidr="$2"
        local gw="$3"
        local dns="$4"
        local nm="$5"
        local config_dir="/etc/sysconfig/network-scripts"
        local config_file="$config_dir/ifcfg-$iface"
        local backup_file="$config_file.bak.$(date +%Y%m%d%H%M%S)"
        local ip_part=$(echo "$ip_cidr" | cut -d'/' -f1)
        local prefix=$(echo "$ip_cidr" | cut -d'/' -f2)

        # 检查目录是否存在
        if [ ! -d "$config_dir" ]; then
            log_error "network-scripts目录不存在: $config_dir"
            log_error "CentOS 9可能已默认使用NetworkManager，请安装network-scripts包"
            log_info "安装命令: sudo dnf install network-scripts"
            exit_animation    # 即将退出动画
            return 1
        fi

        # 备份原配置文件
        if [ -f "$config_file" ]; then
            cp "$config_file" "$backup_file"
            log_info "已备份原配置文件到: $backup_file"
        fi

        # 创建或修改配置文件
        cat >"$config_file" <<EOF
# 静态IP配置 by configure_static_ip ($(date '+%Y-%m-%d %H:%M:%S'))
TYPE=Ethernet
PROXY_METHOD=none
BROWSER_ONLY=no
BOOTPROTO=none
DEFROUTE=yes
IPV4_FAILURE_FATAL=no
IPV6INIT=yes
IPV6_AUTOCONF=yes
IPV6_DEFROUTE=yes
IPV6_FAILURE_FATAL=no
IPV6_ADDR_GEN_MODE=stable-privacy
NAME=$iface
DEVICE=$iface
ONBOOT=yes
IPADDR=$ip_part
PREFIX=$prefix
NETMASK=$nm
GATEWAY=$gw
DNS1=$(echo "$dns" | cut -d',' -f1)
EOF

        # 添加第二个DNS服务器（如果有）
        local dns2=$(echo "$dns" | cut -d',' -f2)
        if [ -n "$dns2" ]; then
            echo "DNS2=$dns2" >>"$config_file"
        fi

        # 添加第三个DNS服务器（如果有）
        local dns3=$(echo "$dns" | cut -d',' -f3)
        if [ -n "$dns3" ]; then
            echo "DNS3=$dns3" >>"$config_file"
        fi

        # 设置权限
        chmod 644 "$config_file"
        log_ok "接口 $iface 静态配置已写入 $config_file"

        # 重启网络服务
        local restart_ok=1
        log_info "重启网络服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 尝试多种重启方式
        if systemctl is-active NetworkManager >/dev/null 2>&1; then
            # 如果NetworkManager正在运行，优先使用nmcli
            log_info "检测到NetworkManager，使用nmcli重启连接"
            if command -v nmcli >/dev/null 2>&1; then
                nmcli connection down "$iface" 2>/dev/null || true
                nmcli connection up "$iface" && restart_ok=0
            fi
        fi

        # 如果nmcli失败或不存在，尝试使用network服务
        if [ $restart_ok -ne 0 ]; then
            if systemctl list-unit-files 2>/dev/null | grep -q "network.service"; then
                systemctl restart network && restart_ok=0
            fi
        fi

        # 如果network服务也不存在，尝试使用nmcli重新加载配置
        if [ $restart_ok -ne 0 ] && command -v nmcli >/dev/null 2>&1; then
            log_info "重新加载NetworkManager配置"
            nmcli connection reload
            nmcli connection up "$iface" && restart_ok=0
        fi

        [ $restart_ok -eq 0 ] && log_ok "网络服务重启成功" || log_error "网络服务重启失败，请手动执行: systemctl restart network 或 nmcli connection up $iface"
        return $restart_ok
    }

    # ------------------------------------------------------------
    # 内部函数：验证IP配置
    _verify_ip_config() {
        local expected_ip="$1"
        local expected_gw="$2"
        local max_retry=8
        local retry=0

        log_info "验证网络配置，等待网络重启 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        sleep_fractional 3

        while [[ $retry -lt $max_retry ]]; do
            local current_ip
            current_ip=$(ip -4 addr show "$interface" 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.\d+){3}/\d+' | head -1)
            local current_gw
            current_gw=$(ip route | grep '^default' | head -1 | awk '{print $3}')

            if [[ -n "$current_ip" && "$current_ip" == "$expected_ip" ]] &&
                [[ -n "$current_gw" && "$current_gw" == "$expected_gw" ]]; then
                log_ok "IP与网关配置成功: IP=${gl_lv}$current_ip${gl_bai}, 网关=${gl_lv}$current_gw${gl_bai}"
                return 0
            fi

            ((retry++))
            log_info "等待网络配置生效 (${retry}/${max_retry}) ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            sleep_fractional 2
        done

        local final_ip=$(ip -4 addr show "$interface" 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.\d+){3}/\d+' | head -1)
        local final_gw=$(ip route | grep '^default' | head -1 | awk '{print $3}')
        log_error "配置验证失败"
        log_error "当前IP: ${gl_hong}${final_ip:-无}${gl_bai} (期望: ${gl_lv}$expected_ip${gl_bai})"
        log_error "当前网关: ${gl_hong}${final_gw:-无}${gl_bai} (期望: ${gl_lv}$expected_gw${gl_bai})"
        return 1
    }

    # ------------------------------------------------------------
    # 检测网络管理工具并应用配置
    local net_manager=$(detect_network_manager)
    log_info "检测到网络管理工具: $net_manager"

    case "$net_manager" in
    "netplan")
        # 假设已有 configure_static_ip_netplan 函数
        configure_static_ip_netplan "$interface" "$ip_address" "$gateway" "$dns_servers"
        local result=$?
        ;;
    "ifupdown")
        log_info "使用 ifupdown (/etc/network/interfaces) 配置静态IP"
        _configure_static_ip_ifupdown "$interface" "$ip_address" "$gateway" "$dns_servers" "$netmask"
        local result=$?
        ;;
    "NetworkManager")
        # CentOS 9 的 NetworkManager 配置
        log_info "使用 NetworkManager 配置静态IP"
        if command -v nmcli >/dev/null 2>&1; then
            log_info "使用 nmcli 配置静态IP"

            # 获取连接名称
            local conn_name=$(nmcli -t -f NAME,DEVICE connection show | grep ":$interface$" | cut -d: -f1)
            if [ -z "$conn_name" ]; then
                conn_name="$interface"
            fi

            # 配置静态IP
            nmcli connection modify "$conn_name" ipv4.method manual \
                ipv4.address "$ip_address" \
                ipv4.gateway "$gateway" \
                ipv4.dns "$(echo "$dns_servers" | tr ',' ' ')" \
                connection.autoconnect yes

            # 重启连接
            nmcli connection down "$conn_name" 2>/dev/null || true
            nmcli connection up "$conn_name"
            result=$?

            if [ $result -eq 0 ]; then
                log_ok "NetworkManager 配置成功"
            else
                log_error "NetworkManager 配置失败"
            fi
        else
            log_error "nmcli 命令不可用，无法配置 NetworkManager"
            result=1
        fi
        ;;
    "network-scripts")
        log_info "使用 network-scripts (CentOS/RHEL) 配置静态IP"
        _configure_static_ip_network_scripts "$interface" "$ip_address" "$gateway" "$dns_servers" "$netmask"
        local result=$?
        ;;
    *)
        log_error "不支持的网络管理工具: $net_manager"
        return 1
        ;;
    esac

    # 验证并显示结果
    if [ $result -eq 0 ]; then
        echo ""
        log_ok "静态IP配置已应用!"
        _verify_ip_config "$ip_address" "$gateway"

        echo ""
        echo -e "${gl_zi}>>> 当前网络状态${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_info "网络接口 $interface 的IP配置:"
        ip addr show $interface 2>/dev/null | grep "inet " || echo -e "${gl_huang}警告: 未找到IP地址配置${gl_bai}"

        echo ""
        log_info "默认网关:"
        ip route | grep default || echo -e "${gl_huang}警告: 未找到默认网关${gl_bai}"

        echo ""
        if [ "$(detect_resolved)" = "yes" ]; then
            log_info "DNS配置 (systemd-resolved):"
            resolvectl status 2>/dev/null | grep -A5 "Global" | grep "DNS Server" || echo -e "${gl_huang}警告: 无法读取DNS配置${gl_bai}"
        else
            log_info "DNS配置:"
            cat /etc/resolv.conf 2>/dev/null | grep "nameserver" || echo -e "${gl_huang}警告: 无法读取DNS配置${gl_bai}"
        fi

        echo ""
        log_info "网络连接测试:"
        if ping -c 2 -W 1 8.8.8.8 &>/dev/null; then
            echo -e "${gl_lv}✓ 外网连接正常${gl_bai}"
        else
            echo -e "${gl_huang}⚠ 外网连接失败，请检查网关和DNS配置${gl_bai}"
        fi
    else
        log_error "配置应用失败，请检查网络配置"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 完整的网关设置函数
# ==================== 完整的网关设置函数（修复版）====================
set_gateway() {
    local gateway="$1"
    local interface="$2"
    local exit_code=0

    # 检查是否以root权限运行
    root_use
    # install yq 2>/dev/null || true   # 可选安装，失败不影响后续

    # 显示当前网关地址
    echo -e "${gl_zi}>>> 配置网关地址${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    show_system_info

    # 如果未提供网关IP，交互式询问
    if [[ -z "$gateway" ]]; then
        if [[ -t 0 ]]; then
            read -r -e -p "$(echo -e "${gl_bai}请输入网关IP地址 (${gl_huang}0${gl_bai}返回): ")" gateway
            [[ "$gateway" == "0" ]] && { cancel_return; return 1; }
            echo ""
        else
            log_error "必须指定网关IP地址"
            echo -e "用法: ${gl_lv}set_gateway <网关IP> [网卡名称]${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        fi
    fi

    # 验证IP地址格式
    if ! [[ "$gateway" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
        log_error "网关IP地址格式不正确: ${gl_hong}$gateway${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 显示可用的网络接口
    echo -e "${gl_huang}可用的网络接口:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if command -v ip &>/dev/null; then
        ip -o link show | awk -F': ' '{print $2}' | grep -v lo
    elif command -v ifconfig &>/dev/null; then
        ifconfig -a | grep -E '^[a-zA-Z0-9]' | cut -d' ' -f1 | grep -v lo
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 如果没有指定网卡，尝试自动检测
    if [[ -z "$interface" ]]; then
        # 尝试多种方法检测默认网卡
        if command -v ip &>/dev/null; then
            interface=$(ip route | grep default | head -1 | awk '{print $5}')
        elif command -v route &>/dev/null; then
            interface=$(route -n | grep '^0\.0\.0\.0' | head -1 | awk '{print $8}')
        fi

        if [[ -n "$interface" ]]; then
            echo -e "检测到默认网卡: ${gl_lv}$interface${gl_bai}"
            if [[ -t 0 ]]; then
                read -r -e -p "$(echo -e "${gl_bai}是否使用此网卡? (${gl_lv}Y${gl_bai}/${gl_hong}n${gl_bai}) [默认Y]: ")" use_detected
                use_detected="${use_detected:-Y}"
                if [[ "$use_detected" =~ ^[Nn]$ ]]; then
                    interface=""
                fi
            fi
        fi

        if [[ -z "$interface" ]] && [[ -t 0 ]]; then
            echo ""
            read -r -e -p "$(echo -e "${gl_bai}请输入网卡名称 (${gl_huang}0${gl_bai}返回): ")" interface
            [[ "$interface" == "0" ]] && { cancel_return; return 1; }
        fi

        if [[ -z "$interface" ]]; then
            log_error "必须指定网卡名称"
            exit_animation    # 即将退出动画
            return 1
        fi
    fi

    # 检查网卡是否存在
    if ! ip link show "$interface" &>/dev/null 2>&1 && ! ifconfig "$interface" &>/dev/null 2>&1; then
        log_error "网卡 ${gl_hong}$interface${gl_bai} 不存在或不可用"
        exit_animation    # 即将退出动画
        return 1
    fi

    echo ""
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_huang}将要进行以下配置:${gl_bai}"
    echo -e "  网关IP地址: ${gl_lv}$gateway${gl_bai}"
    echo -e "  网络接口: ${gl_lv}$interface${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 确认配置
    if [[ -t 0 ]]; then
        read -r -e -p "$(echo -e "${gl_bai}确认使用该配置吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}) [默认N]: ")" confirm
        confirm="${confirm:-N}"
        if [[ ! "$confirm" =~ ^[Yy]$ ]]; then
            log_info "操作已取消"
            return 0
        fi
    fi

    # ------------------------------------------------------------
    # 内部函数：验证网关设置（增强版）
    _verify_gateway() {
        local expected_gateway="$1"
        local max_retry=8 # FIXED: 增加重试次数，给netplan更多生效时间
        local retry=0

        log_info "验证网关设置，等待路由生效 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        sleep_fractional 2 # 首次等待

        while [[ $retry -lt $max_retry ]]; do
            local current_gateway=""
            if command -v ip &>/dev/null; then
                current_gateway=$(ip route | grep '^default' | head -1 | awk '{print $3}')
            elif command -v route &>/dev/null; then
                current_gateway=$(route -n | grep '^0\.0\.0\.0' | awk '{print $2}' | head -1)
            else
                log_error "无法获取当前网关信息"
                exit_animation    # 即将退出动画
                return 1
            fi

            if [[ -n "$current_gateway" ]]; then
                if [[ "$current_gateway" == "$expected_gateway" ]]; then
                    log_ok "网关设置成功: ${gl_lv}$current_gateway${gl_bai}"
                    # 测试网关连通性（可选）
                    if ping -c 1 -W 1 "$expected_gateway" &>/dev/null; then
                        log_ok "网关 ${gl_lv}$expected_gateway${gl_bai} 可达"
                    else
                        log_warn "网关 ${gl_lv}$expected_gateway${gl_bai} 不可达，但配置已生效"
                    fi
                    return 0
                fi
            fi
            ((retry++))
            log_info "等待路由更新 (${retry}/${max_retry}) ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            sleep_fractional 2
        done

        # 最终检查
        local final_gateway
        final_gateway=$(ip route | grep '^default' | head -1 | awk '{print $3}')
        if [[ -z "$final_gateway" ]]; then
            log_error "未找到默认网关"
        else
            log_error "网关设置失败，当前网关为: ${gl_hong}$final_gateway${gl_bai} (期望: ${gl_lv}$expected_gateway${gl_bai})"
        fi
        return 1
    }

    # ------------------------------------------------------------
    # 内部函数：专门处理 netplan 配置（彻底修复）
    _modify_netplan() {
        local gateway="$1"
        local interface="$2"
        local netplan_file="$3"
        local backup_file="${netplan_file}.bak.$(date +%Y%m%d%H%M%S)"

        # 备份
        cp "$netplan_file" "$backup_file"
        log_info "已备份原文件到: ${gl_lv}$backup_file${gl_bai}"

        # ---------- 方案1：使用 netplan set 命令（最推荐，Ubuntu 20.04+）----------
        if command -v netplan &>/dev/null && netplan set --help &>/dev/null; then
            log_info "使用 netplan set 命令修改配置"
            # 删除旧网关和路由，设置新路由
            netplan set "network.ethernets.$interface.gateway4=null" 2>/dev/null
            netplan set "network.ethernets.$interface.routes=null" 2>/dev/null
            netplan set --origin-hint "$(basename "$netplan_file" .yaml)" \
                "network.ethernets.$interface.routes=[{to: 0.0.0.0/0, via: $gateway}]" && {
                log_ok "netplan set 修改成功"
                return 0
            }
            log_warn "netplan set 失败，尝试其他方法"
        fi

        # ---------- 方案2：使用 yq（兼容两种常见版本）----------
        if command -v yq &>/dev/null; then
            log_info "尝试使用 yq 工具修改 netplan 配置"
            local yq_success=1

            # 检测 yq 版本（go版支持 eval -i，python版不支持）
            if yq --version 2>&1 | grep -q "mikefarah"; then
                # go 版 yq (mikefarah/yq)
                yq eval -i "
                    del(.network.ethernets.$interface.gateway4) |
                    del(.network.ethernets.$interface.routes) |
                    .network.ethernets.$interface.routes = [{\"to\": \"0.0.0.0/0\", \"via\": \"$gateway\"}]
                " "$netplan_file" && yq_success=0
            else
                # python 版 yq (jq 封装) 或其它
                # 使用临时文件，因为 python-yq 不支持 -i
                local tmp_yq="${netplan_file}.tmp"
                if yq -y "
                    del(.network.ethernets.$interface.gateway4) |
                    del(.network.ethernets.$interface.routes) |
                    .network.ethernets.$interface.routes = [{\"to\": \"0.0.0.0/0\", \"via\": \"$gateway\"}]
                " "$netplan_file" >"$tmp_yq" 2>/dev/null; then
                    mv "$tmp_yq" "$netplan_file"
                    yq_success=0
                fi
            fi

            if [[ $yq_success -eq 0 ]]; then
                log_ok "yq 修改完成"
                return 0
            else
                log_warn "yq 修改失败，将使用手动重建方式"
            fi
        fi

        # ---------- 方案3：手动重建 YAML 块（稳健可靠）----------
        log_warn "使用手动重建方式修改 netplan 配置（将保留原IP地址）"
        # 提取当前接口的 IP 地址配置（静态IP）
        local current_addresses=""
        # 1. 从当前配置文件提取
        current_addresses=$(grep -A5 "^[[:space:]]*$interface:" "$netplan_file" | grep -oE '[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+/[0-9]+' | head -1)
        # 2. 如果未找到，从系统获取
        if [[ -z "$current_addresses" ]]; then
            current_addresses=$(ip -4 addr show "$interface" 2>/dev/null | grep inet | awk '{print $2}' | head -1)
        fi
        # 3. 如果仍然为空，提示用户手动设置
        if [[ -z "$current_addresses" ]]; then
            log_warn "未能自动获取接口IP，请稍后手动添加 addresses 行"
            current_addresses="请填写静态IP/掩码"
        fi

        # 创建新配置的临时文件
        local tmp_file="${netplan_file}.tmp"
        local in_interface_block=0
        local block_processed=0

        while IFS= read -r line; do
            # 检测是否进入目标接口块
            if [[ "$line" =~ ^[[:space:]]*$interface: ]]; then
                in_interface_block=1
                echo "$line" >>"$tmp_file"
                continue
            fi

            if [[ $in_interface_block -eq 1 ]]; then
                # 遇到下一个顶级键（非缩进行）或文件结束，结束接口块
                if [[ "$line" =~ ^[[:space:]]*[a-zA-Z0-9]+: ]] && [[ ! "$line" =~ ^[[:space:]]+ ]]; then
                    # 在块结束前写入我们需要的配置
                    cat <<EOF >>"$tmp_file"
      dhcp4: false
      addresses:
        - ${current_addresses}
      routes:
        - to: 0.0.0.0/0
          via: $gateway
EOF
                    in_interface_block=0
                    block_processed=1
                    echo "$line" >>"$tmp_file"
                else
                    # 跳过原块内的所有行（不保留 gateway4 和 routes）
                    continue
                fi
            else
                # 不在接口块内，直接写入
                echo "$line" >>"$tmp_file"
            fi
        done <"$netplan_file"

        # 如果文件结束但接口块未关闭（即接口在文件末尾）
        if [[ $in_interface_block -eq 1 ]] && [[ $block_processed -eq 0 ]]; then
            cat <<EOF >>"$tmp_file"
      dhcp4: false
      addresses:
        - ${current_addresses}
      routes:
        - to: 0.0.0.0/0
          via: $gateway
EOF
        fi

        # 替换原文件
        mv "$tmp_file" "$netplan_file"
        log_info "手动修改 netplan 配置完成"
        return 0
    }

    # ------------------------------------------------------------
    # 内部函数：Debian/Ubuntu系统（netplan & ifupdown）
    _set_gateway_debian() {
        local gateway="$1"
        local interface="$2"
        local result=0

        log_info "配置Debian/Ubuntu系统网关 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # ---- 处理 netplan ----
        if [[ -d /etc/netplan ]]; then
            local netplan_file
            netplan_file=$(ls /etc/netplan/*.yaml 2>/dev/null | head -1)
            if [[ -n "$netplan_file" ]]; then
                _modify_netplan "$gateway" "$interface" "$netplan_file"

                # 显示修改后的配置片段（便于调试）
                log_info "修改后的 netplan 配置（接口 $interface）:"
                sed -n "/^[[:space:]]*$interface:/,/^[[:space:]]*[a-zA-Z0-9]\\+:/p" "$netplan_file" | head -20
                echo ""

                # 询问是否应用
                if [[ -t 0 ]]; then
                    read -r -e -p "$(echo -e "${gl_bai}是否应用netplan配置? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}) [默认Y]: ")" apply_netplan
                    apply_netplan="${apply_netplan:-Y}"
                else
                    apply_netplan="Y"
                fi

                if [[ "$apply_netplan" =~ ^[Yy]$ ]]; then
                    log_info "应用 netplan 配置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    # FIXED: 先 generate 再 apply，更可靠
                    if netplan generate && netplan apply; then
                        log_ok "netplan 配置应用成功"
                        # 可选：重启 systemd-networkd 以立即生效
                        systemctl restart systemd-networkd 2>/dev/null || true
                    else
                        log_error "netplan apply 执行失败，请检查配置文件"
                        exit_animation    # 即将退出动画
                        return 1
                    fi
                else
                    log_warn "未应用 netplan 配置，请手动执行: sudo netplan apply"
                    exit_animation    # 即将退出动画
                    return 1
                fi
            else
                log_error "未找到 netplan 配置文件"
                exit_animation    # 即将退出动画
                return 1
            fi

        # ---- 处理传统的 /etc/network/interfaces ----
        elif [[ -f /etc/network/interfaces ]]; then
            local backup_file="/etc/network/interfaces.bak.$(date +%Y%m%d%H%M%S)"
            cp /etc/network/interfaces "$backup_file"
            log_info "已备份原文件到: $backup_file"

            # 清理该接口下的旧 gateway 行，添加新 gateway
            if grep -q "^iface $interface" /etc/network/interfaces; then
                sed -i "/^iface $interface/,/^iface\|^auto\|^$/ s/^[[:space:]]*gateway.*//" /etc/network/interfaces
                sed -i "/^iface $interface/a\    gateway $gateway" /etc/network/interfaces
            else
                cat <<EOF >>/etc/network/interfaces

# 添加的网关配置
auto $interface
iface $interface inet static
    gateway $gateway
EOF
            fi

            # 重启网络服务
            if systemctl list-unit-files | grep -q networking; then
                systemctl restart networking
            elif systemctl list-unit-files | grep -q network-manager; then
                systemctl restart network-manager
            else
                ifdown "$interface" && ifup "$interface"
            fi
            log_ok "网关持久化配置已更新"
        else
            log_error "未找到任何网络配置文件"
            exit_animation    # 即将退出动画
            return 1
        fi

        return 0
    }

    # ------------------------------------------------------------
    # 其他发行版的配置函数（略作简化，实际使用时可保留原有完整实现）
    _set_gateway_redhat() {
        log_info "配置RedHat系系统网关 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        # 此处保留原有实现（略）
        # 示例：修改 /etc/sysconfig/network-scripts/ifcfg-* 并重启网络
        return 0
    }

    _set_gateway_arch() {
        log_info "配置ArchLinux系统网关 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        # 保留原有实现
        return 0
    }

    _set_gateway_suse() {
        log_info "配置SuSE系统网关 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        # 保留原有实现
        return 0
    }

    _set_gateway_generic() {
        log_warn "使用通用方法（临时路由） ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        ip route del default &>/dev/null || true
        ip route add default via "$1" dev "$2"
        # 尝试写入 /etc/rc.local 等（略）
        return 0
    }

    # ------------------------------------------------------------
    # 检测操作系统并调用对应函数
    local os_info
    os_info=$(lsb_release -si 2>/dev/null || cat /etc/os-release 2>/dev/null | grep -E '^NAME=' | cut -d'"' -f2 || uname -o 2>/dev/null || echo "未知")
    log_info "检测到操作系统: ${gl_lv}$os_info${gl_bai}"

    if [[ -f /etc/debian_version ]]; then
        _set_gateway_debian "$gateway" "$interface"
        exit_code=$?
    elif [[ -f /etc/redhat-release ]] || [[ -f /etc/centos-release ]]; then
        _set_gateway_redhat "$gateway" "$interface"
        exit_code=$?
    elif [[ -f /etc/arch-release ]]; then
        _set_gateway_arch "$gateway" "$interface"
        exit_code=$?
    elif [[ -f /etc/SuSE-release ]] || [[ -f /etc/os-release && $(grep -i opensuse /etc/os-release 2>/dev/null) ]]; then
        _set_gateway_suse "$gateway" "$interface"
        exit_code=$?
    else
        log_warn "未知的Linux发行版，尝试通用方法"
        _set_gateway_generic "$gateway" "$interface"
        exit_code=$?
    fi

    # 验证网关设置（仅当配置步骤成功时）
    if [[ $exit_code -eq 0 ]]; then
        _verify_gateway "$gateway"
        exit_code=$?
    else
        log_error "网关配置过程出现错误，跳过验证"
    fi

    # ------------------------------------------------------------
    # 统一调用 break_end（仅交互终端）
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if [[ -t 0 ]]; then
        break_end
    fi

    return $exit_code
}

# 查看当前网络接口函数
show_network_interfaces() {
    echo -e ""
    echo -e "${gl_zi}>>> 查看当前网络接口${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    ip link show
    echo ""
    echo -e "${gl_huang}详细信息:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    ip addr show
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 查看路由表函数
show_routing_table() {
