# 测试网络连接函数
test_network_connectivity() {
    echo -e ""
    echo -e "${gl_zi}>>> 测试网络连接${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 测试本地回环
    echo -e "${gl_bai}测试本地回环 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if ping -c 2 127.0.0.1 &>/dev/null; then
        echo -e "${gl_lv}✓ 本地回环正常${gl_bai}"
    else
        echo -e "${gl_hong}✗ 本地回环失败${gl_bai}"
    fi

    # 获取网关
    local gateway=$(ip route | grep default | awk '{print $3}' | head -1)
    if [ -n "$gateway" ]; then
        echo -e "${gl_bai}测试网关 $gateway ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if ping -c 2 -W 1 $gateway &>/dev/null; then
            echo -e "${gl_lv}✓ 网关可达${gl_bai}"
        else
            echo -e "${gl_hong}✗ 网关不可达${gl_bai}"
        fi
    else
        echo -e "${gl_huang}⚠ 未找到默认网关${gl_bai}"
    fi

    # 测试DNS
    echo -e "${gl_bai}测试DNS解析 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if timeout 2 nslookup google.com &>/dev/null; then
        echo -e "${gl_lv}✓ DNS解析正常${gl_bai}"
    else
        echo -e "${gl_hong}✗ DNS解析失败${gl_bai}"
    fi

    # 测试外网连接
    echo -e "${gl_bai}测试外网连接 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if timeout 3 curl -s --connect-timeout 2 http://connectivitycheck.gstatic.com/generate_204 &>/dev/null; then
        echo -e "${gl_lv}✓ 外网连接正常${gl_bai}"
    else
        echo -e "${gl_hong}✗ 外网连接失败${gl_bai}"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 修复systemd-resolved DNS配置
fix_dns_config() {
    echo -e ""
    echo -e "${gl_zi}>>> 修复systemd-resolved DNS配置${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检测systemd-resolved
    if [ "$(detect_resolved)" != "yes" ]; then
        log_info "未检测到systemd-resolved服务"

        # 检查/etc/resolv.conf
        if [ -f /etc/resolv.conf ]; then
            echo ""
            echo -e "${gl_bai}当前DNS配置 (来自/etc/resolv.conf):${gl_bai}"
            grep -E '^nameserver' /etc/resolv.conf 2>/dev/null | while read line; do
                echo -e "  ${gl_bai}$line${gl_bai}"
            done

            echo ""
            read -r -e -p "$(echo -e "${gl_bai}是否修改当前DNS配置? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" modify_dns
            if [[ "$modify_dns" =~ ^[Yy]$ ]]; then
                echo ""
                echo -e "${gl_bai}请选择DNS服务器:${gl_bai}"
                echo -e "${gl_bufan}1. ${gl_bai}阿里DNS (223.5.5.5, 223.6.6.6)${gl_bai}"
                echo -e "${gl_bufan}2. ${gl_bai}谷歌DNS (8.8.8.8, 8.8.4.4)${gl_bai}"
                echo -e "${gl_bufan}3. ${gl_bai}Cloudflare (1.1.1.1, 1.0.0.1)${gl_bai}"
                echo -e "${gl_bufan}4. ${gl_bai}自定义DNS${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                read -r -e -p "$(echo -e "${gl_bai}请选择 (1-4): ")" dns_choice

                case "$dns_choice" in
                1)
                    dns1="223.5.5.5"
                    dns2="223.6.6.6"
                    ;;
                2)
                    dns1="8.8.8.8"
                    dns2="8.8.4.4"
                    ;;
                3)
                    dns1="1.1.1.1"
                    dns2="1.0.0.1"
                    ;;
                4)
                    read -r -e -p "$(echo -e "${gl_bai}请输入主DNS服务器: ")" dns1
                    read -r -e -p "$(echo -e "${gl_bai}请输入备用DNS服务器 (可选): ")" dns2
                    ;;
                *)
                    log_error "无效的选择"
                    break_end
                    return
                    ;;
                esac

                # 备份当前配置
                cp /etc/resolv.conf /etc/resolv.conf.backup.$(date +%Y%m%d%H%M%S) 2>/dev/null || true

                # 创建新的resolv.conf
                cat >/tmp/resolv.conf.new <<EOF
# Generated by network configuration script
nameserver $dns1
EOF

                if [ -n "$dns2" ]; then
                    echo "nameserver $dns2" >>/tmp/resolv.conf.new
                fi

                # 应用配置
                cp /tmp/resolv.conf.new /etc/resolv.conf
                rm -f /tmp/resolv.conf.new

                echo ""
                echo -e "${gl_bai}新的DNS配置:${gl_bai}"
                cat /etc/resolv.conf

                log_ok "DNS配置已更新"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
            fi
        fi

        return
    fi

    echo -e "${gl_bai}当前DNS配置:${gl_bai}"

    # 检查systemd-resolved状态
    if systemctl is-active systemd-resolved &>/dev/null; then
        echo -e "  ${gl_bufan}systemd-resolved 状态:${gl_bai} ${gl_lv}运行中${gl_bai}"
    elif systemctl is-enabled systemd-resolved &>/dev/null; then
        echo -e "  ${gl_bufan}systemd-resolved 状态:${gl_bai} ${gl_huang}已启用但未运行${gl_bai}"
    fi

    echo -e "${gl_bai}当前DNS服务器:${gl_bai}"
    if command -v resolvectl &>/dev/null; then
        resolvectl status 2>/dev/null | grep "DNS Server" | head -5 | while read line; do
            echo -e "  ${gl_bai}$(echo $line | sed 's/DNS Servers://g' | xargs)${gl_bai}"
        done
    else
        if [ -f /etc/resolv.conf ]; then
            grep -E '^nameserver' /etc/resolv.conf 2>/dev/null | while read line; do
                echo -e "  ${gl_bai}$line${gl_bai}"
            done
        fi
    fi

    echo ""
    echo -e "${gl_bai}请选择DNS服务器:${gl_bai}"
    echo -e "${gl_bufan}1. ${gl_bai}阿里DNS (223.5.5.5, 223.6.6.6)${gl_bai}"
    echo -e "${gl_bufan}2. ${gl_bai}谷歌DNS (8.8.8.8, 8.8.4.4)${gl_bai}"
    echo -e "${gl_bufan}3. ${gl_bai}Cloudflare (1.1.1.1, 1.0.0.1)${gl_bai}"
    echo -e "${gl_bufan}4. ${gl_bai}自定义DNS${gl_bai}"
    echo -e "${gl_bufan}5. ${gl_bai}恢复默认 (127.0.0.53)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请选择 (1-5): ")" dns_choice

    case "$dns_choice" in
    1)
        dns1="223.5.5.5"
        dns2="223.6.6.6"
        ;;
    2)
        dns1="8.8.8.8"
        dns2="8.8.4.4"
        ;;
    3)
        dns1="1.1.1.1"
        dns2="1.0.0.1"
        ;;
    4)
        read -r -e -p "$(echo -e "${gl_bai}请输入主DNS服务器: ")" dns1
        read -r -e -p "$(echo -e "${gl_bai}请输入备用DNS服务器 (可选): ")" dns2
        ;;
    5)
        # 恢复默认配置
        rm -f /etc/systemd/resolved.conf.d/*.conf
        systemctl restart systemd-resolved
        log_ok "已恢复systemd-resolved默认配置 (127.0.0.53)"
        break_end
        return
        ;;
    *)
        log_error "无效的选择"
        break_end
        return
        ;;
    esac

    # 创建配置目录
    mkdir -p /etc/systemd/resolved.conf.d/

    # 创建配置文件
    cat >/etc/systemd/resolved.conf.d/dns.conf <<EOF
[Resolve]
DNS=$dns1 $dns2
FallbackDNS=1.1.1.1 8.8.8.8
Domains=~.
DNSSEC=allow-downgrade
EOF

    # 重启服务
    systemctl restart systemd-resolved

    echo ""
    echo -e "${gl_bai}新的DNS配置:${gl_bai}"

    if command -v resolvectl &>/dev/null; then
        resolvectl status 2>/dev/null | grep -A5 "Global" | grep -E "DNS Server|Current DNS"
    else
        echo -e "${gl_huang}注意: 无法显示详细的DNS配置，但配置已应用${gl_bai}"
    fi

    log_ok "DNS配置已更新"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

