        2)
            bash <(curl -sSL https://linuxmirrors.cn/main.sh) --edu
            ;;
        3)
            bash <(curl -sSL https://linuxmirrors.cn/main.sh) --abroad
            ;;
        4)
            echo -e ""
            echo -e "${gl_zi}>>> 更新软件索引${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            switch_mirror false false
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        5)
            clear
