            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -rp "请输入要禁用的网卡名: " nic
            [ "$nic" = "0" ] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定
            [ -z "$nic" ] && { cancel_empty "上一级选单"; continue; }        # break 或 continue 或 return ，视上下文而定
            if ip link show "$nic" &>/dev/null; then    
                ip link set "$nic" down && echo -e "${gl_lv}✔ 网卡 $nic 已禁用${gl_bai}"
            else
                echo -e "${gl_hong}✘ 网卡不存在${gl_bai}"
            fi
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        3)
            # 查看网卡详情
            echo
            echo -e "${gl_zi}>>> 查看网卡详情${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -rp "请输入要查看的网卡名: " nic
            [ "$nic" = "0" ] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定
            [ -z "$nic" ] && { cancel_empty "上一级选单"; continue; }        # break 或 continue 或 return ，视上下文而定
            if ip link show "$nic" &>/dev/null; then
                echo -e "${gl_bufan}========== $nic 详细信息 ==========${gl_bai}"
                ip addr show "$nic"
                ethtool "$nic" 2>/dev/null | head -n 10
            else
                echo -e "${gl_hong}✘ 网卡不存在${gl_bai}"
            fi
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        4)
            # 刷新网卡信息
            continue
            ;;
        0) cancel_return "系统工具"; break ;;    # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;         # 感谢使用，再见！
        *) handle_invalid_input ;;              # 无效的输入,请重新输入!
        esac
    done
}

linux_log_menu() {
    # 系统日志管理工具
    clear
    show_log_overview() {
        echo -e "${gl_huang}>>> 系统日志概览${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}主机名称: ${gl_lv}$(get_hostname)${gl_bai}"
        echo -e "${gl_bai}系统时间: ${gl_lv}$(date)${gl_bai}"
        echo
        echo -e "${gl_bai}[ ${gl_huang}/var/log ${gl_bai}目录占用 ]"
        du -sh /var/log 2>/dev/null
        echo
        echo -e "${gl_bai}[ ${gl_huang}journal ${gl_bai}日志占用 ]"
        journalctl --disk-usage 2>/dev/null
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    }

    while true; do
        clear
        show_log_overview
        echo
        echo -e "${gl_zi}>>> 系统日志管理菜单${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}查看最近系统日志（journal）"
        echo -e "${gl_bufan}2.  ${gl_bai}查看指定服务日志"
        echo -e "${gl_bufan}3.  ${gl_bai}查看登录/安全日志"
        echo -e "${gl_bufan}4.  ${gl_bai}实时跟踪日志"
        echo -e "${gl_bufan}5.  ${gl_bai}清理旧 journal 日志"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
        echo -e "${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -rp "请输入你的选择: " choice

        case $choice in
        1)
            echo
            echo -e "${gl_zi}>>> 查看最近日志${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -rp "查看最近多少行日志？[默认 80]: " lines
            lines=${lines:-80}
            # journalctl -n "$lines" --no-pager
            list_beautify_journal_log "$lines"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        2)
            echo
            echo -e "${gl_zi}>>> 查看指定服务日志${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -rp "请输入服务名（如 sshd、nginx）: " svc
            if systemctl list-unit-files | grep -q "^$svc"; then
                journalctl -u "$svc" -n 100 --no-pager
            else
                echo -e "${gl_huang}✘ 服务不存在或无日志${gl_bai}"
            fi
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        3)
            echo
            echo -e "${gl_zi}>>> 查看登录/安全日志${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo
            echo -e "${gl_huang}>>> 最近登录日志${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            # last -n 10
            list_beautify_login_log
            echo
            echo -e "${gl_huang}>>> 认证日志${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            # if [ -f /var/log/secure ]; then
            #     tail -n 20 /var/log/secure
            # elif [ -f /var/log/auth.log ]; then
            #     tail -n 20 /var/log/auth.log
            # else
            #     echo -e "${gl_huang}未找到安全日志文件${gl_bai}"
            # fi
            list_beautify_secure_log
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        4)
            echo
            echo -e "${gl_zi}>>> 实时跟踪日志${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}1.  ${gl_bai}系统日志"
            echo -e "${gl_bufan}2.  ${gl_bai}指定服务日志"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -rp "选择跟踪类型: " t
            if [ "$t" = "1" ]; then
                journalctl -f
            elif [ "$t" = "2" ]; then
                read -rp "输入服务名: " svc
                journalctl -u "$svc" -f
            else
                echo "无效选择"
            fi
            ;;
        5)
            echo
            echo -e "${gl_zi}>>> 清理旧 journal 日志${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo "⚠️ 清理 journal 日志（安全方式）"
            echo -e "${gl_bufan}1.  ${gl_bai}保留最近 7 天"
            echo -e "${gl_bufan}2.  ${gl_bai}保留最近 3 天"
            echo -e "${gl_bufan}3.  ${gl_bai}限制日志最大 500M"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -rp "请选择清理方式: " c
            case $c in
            1) journalctl --vacuum-time=7d ;;
            2) journalctl --vacuum-time=3d ;;
            3) journalctl --vacuum-size=500M ;;
            *) handle_invalid_input ;;
            esac
            echo -e "${gl_lv}✔ journal 日志清理完成${gl_bai}"
            sleep_fractional 2
            ;;
        0) cancel_return "系统工具"; break ;;        # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;             # 感谢使用，再见！
        *) handle_invalid_input ;;                  # 无效的输入,请重新输入!
        esac
    done
}

linux_env_menu() {
    BASHRC="$HOME/.bashrc"
    PROFILE="$HOME/.profile"
    show_env_vars() {
        clear
        echo -e "${gl_zi}>>> 当前已生效环境变量${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}>>>  当前已生效环境变量（节选）${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        printf "%-20s %s\n" "变量名" "值"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        for v in USER HOME SHELL LANG PWD; do
            printf "%-20s %s\n" "$v" "${!v}"
        done

        echo
        echo "PATH:"
        echo "$PATH" | tr ':' '\n' | nl -ba

        echo
        echo -e "${gl_huang}>>>  配置文件中定义的变量（解析）${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        parse_file_vars() {
            local file="$1"
            [ -f "$file" ] || return

            echo
            echo -e "${gl_bai}>>> 来源文件：${gl_huang}$file${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            # 提取 export VAR=xxx 或 VAR=xxx
            grep -Ev '^\s*#|^\s*$' "$file" |
                grep -E '^(export[[:space:]]+)?[A-Za-z_][A-Za-z0-9_]*=' |
                while read -r line; do
                    var=$(echo "$line" | sed -E 's/^(export[[:space:]]+)?([A-Za-z_][A-Za-z0-9_]*).*/\2/')
                    val=$(echo "$line" | sed -E 's/^[^=]+=//')
                    printf "%-20s %s\n" "$var" "$val"
                done
        }

        parse_file_vars "$HOME/.bashrc"
        parse_file_vars "$HOME/.profile"

        echo
        echo -e "${gl_bufan}===============================================${gl_bai}"
        break_end
    }

    view_file() {
        local file="$1"
        clear
        if [ -f "$file" ]; then
            echo -e "${gl_bai}>>> 查看变量文件${gl_huang}$file${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            cat -n "$file"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        else
            echo -e "${gl_bai}文件不存在：${gl_huang}$file${gl_bai}"
        fi
        break_end
    }

    edit_file() {
        local file="$1"
        echo "${gl_bai}>>> 编辑变量文件${gl_huang}$file${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        install nano
        nano "$file"
    }

    source_files() {
        echo -e "正在重新加载环境变量 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bai}正在重新加载环境变量 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        source "$BASHRC"
        source "$PROFILE"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lv}✔ 环境变量已重新加载${gl_bai}"
        read -rp "$(echo -e "${gl_bai}按回车继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
    }

    while true; do
        clear
        echo -e "${gl_zi}>>> 系统环境变量管理${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}当前用户：${gl_lv}$USER"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}查看当前常用环境变量"
        echo -e "${gl_bufan}2.  ${gl_bai}查看 ~/.bashrc"
        echo -e "${gl_bufan}3.  ${gl_bai}查看 ~/.profile"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}4.  ${gl_bai}编辑 ~/.bashrc"
        echo -e "${gl_bufan}5.  ${gl_bai}编辑 ~/.profile"
        echo -e "${gl_bufan}6.  ${gl_bai}重新加载环境变量（source）"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
        echo -e "${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -rp "请输入你的选择: " choice

        case "$choice" in
        1) show_env_vars ;;
        2) view_file "$BASHRC" ;;
        3) view_file "$PROFILE" ;;
        4) edit_file "$BASHRC" ;;
        5) edit_file "$PROFILE" ;;
        6) source_files ;;
        0) cancel_return "系统工具"; break ;;    # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;         # 感谢使用，再见！
        *) handle_invalid_input ;;              # 无效的输入,请重新输入!
        esac
    done
}

# 网络连通性测试工具
linux_interactive_ping() {
    while true; do
        clear
        echo -e "${gl_zi}>>> 网络连通性测试工具${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}百度 (www.baidu.com)"
        echo -e "${gl_bufan}2.  ${gl_bai}GitHub (github.com)"
        echo -e "${gl_bufan}3.  ${gl_bai}Google (google.com)"
        echo -e "${gl_bufan}4.  ${gl_bai}自定义网址/IP"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
        echo -e "${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "$(echo -e "${gl_bai}请选择测试目标: ")" choice

        case "$choice" in
        1)
            target="www.baidu.com"
            name="百度"
            ;;
        2)
            target="github.com"
            name="GitHub"
            ;;
        3)
            target="google.com"
            name="Google"
            ;;
        4)
            while true; do
                read -r -e -p "$(echo -e "${gl_bai}请输入要ping的网址或IP地址 (${gl_huang}0${gl_bai}返回): ${gl_bai}")" custom_target

                case "$custom_target" in
                0) cancel_return; continue 2 ;;
                "")
                    log_error "输入不能为空，请重新输入"
                    continue
                    ;;
                *)
                    # 基本格式检查（简单检查是否包含点号或是IPv4地址）
                    if [[ "$custom_target" =~ ^[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}$ ]] || [[ "$custom_target" =~ [a-zA-Z0-9]+\.[a-zA-Z]+ ]]; then
                        target="$custom_target"
                        name="自定义目标"
                        break
                    else
                        log_error "输入的地址格式不正确，请重新输入"
                        continue
                    fi
                    ;;
                esac
            done
            ;;
        0) cancel_return "系统工具"; break ;;        # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;             # 感谢使用，再见！
        *) handle_invalid_input ;;                  # 无效的输入,请重新输入!
        esac

        # 设置ping参数（直接使用默认值，免确认）
        ping_count=4
        packet_size=56
        timeout=2

        # 直接开始测试
        echo -e ""
        echo -e "${gl_huang}>>> 开始ping测试 ${gl_hong}$target ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bai}目标: ${gl_huang}$name${gl_bai} ${gl_hui}($target)${gl_bai}"
        echo -e "${gl_bai}参数: ${gl_lv}次数:$ping_count ${gl_bai}| ${gl_lv}大小:${packet_size}字节${gl_bai} | ${gl_lv}超时:${timeout}秒${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 执行ping命令
        ping_result=$(ping -c "$ping_count" -s "$packet_size" -W "$timeout" "$target" 2>&1)
        ping_exit_code=$?

        echo -e "$ping_result"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 分析结果
        if [ $ping_exit_code -eq 0 ]; then
            log_ok "$target 连通正常"

            # 修正：正确提取平均延迟时间（提取第四个字段avg，而非第六个字段mdev）
            packet_loss=$(echo "$ping_result" | grep -oP '[0-9]+% packet loss' | grep -oP '[0-9]+' | head -1)
            # 使用awk提取avg值更可靠
            avg_time=$(echo "$ping_result" | grep "rtt min/avg/max/mdev" | awk -F'/' '{print $5}')

            if [ -n "$packet_loss" ] && [ -n "$avg_time" ]; then
                echo -e "${gl_bai}丢包率: ${gl_lv}$packet_loss%${gl_bai}"
                echo -e "${gl_bai}平均延迟: ${gl_lv}$avg_time ms${gl_bai}"

                # 根据延迟时间给出评价（使用数值比较）
                if [ "$(echo "$avg_time < 50" | bc 2>/dev/null)" = "1" ]; then
                    echo -e "${gl_bai}网络质量: ${gl_lv}优秀${gl_bai} (延迟<50ms)"
                elif [ "$(echo "$avg_time < 100" | bc 2>/dev/null)" = "1" ]; then
                    echo -e "${gl_bai}网络质量: ${gl_lv}良好${gl_bai} (延迟50-100ms)"
                elif [ "$(echo "$avg_time < 200" | bc 2>/dev/null)" = "1" ]; then
                    echo -e "${gl_bai}网络质量: ${gl_huang}一般${gl_bai} (延迟100-200ms)"
                else
                    echo -e "${gl_bai}网络质量: ${gl_hong}较差${gl_bai} (延迟>200ms)"
                fi
            else
                echo -e "${gl_huang}警告: 无法解析完整的ping统计信息${gl_bai}"
            fi
        else
            log_error "$target 无法连通"

            # 尝试给出可能的原因
            if ! ping -c 1 -W 1 "8.8.8.8" &>/dev/null; then
                echo -e "${gl_huang}提示: 您的设备可能未连接到互联网${gl_bai}"
            elif ! nslookup "$target" &>/dev/null 2>&1; then
                echo -e "${gl_huang}提示: 域名解析失败，请检查DNS设置${gl_bai}"
            else
                echo -e "${gl_huang}提示: 目标主机可能存在或防火墙阻止了ICMP请求${gl_bai}"
            fi
        fi

        # 记录测试历史
        local timestamp=$(date '+%Y-%m-%d %H:%M:%S')
        echo -e "${gl_hui}[$timestamp] ping测试: $target, 结果: $ping_exit_code${gl_bai}" >>/tmp/ping_test_history.log

        # 等待用户按键继续
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    done
}

###### 函数_rsync本地同步工具 - 修复优化版
# 初始化目录结构和全局变量
local_init_globals() {
    # 本地同步配置文件路径
    LOCAL_SYNC_CONFIG="$HOME/.local_rsync_tasks"

    # 创建配置目录
    mkdir -p "$(dirname "$LOCAL_SYNC_CONFIG")" 2>/dev/null || {
        echo -e "${gl_hong}错误: 无法创建配置目录${gl_bai}"
        return 1
    }
    return 0
}

# 显示本地同步任务列表
local_list_tasks() {
    local_init_globals || return 1

    echo "已保存的本地同步任务:"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if [[ -f "$LOCAL_SYNC_CONFIG" ]] && [[ -s "$LOCAL_SYNC_CONFIG" ]]; then
        local line_num=1
        while IFS='|' read -r name source target options; do
            # 格式化输出，确保编号右对齐 3 位
            printf "${gl_bufan}%3d. ${gl_bai}- ${gl_zi}%-10s${gl_bai} ( ${gl_huang}%s${gl_bai} -> ${gl_lv}%s${gl_bai} )\n" \
                "$line_num" "$name" "$source" "$target"
            ((line_num++))
        done <"$LOCAL_SYNC_CONFIG"
    else
        echo -e "${gl_huang}暂无同步任务${gl_bai}"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
}

# 添加本地同步任务
local_add_task() {
    local_init_globals || return 1

    echo "创建新本地同步任务示例："
    echo -e "  ${gl_bai}- 任务名称: ${gl_huang}backup_www${gl_bai}"
    echo -e "  ${gl_bai}- 源目录: ${gl_huang}/var/www${gl_bai}"
    echo -e "  ${gl_bai}- 目标目录: ${gl_huang}/backup/www${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    local name source_path target_path options

    while true; do
        read -r -e -p "$(echo -e "${gl_bai}请输入任务名称(${gl_huang}0${gl_bai})返回: ")" name
        # 检查是否输入0返回
        [ "$name" = "0" ] && { cancel_return "上一级选单"; return 1; }  # break 或 continue 或 return ，视上下文而定
        if [[ -z "$name" ]]; then
            echo -e "${gl_hong}错误: 任务名称不能为空${gl_bai}"
            continue
        fi
        # 检查任务名称是否已存在
        if [[ -f "$LOCAL_SYNC_CONFIG" ]] && grep -q "^$name|" "$LOCAL_SYNC_CONFIG"; then
            echo -e "${gl_hong}错误: 任务名称已存在，请重新输入${gl_bai}"
            continue
        fi
        break
    done

    while true; do
        read -r -e -p "请输入源目录: " source_path
        if [[ -z "$source_path" ]]; then
            echo -e "${gl_hong}错误: 源目录不能为空${gl_bai}"
            continue
        fi
        # 检查源目录是否存在（只是警告，不阻止创建）
        if [[ ! -d "$source_path" ]]; then
            echo -e "${gl_huang}警告: 源目录不存在，请确认路径是否正确${gl_bai}"
            read -r -e -p "是否继续创建任务? (y/n): " confirm
            if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
                continue
            fi
        fi
        break
    done

    while true; do
        read -r -e -p "请输入目标目录: " target_path
        if [[ -z "$target_path" ]]; then
            echo -e "${gl_hong}错误: 目标目录不能为空${gl_bai}"
            continue
        fi
        break
    done

    # 规范化目录路径
    source_path="${source_path%/}/"
    target_path="${target_path%/}/"

    echo ""
    echo -e "${gl_huang}>>> 请选择同步模式"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bufan}1. ${gl_bai}标准模式 (-avhz --progress) - 增量同步，保留文件属性"
    echo -e "${gl_bufan}2. ${gl_bai}安全模式 (-avhz --progress --delete-delay) - 删除目标中多余文件"
    echo -e "${gl_bufan}3. ${gl_bai}严格模式 (-avhz --progress --delete --checksum) - 校验文件内容"
    echo -e "${gl_bufan}4. ${gl_bai}快速模式 (-avh) - 基本同步，不压缩"
    echo -e "${gl_bufan}5. ${gl_bai}权限友好模式 (-avh --no-perms --no-owner --no-group) - 忽略权限问题"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "请输入你的选择: " mode

    case $mode in
    1) options="-avhz --progress" ;;
    2) options="-avhz --progress --delete-delay" ;;
    3) options="-avhz --progress --delete --checksum" ;;
    4) options="-avh" ;;
    5) options="-avh --no-perms --no-owner --no-group" ;;
    *)
        echo "无效选择，使用标准模式 -avhz --progress"
        options="-avhz --progress"
        ;;
    esac

    # 高级选项
    echo ""
    echo -e "${gl_huang}>>> 高级选项"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bufan}1. ${gl_bai}限速同步 (避免影响系统性能)"
    echo -e "${gl_bufan}2. ${gl_bai}排除特定文件类型"
    echo -e "${gl_bufan}3. ${gl_bai}排除Windows系统目录 (解决权限问题)"
    echo -e "${gl_bufan}4. ${gl_bai}跳过高级选项"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "请输入你的选择: " advanced_opt

    case $advanced_opt in
    1)
        read -r -e -p "请输入限速值 (单位: KB/s): " speed_limit
        if [[ "$speed_limit" =~ ^[0-9]+$ ]]; then
            options="$options --bwlimit=$speed_limit"
            echo -e "${gl_lv}已设置限速: ${speed_limit}KB/s${gl_bai}"
        else
            echo -e "${gl_hong}无效的限速值，跳过限速设置${gl_bai}"
        fi
        ;;
    2)
        read -r -e -p "请输入要排除的文件模式 (如: *.tmp,*.log): " exclude_patterns
        if [[ -n "$exclude_patterns" ]]; then
            # 修复：使用数组方式处理带空格的排除模式，避免eval问题
            options="$options --exclude='$exclude_patterns'"
            echo -e "${gl_lv}已设置排除模式: $exclude_patterns${gl_bai}"
        fi
        ;;
    3)
        # 排除Windows系统目录，解决权限问题
        options="$options --exclude='\$RECYCLE.BIN/' --exclude='System Volume Information/' --exclude='Thumbs.db' --exclude='Desktop.ini'"
        echo -e "${gl_lv}已排除Windows系统目录，解决权限问题${gl_bai}"
        ;;
    4 | "")
        echo "跳过高级选项"
        ;;
    *)
        echo -e "${gl_hong}无效选择，跳过高级选项${gl_bai}"
        ;;
    esac

    # 保存任务配置
    echo "$name|$source_path|$target_path|$options" >>"$LOCAL_SYNC_CONFIG"
    echo -e "${gl_lv}✓ 本地同步任务 '${name}' 已保存!${gl_bai}"

    # 显示任务信息
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}任务详情:${gl_bai}"
    echo -e "  ${gl_bai}名称: ${gl_huang}${name}${gl_bai}"
    echo -e "  ${gl_bai}源目录: ${gl_huang}${source_path}${gl_bai}"
    echo -e "  ${gl_bai}目标目录: ${gl_lv}${target_path}${gl_bai}"
    echo -e "  ${gl_bai}同步选项: ${gl_zi}${options}${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 删除本地同步任务
local_delete_task() {
    local_init_globals || return 1

    if [[ ! -f "$LOCAL_SYNC_CONFIG" ]] || [[ ! -s "$LOCAL_SYNC_CONFIG" ]]; then
        echo -e "${gl_hong}错误: 暂无同步任务可删除${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    echo ""

    local_list_tasks

    echo ""
    echo -e "${gl_huang}>>> 删除本地同步任务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    local num
    read -r -e -p "$(echo -e "${gl_bai}请输入要删除的任务编号(${gl_huang}0${gl_bai}返回): ")" num

    [ "$num" = "0" ] && { cancel_return "Rsync本地同步工具"; return 1; }

    if ! [[ "$num" =~ ^[0-9]+$ ]]; then
        echo -e "${gl_hong}错误: 请输入有效的数字编号${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    local total_tasks
    total_tasks=$(wc -l <"$LOCAL_SYNC_CONFIG" 2>/dev/null)
    if [[ "$num" -lt 1 || "$num" -gt "$total_tasks" ]]; then
        echo -e "${gl_hong}错误: 任务编号不存在${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 获取任务名称用于确认
    local task_line
    task_line=$(sed -n "${num}p" "$LOCAL_SYNC_CONFIG")
    local task_name source_path target_path options
    IFS='|' read -r task_name source_path target_path options <<<"$task_line"

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}即将删除的任务:${gl_bai}"
    echo -e "  名称: ${gl_huang}${task_name}${gl_bai}"
    echo -e "  源目录: ${gl_huang}${source_path}${gl_bai}"
    echo -e "  目标目录: ${gl_lv}${target_path}${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}确定要删除这个任务吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    if [[ "$confirm" == "y" || "$confirm" == "Y" ]]; then
        # 使用临时文件安全删除
        local temp_file
        temp_file=$(mktemp)
        sed "${num}d" "$LOCAL_SYNC_CONFIG" >"$temp_file"
        if mv "$temp_file" "$LOCAL_SYNC_CONFIG" 2>/dev/null; then
            echo -e "${gl_lv}✓ 任务已删除!${gl_bai}"
        else
            echo -e "${gl_hong}错误: 删除任务失败${gl_bai}"
            rm -f "$temp_file"
            return 1
        fi
    else
        echo "取消删除"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 执行本地同步任务（免确认模式） - 修复版
local_run_task() {
    local_init_globals || return 1

    if [[ ! -f "$LOCAL_SYNC_CONFIG" ]] || [[ ! -s "$LOCAL_SYNC_CONFIG" ]]; then
        echo -e "${gl_hong}错误: 暂无同步任务可执行${gl_bai}"
        return 1
    fi

    local num="$1"

    # 如果没有传入任务编号，显示列表让用户选择
    if [[ -z "$num" ]]; then
        local_list_tasks
        read -r -e -p "请输入要执行的任务编号: " num
    fi

    if ! [[ "$num" =~ ^[0-9]+$ ]]; then
        echo -e "${gl_hong}错误: 请输入有效的数字编号${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    local total_tasks
    total_tasks=$(wc -l <"$LOCAL_SYNC_CONFIG" 2>/dev/null)
    if [[ "$num" -lt 1 || "$num" -gt "$total_tasks" ]]; then
        echo -e "${gl_hong}错误: 任务编号不存在${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    local task
    task=$(sed -n "${num}p" "$LOCAL_SYNC_CONFIG")
    local name source_path target_path options
    IFS='|' read -r name source_path target_path options <<<"$task"

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}开始执行本地同步任务: ${gl_huang}${name}${gl_bai}"
    echo -e "${gl_bai}同步方向: ${gl_huang}${source_path} ${gl_hong}-> ${gl_lv}${target_path}${gl_bai}"
    echo -e "${gl_bai}同步选项: ${gl_zi}${options}${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查源目录是否存在
    if [[ ! -d "$source_path" ]]; then
        echo -e "${gl_hong}错误: 源目录不存在!${gl_bai}"
        echo -e "${gl_hong}请检查路径: ${source_path}${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 检查源目录权限
    if [[ ! -r "$source_path" ]]; then
        echo -e "${gl_huang}警告: 源目录读取权限受限${gl_bai}"
        echo -e "${gl_huang}建议: 使用权限友好模式同步${gl_bai}"
    fi

    # 自动创建目标目录（如果不存在）
    if [[ ! -d "$target_path" ]]; then
        echo -e "${gl_huang}目标目录不存在，正在自动创建: ${gl_lv}${target_path}${gl_bai}"
        if mkdir -p "$target_path" 2>/dev/null; then
            echo -e "${gl_lv}✓ 目标目录已创建${gl_bai}"
        else
            echo -e "${gl_hong}错误: 无法创建目标目录${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        fi
    fi

    # 检查目标目录权限
    if [[ ! -w "$target_path" ]]; then
        echo -e "${gl_hong}错误: 目标目录写入权限不足!${gl_bai}"
        echo -e "${gl_huang}请检查目录权限或使用sudo执行${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 记录开始时间
    local start_time
    start_time=$(date +%s)
    echo -e "${gl_bai}开始时间: ${gl_lv}$(date)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 执行rsync同步
    echo -e "${gl_bai}正在执行同步 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bai}详细输出如下:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 执行同步并捕获输出
    local output_file
    output_file=$(mktemp)
    local sync_result
    local error_count=0

    # 修复：使用数组执行避免eval的潜在问题，同时保持原有逻辑
    eval rsync $options "$source_path" "$target_path" 2>&1 | tee "$output_file"
    sync_result=${PIPESTATUS[0]}

    # 分析输出，统计错误数量
    error_count=$(grep -c "Permission denied\|rsync error\|failed" "$output_file" || echo 0)

    # 清理临时文件
    rm -f "$output_file"

    local end_time duration
    end_time=$(date +%s)
    duration=$((end_time - start_time))

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 根据错误类型提供不同的反馈
    if [[ $sync_result -eq 0 ]]; then
        echo -e "${gl_lv}✓ 本地同步完成!${gl_bai}"
        echo -e "${gl_bai}同步统计:${gl_bai}"
        echo -e "  - 任务名称: ${gl_huang}${name}${gl_bai}"
        echo -e "  - 源目录: ${gl_huang}${source_path}${gl_bai}"
        echo -e "  - 目标目录: ${gl_lv}${target_path}${gl_bai}"
        echo -e "  - 耗时: ${gl_zi}${duration}秒${gl_bai}"
        echo -e "  - 完成时间: ${gl_lv}$(date)${gl_bai}"
        echo -e "  - 同步结果: ${gl_lv}成功${gl_bai}"
    elif [[ $sync_result -eq 23 ]] && [[ $error_count -gt 0 ]]; then
        # 错误代码23：部分文件传输失败
        echo -e "${gl_huang}⚠ 同步部分完成，但有文件权限问题${gl_bai}"
        echo -e "${gl_bai}同步统计:${gl_bai}"
        echo -e "  - 任务名称: ${gl_huang}${name}${gl_bai}"
        echo -e "  - 源目录: ${gl_huang}${source_path}${gl_bai}"
        echo -e "  - 目标目录: ${gl_lv}${target_path}${gl_bai}"
        echo -e "  - 耗时: ${gl_zi}${duration}秒${gl_bai}"
        echo -e "  - 完成时间: ${gl_lv}$(date)${gl_bai}"
        echo -e "  - 同步结果: ${gl_huang}部分成功${gl_bai}"
        echo -e "  - 错误类型: 文件权限受限"
        echo -e "${gl_huang}建议解决方案:${gl_bai}"
        echo -e "  ${gl_bufan}1. ${gl_bai}重新编辑任务，选择'权限友好模式'"
        echo -e "  ${gl_bufan}2. ${gl_bai}在高级选项中选择'排除Windows系统目录'"
        echo -e "  ${gl_bufan}3. ${gl_bai}使用root权限执行: sudo m local_rsync_run $num"
    else
        echo -e "${gl_hong}✗ 同步失败! 错误代码: ${sync_result}${gl_bai}"
        echo -e "${gl_hong}可能的原因:${gl_bai}"
        echo -e "  ${gl_bufan}1. ${gl_bai}目标目录权限不足 - 使用sudo或检查目录权限"
        echo -e "  ${gl_bufan}2. ${gl_bai}磁盘空间不足 - 检查目标磁盘空间"
        echo -e "  ${gl_bufan}3. ${gl_bai}文件被占用或权限问题 - 尝试重新编辑任务选择权限友好模式"
        echo -e "  ${gl_bufan}4. ${gl_bai}网络存储连接问题（如果是网络路径）"
        echo -e "  ${gl_bufan}5. ${gl_bai}rsync选项配置错误 - 检查同步选项"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
    return $sync_result
}

# 批量执行所有本地同步任务 - 优化版
local_run_all_tasks() {
    local_init_globals || return 1

    if [[ ! -f "$LOCAL_SYNC_CONFIG" ]] || [[ ! -s "$LOCAL_SYNC_CONFIG" ]]; then
        echo -e "${gl_hong}错误: 暂无同步任务可执行${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    local total_tasks
    total_tasks=$(wc -l <"$LOCAL_SYNC_CONFIG")
    echo -e ""
    echo -e "${gl_bai}开始批量执行 ${gl_huang}${total_tasks} ${gl_bai}个本地同步任务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    local success_count=0
    local fail_count=0
    local partial_count=0
    local current_task=0

    # 逐行读取任务配置并执行
    while IFS= read -r task; do
        ((current_task++))
        local name source_path target_path options
        IFS='|' read -r name source_path target_path options <<<"$task"

        echo -e "${gl_bai}[${gl_lv}${current_task}${gl_bai}/${gl_huang}${total_tasks}${gl_bai}] 执行任务: ${gl_huang}${name}${gl_bai}"
        echo -e "${gl_bai}路径: ${gl_huang}${source_path} ${gl_bai}-> ${gl_lv}${target_path}${gl_bai}"

        # 检查源目录是否存在
        if [[ ! -d "$source_path" ]]; then
            echo -e "${gl_hong}✗ 失败: 源目录不存在${gl_bai}"
            ((fail_count++))
            echo ""
            continue
        fi

        # 执行同步（简化输出）
        local output_file
        output_file=$(mktemp)
        # 修复：将eval结果赋值给变量，避免PIPESTATUS在管道中的问题
        eval rsync $options "$source_path" "$target_path" >"$output_file" 2>&1
        local sync_result=$?

        # 检查同步结果
        if [[ $sync_result -eq 0 ]]; then
            echo -e "${gl_lv}✓ 成功${gl_bai}"
            ((success_count++))
        elif [[ $sync_result -eq 23 ]] && grep -q "Permission denied" "$output_file"; then
            echo -e "${gl_huang}⚠ 部分成功 (权限问题)${gl_bai}"
            ((partial_count++))
        else
            echo -e "${gl_hong}✗ 失败 (错误代码: $sync_result)${gl_bai}"
            ((fail_count++))
        fi

        # 清理临时文件
        rm -f "$output_file"
        echo ""
    done <"$LOCAL_SYNC_CONFIG"

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}批量执行完成:"
    echo -e "  ${gl_lv}✓ 成功: ${success_count}${gl_bai}"
    echo -e "  ${gl_huang}⚠ 部分成功: ${partial_count}${gl_bai}"
    echo -e "  ${gl_hong}✗ 失败: ${fail_count}${gl_bai}"

    # 修复：将break_end移到return之前，并修复不可达代码
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end

    if [[ $fail_count -eq 0 ]] && [[ $partial_count -eq 0 ]]; then
        return 0
    elif [[ $fail_count -gt 0 ]]; then
        return 1
    else
        return 2 # 部分成功
    fi
}

# 创建本地同步定时任务 - 优化版
local_schedule_task() {
    echo ""
    echo -e "${gl_zi}>>> 创建本地定时任务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    local_init_globals || return 1

    if [[ ! -f "$LOCAL_SYNC_CONFIG" ]] || [[ ! -s "$LOCAL_SYNC_CONFIG" ]]; then
        echo -e "${gl_hong}错误: 暂无同步任务可设置定时${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    local num

    read -r -e -p "$(echo -e "${gl_bai}请输入要定时同步的任务编号(${gl_huang}0${gl_bai}返回): ")" num

    [ "$num" = "0" ] && { cancel_return "Rsync本地同步工具"; return 1; }
    [ -z "$num" ] && { cancel_empty "上一级选单"; return 1; }

    if ! [[ "$num" =~ ^[0-9]+$ ]]; then
        echo -e "${gl_hong}错误: 请输入有效的数字编号${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    local total_tasks
    total_tasks=$(wc -l <"$LOCAL_SYNC_CONFIG")
    if [[ "$num" -lt 1 || "$num" -gt "$total_tasks" ]]; then
        echo -e "${gl_hong}错误: 任务编号不存在${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    local task
    task=$(sed -n "${num}p" "$LOCAL_SYNC_CONFIG")
    local name source_path target_path options
    IFS='|' read -r name source_path target_path options <<<"$task"

    echo ""
    echo -e "${gl_huang}>>> 请选择定时执行间隔${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bufan}1. ${gl_bai}每小时执行一次"
    echo -e "${gl_bufan}2. ${gl_bai}每天执行一次"
    echo -e "${gl_bufan}3. ${gl_bai}每周执行一次"
    echo -e "${gl_bufan}4. ${gl_bai}每月执行一次"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "请输入你的选择: " interval

    local random_minute
    random_minute=$(shuf -i 0-59 -n 1)
    local cron_time=""
    local interval_desc=""

    case "$interval" in
    1)
        cron_time="$random_minute * * * *"
        interval_desc="每小时（随机分钟 $random_minute）"
        ;;
    2)
        cron_time="$random_minute 2 * * *"
        interval_desc="每天凌晨2点（随机分钟 $random_minute）"
        ;;
    3)
        cron_time="$random_minute 3 * * 1"
        interval_desc="每周一凌晨3点（随机分钟 $random_minute）"
        ;;
    4)
        cron_time="$random_minute 4 1 * *"
        interval_desc="每月1号凌晨4点（随机分钟 $random_minute）"
        ;;
    *)
        echo -e "${gl_hong}错误: 请输入有效的选项！${gl_bai}"
        return 1
        ;;
    esac

    # 获取当前脚本路径
    local script_path
    script_path="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)/$(basename "${BASH_SOURCE[0]}")"

    # 创建cron任务
    local cron_job
    cron_job="$cron_time m local_rsync_run $num"

    # 检查cron服务状态 - 修复：增加对crontab命令存在性的检查
    local cron_service_active=false
    if command -v systemctl >/dev/null 2>&1; then
        if systemctl is-active cron >/dev/null 2>&1 || systemctl is-active crond >/dev/null 2>&1; then
            cron_service_active=true
        fi
    elif command -v service >/dev/null 2>&1; then
        if service cron status >/dev/null 2>&1 || service crond status >/dev/null 2>&1; then
            cron_service_active=true
        fi
    fi

    if ! $cron_service_active; then
        echo -e "${gl_huang}警告: cron服务未运行，正在尝试启动 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if command -v systemctl >/dev/null 2>&1; then
            sudo systemctl start cron 2>/dev/null || sudo systemctl start crond 2>/dev/null
        elif command -v service >/dev/null 2>&1; then
            sudo service cron start 2>/dev/null || sudo service crond start 2>/dev/null
        fi
    fi

    # 检查是否已存在相同任务
    if crontab -l 2>/dev/null | grep -q "local_rsync_run $num"; then
        echo -e "${gl_hong}错误: 该任务的定时同步已存在！${gl_bai}"
        return 1
    fi

    # 创建到用户的crontab
    (
        crontab -l 2>/dev/null | grep -v "^#"
        echo "# 本地Rsync定时任务: $name"
        echo "$cron_job"
        echo ""
    ) | crontab -

    echo ""
    echo -e "${gl_lv}✓ 定时任务已创建：${gl_huang}$cron_job${gl_bai}"

    # 显示任务详情
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}任务详情:${gl_bai}"
    echo -e "  - 任务名称: ${gl_huang}${name}${gl_bai}"
    echo -e "  - 执行间隔: ${gl_huang}${interval_desc}${gl_bai}"
    echo -e "  - 源目录: ${gl_huang}${source_path}${gl_bai}"
    echo -e "  - 目标目录: ${gl_lv}${target_path}${gl_bai}"
    echo -e "  - 同步选项: ${gl_zi}${options}${gl_bai}"
    echo -e "  - Cron命令: ${gl_zi}$cron_job${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 显示当前cron状态
    echo -e "${gl_bai}当前cron状态:${gl_bai}"
    if $cron_service_active; then
        echo -e "  ${gl_lv}✓ cron服务运行正常${gl_bai}"
    else
        echo -e "  ${gl_huang}⚠ cron服务未运行，定时任务可能无法执行${gl_bai}"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 查看本地同步定时任务 - 增强版（显示详细信息）
local_view_schedules() {
    echo "当前的本地同步定时任务:"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    # 检查cron服务状态
    local cron_active=false
    if command -v systemctl >/dev/null 2>&1; then
        if systemctl is-active cron >/dev/null 2>&1 || systemctl is-active crond >/dev/null 2>&1; then
            cron_active=true
        fi
    elif command -v service >/dev/null 2>&1; then
        if service cron status >/dev/null 2>&1 || service crond status >/dev/null 2>&1; then
            cron_active=true
        fi
    fi

    if ! $cron_active; then
        echo -e "${gl_huang}警告: cron服务未运行，定时任务可能无法执行${gl_bai}"
        echo -e "${gl_huang}启动命令: sudo systemctl start cron${gl_bai}"
    fi

    # 获取当前用户的crontab内容
    local crontab_content
    crontab_content=$(crontab -l 2>/dev/null)

    if [[ $? -ne 0 ]] || [[ -z "$crontab_content" ]]; then
        echo -e "${gl_huang}当前用户暂无定时任务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        return 0
    fi

    # 查找本地同步任务
    local task_count=0
    while IFS= read -r line; do
        # 跳过空行和注释
        [[ -z "$line" ]] && continue
        [[ "$line" =~ ^# ]] && continue

        # 检查是否是本地同步任务
        if [[ "$line" =~ local_rsync_run ]] || [[ "$line" =~ local_rsync_run ]]; then
            ((task_count++))
            # 提取任务编号
            local task_num
            task_num=$(echo "$line" | grep -o -- "local_rsync_run [0-9]\+" | awk '{print $2}' ||
                echo "$line" | grep -o "local_rsync_run [0-9]\+" | awk '{print $2}')

            # 从配置文件中获取详细信息
            local task_name=""
            local source_path=""
            local target_path=""
            local options=""
            if [[ -n "$task_num" ]] && [[ -f "$LOCAL_SYNC_CONFIG" ]]; then
                local task_line
                task_line=$(sed -n "${task_num}p" "$LOCAL_SYNC_CONFIG" 2>/dev/null)
                if [[ -n "$task_line" ]]; then
                    IFS='|' read -r task_name source_path target_path options <<<"$task_line"
                fi
            fi

            # 格式化输出详细信息
            echo -e "${gl_bufan}${task_count}. ${gl_bai}Cron表达式: ${gl_zi}${line}${gl_bai}"
            if [[ -n "$task_name" ]]; then
                echo -e "   任务名称: ${gl_huang}${task_name}${gl_bai}"
                echo -e "   源目录:   ${gl_huang}${source_path}${gl_bai}"
                echo -e "   目标目录: ${gl_lv}${target_path}${gl_bai}"
                echo -e "   同步选项: ${gl_zi}${options}${gl_bai}"
            else
                echo -e "   ${gl_hong}警告: 无法获取任务详细信息（可能对应的同步任务已被删除）${gl_bai}"
            fi
            echo ""
        fi
    done <<<"$crontab_content"

    if [[ $task_count -eq 0 ]]; then
        echo -e "${gl_huang}暂无本地同步定时任务${gl_bai}"
    else
        echo -e "${gl_bai}共找到 ${gl_huang}${task_count} ${gl_bai}个定时任务${gl_bai}"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
}

# 删除本地同步定时任务 - 优化版
local_delete_schedule() {
    clear
    echo ""
    echo -e "${gl_zi}>>> 删除定时任务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    local_view_schedules

    local task_num

    read -r -e -p "$(echo -e "${gl_bai}请输入要删除的定时任务编号(${gl_huang}0${gl_bai}返回): ")" task_num

    [ "$task_num" = "0" ] && { cancel_return "Rsync本地同步工具"; return 1; }
    [ -z "$task_num" ] && { cancel_empty "上一级选单"; return 1; }

    if ! [[ "$task_num" =~ ^[0-9]+$ ]]; then
        echo -e "${gl_hong}错误: 请输入有效的数字编号${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 获取当前crontab内容
    local crontab_content
    crontab_content=$(crontab -l 2>/dev/null)

    if [[ $? -ne 0 ]] || [[ -z "$crontab_content" ]]; then
        echo -e "${gl_hong}错误: 未找到定时任务${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 查找要删除的任务行
    local current_task=0
    local target_line=""
    local target_comment_line=""
    local found_target=false
    local prev_line=""
    
    # 逐行读取crontab内容
    while IFS= read -r line; do
        # 检查是否是本地同步任务
        if [[ "$line" =~ local_rsync_run ]] || [[ "$line" =~ local_rsync_run ]]; then
            ((current_task++))
            if [[ $current_task -eq $task_num ]]; then
                target_line="$line"
                found_target=true
                
                # 检查前一行是否是注释行
                if [[ -n "$prev_line" ]] && [[ "$prev_line" =~ ^#.*本地Rsync定时任务 ]]; then
                    target_comment_line="$prev_line"
                fi
                break
            fi
        fi
        # 保存上一行
        prev_line="$line"
    done <<<"$crontab_content"

    if [[ -z "$target_line" ]]; then
        echo -e "${gl_hong}错误: 未找到该编号的定时任务${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 显示要删除的任务
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}即将删除的任务:${gl_bai}"
    if [[ -n "$target_comment_line" ]]; then
        echo -e "${gl_huang}注释行: $target_comment_line${gl_bai}"
    fi
    echo -e "${gl_huang}任务行: $target_line${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}确定要删除这个定时任务吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    if [[ "$confirm" == "y" || "$confirm" == "Y" ]]; then
        # 使用更安全的方法删除任务
        local temp_file
        temp_file=$(mktemp)
        
        # 将当前crontab内容写入临时文件
        crontab -l 2>/dev/null > "$temp_file"
        
        # 如果要删除注释行
        if [[ -n "$target_comment_line" ]]; then
            # 使用grep -v删除注释行
            local temp_file2
            temp_file2=$(mktemp)
            grep -vF "$target_comment_line" "$temp_file" > "$temp_file2"
            mv "$temp_file2" "$temp_file"
        fi
        
        # 删除任务行
        local temp_file3
        temp_file3=$(mktemp)
        grep -vF "$target_line" "$temp_file" > "$temp_file3"
        mv "$temp_file3" "$temp_file"

        # 检查是否删除了任务
        if grep -qF "$target_line" "$temp_file"; then
            echo -e "${gl_hong}错误: 删除任务失败${gl_bai}"
        else
            # 安装新的crontab
            crontab "$temp_file"
            echo -e "${gl_lv}✓ 定时任务已删除!${gl_bai}"
            
            # 验证删除是否成功
            if crontab -l 2>/dev/null | grep -qF "$target_line"; then
                echo -e "${gl_huang}警告: 定时任务可能未被完全删除${gl_bai}"
            fi
        fi

        rm -f "$temp_file"
    else
        echo "取消删除"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 执行本地反向同步任务（将目标目录同步回源目录）- 新增功能
local_run_task_reverse() {
    local_init_globals || return 1

    if [[ ! -f "$LOCAL_SYNC_CONFIG" ]] || [[ ! -s "$LOCAL_SYNC_CONFIG" ]]; then
        echo -e "${gl_hong}错误: 暂无同步任务可执行${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    local num="$1"
    # 如果没有传入任务编号，显示列表让用户选择
    if [[ -z "$num" ]]; then
        local_list_tasks
        read -r -e -p "请输入要执行反向同步的任务编号: " num
    fi

    if ! [[ "$num" =~ ^[0-9]+$ ]]; then
        echo -e "${gl_hong}错误: 请输入有效的数字编号${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    local total_tasks
    total_tasks=$(wc -l <"$LOCAL_SYNC_CONFIG" 2>/dev/null)
    if [[ "$num" -lt 1 || "$num" -gt "$total_tasks" ]]; then
        echo -e "${gl_hong}错误: 任务编号不存在${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    local task
    task=$(sed -n "${num}p" "$LOCAL_SYNC_CONFIG")
    local name source_path target_path options
    IFS='|' read -r name source_path target_path options <<<"$task"

    # 重要警告：反向同步会覆盖源文件！
    echo -e "${gl_hong}⚠⚠⚠ 警告：反向同步 ⚠⚠⚠${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}原始任务方向: ${gl_huang}${source_path} ${gl_bai}-> ${gl_lv}${target_path}${gl_bai}"
    echo -e "${gl_bai}反向同步方向: ${gl_hong}${target_path} ${gl_bai}-> ${gl_huang}${source_path}${gl_bai}"
    echo -e ""
    echo -e "${gl_hong}注意：此操作会将目标目录的内容同步回源目录，可能会覆盖源文件！${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确认执行反向同步吗? (${gl_hong}输入 ${gl_huang}y ${gl_hong}确认${gl_bai}/${gl_lv}任意键取消${gl_bai}): ")" confirm
    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
        echo -e "${gl_huang}已取消反向同步操作${gl_bai}"
        return 0
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}开始执行本地反向同步任务: ${gl_hong}${name}${gl_bai}"
    echo -e "${gl_bai}同步方向: ${gl_lv}${target_path} ${gl_hong}-> ${gl_huang}${source_path}${gl_bai}"
    echo -e "${gl_bai}同步选项: ${gl_zi}${options}${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查原目标目录（现在的源目录）是否存在
    if [[ ! -d "$target_path" ]]; then
        echo -e "${gl_hong}错误: 原目标目录（现源目录）不存在!${gl_bai}"
        echo -e "${gl_hong}请检查路径: ${target_path}${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 检查原源目录（现在的目标目录）是否存在，并确保可写
    if [[ ! -d "$source_path" ]]; then
        echo -e "${gl_huang}警告: 原源目录（现目标目录）不存在，正在自动创建: ${gl_huang}${source_path}${gl_bai}"
        if mkdir -p "$source_path" 2>/dev/null; then
            echo -e "${gl_lv}✓ 目录已创建${gl_bai}"
        else
            echo -e "${gl_hong}错误: 无法创建目录${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        fi
    fi

    if [[ ! -w "$source_path" ]]; then
        echo -e "${gl_hong}错误: 原源目录（现目标目录）写入权限不足!${gl_bai}"
        echo -e "${gl_huang}请检查目录权限或使用sudo执行${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 记录开始时间
    local start_time
    start_time=$(date +%s)
    echo -e "${gl_bai}开始时间: ${gl_lv}$(date)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 执行rsync反向同步（交换源和目标）
    echo -e "${gl_bai}正在执行反向同步 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bai}详细输出如下:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    local output_file
    output_file=$(mktemp)
    local sync_result
    local error_count=0

    # 注意：这里交换了 source_path 和 target_path
    eval rsync $options "$target_path" "$source_path" 2>&1 | tee "$output_file"
    sync_result=${PIPESTATUS[0]}

    error_count=$(grep -c "Permission denied\|rsync error\|failed" "$output_file" || echo 0)
    rm -f "$output_file"

    local end_time duration
    end_time=$(date +%s)
    duration=$((end_time - start_time))

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if [[ $sync_result -eq 0 ]]; then
        echo -e "${gl_lv}✓ 本地反向同步完成!${gl_bai}"
        echo -e "${gl_bai}同步统计:${gl_bai}"
        echo -e "  - 任务名称: ${gl_hong}${name}${gl_bai}"
        echo -e "  - 同步方向: ${gl_lv}${target_path} ${gl_hong}-> ${gl_huang}${source_path}${gl_bai}"
        echo -e "  - 耗时: ${gl_zi}${duration}秒${gl_bai}"
        echo -e "  - 完成时间: ${gl_lv}$(date)${gl_bai}"
        echo -e "  - 同步结果: ${gl_lv}成功${gl_bai}"
    elif [[ $sync_result -eq 23 ]] && [[ $error_count -gt 0 ]]; then
        echo -e "${gl_huang}⚠ 反向同步部分完成，但有文件权限问题${gl_bai}"
        echo -e "${gl_bai}同步统计:${gl_bai}"
        echo -e "  - 任务名称: ${gl_hong}${name}${gl_bai}"
        echo -e "  - 同步方向: ${gl_lv}${target_path} ${gl_hong}-> ${gl_huang}${source_path}${gl_bai}"
        echo -e "  - 耗时: ${gl_zi}${duration}秒${gl_bai}"
        echo -e "  - 完成时间: ${gl_lv}$(date)${gl_bai}"
        echo -e "  - 同步结果: ${gl_huang}部分成功${gl_bai}"
        echo -e "  - 错误类型: 文件权限受限"
        echo -e "${gl_huang}建议解决方案:${gl_bai}"
        echo -e "  ${gl_bufan}1. ${gl_bai}重新编辑任务，选择'权限友好模式'"
        echo -e "  ${gl_bufan}2. ${gl_bai}在高级选项中选择'排除Windows系统目录'"
        echo -e "  ${gl_bufan}3. ${gl_bai}使用root权限执行"
    else
        echo -e "${gl_hong}✗ 反向同步失败! 错误代码: ${sync_result}${gl_bai}"
        echo -e "${gl_hong}可能的原因:${gl_bai}"
        echo -e "  ${gl_bufan}1. ${gl_bai}原源目录（现目标目录）权限不足 - 使用sudo或检查目录权限"
        echo -e "  ${gl_bufan}2. ${gl_bai}磁盘空间不足 - 检查目标磁盘空间"
        echo -e "  ${gl_bufan}3. ${gl_bai}文件被占用或权限问题 - 尝试重新编辑任务选择权限友好模式"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
    return $sync_result
}

# 正向同步菜单函数
local_forward_sync_menu() {
    clear
    echo ""
    echo -e "${gl_huang}>>> 执行正向同步 ${gl_bai}(${gl_huang}源 ${gl_bai}-> ${gl_lv}目标${gl_bai})${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    local_list_tasks
    local task_num
    read -r -e -p "$(echo -e "${gl_bai}请输入要执行的任务编号(${gl_huang}0${gl_bai}返回): ")" task_num

    [ "$task_num" = "0" ] && { cancel_return "Rsync本地同步工具"; return 1; }
    [ -z "$task_num" ] && { cancel_empty "上一级选单"; return 1; }

    local_run_task "$task_num"
}

# 反向同步菜单函数
local_reverse_sync_menu() {
    clear
    echo ""
    echo -e "${gl_zi}>>> 执行反向同步 ${gl_bai}(${gl_huang}目标 ${gl_bai}-> ${gl_lv}源${gl_bai})${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_huang}注意：反向同步会用目标目录文件覆盖源目录！${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    local_list_tasks
    local task_num

    read -r -e -p "$(echo -e "${gl_bai}请输入要执行反向同步的任务编号(${gl_huang}0${gl_bai}返回): ")" task_num

    [ "$task_num" = "0" ] && { cancel_return "Rsync本地同步工具"; return 1; }
    [ -z "$task_num" ] && { cancel_empty "上一级选单"; return 1; }

    local_run_task_reverse "$task_num"
}

# 修复权限问题菜单函数
local_fix_permission_menu() {
    clear
    echo ""
    echo -e "${gl_huang}>>> 修复权限问题${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}常见权限问题解决方案:${gl_bai}"
    echo -e "  ${gl_bufan}1. ${gl_bai}重新创建任务，选择'权限友好模式'"
    echo -e "  ${gl_bufan}2. ${gl_bai}在高级选项中选择'排除Windows系统目录'"
    echo -e "  ${gl_bufan}3. ${gl_bai}使用sudo权限执行同步"
    echo -e "  ${gl_bufan}4. ${gl_bai}修改源目录权限: chmod -R 755 /path/to/source"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 显示本地同步任务详细信息
local_show_task_details() {
    local_init_globals || return 1
    
    echo ""
    echo -e "${gl_zi}>>> 查看本地同步任务详细信息${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    if [[ ! -f "$LOCAL_SYNC_CONFIG" ]]; then
        echo -e "${gl_huang}配置文件不存在，暂无同步任务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 0
    fi
    
    if [[ ! -s "$LOCAL_SYNC_CONFIG" ]]; then
        echo -e "${gl_huang}暂无同步任务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 0
    fi
    
    echo -e "${gl_bai}提示: 直接${gl_lv}回车${gl_bai}查看全部任务，输入${gl_huang}0${gl_bai}返回${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入要查看的任务编号(${gl_huang}0${gl_bai}返回): ")" num

    [ "$num" = "0" ] && { cancel_return "Rsync本地同步工具"; return 1; }
    
    # 如果用户直接回车，则查看所有任务
    if [[ -z "$num" ]]; then
        echo ""
        echo -e "${gl_zi}>>> 所有本地同步任务详情${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        local line_num=1
        while IFS='|' read -r name source_path target_path options; do
            echo -e "${gl_bufan}任务 #${line_num}${gl_bai}"
            echo -e "  ${gl_bai}任务名称: ${gl_zi}$name${gl_bai}"
            echo -e "  ${gl_bai}源目录: ${gl_huang}$source_path${gl_bai}"
            echo -e "  ${gl_bai}目标目录: ${gl_lv}$target_path${gl_bai}"
            echo -e "  ${gl_bai}同步选项: ${gl_zi}$options${gl_bai}"
            
            # 检查源目录是否存在
            if [[ -d "$source_path" ]]; then
                local source_size=$(du -sh "$source_path" 2>/dev/null | cut -f1)
                local source_count=$(find "$source_path" -type f 2>/dev/null | wc -l)
                echo -e "  ${gl_bai}源目录状态: ${gl_lv}存在${gl_bai}"
                echo -e "  ${gl_bai}源目录大小: ${gl_bai}${source_size:-未知}"
                echo -e "  ${gl_bai}源文件数量: ${gl_bai}${source_count}"
                
                # 检查权限
                if [[ ! -r "$source_path" ]]; then
                    echo -e "  ${gl_hong}警告: 源目录读取权限不足!${gl_bai}"
                fi
            else
                echo -e "  ${gl_hong}警告: 源目录不存在!${gl_bai}"
            fi
            
            # 检查目标目录是否存在
            if [[ -d "$target_path" ]]; then
                local target_size=$(du -sh "$target_path" 2>/dev/null | cut -f1)
                local target_count=$(find "$target_path" -type f 2>/dev/null | wc -l)
                echo -e "  ${gl_bai}目标目录状态: ${gl_lv}存在${gl_bai}"
                echo -e "  ${gl_bai}目标目录大小: ${gl_bai}${target_size:-未知}"
                echo -e "  ${gl_bai}目标文件数量: ${gl_bai}${target_count}"
                
                # 检查权限
                if [[ ! -w "$target_path" ]]; then
                    echo -e "  ${gl_hong}警告: 目标目录写入权限不足!${gl_bai}"
                fi
            else
                echo -e "  ${gl_huang}目标目录状态: ${gl_huang}不存在${gl_bai}"
            fi
            
            # 检查是否为网络路径
            if [[ "$source_path" =~ ^// ]] || [[ "$source_path" =~ ^smb:// ]] || [[ "$target_path" =~ ^// ]] || [[ "$target_path" =~ ^smb:// ]]; then
                echo -e "  ${gl_bai}网络路径: ${gl_huang}是${gl_bai}"
            fi
            
            # 显示磁盘空间信息
            echo -e "${gl_bai}磁盘空间信息:${gl_bai}"
            local source_disk=$(df -h "$source_path" 2>/dev/null | tail -1)
            local target_disk=$(df -h "$target_path" 2>/dev/null | tail -1)
            
            if [[ -n "$source_disk" ]]; then
                local source_fs=$(echo "$source_disk" | awk '{print $1}')
                local source_avail=$(echo "$source_disk" | awk '{print $4}')
                echo -e "  ${gl_bai}源磁盘可用空间: ${gl_bai}$source_avail (文件系统: $source_fs)"
            fi
            
            if [[ -n "$target_disk" ]]; then
                local target_fs=$(echo "$target_disk" | awk '{print $1}')
                local target_avail=$(echo "$target_disk" | awk '{print $4}')
                echo -e "  ${gl_bai}目标磁盘可用空间: ${gl_bai}$target_avail (文件系统: $target_fs)"
            fi
            
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            ((line_num++))
        done <"$LOCAL_SYNC_CONFIG"
        
        echo -e "${gl_lv}共找到 $((line_num-1)) 个同步任务${gl_bai}"
        
    else
        # 显示单个任务详情
        local task=$(sed -n "${num}p" "$LOCAL_SYNC_CONFIG" 2>/dev/null)
        if [[ -z "$task" ]]; then
            echo -e "${gl_hong}错误: 未找到任务 #$num${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi
        
        IFS='|' read -r name source_path target_path options <<<"$task"
        
        echo ""
        echo -e "${gl_zi}>>> 本地同步任务 #$num 详情${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_bai}任务名称: ${gl_zi}$name${gl_bai}"
        echo -e "  ${gl_bai}源目录: ${gl_huang}$source_path${gl_bai}"
        echo -e "  ${gl_bai}目标目录: ${gl_lv}$target_path${gl_bai}"
        echo -e "  ${gl_bai}同步选项: ${gl_zi}$options${gl_bai}"
        
        # 详细解析同步选项
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_bai}同步选项解析:${gl_bai}"
        
        if [[ "$options" == *"-a"* ]]; then
            echo -e "  ${gl_bai}  - archive: 归档模式，保留所有文件属性${gl_bai}"
        fi
        if [[ "$options" == *"-v"* ]]; then
            echo -e "  ${gl_bai}  - verbose: 详细输出模式${gl_bai}"
        fi
        if [[ "$options" == *"-h"* ]]; then
            echo -e "  ${gl_bai}  - human-readable: 人类可读的文件大小${gl_bai}"
        fi
        if [[ "$options" == *"-z"* ]]; then
            echo -e "  ${gl_bai}  - compress: 传输时压缩数据${gl_bai}"
        fi
        if [[ "$options" == *"--progress"* ]]; then
            echo -e "  ${gl_bai}  - progress: 显示传输进度${gl_bai}"
        fi
        if [[ "$options" == *"--delete"* ]]; then
            echo -e "  ${gl_bai}  - delete: 删除目标目录中多余的文件${gl_bai}"
        fi
        if [[ "$options" == *"--delete-delay"* ]]; then
            echo -e "  ${gl_bai}  - delete-delay: 延迟删除文件，传输完成后删除${gl_bai}"
        fi
        if [[ "$options" == *"--checksum"* ]]; then
            echo -e "  ${gl_bai}  - checksum: 基于校验和而非大小和时间决定是否跳过${gl_bai}"
        fi
        if [[ "$options" == *"--no-perms"* ]]; then
            echo -e "  ${gl_bai}  - no-perms: 不保留权限${gl_bai}"
        fi
        if [[ "$options" == *"--no-owner"* ]]; then
            echo -e "  ${gl_bai}  - no-owner: 不保留所有者${gl_bai}"
        fi
        if [[ "$options" == *"--no-group"* ]]; then
            echo -e "  ${gl_bai}  - no-group: 不保留组${gl_bai}"
        fi
        if [[ "$options" == *"--bwlimit"* ]]; then
            local bwlimit=$(echo "$options" | grep -o -- "--bwlimit=[0-9]*" | cut -d= -f2)
            echo -e "  ${gl_bai}  - bwlimit: 限速 ${bwlimit}KB/s${gl_bai}"
        fi
        if [[ "$options" == *"--exclude"* ]]; then
            local excludes=$(echo "$options" | grep -o -- "--exclude='[^']*'" || echo "$options" | grep -o -- '--exclude=[^[:space:]]*')
            echo -e "  ${gl_bai}  - exclude: 排除以下文件:${gl_bai}"
            for exclude in $excludes; do
                local pattern=$(echo "$exclude" | sed "s/--exclude='//" | sed "s/'$//" | sed "s/--exclude=//")
                echo -e "    ${gl_bai}    * $pattern${gl_bai}"
            done
        fi
        
        # 目录状态检查
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_bai}源目录状态检查:${gl_bai}"
        
        if [[ -d "$source_path" ]]; then
            local source_size=$(du -sh "$source_path" 2>/dev/null | cut -f1)
            local source_file_count=$(find "$source_path" -type f 2>/dev/null | wc -l)
            local source_dir_count=$(find "$source_path" -type d 2>/dev/null | wc -l)
            
            echo -e "  ${gl_bai}  - 存在: ${gl_lv}是${gl_bai}"
            echo -e "  ${gl_bai}  - 总大小: ${gl_bai}$source_size"
            echo -e "  ${gl_bai}  - 文件数量: ${gl_bai}$source_file_count"
            echo -e "  ${gl_bai}  - 目录数量: ${gl_bai}$source_dir_count"
            
            # 权限检查
            if [[ -r "$source_path" ]]; then
                echo -e "  ${gl_bai}  - 读取权限: ${gl_lv}正常${gl_bai}"
            else
                echo -e "  ${gl_bai}  - 读取权限: ${gl_hong}不足${gl_bai}"
            fi
            
            # 最近修改时间
            local mod_time=$(stat -c "%y" "$source_path" 2>/dev/null | cut -d'.' -f1)
            echo -e "  ${gl_bai}  - 最后修改: ${gl_bai}${mod_time:-未知}"
            
        else
            echo -e "  ${gl_bai}  - 存在: ${gl_hong}否${gl_bai}"
            echo -e "  ${gl_bai}  - 状态: ${gl_hong}目录不存在!${gl_bai}"
        fi
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_bai}目标目录状态检查:${gl_bai}"
        
        if [[ -d "$target_path" ]]; then
            local target_size=$(du -sh "$target_path" 2>/dev/null | cut -f1)
            local target_file_count=$(find "$target_path" -type f 2>/dev/null | wc -l)
            local target_dir_count=$(find "$target_path" -type d 2>/dev/null | wc -l)
            
            echo -e "  ${gl_bai}  - 存在: ${gl_lv}是${gl_bai}"
            echo -e "  ${gl_bai}  - 总大小: ${gl_bai}$target_size"
            echo -e "  ${gl_bai}  - 文件数量: ${gl_bai}$target_file_count"
            echo -e "  ${gl_bai}  - 目录数量: ${gl_bai}$target_dir_count"
            
            # 权限检查
            if [[ -w "$target_path" ]]; then
                echo -e "  ${gl_bai}  - 写入权限: ${gl_lv}正常${gl_bai}"
            else
                echo -e "  ${gl_bai}  - 写入权限: ${gl_hong}不足${gl_bai}"
            fi
            
            # 磁盘空间检查
            local disk_info=$(df -h "$target_path" 2>/dev/null | tail -1)
            if [[ -n "$disk_info" ]]; then
                local fs_type=$(echo "$disk_info" | awk '{print $1}')
                local total_space=$(echo "$disk_info" | awk '{print $2}')
                local used_space=$(echo "$disk_info" | awk '{print $3}')
                local avail_space=$(echo "$disk_info" | awk '{print $4}')
                local use_percent=$(echo "$disk_info" | awk '{print $5}')
                
                echo -e "  ${gl_bai}  - 文件系统: ${gl_bai}$fs_type"
                echo -e "  ${gl_bai}  - 总空间: ${gl_bai}$total_space"
                echo -e "  ${gl_bai}  - 已用空间: ${gl_bai}$used_space ($use_percent)"
                echo -e "  ${gl_bai}  - 可用空间: ${gl_bai}$avail_space"
                
                # 如果可用空间小于源目录大小的警告
                if [[ -n "$source_size" ]] && [[ "$source_size" =~ ^[0-9.]+[KMGTPE]?$ ]]; then
                    local source_bytes=$(echo "$source_size" | numfmt --from=iec 2>/dev/null)
                    local avail_bytes=$(echo "$avail_space" | numfmt --from=iec 2>/dev/null)
                    
                    if [[ -n "$source_bytes" ]] && [[ -n "$avail_bytes" ]] && [[ "$source_bytes" -gt "$avail_bytes" ]]; then
                        echo -e "  ${gl_hong}警告: 目标磁盘空间不足!${gl_bai}"
                        echo -e "  ${gl_hong}源目录大小 ($source_size) 大于可用空间 ($avail_space)${gl_bai}"
                    fi
                fi
            fi
            
        else
            echo -e "  ${gl_bai}  - 存在: ${gl_huang}否${gl_bai}"
            echo -e "  ${gl_bai}  - 状态: 目录不存在，执行同步时会自动创建${gl_bai}"
        fi
        
        # 路径类型检测
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_bai}路径类型检测:${gl_bai}"
        
        if [[ "$source_path" =~ ^// ]] || [[ "$source_path" =~ ^smb:// ]] || mount | grep -q " on $source_path "; then
            echo -e "  ${gl_bai}  - 源路径类型: ${gl_huang}网络共享/挂载点${gl_bai}"
        elif [[ "$source_path" =~ ^/mnt/ ]] || [[ "$source_path" =~ ^/media/ ]]; then
            echo -e "  ${gl_bai}  - 源路径类型: ${gl_huang}挂载点${gl_bai}"
        else
            echo -e "  ${gl_bai}  - 源路径类型: ${gl_lv}本地目录${gl_bai}"
        fi
        
        if [[ "$target_path" =~ ^// ]] || [[ "$target_path" =~ ^smb:// ]] || mount | grep -q " on $target_path "; then
            echo -e "  ${gl_bai}  - 目标路径类型: ${gl_huang}网络共享/挂载点${gl_bai}"
        elif [[ "$target_path" =~ ^/mnt/ ]] || [[ "$target_path" =~ ^/media/ ]]; then
            echo -e "  ${gl_bai}  - 目标路径类型: ${gl_huang}挂载点${gl_bai}"
        else
            echo -e "  ${gl_bai}  - 目标路径类型: ${gl_lv}本地目录${gl_bai}"
        fi
        
        # 执行命令预览
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_bai}执行命令预览:${gl_bai}"
        echo -e "  ${gl_bai}  - 正向同步: ${gl_zi}rsync $options \"$source_path\" \"$target_path\"${gl_bai}"
        echo -e "  ${gl_bai}  - 反向同步: ${gl_zi}rsync $options \"$target_path\" \"$source_path\"${gl_bai}"
        
        # 定时任务检查
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_bai}定时任务检查:${gl_bai}"
        
        local cron_count=$(crontab -l 2>/dev/null | grep -c "local_rsync_run $num")
        if [[ $cron_count -gt 0 ]]; then
            local cron_jobs=$(crontab -l 2>/dev/null | grep "local_rsync_run $num")
            echo -e "  ${gl_bai}  - 定时任务: ${gl_lv}已设置 ($cron_count 个)${gl_bai}"
            while IFS= read -r cron_line; do
                echo -e "  ${gl_bai}    * $cron_line${gl_bai}"
            done <<< "$cron_jobs"
        else
            echo -e "  ${gl_bai}  - 定时任务: ${gl_huang}未设置${gl_bai}"
        fi
        
        # 建议
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "  ${gl_bai}同步建议:${gl_bai}"
        
        if [[ "$options" == *"--delete"* ]]; then
            echo -e "  ${gl_bai}  - ${gl_huang}⚠ 警告: 此任务会删除目标目录中多余的文件${gl_bai}"
        fi
        
        if [[ ! -d "$source_path" ]]; then
            echo -e "  ${gl_bai}  - ${gl_hong}✗ 错误: 源目录不存在，同步将失败${gl_bai}"
        fi
        
        if [[ ! -d "$target_path" ]] && [[ ! -w "$(dirname "$target_path")" ]]; then
            echo -e "  ${gl_bai}  - ${gl_huang}⚠ 注意: 目标目录不存在且父目录不可写，同步将失败${gl_bai}"
        fi
        
        if [[ "$options" != *"--no-perms"* ]] && [[ "$options" != *"--no-owner"* ]] && [[ "$options" != *"--no-group"* ]]; then
            if [[ "$source_path" =~ ^// ]] || [[ "$target_path" =~ ^// ]]; then
                echo -e "  ${gl_bai}  - ${gl_huang}💡 建议: 网络共享建议使用权限友好模式${gl_bai}"
            fi
        fi
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 本地同步任务管理主菜单 - 优化版 (已添加反向同步选项)
local_rsync_manager() {
    local menu_name="${1:-上一级选单}"
    local_init_globals || return 1

    while true; do
        install sshpass rsync
        clear
        local_list_tasks
        echo ""
        local_view_schedules
        echo ""
        echo -e "${gl_zi}>>> Rsync本地同步工具${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo "本地目录之间同步，支持增量同步，高效稳定。"
        df -hT | grep -E "(cifs|smb)" 2>/dev/null || echo -e "${gl_huang}无Samba/CIFS挂载${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}创建新任务           ${gl_bufan}2.  ${gl_bai}查看任务详情"
        echo -e "${gl_bufan}3.  ${gl_bai}执行正向同步         ${gl_bufan}4.  ${gl_bai}执行反向同步"
        echo -e "${gl_bufan}5.  ${gl_bai}批量执行所有任务     ${gl_bufan}6.  ${gl_bai}删除同步任务"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}7.  ${gl_bai}创建定时任务         ${gl_bufan}8.  ${gl_bai}删除定时任务"
        echo -e "${gl_bufan}9.  ${gl_bai}编辑cron文件         ${gl_bufan}10. ${gl_bai}查看cron文件"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}11. ${gl_bai}挂载Win11-D          ${gl_bufan}12. ${gl_bai}卸载Win11-D"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单       ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "请输入你的选择: " choice
        case $choice in
        1)  local_add_task ;;                       # 创建新任务
        2)  local_show_task_details ;;              # 查看任务详情 
        3)  local_forward_sync_menu ;;              # 执行正向同步
        4)  local_reverse_sync_menu ;;              # 执行反向同步
        5)  local_run_all_tasks ;;                  # 批量执行所有任务
        6)  local_delete_task ;;                    # 删除同步任务
        7)  local_schedule_task ;;                  # 创建定时任务
        8)  local_delete_schedule ;;                # 删除定时任务
        9)  edit_crontab; continue ;;               # 编辑cron文件
        10) view_raw_crontab ;;                     # 查看cron文件
        11) local_mount_win11d_menu ;;              # 挂载Win11-D
        12) local_umount_win11d_menu ;;             # 卸载Win11-D
        0)  cancel_return "$menu_name"; break ;;    # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;             # 感谢使用，再见！
        *) handle_invalid_input ;;                  # 无效的输入,请重新输入!
        esac
    done
}

###### Linux计划任务
# 显示cron任务列表（不含标题和边框，用于菜单集成）
show_crontab_list() {
    if ! command -v crontab &>/dev/null; then
        echo -e "${gl_hong}错误：crontab命令不存在${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 获取当前用户的crontab内容
    local crontab_content
    crontab_content=$(crontab -l 2>/dev/null)

    if [[ -n "$crontab_content" ]]; then
        # 过滤出有效的cron任务（排除空行和注释行）
        local valid_tasks
        valid_tasks=$(echo "$crontab_content" | grep -v '^#' | grep -v '^[[:space:]]*$')

        if [[ -n "$valid_tasks" ]]; then

            # 显示过滤后的任务并编号
            local line_number=1
            while IFS= read -r line; do
                if [[ -n "$line" && ! "$line" =~ ^[[:space:]]*# ]]; then
                    echo -e "${gl_huang}$(printf "%d" $line_number). ${gl_lv}$line${gl_bai}"
                    ((line_number++))
                fi
            done <<<"$crontab_content"

            # 统计有效任务数量
            local total_valid_tasks
            total_valid_tasks=$(echo "$valid_tasks" | wc -l)
            # log_ok "共列出 $total_valid_tasks 个有效任务"
            return 0
        else
            echo -e "${gl_huang}当前用户没有有效的${gl_bufan}crontab${gl_huang}任务${gl_bai}（${gl_lv}只有注释和空行${gl_bai}）"
            return 0
        fi
    else
        echo -e "${gl_huang}当前用户没有${gl_bufan}crontab${gl_huang}任务${gl_bai}"
        return 0
    fi
}

# 列出所有有效的cron任务（排除注释和空行）- 独立调用版本
list_crontab() {
    clear
    echo -e "${gl_zi}>>> 查看所有有效的cron任务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if ! command -v crontab &>/dev/null; then
        log_error "crontab命令不存在，请检查系统"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 调用显示函数
    show_crontab_list

    break_end
}

# 编辑crontab（使用默认编辑器）
edit_crontab() {
    clear
    echo -e "${gl_zi}>>> 编辑cron文件${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if ! command -v crontab &>/dev/null; then
        log_error "crontab命令不存在，请检查系统"
        exit_animation    # 即将退出动画
        return 1
    fi

    echo -e "${gl_bai}正在打开${gl_lv}crontab${gl_bai}编辑器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    log_warn "请谨慎编辑，保存后更改将立即生效"

    if crontab -e; then
        log_ok "crontab编辑完成"
    else
        log_error "crontab编辑失败"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 添加新cron任务
add_crontab() {
    clear
    echo -e "${gl_zi}>>> 添加新的cron任务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if ! command -v crontab &>/dev/null; then
        log_error "crontab命令不存在，请检查系统"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 先显示当前任务列表
    show_crontab_list

    local temp_file
    temp_file=$(mktemp)

    # 保存当前crontab
    crontab -l 2>/dev/null >"$temp_file"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e ""
    echo -e "${gl_bufan}请按以下格式输入cron表达式和命令：${gl_bai}"
    echo -e "${gl_bufan}*   *   *   *   *   ${gl_huang}要执行的命令${gl_bai}/${gl_hong}脚本路径${gl_bai}\n\
${gl_zi}|   ${gl_lan}|   ${gl_huang}|   ${gl_lv}|   ${gl_hong}|${gl_bai}\n\
${gl_zi}|   ${gl_lan}|   ${gl_huang}|   ${gl_lv}|   ${gl_hong}└── ${gl_hong}星期 (0-7, 0和7都代表周日)${gl_bai}\n\
${gl_zi}|   ${gl_lan}|   ${gl_huang}|   ${gl_lv}└────── ${gl_lv}月份 (1-12)${gl_bai}\n\
${gl_zi}|  ${gl_lan} |   ${gl_huang}└────────── ${gl_huang}日期 (1-31)${gl_bai}\n\
${gl_zi}|   ${gl_lan}└────────────── ${gl_lan}小时 (0-23)${gl_bai}\n\
${gl_zi}└────────────────── ${gl_zi}分钟 (0-59)${gl_bai}"
    echo -e ""
    echo -e "${gl_bai}任务示例: ${gl_lv}0 1 * * * /path/to/script.sh${gl_bai}"
    echo -e "${gl_bai}示例说明: 表达式 ${gl_lv}0 1 * * *${gl_bai} 精准匹配 “每天凌晨 ${gl_huang}1 ${gl_bai}点整” 执行任务"

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请输入cron任务 (${gl_huang}0${gl_bai}返回): ")" new_cron

    if [[ "$new_cron" == "0" ]]; then
        rm -f "$temp_file"
        cancel_return
        return
    fi

    if [[ -n "$new_cron" ]]; then
        # 添加新行到临时文件
        echo "$new_cron" >>"$temp_file"

        # 更新crontab
        if crontab "$temp_file" 2>/dev/null; then
            log_ok "任务添加成功"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_lv}已添加的任务：${gl_bai}"
            echo -e "${gl_hui}$new_cron${gl_bai}"
        else
            log_error "任务添加失败，请检查cron表达式格式"
        fi
    else
        log_warn "输入为空，未添加任何任务"
    fi

    rm -f "$temp_file"
    break_end
}

# 删除cron任务（基于有效任务行号）
delete_crontab() {
    clear
    echo -e "${gl_zi}>>> 删除cron任务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if ! command -v crontab &>/dev/null; then
        log_error "crontab命令不存在，请检查系统"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 获取当前用户的crontab内容
    local crontab_content
    crontab_content=$(crontab -l 2>/dev/null)

    # 过滤出有效的cron任务
    local valid_tasks
    valid_tasks=$(echo "$crontab_content" | grep -v '^#' | grep -v '^[[:space:]]*$')

    if [[ -z "$valid_tasks" ]]; then
        echo -e "${gl_huang}当前用户没有有效的${gl_bufan}crontab${gl_huang}任务可删除${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 显示当前有效任务并编号
    echo -e "${gl_lv}当前crontab有效任务列表：${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    local line_number=1
    local task_lines=()

    # 第一遍：显示任务并存储行号
    while IFS= read -r line; do
        if [[ -n "$line" && ! "$line" =~ ^[[:space:]]*# ]]; then
            echo -e "${gl_bufan}$(printf "%2d" $line_number). ${gl_bai}$line"
            task_lines+=("$line")
            ((line_number++))
        fi
    done <<<"$crontab_content"

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请输入要删除的任务行号 (${gl_huang}0${gl_bai}返回): ")" line_num

    [[ "$line_num" == "0" ]] && { cancel_return "上一级选单"; return 1; }

    if [[ ! "$line_num" =~ ^[0-9]+$ ]]; then
        log_error "请输入有效的数字"
        exit_animation    # 即将退出动画
        return
    fi

    # 计算实际总任务数
    local total_tasks=${#task_lines[@]}

    if [[ "$line_num" -gt 0 && "$line_num" -le "$total_tasks" ]]; then
        # 创建临时文件
        local temp_file
        temp_file=$(mktemp)

        # 保存当前crontab
        echo "$crontab_content" >"$temp_file"

        # 查找要删除的任务在实际文件中的行号
        local target_task="${task_lines[$((line_num - 1))]}"
        local task_deleted=0

        # 删除对应行
        while IFS= read -r line; do
            if [[ "$line" == "$target_task" && "$task_deleted" -eq 0 ]]; then
                # 删除此行（不写入新文件）
                task_deleted=1
                continue
            fi
            echo "$line" >>"${temp_file}.tmp"
        done <"$temp_file"

        mv "${temp_file}.tmp" "$temp_file"

        # 更新crontab
        if crontab "$temp_file" 2>/dev/null; then
            log_ok "第 ${line_num} 行任务已删除"
            log_info "删除的任务: ${target_task}"
        else
            log_error "删除任务失败"
        fi

        rm -f "$temp_file" "${temp_file}.tmp"
    else
        log_error "行号超出范围 (1-${total_tasks})"
    fi

    break_end
}

# 清空所有cron任务（修复核心错误+优化体验）
clear_crontab() {
    clear
    echo -e "${gl_zi}>>> 清空所有crontab任务（含注释/空行）${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查crontab命令是否存在
    if ! command -v crontab &>/dev/null; then
        log_error "crontab命令不存在，请安装cron/crontabs组件"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 显示完整的crontab内容（包括注释/空行）
    show_crontab_list

    # 优化警告提示，明确包含注释/空行
    echo -e "${gl_hong}⚠️  警告：这将彻底删除crontab文件（包括所有注释、空行、任务）！${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确认要彻底清空吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    confirm=${confirm:-N} # 回车默认取消

    case "$confirm" in
    [yY] | [yY][eE][sS])
        # 获取当前用户名
        local current_user
        if command -v whoami &>/dev/null; then
            current_user=$(whoami)
        elif command -v id &>/dev/null; then
            current_user=$(id -un)
        else
            current_user="root"
        fi

        echo -e "${gl_lan}正在清空crontab（用户: $current_user） ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 方法1: 强制使用crontab -删除所有内容
        echo -e "${gl_lan}正在执行方法1: 强制删除crontab ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 先尝试crontab -r
        crontab -r 2>/dev/null || true

        # 创建一个真正空的临时文件
        local temp_crontab
        temp_crontab=$(mktemp /tmp/crontab_empty_XXXXXX)

        # 写入一个只有换行符的空白文件（不是空文件）
        printf '\n' >"$temp_crontab"

        # 使用这个空白文件替换当前的crontab
        if crontab "$temp_crontab" 2>/dev/null; then
            log_ok "方法1成功: 已设置空白crontab"
        else
            log_warn "方法1设置失败"
        fi

        # 删除临时文件
        rm -f "$temp_crontab"

        # 再次执行crontab -r确保删除
        crontab -r 2>/dev/null || true

        # 方法2: 直接删除crontab文件
        echo -e "${gl_lan}正在执行方法2: 直接删除crontab文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 常见crontab文件路径
        local crontab_paths=(
            "/var/spool/cron/crontabs/$current_user"
            "/var/spool/cron/$current_user"
        )

        local file_deleted=0
        for crontab_path in "${crontab_paths[@]}"; do
            if [ -f "$crontab_path" ]; then
                echo -e "${gl_lan}找到crontab文件: $crontab_path${gl_bai}"

                # 显示文件内容（查看是否有注释）
                echo -e "${gl_huang}文件内容:${gl_bai}"
                head -20 "$crontab_path" 2>/dev/null || echo "无法读取文件"
                echo ""

                # 尝试删除文件
                if rm -f "$crontab_path" 2>/dev/null; then
                    log_ok "成功删除: $crontab_path"
                    file_deleted=1
                elif sudo rm -f "$crontab_path" 2>/dev/null; then
                    log_ok "使用sudo成功删除: $crontab_path"
                    file_deleted=1
                else
                    log_warn "无法删除: $crontab_path"
                fi
            fi
        done

        # 方法3: 暴力方法 - 创建一个只有换行符的crontab
        echo -e "${gl_lan}正在执行方法3: 创建空白crontab ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 创建一个临时脚本，执行真正的空crontab
        local temp_script
        temp_script=$(mktemp /tmp/cron_clear_XXXXXX.sh)

        cat >"$temp_script" <<'EOF'
#!/bin/bash
# 尝试多种方法清空crontab

USERNAME="$1"

# 方法1: 使用/dev/null作为输入
crontab /dev/null 2>/dev/null || true

# 方法2: 创建一个只有一个换行符的文件
TEMP_FILE=$(mktemp /tmp/cron_empty_XXXXXX)
printf '\n' > "$TEMP_FILE"
crontab "$TEMP_FILE" 2>/dev/null || true
rm -f "$TEMP_FILE"

# 方法3: 使用echo -n设置空内容
echo -n | crontab - 2>/dev/null || true

# 方法4: 使用python清空
python3 -c "
import sys
import os

# 尝试删除当前用户的crontab
try:
    import subprocess
    subprocess.run(['crontab', '-r'], check=False)
except:
    pass

# 创建一个完全空的crontab
temp_file = '/tmp/empty_cron'
with open(temp_file, 'w') as f:
    f.write('')
try:
    subprocess.run(['crontab', temp_file], check=False)
except:
    pass
os.unlink(temp_file)
" 2>/dev/null || true
EOF

        chmod +x "$temp_script"

        # 执行清理脚本
        if "$temp_script" "$current_user" 2>/dev/null; then
            log_ok "方法3: 脚本执行完成"
        else
            log_warn "方法3: 脚本执行可能失败"
        fi

        rm -f "$temp_script"

        # 方法4: 系统级清理（针对root用户）
        if [ "$(id -u)" -eq 0 ]; then
            echo -e "${gl_lan}正在执行方法4: 系统级清理 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

            # 清除系统crontab文件的内容（但不删除文件）
            if [ -f "/etc/crontab" ]; then
                # 备份原文件
                cp -f "/etc/crontab" "/etc/crontab.backup.$(date +%s)" 2>/dev/null

                # 写入一个只有换行符的文件
                printf '\n' >/etc/crontab
                log_ok "已清空/etc/crontab"
            fi

            # 清理cron.d目录
            if [ -d "/etc/cron.d" ]; then
                for file in /etc/cron.d/*; do
                    if [ -f "$file" ] && [[ "$file" != *".placeholder" ]]; then
                        printf '\n' >"$file" 2>/dev/null || true
                    fi
                done
                log_ok "已清空/etc/cron.d/目录中的文件"
            fi
        fi

        # 方法5: 特殊处理 - 创建一个真正的空任务
        echo -e "${gl_lan}正在执行方法5: 创建真正的空任务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 检查是否安装了python3
        if command -v python3 &>/dev/null; then
            python3 -c "
import os
import tempfile

# 创建一个完全空的文件
with tempfile.NamedTemporaryFile(mode='w', delete=False) as f:
    f.write('')
    temp_file = f.name

try:
    # 导入crontab模块（如果可用）
    try:
        from crontab import CronTab
        cron = CronTab(user=True)
        cron.remove_all()
        cron.write()
        print('使用python-crontab模块清空成功')
    except ImportError:
        # 使用系统命令
        os.system('crontab -r 2>/dev/null')
        os.system(f'crontab {temp_file} 2>/dev/null')
        print('使用系统命令清空成功')
except Exception as e:
    print(f'清空失败: {e}')
finally:
    if os.path.exists(temp_file):
        os.unlink(temp_file)
" 2>/dev/null || log_warn "Python清理失败"
        else
            # 使用shell方法
            true | crontab - 2>/dev/null || :
        fi

        # 最终验证
        echo -e "${gl_lv}正在验证crontab是否已清空 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 等待一小会儿，让cron服务更新
        sleep_fractional 0.5

        # 检查crontab
        if crontab -l &>/dev/null; then
            local content
            content=$(crontab -l 2>/dev/null || true)

            # 去除注释和空行后检查是否为空
            local clean_content
            clean_content=$(echo "$content" | sed '/^#/d' | sed '/^$/d')

            if [ -z "$clean_content" ]; then
                if [ -z "$content" ]; then
                    log_ok "✅ 验证通过: crontab已完全清空（无任何内容）"
                else
                    log_ok "✅ 验证通过: crontab已清空（仅剩注释，无有效任务）"
                    echo -e "${gl_huang}注意: 系统保留了默认注释模板${gl_bai}"
                    echo -e "${gl_huang}如需完全删除，请手动删除相关文件${gl_bai}"
                fi
            else
                log_warn "⚠️  验证失败: 仍有内容存在"
                echo -e "${gl_hong}剩余内容:${gl_bai}"
                echo "$content"

                # 显示文件位置建议
                echo -e "\n${gl_huang}建议手动删除以下文件:${gl_bai}"
                for path in "/var/spool/cron/crontabs/$current_user" "/var/spool/cron/$current_user"; do
                    if [ -f "$path" ]; then
                        echo "  rm -f $path"
                    fi
                done
            fi
        else
            log_ok "✅ 验证通过: crontab文件不存在或已清空"
        fi

        # 提供最终建议
        echo -e "\n${gl_zi}清理完成！${gl_bai}"
        echo -e "${gl_huang}如果仍有注释显示，可能是由于:${gl_bai}"
        echo -e "1. 系统默认模板被crontab命令自动生成"
        echo -e "2. crontab缓存未更新（可重启cron服务: systemctl restart cron）"
        echo -e "3. 可尝试直接删除文件: rm -f /var/spool/cron/crontabs/$current_user"
        ;;
    *)
        log_info "已取消清空crontab操作"
        ;;
    esac

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 查看crontab原始内容（包含注释）
view_raw_crontab() {
    clear
    echo -e "${gl_zi}>>> 查看crontab原始内容（包含注释）${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if ! command -v crontab &>/dev/null; then
        log_error "crontab命令不存在，请检查系统"
        exit_animation    # 即将退出动画
        return 1
    fi

    local crontab_content
    crontab_content=$(crontab -l 2>/dev/null)

    if [[ -n "$crontab_content" ]]; then
        echo -e "${gl_lv}当前用户的crontab原始内容：${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        # echo "$crontab_content" | cat -n
        echo -e "$crontab_content" | awk '{printf "%2d    %s\n", NR, $0}'
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 统计总行数
        local total_lines
        total_lines=$(echo "$crontab_content" | wc -l)

        # 统计有效任务数
        local valid_tasks
        valid_tasks=$(echo "$crontab_content" | grep -v '^#' | grep -v '^[[:space:]]*$' | wc -l)

        echo -e "${gl_bai}总行数: ${gl_huang}$total_lines${gl_bai}，有效任务数: ${gl_lv}$valid_tasks${gl_bai}"
    else
        echo -e "${gl_huang}当前用户没有${gl_bufan}crontab${gl_huang}任务${gl_bai}"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 显示crontab服务状态（精简版）
show_crontab_status() {
    # 检查crontab命令是否可用
    if ! command -v crontab &>/dev/null; then
        echo -e "${gl_hong}✗ crontab命令不可用${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 检查cron进程状态
    local cron_process_found=0
    local pid=""
    local cmd=""

    # 使用更广泛的进程搜索
    if ps aux | grep -v grep | grep -E "(cron|crond|CRON)" >/dev/null 2>&1; then
        cron_process_found=1
        pid=$(ps aux | grep -v grep | grep -E "(cron|crond|CRON)" | head -1 | awk '{print $2}')
        cmd=$(ps aux | grep -v grep | grep -E "(cron|crond|CRON)" | head -1 | awk '{for(i=11;i<=NF;i++) printf $i " "}')
        echo -e "${gl_bai}进程状态:${gl_bai} ${gl_lv}✓ cron守护进程正在运行 ${gl_bai}(PID: ${gl_huang}$pid, ${gl_bai}命令: ${gl_huang}$cmd${gl_bai})"
    else
        echo -e "${gl_bai}进程状态:${gl_bai} ${gl_hong}✗ cron守护进程未运行${gl_bai}"
    fi

    # 检查系统服务状态
    local service_status_found=0
    local service_status=""

    # systemd系统
    if command -v systemctl &>/dev/null; then
        local service_name=""
        for service in cron crond cronie; do
            if systemctl list-unit-files --type=service 2>/dev/null | grep -q "^${service}.service"; then
                service_name="$service"
                break
            fi
        done

        if [ -n "$service_name" ]; then
            service_status_found=1
            local status
            status=$(systemctl is-active "$service_name" 2>/dev/null || echo "unknown")
            service_status="$service_name.service: $status"
            if [ "$status" = "active" ]; then
                echo -e "${gl_bai}服务状态:${gl_bai} ${gl_lv}$service_status${gl_bai}"
            elif [ "$status" = "inactive" ]; then
                echo -e "${gl_bai}服务状态:${gl_bai} ${gl_hong}$service_status${gl_bai}"
            else
                echo -e "${gl_bai}服务状态:${gl_bai} ${gl_huang}$service_status${gl_bai}"
            fi
        else
            echo -e "${gl_bai}服务状态:${gl_bai} ${gl_huang}未找到cron服务${gl_bai}"
        fi

    # SysV init系统
    elif command -v service &>/dev/null; then
        local service_name=""
        for service in cron crond; do
            if service --status-all 2>/dev/null | grep -q "\s${service}" ||
                ls /etc/init.d/ 2>/dev/null | grep -q "^${service}$"; then
                service_name="$service"
                break
            fi
        done

        if [ -n "$service_name" ]; then
            service_status_found=1
            local status
            if service "$service_name" status 2>/dev/null | grep -qi "running\|active"; then
                status="运行中"
                echo -e "${gl_bai}服务状态:${gl_bai} ${gl_lv}$service_name: $status${gl_bai}"
            else
                status="停止"
                echo -e "${gl_bai}服务状态:${gl_bai} ${gl_hong}$service_name: $status${gl_bai}"
            fi
        else
            echo -e "${gl_bai}服务状态:${gl_bai} ${gl_huang}未找到cron服务${gl_bai}"
        fi
    else
        echo -e "${gl_bai}服务状态:${gl_bai} ${gl_huang}无法检测服务状态${gl_bai}"
    fi

}

# 检测cron服务信息
detect_cron_service() {
    # 重置变量
    service_command=""
    cron_service_name=""

    # 获取当前用户
    current_user=$(whoami 2>/dev/null || echo "$USER")

    # 检查systemd
    if command -v systemctl &>/dev/null; then
        service_command="systemctl"
        for service in cron crond cronie; do
            if systemctl list-unit-files --type=service 2>/dev/null | grep -q "^${service}.service"; then
                cron_service_name="$service"
                break
            fi
        done

    # 检查SysV init
    elif command -v service &>/dev/null; then
        service_command="service"
        for service in cron crond; do
            if service --status-all 2>/dev/null | grep -q "\s${service}" ||
                ls /etc/init.d/ 2>/dev/null | grep -q "^${service}$"; then
                cron_service_name="$service"
                break
            fi
        done

    # 检查OpenRC
    elif command -v rc-service &>/dev/null; then
        service_command="rc-service"
        cron_service_name="cron"

    # 检查init.d
    elif [ -f "/etc/init.d/cron" ] || [ -f "/etc/init.d/crond" ]; then
        service_command="init.d"
        if [ -f "/etc/init.d/cron" ]; then
            cron_service_name="cron"
        else
            cron_service_name="crond"
        fi
    fi

    echo -e "${gl_huang}检测到: ${service_command:-未知}, 服务名: ${cron_service_name:-未知}${gl_bai}"
}

# 停止cron服务
stop_cron_service() {
    echo -e ""
    echo -e "${gl_zi}>>> 正在停止cron服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检测服务信息
    detect_cron_service

    if [ -n "$service_command" ] && [ -n "$cron_service_name" ]; then
        case "$service_command" in
        "systemctl")
            sudo systemctl stop "$cron_service_name" &&
                log_ok "cron服务已停止" ||
                log_error "停止cron服务失败"
            ;;
        "service")
            sudo service "$cron_service_name" stop &&
                log_ok "cron服务已停止" ||
                log_error "停止cron服务失败"
            ;;
        "rc-service")
            sudo rc-service cron stop &&
                log_ok "cron服务已停止" ||
                log_error "停止cron服务失败"
            ;;
        "init.d")
            sudo "/etc/init.d/$cron_service_name" stop &&
                log_ok "cron服务已停止" ||
                log_error "停止cron服务失败"
            ;;
        esac
    else
        log_error "无法确定如何停止cron服务"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 启动cron服务
start_cron_service() {
    echo -e ""
    echo -e "${gl_zi}>>> 正在启动cron服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检测服务信息
    detect_cron_service

    if [ -n "$service_command" ] && [ -n "$cron_service_name" ]; then
        case "$service_command" in
        "systemctl")
            sudo systemctl start "$cron_service_name" &&
                log_ok "cron服务已启动" ||
                log_error "启动cron服务失败"
            ;;
        "service")
            sudo service "$cron_service_name" start &&
                log_ok "cron服务已启动" ||
                log_error "启动cron服务失败"
            ;;
        "rc-service")
            sudo rc-service cron start &&
                log_ok "cron服务已启动" ||
                log_error "启动cron服务失败"
            ;;
        "init.d")
            sudo "/etc/init.d/$cron_service_name" start &&
                log_ok "cron服务已启动" ||
                log_error "启动cron服务失败"
            ;;
        esac
    else
        log_error "无法确定如何启动cron服务"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 重启cron服务
restart_cron_service() {
    echo -e ""
    echo -e "${gl_zi}>>> 正在重启cron服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检测服务信息
    detect_cron_service

    if [ -n "$service_command" ]; then
        case "$service_command" in
        "systemctl")
            if [ -n "$cron_service_name" ]; then
                if sudo systemctl restart "$cron_service_name"; then
                    log_ok "cron服务重启成功"
                    sleep_fractional 1
                    sudo systemctl status "$cron_service_name" --no-pager --lines=3
                else
                    log_error "cron服务重启失败"
                fi
            else
                log_error "未找到cron服务名，尝试通用方法 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                sudo systemctl restart cron crond cronie 2>/dev/null ||
                    log_warn "无法重启服务，可能需要手动操作"
            fi
            ;;
        "service")
            if [ -n "$cron_service_name" ]; then
                if sudo service "$cron_service_name" restart; then
                    log_ok "cron服务重启成功"
                    sleep_fractional 1
                    sudo service "$cron_service_name" status 2>/dev/null || true
                else
                    log_error "cron服务重启失败"
                fi
            else
                log_error "未找到cron服务名"
            fi
            ;;
        "rc-service")
            if sudo rc-service cron restart; then
                log_ok "cron服务重启成功"
            else
                log_error "cron服务重启失败"
            fi
            ;;
        "init.d")
            if [ -f "/etc/init.d/cron" ]; then
                sudo /etc/init.d/cron restart &&
                    log_ok "cron服务重启成功" ||
                    log_error "cron服务重启失败"
            elif [ -f "/etc/init.d/crond" ]; then
                sudo /etc/init.d/crond restart &&
                    log_ok "crond服务重启成功" ||
                    log_error "crond服务重启失败"
            else
                log_error "找不到init.d脚本"
            fi
            ;;
        esac
    else
        # 直接尝试杀死进程并重新启动
        log_warn "未找到服务管理器，尝试直接重启 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 杀死cron进程
        local cron_pids
        cron_pids=$(pgrep -x "cron\|crond\|cronie" 2>/dev/null)

        if [ -n "$cron_pids" ]; then
            echo -e "${gl_lan}停止cron进程 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            sudo kill $cron_pids 2>/dev/null
            sleep_fractional 1
        fi

        # 尝试启动cron
        echo -e "${gl_lan}启动cron进程 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 尝试不同的启动方式
        if command -v cron &>/dev/null; then
            sudo cron && log_ok "cron启动成功" || log_error "cron启动失败"
        elif command -v crond &>/dev/null; then
            sudo crond && log_ok "crond启动成功" || log_error "crond启动失败"
        else
            log_error "找不到cron守护进程"
        fi
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 重新加载cron配置（不重启服务）
reload_cron_config() {
    echo -e ""
    echo -e "${gl_zi}>>> 重新加载cron配置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检测服务信息
    detect_cron_service

    # 方法1: 使用systemd重新加载
    if [ "$service_command" = "systemctl" ] && [ -n "$cron_service_name" ]; then
        if sudo systemctl reload "$cron_service_name" 2>/dev/null; then
            log_ok "cron配置重新加载成功"
        elif sudo systemctl reload-or-restart "$cron_service_name" 2>/dev/null; then
            log_ok "cron配置已重新加载"
        else
            log_warn "systemd重新加载失败，尝试其他方法 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        fi
    fi

    # 方法2: 发送SIGHUP信号给cron进程
    local cron_pids
    cron_pids=$(pgrep -x "cron\|crond\|cronie" 2>/dev/null)

    if [ -n "$cron_pids" ]; then
        echo -e "${gl_lan}向cron进程发送重载信号 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if sudo kill -HUP $cron_pids 2>/dev/null; then
            log_ok "已发送重载信号给cron进程"
        else
            log_error "无法发送重载信号"
        fi
    else
        log_warn "未找到运行的cron进程"
    fi

    # 方法3: 通过crontab命令触发重载
    echo -e "${gl_lan}通过crontab命令触发重载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if crontab -l >/dev/null 2>&1; then
        # 重新加载当前用户的crontab
        crontab -l | crontab - 2>/dev/null &&
            log_ok "当前用户crontab已重新加载" ||
            log_warn "重新加载当前用户crontab失败"
    fi

    # 对于系统crontab，可以尝试重启服务
    echo -e "${gl_huang}提示：要重新加载系统crontab（/etc/crontab），需要重启服务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 函数_创建脚本文件
create_script_in_opt() {
    # 显示标题
    echo -e ""
    echo -e "${gl_zi}>>> 在${gl_huang}/opt/scripts${gl_zi}创建脚本文件并用${gl_lv}nano${gl_zi}打开${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查并安装nano
    install nano

    # 定义目标目录
    local target_dir="/opt/scripts"

    # 检查并创建目录
    if [ ! -d "$target_dir" ]; then
        log_info "目录 ${gl_lv}$target_dir${gl_bai} 不存在，正在创建 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        mkdir -p "$target_dir"
        if [ $? -eq 0 ]; then
            log_ok "目录创建成功。"
        else
            log_error "目录创建失败。"
            return 1
        fi
    fi

    while true; do
        # 提示输入脚本名称
        read -r -e -p "$(echo -e "${gl_bai}请输入脚本名称 (直接回车使用 ${gl_lv}test${gl_bai}, ${gl_huang}0${gl_bai}返回): ")" script_name

        # 处理用户输入
        case "$script_name" in
        0) cancel_return; return 0 ;;
        "") script_name="test" ;;
        *)
            # 使用用户输入的脚本名称
            ;;
        esac

        # 确保文件名以 .sh 结尾
        if [[ ! "$script_name" =~ \.sh$ ]]; then
            script_name="${script_name}.sh"
        fi

        local file_path="$target_dir/$script_name"

        # 检查文件是否已存在
        if [ -f "$file_path" ]; then
            log_warn "文件 $file_path 已存在。是否覆盖？"
            read -r -e -p "$(echo -e "${gl_bai}确认覆盖吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
            case "$confirm" in
            [Yy] | [Yy][Ee][Ss])
                log_info "将覆盖现有文件。"
                ;;
            *)
                log_info "跳过创建。"
                continue
                ;;
            esac
        fi

        # 创建脚本文件
        touch "$file_path"
        if [ $? -eq 0 ]; then
            echo -e "${gl_bai}文件 ${gl_huang}$file_path ${gl_bai}创建成功。"

            # 添加执行权限
            chmod +x "$file_path"

            # 使用 nano 打开文件
            nano "$file_path"

            # 获取nano的退出状态
            local nano_exit_code=$?

            # 打印脚本文件的绝对路径
            echo -e ""
            echo -e "${gl_zi}>>> 脚本文件使用说明${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}请按以下格式输入cron表达式和命令：${gl_bai}"
            echo -e "${gl_bufan}*   *   *   *   *   ${gl_huang}要执行的命令${gl_bai}/${gl_hong}脚本路径${gl_bai}\n\
${gl_zi}|   ${gl_lan}|   ${gl_huang}|   ${gl_lv}|   ${gl_hong}|${gl_bai}\n\
${gl_zi}|   ${gl_lan}|   ${gl_huang}|   ${gl_lv}|   ${gl_hong}└── ${gl_hong}星期 (0-7, 0和7都代表周日)${gl_bai}\n\
${gl_zi}|   ${gl_lan}|   ${gl_huang}|   ${gl_lv}└────── ${gl_lv}月份 (1-12)${gl_bai}\n\
${gl_zi}|  ${gl_lan} |   ${gl_huang}└────────── ${gl_huang}日期 (1-31)${gl_bai}\n\
${gl_zi}|   ${gl_lan}└────────────── ${gl_lan}小时 (0-23)${gl_bai}\n\
${gl_zi}└────────────────── ${gl_zi}分钟 (0-59)${gl_bai}"
            echo -e ""
            echo -e "${gl_bai}任务示例: ${gl_zi}0 ${gl_lan}1 ${gl_huang}* ${gl_lv}* ${gl_hong}* ${gl_bufan}$file_path${gl_bai}"
            echo -e "${gl_bai}示例说明: 表达式 ${gl_lv}0 1 * * *${gl_bai} 精准匹配 “每天凌晨 ${gl_huang}1 ${gl_bai}点整” 执行任务"

            if [ $nano_exit_code -eq 0 ]; then
                echo -e "${gl_bai}脚本文件：${gl_lv}$file_path${gl_bai} 编辑完成。"
                chmod +x "$file_path"
                # ls -l --color=auto "$file_path"   # 自动根据终端决定是否显示颜色

                # 获取文件名（%n）和权限（(%a/%A)）
                filename=$(stat -c "%n" "$file_path")
                perm=$(stat -c "(%a/%A)" "$file_path")

                # 带颜色输出（假设颜色变量已定义）
                echo -e "文件：${gl_lv}${filename}${gl_bai}  权限：${gl_huang}${perm}${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
            else
                log_error "nano 编辑异常退出 (退出码: $nano_exit_code)，但文件已创建。"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
            fi

            return 0
        else
            log_error "文件创建失败。"
            # 询问是否重试
            read -r -e -p "$(echo -e "${gl_bai}是否重试? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" retry
            case "$retry" in
            [Yy] | [Yy][Ee][Ss])
                continue
                ;;
            *)
                return 1
                ;;
            esac
        fi
    done
}

# 主菜单函数
linux_crontab_management() {
    while true; do
        clear
        echo -e "${gl_zi}>>> cron计划任务管理器${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        show_crontab_status
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 直接显示当前的任务列表
        show_crontab_list

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}停止cron服务            ${gl_bufan}2.  ${gl_bai}启动cron服务"
        echo -e "${gl_bufan}3.  ${gl_bai}重启cron服务            ${gl_bufan}4.  ${gl_bai}重载cron配置"
        echo -e "${gl_bufan}5.  ${gl_bai}创建脚本文件            ${gl_bufan}6.  ${gl_bai}删除脚本文件"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}7.  ${gl_bai}添加cron任务            ${gl_bufan}8.  ${gl_bai}删除cron任务"
        echo -e "${gl_bufan}9.  ${gl_bai}编辑cron文件            ${gl_bufan}10. ${gl_bai}查看cron文件"
        echo -e "${gl_bufan}11. ${gl_bai}刷新任务列表            ${gl_bufan}12. ${gl_bai}清空cron任务"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单          ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "$(echo -e "${gl_bai}请输入你的选择: ")" choice

        case "$choice" in
        1)  stop_cron_service ;;                        # 停止cron服务
        2)  start_cron_service ;;                       # 启动cron服务
        3)  restart_cron_service ;;                     # 重启cron服务
        4)  reload_cron_config ;;                       # 重载cron配置
        5)  create_script_in_opt ;;                     # 创建脚本文件
        6)  cd /opt/scripts && interactive_delete ;;    # 删除脚本文件
        7)  add_crontab; continue ;;                    # 添加cron任务
        8)  delete_crontab; continue ;;                 # 删除cron任务
        9)  edit_crontab; continue ;;                   # 编辑cron文件
        10) view_raw_crontab ;;                         # 查看cron文件
        11) continue ;;                                 # 刷新任务列表
        12) clear_crontab; continue ;;                  # 清空cron任务
        0)  cancel_return "系统工具"; break ;;           # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;                 # 感谢使用，再见！
        *) handle_invalid_input ;;                      # 无效的输入,请重新输入!
        esac
    done
}

# 显示1Panel状态函数
show_1panel_status() {

    # 获取版本信息
    if command -v 1panel &>/dev/null; then
        # 尝试获取版本信息，处理可能的错误输出
        local version_output=$(1panel version 2>&1 | grep -v "Too few arguments" | grep -v "^$")
        if echo "$version_output" | grep -q "version:"; then
            local version=$(echo "$version_output" | grep "version:" | head -1 | sed 's/.*version: //')
            echo -e "${gl_bai}1Panel版本信息: ${gl_lv}$version${gl_bai}"
        elif [ -n "$version_output" ] && [ "$version_output" != "Too few arguments." ]; then
            echo -e "${gl_bai}版本信息: ${gl_lv}$version_output${gl_bai}"
        else
            echo -e "${gl_huang}无法获取版本信息${gl_bai}"
        fi
    else
        echo -e "${gl_huang}1panel 命令未找到${gl_bai}"
    fi

    # 获取 Core 运行状态
    if command -v 1pctl &>/dev/null; then
        local core_output=$(1pctl status core 2>/dev/null)
        if [ -n "$core_output" ]; then
            # 提取 Core 状态行
            local core_status=$(echo "$core_output" | grep "Core:" | head -1)
            if [ -n "$core_status" ]; then
                # 根据状态添加颜色
                if echo "$core_status" | grep -q "正在运行\|running\|active\|🟢"; then
                    echo -e "${gl_bai}Core  运行状态：${gl_lv}$core_status${gl_bai}"
                elif echo "$core_status" | grep -q "已停止\|stopped\|inactive\|🔴"; then
                    echo -e "${gl_bai}Core  运行状态：${gl_hong}$core_status${gl_bai}"
                elif echo "$core_status" | grep -q "失败\|failed\|❌"; then
                    echo -e "${gl_bai}Core  运行状态：${gl_hong}$core_status${gl_bai}"
                else
                    echo -e "${gl_bai}Core  运行状态：${gl_huang}$core_status${gl_bai}"
                fi
            else
                # 如果没有找到 Core 状态，显示整个输出
                echo -e "${gl_bai}Core  运行状态：${gl_huang}$core_output${gl_bai}" | head -3
            fi
        else
            echo -e "${gl_bai}Core  运行状态：${gl_huang}无法获取 Core 状态${gl_bai}"
        fi
    else
        echo -e "${gl_bai}Core  运行状态：${gl_huang}1pctl 命令未找到${gl_bai}"
    fi

    # 获取 Agent 运行状态
    if command -v 1pctl &>/dev/null; then
        local agent_output=$(1pctl status agent 2>/dev/null)
        if [ -n "$agent_output" ]; then
            # 提取 Agent 状态行
            local agent_status=$(echo "$agent_output" | grep "Agent:" | head -1)
            if [ -n "$agent_status" ]; then
                # 根据状态添加颜色
                if echo "$agent_status" | grep -q "正在运行\|running\|active\|🟢"; then
                    echo -e "${gl_bai}Agent 运行状态：${gl_lv}$agent_status${gl_bai}"
                elif echo "$agent_status" | grep -q "已停止\|stopped\|inactive\|🔴"; then
                    echo -e "${gl_bai}Agent 运行状态：${gl_hong}$agent_status${gl_bai}"
                elif echo "$agent_status" | grep -q "失败\|failed\|❌"; then
                    echo -e "${gl_bai}Agent 运行状态：${gl_hong}$agent_status${gl_bai}"
                else
                    echo -e "${gl_bai}Agent 运行状态：${gl_huang}$agent_status${gl_bai}"
                fi
            else
                # 如果没有找到 Agent 状态，显示整个输出
                echo -e "${gl_bai}Agent 运行状态：${gl_huang}$agent_output${gl_bai}" | head -3
            fi
        else
            echo -e "${gl_bai}Agent 运行状态：${gl_huang}无法获取 Agent 状态${gl_bai}"
        fi
    else
        echo -e "${gl_bai}Agent 运行状态：${gl_huang}1pctl 命令未找到${gl_bai}"
    fi
}

# 显示备份信息函数
show_backup_info() {
    local backup_dir="/opt/1panel/backup/system_snapshot"
    if [ -d "$backup_dir" ]; then
        local file_count=$(ls -1 "$backup_dir"/*.tar.gz 2>/dev/null | wc -l)

        if [ "$file_count" -eq 0 ]; then
            echo -e "${gl_hong}未找到备份文件${gl_bai}"
        else
            echo -e "${gl_bai}1Panel备份目录: ${gl_huang}${backup_dir}${gl_bai}"

            local i=1
            for file in "$backup_dir"/*.tar.gz; do
                if [ -f "$file" ]; then
                    local filename=$(basename "$file")
                    local filesize=$(du -h "$file" | cut -f1)
                    local filetime=$(stat -c "%y" "$file" | cut -d' ' -f1,2 | cut -d'.' -f1)
                    echo -e "${gl_huang}$i. ${gl_lv}${filename}  ${gl_bai}${filesize}"
                    # echo -e "   大小: ${filesize} | 时间: ${filetime}"
                    ((i++))
                fi
            done
        fi
    else
        echo -e "${gl_huang}备份目录不存在: ${gl_lv}$backup_dir${gl_bai}"
    fi
}

view_auth_log() {
    local lines=${1:-30} # 默认显示20行，可通过参数自定义

    echo -e "${gl_bai}正在显示最新 ${gl_lv}$lines${gl_bai} 条日志（${gl_huang}按 Ctrl+C 退出${gl_bai}） ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    sudo tail -n "$lines" -f /var/log/auth.log
}

# ============================================
# 1Panel 命令行工具管理函数
# ============================================

linux_1panel_cli_menu() {
    while true; do
        clear
        echo -e "${gl_zi}>>> 1Panel 命令行工具管理${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        show_1panel_status
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        show_backup_info
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}关闭1Panel            ${gl_bufan}2.  ${gl_bai}开启1Panel"
        echo -e "${gl_bufan}3.  ${gl_bai}重启1Panel            ${gl_bufan}4.  ${gl_bai}获取用户信息"
        echo -e "${gl_bufan}5.  ${gl_bai}重置系统信息          ${gl_bufan}6.  ${gl_bai}修改监听IP"
        echo -e "${gl_bufan}7.  ${gl_bai}修改系统信息          ${gl_bufan}8.  ${gl_bai}恢复服务及数据"
        echo -e "${gl_bufan}9.  ${gl_bai}管理备份文件          ${gl_bufan}10. ${gl_bai}实时监控日志"
        echo -e "${gl_bufan}11. ${gl_bai}Rsync远程同步工具     ${gl_bufan}12. ${gl_bai}Rsync本地同步工具"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lv}66. ${gl_bai}安装1Panel            ${gl_hong}99. ${gl_bai}卸载1Panel"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单        ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " choice

        case $choice in
        1) stop_1panel ;;                                           # 关闭1Panel 
        2) start_1panel ;;                                          # 开启1Panel
        3) restart_1panel ;;                                        # 重启1Panel
        4) user-info_1panel ;;                                      # 获取用户信息
        5) 1pctl_reset_menu ;;                                      # 重置系统信息
        6) 1pctl_listen_ip_menu ;;                                  # 修改监听IP
        7) 1pctl_update_menu ;;                                     # 修改系统信息
        8) 1pctl_restore ;;                                         # 恢复服务及数据
        9) linux_file "/opt/1panel/backup/system_snapshot" "1Panel备份文件管理" ;;   # 管理备份文件
        10) view_auth_log ;;                                        # 实时监控日志
        11) remote_rsync_manager "1Panel 命令行工具管理" ;;          # Rsync远程同步工具
        12) local_rsync_manager "1Panel 命令行工具管理" ;;           # Rsync本地同步工具
        66) install_1panel ;;                                       # 安装1Panel
        99) uninstall_1panel ;;                                     # 卸载1Panel
        0) cancel_return "系统工具"; break ;;                        # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;                             # 感谢使用，再见！
        *) handle_invalid_input ;;                                  # 无效的输入,请重新输入!
        esac
    done
}

# 关闭1Panel服务
stop_1panel() {
    echo -e ""
    echo -e "${gl_zi}>>> 正在停止 1Panel 服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if 1pctl stop; then
        log_ok "1Panel 服务已停止"
    else
        log_error "停止 1Panel 服务失败"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 开启1Panel服务
start_1panel() {
    echo -e ""
    echo -e "${gl_zi}>>> 正在启动 1Panel 服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if 1pctl start; then
        log_ok "1Panel 服务已启动"
    else
        log_error "启动 1Panel 服务失败"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 重启1Panel服务
restart_1panel() {
    echo -e ""
    echo -e "${gl_zi}>>> 正在重启 1Panel 服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if 1pctl restart; then
        log_ok "1Panel 服务已重启"
    else
        log_error "重启 1Panel 服务失败"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# --------------------------------------------
# 重置系统信息
# --------------------------------------------
1pctl_reset_menu() {
    while true; do
        clear
        echo -e "${gl_zi}>>> 重置 1Panel 系统信息${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}取消域名绑定        ${gl_bufan}2.  ${gl_bai}取消安全入口"
        echo -e "${gl_bufan}3.  ${gl_bai}取消 HTTPS 登录     ${gl_bufan}4.  ${gl_bai}取消授权 IP 限制"
        echo -e "${gl_bufan}5.  ${gl_bai}取消两步验证"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单      ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " choice

        case $choice in
        1)
            log_warn "即将取消域名绑定"
            read -r -e -p "$(echo -e "${gl_bai}确认要这样吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
            case "$confirm" in
            [Yy]*)
                log_info "正在取消域名绑定 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                if 1pctl reset domain; then
                    log_ok "域名绑定已取消"
                else
                    log_error "取消域名绑定失败"
                fi
                ;;
            *)
                log_info "已取消操作"
                ;;
            esac
            break_end
            ;;
        2)
            log_warn "即将取消安全入口"
            read -r -e -p "$(echo -e "${gl_bai}确认要这样吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
            case "$confirm" in
            [Yy]*)
                log_info "正在取消安全入口 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                if 1pctl reset entrance; then
                    log_ok "安全入口已取消"
                else
                    log_error "取消安全入口失败"
                fi
                ;;
            *)
                log_info "已取消操作"
                ;;
            esac
            break_end
            ;;
        3)
            log_warn "即将取消 HTTPS 登录"
            read -r -e -p "$(echo -e "${gl_bai}确认要这样吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
            case "$confirm" in
            [Yy]*)
                log_info "正在取消 HTTPS 登录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                if 1pctl reset https; then
                    log_ok "HTTPS 登录已取消"
                else
                    log_error "取消 HTTPS 登录失败"
                fi
                ;;
            *)
                log_info "已取消操作"
                ;;
            esac
            break_end
            ;;
        4)
            log_warn "即将取消授权 IP 限制"
            read -r -e -p "$(echo -e "${gl_bai}确认要这样吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
            case "$confirm" in
            [Yy]*)
                log_info "正在取消授权 IP 限制 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                if 1pctl reset ips; then
                    log_ok "授权 IP 限制已取消"
                else
                    log_error "取消授权 IP 限制失败"
                fi
                ;;
            *)
                log_info "已取消操作"
                ;;
            esac
            break_end
            ;;
        5)
            log_warn "即将取消两步验证"
            read -r -e -p "$(echo -e "${gl_bai}确认要这样吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
            case "$confirm" in
            [Yy]*)
                log_info "正在取消两步验证 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                if 1pctl reset mfa; then
                    log_ok "两步验证已取消"
                else
                    log_error "取消两步验证失败"
                fi
                ;;
            *)
                log_info "已取消操作"
                ;;
            esac
            break_end
            ;;
        0) cancel_return; break ;;      # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;; # 感谢使用，再见！
        *) handle_invalid_input ;;      # 无效的输入,请重新输入!
        esac
    done
}

