# --------------------------------------------
# 获取用户信息
# --------------------------------------------
ip_address_1panel() {
    # 强制获取服务器真实内网IP（修复核心）
    local ip
    ip=$(ip route get 8.8.8.8 2>/dev/null | awk '/src/ {print $7}')
    if [[ -z "$ip" ]]; then
        ip=$(hostname -I 2>/dev/null | awk '{print $1}')
    fi
    if [[ -z "$ip" ]]; then
        ip=$(ifconfig 2>/dev/null | grep -E 'inet (192\.168|10\.|172\.)' | grep -v '127.0.0.1' | head -n1 | awk '{print $2}')
    fi
    echo "$ip"
}

user-info_1panel() {
    echo -e ""
    echo -e "${gl_zi}>>> 查看1Panel登录信息${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 获取正确内网IP
    local_ip=$(ip_address_1panel)

    # 获取原始信息
    panel_info=$(1pctl user-info)

    # 替换IP
    if [[ -n "$local_ip" ]]; then
        panel_info=$(echo "$panel_info" | sed "s/\$LOCAL_IP/$local_ip/g")
    else
        panel_info=$(echo "$panel_info" | sed "s/\$LOCAL_IP/127.0.0.1/g")
    fi

    echo "$panel_info"

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# --------------------------------------------
# 恢复服务及数据
# --------------------------------------------
1pctl_restore() {
    clear
    log_warn "即将恢复 1Panel 服务及数据"
    read -r -e -p "$(echo -e "${gl_bai}确认要这样吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    case "$confirm" in
    [Yy]*)
        log_info "正在恢复服务及数据 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if 1pctl restore; then
            log_ok "服务及数据恢复成功"
        else
            log_error "恢复失败"
        fi
        ;;
    *)
        log_info "已取消操作"
        ;;
    esac
    break_end
}

# 安装1Panel
install_1panel() {
    echo -e "${gl_zi}>>> 安装 1Panel${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    log_warn "警告: 这将安装最新版本的 1Panel!"
    read -r -e -p "$(echo -e "${gl_bai}确认要安装吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

    case "$confirm" in
    [yY][eE][sS] | [yY])
        log_info "正在安装 1Panel ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if bash -c "$(curl -sSL https://resource.fit2cloud.com/1panel/package/v2/quick_start.sh)"; then
            log_ok "1Panel 安装完成"
        else
            log_error "安装失败"
        fi
        ;;
    *)
        log_info "已取消安装"
        ;;
    esac

    break_end
}

# 卸载1Panel
uninstall_1panel() {
    echo -e "${gl_zi}>>> 卸载 1Panel${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    log_warn "警告: 这将卸载 1Panel 并删除所有数据!"
    read -r -e -p "$(echo -e "${gl_bai}确认要卸载吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

    case "$confirm" in
    [yY][eE][sS] | [yY])
        if command -v 1pctl &>/dev/null; then
            log_info "正在卸载 1Panel ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            if 1pctl uninstall; then
                log_ok "1Panel 已卸载"
            else
                log_error "卸载失败"
            fi
        else
            log_error "1pctl 命令未找到，无法执行卸载"
        fi
        ;;
    *)
        log_info "已取消卸载"
        ;;
    esac

    break_end
}

# ============================================
# DD备份恢复工具函数
# 功能：提供完整的磁盘/系统备份和恢复功能
# ============================================
dd_backup_restore_tool() {
    # 备份工具版本
    local TOOL_VERSION="3.0"
    local DEFAULT_BACKUP_DIR="/mnt/backup"
    local BACKUP_DIR="$DEFAULT_BACKUP_DIR"
    local HOSTNAME=$(hostname -s 2>/dev/null || echo "unknown")

    # ---------- 初始化备份目录 ----------
    init_backup_dir() {
        if [[ ! -d "$BACKUP_DIR" ]]; then
            log_info "创建备份目录: $BACKUP_DIR"
            mkdir -p "$BACKUP_DIR" 2>/dev/null
            if [[ $? -ne 0 ]]; then
                log_error "无法创建备份目录: $BACKUP_DIR"
                log_warn "使用当前目录: $(pwd)"
                BACKUP_DIR="$(pwd)"
            fi
        fi
    }

    # ---------- 显示备份文件列表 ----------
    show_backup_list() {

        local backup_files=()

        for file in "$BACKUP_DIR"/*.img; do
            if [[ -f "$file" ]] && [[ "$file" != "$BACKUP_DIR"/*.img.gz ]] && [[ "$file" != "$BACKUP_DIR"/*.img.xz ]] && [[ "$file" != "$BACKUP_DIR"/*.img.bz2 ]]; then
                backup_files+=("$file")
            fi
        done

        for file in "$BACKUP_DIR"/*.img.gz; do
            if [[ -f "$file" ]]; then
                backup_files+=("$file")
            fi
        done

        if [[ ${#backup_files[@]} -eq 0 ]]; then
            echo -e "${gl_huang}暂无备份文件${gl_bai}"
            return 1
        fi

        echo -e "${gl_bufan}序号${gl_bai}   ${gl_bufan}备份文件名${gl_bai}                ${gl_bufan}大小${gl_bai}      ${gl_bufan}修改时间${gl_bai}"

        local count=0
        for file in "${backup_files[@]}"; do
            count=$((count + 1))
            local filename=$(basename "$file")
            if [[ -z "$filename" ]] || [[ "$filename" == "*" ]]; then
                count=$((count - 1))
                continue
            fi

            local filesize=$(du -h "$file" 2>/dev/null | cut -f1)
            local filetime=$(stat -c '%y' "$file" 2>/dev/null | cut -d' ' -f1-2)

            if [[ ${#filename} -gt 30 ]]; then
                filename="${filename:0:27}..."
            fi

            printf "${gl_huang}%3d.${gl_bai}  ${gl_lv}%-30s${gl_bai}  ${gl_bufan}%6s${gl_bai}  ${gl_lan}%s${gl_bai}\n" \
                "$count" "$filename" "$filesize" "$filetime"
        done

        echo -e ""
        echo -e "备份目录: ${gl_bufan}$BACKUP_DIR${gl_bai}  备份数量: ${gl_bufan}$count${gl_bai} 个文件"

        return 0
    }

    # ---------- 获取备份文件 ----------
    get_backup_by_index() {
        local index="$1"

        if [[ -z "$index" ]] || [[ "$index" -le 0 ]]; then
            echo ""
            return 1
        fi

        local backup_files=()

        for file in "$BACKUP_DIR"/*.img; do
            if [[ -f "$file" ]] && [[ "$file" != "$BACKUP_DIR"/*.img.gz ]] && [[ "$file" != "$BACKUP_DIR"/*.img.xz ]] && [[ "$file" != "$BACKUP_DIR"/*.img.bz2 ]]; then
                backup_files+=("$file")
            fi
        done

        for file in "$BACKUP_DIR"/*.img.gz; do
            if [[ -f "$file" ]]; then
                backup_files+=("$file")
            fi
        done

        local count=1
        for file in "${backup_files[@]}"; do
            local filename=$(basename "$file")
            if [[ -z "$filename" ]] || [[ "$filename" == "*" ]]; then
                continue
            fi
            if [[ $count -eq $index ]]; then
                echo "$file"
                return 0
            fi
            count=$((count + 1))
        done

        echo ""
        return 1
    }

    # ---------- 清理旧备份 ----------
    clean_old_backups() {
        local days="$1"

        log_info "将删除 ${days} 天前的备份文件:"

        local old_files=()
        while IFS= read -r -d $'\0' file; do
            old_files+=("$file")
        done < <(find "$BACKUP_DIR" -type f \( -name "*.img" -o -name "*.img.gz" \) \
            -mtime +"$days" -print0 2>/dev/null)

        if [[ ${#old_files[@]} -eq 0 ]]; then
            log_info "没有找到 ${days} 天前的备份文件"
            return 0
        fi

        for file in "${old_files[@]}"; do
            local filename=$(basename "$file")
            if [[ -n "$filename" ]] && [[ "$filename" != "*" ]]; then
                echo -e "  ${gl_huang}${filename}${gl_bai}"
            fi
        done

        read -r -e -p "$(echo -e "${gl_bai}确认删除? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
        case "$confirm" in
        [yY] | [yY][eE][sS])
            for file in "${old_files[@]}"; do
                local filename=$(basename "$file")
                if [[ -n "$filename" ]] && [[ "$filename" != "*" ]]; then
                    rm -f "$file" 2>/dev/null
                fi
            done
            log_ok "已清理 $days 天前的备份文件"
            ;;
        *)
            log_info "取消清理"
            ;;
        esac

        return 0
    }

    # ---------- 精确进度条 ----------
    show_precise_progress() {
        local pid=$1
        local total_size=$2
        local source_device="$3"
        local target_file="$4"
        local start_time=$(date +%s)
        local last_size=0
        local last_time=$start_time
        local bar_width=40

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_info "开始备份 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo ""

        tput civis 2>/dev/null || :

        while kill -0 "$pid" 2>/dev/null; do
            local current_size=0

            if [[ -f "$target_file" ]]; then
                current_size=$(stat -c%s "$target_file" 2>/dev/null || echo 0)
            fi

            local current_time=$(date +%s)

            if [[ $current_size -gt 0 ]]; then
                local percent=0
                if [[ $total_size -gt 0 ]]; then
                    percent=$((current_size * 100 / total_size))
                    [[ $percent -gt 100 ]] && percent=100
                fi

                local time_diff=$((current_time - last_time))
                local size_diff=$((current_size - last_size))
                local speed_mb=0
                if [[ $time_diff -gt 0 ]] && [[ $size_diff -gt 0 ]]; then
                    speed_mb=$((size_diff / time_diff / 1024 / 1024))
                fi

                local elapsed=$((current_time - start_time))
                local remaining="--:--"
                if [[ $percent -gt 0 ]] && [[ $percent -lt 100 ]]; then
                    local remaining_sec=$(((elapsed * 100 / percent) - elapsed))
                    if [[ $remaining_sec -gt 0 ]]; then
                        remaining=$(printf "%02d:%02d" $((remaining_sec / 60)) $((remaining_sec % 60)))
                    else
                        remaining="00:00"
                    fi
                fi

                local elapsed_str=$(printf "%02d:%02d" $((elapsed / 60)) $((elapsed % 60)))

                local current_size_hr=""
                local total_size_hr=""

                if command -v numfmt >/dev/null 2>&1; then
                    current_size_hr=$(numfmt --to=iec $current_size 2>/dev/null || echo "$current_size")
                    total_size_hr=$(numfmt --to=iec $total_size 2>/dev/null || echo "$total_size")
                else
                    if [[ $current_size -ge $((1024 * 1024 * 1024)) ]]; then
                        current_size_hr=$(printf "%.1fG" $(echo "scale=2; $current_size/1073741824" | bc 2>/dev/null || echo "0"))
                    elif [[ $current_size -ge $((1024 * 1024)) ]]; then
                        current_size_hr=$(printf "%.1fM" $(echo "scale=2; $current_size/1048576" | bc 2>/dev/null || echo "0"))
                    elif [[ $current_size -ge 1024 ]]; then
                        current_size_hr=$(printf "%.1fK" $(echo "scale=2; $current_size/1024" | bc 2>/dev/null || echo "0"))
                    else
                        current_size_hr="${current_size}B"
                    fi

                    if [[ $total_size -ge $((1024 * 1024 * 1024)) ]]; then
                        total_size_hr=$(printf "%.1fG" $(echo "scale=2; $total_size/1073741824" | bc 2>/dev/null || echo "0"))
                    elif [[ $total_size -ge $((1024 * 1024)) ]]; then
                        total_size_hr=$(printf "%.1fM" $(echo "scale=2; $total_size/1048576" | bc 2>/dev/null || echo "0"))
                    elif [[ $total_size -ge 1024 ]]; then
                        total_size_hr=$(printf "%.1fK" $(echo "scale=2; $total_size/1024" | bc 2>/dev/null || echo "0"))
                    else
                        total_size_hr="${total_size}B"
                    fi
                fi

                local filled=$((percent * bar_width / 100))
                local empty=$((bar_width - filled))

                printf "\r${gl_bai}[${gl_lv}%3d%%${gl_bai}] [" "$percent"
                if [[ $filled -gt 0 ]]; then
                    printf "${gl_bufan}%${filled}s" "" | tr ' ' '█'
                fi
                if [[ $empty -gt 0 ]]; then
                    printf "${gl_hui}%${empty}s" "" | tr ' ' '─'
                fi
                printf "${gl_bai}] "
                printf "${gl_huang}%s/${gl_lv}%s${gl_bai} | " "$current_size_hr" "$total_size_hr"
                printf "${gl_lan}%3d MB/s${gl_bai} | " "$speed_mb"
                printf "⏱️  ${gl_bai}%s/${gl_huang}%s${gl_bai}" "$elapsed_str" "$remaining"

                last_size=$current_size
                last_time=$current_time
            fi
            sleep_fractional 1
        done

        local final_size=0
        if [[ -f "$target_file" ]]; then
            final_size=$(stat -c%s "$target_file" 2>/dev/null || echo 0)
        fi

        local final_size_hr=""
        if command -v numfmt >/dev/null 2>&1; then
            final_size_hr=$(numfmt --to=iec $final_size 2>/dev/null || echo "$final_size")
        else
            if [[ $final_size -ge $((1024 * 1024 * 1024)) ]]; then
                final_size_hr=$(printf "%.1fG" $(echo "scale=2; $final_size/1073741824" | bc 2>/dev/null || echo "0"))
            elif [[ $final_size -ge $((1024 * 1024)) ]]; then
                final_size_hr=$(printf "%.1fM" $(echo "scale=2; $final_size/1048576" | bc 2>/dev/null || echo "0"))
            elif [[ $final_size -ge 1024 ]]; then
                final_size_hr=$(printf "%.1fK" $(echo "scale=2; $final_size/1024" | bc 2>/dev/null || echo "0"))
            else
                final_size_hr="${final_size}B"
            fi
        fi

        local total_time=$(($(date +%s) - start_time))
        local total_time_str=$(printf "%02d:%02d" $((total_time / 60)) $((total_time % 60)))

        printf "\r${gl_bai}[${gl_lv}100%%${gl_bai}] ["
        printf "${gl_bufan}%${bar_width}s" "" | tr ' ' '█'
        printf "${gl_bai}] "
        printf "${gl_huang}%s${gl_bai} | " "$final_size_hr"
        printf "✅ ${gl_lv}完成!${gl_bai} | "
        printf "⏱️  ${gl_bai}%s    " "$total_time_str"

        tput cnorm 2>/dev/null || :
        echo -e "\n${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    }

    # ---------- 获取设备大小 ----------
    get_device_size() {
        local device="$1"
        local size=0

        if [[ -b "$device" ]]; then
            size=$(blockdev --getsize64 "$device" 2>/dev/null || echo 0)
        elif [[ -f "$device" ]]; then
            size=$(stat -c%s "$device" 2>/dev/null || echo 0)
        fi

        echo "$size"
    }

    # ---------- 备份函数 ----------
    backup_with_progress() {
        local source_device="$1"
        local target_file="$2"
        local block_size="$3"
        local compress_type="$4"

        local total_size=$(get_device_size "$source_device")

        if [[ $total_size -eq 0 ]]; then
            log_warn "无法获取设备大小，进度百分比可能不准确"
        else
            log_info "设备总大小: ${gl_huang}$(numfmt --to=iec $total_size 2>/dev/null || echo "$total_size")${gl_bai}"
        fi

        mkdir -p "$(dirname "$target_file")" 2>/dev/null

        case $compress_type in
        "none")
            (dd if="$source_device" bs="$block_size" conv=sync,noerror status=none 2>/dev/null |
                dd of="$target_file" bs="$block_size" conv=sync,noerror status=none) &
            local backup_pid=$!
            ;;
        "gzip")
            (dd if="$source_device" bs="$block_size" conv=sync,noerror status=none 2>/dev/null |
                gzip -c >"$target_file") &
            local backup_pid=$!
            ;;
        "pigz")
            if command -v pigz >/dev/null 2>&1; then
                (dd if="$source_device" bs="$block_size" conv=sync,noerror status=none 2>/dev/null |
                    pigz -c >"$target_file") &
            else
                (dd if="$source_device" bs="$block_size" conv=sync,noerror status=none 2>/dev/null |
                    gzip -c >"$target_file") &
            fi
            local backup_pid=$!
            ;;
        esac

        show_precise_progress $backup_pid $total_size "$source_device" "$target_file"

        wait $backup_pid 2>/dev/null
        local dd_status=$?

        return $dd_status
    }

    # ---------- 恢复函数 ----------
    restore_with_progress() {
        local source_file="$1"
        local target_device="$2"
        local block_size="$3"

        local total_size=$(stat -c%s "$source_file" 2>/dev/null || echo 0)

        if [[ $total_size -eq 0 ]]; then
            log_warn "无法获取源文件大小"
        else
            log_info "备份文件大小: ${gl_huang}$(numfmt --to=iec $total_size 2>/dev/null || echo "$total_size")${gl_bai}"
        fi

        if [[ "$source_file" == *.gz ]] || file "$source_file" 2>/dev/null | grep -q "gzip compressed"; then
            if command -v pigz >/dev/null 2>&1; then
                (pigz -dc "$source_file" 2>/dev/null |
                    dd of="$target_device" bs="$block_size" conv=sync,noerror status=none) &
            else
                (gzip -dc "$source_file" 2>/dev/null |
                    dd of="$target_device" bs="$block_size" conv=sync,noerror status=none) &
            fi
            local restore_pid=$!
        else
            (dd if="$source_file" of="$target_device" bs="$block_size" conv=sync,noerror status=none) &
            local restore_pid=$!
        fi

        show_precise_progress $restore_pid $total_size "$source_file" "$target_device"

        wait $restore_pid 2>/dev/null
        local dd_status=$?

        return $dd_status
    }

    # ---------- 交互式备份 ----------
    interactive_backup() {
        while true; do
            clear
            echo -e "${gl_zi}>>> 备份系统 (${gl_huang}${BACKUP_DIR}${gl_zi})${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            show_backup_list

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}1.  ${gl_bai}备份整个磁盘        ${gl_bufan}2.  ${gl_bai}备份分区"
            echo -e "${gl_bufan}3.  ${gl_bai}更改备份目录        ${gl_bufan}4.  ${gl_bai}查看磁盘列表"
            echo -e "${gl_bufan}5.  ${gl_bai}清理旧备份          ${gl_bufan}6.  ${gl_bai}权限检查"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单      ${gl_hong}00. ${gl_bai}退出脚本"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            read -r -e -p "$(echo -e "${gl_bai}请输入你的选择: ")" mode_choice

            case $mode_choice in
            0) cancel_return "DD备份恢复工具"; break ;;        # 返回到上一级菜单
            00 | 000 | 0000) exit_script ;;                   # 感谢使用，再见！
            3)
                echo ""
                echo -e "${gl_zi}>>> 更改备份目录${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_bai}当前备份目录: ${BACKUP_DIR}${gl_bai}"
                read -r -e -p "$(echo -e "${gl_bai}请输入新备份目录 (${gl_huang}0${gl_bai}取消): ")" new_dir
                [ "$new_dir" = "0" ] && { cancel_return "备份系统"; continue; }   # break 或 continue 或 return ，视上下文而定

                if [[ -n "$new_dir" ]]; then
                    BACKUP_DIR="$new_dir"
                    init_backup_dir
                    log_ok "备份目录已更改为: $BACKUP_DIR"
                fi
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                continue
                ;;
            4)
                echo ""
                echo -e "${gl_zi}>>> 磁盘设备列表:${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                lsblk -o NAME,SIZE,TYPE,MOUNTPOINT,MODEL 2>/dev/null || lsblk
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                continue
                ;;
            5)
                echo ""
                echo -e "${gl_zi}>>> 更改备份目录${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "$(echo -e "${gl_bai}删除几天前的备份? (默认7天) (${gl_huang}0${gl_bai}取消): ")" days
                [[ "$days" == "0" ]] && continue
                days=${days:-7}

                clean_old_backups "$days"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                continue
                ;;
            6)
                echo ""
                echo -e "${gl_zi}>>> 权限检查:${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "当前用户: $(whoami)"
                echo -e "用户ID: $EUID"
                if [[ $EUID -eq 0 ]]; then
                    log_ok "✓ root用户"
                else
                    log_warn "○ 非root用户"
                fi
                echo -e ""
                echo -e "设备访问测试:"
                if [[ -r "/dev/sda" ]]; then
                    log_ok "✓ 可读取 /dev/sda"
                else
                    log_error "✗ 无法读取 /dev/sda"
                fi
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                continue
                ;;
            esac

            # 备份逻辑
            if [[ "$mode_choice" == "1" ]] || [[ "$mode_choice" == "2" ]]; then
                echo -e "${gl_bai}可用磁盘:${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                lsblk -nd -o NAME,SIZE,TYPE 2>/dev/null | head -5
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                read -r -e -p "$(echo -e "${gl_bai}请输入设备名 (例如: sda) (${gl_huang}0${gl_bai}返回): ")" device_input

                [[ "$device_input" == "0" ]] && { cancel_return "备份系统"; continue; }     # break 或 continue 或 return ，视上下文而定

                device_input=$(echo "$device_input" | awk '{print $1}')
                device_path="/dev/$device_input"

                if [[ ! -e "$device_path" ]]; then
                    log_error "设备不存在: $device_path"
                    break_end
                    continue
                fi

                # 备份名称
                local TIMESTAMP=$(date +%Y%m%d_%H%M%S)
                local DEFAULT_BACKUP_NAME="${HOSTNAME}_${TIMESTAMP}"

                echo -e "${gl_bai}备份名称设置:${gl_bai}"
                echo -e "${gl_hui}默认名称: ${DEFAULT_BACKUP_NAME}${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                read -r -e -p "$(echo -e "${gl_bai}请输入备份名称 (留空使用默认) (${gl_huang}0${gl_bai}返回): ")" backup_name
                [[ "$backup_name" == "0" ]] && continue

                if [[ -z "$backup_name" ]]; then
                    backup_name="$DEFAULT_BACKUP_NAME"
                fi

                # 压缩格式
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_bufan}1.  ${gl_bai}无压缩 (.img)"
                echo -e "${gl_bufan}2.  ${gl_bai}gzip压缩 (.img.gz)"
                echo -e "${gl_bufan}3.  ${gl_bai}并行压缩(pigz)"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                read -r -e -p "$(echo -e "${gl_bai}请选择压缩格式 (${gl_huang}0${gl_bai}返回): ")" compress_choice

                [[ "$compress_choice" == "0" ]] && { cancel_return "上一级选单"; continue; }     # break 或 continue 或 return ，视上下文而定

                case $compress_choice in
                1) ext=".img" ;;
                2 | 3) ext=".img.gz" ;;
                *) ext=".img.gz" ;;
                esac

                backup_file="${BACKUP_DIR}/${backup_name}${ext}"

                if [[ -f "$backup_file" ]]; then
                    log_error "备份文件已存在: $backup_file"
                    read -r -e -p "$(echo -e "${gl_bai}是否覆盖? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" overwrite
                    case "$overwrite" in
                    [yY] | [yY][eE][sS])
                        rm -f "$backup_file"
                        ;;
                    *)
                        log_info "备份已取消"
                        break_end
                        continue
                        ;;
                    esac
                fi

                case $compress_choice in
                2) compress_option="gzip" ;;
                3) compress_option="pigz" ;;
                *) compress_option="none" ;;
                esac

                read -r -e -p "$(echo -e "${gl_bai}块大小 [默认:4M] (${gl_huang}0${gl_bai}返回): ")" block_size
                [[ "$inpblock_sizeut" == "0" ]] && { cancel_return "上一级选单"; continue; }
                block_size=${block_size:-4M}

                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                log_info "备份配置:"
                echo -e "  ${gl_bai}源设备:${gl_lan} $device_path${gl_bai}"
                echo -e "  ${gl_bai}文件名:${gl_lan} $(basename "$backup_file")${gl_bai}"
                echo -e "  ${gl_bai}完整路径:${gl_lan} $backup_file${gl_bai}"
                echo -e "  ${gl_bai}压缩格式:${gl_lan} $compress_option${gl_bai}"
                echo -e "  ${gl_bai}块大小:${gl_lan} $block_size${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                read -r -e -p "$(echo -e "${gl_bai}确认开始备份? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
                case "$confirm" in
                [yY] | [yY][eE][sS])
                    log_info "开始备份，请稍候 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    backup_with_progress "$device_path" "$backup_file" "$block_size" "$compress_option"

                    if [[ $? -eq 0 ]]; then
                        log_ok "✅ 备份成功完成!"
                        if [[ -f "$backup_file" ]]; then
                            local final_size=$(du -h "$backup_file" 2>/dev/null | cut -f1 || echo "未知")
                            log_ok "文件: $(basename "$backup_file")"
                            log_ok "大小: $final_size"
                        fi
                    else
                        log_error "❌ 备份失败!"
                    fi
                    ;;
                *)
                    log_info "备份已取消"
                    ;;
                esac

                break_end
            else
                handle_invalid_input
            fi
        done
    }

    # ---------- 交互式恢复 ----------
    interactive_restore() {
        while true; do
            clear
            echo -e "${gl_zi}>>> 恢复系统${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            show_backup_list

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}1.  ${gl_bai}按序号恢复          ${gl_bufan}2.  ${gl_bai}手动输入路径"
            echo -e "${gl_bufan}3.  ${gl_bai}查看磁盘列表        ${gl_bufan}4.  ${gl_bai}测试恢复模式"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单      ${gl_hong}00. ${gl_bai}退出脚本"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            read -r -e -p "$(echo -e "${gl_bai}请输入你的选择: ")" mode_choice

            case $mode_choice in
            1)
                echo ""
                echo -e "${gl_zi}>>> 按序号恢复${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "$(echo -e "${gl_bai}请输入备份序号 (${gl_huang}0${gl_bai}返回): ")" file_index
                [[ "$file_index" == "0" ]] && { cancel_return "上一级选单"; continue; }      # break 或 continue 或 return ，视上下文而定

                local backup_file=$(get_backup_by_index "$file_index")
                if [[ -z "$backup_file" ]] || [[ ! -f "$backup_file" ]]; then
                    log_error "无效的备份序号: $file_index"
                    sleep_fractional 1
                    continue
                fi
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;
            2)
                echo ""
                echo -e "${gl_zi}>>> 手动输入路径${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "$(echo -e "${gl_bai}请输入备份文件完整路径 (${gl_huang}0${gl_bai}返回): ")" backup_file
                [[ "$backup_file" == "0" ]] && continue

                if [[ ! -f "$backup_file" ]]; then
                    log_error "文件不存在: $backup_file"
                    sleep_fractional 1
                    continue
                fi
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;
            3)
                echo ""
                echo -e "${gl_zi}>>> 磁盘设备列表${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                lsblk -o NAME,SIZE,TYPE,MOUNTPOINT 2>/dev/null || lsblk
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                continue
                ;;
            4)
                echo ""
                echo -e "${gl_zi}>>> 测试恢复模式${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                log_info "测试恢复模式: 恢复到临时文件"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "$(echo -e "${gl_bai}请输入备份序号 (${gl_huang}0${gl_bai}返回): ")" file_index
                [[ "$file_index" == "0" ]] && { cancel_return "上一级选单"; continue; }      # break 或 continue 或 return ，视上下文而定

                local backup_file=$(get_backup_by_index "$file_index")
                if [[ -z "$backup_file" ]] || [[ ! -f "$backup_file" ]]; then
                    log_error "无效的备份序号: $file_index"
                    sleep_fractional 1
                    continue
                fi

                log_info "选择的备份: $(basename "$backup_file")"

                local target_disk="/tmp/restore_test_$(date +%Y%m%d_%H%M%S).img"
                log_info "测试目标: $target_disk"

                read -r -e -p "$(echo -e "${gl_bai}块大小 [默认:4M] (${gl_huang}0${gl_bai}返回): ")" block_size
                [[ "$block_size" == "0" ]] && { cancel_return "上一级选单"; continue; }      # break 或 continue 或 return ，视上下文而定
                block_size=${block_size:-4M}

                log_info "开始测试恢复 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                restore_with_progress "$backup_file" "$target_disk" "$block_size"

                if [[ $? -eq 0 && -f "$target_disk" ]]; then
                    local final_size=$(du -h "$target_disk" 2>/dev/null | cut -f1 || echo "未知")
                    log_ok "测试恢复成功! 临时文件: $target_disk"
                    log_ok "大小: $final_size"
                    rm -f "$target_disk" 2>/dev/null
                    log_ok "临时文件已清理"
                else
                    log_error "测试恢复失败"
                fi
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                continue
                ;;
            0) cancel_return "上一级选单"; return 0 ;;       # 返回到上一级菜单
            00 | 000 | 0000) exit_script ;;                 # 感谢使用，再见！
            *) handle_invalid_input; continue;;             # 无效的输入,请重新输入!
            esac

            if [[ -z "$backup_file" ]] || [[ ! -f "$backup_file" ]]; then
                break_end
                continue
            fi

            log_ok "选择的备份文件:"
            echo -e "  ${gl_bai}文件名:${gl_lan} $(basename "$backup_file")${gl_bai}"
            echo -e "  ${gl_bai}路径:${gl_lan} $backup_file${gl_bai}"
            echo -e "  ${gl_bai}大小:${gl_lan} $(du -h "$backup_file" 2>/dev/null | cut -f1 || echo "未知")${gl_bai}"

            echo -e "\n${gl_bai}可用目标磁盘:${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            lsblk -nd -o NAME,SIZE,TYPE 2>/dev/null | head -5
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            read -r -e -p "$(echo -e "${gl_bai}请输入目标设备名 (例如: sda) (${gl_huang}0${gl_bai}返回): ")" target_input
            [[ "$target_input" == "0" ]] && continue

            target_input=$(echo "$target_input" | awk '{print $1}')
            local target_disk="/dev/$target_input"

            if [[ ! -e "$target_disk" ]]; then
                log_error "设备不存在: $target_disk"
                break_end
                continue
            fi

            read -r -e -p "$(echo -e "${gl_bai}块大小 [默认:4M] (${gl_huang}0${gl_bai}返回): ")" block_size
            [[ "$block_size" == "0" ]] && continue
            block_size=${block_size:-4M}

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_warn "⚠️  即将执行系统恢复操作"
            echo -e "${gl_hong}警告: 这将完全覆盖目标设备 ${target_disk} 上的所有数据!${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_info "恢复配置:"
            echo -e "  ${gl_bai}备份文件:${gl_lan} $(basename "$backup_file")${gl_bai}"
            echo -e "  ${gl_bai}目标设备:${gl_lan} $target_disk${gl_bai}"
            echo -e "  ${gl_bai}块大小:${gl_lan} $block_size${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            read -r -e -p "$(echo -e "${gl_bai}确认执行恢复? (${gl_hong}输入YES${gl_bai}确认): ")" confirm
            if [[ "$confirm" != "YES" ]]; then
                log_info "恢复已取消"
                break_end
                continue
            fi

            log_info "开始恢复系统到 $target_disk ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            restore_with_progress "$backup_file" "$target_disk" "$block_size"

            if [[ $? -eq 0 ]]; then
                log_ok "✅ 系统恢复成功!"
                log_warn "建议执行以下命令:"
                echo -e "  ${gl_huang}sync${gl_bai}"
                echo -e "  ${gl_huang}partprobe $target_disk${gl_bai}"
            else
                log_error "❌ 系统恢复失败!"
            fi

            break_end
        done
    }

    # ---------- 备份文件管理 ----------
    backup_management() {
        while true; do
            clear
            echo -e "${gl_zi}>>> 备份文件管理${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            show_backup_list
            echo ""
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}1.  ${gl_bai}删除指定备份        ${gl_bufan}2.  ${gl_bai}更改备份目录"
            echo -e "${gl_bufan}3.  ${gl_bai}清理旧备份          ${gl_bufan}4.  ${gl_bai}查看备份信息"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单      ${gl_hong}00. ${gl_bai}退出脚本"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            read -r -e -p "$(echo -e "${gl_bai}请选择: ")" manage_choice
            case $manage_choice in
            0) cancel_return; return 0 ;;      # 返回到上一级菜单
            00 | 000 | 0000) exit_script ;; # 感谢使用，再见！
            *) handle_invalid_input ;;      # 无效的输入,请重新输入!
            1)
                read -r -e -p "$(echo -e "${gl_bai}输入要删除的备份序号 (${gl_huang}0${gl_bai}取消): ")" del_index
                if [[ "$del_index" != "0" ]]; then
                    local del_file=$(get_backup_by_index "$del_index")
                    if [[ -n "$del_file" ]]; then
                        read -r -e -p "$(echo -e "${gl_bai}确认删除 ${gl_huang}$(basename "$del_file")${gl_bai}? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
                        case "$confirm" in
                        [yY] | [yY][eE][sS])
                            rm -f "$del_file"
                            log_ok "已删除备份文件"
                            ;;
                        esac
                    fi
                fi
                break_end
                ;;
            2)
                echo -e "${gl_bai}当前备份目录: ${BACKUP_DIR}${gl_bai}"
                read -r -e -p "$(echo -e "${gl_bai}请输入新备份目录: ")" new_dir
                if [[ -n "$new_dir" ]]; then
                    BACKUP_DIR="$new_dir"
                    init_backup_dir
                    log_ok "备份目录已更改为: $BACKUP_DIR"
                fi
                break_end
                ;;
            3)
                read -r -e -p "$(echo -e "${gl_bai}删除几天前的备份? (默认7天): ")" days
                days=${days:-7}
                if [[ "$days" -gt 0 ]]; then
                    clean_old_backups "$days"
                fi
                break_end
                ;;
            4)
                echo -e "${gl_bai}备份目录信息:${gl_bai}"
                du -sh "$BACKUP_DIR" 2>/dev/null || echo "未知"
                echo -e ""
                echo -e "${gl_bai}磁盘空间:${gl_bai}"
                df -h "$BACKUP_DIR" 2>/dev/null || echo "无法获取磁盘信息"
                break_end
                ;;
            esac
        done
    }

    # ---------- 系统检查 ----------
    system_check() {
        clear
        echo -e "${gl_zi}>>> 系统检查${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}系统信息:${gl_bai}"
        echo -e "  主机名: ${gl_lv}$(hostname)${gl_bai}"
        echo -e "  系统: ${gl_lv}$(uname -o) $(uname -m)${gl_bai}"
        echo -e "  内核: ${gl_lv}$(uname -r)${gl_bai}"
        echo -e "  当前用户: ${gl_lv}$(whoami)${gl_bai}"
        echo -e "  用户ID: ${gl_lv}$EUID${gl_bai}"
        echo -e ""
        echo -e "${gl_bai}工具检查:${gl_bai}"
        for cmd in dd lsblk gzip file numfmt bc pigz; do
            if command -v $cmd >/dev/null 2>&1; then
                echo -e "  ${gl_lv}✓${gl_bai} $cmd"
            else
                echo -e "  ${gl_hong}✗${gl_bai} $cmd (建议安装)"
            fi
        done
        echo -e ""
        echo -e "${gl_bai}设备访问测试:${gl_bai}"
        if [[ -r "/dev/sda" ]]; then
            echo -e "  ${gl_lv}✓${gl_bai} 可读取 /dev/sda"
        else
            echo -e "  ${gl_hong}✗${gl_bai} 无法读取 /dev/sda (需要root)"
        fi
        echo -e ""
        echo -e "${gl_bai}备份目录:${gl_bai}"
        echo -e "  ${gl_lv}${BACKUP_DIR}${gl_bai}"
        if [[ -d "$BACKUP_DIR" ]]; then
            local free_space=$(df -h "$BACKUP_DIR" 2>/dev/null | tail -1 | awk '{print $4}' || echo "未知")
            echo -e "  ${gl_lv}可用空间: $free_space${gl_bai}"
        fi
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # ---------- 主菜单 ----------
    main_menu() {
        while true; do
            clear
            echo -e "${gl_zi}>>> DD备份恢复工具${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            show_backup_list
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}1.  ${gl_bai}进入备份功能        ${gl_bufan}2.  ${gl_bai}进入恢复功能"
            echo -e "${gl_bufan}3.  ${gl_bai}备份文件管理        ${gl_bufan}4.  ${gl_bai}系统检查"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单      ${gl_hong}00. ${gl_bai}退出脚本"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            read -r -e -p "$(echo -e "${gl_bai}请输入你的选择: ")" choice

            case $choice in
            1)
                interactive_backup
                if [[ $? -eq 1 ]]; then
                    return
                fi
                ;;
            2)
                interactive_restore
                if [[ $? -eq 1 ]]; then
                    return
                fi
                ;;
            3)
                backup_management
                if [[ $? -eq 1 ]]; then
                    return
                fi
                ;;
            4)
                system_check
                ;;
            0 | 00)
                return
                ;;
            *)
                handle_invalid_input
                ;;
            esac
        done
    }

    # ---------- 启动函数 ----------
    clear
    echo -e "${gl_zi}>>> DD备份恢复工具${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 初始化备份目录
    init_backup_dir

    # 权限提示
    if [[ $EUID -ne 0 ]]; then
        log_warn "当前不是root用户，备份真实设备需要root权限"
        log_info "建议使用: ${gl_huang}sudo${gl_bai} 执行脚本"
        echo ""
    fi

    # 显示备份目录信息
    echo -e "${gl_bai}备份目录: ${gl_lv}${BACKUP_DIR}${gl_bai}"
    if [[ -d "$BACKUP_DIR" ]]; then
        local backup_count=$(ls "$BACKUP_DIR"/*.img "$BACKUP_DIR"/*.img.gz 2>/dev/null | wc -l 2>/dev/null || echo 0)
        local dir_size=$(du -sh "$BACKUP_DIR" 2>/dev/null | cut -f1 || echo "未知")
        echo -e "${gl_bai}已有备份: ${gl_lv}${backup_count}${gl_bai} 个文件 (${dir_size})"
    fi
    echo ""

    # 启动主菜单
    main_menu
}

# ---------- 图片转换函数 ----------
image_converter_main() {
    local menu_name="${1:-上一级选单}"
    while true; do
        install ffmpeg

        # 检查当前目录是否为空，如果为空则显示提示并返回错误
        check_directory_empty "." "图片格式转换工具" "true" || return

        clear
        echo -e "${gl_zi}>>> 图片格式转换工具${gl_bai}(${gl_lv}$(pwd)${gl_bai})"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 获取当前目录图片
        local image_files=()
        local image_sizes=()
        image_converter_find_images image_files image_sizes

        if [[ ${#image_files[@]} -eq 0 ]]; then
            echo -e "${gl_huang}当前目录没有找到图片文件${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -ne "${gl_lv}即将退出 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
            sleep_fractional 0.5
            echo -ne " ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}\c"
            sleep_fractional 0.5
            return
        else
            image_converter_show_list image_files image_sizes
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}指定转${gl_bufan}JPG${gl_bai}格式       ${gl_bufan}2.  ${gl_bai}全部转${gl_bufan}JPG${gl_bai}格式"
        echo -e "${gl_bufan}3.  ${gl_bai}指定转${gl_bufan}PNG${gl_bai}格式       ${gl_bufan}4.  ${gl_bai}全部转${gl_bufan}PNG${gl_bai}格式"
        echo -e "${gl_bufan}5.  ${gl_bai}指定转${gl_bufan}WEBP${gl_bai}格式      ${gl_bufan}6.  ${gl_bai}全部转${gl_bufan}WEBP${gl_bai}格式"
        echo -e "${gl_bufan}7.  ${gl_bai}指定转${gl_bufan}BMP${gl_bai}格式       ${gl_bufan}8.  ${gl_bai}全部转${gl_bufan}BMP${gl_bai}格式"
        echo -e "${gl_bufan}9.  ${gl_bai}指定转${gl_bufan}JPEG${gl_bai}格式      ${gl_bufan}10. ${gl_bai}全部转${gl_bufan}JPEG${gl_bai}格式"
        echo -e "${gl_bufan}11. ${gl_bai}指定转${gl_bufan}GIF${gl_bai}格式       ${gl_bufan}12. ${gl_bai}全部转${gl_bufan}GIF${gl_bai}格式"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}13. ${gl_bai}质量压缩图片        ${gl_bufan}14. ${gl_bai}批量调整尺寸${gl_bai}"
        echo -e "${gl_bufan}15. ${gl_bai}批量重命名          ${gl_bufan}16. ${gl_bai}批量删除图片${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单      ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "$(echo -e "${gl_bai}请输入你的选择: ")" choice

        case $choice in
        1)  image_converter_convert_selected "jpg" image_files ;;   # 指定转JPG格式
        2)  image_converter_batch_all "jpg" image_files ;;          # 全部转JPG格式
        3)  image_converter_convert_selected "png" image_files ;;   # 指定转PNG格式
        4)  image_converter_batch_all "png" image_files ;;          # 全部转PNG格式
        5)  image_converter_convert_selected "webp" image_files ;;  # 指定转WEBP格式
        6)  image_converter_batch_all "webp" image_files ;;         # 全部转WEBP格式
        7)  image_converter_convert_selected "bmp" image_files ;;   # 指定转BMP格式
        8)  image_converter_batch_all "bmp" image_files ;;          # 全部转BMP格式
        9)  image_converter_convert_selected "jpeg" image_files ;;  # 指定转JPEG格式
        10) image_converter_batch_all "jpeg" image_files ;;         # 全部转JPEG格式
        11) image_converter_convert_selected "gif" image_files ;;   # 指定转GIF格式
        12) image_converter_batch_all "gif" image_files ;;          # 全部转GIF格式
        13) image_converter_compress_quality image_files ;;         # 质量压缩图片
        14) image_converter_resize_batch image_files ;;             # 批量调整尺寸
        15) image_converter_batch_rename image_files ;;             # 批量重命名
        16) image_converter_batch_delete image_files ;;             # 批量删除图片
        0) cancel_return "$menu_name"; break ;;                     # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;                             # 感谢使用，再见！
        *) handle_invalid_input ;;                                  # 无效的输入,请重新输入!
        esac
    done
}

# ---------- 辅助函数 ----------

# 查找当前目录的图片
image_converter_find_images() {
    local -n files_ref=$1
    local -n sizes_ref=$2

    files_ref=()
    sizes_ref=()

    # 支持的扩展名
    local exts=("jpg" "jpeg" "png" "bmp" "gif" "tiff" "tif" "webp" "heic" "JPG" "JPEG" "PNG" "BMP" "GIF" "TIFF" "TIF" "WEBP" "HEIC")

    # 查找文件
    for ext in "${exts[@]}"; do
        for file in *."$ext"; do
            if [[ -f "$file" ]] && [[ "$file" != *\* ]]; then
                files_ref+=("$file")
            fi
        done
    done

    # 按文件名排序
    if [[ ${#files_ref[@]} -gt 0 ]]; then
        IFS=$'\n' files_ref=($(printf '%s\n' "${files_ref[@]}" | sort))
        unset IFS
    fi

    # 获取文件大小
    for file in "${files_ref[@]}"; do
        if [[ -f "$file" ]]; then
            local size=$(stat -c%s "$file" 2>/dev/null || stat -f%z "$file" 2>/dev/null || echo "0")
            if [[ $size -ge 1048576 ]]; then
                local size_display=$(echo "scale=1; $size/1048576" | bc 2>/dev/null || echo "0")M
            elif [[ $size -ge 1024 ]]; then
                local size_display=$(echo "scale=1; $size/1024" | bc 2>/dev/null || echo "0")K
            else
                local size_display="${size}B"
            fi
        else
            local size_display="未知"
        fi
        sizes_ref+=("$size_display")
    done
}

# 显示图片列表
image_converter_show_list() {
    local -n files_ref=$1
    local -n sizes_ref=$2

    for i in "${!files_ref[@]}"; do
        local file="${files_ref[i]}"
        local resolution="未知"

        # 获取图片分辨率
        if command -v identify &>/dev/null; then
            # 使用ImageMagick的identify命令
            resolution=$(identify -format "%wx%h" "$file" 2>/dev/null || echo "未知")
        elif command -v ffprobe &>/dev/null; then
            # 使用ffprobe获取分辨率
            resolution=$(ffprobe -v error -select_streams v:0 -show_entries stream=width,height -of csv=p=0 "$file" 2>/dev/null | tr ',' 'x' || echo "未知")
        elif [[ "$file" =~ \.(jpg|jpeg|png|gif|bmp|tiff|tif|webp)$ ]]; then
            # 使用file命令尝试获取
            resolution=$(file "$file" 2>/dev/null | grep -oE "[0-9]+ x [0-9]+" | head -1 | tr ' ' 'x' || echo "未知")
        fi

        # 如果获取失败，显示未知
        if [[ "$resolution" == "" ]] || [[ "$resolution" == "x" ]]; then
            resolution="未知"
        fi

        printf "${gl_huang}%3d${gl_bai}.  ${gl_lv}%-25s${gl_bai}  ${gl_zi}%12s${gl_bai}  ${gl_lan}%8s${gl_bai}\n" \
            $((i + 1)) "${files_ref[i]}" "$resolution" "${sizes_ref[i]}"
    done
}

# 转换单张图片
image_converter_convert_single() {
    local file="$1"
    local format="$2"

    if [[ ! -f "$file" ]]; then
        log_error "文件不存在: $file"
        return 1
    fi

    # 获取文件名
    local filename=$(basename "$file")
    local name="${filename%.*}"

    # 生成新文件名
    local new_name="${name}.${format}"
    local count=1
    while [[ -f "$new_name" ]]; do
        new_name="${name}_${count}.${format}"
        count=$((count + 1))
    done

    log_info "开始转换: ${filename} → ${new_name}"

    # 使用ffmpeg转换
    if ffmpeg -i "$file" "$new_name" 2>/dev/null; then
        local input_size=$(du -h "$file" 2>/dev/null | cut -f1)
        local output_size=$(du -h "$new_name" 2>/dev/null | cut -f1)
        log_ok "转换成功"
        log_info "原文件: ${filename} (${input_size:-未知})"
        log_info "新文件: ${new_name} (${output_size:-未知})"
        return 0
    else
        log_error "转换失败: ${filename}"
        return 1
    fi
}

# 批量转换全部图片
image_converter_batch_all() {
    local format="$1"
    local -n files_ref=$2

    if [[ ${#files_ref[@]} -eq 0 ]]; then
        log_error "没有图片可转换"
        return
    fi

    echo ""
    log_info "开始批量转换全部图片为 ${format} 格式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo ""

    local success=0
    local total=${#files_ref[@]}

    for i in "${!files_ref[@]}"; do
        local file="${files_ref[i]}"
        local progress=$(((i + 1) * 100 / total))

        printf "\r${gl_bai}处理中: [${gl_lv}%3d%%${gl_bai}] ${gl_huang}%d/${total}${gl_bai} - ${gl_lan}%s${gl_bai}" \
            "$progress" "$((i + 1))" "$file"

        if image_converter_convert_single "$file" "$format" >/dev/null 2>&1; then
            success=$((success + 1))
        fi
    done

    echo -e "\n\n${gl_bufan}————————————————————————${gl_bai}"
    log_ok "批量转换完成"
    log_info "成功: ${gl_lv}${success}${gl_bai} 个文件"
    if [[ $((total - success)) -gt 0 ]]; then
        log_warn "失败: ${gl_huang}$((total - success))${gl_bai} 个文件"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    break_end
}

# 转换指定图片
image_converter_convert_selected() {
    local format="$1"
    local -n files_ref=$2

    if [[ ${#files_ref[@]} -eq 0 ]]; then
        log_error "没有图片可选"
        return
    fi

    echo ""
    echo -e "${gl_bai}请选择要转换的图片序号${gl_bai}"
    echo -e "${gl_huang}支持: 单个序号, 多个用空格分隔, 范围用'-'连接${gl_bai}"
    echo -e "${gl_huang}示例: 1 3 5 或 2-5 或 1,3,7${gl_bai}"
    echo ""

    read -r -e -p "$(echo -e "${gl_bai}请输入你的选择 (${gl_huang}0${gl_bai}返回): ")" selection

    [[ -z "$selection" ]] && { cancel_empty "上一级选单"; return 1; }       # break 或 continue 或 return ，视上下文而定
    [[ "$selection" == "0" ]] && { cancel_return "上一级选单"; return; }    # break 或 continue 或 return ，视上下文而定

    # 处理输入
    local selected_files=()

    # 处理逗号分隔
    selection=$(echo "$selection" | tr ',' ' ')

    # 处理数字范围
    if [[ "$selection" =~ ^[0-9]+-[0-9]+$ ]]; then
        local start=${selection%-*}
        local end=${selection#*-}
        for ((i = start; i <= end; i++)); do
            if [[ $i -ge 1 ]] && [[ $i -le ${#files_ref[@]} ]]; then
                selected_files+=("${files_ref[$((i - 1))]}")
            fi
        done
    else
        # 处理空格分隔的数字
        for num in $selection; do
            if [[ $num =~ ^[0-9]+$ ]]; then
                if [[ $num -ge 1 ]] && [[ $num -le ${#files_ref[@]} ]]; then
                    selected_files+=("${files_ref[$((num - 1))]}")
                else
                    log_warn "序号 ${num} 无效"
                fi
            fi
        done
    fi

    if [[ ${#selected_files[@]} -eq 0 ]]; then
        log_error "没有选择有效的图片"
        return
    fi

    echo ""
    echo -e "${gl_bai}选择的图片:${gl_bai}"
    for file in "${selected_files[@]}"; do
        echo -e "  ${gl_lv}✓${gl_bai} $file"
    done
    echo ""

    read -r -e -p "$(echo -e "${gl_bai}确认转换这 ${#selected_files[@]} 个文件为 ${format} 格式? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    if [[ ! "$confirm" =~ ^[Yy]$ ]]; then
        log_info "操作取消"
        return
    fi

    echo ""
    log_info "开始转换 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo ""

    local success=0
    local total=${#selected_files[@]}

    for i in "${!selected_files[@]}"; do
        local file="${selected_files[i]}"
        echo -e "${gl_huang}[$((i + 1))/$total]${gl_bai} 处理: $file"

        if image_converter_convert_single "$file" "$format"; then
            success=$((success + 1))
        fi
        echo ""
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_ok "转换完成"
    log_info "成功: ${gl_lv}${success}${gl_bai} 个文件"
    if [[ $((total - success)) -gt 0 ]]; then
        log_warn "失败: ${gl_huang}$((total - success))${gl_bai} 个文件"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    break_end
}

# 质量压缩图片
image_converter_compress_quality() {
    local -n files_ref=$1

    if [[ ${#files_ref[@]} -eq 0 ]]; then
        log_error "没有图片可压缩"
        return
    fi

    echo ""
    echo -e "${gl_bai}请选择要压缩的图片序号${gl_bai}"
    echo -e "${gl_huang}支持: 单个序号, 多个用空格分隔, 范围用'-'连接${gl_bai}"
    echo -e "${gl_huang}示例: 1 3 5 或 2-5 或 1,3,7${gl_bai}"
    echo ""

    read -r -e -p "$(echo -e "${gl_bai}请输入你的选择 (${gl_huang}0${gl_bai}返回): ")" selection

    [[ -z "$selection" ]] && { cancel_empty "上一级选单"; return 1; }
    [[ "$selection" == "0" ]] && { cancel_return "上一级选单"; return 1; }

    # 处理输入
    local selected_files=()
    selection=$(echo "$selection" | tr ',' ' ')

    if [[ "$selection" =~ ^[0-9]+-[0-9]+$ ]]; then
        local start=${selection%-*}
        local end=${selection#*-}
        for ((i = start; i <= end; i++)); do
            if [[ $i -ge 1 ]] && [[ $i -le ${#files_ref[@]} ]]; then
                selected_files+=("${files_ref[$((i - 1))]}")
            fi
        done
    else
        for num in $selection; do
            if [[ $num =~ ^[0-9]+$ ]]; then
                if [[ $num -ge 1 ]] && [[ $num -le ${#files_ref[@]} ]]; then
                    selected_files+=("${files_ref[$((num - 1))]}")
                else
                    log_warn "序号 ${num} 无效"
                fi
            fi
        done
    fi

    if [[ ${#selected_files[@]} -eq 0 ]]; then
        log_error "没有选择有效的图片"
        return
    fi

    echo ""
    echo -e "${gl_bai}输入质量参数 (1-100, 默认85)${gl_bai}"
    echo -e "${gl_huang}数值越高质量越好, 文件越大${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请输入质量 (${gl_huang}1-100${gl_bai}): ")" quality
    quality=${quality:-85}

    if ! [[ "$quality" =~ ^[0-9]+$ ]] || [ "$quality" -lt 1 ] || [ "$quality" -gt 100 ]; then
        log_error "质量参数无效, 使用默认值85"
        quality=85
    fi

    echo ""
    echo -e "${gl_bai}选择的图片:${gl_bai}"
    for file in "${selected_files[@]}"; do
        echo -e "  ${gl_lv}✓${gl_bai} $file"
    done
    echo ""

    read -r -e -p "$(echo -e "${gl_bai}确认压缩这 ${#selected_files[@]} 个文件? 质量: ${quality} (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    if [[ ! "$confirm" =~ ^[Yy]$ ]]; then
        log_info "操作取消"
        return
    fi

    local success=0
    local total=${#selected_files[@]}

    for i in "${!selected_files[@]}"; do
        local file="${selected_files[i]}"
        local filename=$(basename "$file")
        local extension="${filename##*.}"
        local name="${filename%.*}"
        local new_name="${name}_compressed.${extension}"
        local count=1

        while [[ -f "$new_name" ]]; do
            new_name="${name}_compressed_${count}.${extension}"
            count=$((count + 1))
        done

        echo -e "${gl_huang}[$((i + 1))/$total]${gl_bai} 压缩: $file"

        if ffmpeg -i "$file" -q:v "$quality" "$new_name" 2>/dev/null; then
            log_ok "压缩成功: $new_name"
            success=$((success + 1))
        else
            log_error "压缩失败: $file"
        fi
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_ok "压缩完成"
    log_info "成功: ${gl_lv}${success}${gl_bai} 个文件"
    if [[ $((total - success)) -gt 0 ]]; then
        log_warn "失败: ${gl_huang}$((total - success))${gl_bai} 个文件"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    break_end
}

# 批量调整图片尺寸
image_converter_resize_batch() {
    local -n files_ref=$1

    if [[ ${#files_ref[@]} -eq 0 ]]; then
        log_error "没有图片可调整"
        return
    fi

    echo ""
    echo -e "${gl_bai}请选择调整模式${gl_bai}"
    echo -e "${gl_bufan}1.  ${gl_bai}按宽度等比缩放"
    echo -e "${gl_bufan}2.  ${gl_bai}按高度等比缩放"
    echo -e "${gl_bufan}3.  ${gl_bai}按百分比缩放"
    echo -e "${gl_bufan}4.  ${gl_bai}指定宽度和高度"
    echo ""

    read -r -e -p "$(echo -e "${gl_bai}请输入模式 (${gl_huang}1-4${gl_bai}): ")" mode

    case $mode in
    1)
        read -r -e -p "$(echo -e "${gl_bai}请输入目标宽度: ")" width
        if ! [[ "$width" =~ ^[0-9]+$ ]]; then
            log_error "无效的宽度"
            return
        fi
        resize_cmd="-vf scale=${width}:-1"
        ;;
    2)
        read -r -e -p "$(echo -e "${gl_bai}请输入目标高度: ")" height
        if ! [[ "$height" =~ ^[0-9]+$ ]]; then
            log_error "无效的高度"
            return
        fi
        resize_cmd="-vf scale=-1:${height}"
        ;;
    3)
        read -r -e -p "$(echo -e "${gl_bai}请输入缩放百分比 (如50表示50%): ")" percent
        if ! [[ "$percent" =~ ^[0-9]+$ ]]; then
            log_error "无效的百分比"
            return
        fi
        local scale_percent=$(echo "scale=2; $percent/100" | bc)
        resize_cmd="-vf scale=iw*${scale_percent}:ih*${scale_percent}"
        ;;
    4)
        read -r -e -p "$(echo -e "${gl_bai}请输入目标宽度: ")" width
        read -r -e -p "$(echo -e "${gl_bai}请输入目标高度: ")" height
        if ! [[ "$width" =~ ^[0-9]+$ ]] || ! [[ "$height" =~ ^[0-9]+$ ]]; then
            log_error "无效的尺寸"
            return
        fi
        resize_cmd="-vf scale=${width}:${height}"
        ;;
    *)
        log_error "无效的模式"
        return
        ;;
    esac

    echo ""
    echo -e "${gl_bai}请选择要调整的图片${gl_bai}"
    echo -e "${gl_bai}输入 ${gl_lv}all${gl_bai} 批量处理所有图片"
    echo -e "${gl_bai}或输入序号 (用空格分隔, 如 1 3 5)${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请输入你的选择 (${gl_huang}0${gl_bai}返回): ")" selection

    [[ -z "$selection" ]] && { cancel_empty "上一级选单"; return 1; }        # break 或 continue 或 return ，视上下文而定
    [[ "$selection" == "0" ]] && { cancel_return "上一级选单"; return; }     # break 或 continue 或 return ，视上下文而定

    local selected_files=()

    if [[ "$selection" == "all" ]]; then
        selected_files=("${files_ref[@]}")
    else
        selection=$(echo "$selection" | tr ',' ' ')

        if [[ "$selection" =~ ^[0-9]+-[0-9]+$ ]]; then
            local start=${selection%-*}
            local end=${selection#*-}
            for ((i = start; i <= end; i++)); do
                if [[ $i -ge 1 ]] && [[ $i -le ${#files_ref[@]} ]]; then
                    selected_files+=("${files_ref[$((i - 1))]}")
                fi
            done
        else
            for num in $selection; do
                if [[ $num =~ ^[0-9]+$ ]]; then
                    if [[ $num -ge 1 ]] && [[ $num -le ${#files_ref[@]} ]]; then
                        selected_files+=("${files_ref[$((num - 1))]}")
                    else
                        log_warn "序号 ${num} 无效"
                    fi
                fi
            done
        fi
    fi

    if [[ ${#selected_files[@]} -eq 0 ]]; then
        log_error "没有选择有效的图片"
        return
    fi

    echo ""
    echo -e "${gl_bai}选择的图片:${gl_bai}"
    for file in "${selected_files[@]}"; do
        echo -e "  ${gl_lv}✓${gl_bai} $file"
    done
    echo ""

    read -r -e -p "$(echo -e "${gl_bai}确认调整这 ${#selected_files[@]} 个文件的尺寸? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    if [[ ! "$confirm" =~ ^[Yy]$ ]]; then
        log_info "操作取消"
        return
    fi

    local success=0
    local total=${#selected_files[@]}

    for i in "${!selected_files[@]}"; do
        local file="${selected_files[i]}"
        local filename=$(basename "$file")
        local extension="${filename##*.}"
        local name="${filename%.*}"
        local new_name="${name}_resized.${extension}"
        local count=1

        while [[ -f "$new_name" ]]; do
            new_name="${name}_resized_${count}.${extension}"
            count=$((count + 1))
        done

        echo -e "${gl_huang}[$((i + 1))/$total]${gl_bai} 调整: $file"

        if ffmpeg -i "$file" $resize_cmd "$new_name" 2>/dev/null; then
            log_ok "调整成功: $new_name"
            success=$((success + 1))
        else
            log_error "调整失败: $file"
        fi
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_ok "尺寸调整完成"
    log_info "成功: ${gl_lv}${success}${gl_bai} 个文件"
    if [[ $((total - success)) -gt 0 ]]; then
        log_warn "失败: ${gl_huang}$((total - success))${gl_bai} 个文件"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    break_end
}

# 批量重命名图片
image_converter_batch_rename() {
    local -n files_ref=$1

    if [[ ${#files_ref[@]} -eq 0 ]]; then
        log_error "没有图片可重命名"
        return
    fi

    echo ""
    echo -e "${gl_bai}批量重命名图片${gl_bai}"
    echo -e "${gl_huang}请输入新的文件名前缀${gl_bai}"
    echo -e "${gl_huang}示例: 输入 ${gl_bai}photo${gl_huang}, 会生成 ${gl_bai}photo_001.jpg, photo_002.png${gl_huang} 等${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请输入前缀 (${gl_huang}0${gl_bai}返回): ")" prefix

    [[ -z "$prefix" ]] && { cancel_empty "上一级选单"; return 1; }       # break 或 continue 或 return ，视上下文而定
    [[ "$prefix" == "0" ]] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定

    echo ""
    echo -e "${gl_bai}是否保持原扩展名?${gl_bai}"
    echo -e "${gl_huang}保持: 文件扩展名不变"
    echo -e "统一: 所有图片使用相同的扩展名${gl_bai}"
    echo ""
    echo -e "${gl_bufan}1.  ${gl_bai}保持原扩展名"
    echo -e "${gl_bufan}2.  ${gl_bai}统一为JPG格式"
    echo -e "${gl_bufan}3.  ${gl_bai}统一为PNG格式"
    echo -e "${gl_bufan}4.  ${gl_bai}统一为WEBP格式"
    echo ""

    read -r -e -p "$(echo -e "${gl_bai}请选择 (${gl_huang}1-4${gl_bai}): ")" ext_choice

    case $ext_choice in
    1) keep_original=true ;;
    2) target_ext="jpg" ;;
    3) target_ext="png" ;;
    4) target_ext="webp" ;;
    *)
        log_error "无效的选择"
        return
        ;;
    esac

    echo ""
    echo -e "${gl_bai}请选择要重命名的图片${gl_bai}"
    echo -e "${gl_bai}输入 ${gl_lv}all${gl_bai} 批量处理所有图片"
    echo -e "${gl_bai}或输入序号 (用空格分隔)${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请输入选择 (${gl_huang}0${gl_bai}返回): ")" selection

    [[ -z "$selection" ]] && { cancel_empty "上一级选单"; return 1; }      # break 或 continue 或 return ，视上下文而定
    [[ "$selection" == "0" ]] && { cancel_return "上一级选单"; return 1; } # break 或 continue 或 return ，视上下文而定

    local selected_files=()

    if [[ "$selection" == "all" ]]; then
        selected_files=("${files_ref[@]}")
    else
        selection=$(echo "$selection" | tr ',' ' ')

        if [[ "$selection" =~ ^[0-9]+-[0-9]+$ ]]; then
            local start=${selection%-*}
            local end=${selection#*-}
            for ((i = start; i <= end; i++)); do
                if [[ $i -ge 1 ]] && [[ $i -le ${#files_ref[@]} ]]; then
                    selected_files+=("${files_ref[$((i - 1))]}")
                fi
            done
        else
            for num in $selection; do
                if [[ $num =~ ^[0-9]+$ ]]; then
                    if [[ $num -ge 1 ]] && [[ $num -le ${#files_ref[@]} ]]; then
                        selected_files+=("${files_ref[$((num - 1))]}")
                    else
                        log_warn "序号 ${num} 无效"
                    fi
                fi
            done
        fi
    fi

    if [[ ${#selected_files[@]} -eq 0 ]]; then
        log_error "没有选择有效的图片"
        return
    fi

    echo ""
    echo -e "${gl_bai}选择的图片:${gl_bai}"
    for file in "${selected_files[@]}"; do
        echo -e "  ${gl_lv}✓${gl_bai} $file"
    done
    echo ""

    read -r -e -p "$(echo -e "${gl_bai}确认重命名这 ${#selected_files[@]} 个文件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    if [[ ! "$confirm" =~ ^[Yy]$ ]]; then
        log_info "操作取消"
        return
    fi

    local success=0
    local total=${#selected_files[@]}

    for i in "${!selected_files[@]}"; do
        local file="${selected_files[i]}"
        local filename=$(basename "$file")

        if [[ "$keep_original" == "true" ]]; then
            local extension="${filename##*.}"
        else
            local extension="$target_ext"
        fi

        local index=$(printf "%03d" $((i + 1)))
        local new_name="${prefix}_${index}.${extension}"
        local count=1

        while [[ -f "$new_name" ]]; do
            new_name="${prefix}_${index}_${count}.${extension}"
            count=$((count + 1))
        done

        echo -e "${gl_huang}[$((i + 1))/$total]${gl_bai} 重命名: $file → $new_name"

        if mv "$file" "$new_name" 2>/dev/null; then
            files_ref[$i]="$new_name"
            log_ok "重命名成功"
            success=$((success + 1))
        else
            log_error "重命名失败: $file"
        fi
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_ok "重命名完成"
    log_info "成功: ${gl_lv}${success}${gl_bai} 个文件"
    if [[ $((total - success)) -gt 0 ]]; then
        log_warn "失败: ${gl_huang}$((total - success))${gl_bai} 个文件"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    break_end
}

# 批量删除图片
image_converter_batch_delete() {
    local -n files_ref=$1

    if [[ ${#files_ref[@]} -eq 0 ]]; then
        log_error "没有图片可删除"
        return
    fi

    echo ""
    echo -e "${gl_bai}批量删除图片${gl_bai}"
    echo -e "${gl_hong}警告: 此操作不可恢复!${gl_bai}"
    echo ""
    echo -e "${gl_bai}请选择要删除的图片${gl_bai}"
    echo -e "${gl_bai}输入 ${gl_lv}all${gl_bai} 删除所有图片"
    echo -e "${gl_bai}或输入序号 (用空格分隔)${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请输入选择 (${gl_huang}0${gl_bai}返回): ")" selection

    [[ -z "$selection" ]] && { cancel_empty "上一级选单"; return 1; }      # break 或 continue 或 return ，视上下文而定
    [[ "$selection" == "0" ]] && { cancel_return "上一级选单"; return 1; } # break 或 continue 或 return ，视上下文而定

    local selected_files=()

    if [[ "$selection" == "all" ]]; then
        selected_files=("${files_ref[@]}")
    else
        selection=$(echo "$selection" | tr ',' ' ')

        if [[ "$selection" =~ ^[0-9]+-[0-9]+$ ]]; then
            local start=${selection%-*}
            local end=${selection#*-}
            for ((i = start; i <= end; i++)); do
                if [[ $i -ge 1 ]] && [[ $i -le ${#files_ref[@]} ]]; then
                    selected_files+=("${files_ref[$((i - 1))]}")
                fi
            done
        else
            for num in $selection; do
                if [[ $num =~ ^[0-9]+$ ]]; then
                    if [[ $num -ge 1 ]] && [[ $num -le ${#files_ref[@]} ]]; then
                        selected_files+=("${files_ref[$((num - 1))]}")
                    else
                        log_warn "序号 ${num} 无效"
                    fi
                fi
            done
        fi
    fi

    if [[ ${#selected_files[@]} -eq 0 ]]; then
        log_error "没有选择有效的图片"
        return
    fi

    echo ""
    echo -e "${gl_bai}将要删除的图片:${gl_bai}"
    for file in "${selected_files[@]}"; do
        echo -e "  ${gl_hong}✗${gl_bai} $file"
    done
    echo ""

    read -r -e -p "$(echo -e "${gl_hong}确认删除这 ${#selected_files[@]} 个文件? 此操作不可恢复! (${gl_hong}Y${gl_bai}/${gl_lv}n${gl_bai}): ")" confirm
    if [[ ! "$confirm" =~ ^[Yy]$ ]] && [[ -z "$confirm" ]]; then
        log_info "操作取消"
        return
    fi

    echo ""
    read -r -e -p "$(echo -e "${gl_hong}最后确认! 输入${gl_lv}confirm${gl_hong}以继续删除: ")" final_confirm
    if [[ "$final_confirm" != "confirm" ]]; then
        log_info "操作取消"
        return
    fi

    local success=0
    local total=${#selected_files[@]}

    for i in "${!selected_files[@]}"; do
        local file="${selected_files[i]}"
        echo -e "${gl_huang}[$((i + 1))/$total]${gl_bai} 删除: $file"

        if rm -f "$file" 2>/dev/null; then
            log_ok "删除成功"
            success=$((success + 1))
        else
            log_error "删除失败: $file"
        fi
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_ok "删除完成"
    log_info "成功: ${gl_lv}${success}${gl_bai} 个文件"
    if [[ $((total - success)) -gt 0 ]]; then
        log_warn "失败: ${gl_huang}$((total - success))${gl_bai} 个文件"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    break_end
}

# 关闭服务器函数
linux_shutdown_server() {
    echo -e ""
    echo -e "${gl_zi}>>> 关闭${gl_huang}"$(get_hostname)"${gl_zi}服务器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确定${gl_huang}"$(get_hostname)"${gl_bai}关闭服务器吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" shut_down
    [ "$shut_down" = "0" ] && { cancel_return "系统工具"; return; }   # break 或 continue 或 return ，视上下文而定
    case "$shut_down" in
    [Yy])
        echo -e "${gl_bai}正在尝试关闭${gl_huang}"$(get_hostname)"${gl_bai}服务器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        # 尝试使用 poweroff 命令
        if poweroff; then
            echo -e "${gl_lv}服务器关闭命令已执行。${gl_bai}"
        else
            echo -e "${gl_huang}poweroff 命令执行失败，正在尝试 halt ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            # 如果 poweroff 失败，则尝试 halt
            if halt; then
                echo -e "${gl_lv}已通过 halt 命令关闭${gl_huang}"$(get_hostname)"${gl_lv}服务器。${gl_bai}"
            else
                echo -e "${gl_hong}错误：无法关闭服务器，请检查权限或手动操作。${gl_bai}"
            fi
        fi
        ;;
    [Nn])
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}已取消关闭服务器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        sleep_fractional 1
        return 1
        ;;
    *) handle_y_n ;;        # 无效的输入,请输入(y或N)。
    esac
}

# 重启服务器函数
linux_reboot_server() {
    echo -e ""
    echo -e "${gl_zi}>>> 重启服务器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确定重启服务器吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" choice
    [ "$choice" = "0" ] && { cancel_return "系统工具"; return; }   # break 或 continue 或 return ，视上下文而定

    case "$choice" in
    [Yy])
        server_reboot
        ;;
    [Nn])
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}已取消重启服务器${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
        ;;
    *) handle_y_n ;;        # 无效的输入,请输入(y或N)。
    esac
}

# 时区设置函数
linux_timezone_settings() {
    root_use
    while true; do
        clear
        echo -e "${gl_huang}>>> 系统时间信息${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 获取当前系统时区
        local timezone=$(current_timezone)

        # 获取当前系统时间
        local current_time=$(date +"%Y-%m-%d %H:%M:%S")

        # 显示时区和时间
        echo -e "当前系统时区：${gl_lv}$timezone${gl_bai}"
        echo -e "当前系统时间：${gl_lv}$current_time${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

