# 用户管理函数
linux_user_management() {
    while true; do
        root_use
        echo -e "${gl_huang}用户列表${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        # printf "%-24s %-34s %-20s %-10s\n" "用户名" "用户权限" "用户组" "sudo权限"
        # while IFS=: read -r -r username _ userid groupid _ _ homedir shell; do
        #     local groups=$(groups "$username" | cut -d : -f 2)
        #     local sudo_status=$(sudo -n -lU "$username" 2>/dev/null | grep -q '(ALL : ALL)' && echo "Yes" || echo "No")
        #     printf "%-20s %-30s %-20s %-10s\n" "$username" "$homedir" "$groups" "$sudo_status"
        # done </etc/passwd
        list_beautify_user_info
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo ""
        echo -e "${gl_zi}>>> 账户操作${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}创建普通账户             ${gl_bufan}2.  ${gl_bai}创建高级账户"
        echo -e "${gl_bufan}3.  ${gl_bai}赋予最高权限             ${gl_bufan}4.  ${gl_bai}取消最高权限"
        echo -e "${gl_bufan}5.  ${gl_bai}删除账号"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单           ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " sub_choice

        case $sub_choice in
        1)
            echo ""
            echo -e "${gl_zi}>>> 创建普通账户${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入新用户名: " new_username
            [ "$new_username" = "0" ] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定
            [ -z "$new_username" ] && { cancel_empty "上一级选单"; continue; }        # break 或 continue 或 return ，视上下文而定
            useradd -m -s /bin/bash "$new_username"
            passwd "$new_username"
            echo "操作已完成。"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        2)
            echo ""
            echo -e "${gl_zi}>>> 创建高级账户${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入新用户名: " new_username
            [ "$new_username" = "0" ] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定
            [ -z "$new_username" ] && { cancel_empty "上一级选单"; continue; }        # break 或 continue 或 return ，视上下文而定
            useradd -m -s /bin/bash "$new_username"
            passwd "$new_username"
            echo "$new_username ALL=(ALL:ALL) ALL" | tee -a /etc/sudoers
            install sudo
            echo "操作已完成。"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        3)
            echo ""
            echo -e "${gl_zi}>>> 赋予最高权限${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入用户名: " username
            [ "$new_username" = "0" ] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定
            [ -z "$new_username" ] && { cancel_empty "上一级选单"; continue; }        # break 或 continue 或 return ，视上下文而定
            echo "$username ALL=(ALL:ALL) ALL" | tee -a /etc/sudoers
            install sudo
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        4)
            echo ""
            echo -e "${gl_zi}>>> 取消最高权限${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入用户名: " username
            [ "$new_username" = "0" ] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定
            [ -z "$new_username" ] && { cancel_empty "上一级选单"; continue; }        # break 或 continue 或 return ，视上下文而定
            sed -i "/^$username\sALL=(ALL:ALL)\sALL/d" /etc/sudoers
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        5)
            echo ""
            echo -e "${gl_zi}>>> 删除账号${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入要删除的用户名: " username
            [ "$new_username" = "0" ] && { cancel_return "上一级选单"; continue; }    # break 或 continue 或 return ，视上下文而定
            [ -z "$new_username" ] && { cancel_empty "上一级选单"; continue; }        # break 或 continue 或 return ，视上下文而定
            userdel -r "$username"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        0) cancel_return "系统工具"; break ;;        # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;             # 感谢使用，再见！
        *) handle_invalid_input ;;                  # 无效的输入,请重新输入!
        esac
    done
}

