# 修改主机名函数
linux_change_hostname() {
    root_use
    while true; do
        echo -e ""
        local current_hostname=$(uname -n)
        echo -e "${gl_zi}>>> 修改主机名"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "当前主机名: ${gl_huang}$current_hostname${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入新的主机名(${gl_huang}0${gl_bai}返回): ")" new_hostname

        if [ -n "$new_hostname" ] && [ "$new_hostname" != "0" ]; then
            if [ -f /etc/alpine-release ]; then
                # Alpine
                echo "$new_hostname" >/etc/hostname
                hostname "$new_hostname"
            else
                # 其他系统，如 Debian, Ubuntu, CentOS 等
                hostnamectl set-hostname "$new_hostname"
                sed -i "s/$current_hostname/$new_hostname/g" /etc/hostname
                systemctl restart systemd-hostnamed
            fi

            if grep -q "127.0.0.1" /etc/hosts; then
                sed -i "s/127.0.0.1 .*/127.0.0.1       $new_hostname localhost localhost.localdomain/g" /etc/hosts
            else
                echo "127.0.0.1       $new_hostname localhost localhost.localdomain" >>/etc/hosts
            fi

            if grep -q "^::1" /etc/hosts; then
                sed -i "s/^::1 .*/::1             $new_hostname localhost localhost.localdomain ipv6-localhost ipv6-loopback/g" /etc/hosts
            else
                echo "::1             $new_hostname localhost localhost.localdomain ipv6-localhost ipv6-loopback" >>/etc/hosts
            fi

            echo "主机名已更改为: $new_hostname"
            sleep_fractional 1
        else
            echo "已退出，未更改主机名。"
            break
        fi
    done
}

# 设置虚拟内存函数
linux_set_swap() {
    root_use
    while true; do
        clear
        echo -e "${gl_zi}>>> 设置虚拟内存${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        local swap_used=$(free -m | awk 'NR==3{print $3}')
        local swap_total=$(free -m | awk 'NR==3{print $2}')
        local swap_info=$(free -m | awk 'NR==3{used=$3; total=$2; if (total == 0) {percentage=0} else {percentage=used*100/total}; printf "%dM/%dM (%d%%)", used, total, percentage}')
        echo -e "当前虚拟内存: ${gl_huang}$swap_info${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}分配1024M"
        echo -e "${gl_bufan}2.  ${gl_bai}分配2048M"
        echo -e "${gl_bufan}3.  ${gl_bai}分配4096M"
        echo -e "${gl_bufan}4.  ${gl_bai}自定义大小"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
        echo -e "${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " choice

        case "$choice" in
        1)
            add_swap 1024
            ;;
        2)
            add_swap 2048
            ;;
        3)
            add_swap 4096
            ;;
        4)
            read -r -e -p "请输入虚拟内存大小（单位M）: " new_swap
            [ "$new_swap" = "0" ] && { cancel_return "上一级选单"; continue; }      # break 或 continue 或 return ，视上下文而定
            [ -z "$new_swap" ] && { cancel_empty "上一级选单"; continue; }           # break 或 continue 或 return ，视上下文而定
            add_swap "$new_swap"
            ;;
        0) cancel_return "系统工具"; break ;;      # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;; # 感谢使用，再见！
        *) handle_invalid_input ;;      # 无效的输入,请重新输入!
        esac
    done
}

# 配置SSH服务函数
linux_setup_ssh() {
    clear
    root_use

    echo -e "${gl_zi}>>> 配置 SSH 服务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    # log_info "脚本功能:"
    # echo "  • 自动检测 Linux 发行版并安装 SSH 服务"
    # echo "  • 配置 SSH 基本参数和优化设置"
    # echo "  • 配置防火墙允许 SSH 连接"
    # echo "  • 启动并启用 SSH 服务"
    # log_info "支持的系统:"
    # echo "  • Debian 及其衍生版 (Ubuntu, Proxmox VE, FnOS)"
    # echo "  • Red Hat 系 (CentOS, RHEL, Fedora, Rocky Linux)"
    # echo "  • SUSE 系 (OpenSUSE, SUSE Linux Enterprise)"
    # log_warn "注意:"
    # echo "  • 此脚本需要 root 权限运行"
    # echo "  • 脚本会修改 SSH 配置并开放防火墙"
    # echo "  • 默认配置允许 root 登录，建议后续修改为更安全的设置"
    list_beautify_sshd_config
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo ""
    echo -e "${gl_huang}>>> 配置 SSH 端口${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    local port_input
    while true; do
        read -r -e -p "$(echo -e "${gl_bai}请输入 SSH 端口 (回车默认 ${gl_huang}22${gl_bai}, ${gl_huang}0${gl_bai}返回): ")" port_input
        [ -z "$port_input" ] && { SSH_PORT=22; break; }                         # break 或 continue 或 return ，视上下文而定
        [ "$port_input" = "0" ] && { cancel_return "上一级选单"; return 1; }     # break 或 continue 或 return ，视上下文而定

        if [[ "$port_input" =~ ^[1-9][0-9]{0,4}$ ]] && (( port_input <= 65535 )); then
            SSH_PORT=$port_input
            break
        else
            log_error "端口格式非法，请重新输入！"
        fi
    done
    log_info "使用 SSH 端口: $SSH_PORT"
    
    # 检测操作系统
    log_info "检测操作系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if [ -f /etc/os-release ]; then
        . /etc/os-release
        OS=$ID
        OS_VERSION=$VERSION_ID
        OS_NAME=$PRETTY_NAME
    elif type lsb_release >/dev/null 2>&1; then
        OS=$(lsb_release -si | tr '[:upper:]' '[:lower:]')
        OS_VERSION=$(lsb_release -sr)
        OS_NAME=$(lsb_release -sd)
    elif [ -f /etc/lsb-release ]; then
        . /etc/lsb-release
        OS=$DISTRIB_ID
        OS_VERSION=$DISTRIB_RELEASE
        OS_NAME=$DISTRIB_DESCRIPTION
    elif [ -f /etc/debian_version ]; then
        OS=debian
        OS_VERSION=$(cat /etc/debian_version)
        OS_NAME="Debian $OS_VERSION"
    elif [ -f /etc/redhat-release ]; then
        OS=$(awk '{print tolower($1)}' /etc/redhat-release)
        OS_VERSION=$(awk '{print $3}' /etc/redhat-release)
        OS_NAME=$(cat /etc/redhat-release)
    else
        log_error "无法检测操作系统"; exit 1
    fi
    log_info "检测到操作系统: $OS_NAME"
    
    # 安装SSH
    log_info "开始安装 SSH 服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    case $OS in
        debian|ubuntu|linuxmint)
            apt-get update -qq
            apt-get install -y openssh-server
            ;;
        centos|rhel|fedora|rocky|almalinux)
            if command -v dnf >/dev/null 2>&1; then
                dnf install -y openssh-server
            else
                yum install -y openssh-server
            fi
            ;;
        opensuse*|suse*)
            zypper install -y openssh
            ;;
        arch|manjaro)
            pacman -Syu --noconfirm openssh
            ;;
        *)
            log_error "不支持的发行版: $OS"; exit 1
            ;;
    esac
    log_ok "SSH 服务安装完成"
    
    # 配置SSH
    log_info "开始配置 SSH 服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    [ -f /etc/ssh/sshd_config ] && \
        cp /etc/ssh/sshd_config /etc/ssh/sshd_config.backup.$(date +%Y%m%d%H%M%S)

    # 关键配置缺省值表
    declare -A SSH_DEF
    SSH_DEF=(
        ["Port"]="$SSH_PORT"
        ["PermitRootLogin"]="yes"
        ["GSSAPIAuthentication"]="no"
        ["PrintMotd"]="no"
        ["PrintLastLog"]="no"
        ["TCPKeepAlive"]="no"
        ["Compression"]="delayed"
        ["ClientAliveInterval"]="30"
        ["ClientAliveCountMax"]="120"
        ["UseDNS"]="no"
        ["X11Forwarding"]="no"
    )

    # 1. 备份
    cp /etc/ssh/sshd_config "/etc/ssh/sshd_config.bak.$(date +%Y%m%d_%H%M%S)"

    # 2. 删除空行
    sed -i '/^[[:space:]]*$/d' /etc/ssh/sshd_config

    # 3. 删除纯注释行
    sed -i '/^[[:space:]]*#/d' /etc/ssh/sshd_config

    # 4. 删除已存在的配置行
    for key in "${!SSH_DEF[@]}"; do
        sed -i "/^[[:space:]]*#*[[:space:]]*$key[[:space:]]/d" /etc/ssh/sshd_config
    done

    sed -i "/[[:space:]]*自动补写缺省值/d" /etc/ssh/sshd_config

    # 5. 追加缺省值
    echo "" >> /etc/ssh/sshd_config
    echo "# ==== 自动补写缺省值 $(date +%F' '%T) ====" >> /etc/ssh/sshd_config
    for key in "${!SSH_DEF[@]}"; do
        printf "%-25s %s\n" "$key" "${SSH_DEF[$key]}" >> /etc/ssh/sshd_config
    done

    log_ok "SSH 配置已更新/补全"
    
    # 配置防火墙
    log_info "开始配置防火墙 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if command -v ufw >/dev/null 2>&1; then
        ufw allow "$SSH_PORT"/tcp
        echo "y" | ufw enable
    elif command -v firewall-cmd >/dev/null 2>&1; then
        systemctl enable --now firewalld
        firewall-cmd --permanent --add-port="$SSH_PORT"/tcp
        firewall-cmd --reload
    elif command -v iptables >/dev/null 2>&1; then
        iptables -A INPUT -p tcp --dport "$SSH_PORT" -j ACCEPT
        mkdir -p /etc/iptables
        iptables-save > /etc/iptables/rules.v4
    else
        log_warn "未找到支持的防火墙工具，请手动配置"
    fi
    log_ok "防火墙配置完成"
    
    # 修改root密码
    echo ""
    echo -e "${gl_huang}>>> 修改 root 密码${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}修改 root 密码？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai} 回车跳过): ")" -re ans
    echo -e "${gl_bai}"
    case "${ans,,}" in
        y|yes)
            while true; do
                read -s -p "请输入新密码: " -re pw1; echo
                read -s -p "请再次输入新密码: " -re pw2; echo
                if [ "$pw1" = "$pw2" ]; then
                    echo "root:$pw1" | chpasswd 2>/dev/null && {
                        log_ok "root 密码已更新。"; break
                    } || log_warn "密码设置失败（可能过于简单），请重试。"
                else
                    log_warn "两次输入不一致，请重新输入！"
                fi
            done
            ;;
        *) log_info "已跳过 root 密码修改。" ;;
    esac
    
    # 启动SSH服务
    log_info "启动/重启 SSH 服务 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    case $OS in
        debian|ubuntu|linuxmint|opensuse*|suse*|arch|manjaro)
            systemctl enable ssh
            systemctl restart ssh
            systemctl status ssh --no-pager -l
            ;;
        centos|rhel|fedora|rocky|almalinux)
            systemctl enable sshd
            systemctl restart sshd
            systemctl status sshd --no-pager -l
            ;;
        *)
            log_error "不支持的发行版: $OS"; exit 1
            ;;
    esac
    log_ok "SSH 服务已重启并生效"
    
    # 显示配置更改
    echo ""
    echo -e "${gl_huang}>>> 本次脚本涉及的关键配置："
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    grep -E '^(Port|PermitRootLogin|GSSAPIAuthentication|UseDNS|Compression|ClientAliveInterval|ClientAliveCountMax|TCPKeepAlive|PrintMotd|PrintLastLog|X11Forwarding)[[:space:]]' /etc/ssh/sshd_config
    
    # 显示连接信息
    local ip=$(hostname -I | awk '{print $1}')
    echo ""
    echo -e "${gl_huang}>>> 连接信息："
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "  配置文件: ${gl_lv}/etc/ssh/sshd_config${gl_bai}"
    echo -e "  服务器IP: ${gl_lv}$ip${gl_bai}"
    echo -e "  SSH 端口: ${gl_lv}$SSH_PORT${gl_bai}"
    echo -e "  连接命令: ${gl_lv}ssh -p $SSH_PORT root@$ip${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 修改SSH连接端口函数
linux_change_ssh_port() {
    # 修改SSH连接端口
    root_use
    while true; do
        clear
        
        # 读取当前的 SSH 端口号
        local current_port=$(grep -E '^[[:space:]]*Port[[:space:]]+[0-9]+' /etc/ssh/sshd_config 2>/dev/null | head -n1 | awk '{print $2}')
        
        # 如果找不到明确配置的端口，则使用默认端口22
        if [ -z "$current_port" ]; then
            # 检查是否有被注释的端口配置
            local commented_port=$(grep -E '^[[:space:]]*#[[:space:]]*Port[[:space:]]+[0-9]+' /etc/ssh/sshd_config 2>/dev/null | head -n1 | awk '{print $2}')
            if [ -n "$commented_port" ]; then
                current_port="$commented_port (被注释)"
            else
                current_port="22 (默认)"
            fi
        fi

        echo ""
        echo -e "${gl_zi}>>> 修改SSH连接端口${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "当前的 SSH 端口号是:  ${gl_huang}$current_port ${gl_bai}"
        echo -e "端口号范围1到65535之间的数字。"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入新的 SSH 端口号 (${gl_huang}0${gl_bai}返回): ")" new_port
        [ "$new_port" = "0" ] && { cancel_return "系统工具"; break; }       # break 或 continue 或 return ，视上下文而定
        [ -z "$new_port" ] && { cancel_empty "重新输入"; continue; }        # break 或 continue 或 return ，视上下文而定

        # 判断端口号是否在有效范围内
        if [[ $new_port =~ ^[0-9]+$ ]]; then # 检查输入是否为数字
            if [[ $new_port -ge 1 && $new_port -le 65535 ]]; then
                # 检查端口是否已被占用
                if ss -tuln | grep -q ":$new_port "; then
                    echo -e "${gl_hong}错误：端口 $new_port 已被占用，请选择其他端口${gl_bai}"
                    continue
                fi
                
                # 检查端口是否是当前端口
                if [ "$current_port" = "$new_port" ] || [[ "$current_port" =~ "$new_port" ]]; then
                    echo -e "${gl_huang}新端口与当前端口相同，无需修改${gl_bai}"
                    continue
                fi
                
                # 调用new_ssh_port函数修改端口
                if command -v new_ssh_port &>/dev/null; then
                    echo -e "${gl_lv}正在修改SSH端口为: $new_port${gl_bai}"
                    new_ssh_port
                else
                    echo -e "${gl_hong}错误：new_ssh_port函数未定义${gl_bai}"
                fi
                
                break_end
                break
            elif [[ $new_port -eq 0 ]]; then
                echo "已取消修改端口"
                break
            else
                echo -e "${gl_hong}端口号无效，请输入1到65535之间的数字。${gl_bai}"
                break_end
            fi
        else
            echo -e "${gl_hong}输入无效，请输入数字。${gl_bai}"
            break_end
        fi
    done
}


# 本地SSH密钥自动分发函数
linux_ssh_key_distribution() {
    clear
    # 本地SSH密钥自动分发
    echo -e "${gl_zi}>>> 本地SSH密钥自动分发${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    scan_key_done 10.10.10
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 直接读取输入（无循环）
    read -r -e -p "$(echo -e "${gl_bai}请输入要批量推钥的主机号，用空格或逗号隔开（例：${gl_lv}251 ${gl_huang}253 ${gl_hong}254${gl_bai}，${gl_huang}0${gl_bai}返回）: ")" input
    [ "$input" == "0" ] && { cancel_return "上一级选单"; return 1; }        # break 或 continue 或 return ，视上下文而定
    [ -z "$repoUrl" ] && { cancel_empty "上一级选单"; return 1; }           # break 或 continue 或 return ，视上下文而定

    # 把逗号替换成空格，再压成数组
    hosts=(${input//,/ })

    # 拼成"251 252 253"这种形式
    host_args="${hosts[*]}"

    # 拉取官方脚本并执行
    bash <(curl -sL https://gitee.com/meimolihan/script/raw/master/sh/ssh/auto_keypush.sh ) $host_args
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# SSH防御程序管理函数
linux_ssh_defense_management() {
    root_use
    while true; do
        check_f2b_status
        echo -e "SSH防御程序 $check_f2b_status"
        echo -e "fail2ban是一个SSH防止暴力破解工具"
        echo -e "${gl_bufan}官网介绍: ${gl_bai}${gh_proxy}github.com/fail2ban/fail2ban"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}安装防御程序"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}2.  ${gl_bai}查看SSH拦截记录"
        echo -e "${gl_bufan}3.  ${gl_bai}日志实时监控"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}9.  ${gl_bai}卸载防御程序"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
        echo -e "${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " sub_choice
        case $sub_choice in
        1)
            f2b_install_sshd
            cd ~
            f2b_status
            break_end
            ;;
        2)
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            f2b_sshd
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        3)
            tail -f /var/log/fail2ban.log
            break
            ;;
        9)
            remove fail2ban
            rm -rf /etc/fail2ban
            echo "Fail2Ban防御程序已卸载"
            exit_animation    # 即将退出动画
            break
            ;;
        0) cancel_return "系统工具"; break ;;    # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;         # 感谢使用，再见！
        *) handle_invalid_input ;;              # 无效的输入,请重新输入!
        esac
    done
}

