# 命令行历史记录函数
linux_command_history() {
    clear
    echo -e ""
    echo -e "${gl_zi}>>> 命令行历史记录${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    get_history_file() {
        for file in "$HOME"/.bash_history "$HOME"/.ash_history "$HOME"/.zsh_history "$HOME"/.local/share/fish/fish_history; do
            [ -f "$file" ] && {
                echo "$file"
                return
            }
        done
        exit_animation    # 即将退出动画
        return 1
    }

    history_file=$(get_history_file) && cat -n "$history_file"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 设置脚本启动快捷键函数
linux_set_shortcut() {
    # 设置脚本启动快捷键
    while true; do
        clear
        read -r -e -p "$(echo -e "${gl_bai}请输入你的快捷按键（${gl_huang}0${gl_bai}返回）: ")" kuaijiejian
        [ "$kuaijiejian" == "0" ] && { cancel_return "上一级选单"; break; }          # break 或 continue 或 return ，视上下文而定
        [ -z "$repoUrl" ] && { cancel_empty "重新输入仓库地址"; continue; }           # break 或 continue 或 return ，视上下文而定
        find /usr/local/bin/ -type l -exec bash -c 'test "$(readlink -f {})" = "/usr/local/bin/m" && rm -f {}' \;
        ln -s /usr/local/bin/m /usr/local/bin/"$kuaijiejian"
        echo "快捷键已设置"
        exit_animation    # 即将退出动画
        linux_Settings "$@"
    done
}

