    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入新用户名 (${gl_huang}0${gl_bai}返回): ")" new_username
    [ "$new_username" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
    [ -z "$new_username" ] && { cancel_empty "上一级选单"; return 1; }         # break 或 continue 或 return ，视上下文而定  

    create_user_with_sshkey $new_username true

    ssh-keygen -l -f /home/$new_username/.ssh/authorized_keys &>/dev/null && {
        passwd -l root &>/dev/null
        sed -i 's/^[[:space:]]*#\?[[:space:]]*PermitRootLogin.*/PermitRootLogin no/' /etc/ssh/sshd_config
    }
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

