            fi
            ;;
        4)
            if [[ -d "/vol2/1000/阿里云盘/教程文件/壁纸原图/手机原图" ]]; then
                cd "/vol2/1000/阿里云盘/教程文件/壁纸原图/手机原图" && $target_func "." "手机原图管理" "随机壁纸文件管理"
            else
                check_directory_empty "/vol2/1000/阿里云盘/教程文件/壁纸原图/手机原图" "手机原图管理" || continue
            fi
            ;;
        5)
            if [[ -d "/vol1/1000/compose/random-pic-api/photos" ]]; then
                cd "/vol1/1000/compose/random-pic-api/photos" && $target_func "." "随机壁纸目录" "随机壁纸文件管理"
            else
                check_directory_empty "/vol1/1000/compose/random-pic-api/photos" "随机壁纸目录" || continue
            fi
            ;;
        6)
            read -r -e -p "$(echo -e "${gl_bai}请输入要进入的目录路径: ")" custom_path
            if [[ -d "$custom_path" ]]; then
                cd "$custom_path" && $target_func "." "自定义目录管理" "随机壁纸文件管理"
            else
                check_directory_empty "$custom_path" "自定义目录管理" || continue
            fi
            ;;
        0) cancel_return; return ;;
        *) handle_invalid_input ;;
        esac
    done
}

