                cd "/vol2/1000/mydisk/Video" && $target_func "/vol2/1000/mydisk/Video" "视频文件管理" "常用目录管理"
            else
                check_directory_empty "/vol2/1000/mydisk/Video" "视频文件管理" || continue
            fi
            ;;
        3)
            if [[ -d "/vol2/1000/media" ]]; then
                cd "/vol2/1000/media" && $target_func "." "飞牛 TV 目录管理" "常用目录管理"
            else
                check_directory_empty "/vol2/1000/media" "飞牛 TV 目录管理" || continue
            fi
            ;;
        4)
            if [[ -d "/vol2/1000" ]]; then
                cd "/vol2/1000" && $target_func "." "飞牛文件管理" "常用目录管理"
            else
                check_directory_empty "/vol2/1000" "飞牛文件管理" || continue
            fi
            ;;
        5)
            if [[ -d "/vol1/1000/compose/random-pic-api/photos" ]]; then
                cd "/vol1/1000/compose/random-pic-api/photos" && $target_func "." "随机壁纸待处理目录管理" "常用目录管理"
            else
                check_directory_empty "/vol1/1000/compose/random-pic-api/photos" "随机壁纸待处理目录管理" || continue
            fi
            ;;
        6)
            if [[ -d "/var/lib/vz/template/iso" ]]; then
                cd "/var/lib/vz/template/iso" && $target_func "." "PVE 固件目录管理" "常用目录管理"
            else
                check_directory_empty "/var/lib/vz/template/iso" "PVE 固件目录管理" || continue
            fi
            ;;
        7)
            if [[ -d "/var/lib/vz/dump" ]]; then
                cd "/var/lib/vz/dump" && $target_func "." "PVE 备份目录管理" "常用目录管理"
            else
                check_directory_empty "/var/lib/vz/dump" "PVE 备份目录管理" || continue
            fi
            ;;
        8)
            if [[ -d "/mnt/compose" ]]; then
                cd "/mnt/compose" && $target_func "/mnt/compose" "Compose项目管理" "常用目录管理"
            else
                check_directory_empty "/mnt/compose" "Compose项目管理" || continue
            fi
            ;;
        9)
            read -r -e -p "$(echo -e "${gl_bai}请输入要进入的目录路径: ")" custom_path
            if [[ -d "$custom_path" ]]; then
                cd "$custom_path" && $target_func "." "自定义目录管理" "常用目录管理"
            else
                check_directory_empty "$custom_path" "飞牛文件管理" || continue
            fi
            ;;
        0) cancel_return; return ;;
        *) handle_invalid_input ;;
        esac
    done
}

# 检查 PVE 版本
check_pve_version() {
    if command -v pveversion &>/dev/null; then
        # 获取PVE版本
        pve_version=$(pveversion | grep -oP 'pve-manager\/\K[^ ]+')
        # 获取内核版本
        kernel_version=$(uname -r)

        echo -e "${gl_bai}PVE 系统版本：${gl_lv}$pve_version${gl_bai}"
        echo -e "${gl_bai}PVE 内核版本：${gl_lv}$kernel_version${gl_bai}"
    else
        echo -e "${gl_bai}PVE 系统版本：${gl_hong}非PVE系统或未安装pveversion${gl_bai}"
    fi
}

pve_running_status_simple() {
    # 检查命令是否存在
    if ! command -v qm &>/dev/null; then
        log_error "qm命令未找到，可能不在PVE节点上"
        return 1
    fi

    # 虚拟机
    echo -e "${gl_bai}运行中的虚拟机:${gl_bai}"
    if qm_output=$(qm list 2>/dev/null | grep -E "running"); then
        echo "$qm_output" | while IFS= read -r line; do
            echo -e " ${gl_lv}${line}${gl_bai}"
        done
    else
        echo -e "    ${gl_huang}无运行中的虚拟机${gl_bai}"
    fi

    # 容器
    echo -e "${gl_bai}运行中的容器:${gl_bai}"
    if pct_output=$(pct list 2>/dev/null | grep -E "running"); then
        echo "   $pct_output" | while IFS= read -r line; do
            echo -e "     ${gl_lan}${line}${gl_bai}"
        done
    else
        echo -e "     ${gl_huang}无运行中的容器${gl_bai}"
    fi
}

# 函数_PVE 资源锁状态检测
pve_check_locks() {
    # 检查是否在PVE环境中
    if [ ! -f /etc/pve/.version ] && ! command -v qm &>/dev/null; then
        log_error "不在Proxmox VE环境中或qm命令未找到"
        exit_animation    # 即将退出动画
        return 1
    fi

    # echo -e "${gl_zi}>>> PVE 资源锁状态检测${gl_bai}"
    # echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查QEMU虚拟机锁
    local vm_locked_count=0
    local container_locked_count=0
    local has_lock=false

    echo -e "${gl_lv}🖥️  KVM 虚拟机锁状态${gl_bai}"

    # 获取虚拟机列表
    local vm_list
    vm_list=$(qm list 2>/dev/null)

    if [ -n "$vm_list" ]; then
        # 打印表头
        # echo -e "${gl_huang}VMID    名称                状态    锁类型    说明${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        echo "$vm_list" | grep -E "^[0-9]+" | while IFS= read -r line; do
            local vmid
            local name
            local status
            local lock
            vmid=$(echo "$line" | awk '{print $1}')
            name=$(echo "$line" | awk '{print $2}')
            status=$(echo "$line" | awk '{print $3}')
            lock=$(echo "$line" | awk '{print $4}')

            # 检查锁状态
            if [ -n "$lock" ] && [ "$lock" != "-" ]; then
                # 只显示标准PVE锁类型
                case "$lock" in
                backup | migrate | snapshot | snapdelete | clone | rollback)
                    ((vm_locked_count++))
                    has_lock=true
                    local lock_desc=""
                    local lock_color=""

                    # 根据锁类型设置描述和颜色
                    case "$lock" in
                    backup)
                        lock_desc="${gl_huang}备份中"
                        lock_color="${gl_huang}"
                        ;;
                    migrate)
                        lock_desc="${gl_zi}迁移中"
                        lock_color="${gl_zi}"
                        ;;
                    snapshot)
                        lock_desc="${gl_lan}快照中"
                        lock_color="${gl_lan}"
                        ;;
                    snapdelete)
                        lock_desc="${gl_hong}删快照"
                        lock_color="${gl_hong}"
                        ;;
                    clone)
                        lock_desc="${gl_bufan}克隆中"
                        lock_color="${gl_bufan}"
                        ;;
                    rollback)
                        lock_desc="${gl_huang}回滚中"
                        lock_color="${gl_huang}"
                        ;;
                    esac

                    # 状态颜色
                    if [ "$status" = "running" ]; then
                        status_display="${gl_lv}● 运行${gl_bai}"
                    else
                        status_display="${gl_hui}○ 停止${gl_bai}"
                    fi

                    # 输出带锁的虚拟机
                    printf "${gl_bai}%-6s  %-18s  %s  %-8s  %s${gl_bai}\n" \
                        "$vmid" "$name" "$status_display" "${lock_color}${lock}${gl_bai}" "${lock_desc}${gl_bai}"
                    ;;
                esac
            fi
        done

        if [ "$vm_locked_count" -eq 0 ]; then
            log_ok "没有虚拟机处于锁定状态"
        fi
    else
        log_warn "未找到虚拟机或qm命令执行失败"
    fi

    echo ""
    echo -e "${gl_lv}📦 LXC 容器锁状态${gl_bai}"

    # 获取容器列表
    local container_list
    container_list=$(pct list 2>/dev/null)

    if [ -n "$container_list" ]; then
        # 打印表头
        # echo -e "${gl_huang}CTID    名称                状态    锁类型    说明${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        echo "$container_list" | grep -E "^[0-9]+" | while IFS= read -r line; do
            local vmid
            local status
            local lock
            local name
            vmid=$(echo "$line" | awk '{print $1}')
            status=$(echo "$line" | awk '{print $2}')
            lock=$(echo "$line" | awk '{print $3}')
            name=$(echo "$line" | awk '{print $4}')

            # 检查锁状态
            if [ -n "$lock" ] && [ "$lock" != "-" ]; then
                # 只显示标准PVE锁类型
                case "$lock" in
                backup | migrate | snapshot | snapdelete | clone | rollback)
                    ((container_locked_count++))
                    has_lock=true
                    local lock_desc=""
                    local lock_color=""

                    # 根据锁类型设置描述和颜色
                    case "$lock" in
                    backup)
                        lock_desc="${gl_huang}备份中"
                        lock_color="${gl_huang}"
                        ;;
                    migrate)
                        lock_desc="${gl_zi}迁移中"
                        lock_color="${gl_zi}"
                        ;;
                    snapshot)
                        lock_desc="${gl_lan}快照中"
                        lock_color="${gl_lan}"
                        ;;
                    snapdelete)
                        lock_desc="${gl_hong}删快照"
                        lock_color="${gl_hong}"
                        ;;
                    clone)
                        lock_desc="${gl_bufan}克隆中"
                        lock_color="${gl_bufan}"
                        ;;
                    rollback)
                        lock_desc="${gl_huang}回滚中"
                        lock_color="${gl_huang}"
                        ;;
                    esac

                    # 状态颜色
                    if [ "$status" = "running" ]; then
                        status_display="${gl_lv}● 运行${gl_bai}"
                    else
                        status_display="${gl_hui}○ 停止${gl_bai}"
                    fi

                    # 输出带锁的容器
                    printf "${gl_bai}%-6s  %-18s  %s  %-8s  %s${gl_bai}\n" \
                        "$vmid" "$name" "$status_display" "${lock_color}${lock}${gl_bai}" "${lock_desc}${gl_bai}"
                    ;;
                esac
            fi
        done

        if [ "$container_locked_count" -eq 0 ]; then
            log_ok "没有容器处于锁定状态"
        fi
    else
        log_warn "未找到容器或pct命令执行失败"
    fi

}

