                echo -e "${gl_hong}错误：未输入有效的URL${gl_bai}"
                exit_animation    # 即将退出动画
                return
            fi
            local cleanUrl=${repoUrl#*git clone }
            cleanUrl=${cleanUrl//[\"\'\']/}
            local repoName=$(basename "$cleanUrl" .git)

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}即将克隆仓库: $repoName${gl_bai}"
            echo -e "${gl_bufan}仓库地址: $cleanUrl${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            if [ -d "$repoName" ]; then
                echo -e "${gl_huang}警告：仓库目录 '$repoName' 已存在${gl_bai}"
                read -r -rp "$(echo -e "${gl_bufan}是否强制重新克隆? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}) ：")" overwrite
                if [[ ${overwrite,,} != "y" ]]; then
                    echo -e "${gl_lv}已取消克隆${gl_bai}"
                    exit_animation    # 即将退出动画
                    return
                fi
                rm -rf "$repoName"
            fi

            git clone "$cleanUrl"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            if [ $? -ne 0 ]; then
                echo -e "${gl_hong}仓库 '$repoName' 克隆失败，请检查URL是否正确或网络连接。${gl_bai}"
            else
                echo -e "${gl_lv}仓库 '$repoName' 克隆成功！${gl_bai}"
            fi
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
            ;;
        99)
            echo -e "${gl_huang}正在克隆全部仓库 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_huang}这可能需要一些时间，请耐心等待 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            success_count=0
            fail_count=0

            for i in {1..42}; do
                repo_name=$(basename "${repositories[$i]}" .git)
                echo -n "$(echo -e "${gl_huang}克隆 $repo_name ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} ${gl_bai}")"
                if git clone "${repositories[$i]}" 2>/dev/null; then
                    echo -e "${gl_lv}成功${gl_bai}"
                    ((success_count++))
                else
                    echo -e "${gl_hong}失败${gl_bai}"
                    ((fail_count++))
                fi
            done

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "克隆完成: ${gl_lv}成功 $success_count${gl_bai}, ${gl_hong}失败 $fail_count${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
            ;;
        0) cancel_return; break ;;      # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;; # 感谢使用，再见！
        *) handle_invalid_input ;;      # 无效的输入,请重新输入!
        esac
    done
}

###### 检查docker状态
docker_status() {
    # 1. 命令是否存在
    if ! command -v docker >/dev/null 2>&1; then
        echo -e "${gl_bufan}Docker${gl_bai} 状态：${gl_hong}未安装${gl_bai}"
        return 1
    fi

    # 2. 直接问 daemon 要版本，能答就说明“已启动”
    #    比猜 init 系统更通用，2 秒超时防止挂死
    if timeout 2 docker version >/dev/null 2>&1; then
        echo -e "${gl_bufan}Docker${gl_bai} 状态：${gl_lv}已启动${gl_bai}"
        return 0
    fi

    # 3. 命令存在但 daemon 无响应 → 已停止
    echo -e "${gl_bufan}Docker${gl_bai} 状态：${gl_hui}已停止${gl_bai}"
    return 2
}

###### 检查docker版本
check_docker_version() {
    if command -v docker &>/dev/null; then
        # 获取 docker 版本信息
        version=$(docker --version | grep -oP 'version \K[^, ]+' 2>/dev/null || echo "未知")
        echo -e "${gl_bufan}Docker ${gl_bai}版本：${gl_lv}$version${gl_bai}"
    else
        echo -e "${gl_bufan}Docker ${gl_bai}版本：${gl_hong}未安装${gl_bai}"
    fi
}

###### 检查docker-compose版本
check_docker_compose() {
    if command -v docker-compose &>/dev/null; then
        # 使用 docker-compose（旧版独立安装）
        version=$(docker-compose --version | sed -n 's/.*version[[:space:]]*\([^, ]*\).*/\1/p')
        echo -e "${gl_bufan}Compose${gl_bai}版本：${gl_lv}${version:-未知}${gl_bai}"
    elif docker compose version &>/dev/null; then
        # 使用 docker compose（新版插件方式）
        version=$(docker compose version | sed -n 's/.*\(v[0-9]\+\.[0-9]\+\.[0-9]\+\).*/\1/p')
        echo -e "${gl_bufan}Compose${gl_bai}版本：${gl_lv}${version:-未知}${gl_bai}"
    else
        echo -e "${gl_bufan}Compose${gl_bai}版本：${gl_hong}未安装${gl_bai}"
    fi
}

###### 检查git版本
check_git_version() {
    if command -v git &>/dev/null; then
        # 获取当前安装的 git 版本
        local current_version=$(git --version 2>/dev/null | grep -oP 'version \K[^ ]+' || echo "未知")
        echo -e "${gl_bufan}Git ${gl_bai}版本：${gl_lv}$current_version${gl_bai}"

        # 尝试获取最新版本
        local latest_version=""

        # 方法1: 通过GitHub API获取最新版本（推荐）
        if command -v curl &>/dev/null; then
            latest_version=$(curl -s https://api.github.com/repos/git/git/releases/latest 2>/dev/null |
                grep -oP '"tag_name": "v\K[^"]+' | head -1)
        elif command -v wget &>/dev/null; then
            # 如果没有curl，尝试用wget
            latest_version=$(wget -qO- https://api.github.com/repos/git/git/releases/latest 2>/dev/null |
                grep -oP '"tag_name": "v\K[^"]+' | head -1)
        fi

        # 如果通过API获取失败，尝试从git-scm.com获取
        if [[ -z "$latest_version" ]]; then
            if command -v curl &>/dev/null; then
                latest_version=$(curl -s https://git-scm.com/ 2>/dev/null |
                    grep -oP 'Latest source release <span[^>]*>\K[^<]+' |
                    head -1)
            fi
        fi

        # 如果获取到最新版本，进行比较
        if [[ -n "$latest_version" && "$current_version" != "未知" ]]; then
            # 移除版本号中的v前缀（如果有）
            latest_version=${latest_version#v}
            current_version=${current_version#v}

            # 比较版本号
            if [[ "$(printf '%s\n' "$current_version" "$latest_version" | sort -V | head -1)" != "$latest_version" ]]; then
                echo -e "${gl_bufan}Git 最新版本：${gl_huang}${latest_version}${gl_bai} ${gl_bai}(可更新)${gl_bai}"
            else
                echo -e "${gl_bufan}Git 已是最新版本${gl_bai}"
            fi
        fi
    else
        echo -e "${gl_bufan}Git ${gl_bai}版本：${gl_hong}未安装${gl_bai}"
    fi
}

###### 检查Git状态
git_status() {
    # 1. 命令是否存在
    if ! command -v git >/dev/null 2>&1; then
        echo -e "${gl_bufan}Git ${gl_bai}状态：${gl_hong}未安装${gl_bai}"
        return 1
