    # 2. 是否能成功调用 git 版本（验证 git 可用）
    if git --version >/dev/null 2>&1; then
        echo -e "${gl_bufan}Git ${gl_bai}状态：${gl_lv}已安装${gl_bai}"
        return 0
    else
        echo -e "${gl_bufan}Git ${gl_bai}状态：${gl_hui}未安装${gl_bai}"
        return 2
    fi
}

###### 个人Docker镜像加速
set_mirrors() {
    local mirrors="$1"
    install jq || return 1

    local tmp
    tmp=$(mktemp)
    [[ -f /etc/docker/daemon.json ]] || echo '{}' | sudo tee /etc/docker/daemon.json >/dev/null

    sudo jq --argjson m "$mirrors" '.["registry-mirrors"] = $m' /etc/docker/daemon.json >"$tmp" &&
        sudo mv "$tmp" /etc/docker/daemon.json
    sudo systemctl restart docker
    log_ok "镜像加速已切换并重启 Docker！"
}

check_mirror() {
    if [[ -f /etc/docker/daemon.json ]]; then
        sudo cat /etc/docker/daemon.json | jq .
    else
        log_warn "daemon.json 不存在！"
    fi

    log_info "Docker 实际使用的镜像列表："
    sudo docker info --format '{{json .RegistryConfig.Mirrors}}' | jq .

    log_info "可执行 ${gl_huang}docker pull nginx${gl_bai} 实测速度"
}

###### 安装docker-compose
install_docker_compose() {
    # 默认下载地址
    # local DEFAULT_URL="https://github.com/docker/compose/releases/download/v5.1.0/docker-compose-linux-x86_64"
    local DEFAULT_URL="https://sh.meimolihan.eu.org/compose/download/v5.1.0/docker-compose-linux-x86_64"

    clear
    echo -e "${gl_zi}>>> Docker Compose 安装${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 1. 检查并清理旧版本
    log_info "检查已安装的 Docker Compose ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    local OLD_VERSION_FOUND=false

    # 检查是否存在旧版本
    if command -v docker-compose &>/dev/null || [ -f /usr/bin/docker-compose ] || [ -f /usr/local/bin/docker-compose ]; then
        OLD_VERSION_FOUND=true
        log_warn "检测到已安装的 Docker Compose"

        # 显示当前版本信息
        if command -v docker-compose &>/dev/null; then
            log_info "当前版本信息:"
            docker-compose --version
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 询问是否清理旧版本
        read -r -e -p "$(echo -e "${gl_bai}是否先清理旧版本? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_clean
        [ "$confirm_clean" = "0" ] && { cancel_return "上一级选单"; return 1; }   # break 或 continue 或 return ，视上下文而定
        [ -z "$confirm_clean" ] && { cancel_empty "上一级选单"; return 1; }        # break 或 continue 或 return ，视上下文而定
        if [[ "$confirm_clean" =~ ^[Yy]$ ]]; then
            log_info "正在清理旧版本 Docker Compose ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            # 清理各种可能的位置
            local files_to_remove=(
                "/usr/bin/docker-compose"
                "/usr/local/bin/docker-compose"
                "/usr/local/bin/docker-compose-plugin"
            )

            local removed_count=0
            for file in "${files_to_remove[@]}"; do
                if [ -f "$file" ] || [ -L "$file" ]; then
                    log_info "删除: $file"
                    if sudo rm -f "$file" 2>/dev/null; then
                        ((removed_count++))
                        log_ok "删除成功"
                    else
                        log_error "删除失败，可能需要 sudo 权限"
                    fi
                fi
            done

            # 清理命令缓存
            if command -v docker-compose &>/dev/null; then
                hash -r
                log_info "已清理命令缓存"
            fi

            if [ $removed_count -gt 0 ]; then
                log_ok "已清理 $removed_count 个旧版本文件"
            else
                log_info "未发现可清理的旧版本文件"
            fi
        else
            log_info "跳过清理旧版本"
        fi
    else
        log_ok "未发现 Docker Compose 旧版本"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 2. 设置下载地址
    echo ""
    log_info "官方项目地址: ${gl_lv}https://github.com/docker/compose/releases${gl_bai}"
    log_info "个人内网地址: ${gl_lv}http://10.10.10.251:5000/file/myfile/compose/v5.1.0/docker-compose-linux-x86_64${gl_bai}"
    log_info "默认下载地址: ${gl_lv}$DEFAULT_URL${gl_bai}"
    echo ""

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入 docker-compose 下载地址 (直接回车使用默认地址，${gl_huang}0${gl_bai}返回): ")" custom_url

    # 处理用户输入
    if [ -z "$custom_url" ]; then
        # 用户直接回车，使用默认地址
        local DOWNLOAD_URL="$DEFAULT_URL"
        log_info "使用默认下载地址"
    elif [ "$custom_url" = "0" ]; then
        cancel_return
        return
    else
        # 用户输入了自定义地址
        local DOWNLOAD_URL="$custom_url"
        log_info "使用自定义下载地址"
    fi

    # 3. 开始下载安装
    log_info "正在从 ${gl_lv}$DOWNLOAD_URL ${gl_bai}下载 ${gl_huang}docker-compose ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 创建临时文件路径
    local TEMP_FILE="/tmp/docker-compose-$$"

    if wget -c -O "$TEMP_FILE" "$DOWNLOAD_URL"; then
        # 验证下载的文件是否有效
        if [ ! -s "$TEMP_FILE" ]; then
            log_error "下载的文件为空，可能URL无效"
            rm -f "$TEMP_FILE"
            exit_animation    # 即将退出动画
            return 1
        fi

        # 检查是否为二进制文件
        if file "$TEMP_FILE" | grep -q "text"; then
            log_warn "下载的文件可能是文本文件而不是二进制文件"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            head -n 5 "$TEMP_FILE"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            read -r -e -p "$(echo -e "${gl_bai}文件可能不是正确的二进制文件，是否继续安装? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" continue_install

            [ "$continue_install" = "0" ] && { cancel_return "上一级选单"; return 1; }   # break 或 continue 或 return ，视上下文而定
            [ -z "$continue_install" ] && { cancel_empty "上一级选单"; return 1; }        # break 或 continue 或 return ，视上下文而定

            if [[ ! "$continue_install" =~ ^[Yy]$ ]]; then
                log_info "安装已取消"
                rm -f "$TEMP_FILE"
                exit_animation    # 即将退出动画
                return
            fi
        fi

        # 移动文件到系统目录
        log_info "安装 ${gl_huang}docker-compose ${gl_bai}到 ${gl_lv}/usr/bin/docker-compose${gl_bai}"
        if sudo mv "$TEMP_FILE" /usr/bin/docker-compose; then
            sudo chmod 755 /usr/bin/docker-compose

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_ok "安装完成，版本信息："

            # 验证安装
            if docker-compose --version; then
                log_ok "Docker Compose 安装成功"
            else
                log_error "Docker Compose 版本检测失败"
                exit_animation    # 即将退出动画
                return 1
            fi
        else
            log_error "移动文件失败，可能需要 sudo 权限"
            rm -f "$TEMP_FILE"
            exit_animation    # 即将退出动画
            return 1
        fi
    else
        log_error "下载失败，请检查网络连接或URL地址"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 4. 验证安装结果
    if command -v docker-compose &>/dev/null; then
        log_ok "Docker Compose 已成功安装到系统 PATH 中"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 卸载docker-compose
uninstall_docker_compose() {
    clear
    echo -e "${gl_zi}>>> Docker Compose 卸载${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 1. 检查是否已安装
    log_info "正在检查已安装的 Docker Compose ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    local FOUND_FILES=()
    local VERSION_INFO=""
    local INSTALLED=false

    # 先记录当前版本信息（用于最后对比）
    local OLD_VERSION=""
    if command -v docker-compose &>/dev/null; then
        OLD_VERSION=$(docker-compose --version 2>/dev/null)
    elif docker compose version &>/dev/null 2>&1; then
        OLD_VERSION=$(docker compose version 2>&1 | head -n 1)
    fi

    # 检查各种可能的安装位置
    if command -v docker-compose &>/dev/null; then
        VERSION_INFO=$(docker-compose --version 2>/dev/null)
        INSTALLED=true
        log_ok "在系统 PATH 中找到: $(which docker-compose)"
    fi

    # 检查常用安装路径
    local CHECK_PATHS=(
        "/usr/bin/docker-compose"
        "/usr/local/bin/docker-compose"
        "/usr/local/bin/docker-compose-plugin"
        "/bin/docker-compose"
        "/usr/sbin/docker-compose"
    )

    for path in "${CHECK_PATHS[@]}"; do
        if [ -f "$path" ] || [ -L "$path" ]; then
            FOUND_FILES+=("$path")
            log_info "发现文件: $path"
            if [ -z "$VERSION_INFO" ]; then
                VERSION_INFO=$("$path" --version 2>/dev/null)
            fi
            INSTALLED=true
        fi
    done

    # 检查 Docker Compose 插件位置（新版本）
    local PLUGIN_PATHS=(
        "/usr/libexec/docker/cli-plugins/docker-compose"
        "/usr/local/libexec/docker/cli-plugins/docker-compose"
        "/usr/local/lib/docker/cli-plugins/docker-compose"
        "/usr/lib/docker/cli-plugins/docker-compose"
        "$HOME/.docker/cli-plugins/docker-compose"
        "/root/.docker/cli-plugins/docker-compose"
    )

    for path in "${PLUGIN_PATHS[@]}"; do
        if [ -f "$path" ] || [ -L "$path" ]; then
            FOUND_FILES+=("$path")
            log_info "发现插件: $path"
            INSTALLED=true
        fi
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if [ "$INSTALLED" = false ]; then
        log_warn "未找到 Docker Compose 安装文件"
        read -r -e -p "$(echo -e "${gl_bai}是否继续检查其他位置? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" search_more
        if [[ "$search_more" =~ ^[Yy]$ ]]; then
            log_info "正在全盘搜索 docker-compose 文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            find / -name "*docker-compose*" -type f -executable 2>/dev/null | grep -E "(docker-compose|docker/compose)" | head -20 | while read file; do
                log_info "发现: $file"
                FOUND_FILES+=("$file")
                INSTALLED=true
            done
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        fi
    fi

    if [ "$INSTALLED" = false ]; then
        log_error "系统未安装 Docker Compose"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 2. 显示当前版本信息
    if [ -n "$VERSION_INFO" ]; then
        log_info "当前版本信息:"
        echo -e "${gl_hui}$VERSION_INFO${gl_bai}"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 3. 确认卸载
    if [ ${#FOUND_FILES[@]} -gt 0 ]; then
        log_warn "将删除以下文件:"
        for file in "${FOUND_FILES[@]}"; do
            echo -e "${gl_hui}  $file${gl_bai}"
        done
    fi

    echo ""
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确认要卸载 Docker Compose 吗? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_uninstall
    [ "$confirm_uninstall" = "0" ] && { cancel_return "上一级选单"; return 1; }   # break 或 continue 或 return ，视上下文而定

    if [[ ! "$confirm_uninstall" =~ ^[Yy]$ ]]; then
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_hong}卸载已取消${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 4. 执行卸载
    log_info "正在卸载 Docker Compose ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    local REMOVED_COUNT=0
    local FAILED_FILES=()

    # 删除找到的文件
    for file in "${FOUND_FILES[@]}"; do
        log_info "正在删除: $file"
        if sudo rm -f "$file" 2>/dev/null; then
            ((REMOVED_COUNT++))
            log_ok "删除成功"
        else
            log_error "删除失败"
            FAILED_FILES+=("$file")
        fi
    done

    # 清理命令缓存
    hash -r 2>/dev/null
    log_info "已清理命令缓存"

    # 清理 Docker 插件缓存
    if command -v docker &>/dev/null; then
        log_info "清理 Docker 插件缓存 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        docker compose version &>/dev/null 2>&1 # 触发插件重新加载
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 5. 显示卸载结果
    if [ $REMOVED_COUNT -gt 0 ]; then
        log_ok "已成功删除 $REMOVED_COUNT 个文件"
    fi

    if [ ${#FAILED_FILES[@]} -gt 0 ]; then
        log_error "以下文件删除失败 (可能需要手动删除):"
        for file in "${FAILED_FILES[@]}"; do
            echo -e "${gl_hui}  $file${gl_bai}"
        done
    fi

    # 6. 验证卸载
    log_info "验证卸载结果:"

    local STILL_INSTALLED=false
    if command -v docker-compose &>/dev/null; then
        log_warn "docker-compose 命令仍然存在"
        STILL_INSTALLED=true
    fi

    if docker compose version &>/dev/null 2>&1; then
        local NEW_VERSION=$(docker compose version 2>&1 | head -n 1)
        if [ -n "$OLD_VERSION" ] && [ "$OLD_VERSION" = "$NEW_VERSION" ]; then
            log_warn "Docker Compose 插件版本未改变: $NEW_VERSION"
            log_warn "可能需要重启 Docker 服务或终端"
        else
            log_ok "Docker Compose 插件已卸载"
        fi
    else
        log_ok "Docker Compose 插件已成功卸载"
    fi

    if [ "$STILL_INSTALLED" = false ]; then
        log_ok "Docker Compose 已成功卸载"
    else
        log_warn "部分组件可能仍然存在，建议:"
        log_info "1. 重新打开终端"
        log_info "2. 重启 Docker 服务: systemctl restart docker"
        log_info "3. 或执行: hash -r && which docker-compose"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 交互子菜单
docker_mirror_menu() {
    local menu_name="${1:-上一级选单}"
    while true; do
        check_and_install_docker || return 1
        clear
        echo -e "${gl_zi}>>> Docker 镜像加速${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}配置KSpeeder镜像加速（${gl_huang}客户端${gl_hong}/${gl_bufan}服务端${gl_bai}）"
        echo -e "${gl_bufan}2.  ${gl_bai}解析到KSpeeder服务器（${gl_huang}客户端${gl_bai}）"
        echo -e "${gl_bufan}3.  ${gl_bai}验证域名解析        （${gl_huang}客户端${gl_bai}）"
        echo -e "${gl_bufan}4.  ${gl_bai}拉取测试镜像        （${gl_huang}客户端${gl_bai}）"
        echo -e "${gl_bufan}5.  ${gl_bai}编辑hosts文件"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}11. ${gl_bai}官方推荐多镜像"
        echo -e "${gl_bufan}12. ${gl_bai}自定义镜像"
        echo -e "${gl_bufan}13. ${gl_bai}延迟测速并选用镜像"
        echo -e "${gl_bufan}14. ${gl_bai}查看当前加速地址"
        echo -e "${gl_bufan}15. ${gl_bai}拉取测试镜像"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}77. ${gl_bai}轩辕镜像加速"
        echo -e "${gl_bufan}88. ${gl_bai}清理无用镜像"
        echo -e "${gl_bufan}99. ${gl_bai}备份${gl_hong}/${gl_bai}还原 daemon.json"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回主菜单"
        echo -e "${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " sel

        case $sel in
        1)
            # 配置KSpeeder镜像加速（服务端/客户端）
            echo -e ""
            echo -e "${gl_zi}>>> 配置KSpeeder镜像加速${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            set_mirrors '["https://registry.linkease.net:5443"]'
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        2)
            # 解析到KSpeeder服务器（客户端）
            echo -e ""
            echo -e "${gl_zi}>>> 解析到KSpeeder服务器${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "请输入KSpeeder服务器 ${gl_huang}IP${gl_bai} [${gl_huang}0${gl_bai}=返回]：")" ip

            [ "$ip" = "0" ] && { cancel_return "Docker 镜像加速"; return 1; }

            if [[ -n "$ip" ]]; then
                line="$ip registry.linkease.net"
                existed=false

                # 检查是否已存在
                echo -e ""
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                if grep -qF "$line" /etc/hosts; then
                    log_info "该记录已存在：${gl_huang}/etc/hosts${gl_bai} 中"
                    existed=true
                else
                    echo "$line" | sudo tee -a /etc/hosts >/dev/null
                    log_ok "成功添加记录：${gl_huang}/etc/hosts${gl_bai} 中"
                fi

                # 打印结果
                if [ "$existed" = true ]; then
                    log_info "已存在的记录：${gl_lv}$line${gl_bai}"
                else
                    log_ok "新添加的记录：${gl_lv}$line${gl_bai}"
                fi
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            else
                log_error "${gl_huang}未输入IP地址${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            fi

            break_end
            ;;
        3)
            # 验证域名解析        （客户端）
            echo -e ""
            echo -e "${gl_zi}>>> 验证域名解析${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            ping -c 5 registry.linkease.net
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        4 | 15)
            # 拉取测试镜像        （客户端）
            echo -e ""
            echo -e "${gl_zi}>>> 拉取测试镜像${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            docker pull hello-world
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        5)
            # 编辑hosts文件
            install nano
            nano /etc/hosts
            break_end
            ;;
        11)
            # 官方推荐多镜像
            echo -e ""
            echo -e "${gl_zi}>>> 官方推荐多镜像${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            set_mirrors '[
                    "https://docker.mirrors.ustc.edu.cn",
                    "https://hub-mirror.c.163.com",
                    "https://mirror.baidubce.com",
                    "https://registry.docker-cn.com",
                    "https://docker.1panel.live",
                    "https://hub.rat.dev"
                ]'
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        12)
            # 自定义镜像
            echo -e ""
            echo -e "${gl_zi}>>> 自定义镜像${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入镜像地址（多个用空格分隔，直接回车或输入 0 取消）: " -a arr
            [[ ${arr[0]} == "0" ]] || [[ -z "$(echo "${arr[*]}" | xargs)" ]] && {
                log_warn "${gl_huang}未输入任何地址，已取消修改${gl_bai}"
                break_end
                continue
            }
            printf -v json '"%s",' "${arr[@]}"
            set_mirrors "[${json%,}]"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        13)
            # 延迟测速并选用镜像
            echo -e ""
            echo -e "${gl_zi}>>> 镜像站延迟测速${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            # 预置常用镜像站
            mapfile -t urls < <(
                printf %s\\n \
                    https://registry.linkeas.net:5443 \
                    https://docker.mirrors.ustc.edu.cn \
                    https://hub-mirror.c.163.com \
                    https://mirror.baidubce.com \
                    https://registry.docker-cn.com \
                    https://docker.1panel.live \
                    https://proxy.1panel.live \
                    https://docker.1panel.top \
                    https://docker.ketches.cn \
                    https://docker.1ms.run \
                    https://docker-0.unsee.tech \
                    https://docker.m.daocloud.io \
                    https://hub.rat.dev
            )

            fastest=""
            min=9999
            for u in "${urls[@]}"; do
                host_port="${u#https://}"
                host="${host_port%:*}"
                [[ $host_port == *:* ]] && port="${host_port##*:}" || port=443

                # 1) TCP 连通性
                if ! timeout 2 bash -c "echo &>/dev/tcp/$host/$port" 2>/dev/null; then
                    t=9999
                else
                    # 2) ICMP RTT（取平均）
                    rtt=$(ping -c1 -W1 "$host" 2>/dev/null | awk -F'/' 'END{print $5}')
                    t=$(printf '%.0f' "${rtt:-9999}" 2>/dev/null || echo 9999)
                fi

                [[ $t -lt $min ]] && {
                    min=$t
                    fastest=$u
                }
                printf '%b%-45s %b%5s ms%b\n' "$gl_hui" "$u" "$gl_bai" "$t"
            done

            [[ $min -ge 9999 ]] && {
                log_error "所有镜像站均不可达！"
                break_end
                continue
            }
            log_ok "最快镜像：${gl_lv}${fastest}${gl_bai} 延迟 ${min}ms"

            read -r -e -p "$(echo -e "${gl_bai}是否直接应用最快镜像？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" yn

            [[ $yn =~ [Yy] ]] && {
                set_mirrors "[\"$fastest\"]"
                break_end
            }
            ;;
        14)
            # 查看当前加速地址
            clear
            echo -e ""
            echo -e "${gl_zi}>>> 查看当前加速地址${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            check_mirror
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        77)
            # 轩辕镜像加速
            echo -e ""
            echo -e "${gl_zi}>>> 轩辕镜像加速${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}轩辕镜像官网：${gl_lv}https://docker.xuanyuan.me/${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -n 1 -s -r -p "$(echo -e "${gl_bai}按任意键执行加速脚本 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c")"
            clear
            bash <(curl -sL xuanyuan.cloud/docker.sh)
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        88)
            # 清理无用镜像
            # 检查 Docker 是否安装
            if ! command -v docker &>/dev/null; then
                echo -e "${gl_huang}检测到系统未安装 Docker${gl_bai}"
                read -r -e -p "$(echo -e "${gl_bufan}是否立即安装 Docker？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" install_docker

                if [ "$install_docker" = "y" ] || [ "$install_docker" = "Y" ]; then
                    echo -e "${gl_huang}正在安装 Docker ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    if bash <(curl -sL kejilion.sh) docker install; then
                        echo -e "${gl_lv}Docker 安装成功！${gl_bai}"
                        # 等待一段时间让 Docker 服务完全启动
                        sleep_fractional 3
                    else
                        echo -e "${gl_hong}Docker 安装失败，请手动安装后重试${gl_bai}"
                        exit_animation    # 即将退出动画
                        return
                    fi
                else
                    echo -e "${gl_huang}已取消安装，返回主菜单${gl_bai}"
                    exit_animation    # 即将退出动画
                    return
                fi
            fi

            # 检查 Docker 服务是否运行
            if ! docker info &>/dev/null; then
                echo -e "${gl_hong}Docker 服务未运行，请先启动 Docker 服务${gl_bai}"
                exit_animation    # 即将退出动画
                return
            fi

            echo -e ""
            echo -e "${gl_zi}>>> 清理镜像容器网络${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_huang}提示: ${gl_bai}将清理无用的镜像容器网络，包括停止的容器，确定清理吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" choice
            case "$choice" in
            [Yy])
                docker system prune -af --volumes
                ;;
            [Nn]) ;;
            *)
                echo -e "${gl_huang}无效的选择，请输入 ${gl_lv}y${gl_bai}或${gl_hong}N${gl_bai}。"
                ;;
            esac
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        99)
            # 备份/还原 daemon.json
            echo -e ""
            echo -e "${gl_zi}>>> 备份/还原 daemon.json${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}1.  ${gl_bai}备份当前 daemon.json"
            echo -e "${gl_bufan}2.  ${gl_bai}还原上次备份"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请选择: " bk_sel
            case $bk_sel in
            1) sudo cp -f /etc/docker/daemon.json /etc/docker/daemon.json.bak &&
                log_ok "已备份到 /etc/docker/daemon.json.bak" ;;
            2) [[ -f /etc/docker/daemon.json.bak ]] &&
                {
                    sudo cp -f /etc/docker/daemon.json.bak /etc/docker/daemon.json
                    sudo systemctl restart docker
                    log_ok "已还原并重启 Docker"
                } ||
                log_warn "备份文件不存在！" ;;
            *) handle_invalid_input ;;
            esac
            break_end
            ;;
        0) cancel_return "$menu_name" ; return ;;   # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;             # 感谢使用，再见！
        *) handle_invalid_input ;;                  # 无效的输入,请重新输入!
        esac
    done
}

# 函数_进入Docker Compose工作目录
enter_compose_dir() {
    check_and_install_docker || return 1
    clear
    echo -e ""
    echo -e "${gl_zi}>>> 进入 Compose 工作目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 获取当前目录
    local current_dir
    current_dir=$(pwd)

    # 预设目录选项
    local preset_dirs=(
        "/compose"
        "/mnt/compose"
        "/vol1/1000/compose"
        "/vol2/1000/compose"
    )

    # 根据IP自动确定默认目录
    local default_dir=""
    case $(get_internal_ip | tr -d '[:space:]') in
    10.10.10.251) default_dir="/vol1/1000/compose" ;;
    10.10.10.16) default_dir="/vol1/1000/compose" ;;
    10.10.10.246) default_dir="/mnt/compose" ;;
    10.10.10.239) default_dir="/mnt/compose" ;;
    10.10.10.238) default_dir="/mnt/compose" ;;
    *) default_dir="/mnt/compose" ;;
    esac

    echo -e "${gl_bai}当前目录: ${gl_lv}$current_dir${gl_bai}"
    echo -e "${gl_bai}根据当前IP自动选择的默认目录: ${gl_huang}$default_dir${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 显示预设目录菜单
    echo -e "${gl_bai}请选择工作目录:${gl_bai}"

    # 选项1: 当前目录
    local marker_current=""
    [[ "$current_dir" == "$default_dir" ]] && marker_current=" ${gl_hong}(推荐)${gl_bai}"
    echo -e "${gl_bufan}1.${gl_bai} ${current_dir}$marker_current"

    # 选项2-5: 预设目录
    for i in "${!preset_dirs[@]}"; do
        local marker=""
        [[ "${preset_dirs[i]}" == "$default_dir" ]] && marker=" ${gl_hong}(推荐)${gl_bai}"
        echo -e "${gl_bufan}$((i + 2)).${gl_bai} ${preset_dirs[i]}$marker"
    done

    # 选项6: 自定义路径
    local custom_option_index=$((${#preset_dirs[@]} + 2))
    echo -e "${gl_bufan}${custom_option_index}.${gl_bai} 自定义路径"

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_huang}0.${gl_bai} 返回上一级选单"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 读取用户选择
    read -r -e -p "$(echo -e "${gl_bai}请输入你的选择 (${gl_huang}0${gl_bai}-${gl_hong}${custom_option_index}${gl_bai})，直接回车使用推荐目录: ")" choice

    # 处理选择
    local COMPOSE_WORK_DIR=""

    if [[ -z "$choice" ]]; then
        # 直接回车，使用推荐目录
        COMPOSE_WORK_DIR="$default_dir"
        echo -e "${gl_bai}使用推荐目录: ${gl_huang}$default_dir${gl_bai}"
    elif [[ "$choice" =~ ^[0-9]+$ ]]; then
        if [[ $choice -eq 0 ]]; then
            # 返回
            cancel_return
            return
        elif [[ $choice -eq 1 ]]; then
            # 当前目录
            COMPOSE_WORK_DIR="$current_dir"
        elif [[ $choice -le $((${#preset_dirs[@]} + 1)) ]]; then
            # 选择预设目录
            COMPOSE_WORK_DIR="${preset_dirs[$((choice - 2))]}"
        elif [[ $choice -eq $custom_option_index ]]; then
            # 自定义路径
            read -r -e -p "$(echo -e "${gl_bai}请输入自定义路径: ")" COMPOSE_WORK_DIR
        else
            echo -e "${gl_hong}无效选择${gl_bai}"
            return
        fi
    else
        # 非数字输入，视为自定义路径
        COMPOSE_WORK_DIR="$choice"
    fi

    # 检查是否为空
    if [[ -z "$COMPOSE_WORK_DIR" ]]; then
        echo -e "${gl_huang}路径不能为空${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 检查目录是否存在
    if [[ ! -d "$COMPOSE_WORK_DIR" ]]; then
        echo -e "${gl_huang}目录不存在: ${gl_hong}$COMPOSE_WORK_DIR${gl_bai}"
        read -r -e -p "$(echo -e "是否创建? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
        if [[ "$confirm" =~ ^[Yy]$ ]]; then
            mkdir -p "$COMPOSE_WORK_DIR"
            if [[ $? -eq 0 ]]; then
                echo -e "${gl_lv}✓ 已创建目录: $COMPOSE_WORK_DIR${gl_bai}"
            else
                echo -e "${gl_hong}✗ 创建目录失败${gl_bai}"
                exit_animation    # 即将退出动画
                return
            fi
        else
            echo -e "${gl_huang}已取消${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi
    fi

    # 进入目录并显示菜单
    echo -e "${gl_bai}进入目录: ${gl_huang}$COMPOSE_WORK_DIR${gl_bai}"
    if cd "$COMPOSE_WORK_DIR" 2>/dev/null; then
        echo -e "${gl_lv}✓ 进入目录成功${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        # 延迟一下，让用户看到进入成功的消息
        sleep_fractional 0.5
        show_compose_project_menu
    else
        echo -e "${gl_hong}✗ 进入目录失败: $COMPOSE_WORK_DIR${gl_bai}"
    fi
}

###### 备份/迁移/还原 docker-compose 项目
docker_compose_env_tools() {

    # --------------- 列出备份 ---------------
    list_backups() {
        local BACKUP_ROOT="/mnt/backup_compose"
        mkdir -p "$BACKUP_ROOT"
        chmod 755 "$BACKUP_ROOT"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "当前备份列表："
        shopt -s nullglob
        local list
        list=("${BACKUP_ROOT}"/compose_backup_*)
        shopt -u nullglob
        ((${#list[@]})) && ls -1d "${list[@]}" || echo -e "${gl_huang}暂无备份${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    }

    # --------------- 备份 Compose 环境 ---------------
    backup_compose_env() {
        echo -e ""
        echo -e "${gl_zi}安装依赖中 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        install tar jq gzip sshpass
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        clear
        echo -e "${gl_zi}>>> 备份 ${gl_huang}Compose${gl_zi} 环境 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 扫描所有运行中的 docker-compose 项目
        log_info "正在扫描所有 docker-compose 项目 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        mapfile -t PROJECT_DIRS < <(
            docker ps --format '{{.Names}}' 2>/dev/null |
                xargs -I{} docker inspect {} 2>/dev/null |
                jq -r '.[0].Config.Labels["com.docker.compose.project.working_dir"]' 2>/dev/null |
                sort -u
        )

        # 预设目录选项
        local preset_dirs=(
            "/compose"
            "/mnt/compose"
            "/vol1/1000/compose"
            "/vol2/1000/compose"
        )

        # 显示扫描到的项目
        if [[ ${#PROJECT_DIRS[@]} -gt 0 ]]; then
            log_info "${gl_bai}扫描到以下运行中的 docker-compose 项目:${gl_bai}"
            for dir in "${PROJECT_DIRS[@]}"; do
                [[ -z "$dir" ]] && continue
                echo -e "${gl_lv}  •${gl_bai} ${dir}"
            done

            # 标记推荐的目录
            local recommended_dirs=()
            for preset_dir in "${preset_dirs[@]}"; do
                for project_dir in "${PROJECT_DIRS[@]}"; do
                    [[ -z "$project_dir" ]] && continue
                    if [[ "$project_dir" == "$preset_dir" ]] || [[ "$project_dir" == "$preset_dir"/* ]]; then
                        recommended_dirs+=("$preset_dir")
                        break
                    fi
                done
            done

            # 去重
            recommended_dirs=($(printf "%s\n" "${recommended_dirs[@]}" | sort -u))
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 显示目录选择菜单
        echo -e ""
        echo -e "${gl_huang}>>> 请选择要备份的 Compose 工作目录:${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        for i in "${!preset_dirs[@]}"; do
            local marker=""
            local dir_status=""

            # 检查是否为推荐目录
            if [[ -v recommended_dirs ]]; then
                for rd in "${recommended_dirs[@]}"; do
                    if [[ "${preset_dirs[i]}" == "$rd" ]]; then
                        marker=" ${gl_hong}(推荐)${gl_bai}"
                        break
                    fi
                done
            fi

            # 检查目录是否存在
            if [[ -d "${preset_dirs[i]}" ]]; then
                # 检查目录下是否有 docker-compose 文件
                local compose_count=$(find "${preset_dirs[i]}" -maxdepth 2 -type f \( -name "docker-compose.yml" -o -name "docker-compose.yaml" \) 2>/dev/null | wc -l)
                if [[ $compose_count -gt 0 ]]; then
                    dir_status="${gl_lv}[有 ${compose_count} 个项目]${gl_bai}"
                else
                    dir_status="${gl_huang}[无 compose 项目]${gl_bai}"
                fi
            else
                dir_status="${gl_huang}[目录不存在]${gl_bai}"
            fi

            echo -e "${gl_bufan}$((i + 1)).${gl_bai} ${preset_dirs[i]} $dir_status$marker"
        done
        echo -e "${gl_bufan}$((${#preset_dirs[@]} + 1)).${gl_bai} 手动指定路径"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.${gl_bai} 返回上一级选单"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 读取用户选择
        read -r -e -p "$(echo -e "${gl_bai}请输入你的选择 (${gl_huang}0${gl_bai}-${gl_hong}$((${#preset_dirs[@]} + 1))${gl_bai}): ")" dir_choice

        # 处理选择
        local COMPOSE_WORK_DIR=""

        if [[ -z "$dir_choice" ]] && [[ -v recommended_dirs ]] && [[ ${#recommended_dirs[@]} -gt 0 ]]; then
            # 直接回车，使用第一个推荐目录
            COMPOSE_WORK_DIR="${recommended_dirs[0]}"
            echo -e "${gl_bai}使用推荐目录: ${gl_huang}$COMPOSE_WORK_DIR${gl_bai}"
        elif [[ "$dir_choice" =~ ^[0-9]+$ ]]; then
            if [[ $dir_choice -eq 0 ]]; then
                # 返回
                return
            elif [[ $dir_choice -le ${#preset_dirs[@]} ]]; then
                # 选择预设目录
                COMPOSE_WORK_DIR="${preset_dirs[$((dir_choice - 1))]}"
            elif [[ $dir_choice -eq $((${#preset_dirs[@]} + 1)) ]]; then
                # 手动指定路径
                read -r -e -p "$(echo -e "${gl_bai}请输入自定义路径: ")" COMPOSE_WORK_DIR
            else
                log_error "无效选择"
                exit_animation    # 即将退出动画
                return
            fi
        else
            # 非数字输入，视为手动指定路径
            COMPOSE_WORK_DIR="$dir_choice"
        fi

        # 检查是否为空
        if [[ -z "$COMPOSE_WORK_DIR" ]]; then
            log_warn "路径不能为空"
            exit_animation    # 即将退出动画
            return
        fi

        # 检查目录是否存在
        if [[ ! -d "$COMPOSE_WORK_DIR" ]]; then
            log_warn "目录不存在: $COMPOSE_WORK_DIR"
            read -r -e -p "$(echo -e "是否创建? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
            if [[ "$confirm" =~ ^[Yy]$ ]]; then
                mkdir -p "$COMPOSE_WORK_DIR"
                if [[ $? -eq 0 ]]; then
                    log_ok "已创建目录: $COMPOSE_WORK_DIR"
                else
                    log_error "创建目录失败"
                    exit_animation    # 即将退出动画
                    return
                fi
            else
                log_warn "已取消"
                exit_animation    # 即将退出动画
                return
            fi
        fi

        # 进入工作目录
        echo -e "${gl_bai}工作目录: ${gl_huang}$COMPOSE_WORK_DIR${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 扫描指定目录下的 docker-compose 项目
        log_info "正在扫描 ${gl_huang}$COMPOSE_WORK_DIR${gl_bai} 下的 docker-compose 项目 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 收集项目目录
        local found_projects=()

        # 先检查根目录是否有 docker-compose 文件
        if [[ -f "$COMPOSE_WORK_DIR/docker-compose.yml" ]] || [[ -f "$COMPOSE_WORK_DIR/docker-compose.yaml" ]]; then
            found_projects+=("$(basename "$COMPOSE_WORK_DIR")")
            log_info "${gl_bai}发现 Compose 项目:${gl_huang} $(basename "$COMPOSE_WORK_DIR")${gl_bai} (根目录)"
        fi

        # 扫描子目录
        while IFS= read -r dir; do
            if [[ -f "$dir/docker-compose.yml" ]] || [[ -f "$dir/docker-compose.yaml" ]]; then
                local rel_path=$(realpath --relative-to="$COMPOSE_WORK_DIR" "$dir")
                found_projects+=("$rel_path")
                log_info "${gl_bai}发现 Compose 项目:${gl_huang} $(basename "$dir")${gl_bai}"
            fi
        done < <(find "$COMPOSE_WORK_DIR" -maxdepth 2 -type d 2>/dev/null)

        local project_count=${#found_projects[@]}

        if [[ $project_count -eq 0 ]]; then
            log_warn "在 ${COMPOSE_WORK_DIR} 中未找到任何 docker-compose 项目"
            exit_animation    # 即将退出动画
            return
        fi

        log_info "${gl_bai}在 ${gl_huang}${COMPOSE_WORK_DIR}${gl_bai} 中找到 ${gl_huang}${project_count}${gl_bai} 个 Compose 项目"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 创建备份目录
        local BACKUP_ROOT="/mnt/backup_compose"
        local DATE_STR=$(date +%Y%m%d_%H%M%S)
        local BACKUP_DIR="${BACKUP_ROOT}/compose_backup_${DATE_STR}"
        mkdir -p "$BACKUP_DIR"

        # 创建还原脚本
        local RESTORE_SCRIPT="${BACKUP_DIR}/restore_compose.sh"
        cat >"$RESTORE_SCRIPT" <<'EOF'
#!/bin/bash
set -e

# 默认工作目录
WORKDIR="/compose"

gl_bai='\033[0m'    # 定义重置终端颜色的ANSI转义序列（恢复默认样式）
gl_bufan='\033[96m' # 定义亮青色（或浅蓝）字体的ANSI转义序列
gl_lv='\033[32m'    # 定义绿色字体的ANSI转义序列
gl_huang='\033[33m' # 定义黄色字体的ANSI转义序列

# 检查是否传入参数
if [ $# -ge 1 ]; then
    WORKDIR="$1"
    echo -e "${gl_bai}使用自定义工作目录: ${gl_lv}$WORKDIR${gl_bai}"
else
    echo -e "${gl_bai}使用默认工作目录: ${gl_lv}$WORKDIR${gl_bai}"
fi

BACKUP_DIR="$(cd "$(dirname "$0")"; pwd)"
mkdir -p "$WORKDIR"
echo -e "${gl_bai}备份目录: ${gl_lv}$BACKUP_DIR${gl_bai}"
echo -e "${gl_bai}工作目录: ${gl_huang}$WORKDIR${gl_bai}"
EOF

        # 备份每个项目
        for project_rel_path in "${found_projects[@]}"; do
            local project_name=$(basename "$project_rel_path")
            if [[ "$project_name" == "." ]]; then
                project_name=$(basename "$COMPOSE_WORK_DIR")
            fi

            log_info "${gl_bai}备份 Compose 项目:${gl_huang} $project_name${gl_bai}"

            # 计算完整路径
            local project_full_path="$COMPOSE_WORK_DIR/$project_rel_path"
            if [[ "$project_rel_path" == "$(basename "$COMPOSE_WORK_DIR")" ]]; then
                project_full_path="$COMPOSE_WORK_DIR"
            fi

            # 备份项目
            (cd "$COMPOSE_WORK_DIR" && tar -czf "${BACKUP_DIR}/${project_name}.tar.gz" "$project_rel_path" 2>/dev/null)

            # 添加到还原脚本
            cat >>"$RESTORE_SCRIPT" <<EOF

echo -e "${gl_bai}正在还原项目: ${gl_huang}$project_name${gl_bai}"
tar -xzf "\$BACKUP_DIR/${project_name}.tar.gz" -C "\$WORKDIR"
if [[ -f "\$WORKDIR/$project_rel_path/docker-compose.yml" ]] || [[ -f "\$WORKDIR/$project_rel_path/docker-compose.yaml" ]]; then
    (cd "\$WORKDIR/$project_rel_path" && docker compose down 2>/dev/null || true && docker compose up -d)
    echo -e "${gl_bai}项目 ${gl_huang}$project_name ${gl_lv}还原并启动完成${gl_bai}"
else
    echo -e "${gl_huang}警告: \$WORKDIR/$project_rel_path/docker-compose.yml 不存在，跳过启动${gl_bai}"
fi
EOF
        done

        cat >>"$RESTORE_SCRIPT" <<'EOF'

echo ""
echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
echo -e "${gl_bai}所有 Compose 项目已成功还原到: ${gl_huang}$WORKDIR${gl_bai}"
echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
EOF

        chmod +x "$RESTORE_SCRIPT"

        # 创建备份信息文件
        cat >"${BACKUP_DIR}/backup_info.txt" <<EOF
备份时间: $(date '+%Y-%m-%d %H:%M:%S')
工作目录: ${COMPOSE_WORK_DIR}
备份目录: ${BACKUP_DIR}
项目数量: ${project_count}
项目列表:
EOF

        for i in "${!found_projects[@]}"; do
            local proj_name=$(basename "${found_projects[i]}")
            if [[ "$proj_name" == "." ]]; then
                proj_name=$(basename "$COMPOSE_WORK_DIR")
            fi
            echo "$((i + 1)). ${proj_name}: ${found_projects[i]}" >>"${BACKUP_DIR}/backup_info.txt"
        done

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_ok "${gl_bai}备份完成: ${gl_lv}$BACKUP_DIR${gl_bai}"
        log_ok "${gl_bai}备份信息: ${gl_huang}$BACKUP_DIR/backup_info.txt${gl_bai}"
        log_ok "${gl_bai}还原脚本: ${gl_lan}$RESTORE_SCRIPT${gl_bai}"
        log_info "${gl_bai}使用说明: ${gl_huang}$RESTORE_SCRIPT [工作目录]${gl_bai}"
        log_info "${gl_bai}示例: ${gl_huang}$RESTORE_SCRIPT $COMPOSE_WORK_DIR${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # --------------- 还原 Compose 环境 ---------------
    restore_compose_env() {
        echo -e ""
        echo -e "${gl_zi}安装依赖中 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        install tar jq gzip sshpass
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        clear
        echo -e "${gl_zi}>>> 还原 ${gl_huang}Compose${gl_zi} 环境 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 获取备份根目录
        local BACKUP_ROOT="/mnt/backup_compose"
        mkdir -pm 755 "$BACKUP_ROOT"

        # 查找最新的备份目录
        local latest_backup=""
        shopt -s nullglob
        local backups=(${BACKUP_ROOT}/compose_backup_*)
        shopt -u nullglob

        # 获取最新的备份目录（完整路径和名称）
        local latest_backup_name=""
        if ((${#backups[@]} > 0)); then
            # 按时间倒序排序，获取最新的备份
            latest_backup=$(printf '%s\n' "${backups[@]}" | sort -r | head -n1)
            latest_backup_name=$(basename "$latest_backup")
        fi

        log_info "${gl_bai}可用备份列表："
        if ((${#backups[@]} > 0)); then
            for i in "${!backups[@]}"; do
                echo -e "${gl_huang}$((i + 1)).${gl_bai} ${backups[i]}"
            done
        else
            log_warn "无备份"
        fi

        # 显示可用的备份（使用绝对路径）
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        # 显示最新备份（使用绝对路径）
        if [[ -n "$latest_backup" ]]; then
            log_info "${gl_bai}最新备份: ${gl_lv}$latest_backup${gl_bai}"
        fi
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 提示用户输入，支持回车默认最新备份
        if [[ -n "$latest_backup_name" ]]; then
            read -r -e -p "$(echo -e "${gl_bai}请输入备份目录路径 (回车使用最新备份: ${gl_lv}$latest_backup_name${gl_bai}): ")" BACKUP_DIR

            if [[ -z "$BACKUP_DIR" ]]; then
                BACKUP_DIR="$latest_backup"
                log_info "${gl_bai}使用默认最新备份: ${gl_lv}$latest_backup${gl_bai}"
            fi
        else
            read -r -e -p "$(echo -e "${gl_bai}请输入备份目录路径: ")" BACKUP_DIR
        fi

        # 处理用户输入的数字选择
        if [[ "$BACKUP_DIR" =~ ^[0-9]+$ ]] && [[ $BACKUP_DIR -ge 1 ]] && [[ $BACKUP_DIR -le ${#backups[@]} ]]; then
            BACKUP_DIR="${backups[$((BACKUP_DIR - 1))]}"
            log_info "${gl_bai}选择备份: ${gl_huang}$BACKUP_DIR${gl_bai}"
        fi

        # 如果用户只输入了目录名，没有路径，则加上备份根目录路径
        if [[ -n "$BACKUP_DIR" ]] && [[ ! "$BACKUP_DIR" =~ ^/ ]] && [[ ! "$BACKUP_DIR" =~ ^[0-9]+$ ]]; then
            # 尝试在备份根目录下查找
            local full_path="$BACKUP_ROOT/$BACKUP_DIR"
            if [[ -d "$full_path" ]]; then
                BACKUP_DIR="$full_path"
            fi
        fi

        # 验证备份目录
        [[ ! -d "$BACKUP_DIR" ]] && {
            log_error "${gl_hong}备份目录不存在: ${gl_huang}$BACKUP_DIR${gl_bai}"
            exit_animation    # 即将退出动画
            return
        }

        local RESTORE_SCRIPT="$BACKUP_DIR/restore_compose.sh"
        if [[ -f "$RESTORE_SCRIPT" ]]; then
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_info "找到自动还原脚本"
            log_info "${gl_bai}默认工作目录: ${gl_huang}/compose${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}请输入还原工作目录 (回车使用默认: ${gl_huang}/compose${gl_bai}): ")" workdir_input
            workdir_input=${workdir_input:-/compose}

            log_info "${gl_bai}正在执行还原脚本，工作目录: ${gl_huang}$workdir_input ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            bash "$RESTORE_SCRIPT" "$workdir_input"
            log_ok "所有 Compose 项目已还原并启动"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            return
        fi

        log_info "未找到自动脚本，进入手动解压模式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        for tar in "$BACKUP_DIR"/*.tar.gz; do
            [[ ! -f "$tar" ]] && continue
            [[ "$(basename "$tar")" == .*.tar.gz ]] && continue
            local project_name=$(basename "$tar" .tar.gz)
            [[ -z "$project_name" ]] && continue
            local target_dir="/compose/$project_name"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}还原 ${gl_huang}$project_name ${gl_bai}到目录 [${gl_lv}$target_dir${gl_bai}] (回车确认，或输入新路径): ")" new_dir
            [[ -n "$new_dir" ]] && target_dir="$new_dir"
            mkdir -p "$target_dir"
            tar -xzf "$tar" -C "$target_dir" --strip-components=1
            cd "$target_dir" || continue
            docker compose down 2>/dev/null || true
            docker compose up -d
            log_ok "项目 $project_name 已还原并启动"
        done
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # --------------- 迁移 Compose 环境 ---------------
    migrate_compose_env() {
        echo -e ""
        echo -e "${gl_zi}安装依赖中 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        install tar jq gzip sshpass
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        clear
        echo -e "${gl_zi}>>> 迁移 ${gl_huang}Compose${gl_zi} 环境 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 获取备份根目录
        local BACKUP_ROOT="/mnt/backup_compose"
        mkdir -pm 755 "$BACKUP_ROOT"

        # 查找最新的备份目录
        local latest_backup=""
        shopt -s nullglob
        local backups=("${BACKUP_ROOT}"/compose_backup_*)
        shopt -u nullglob

        # 获取最新的备份目录
        local latest_backup_name=""
        if ((${#backups[@]} > 0)); then
            latest_backup=$(printf '%s\n' "${backups[@]}" | sort -r | head -n1)
            latest_backup_name=$(basename "$latest_backup")
        fi

        log_info "可用备份列表："
        if ((${#backups[@]} > 0)); then
            for i in "${!backups[@]}"; do
                echo -e "${gl_huang}$((i + 1)).${gl_bai} ${backups[i]}"
            done
        else
            log_warn "无备份"
            exit_animation    # 即将退出动画
            return 1
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        # 显示备份信息
        if [[ -n "$latest_backup" ]]; then
            log_info "${gl_bai}最新备份: ${gl_huang}$latest_backup${gl_bai}"
        fi
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 备份目录选择逻辑
        local BACKUP_DIR=""
        if [[ -n "$latest_backup_name" ]]; then
            read -r -e -p "$(echo -e "${gl_bai}请输入备份目录路径 (回车使用最新备份: ${gl_huang}$latest_backup_name${gl_bai})(${gl_huang}0${gl_bai}返回): ")" BACKUP_DIR

            # 修复：直接回车应该使用最新备份，而不是返回
            if [[ -z "$BACKUP_DIR" ]]; then
                BACKUP_DIR="$latest_backup"
                log_info "${gl_bai}使用最新备份: ${gl_lv}$latest_backup${gl_bai}"
            elif [[ "$BACKUP_DIR" == "0" ]]; then
                cancel_return
                return
            fi
        else
            read -r -e -p "$(echo -e "${gl_bai}请输入备份目录路径: ")" BACKUP_DIR
        fi

        # 处理数字选择
        if [[ "$BACKUP_DIR" =~ ^[0-9]+$ ]] && [[ $BACKUP_DIR -ge 1 ]] && [[ $BACKUP_DIR -le ${#backups[@]} ]]; then
            BACKUP_DIR="${backups[$((BACKUP_DIR - 1))]}"
            log_info "${gl_bai}选择备份: ${gl_lv}$BACKUP_DIR${gl_bai}"
        fi

        # 处理相对路径
        if [[ -n "$BACKUP_DIR" ]] && [[ ! "$BACKUP_DIR" =~ ^/ ]] && [[ ! "$BACKUP_DIR" =~ ^[0-9]+$ ]]; then
            local full_path="$BACKUP_ROOT/$BACKUP_DIR"
            if [[ -d "$full_path" ]]; then
                BACKUP_DIR="$full_path"
            fi
        fi

        # 验证备份目录
        [[ ! -d "$BACKUP_DIR" ]] && {
            log_error "${gl_bai}备份目录不存在: ${gl_hong}$BACKUP_DIR${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        }

        # 目标服务器信息收集
        read -r -e -p "$(echo -e "${gl_bai}目标服务器 IP: ")" TARGET_IP
        [[ -z "$TARGET_IP" ]] && {
            log_error "目标服务器 IP 不能为空"
            exit_animation    # 即将退出动画
            return 1
        }

        read -r -e -p "$(echo -e "${gl_bai}目标服务器 SSH 用户名 [默认 ${gl_huang}root${gl_bai}]: ")" TARGET_USER
        TARGET_USER=${TARGET_USER:-root}

        read -r -e -p "$(echo -e "${gl_bai}目标服务器 SSH 端口 [默认 ${gl_huang}22${gl_bai}]: ")" TARGET_PORT
        TARGET_PORT=${TARGET_PORT:-22}

        # 密码读取
        read -s -p "$(echo -e "${gl_bai}目标服务器 ${gl_huang}${TARGET_USER} ${gl_bai}密码: ")" SSHPASS
        echo
        export SSHPASS

        # 目标服务器验证
        log_info "验证目标服务器连接性 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 测试连接
        if ! sshpass -e ssh -p "$TARGET_PORT" -o StrictHostKeyChecking=no -o ConnectTimeout=10 \
            "${TARGET_USER}@${TARGET_IP}" "whoami" &>/dev/null; then
            log_error "无法连接到目标服务器或认证失败"
            exit_animation    # 即将退出动画
            return 1
        fi

        # 固定目标备份目录为 /mnt/backup_compose
        local target_backup_dir="/mnt/backup_compose"

        # 传输备份
        log_info "开始传输备份到目标服务器 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 创建目标目录
        if ! sshpass -e ssh -p "$TARGET_PORT" -o StrictHostKeyChecking=no \
            "${TARGET_USER}@${TARGET_IP}" "mkdir -p '$target_backup_dir'" 2>/dev/null; then
            log_error "无法在目标服务器创建目录: $target_backup_dir"
            exit_animation    # 即将退出动画
            return 1
        fi

        # 传输文件
        local backup_base_name=$(basename "$BACKUP_DIR")
        if sshpass -e scp -o StrictHostKeyChecking=no -P "$TARGET_PORT" -r \
            "$BACKUP_DIR" "${TARGET_USER}@${TARGET_IP}:${target_backup_dir}/" 2>/dev/null; then
            log_ok "备份传输完成"
        else
            # 如果 SCP 失败，尝试 tar 流传输
            log_info "SCP 传输失败，尝试备用传输方式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            if sshpass -e ssh -p "$TARGET_PORT" -o StrictHostKeyChecking=no \
                "${TARGET_USER}@${TARGET_IP}" "mkdir -p '${target_backup_dir}/${backup_base_name}'" &&
                tar -czf - -C "$(dirname "$BACKUP_DIR")" "$backup_base_name" |
                sshpass -e ssh -p "$TARGET_PORT" -o StrictHostKeyChecking=no \
                    "${TARGET_USER}@${TARGET_IP}" "tar -xzf - -C '${target_backup_dir}'"; then
                log_ok "备用传输方式完成"
            else
                log_error "所有传输方式均失败"
                exit_animation    # 即将退出动画
                return 1
            fi
        fi

        # 验证传输结果
        if sshpass -e ssh -p "$TARGET_PORT" -o StrictHostKeyChecking=no \
            "${TARGET_USER}@${TARGET_IP}" "test -d '${target_backup_dir}/${backup_base_name}'" 2>/dev/null; then
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_ok "迁移完成！"
            log_info "备份已保存到目标服务器: ${target_backup_dir}/${backup_base_name}"
            log_info "在目标服务器上执行以下命令进行还原:"
            echo -e "${gl_huang}cd '${target_backup_dir}/${backup_base_name}' && ./restore_compose.sh${gl_bai}"
            log_info "可选指定工作目录:"
            echo -e "${gl_huang}cd '${target_backup_dir}/${backup_base_name}' && ./restore_compose.sh /your/workdir${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
        else
            log_error "传输验证失败，备份可能不完整"
            exit_animation    # 即将退出动画
            return 1
        fi
    }

    # --------------- 删除备份 ---------------
    delete_compose_backup() {
        local BACKUP_ROOT="/mnt/backup_compose"

        echo -e ""
        echo -e "${gl_zi}>>> 删除备份 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入要删除的备份目录路径 (${gl_hong}回车${gl_bai}删除全部): ")" BACKUP_DIR

        # 回车 = 删除全部
        if [[ -z "$BACKUP_DIR" ]]; then
            read -r -e -p "$(echo -e "即将删除 ${gl_huang}${BACKUP_ROOT}${gl_bai} 下所有备份，确认吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" sure

            [[ "$sure" != "y" && "$sure" != "Y" ]] && {
                echo -e "${gl_hong}已取消${gl_bai}"
                exit_animation    # 即将退出动画
                return
            }
            rm -rf "${BACKUP_ROOT}"/compose_backup_*
            log_ok "已清空所有备份"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            return
        fi

        # 指定路径删除
        [[ ! -d "$BACKUP_DIR" ]] && {
            log_error "备份目录不存在"
            return
        }
        read -r -e -p "$(echo -e "确认删除 $BACKUP_DIR ？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" sure

        [[ "$sure" != "y" && "$sure" != "Y" ]] && {
            echo -e "${gl_hong}已取消${gl_bai}"
            exit_animation    # 即将退出动画
            return
        }
        rm -rf "$BACKUP_DIR"
        log_ok "${gl_bai}已删除备份: ${gl_huang}$BACKUP_DIR${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # 管理 Compose 容器
    manage_compose_containers() {
        # 检查 Docker 是否安装
        if ! command -v docker &>/dev/null; then
            echo -e ""
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}Docker状态：${gl_hong}未安装${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            while true; do
                read -r -e -p "$(echo -e "${gl_bai}确定安装 ${gl_huang}Docker${gl_bai} 吗？ (${gl_lv}Y${gl_bai}/${gl_hong}n${gl_bai}): ")" docker_choice

                case "${docker_choice,,}" in # 转换为小写进行比较
                y | yes)
                    echo -e ""
                    if install_add_docker; then # 调用安装函数并检查结果
                        echo -e "${gl_lv}Docker安装成功！${gl_bai}"
                        break # 安装成功，跳出循环继续执行
                    else
                        echo -e "${gl_hong}Docker安装失败，请检查！${gl_bai}"
                        exit_animation    # 即将退出动画
                        return 1 # 或者 exit 1，取决于您的脚本结构
                    fi
                    ;;
                n | no | "")
                    echo -e "${gl_hong}已取消安装Docker，退出 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    exit_animation    # 即将退出动画
                    return 1 # 或者 exit 1，取决于您的脚本结构
                    ;;
                *)
                    echo -e "${gl_hong}输入错误，请重新输入！${gl_bai}"
                    ;;
                esac
            done
        fi

        # 检查 Docker 服务是否运行
        if ! docker info &>/dev/null; then
            echo -e "${gl_hong}Docker${gl_bai} 服务未运行，请先启动 ${gl_hong}Docker${gl_bai} 服务${gl_bai}"
            read -n 1 -s -r -p "$(echo -e "按任意键返回主菜单 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
            echo
            return 1
        fi

        enter_compose_dir
    }

    # --------------- 主菜单 ---------------
    main_menu() {
        while true; do
            clear
            echo -e "${gl_zi}>>> Docker Compose 环境备份/迁移/还原工具${gl_bai}"
            list_backups
            echo -e "${gl_bufan}1.  ${gl_bai}备份 Compose 环境"
            echo -e "${gl_bufan}2.  ${gl_bai}迁移 Compose 环境"
            echo -e "${gl_bufan}3.  ${gl_bai}还原 Compose 环境"
            echo -e "${gl_bufan}4.  ${gl_bai}管理 Compose 容器"
            echo -e "${gl_bufan}5.  ${gl_bai}删除 Compose 备份"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
            echo -e "${gl_hong}00. ${gl_bai}退出脚本"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入你的选择: " choice
            case $choice in
            1) backup_compose_env ;;            # 备份 Compose 环境
            2) migrate_compose_env ;;           # 迁移 Compose 环境
            3) restore_compose_env ;;           # 还原 Compose 环境
            4) manage_compose_containers ;;     # 管理 Compose 容器
            5) delete_compose_backup ;;         # 删除 Compose 备份
            0) cancel_return; break ;;          # 返回到上一级菜单
            00 | 000 | 0000) exit_script ;;     # 感谢使用，再见！
            *) handle_invalid_input ;;          # 无效的输入,请重新输入!
            esac
        done
    }
    # --------------- 启动入口 ---------------
    main_menu
}

# 函数_备份Docker镜像
docker_image_backup_tools() {

    # --------------- 列出镜像备份 ---------------
    clear
    list_image_backups() {
        local BACKUP_ROOT="/mnt/backup_images"
        mkdir -p "$BACKUP_ROOT"
        chmod 755 "$BACKUP_ROOT"
        echo -e "${gl_huang}>>> 当前镜像备份列表${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        shopt -s nullglob
        local list
        list=("${BACKUP_ROOT}"/images_backup_*)
        shopt -u nullglob
        ((${#list[@]})) && ls -1d "${list[@]}" || echo -e "${gl_huang}暂无镜像备份${gl_bai}"

        # 列出镜像数量和大小
        for backup_dir in "${list[@]}"; do
            if [[ -f "${backup_dir}/manifest.json" ]]; then
                local img_count=$(jq '.images | length' "${backup_dir}/manifest.json" 2>/dev/null || echo "?")
                local backup_size=$(du -sh "${backup_dir}" 2>/dev/null | cut -f1 || echo "未知")
                echo -e "${gl_bai}备份 ${gl_huang}$(basename "${backup_dir}")${gl_bai}: ${gl_zi}${img_count}${gl_bai} 个镜像, ${gl_lv}${backup_size}${gl_bai}"
            fi
        done
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    }

    # --------------- 备份 Docker 镜像 ---------------
    backup_docker_images() {
        echo -e ""
        echo -e "${gl_zi}安装依赖中 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        install tar jq gzip sshpass pigz
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 检查 Docker
        if ! command -v docker &>/dev/null || ! docker info &>/dev/null; then
            echo -e "${gl_hong}错误: Docker 未安装或未运行${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        fi

        local BACKUP_ROOT="/mnt/backup_images"
        local DATE_STR=$(date +%Y%m%d_%H%M%S)
        local BACKUP_DIR="${BACKUP_ROOT}/images_backup_${DATE_STR}"
        mkdir -p "$BACKUP_DIR"

        clear
        echo -e "${gl_zi}>>> 备份 ${gl_huang}Docker${gl_zi} 镜像 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 获取所有镜像
        log_info "正在获取 Docker 镜像列表 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        mapfile -t IMAGES < <(docker images --format "{{.Repository}}:{{.Tag}}" | grep -v "<none>" | grep -v "REPOSITORY:TAG")

        if [[ ${#IMAGES[@]} -eq 0 ]]; then
            log_warn "未找到任何 Docker 镜像"
            exit_animation    # 即将退出动画
            return
        fi

        # 显示镜像列表
        echo -e "${gl_zi}找到以下 ${gl_huang}${#IMAGES[@]}${gl_zi} 个镜像:${gl_bai}"
        for i in "${!IMAGES[@]}"; do
            echo -e "  ${gl_huang}$((i + 1)).${gl_bai} ${IMAGES[i]}"
        done

        # 选择备份方式
        echo -e ""
        echo -e "${gl_huang}>>> 请选择备份方式:${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai} 备份所有镜像 (${gl_huang}${#IMAGES[@]}${gl_bai} 个)"
        echo -e "${gl_bufan}2.  ${gl_bai} 手动选择镜像"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai} 返回主上一级选单"
        echo -e "${gl_hong}00. ${gl_bai} 退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择 : " backup_choice

        case "$backup_choice" in
        1)
            # 备份所有镜像
            images_to_backup=("${IMAGES[@]}")
            ;;
        2)
            # 手动选择镜像
            images_to_backup=()
            echo -e ""
            echo -e "${gl_huang}>>> 手动选择镜像${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}请输入要备份的镜像编号 (用空格分隔，例如: ${gl_hong}1 ${gl_huang}3 ${gl_lv}5${gl_bai}):"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入你的选择: " selected_nums

            for num in $selected_nums; do
                if [[ "$num" =~ ^[0-9]+$ ]] && [[ $num -ge 1 ]] && [[ $num -le ${#IMAGES[@]} ]]; then
                    images_to_backup+=("${IMAGES[$((num - 1))]}")
                fi
            done

            if [[ ${#images_to_backup[@]} -eq 0 ]]; then
                log_warn "未选择任何镜像"
                exit_animation    # 即将退出动画
                return
            fi
            echo -e "${gl_zi}已选择 ${gl_huang}${#images_to_backup[@]}${gl_zi} 个镜像${gl_bai}"

            ;;
        0) cancel_return; return ;;     # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;; # 感谢使用，再见！
        *) handle_invalid_input ;;      # 无效的输入,请重新输入!
        esac

        # 创建恢复脚本
        local RESTORE_SCRIPT="${BACKUP_DIR}/restore_images.sh"
        cat >"$RESTORE_SCRIPT" <<'EOF'
#!/bin/bash
set -e

# 颜色定义
gl_bai='\033[0m'
gl_bufan='\033[96m'
gl_lv='\033[32m'
gl_huang='\033[33m'
gl_hong='\033[31m'
gl_zi='\033[35m'

# 备份目录
BACKUP_DIR="$(cd "$(dirname "$0")"; pwd)"
MANIFEST="${BACKUP_DIR}/manifest.json"

echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
echo -e "${gl_zi}>>> 恢复 Docker 镜像 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

# 检查 manifest
if [[ ! -f "$MANIFEST" ]]; then
    echo -e "${gl_hong}错误: 未找到 manifest.json 文件${gl_bai}"
    exit_animation    # 即将退出动画
    exit 1
fi

# 解析 manifest
IMAGE_COUNT=$(jq '.images | length' "$MANIFEST")
echo -e "${gl_bai}发现 ${gl_huang}${IMAGE_COUNT}${gl_bai} 个镜像需要加载${gl_bai}"

# 确认操作
read -r -e -p "$(echo -e "${gl_bai}是否要加载所有镜像? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
if [[ ! "$confirm" =~ ^[Yy]$ ]]; then
    echo -e "${gl_huang}已取消${gl_bai}"
    exit_animation    # 即将退出动画
    exit 0
fi

# 开始加载
for i in $(seq 0 $((IMAGE_COUNT-1))); do
    IMAGE_NAME=$(jq -r ".images[$i].name" "$MANIFEST")
    IMAGE_FILE=$(jq -r ".images[$i].file" "$MANIFEST")
    IMAGE_PATH="${BACKUP_DIR}/${IMAGE_FILE}"
    
    echo -e "${gl_bai}[$((i+1))/${IMAGE_COUNT}] 加载镜像: ${gl_huang}${IMAGE_NAME}${gl_bai}"
    
    if [[ -f "$IMAGE_PATH" ]]; then
