            echo -e "${gl_huang}cd '${target_backup_dir}/${backup_base_name}'${gl_bai}"
            echo -e "${gl_huang}for tar_file in *.tar.gz; do docker load -i \"\$tar_file\"; done${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
        else
            log_error "传输验证失败，备份可能不完整"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            return 1
        fi
