        1)
            # 加载所有镜像
            files_to_load=("${image_files[@]}")
            ;;
        2)
            # 选择特定镜像
            files_to_load=()
            echo -e "${gl_bai}请输入要加载的镜像文件编号 (用空格分隔):${gl_bai}"
            read -r -e -p "选择: " selected_nums

            for num in $selected_nums; do
                if [[ "$num" =~ ^[0-9]+$ ]] && [[ $num -ge 1 ]] && [[ $num -le ${#image_files[@]} ]]; then
                    files_to_load+=("${image_files[$((num - 1))]}")
                fi
            done

            if [[ ${#files_to_load[@]} -eq 0 ]]; then
                log_warn "未选择任何镜像文件"
                exit_animation    # 即将退出动画
                return
            fi
            ;;
        0) cancel_return; break ;;      # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;; # 感谢使用，再见！
        *) handle_invalid_input ;;      # 无效的输入,请重新输入!
        esac

        # 开始加载
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_zi}开始加载 ${gl_huang}${#files_to_load[@]}${gl_zi} 个镜像 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        success_count=0
        fail_count=0

        for i in "${!files_to_load[@]}"; do
            local image_file="${files_to_load[i]}"
            local filename=$(basename "$image_file")

            echo -e "${gl_bai}[$((i + 1))/${#files_to_load[@]}] 加载: ${gl_huang}${filename}${gl_bai}"

            if docker load -i "$image_file" 2>/dev/null; then
                echo -e "${gl_lv}✓ 成功${gl_bai}"
                ((success_count++))
            else
                echo -e "${gl_hong}✗ 失败${gl_bai}"
                ((fail_count++))
            fi
        done

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lv}加载完成！${gl_bai}"
        echo -e "  ${gl_bai}成功: ${gl_huang}${success_count}${gl_bai} 个"
        echo -e "  ${gl_bai}失败: ${gl_huang}${fail_count}${gl_bai} 个"
        echo -e ""
        echo -e "${gl_bai}使用 ${gl_huang}docker images${gl_bai} 查看已加载的镜像${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # --------------- 管理 Docker 镜像 ---------------
    manage_docker_images() {
        # 检查 Docker
        if ! command -v docker &>/dev/null || ! docker info &>/dev/null; then
            echo -e "${gl_hong}错误: Docker 未安装或未运行${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            return 1
        fi

        # 管理菜单
        while true; do
            clear
            # 获取镜像信息
            echo -e "${gl_huang}>>> 当前 Docker 镜像列表${gl_bai}"

            # 获取镜像列表
            mapfile -t ALL_IMAGES < <(docker images --format "table {{.Repository}}\t{{.Tag}}\t{{.ID}}\t{{.Size}}" | tail -n +2)

            if [[ ${#ALL_IMAGES[@]} -eq 0 ]]; then
                echo -e "${gl_huang}没有找到 Docker 镜像${gl_bai}"
            else
                # echo -e "${gl_lv}编号\t镜像:标签\t\t\t\tID\t\t大小${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                for i in "${!ALL_IMAGES[@]}"; do
                    IFS=$'\t' read -r repo tag id size <<<"${ALL_IMAGES[i]}"
                    local full_name="${repo}:${tag}"
                    if [[ "$tag" == "<none>" ]]; then
                        full_name="${repo}"
                    fi

                    # 计算编号宽度
                    local num_width=$((${#ALL_IMAGES[@]} > 99 ? 3 : ${#ALL_IMAGES[@]} > 9 ? 2 : 1))
                    printf "${gl_huang}%-${num_width}d${gl_bai}\t%-40s\t%-12s\t%s\n" \
                        $((i + 1)) \
                        "${full_name:0:40}" \
                        "${id:0:12}" \
                        "$size"
                done
            fi

            local total_images=$(docker images -q | wc -l)
            local total_size=$(docker system df --format "{{.TotalSize}}" 2>/dev/null || echo "未知")

            # echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            # echo -e "${gl_bai}镜像总数: ${gl_huang}${total_images}${gl_bai} 个"
            # echo -e "${gl_bai}总大小: ${gl_huang}${total_size}${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            echo -e ""
            echo -e "${gl_zi}>>> 管理 ${gl_huang}Docker${gl_zi} 镜像${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}1.  ${gl_bai} 删除指定镜像      ${gl_bufan}2.  ${gl_bai} 清理悬空镜像"
            echo -e "${gl_bufan}3.  ${gl_bai} 清理未使用镜像    ${gl_bufan}4.  ${gl_bai} 导出单个镜像"
            echo -e "${gl_bufan}5.  ${gl_bai} 加载单个镜像      ${gl_bufan}6.  ${gl_bai} 管理导出的镜像"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_hong}00.  ${gl_bai}退出脚本          ${gl_huang}0.  ${gl_bai} 返回上一级选单"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入你的选择: " manage_choice

            case "$manage_choice" in
            1)
                # 删除指定镜像
                if [[ ${#ALL_IMAGES[@]} -eq 0 ]]; then
                    echo -e "${gl_huang}没有可删除的镜像${gl_bai}"
                    read -n 1 -s -r -p "$(echo -e "按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
                    echo
                    continue
                fi

                clear
                # 获取镜像信息
                echo -e "${gl_huang}>>> 当前 Docker 镜像列表${gl_bai}"

                # 获取镜像列表
                mapfile -t ALL_IMAGES < <(docker images --format "table {{.Repository}}\t{{.Tag}}\t{{.ID}}\t{{.Size}}" | tail -n +2)

                if [[ ${#ALL_IMAGES[@]} -eq 0 ]]; then
                    echo -e "${gl_huang}没有找到 Docker 镜像${gl_bai}"
                else
                    # echo -e "${gl_lv}编号\t镜像:标签\t\t\t\tID\t\t大小${gl_bai}"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                    for i in "${!ALL_IMAGES[@]}"; do
                        IFS=$'\t' read -r repo tag id size <<<"${ALL_IMAGES[i]}"
                        local full_name="${repo}:${tag}"
                        if [[ "$tag" == "<none>" ]]; then
                            full_name="${repo}"
                        fi

                        # 计算编号宽度
                        local num_width=$((${#ALL_IMAGES[@]} > 99 ? 3 : ${#ALL_IMAGES[@]} > 9 ? 2 : 1))
                        printf "${gl_huang}%-${num_width}d${gl_bai}\t%-40s\t%-12s\t%s\n" \
                            $((i + 1)) \
                            "${full_name:0:40}" \
                            "${id:0:12}" \
                            "$size"
                    done
                fi

                local total_images=$(docker images -q | wc -l)
                local total_size=$(docker system df --format "{{.TotalSize}}" 2>/dev/null || echo "未知")
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                echo -e ""
                echo -e "${gl_zi}>>> 删除的镜像编号 (用空格分隔多个):${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                read -r -e -p "请输入你的选择: " delete_nums

                for num in $delete_nums; do
                    if [[ "$num" =~ ^[0-9]+$ ]] && [[ $num -ge 1 ]] && [[ $num -le ${#ALL_IMAGES[@]} ]]; then
                        IFS=$'\t' read -r repo tag id size <<<"${ALL_IMAGES[$((num - 1))]}"
                        local image_id="$id"

                        echo -e "${gl_bai}删除镜像: ${gl_huang}${repo}:${tag}${gl_bai} (${image_id})"

                        # 检查是否有容器使用
                        local containers=$(docker ps -a -q --filter ancestor="$image_id")
                        if [[ -n "$containers" ]]; then
                            echo -e "${gl_hong}警告: 有容器使用此镜像，请先删除容器${gl_bai}"
                            continue
                        fi

                        read -r -e -p "$(echo -e "确认删除? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
                        if [[ "$confirm" =~ ^[Yy]$ ]]; then
                            if docker rmi "$image_id" 2>/dev/null; then
                                echo -e "${gl_lv}✓ 删除成功${gl_bai}"
                            else
                                echo -e "${gl_hong}✗ 删除失败${gl_bai}"
                            fi
                        fi
                    fi
                done
                ;;
            2)
                # 清理悬空镜像
                echo -e "${gl_bai}正在查找悬空镜像 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                local dangling_images=$(docker images -f "dangling=true" -q)

                if [[ -z "$dangling_images" ]]; then
                    echo -e "${gl_huang}没有悬空镜像${gl_bai}"
                    read -n 1 -s -r -p "$(echo -e "按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
                else
                    echo -e "${gl_bai}找到悬空镜像:${gl_bai}"
                    docker images -f "dangling=true" --format "  {{.ID}} {{.Repository}}"

                    read -r -e -p "$(echo -e "是否清理所有悬空镜像? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
                    if [[ "$confirm" =~ ^[Yy]$ ]]; then
                        if docker image prune -f; then
                            echo -e "${gl_lv}✓ 悬空镜像清理完成${gl_bai}"
                            read -n 1 -s -r -p "$(echo -e "按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
                        else
                            echo -e "${gl_hong}✗ 清理失败${gl_bai}"
                            read -n 1 -s -r -p "$(echo -e "按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
                        fi
                    fi
                fi
                ;;
            3)
                # 清理未使用镜像
                echo -e ""
                echo -e "${gl_bai}当前镜像空间使用情况:${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                list_beautify_docker_system
                # docker system df
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "$(echo -e "是否清理所有未使用的镜像? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
                if [[ "$confirm" =~ ^[Yy]$ ]]; then
                    docker image prune -a -f
                    echo -e "${gl_lv}✓ 未使用镜像清理完成${gl_bai}"
                fi
                ;;
            4)
                # 导出单个镜像
                if [[ ${#ALL_IMAGES[@]} -eq 0 ]]; then
                    echo -e "${gl_huang}没有可导出的镜像${gl_bai}"
                    exit_animation    # 即将退出动画
                    continue
                fi

                clear
                # 获取镜像信息
                echo -e "${gl_huang}>>> 当前 Docker 镜像列表${gl_bai}"

                # 获取镜像列表
                mapfile -t ALL_IMAGES < <(docker images --format "table {{.Repository}}\t{{.Tag}}\t{{.ID}}\t{{.Size}}" | tail -n +2)

                if [[ ${#ALL_IMAGES[@]} -eq 0 ]]; then
                    echo -e "${gl_huang}没有找到 Docker 镜像${gl_bai}"
                else
                    # echo -e "${gl_lv}编号\t镜像:标签\t\t\t\tID\t\t大小${gl_bai}"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                    for i in "${!ALL_IMAGES[@]}"; do
                        IFS=$'\t' read -r repo tag id size <<<"${ALL_IMAGES[i]}"
                        local full_name="${repo}:${tag}"
                        if [[ "$tag" == "<none>" ]]; then
                            full_name="${repo}"
                        fi

                        # 计算编号宽度
                        local num_width=$((${#ALL_IMAGES[@]} > 99 ? 3 : ${#ALL_IMAGES[@]} > 9 ? 2 : 1))
                        printf "${gl_huang}%-${num_width}d${gl_bai}\t%-40s\t%-12s\t%s\n" \
                            $((i + 1)) \
                            "${full_name:0:40}" \
                            "${id:0:12}" \
                            "$size"
                    done
                fi

                local total_images=$(docker images -q | wc -l)
                local total_size=$(docker system df --format "{{.TotalSize}}" 2>/dev/null || echo "未知")
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                echo -e ""
                echo -e "${gl_zi}>>> 请输入要导出的镜像编号:${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "请输入你的选择: " export_num

                if [[ "$export_num" =~ ^[0-9]+$ ]] && [[ $export_num -ge 1 ]] && [[ $export_num -le ${#ALL_IMAGES[@]} ]]; then
                    # 修复字段解析：使用正则提取有效字段
                    local image_info="${ALL_IMAGES[$((export_num - 1))]}"
                    local repo=$(echo "$image_info" | grep -oP '^\S+')
                    local tag=$(echo "$image_info" | grep -oP '\S+\s+\K\S+' | head -1)
                    local export_name="${repo}:${tag}"

                    # 安全处理文件名：移除所有特殊字符
                    local safe_name=$(echo "$export_name" | sed 's/[^a-zA-Z0-9._-]/-/g')
                    local export_file="/mnt/backup_images/${safe_name}_$(date +%Y%m%d_%H%M%S).tar"

                    echo -e "${gl_bai}正在导出镜像: ${gl_huang}${export_name}${gl_bai}"
                    echo -e "${gl_bai}保存到: ${gl_huang}${export_file}${gl_bai}"

                    mkdir -p "/mnt/backup_images"
                    if docker save -o "$export_file" "$export_name" 2>/dev/null; then
                        echo -e "${gl_lv}✓ 导出成功${gl_bai}"

                        # 压缩
                        read -r -e -p "$(echo -e "是否压缩? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" compress
                        if [[ "$compress" =~ ^[Yy]$ ]]; then
                            if gzip "$export_file"; then
                                echo -e "${gl_lv}✓ 压缩完成: ${export_file}.gz${gl_bai}"
                            fi
                        fi
                    else
                        echo -e "${gl_hong}✗ 导出失败${gl_bai}"
                        # 添加错误日志
                        docker save "$export_name" 2>&1 | grep -i error
                    fi
                fi
                ;;
            5)
                # 加载单个镜像
                # 创建备份目录（如果不存在）
                mkdir -p "/mnt/backup_images"

                # 扫描备份目录
                local backup_files=()
                local i=1

                echo -e "${gl_bai}正在扫描备份目录 /mnt/backup_images ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

                # 查找所有 .tar 和 .tar.gz 文件
                while IFS= read -r -d $'\0' file; do
                    backup_files+=("$file")
                done < <(find "/mnt/backup_images" -type f \( -name "*.tar" -o -name "*.tar.gz" -o -name "*.tgz" \) -print0 2>/dev/null | sort -z)

                if [[ ${#backup_files[@]} -eq 0 ]]; then
                    echo -e "${gl_huang}在 /mnt/backup_images 目录中没有找到备份文件${gl_bai}"
                    echo -e "${gl_bai}支持的格式: .tar, .tar.gz, .tgz${gl_bai}"
                    read -n 1 -s -r -p "$(echo -e "按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
                    echo
                    continue
                fi

                clear
                echo -e "${gl_huang}>>> 可加载的备份文件列表${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_lv}编号\t文件大小\t最后修改\t文件名${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

                # 显示文件列表
                for i in "${!backup_files[@]}"; do
                    local file="${backup_files[i]}"
                    local file_name=$(basename "$file")
                    local file_size=$(du -h "$file" | cut -f1)
                    local mod_time=$(stat -c "%y" "$file" | cut -d' ' -f1,2 | cut -d'.' -f1)
                    local file_num=$((i + 1))

                    printf "${gl_huang}%3d${gl_bai}\t%-8s\t%s\t${gl_lv}%s${gl_bai}\n" \
                        "$file_num" \
                        "$file_size" \
                        "$mod_time" \
                        "$file_name"
                done

                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e ""
                echo -e "${gl_zi}>>> 请输入要加载的备份文件编号:${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "请输入你的选择: " file_num

                if [[ ! "$file_num" =~ ^[0-9]+$ ]] || [[ $file_num -lt 1 ]] || [[ $file_num -gt ${#backup_files[@]} ]]; then
                    echo -e "${gl_hong}✗ 无效的编号${gl_bai}"
                    continue
                fi

                local selected_file="${backup_files[$((file_num - 1))]}"
                local file_size=$(du -h "$selected_file" | cut -f1)
                local file_name=$(basename "$selected_file")

                echo -e ""
                echo -e "${gl_bai}选择的文件: ${gl_huang}${file_name}${gl_bai}"
                echo -e "${gl_bai}文件大小: ${gl_huang}${file_size}${gl_bai}"
                echo -e "${gl_bai}完整路径: ${gl_huang}${selected_file}${gl_bai}"
                echo -e ""

                # 确认加载
                read -r -e -p "$(echo -e "确认加载此镜像? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_load
                if [[ ! "$confirm_load" =~ ^[Yy]$ ]]; then
                    echo -e "${gl_huang}已取消加载${gl_bai}"
                    continue
                fi

                echo -e "${gl_bai}正在加载镜像，请稍候 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

                # 显示加载进度
                echo -n "["
                for i in {1..20}; do
                    echo -n " "
                done
                echo -n "]"

                # 加载镜像
                local load_output=$(docker load -i "$selected_file" 2>&1)
                local load_status=$?

                # 清除进度条
                echo -ne "\r\033[K"

                if [[ $load_status -eq 0 ]]; then
                    echo -e "${gl_lv}✓ 镜像加载成功${gl_bai}"

                    # 提取加载的镜像名称
                    local loaded_image=$(echo "$load_output" | grep -oP "Loaded image: \K.*" || echo "")

                    if [[ -n "$loaded_image" ]]; then
                        echo -e "${gl_bai}加载的镜像: ${gl_huang}${loaded_image}${gl_bai}"

                        # 显示新加载的镜像
                        echo -e ""
                        echo -e "${gl_bai}当前镜像列表中的最新镜像:${gl_bai}"
                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        docker images --format "table {{.Repository}}\t{{.Tag}}\t{{.ID}}\t{{.Size}}" | head -n 6
                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    else
                        echo -e "${gl_bai}加载的输出: ${gl_huang}${load_output}${gl_bai}"
                    fi

                    # 询问是否删除原文件
                    echo -e ""
                    read -r -e -p "$(echo -e "是否删除备份文件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" delete_file
                    if [[ "$delete_file" =~ ^[Yy]$ ]]; then
                        if rm -f "$selected_file"; then
                            echo -e "${gl_lv}✓ 备份文件已删除${gl_bai}"
                        else
                            echo -e "${gl_hong}✗ 文件删除失败${gl_bai}"
                        fi
                    fi
                else
                    echo -e "${gl_hong}✗ 镜像加载失败${gl_bai}"
                    echo -e "${gl_bai}错误信息:${gl_bai}"
                    echo -e "${gl_huang}${load_output}${gl_bai}"
                    echo -e ""
                    echo -e "${gl_huang}可能的原因:${gl_bai}"
                    echo -e "  1. 文件损坏或不完整"
                    echo -e "  2. 磁盘空间不足"
                    echo -e "  3. Docker 服务异常"
                    echo -e "  4. 权限不足"
                    echo -e "  5. 镜像格式不正确"
                fi
                read -n 1 -s -r -p "$(echo -e "按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
                echo
                ;;
            6)
                # 管理导出的镜像
                cd "/mnt/backup_images" && linux_file "." "管理导出的镜像" "管理 ${gl_huang}Docker${gl_bai} 镜像"
                ;;
            0) cancel_return; break ;;      # 返回到上一级菜单
            00 | 000 | 0000) exit_script ;; # 感谢使用，再见！
            *) handle_invalid_input ;;      # 无效的输入,请重新输入!
            esac
            echo
        done
    }

    # --------------- 删除 Docker 镜像备份 ---------------
    delete_image_backup() {
        local BACKUP_ROOT="/mnt/backup_images"

        echo -e ""
        echo -e "${gl_zi}>>> 删除镜像备份 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 列出备份
        shopt -s nullglob
        local backups=("${BACKUP_ROOT}"/images_backup_*)
        shopt -u nullglob

        if [[ ${#backups[@]} -eq 0 ]]; then
            echo -e "${gl_huang}没有找到镜像备份${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi

        echo -e "${gl_bai}可用备份列表:${gl_bai}"
        for i in "${!backups[@]}"; do
            local backup_dir="${backups[i]}"
            local img_count="?"
            local backup_size="未知"

            if [[ -f "${backup_dir}/manifest.json" ]]; then
                img_count=$(jq '.images | length' "${backup_dir}/manifest.json" 2>/dev/null || echo "?")
            fi
            backup_size=$(du -sh "${backup_dir}" 2>/dev/null | cut -f1 || echo "未知")

            echo -e "${gl_huang}$((i + 1)).${gl_bai} $(basename "${backup_dir}") (${gl_huang}${img_count}${gl_bai} 个镜像, ${gl_huang}${backup_size}${gl_bai})"
        done
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "$(echo -e "${gl_bai}请输入要删除的备份编号 (用空格分隔多个)，${gl_hong}回车${gl_bai}删除全部: ")" delete_input

        if [[ -z "$delete_input" ]]; then
            # 直接回车删除全部
            read -r -e -p "$(echo -e "确认删除 ${gl_huang}${#backups[@]}${gl_bai} 个备份? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

            if [[ "$confirm" =~ ^[Yy]$ ]]; then
                for backup in "${backups[@]}"; do
                    rm -rf "$backup"
                done
                echo -e "${gl_lv}✓ 已删除所有备份${gl_bai}"
            else
                echo -e "${gl_huang}已取消${gl_bai}"
            fi
        else
            # 删除选定的备份
            for num in $delete_input; do
                if [[ "$num" =~ ^[0-9]+$ ]] && [[ $num -ge 1 ]] && [[ $num -le ${#backups[@]} ]]; then
                    local backup_dir="${backups[$((num - 1))]}"
                    read -r -e -p "$(echo -e "确认删除 ${gl_huang}$(basename "${backup_dir}")${gl_bai}? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

                    if [[ "$confirm" =~ ^[Yy]$ ]]; then
                        rm -rf "$backup_dir"
                        echo -e "${gl_lv}✓ 已删除: $(basename "${backup_dir}")${gl_bai}"
                    else
                        echo -e "${gl_huang}跳过: $(basename "${backup_dir}")${gl_bai}"
                    fi
                fi
            done
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    }

    # --------------- 主菜单 ---------------
    main_menu() {
        while true; do
            clear
            list_image_backups
            echo -e ""
            echo -e "${gl_zi}>>> Docker 镜像备份/迁移/还原工具${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}1.  ${gl_bai}备份 Docker 镜像"
            echo -e "${gl_bufan}2.  ${gl_bai}迁移 Docker 镜像"
            echo -e "${gl_bufan}3.  ${gl_bai}加载 Docker 镜像"
            echo -e "${gl_bufan}4.  ${gl_bai}管理 Docker 镜像"
            echo -e "${gl_bufan}5.  ${gl_bai}删除 Docker 镜像备份"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
            echo -e "${gl_hong}00. ${gl_bai}退出脚本"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入你的选择: " choice
            case $choice in
            1) backup_docker_images ;;
            2) migrate_docker_images ;;
            3) load_docker_images ;;
            4) manage_docker_images ;;
            5) delete_image_backup ;;
            0) cancel_return; break ;;      # 返回到上一级菜单
            00 | 000 | 0000) exit_script ;; # 感谢使用，再见！
            *) handle_invalid_input ;;      # 无效的输入,请重新输入!
            esac
        done
    }

    # --------------- 启动入口 ---------------
    main_menu
}

# 公共函数：停止所有docker-compose项目
stop_all_compose_projects() {
    clear
    echo -e ""
    echo -e "${gl_zi}>>> 停止所有 Compose 项目 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查Docker是否运行
    if ! docker info &>/dev/null; then
        log_error "Docker 服务未运行"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 预设目录选项
    local preset_dirs=(
        "/compose"
        "/mnt/compose"
        "/vol1/1000/compose"
        "/vol2/1000/compose"
    )

    # 扫描所有运行中的 docker-compose 项目
    log_info "正在扫描运行中的 docker-compose 项目 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 获取所有运行中的docker-compose项目的工作目录
    local running_projects=()
    if command -v docker &>/dev/null && docker info &>/dev/null; then
        while IFS= read -r dir; do
            [[ -z "$dir" ]] && continue
            [[ ! -d "$dir" ]] && continue
            running_projects+=("$(realpath "$dir")")
        done < <(
            docker ps --format '{{.Names}}' 2>/dev/null |
                xargs -I{} sh -c 'docker inspect {} 2>/dev/null | jq -r ".[0].Config.Labels[\"com.docker.compose.project.working_dir\"]" 2>/dev/null || echo ""' |
                sort -u
        )
    fi

    # 标记推荐的目录
    local recommended_dirs=()
    for preset_dir in "${preset_dirs[@]}"; do
        for running_dir in "${running_projects[@]}"; do
            if [[ "$running_dir" == "$preset_dir" ]] || [[ "$running_dir" == "$preset_dir"* ]]; then
                recommended_dirs+=("$preset_dir")
                break
            fi
        done
    done

    # 去重推荐目录
    recommended_dirs=($(printf "%s\n" "${recommended_dirs[@]}" | sort -u))

    # 显示扫描结果
    if [[ ${#running_projects[@]} -gt 0 ]]; then
        echo -e "${gl_bai}扫描到运行中的 docker-compose 项目目录:${gl_bai}"
        for dir in "${running_projects[@]}"; do
            echo -e "  ${gl_lv}•${gl_bai} ${dir}"
        done

        if [[ ${#recommended_dirs[@]} -gt 0 ]]; then
            echo -e "${gl_bai}推荐的工作目录:${gl_bai}"
            for dir in "${recommended_dirs[@]}"; do
                echo -e "  ${gl_hong}★${gl_bai} ${dir}"
            done
        fi
    else
        echo -e "${gl_huang}未找到运行中的 docker-compose 项目${gl_bai}"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 显示目录选择菜单
    echo -e ""
    echo -e "${gl_huang}>>> 请选择要停止的工作目录:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    for i in "${!preset_dirs[@]}"; do
        local marker=""
        local dir_status=""

        # 检查是否为推荐目录
        for rd in "${recommended_dirs[@]}"; do
            if [[ "${preset_dirs[i]}" == "$rd" ]]; then
                marker=" ${gl_hong}(推荐)${gl_bai}"
                break
            fi
        done

        # 检查目录是否存在
        if [[ -d "${preset_dirs[i]}" ]]; then
            # 检查目录下是否有 docker-compose 文件
            local compose_count=$(find "${preset_dirs[i]}" -maxdepth 2 -type f \( -name "docker-compose.yml" -o -name "docker-compose.yaml" \) 2>/dev/null | wc -l)
            if [[ $compose_count -gt 0 ]]; then
                dir_status="${gl_lv}[有 ${compose_count} 个项目]${gl_bai}"
            else
                dir_status="${gl_huang}[无 compose 项目]${gl_bai}"
            fi
        else
            dir_status="${gl_huang}[目录不存在]${gl_bai}"
        fi

        echo -e "${gl_bufan}$((i + 1)).${gl_bai} ${preset_dirs[i]} $dir_status$marker"
    done
    echo -e "${gl_bufan}$((${#preset_dirs[@]} + 1)).${gl_bai} 手动指定路径"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_huang}0.${gl_bai} 返回上一级选单"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 读取用户选择
    read -r -e -p "$(echo -e "${gl_bai}请输入你的选择 (${gl_huang}0${gl_bai}-${gl_hong}$((${#preset_dirs[@]} + 1))${gl_bai}): ")" dir_choice

    # 处理选择
    local COMPOSE_WORK_DIR=""

    if [[ -z "$dir_choice" ]] && [[ ${#recommended_dirs[@]} -gt 0 ]]; then
        # 直接回车，使用第一个推荐目录
        COMPOSE_WORK_DIR="${recommended_dirs[0]}"
        echo -e "${gl_bai}使用推荐目录: ${gl_huang}$COMPOSE_WORK_DIR${gl_bai}"
    elif [[ "$dir_choice" =~ ^[0-9]+$ ]]; then
        if [[ $dir_choice -eq 0 ]]; then
            # 返回
            return
        elif [[ $dir_choice -le ${#preset_dirs[@]} ]]; then
            # 选择预设目录
            COMPOSE_WORK_DIR="${preset_dirs[$((dir_choice - 1))]}"
        elif [[ $dir_choice -eq $((${#preset_dirs[@]} + 1)) ]]; then
            # 手动指定路径
            read -r -e -p "$(echo -e "${gl_bai}请输入自定义路径: ")" COMPOSE_WORK_DIR
        else
            log_error "无效选择"
            exit_animation    # 即将退出动画
            return
        fi
    else
        # 非数字输入，视为手动指定路径
        COMPOSE_WORK_DIR="$dir_choice"
    fi

    # 检查是否为空
    if [[ -z "$COMPOSE_WORK_DIR" ]]; then
        log_warn "路径不能为空"
        exit_animation    # 即将退出动画
        return
    fi

    # 检查目录是否存在
    if [[ ! -d "$COMPOSE_WORK_DIR" ]]; then
        log_warn "目录不存在: $COMPOSE_WORK_DIR"
        exit_animation    # 即将退出动画
        return
    fi

    echo -e "${gl_bai}工作目录: ${gl_huang}$COMPOSE_WORK_DIR${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 确认停止操作
    read -r -e -p "$(echo -e "${gl_hong}警告: ${gl_bai}确定停止 ${gl_huang}$COMPOSE_WORK_DIR${gl_bai} 下的所有 Compose 项目吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

    if [[ ! "$confirm" =~ ^[Yy]$ ]]; then
        echo -e "${gl_huang}已取消${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 切换到工作目录
    if ! cd "$COMPOSE_WORK_DIR" 2>/dev/null; then
        log_error "无法进入目录: $COMPOSE_WORK_DIR"
        exit_animation    # 即将退出动画
        return
    fi

    # 统计停止的项目数量
    local stopped_count=0
    local total_count=0

    echo -e "${gl_bai}正在扫描 ${gl_huang}$COMPOSE_WORK_DIR${gl_bai} 下的 Compose 项目 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 扫描当前目录是否有 docker-compose.yml
    if [[ -f "docker-compose.yml" ]] || [[ -f "docker-compose.yaml" ]]; then
        local current_dir_name=$(basename "$(pwd)")
        echo -e "${gl_bai}停止项目: ${gl_huang}$current_dir_name${gl_bai} (当前目录)"

        # 检查使用哪个docker compose命令
        if command -v docker-compose &>/dev/null; then
            docker-compose down
        elif docker compose version &>/dev/null; then
            docker compose down
        else
            log_error "未找到 docker-compose 命令"
            return
        fi

        if [[ $? -eq 0 ]]; then
            echo -e "${gl_lv}✓ 已停止: $current_dir_name${gl_bai}"
            stopped_count=$((stopped_count + 1))
        fi
        total_count=$((total_count + 1))
    fi

    # 遍历子目录
    for dir in */; do
        if [[ -d "$dir" ]]; then
            cd "$dir" 2>/dev/null || continue

            if [[ -f "docker-compose.yml" ]] || [[ -f "docker-compose.yaml" ]]; then
                local project_name=$(basename "$dir")
                echo -e "${gl_bai}停止项目: ${gl_huang}$project_name${gl_bai}"

                # 检查使用哪个docker compose命令
                if command -v docker-compose &>/dev/null; then
                    docker-compose down
                elif docker compose version &>/dev/null; then
                    docker compose down
                else
                    log_error "未找到 docker-compose 命令"
                    cd ..
                    continue
                fi

                if [[ $? -eq 0 ]]; then
                    echo -e "${gl_lv}✓ 已停止: $project_name${gl_bai}"
                    stopped_count=$((stopped_count + 1))
                fi
                total_count=$((total_count + 1))
            fi

            cd .. 2>/dev/null
        fi
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if [[ $total_count -eq 0 ]]; then
        echo -e "${gl_huang}在 ${gl_hong}$COMPOSE_WORK_DIR${gl_huang} 中没有找到 Compose 项目${gl_bai}"
    else
        echo -e "${gl_bai}停止完成${gl_bai}"
        echo -e "${gl_bai}总计项目: ${gl_huang}$total_count${gl_bai}"
        echo -e "${gl_bai}成功停止: ${gl_lv}$stopped_count${gl_bai}"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 返回主菜单
    read -n 1 -s -r -p "$(echo -e "按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
    echo
}

# 公共函数：启动所有docker-compose项目
start_all_compose_projects() {
    clear
    echo -e ""
    echo -e "${gl_zi}>>> 启动所有 Compose 项目 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查Docker是否运行
    if ! docker info &>/dev/null; then
        log_error "Docker 服务未运行"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 预设目录选项
    local preset_dirs=(
        "/compose"
        "/mnt/compose"
        "/vol1/1000/compose"
        "/vol2/1000/compose"
    )

    # 扫描所有docker-compose 项目（包括已停止的）
    log_info "正在扫描所有 docker-compose 项目 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 获取所有存在的docker-compose项目的工作目录
    local all_projects=()
    for preset_dir in "${preset_dirs[@]}"; do
        if [[ -d "$preset_dir" ]]; then
            # 检查根目录是否有docker-compose文件
            if [[ -f "$preset_dir/docker-compose.yml" ]] || [[ -f "$preset_dir/docker-compose.yaml" ]]; then
                all_projects+=("$preset_dir")
            fi

            # 检查子目录
            for dir in "$preset_dir"/*/; do
                if [[ -d "$dir" ]] && ([[ -f "$dir/docker-compose.yml" ]] || [[ -f "$dir/docker-compose.yaml" ]]); then
                    all_projects+=("$(realpath "$dir")")
                fi
            done
        fi
    done

    # 去重
    all_projects=($(printf "%s\n" "${all_projects[@]}" | sort -u))

    # 获取所有运行中的docker-compose项目的工作目录
    local running_projects=()
    if command -v docker &>/dev/null && docker info &>/dev/null; then
        while IFS= read -r dir; do
            [[ -z "$dir" ]] && continue
            [[ ! -d "$dir" ]] && continue
            running_projects+=("$(realpath "$dir")")
        done < <(
            docker ps --format '{{.Names}}' 2>/dev/null |
                xargs -I{} sh -c 'docker inspect {} 2>/dev/null | jq -r ".[0].Config.Labels[\"com.docker.compose.project.working_dir\"]" 2>/dev/null || echo ""' |
                sort -u
        )
    fi

    # 标记推荐的目录（有项目但未全部运行的目录）
    local recommended_dirs=()
    for preset_dir in "${preset_dirs[@]}"; do
        # 检查该预设目录下是否有项目
        local has_projects=false
        for project in "${all_projects[@]}"; do
            if [[ "$project" == "$preset_dir" ]] || [[ "$project" == "$preset_dir"* ]]; then
                has_projects=true
                break
            fi
        done

        if $has_projects; then
            # 检查是否有未运行的项目
            local all_running=true
            for project in "${all_projects[@]}"; do
                if [[ "$project" == "$preset_dir" ]] || [[ "$project" == "$preset_dir"* ]]; then
                    # 检查这个项目是否在运行
                    local is_running=false
                    for running_dir in "${running_projects[@]}"; do
                        if [[ "$running_dir" == "$project" ]]; then
                            is_running=true
                            break
                        fi
                    done

                    if ! $is_running; then
                        all_running=false
                        break
                    fi
                fi
            done

            if ! $all_running; then
                recommended_dirs+=("$preset_dir")
            fi
        fi
    done

    # 显示扫描结果
    if [[ ${#all_projects[@]} -gt 0 ]]; then
        echo -e "${gl_bai}扫描到的 docker-compose 项目目录:${gl_bai}"
        for dir in "${all_projects[@]}"; do
            # 检查是否正在运行
            local is_running=""
            for running_dir in "${running_projects[@]}"; do
                if [[ "$running_dir" == "$dir" ]]; then
                    is_running=" ${gl_lv}[运行中]${gl_bai}"
                    break
                fi
            done
            [[ -z "$is_running" ]] && is_running=" ${gl_huang}[已停止]${gl_bai}"

            echo -e "  ${gl_lv}•${gl_bai} ${dir}$is_running"
        done

        if [[ ${#recommended_dirs[@]} -gt 0 ]]; then
            echo -e "${gl_bai}推荐的工作目录（有未运行的项目）:${gl_bai}"
            for dir in "${recommended_dirs[@]}"; do
                echo -e "  ${gl_hong}★${gl_bai} ${dir}"
            done
        fi
    else
        echo -e "${gl_huang}未找到任何 docker-compose 项目${gl_bai}"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    echo -e ""
    # 显示目录选择菜单
    echo -e "${gl_huang}>>> 请选择要启动的工作目录:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    for i in "${!preset_dirs[@]}"; do
        local marker=""
        local dir_status=""

        # 检查是否为推荐目录
        for rd in "${recommended_dirs[@]}"; do
            if [[ "${preset_dirs[i]}" == "$rd" ]]; then
                marker=" ${gl_hong}(推荐)${gl_bai}"
                break
            fi
        done

        # 检查目录是否存在
        if [[ -d "${preset_dirs[i]}" ]]; then
            # 检查目录下是否有 docker-compose 文件
            local compose_count=$(find "${preset_dirs[i]}" -maxdepth 2 -type f \( -name "docker-compose.yml" -o -name "docker-compose.yaml" \) 2>/dev/null | wc -l)
            if [[ $compose_count -gt 0 ]]; then
                # 统计运行中的项目
                local running_count=0
                for project in "${running_projects[@]}"; do
                    if [[ "$project" == "${preset_dirs[i]}" ]] || [[ "$project" == "${preset_dirs[i]}"/* ]]; then
                        running_count=$((running_count + 1))
                    fi
                done

                if [[ $running_count -eq 0 ]]; then
                    dir_status="${gl_huang}[${compose_count}个项目，均未运行]${gl_bai}"
                elif [[ $running_count -eq $compose_count ]]; then
                    dir_status="${gl_lv}[${compose_count}个项目，全部运行中]${gl_bai}"
                else
                    dir_status="${gl_huang}[${compose_count}个项目，${running_count}个运行中]${gl_bai}"
                fi
            else
                dir_status="${gl_huang}[无 compose 项目]${gl_bai}"
            fi
        else
            dir_status="${gl_huang}[目录不存在]${gl_bai}"
        fi

        echo -e "${gl_bufan}$((i + 1)).${gl_bai} ${preset_dirs[i]} $dir_status$marker"
    done
    echo -e "${gl_bufan}$((${#preset_dirs[@]} + 1)).${gl_bai} 手动指定路径"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_huang}0.${gl_bai} 返回上一级选单"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 读取用户选择
    read -r -e -p "$(echo -e "${gl_bai}请输入你的选择 (${gl_huang}0${gl_bai}-${gl_hong}$((${#preset_dirs[@]} + 1))${gl_bai}): ")" dir_choice

    # 处理选择
    local COMPOSE_WORK_DIR=""

    if [[ -z "$dir_choice" ]] && [[ ${#recommended_dirs[@]} -gt 0 ]]; then
        # 直接回车，使用第一个推荐目录
        COMPOSE_WORK_DIR="${recommended_dirs[0]}"
        echo -e "${gl_bai}使用推荐目录: ${gl_huang}$COMPOSE_WORK_DIR${gl_bai}"
    elif [[ "$dir_choice" =~ ^[0-9]+$ ]]; then
        if [[ $dir_choice -eq 0 ]]; then
            # 返回
            return
        elif [[ $dir_choice -le ${#preset_dirs[@]} ]]; then
            # 选择预设目录
            COMPOSE_WORK_DIR="${preset_dirs[$((dir_choice - 1))]}"
        elif [[ $dir_choice -eq $((${#preset_dirs[@]} + 1)) ]]; then
            # 手动指定路径
            read -r -e -p "$(echo -e "${gl_bai}请输入自定义路径: ")" COMPOSE_WORK_DIR
        else
            log_error "无效选择"
            return
        fi
    else
        # 非数字输入，视为手动指定路径
        COMPOSE_WORK_DIR="$dir_choice"
    fi

    # 检查是否为空
    if [[ -z "$COMPOSE_WORK_DIR" ]]; then
        log_warn "路径不能为空"
        exit_animation    # 即将退出动画
        return
    fi

    # 检查目录是否存在
    if [[ ! -d "$COMPOSE_WORK_DIR" ]]; then
        log_warn "目录不存在: $COMPOSE_WORK_DIR"
        exit_animation    # 即将退出动画
        return
    fi

    echo -e "${gl_bai}工作目录: ${gl_huang}$COMPOSE_WORK_DIR${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 确认启动操作
    read -r -e -p "$(echo -e "${gl_bai}确定启动 ${gl_huang}$COMPOSE_WORK_DIR${gl_bai} 下的所有 Compose 项目吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm

    if [[ ! "$confirm" =~ ^[Yy]$ ]]; then
        echo -e "${gl_huang}已取消${gl_bai}"
        exit_animation    # 即将退出动画
        return
    fi

    # 切换到工作目录
    if ! cd "$COMPOSE_WORK_DIR" 2>/dev/null; then
        log_error "无法进入目录: $COMPOSE_WORK_DIR"
        exit_animation    # 即将退出动画
        return
    fi

    # 统计启动的项目数量
    local started_count=0
    local total_count=0

    echo -e "${gl_bai}正在扫描 ${gl_huang}$COMPOSE_WORK_DIR${gl_bai} 下的 Compose 项目 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 扫描当前目录是否有 docker-compose.yml
    if [[ -f "docker-compose.yml" ]] || [[ -f "docker-compose.yaml" ]]; then
        local current_dir_name=$(basename "$(pwd)")
        echo -e "${gl_bai}启动项目: ${gl_huang}$current_dir_name${gl_bai} (当前目录)"

        # 检查使用哪个docker compose命令
        if command -v docker-compose &>/dev/null; then
            docker-compose up -d
        elif docker compose version &>/dev/null; then
            docker compose up -d
        else
            log_error "未找到 docker-compose 命令"
            return
        fi

        if [[ $? -eq 0 ]]; then
            echo -e "${gl_lv}✓ 已启动: $current_dir_name${gl_bai}"
            started_count=$((started_count + 1))
        else
            echo -e "${gl_hong}✗ 启动失败: $current_dir_name${gl_bai}"
        fi
        total_count=$((total_count + 1))
    fi

    # 遍历子目录
    for dir in */; do
        if [[ -d "$dir" ]]; then
            cd "$dir" 2>/dev/null || continue

            if [[ -f "docker-compose.yml" ]] || [[ -f "docker-compose.yaml" ]]; then
                local project_name=$(basename "$dir")
                echo -e "${gl_bai}启动项目: ${gl_huang}$project_name${gl_bai}"

                # 检查使用哪个docker compose命令
                if command -v docker-compose &>/dev/null; then
                    docker-compose up -d
                elif docker compose version &>/dev/null; then
                    docker compose up -d
                else
                    log_error "未找到 docker-compose 命令"
                    cd ..
                    continue
                fi

                if [[ $? -eq 0 ]]; then
                    echo -e "${gl_lv}✓ 已启动: $project_name${gl_bai}"
                    started_count=$((started_count + 1))
                else
                    echo -e "${gl_hong}✗ 启动失败: $project_name${gl_bai}"
                fi
                total_count=$((total_count + 1))
            fi

            cd .. 2>/dev/null
        fi
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if [[ $total_count -eq 0 ]]; then
        echo -e "${gl_huang}在 ${gl_hong}$COMPOSE_WORK_DIR${gl_huang} 中没有找到 Compose 项目${gl_bai}"
    else
        echo -e "${gl_bai}启动完成${gl_bai}"
        echo -e "${gl_bai}总计项目: ${gl_huang}$total_count${gl_bai}"
        echo -e "${gl_bai}成功启动: ${gl_lv}$started_count${gl_bai}"
        if [[ $started_count -lt $total_count ]]; then
            echo -e "${gl_hong}启动失败: $((total_count - started_count))${gl_bai}"
        fi
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 返回主菜单
    read -n 1 -s -r -p "$(echo -e "按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
    echo
}

# 检查 FnOS 版本
check_fnos_version() {
    # 检测FNOS版本
    if [ -f "/etc/issue" ]; then
        # 尝试从/etc/issue文件中提取fnOS版本
        if grep -qi "fnos\|fnOS" /etc/issue; then
            # 从OS version行提取版本号
            # 使用兼容BusyBox的grep语法（不支持-P选项）
            version=$(grep -i "OS version" /etc/issue | sed -n 's/.*fnOS[[:space:]]*v\?\([0-9]\+\.[0-9]\+\.[0-9]\+\).*/\1/p' 2>/dev/null)
            
            if [ -n "$version" ]; then
                echo -e "${gl_bufan}FNOS   ${gl_bai}版本：${gl_lv}v$version${gl_bai}"
            else
                # 尝试其他方式提取版本
                version=$(grep -i "fnOS" /etc/issue | sed -n 's/.*v\?\([0-9]\+\.[0-9]\+\.[0-9]\+\).*/\1/p' 2>/dev/null)
                if [ -n "$version" ]; then
                    echo -e "${gl_bufan}FNOS   ${gl_bai}版本：${gl_lv}v$version${gl_bai}"
                else
                    # 如果提取失败，显示文件中的相关内容
                    version_info=$(grep -i "fnOS" /etc/issue | head -1)
                    echo -e "${gl_bufan}FNOS   ${gl_bai}版本：${gl_lv}${version_info:-未知}${gl_bai}"
                fi
            fi
        else
            echo -e "${gl_bufan}FNOS   ${gl_bai}版本：${gl_hong}非FNOS${gl_bai}"
        fi
    else
        echo -e "${gl_bufan}FNOS   ${gl_bai}版本：${gl_hong}非FNO${gl_bai}"
    fi
}

# 智能GPU检测函数
detect_primary_gpu() {
    root_use
    clear
    local gpu_list=()
    local primary_vendor="Unknown"
    local primary_id=""

    # 获取所有GPU设备
    while IFS= read -r line; do
        gpu_list+=("$line")
    done < <(lspci -nn 2>/dev/null | grep -i "vga\|3d\|display")

    if [[ ${#gpu_list[@]} -eq 0 ]]; then
        log_warn "未检测到GPU设备"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 显示所有GPU设备
    echo -e "${gl_zi}>>> 系统GPU设备列表${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    for ((i = 0; i < ${#gpu_list[@]}; i++)); do
        local device="${gpu_list[$i]}"
        local device_id=$(echo "$device" | awk '{print $1}')

        # 判断设备类型
        local device_type="未知"
        local device_desc=""

        if echo "$device" | grep -qi "intel.*8086"; then
            device_type="Intel"
            # 提取Intel具体型号
            device_desc=$(echo "$device" | grep -o "Intel Corporation.*\[" | sed 's/Intel Corporation //;s/ \[//')
        elif echo "$device" | grep -qi "amd.*1002\|ati.*1002"; then
            device_type="AMD"
        elif echo "$device" | grep -qi "nvidia.*10de"; then
            device_type="NVIDIA"
        elif echo "$device" | grep -qi "1234:1111"; then
            device_type="QEMU虚拟显卡"
        elif echo "$device" | grep -qi "virtio"; then
            device_type="VirtIO虚拟显卡"
        elif echo "$device" | grep -qi "vmware"; then
            device_type="VMware虚拟显卡"
        fi

        if [[ -n "$device_desc" ]]; then
            echo -e "  ${gl_lv}GPU-$((i + 1))${gl_bai} [$device_type]: $device_desc"
        else
            echo -e "  ${gl_lv}GPU-$((i + 1))${gl_bai} [$device_type]: $device"
        fi

        # 根据优先级选择主GPU（物理GPU优先于虚拟GPU）
        if [[ "$device_type" == "Intel" && "$primary_vendor" != "Intel" ]]; then
            primary_vendor="Intel"
            primary_id="$device_id"
        elif [[ "$device_type" == "AMD" && "$primary_vendor" != "Intel" && "$primary_vendor" != "AMD" ]]; then
            primary_vendor="AMD"
            primary_id="$device_id"
        elif [[ "$device_type" == "NVIDIA" && "$primary_vendor" != "Intel" && "$primary_vendor" != "AMD" && "$primary_vendor" != "NVIDIA" ]]; then
            primary_vendor="NVIDIA"
            primary_id="$device_id"
        elif [[ "$device_type" == *"虚拟"* && -z "$primary_vendor" ]]; then
            primary_vendor="Virtual"
            primary_id="$device_id"
        fi
    done
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 如果没有检测到已知厂商，使用第一个GPU
    if [[ "$primary_vendor" == "Unknown" && ${#gpu_list[@]} -gt 0 ]]; then
        primary_vendor="Other"
        primary_id=$(echo "${gpu_list[0]}" | awk '{print $1}')
        log_warn "无法识别GPU厂商，使用第一个设备: $primary_id"
    fi

    # 设置驱动类型
    case "$primary_vendor" in
    "Intel") driver="i915/xe" ;;
    "AMD") driver="amdgpu" ;;
    "NVIDIA") driver="nvidia" ;;
    "Virtual") driver="virtio-gpu/qxl" ;;
    *) driver="unknown" ;;
    esac

    echo "$primary_vendor|$driver|$primary_id"
}

# GPU检测主函数
fnos_check_gpu_info() {
    is_fnos_system || return 1  # 非FnOS退出
    clear
    echo -e "${gl_zi}>>> GPU硬件信息检测${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查lspci命令
    if ! command -v lspci &>/dev/null; then
        log_info "安装pciutils工具 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        apt-get install -y pciutils 2>/dev/null || {
            log_error "无法安装pciutils，请手动安装：apt-get install pciutils"
            exit_animation    # 即将退出动画
            return 1
        }
    fi

    # 检测GPU厂商
    local gpu_info
    gpu_info=$(detect_primary_gpu 2>&1)

    if [[ -z "$gpu_info" || "$gpu_info" == *"未检测到GPU设备"* ]]; then
        log_error "无法检测GPU信息"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 提取主GPU信息（最后一行）
    local primary_info=$(echo "$gpu_info" | tail -1)
    local vendor=$(echo "$primary_info" | cut -d'|' -f1)
    local driver=$(echo "$primary_info" | cut -d'|' -f2)
    local gpu_id=$(echo "$primary_info" | cut -d'|' -f3)

    log_info "主GPU厂商: ${gl_lv}${vendor}${gl_bai}"
    if [[ -n "$gpu_id" ]]; then
        log_info "设备ID: $gpu_id"
    fi

    # 驱动检测
    echo ""
    echo -e "${gl_zi}>>> 驱动状态检测${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    case $vendor in
    "Intel")
        if lsmod | grep -q "^i915"; then
            log_ok "Intel i915 驱动已加载"
        elif lsmod | grep -q "^xe"; then
            log_ok "Intel Xe 驱动已加载"
        else
            log_warn "Intel驱动未加载，尝试加载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            if modprobe i915 2>/dev/null; then
                log_ok "Intel i915 驱动加载成功"
            elif modprobe xe 2>/dev/null; then
                log_ok "Intel Xe 驱动加载成功"
            else
                log_error "Intel驱动加载失败"
                log_info "尝试安装Intel驱动: apt-get install -y xserver-xorg-video-intel"
            fi
        fi
        ;;
    "AMD")
        if lsmod | grep -q "^amdgpu"; then
            log_ok "AMD amdgpu 驱动已加载"
        elif lsmod | grep -q "^radeon"; then
            log_warn "使用旧版radeon驱动"
        else
            log_warn "AMD驱动未加载，尝试加载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            if modprobe amdgpu 2>/dev/null; then
                log_ok "amdgpu驱动加载成功"
            elif modprobe radeon 2>/dev/null; then
                log_warn "radeon驱动加载成功"
            else
                log_error "AMD驱动加载失败"
            fi
        fi
        ;;
    "NVIDIA")
        if lsmod | grep -q "^nvidia_drm"; then
            log_ok "NVIDIA DRM驱动已加载"
        elif lsmod | grep -q "^nvidia"; then
            log_ok "NVIDIA闭源驱动已加载"
        elif lsmod | grep -q "^nouveau"; then
            log_warn "使用开源nouveau驱动（性能受限）"
        else
            log_warn "尝试加载NVIDIA开源驱动 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            if modprobe nouveau 2>/dev/null; then
                log_ok "nouveau驱动加载成功"
            else
                log_error "未检测到NVIDIA驱动"
                log_info "安装闭源驱动: apt-get install -y nvidia-driver"
            fi
        fi
        ;;
    "Virtual")
        if lsmod | grep -qE "virtio_gpu|qxl|vmwgfx|bochs_drm"; then
            log_ok "虚拟显卡驱动已加载"
        else
            log_warn "尝试加载虚拟显卡驱动 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            for drv in virtio_gpu qxl vmwgfx bochs_drm; do
                if modprobe "$drv" 2>/dev/null; then
                    log_ok "$drv 驱动加载成功"
                    break
                fi
            done
        fi
        ;;
    *)
        log_warn "未知显卡类型，尝试检测通用DRM驱动"
        if lsmod | grep -q "^drm"; then
            log_ok "DRM驱动已加载"
        else
            log_error "未检测到DRM驱动"
        fi
        ;;
    esac

    # DRI设备检查
    echo ""
    echo -e "${gl_zi}>>> DRI设备状态${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if [[ -d "/dev/dri" ]]; then
        echo -e "${gl_lv}DRI设备列表:${gl_bai}"
        ls -la /dev/dri/ 2>/dev/null | while read -r line; do
            echo "  $line"
        done

        # 检查渲染节点
        local render_nodes=()
        for node in /dev/dri/renderD* /dev/dri/card*; do
            [[ -e "$node" ]] && render_nodes+=("$node")
        done

        if [[ ${#render_nodes[@]} -gt 0 ]]; then
            log_ok "检测到 ${#render_nodes[@]} 个DRI设备"
            for node in "${render_nodes[@]}"; do
                echo -e "  ${gl_lv}✓${gl_bai} $node"
            done
        else
            log_warn "未找到DRI渲染节点"
        fi
    else
        log_error "/dev/dri 目录不存在，内核可能未启用DRM"
        log_info "尝试创建DRI设备节点 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        mkdir -p /dev/dri
        mknod /dev/dri/renderD128 c 226 128 2>/dev/null && chmod 666 /dev/dri/renderD128
    fi

    # 安装检测工具
    echo ""
    echo -e "${gl_zi}>>> 安装检测工具${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if command -v apt-get &>/dev/null; then
        log_info "正在更新软件源 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        apt-get update -qq 2>/dev/null || apt-get update

        log_info "安装基础工具 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        local packages="vainfo mesa-utils ffmpeg"
        if ! dpkg -l | grep -q "vainfo\|mesa-utils\|ffmpeg"; then
            apt-get install -y -qq $packages 2>/dev/null || apt-get install -y $packages
            log_ok "基础工具安装完成"
        else
            log_ok "基础工具已安装"
        fi

        # 厂商特定工具
        case $vendor in
        "Intel")
            if ! dpkg -l | grep -q "intel-gpu-tools"; then
                log_info "安装Intel专用工具 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                apt-get install -y -qq intel-gpu-tools 2>/dev/null ||
                    apt-get install -y intel-gpu-tools
            fi
            ;;
        "AMD")
            if ! dpkg -l | grep -q "radeontop"; then
                log_info "安装AMD专用工具 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                apt-get install -y -qq radeontop mesa-va-drivers 2>/dev/null ||
                    apt-get install -y radeontop
            fi
            ;;
        "NVIDIA")
            if ! dpkg -l | grep -q "nvtop"; then
                log_info "安装NVIDIA监控工具 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                apt-get install -y -qq nvtop 2>/dev/null || log_warn "nvtop安装失败"
            fi
            ;;
        esac
    else
        log_warn "非APT系统，跳过自动安装工具"
        log_info "请手动安装: vainfo mesa-utils ffmpeg"
    fi

    # VA-API检测
    echo ""
    echo -e "${gl_zi}>>> VA-API硬解支持${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if command -v vainfo &>/dev/null; then
        # 设置Intel iHD驱动
        export LIBVA_DRIVER_NAME=iHD
        local vainfo_output
        vainfo_output=$(vainfo 2>&1)

        # 检查VA-API是否正常工作
        if echo "$vainfo_output" | grep -q "libva info" && ! echo "$vainfo_output" | grep -q "Failed to initialize"; then
            log_info "VA-API版本信息:"
            echo "$vainfo_output" | grep -E "(VA-API version|libva|driver version|Driver version)" | head -5 | sed 's/^/  /'
            echo ""

            # 获取编码能力
            log_info "支持的编码器:"
            local encode_profiles
            encode_profiles=$(echo "$vainfo_output" | grep -i "VAProfile.*Enc" | sort -u)
            if [[ -n "$encode_profiles" ]]; then
                echo "$encode_profiles" | head -15 | sed 's/^/  /'
            else
                log_warn "未检测到编码器支持"
            fi

            echo ""

            # 检查Intel iHD驱动
            if echo "$vainfo_output" | grep -q "iHD_drv_video"; then
                log_ok "检测到Intel iHD驱动，适用于11代及以上CPU"

                # 测试i965驱动作为备用
                export LIBVA_DRIVER_NAME=i965
                local i965_output
                i965_output=$(vainfo 2>&1)
                if echo "$i965_output" | grep -q "VAProfile"; then
                    log_info "Intel i965驱动也可用（适用于较老CPU）"
                fi
                export LIBVA_DRIVER_NAME=iHD
            fi
        else
            log_error "VA-API初始化失败"
            echo "$vainfo_output" | head -10 | sed 's/^/  /'

            # 尝试使用不同的驱动
            log_info "尝试切换VA-API驱动 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            for driver in iHD i965 radeonsi; do
                export LIBVA_DRIVER_NAME=$driver
                local test_output
                test_output=$(vainfo 2>&1)
                if echo "$test_output" | grep -q "VAProfile"; then
                    log_ok "找到可用的VA-API驱动: $driver"
                    break
                fi
            done
        fi
    else
        log_error "vainfo未安装，无法检测VA-API"
    fi

    # FFmpeg硬解检测
    echo ""
    echo -e "${gl_zi}>>> FFmpeg硬件加速${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if command -v ffmpeg &>/dev/null; then
        local ffmpeg_version
        ffmpeg_version=$(ffmpeg -version 2>&1 | head -1 | awk '{print $3}')
        log_info "FFmpeg版本: ${ffmpeg_version}"
        echo ""

        # 硬件加速方法
        log_info "可用的硬件加速方法:"
        local hwaccels_output
        hwaccels_output=$(ffmpeg -hwaccels 2>&1)
        if echo "$hwaccels_output" | grep -q "Hardware acceleration methods:"; then
            echo "$hwaccels_output" | grep -A 10 "Hardware acceleration methods:" | tail -n +2 | while read -r line; do
                if [[ -n "$line" ]]; then
                    echo -e "  ${gl_lv}✓${gl_bai} $line"
                fi
            done
        else
            echo -e "  ${gl_huang}无硬件加速支持${gl_bai}"
        fi
        echo ""

        # 硬件编码器检测
        log_info "硬件编码器:"
        local encoders_output
        encoders_output=$(ffmpeg -encoders 2>&1)

        if [[ "$vendor" == "Intel" ]]; then
            echo "$encoders_output" | grep -i "qsv" | grep -E "(h264|hevc|av1|vp9|mpeg2|mjpeg)" | head -10 | sed 's/^/  /'
        elif [[ "$vendor" == "AMD" ]]; then
            echo "$encoders_output" | grep -i "vaapi" | grep -E "(h264|hevc|av1|vp9)" | head -10 | sed 's/^/  /'
        elif [[ "$vendor" == "NVIDIA" ]]; then
            echo "$encoders_output" | grep -i "nvenc" | head -10 | sed 's/^/  /'
        elif [[ "$vendor" == "Virtual" ]]; then
            echo -e "  ${gl_huang}虚拟显卡不支持硬件编码${gl_bai}"
        else
            # 通用检测
            local hw_encoders
            hw_encoders=$(echo "$encoders_output" | grep -i "vaapi\|qsv\|nvenc\|cuvid\|vdpau" | head -10)
            if [[ -n "$hw_encoders" ]]; then
                echo "$hw_encoders" | sed 's/^/  /'
            else
                echo -e "  ${gl_huang}未检测到硬件编码器${gl_bai}"
            fi
        fi
    else
        log_error "FFmpeg未安装"
    fi

    # 厂商特定检测
    echo ""
    echo -e "${gl_zi}>>> ${vendor} GPU详细信息${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    case $vendor in
    "Intel")
        # 检查Intel GPU工具
        if command -v intel_gpu_top &>/dev/null; then
            log_info "运行GPU监控(3秒) ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            timeout 3 intel_gpu_top -L 1 2>/dev/null | head -20 || log_warn "无法读取GPU状态"
        elif command -v intel_gpu_frequency &>/dev/null; then
            log_info "GPU频率:"
            intel_gpu_frequency 2>/dev/null | head -3 | sed 's/^/  /'
        else
            log_warn "安装intel-gpu-tools可实时监控GPU"
        fi

        # 检查Intel GPU信息
        if [[ -d "/sys/class/drm" ]]; then
            log_info "Intel GPU设备信息:"
            for card in /sys/class/drm/card*; do
                if [[ -f "$card/device/vendor" ]] && grep -q "0x8086" "$card/device/vendor" 2>/dev/null; then
                    echo -e "  ${gl_lv}设备:${gl_bai} ${card##*/}"
                    if [[ -f "$card/device/device" ]]; then
                        local device_id
                        device_id=$(cat "$card/device/device" 2>/dev/null)
                        # 去掉前导0x（如果存在）
                        device_id=${device_id#0x}
                        echo -e "  设备ID: 0x${device_id}"
                    fi
                    if [[ -f "$card/device/revision" ]]; then
                        local revision
                        revision=$(cat "$card/device/revision" 2>/dev/null)
                        revision=${revision#0x}
                        echo -e "  修订版本: 0x${revision}"
                    fi
                    # 获取设备名称
                    if [[ -f "$card/device/uevent" ]]; then
                        local product_name
                        product_name=$(grep "PRODUCT=" "$card/device/uevent" 2>/dev/null | cut -d= -f2)
                        if [[ -n "$product_name" ]]; then
                            echo -e "  产品型号: $product_name"
                        fi
                    fi
                    break
                fi
            done
        fi
        ;;
    "AMD")
        if command -v radeontop &>/dev/null; then
            log_ok "AMD GPU监控可用: sudo radeontop"
        else
            log_warn "安装radeontop可监控AMD GPU"
        fi
        if [[ -f "/sys/kernel/debug/dri/0/amdgpu_gpu_info" ]]; then
            log_info "GPU信息:"
            head -10 /sys/kernel/debug/dri/0/amdgpu_gpu_info 2>/dev/null | sed 's/^/  /'
        elif [[ -f "/sys/class/drm/card0/device/gpu_busy_percent" ]]; then
            log_info "GPU利用率: $(cat /sys/class/drm/card0/device/gpu_busy_percent 2>/dev/null)%"
        fi
        ;;
    "NVIDIA")
        if command -v nvidia-smi &>/dev/null; then
            log_info "NVIDIA GPU信息:"
            nvidia-smi -L 2>/dev/null | sed 's/^/  /'
            echo ""
            nvidia-smi --query-gpu=name,driver_version,temperature.gpu,utilization.gpu --format=csv 2>/dev/null | sed 's/^/  /'
        elif command -v nvtop &>/dev/null; then
            log_ok "使用nvtop监控NVIDIA GPU"
        else
            log_warn "NVIDIA驱动未安装或nvidia-smi不可用"
        fi
        ;;
    "Virtual")
        log_info "虚拟显卡信息:"
        if [[ -d "/sys/class/drm" ]]; then
            ls /sys/class/drm/ 2>/dev/null | grep "^card" | while read -r card; do
                if [[ -f "/sys/class/drm/$card/device/vendor" ]]; then
                    local vendor_id
                    vendor_id=$(cat "/sys/class/drm/$card/device/vendor" 2>/dev/null)
                    case "$vendor_id" in
                    "0x1234") echo -e "  ${card}: QEMU虚拟显卡" ;;
                    "0x1af4") echo -e "  ${card}: VirtIO虚拟显卡" ;;
                    "0x15ad") echo -e "  ${card}: VMware虚拟显卡" ;;
                    *) echo -e "  ${card}: 未知虚拟显卡 (Vendor: ${vendor_id})" ;;
                    esac
                fi
            done
        fi
        ;;
    *)
        log_info "系统显卡信息:"
        if [[ -d "/sys/class/drm" ]]; then
            echo -e "${gl_lv}DRM设备:${gl_bai}"
            ls /sys/class/drm/ 2>/dev/null | while read -r card; do
                echo "  $card"
            done
        fi
        ;;
    esac

    # 权限配置
    echo ""
    echo -e "${gl_zi}>>> 权限配置${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    local current_user
    current_user="${SUDO_USER:-$USER}"

    if [[ "$current_user" == "root" ]]; then
        log_warn "当前是root用户，跳过权限配置"
        log_info "请为运行容器的非root用户配置权限"
    else
        log_info "当前用户: ${current_user}"

        # 检查video组
        if ! groups "$current_user" | grep -q "video"; then
            if usermod -aG video "$current_user" 2>/dev/null; then
                log_ok "已添加到video组"
            else
                log_error "添加video组失败"
            fi
        else
            log_ok "已在video组"
        fi

        # 检查render组
        if getent group render >/dev/null 2>&1; then
            if ! groups "$current_user" | grep -q "render"; then
                if usermod -aG render "$current_user" 2>/dev/null; then
                    log_ok "已添加到render组"
                else
                    log_error "添加render组失败"
                fi
            else
                log_ok "已在render组"
            fi
        fi

        # NVIDIA组
        if [[ "$vendor" == "NVIDIA" ]] && getent group nvidia >/dev/null 2>&1; then
            if ! groups "$current_user" | grep -q "nvidia"; then
                if usermod -aG nvidia "$current_user" 2>/dev/null; then
                    log_ok "已添加到nvidia组"
                fi
            fi
        fi
    fi

    # 检查DRI设备权限
    if [[ -d "/dev/dri" ]]; then
        echo ""
        log_info "DRI设备权限:"
        ls -la /dev/dri/ | grep -E "card|render" | while read -r line; do
            echo "  $line"
        done
    fi

    log_warn "重新登录后权限生效"

    # 优化建议
    echo ""
    echo -e "${gl_zi}>>> 优化建议${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    case $vendor in
    "Intel")
        echo -e "${gl_lv}✅ Intel Alder Lake-N (Gen12) GPU检测完成${gl_bai}"
        echo ""
        echo -e "${gl_lv}硬件加速配置:${gl_bai}"
        echo "  • Docker硬解参数: --device /dev/dri:/dev/dri"
        echo "  • 环境变量: -e LIBVA_DRIVER_NAME=iHD (推荐) 或 i965"
        echo "  • Jellyfin/Plex设置: 硬件加速选 'Intel QuickSync (QSV)'"
        echo "  • 备用方案: VA-API（如果QSV有问题）"
        echo ""
        echo -e "${gl_lv}支持的编码格式:${gl_bai}"
        echo "  • H.264/AVC (h264_qsv)"
        echo "  • H.265/HEVC (hevc_qsv)"
        echo "  • VP9 (vp9_qsv)"
        echo "  • MPEG-2 (mpeg2_qsv)"
        echo "  • MJPEG (mjpeg_qsv)"
        echo ""
        echo -e "${gl_lv}监控命令:${gl_bai}"
        echo "  • sudo intel_gpu_top"
        echo "  • vainfo (查看VA-API状态)"
        echo "  • ffmpeg -hwaccels (查看硬件加速方法)"
        echo ""
        echo -e "${gl_lv}QSV测试命令:${gl_bai}"
        echo "  ffmpeg -hwaccel qsv -c:v h264_qsv -i input.mp4 -f null -"
        ;;
    "AMD")
        echo -e "${gl_lv}AMD GPU优化建议:${gl_bai}"
        echo "  • Docker硬解参数: --device /dev/dri:/dev/dri"
        echo "  • Jellyfin/Plex设置: 硬件加速选 'VA-API'"
        echo "  • 环境变量: -e LIBVA_DRIVER_NAME=radeonsi"
        echo "  • 注意: 较新的AMD GPU需要mesa 22.0+"
        echo "  • 监控命令: sudo radeontop"
        ;;
    "NVIDIA")
        echo -e "${gl_lv}NVIDIA GPU优化建议:${gl_bai}"
        echo "  • Docker硬解参数: --gpus all (需nvidia-docker2)"
        echo "  • Jellyfin/Plex设置: 硬件加速选 'NVIDIA NVENC'"
        echo "  • 需要: 安装NVIDIA闭源驱动和CUDA工具包"
        echo "  • 监控命令: nvidia-smi 或 nvtop"
        echo "  • 注意: 确保NVIDIA驱动版本与CUDA兼容"
        ;;
    "Virtual")
        echo -e "${gl_huang}虚拟显卡说明:${gl_bai}"
        echo "  • 检测到QEMU虚拟显卡 (1234:1111)"
        echo "  • 虚拟显卡不支持硬件视频编解码"
        echo "  • 系统同时检测到Intel集成显卡 (8086:46d1)"
        echo "  • 建议: 在虚拟机设置中直通Intel GPU以获得硬解能力"
        echo "  • 当前仅支持CPU软解"
        echo ""
        echo -e "${gl_lv}虚拟机GPU直通建议:${gl_bai}"
        echo "  1. 在宿主机上启用Intel GVT-g或完整GPU直通"
        echo "  2. 将Intel GPU设备直通到虚拟机"
        echo "  3. 在虚拟机中安装Intel显卡驱动"
        ;;
    *)
        echo -e "${gl_huang}通用建议:${gl_bai}"
        echo "  • 检查内核是否启用DRM和GPU驱动"
        echo "  • 安装mesa驱动包: apt-get install mesa-utils"
        echo "  • 确保/dev/dri设备存在且有正确权限"
        ;;
    esac

    echo ""

    # 根据检测到的GPU提供配置建议
    if [[ "$vendor" == "Intel" ]]; then
        echo -e "${gl_lv}📦 Intel Docker硬解配置示例:${gl_bai}"
        echo ""
        echo -e "${gl_lv}Jellyfin配置:${gl_bai}"
        echo "  docker run -d \\"
        echo "    --name jellyfin \\"
        echo "    --device /dev/dri:/dev/dri \\"
        echo "    -e LIBVA_DRIVER_NAME=iHD \\"
        echo "    -e PUID=1000 \\"
        echo "    -e PGID=1000 \\"
        echo "    -p 8096:8096 \\"
        echo "    jellyfin/jellyfin:latest"
    else
        echo -e "${gl_lv}通用Docker硬解配置:${gl_bai}"
        echo "  docker run -d \\"
        echo "    --name media-server \\"
        echo "    --device /dev/dri:/dev/dri \\"
        echo "    -e PUID=1000 \\"
        echo "    -e PGID=1000 \\"
        echo "    -p 8096:8096 \\"
        echo "    jellyfin/jellyfin:latest"
    fi

    echo ""
    echo -e "${gl_huang}⚠️ 注意事项:${gl_bai}"
    echo "  1. 确保容器内用户有访问/dev/dri的权限"
    echo "  2. 检查Docker用户映射(PUID/PGID)"
    echo "  3. 媒体服务器软件需要支持相应硬解"
    echo "  4. 检查内核模块是否正确加载"
    echo "  5. 重新登录后权限变更生效"
    echo ""

    log_ok "✅ GPU检测完成！"
    echo -e "${gl_zi}检测时间: $(date)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 函数：清理错误内核
fnos_clean_broken_kernels() {
    is_fnos_system || return 1  # 非FnOS退出
    clear
    echo -e "${gl_zi}>>> 开始检测并清理错误内核${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_huang}update-initramfs ${gl_bai}输出："

    # 运行 update-initramfs 并捕获输出
    local output
    output=$(sudo update-initramfs -u -k all 2>&1)

    # 显示原始输出
    echo "$output"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 提取缺失模块目录的内核版本（如 6.1.0-43-amd64）
    local missing_kernels
    missing_kernels=$(echo "$output" | grep -oP 'missing /lib/modules/\K[0-9a-z.-]+' | sort -u)

    # 提取 depmod 错误中的内核版本
    local depmod_errors
    depmod_errors=$(echo "$output" | grep -oP 'could not open directory /lib/modules/\K[0-9a-z.-]+' | sort -u)

    # 合并并去重
    local broken_kernels
    broken_kernels=$(printf "%s\n%s" "$missing_kernels" "$depmod_errors" | grep -v '^$' | sort -u)

    if [ -z "$broken_kernels" ]; then
        log_ok "没有发现错误内核，系统干净"
        exit_animation    # 即将退出动画
        return 0
    fi

    log_info "发现以下错误内核需要清理："
    echo "$broken_kernels"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 遍历清理每个错误内核
    while IFS= read -r kernel; do
        [ -z "$kernel" ] && continue

        echo -e "${gl_zi}>>> 正在清理内核: $kernel${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 1. 删除 /boot 中的相关文件
        log_info "删除 /boot 文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        sudo rm -f "/boot/initrd.img-${kernel}"* 2>/dev/null && log_ok "已删除 initrd.img-${kernel}"
        sudo rm -f "/boot/vmlinuz-${kernel}"* 2>/dev/null && log_ok "已删除 vmlinuz-${kernel}"
        sudo rm -f "/boot/System.map-${kernel}"* 2>/dev/null && log_ok "已删除 System.map-${kernel}"
        sudo rm -f "/boot/config-${kernel}"* 2>/dev/null && log_ok "已删除 config-${kernel}"

        # 2. 删除 /lib/modules 目录
        if [ -d "/lib/modules/${kernel}" ]; then
            log_info "删除 /lib/modules/${kernel} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            sudo rm -rf "/lib/modules/${kernel}" && log_ok "已删除 /lib/modules/${kernel}"
        else
            log_warn "/lib/modules/${kernel} 目录不存在"
        fi

        # 3. 尝试卸载对应的包（如果存在）
        local pkg_name="linux-image-${kernel}"
        if dpkg -l | grep -q "^ii  ${pkg_name} "; then
            log_info "卸载包 ${pkg_name} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            if sudo apt remove --purge "${pkg_name}" -y --allow-change-held-packages 2>/dev/null; then
                log_ok "成功卸载包 ${pkg_name}"
            elif sudo dpkg --remove --force-remove-reinstreq "${pkg_name}" 2>/dev/null; then
                log_ok "强制卸载包 ${pkg_name}"
            else
                log_warn "无法卸载包 ${pkg_name}，可能已被保留(hold)"
            fi
        fi

        # 4. 清理该内核的配置残留
        if dpkg -l | grep -q "^rc  ${pkg_name} "; then
            log_info "清除配置残留 ${pkg_name} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            sudo dpkg --purge "${pkg_name}" 2>/dev/null && log_ok "已清除配置残留"
        fi

        log_ok "内核 $kernel 清理完成"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    done <<<"$broken_kernels"

    # 5. 清理其他残留
    log_info "清理系统残留 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    sudo apt autoremove -y 2>/dev/null && log_ok "已清理无用依赖"
    sudo apt autoclean 2>/dev/null && log_ok "已清理软件包缓存"

    # 6. 清理临时文件
    log_info "清理临时文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    sudo rm -rf /var/tmp/mkinitramfs_* 2>/dev/null && log_ok "已清理临时文件"

    # 7. 更新 grub
    log_info "更新 GRUB ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    sudo update-grub && log_ok "GRUB 更新完成"

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_zi}>>> 重新生成 initramfs 验证${gl_bai}"
    sudo update-initramfs -u -k all

    log_ok "清理完成"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 函数：修复固件缺失错误
fnos_handle_firmware_missing() {
    is_fnos_system || return 1  # 非FnOS退出
    clear
    echo -e "${gl_zi}>>> 修复固件缺失错误${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_huang}update-initramfs ${gl_bai}输出："
    local cmd_output
    cmd_output=$(sudo update-initramfs -u -k all 2>&1)
    local exit_status=$?

    # 显示原始命令输出
    echo "$cmd_output"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查是否存在固件缺失警告
    local has_bxtg_error=$(echo "$cmd_output" | grep -c "Possible missing firmware /lib/firmware/i915/bxtg_dmc.bin for module i915")
    local has_skl_error=$(echo "$cmd_output" | grep -c "Possible missing firmware /lib/firmware/i915/skl_guc.bin for module i915")

    if [ $has_bxtg_error -gt 0 ] || [ $has_skl_error -gt 0 ]; then
        log_warn "检测到固件文件缺失警告"

        echo -e "${gl_zi}>>> 固件缺失问题处理${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 定义默认链接（基于您提供的有效链接）
        local default_url_bmg="http://10.10.10.251:5000/file/myfile/fnos/i915/bmg_dmc.bin"
        local default_url_skl="http://10.10.10.251:5000/file/myfile/fnos/i915/skl_guc.bin"

        # 处理 bxtg_dmc.bin 错误（使用 bmg_dmc.bin 链接）
        if [ $has_bxtg_error -gt 0 ]; then
            log_info "需要处理固件: bxtg_dmc.bin"
            log_info "将使用 bmg_dmc.bin 替代下载"
            log_info "默认下载链接: ${default_url_bmg}"
            log_info "目标保存路径: /lib/firmware/i915/bmg_dmc.bin"
            echo ""

            read -r -e -p "$(echo -e "${gl_bai}是否使用默认链接下载? (${gl_lv}Y${gl_bai}/${gl_hong}n${gl_bai}/${gl_huang}0${gl_bai}返回): ")" choice_bmg

            case "$choice_bmg" in
            [yY] | "")
                log_info "正在使用默认链接下载 bmg_dmc.bin ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                if sudo wget -O /lib/firmware/i915/bmg_dmc.bin "$default_url_bmg"; then
                    log_ok "bmg_dmc.bin 下载完成并已保存"
                else
                    log_error "bmg_dmc.bin 下载失败，请检查网络或链接"
                fi
                ;;
            [nN])
                read -r -e -p "$(echo -e "${gl_bai}请输入自定义下载链接 (${gl_huang}0${gl_bai}返回): ")" custom_url_bmg
                if [[ "$custom_url_bmg" != "0" ]] && [[ -n "$custom_url_bmg" ]]; then
                    log_info "正在使用自定义链接下载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    if sudo wget -O /lib/firmware/i915/bmg_dmc.bin "$custom_url_bmg"; then
                        log_ok "文件下载完成"
                    else
                        log_error "下载失败"
                    fi
                else
                    log_info "已返回，未下载"
                fi
                ;;
            0)
                log_info "已返回，跳过下载"
                ;;
            *)
                log_warn "无效输入，跳过下载"
                ;;
            esac

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        fi

        # 处理 skl_guc.bin 错误
        if [ $has_skl_error -gt 0 ]; then
            log_info "需要处理固件: skl_guc.bin"
            log_info "默认下载链接: ${default_url_skl}"
            log_info "目标保存路径: /lib/firmware/i915/skl_guc.bin"
            echo ""

            read -r -e -p "$(echo -e "${gl_bai}是否使用默认链接下载? (${gl_lv}Y${gl_bai}/${gl_hong}n${gl_bai}/${gl_huang}0${gl_bai}返回): ")" choice_skl

            case "$choice_skl" in
            [yY] | "")
                log_info "正在使用默认链接下载 skl_guc.bin ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                if sudo wget -O /lib/firmware/i915/skl_guc.bin "$default_url_skl"; then
                    log_ok "skl_guc.bin 下载完成并已保存"
                else
                    log_error "skl_guc.bin 下载失败，请检查网络或链接"
                fi
                ;;
            [nN])
                read -r -e -p "$(echo -e "${gl_bai}请输入自定义下载链接 (${gl_huang}0${gl_bai}返回): ")" custom_url_skl
                if [[ "$custom_url_skl" != "0" ]] && [[ -n "$custom_url_skl" ]]; then
                    log_info "正在使用自定义链接下载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    if sudo wget -O /lib/firmware/i915/skl_guc.bin "$custom_url_skl"; then
                        log_ok "文件下载完成"
                    else
                        log_error "下载失败"
                    fi
                else
                    log_info "已返回，未下载"
                fi
                ;;
            0)
                log_info "已返回，跳过下载"
                ;;
            *)
                log_warn "无效输入，跳过下载"
                ;;
            esac

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        fi

        # 下载完成后，重新运行 update-initramfs
        log_info "重新运行 update-initramfs 验证修复 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        sudo update-initramfs -u -k all

    else
        # 如果没有检测到固件缺失错误
        if [ $exit_status -eq 0 ]; then
            log_ok "update-initramfs 执行成功，未发现固件缺失错误"
        else
            log_error "update-initramfs 执行失败，错误代码: $exit_status"
        fi
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 文件重命名排序函数
file_rename_sorter() {
    # 默认前缀
    local default_prefix="$1"
    if [[ -z "$default_prefix" ]]; then
        default_prefix="pc"
    fi

    # 文件类型
    local file_type="$2"
    if [[ -z "$file_type" ]]; then
        file_type="webp"
    fi

    # 交互式输入前缀
    echo ""
    echo -e "${gl_zi}>>> 修改文件名前缀 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请输入文件名前缀（默认 ${gl_lv}$default_prefix${gl_bai}）: ")" prefix

    if [[ -z "$prefix" ]]; then
        prefix="$default_prefix"
    fi
    log_info "正在使用前缀: ${gl_lv}$prefix${gl_bai}"

    # 设置起始编号
    local counter=1
    local temp_folder="temp_rename_folder_$RANDOM"
    local processed_count=0
    local final_count=0

    # 检查是否有指定类型的文件
    shopt -s nullglob nocaseglob
    local files=(*.$file_type)

    if [[ ${#files[@]} -eq 0 ]]; then
        echo -e "${gl_huang}当前目录中没有找到 ${gl_bai}.${gl_lv}$file_type ${gl_huang}文件"
        exit_animation    # 即将退出动画
        return 1
    fi

    log_info "找到 ${#files[@]} 个 .$file_type 文件"

    # 创建临时文件夹
    if ! mkdir -p "$temp_folder" 2>/dev/null; then
        log_error "无法创建临时文件夹"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 安全移动文件到临时文件夹
    echo ""
    log_info "正在移动文件到临时文件夹 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    for file in "${files[@]}"; do
        if [[ -f "$file" ]]; then
            if mv -n "$file" "$temp_folder/" 2>/dev/null; then
                ((processed_count++))
                echo -e "  ${gl_huang}[$processed_count/${#files[@]}]${gl_bai} 已移动: ${gl_lv}$file${gl_bai}"
            else
                log_warn "移动失败: $file"
            fi
        fi
    done

    # 检查是否成功移动了文件
    shopt -s nullglob nocaseglob
    local moved_files=("$temp_folder"/*.$file_type)
    if [[ ${#moved_files[@]} -eq 0 ]]; then
        log_warn "没有文件被移动到临时文件夹"
        rm -rf "$temp_folder" 2>/dev/null
        exit_animation    # 即将退出动画
        return 1
    fi

    # 按顺序重命名文件
    echo ""
    log_info "正在重命名文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    local rename_counter=1
    for old_path in "${moved_files[@]}"; do
        local file=$(basename "$old_path")

        # 生成新文件名（三位数编号自动补零）
        local new_file=$(printf "%s-%03d.$file_type" "$prefix" "$rename_counter")

        # 执行重命名并移动
        echo -e "  ${gl_huang}[$rename_counter/${#moved_files[@]}]${gl_bai} 重命名: ${gl_lv}$file${gl_bai} → ${gl_lv}$new_file${gl_bai}"

        if mv -n "$old_path" "./$new_file" 2>/dev/null; then
            ((rename_counter++))
        else
            log_error "重命名失败: $file"
        fi
    done

    # 删除临时文件夹
    rm -rf "$temp_folder" 2>/dev/null

    # 执行结果报告
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    final_count=$((rename_counter - 1))
    if [[ $final_count -gt 0 ]]; then
        log_ok "文件排序完成！共处理 ${gl_lv}$final_count${gl_bai} 个文件"
        log_info "新文件名格式: ${gl_lv}$prefix-XXX.$file_type${gl_bai}"
    else
        log_warn "没有文件被重命名"
    fi
    return 0
}

# 函数_电脑原图排序
rename_original_images_pc() {
    # 配置区
    local default_prefix="pc"
    local prefix=""
    local processed_files=0
    local success_files=0
    local failed_files=0

    # 支持的图片扩展名
    local image_extensions=("png" "jpg" "jpeg" "webp")

    # 用户输入交互
    read -r -e -p "$(echo -e "${gl_bai}请输入文件名前缀（默认 ${gl_lv}$default_prefix${gl_bai}）: ")" prefix

    if [[ -z "$prefix" ]]; then
        prefix="$default_prefix"
        log_info "使用默认前缀: ${gl_lv}$prefix${gl_bai}"
    else
        log_info "正在使用前缀: ${gl_lv}$prefix${gl_bai}"
    fi

    # 创建临时文件夹（使用时间戳+随机数避免冲突）
    local temp_folder="temp_rename_folder_$(date +%s)_$RANDOM"
    log_info "创建临时文件夹: ${gl_lv}$temp_folder${gl_bai}"

    if ! mkdir -p "$temp_folder" 2>/dev/null; then
        log_error "无法创建临时文件夹"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 统计当前目录下的图片文件（不递归子目录）
    local total_count=0
    local files_to_move=()
    for ext in "${image_extensions[@]}"; do
        while IFS= read -r -d '' file; do
            files_to_move+=("$file")
            ((total_count++))
        done < <(find . -maxdepth 1 -type f -iname "*.$ext" -print0 2>/dev/null)
    done

    if [[ $total_count -eq 0 ]]; then
        log_warn "当前目录中没有找到图片文件"
        rm -rf "$temp_folder" 2>/dev/null
        exit_animation    # 即将退出动画
        return 1
    fi

    log_info "找到 ${gl_lv}$total_count${gl_bai} 个图片文件"
    echo ""

    # 移动所有图片文件到临时文件夹
    log_info "正在移动文件到临时文件夹 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    local moved_count=0
    for file in "${files_to_move[@]}"; do
        # 修复：使用完整路径移动到临时文件夹
        if mv -n -- "$file" "$temp_folder/" 2>/dev/null; then
            ((moved_count++))
        else
            log_warn "无法移动文件: ${gl_huang}$(basename "$file")${gl_bai}"
        fi
    done

    if [[ $moved_count -eq 0 ]]; then
        log_warn "没有文件被成功移动"
        rm -rf "$temp_folder" 2>/dev/null
        exit_animation    # 即将退出动画
        return 1
    fi

    log_info "已移动 ${gl_lv}$moved_count${gl_bai} 个文件到临时文件夹"
    echo ""

    # 按修改时间排序并重命名（最旧的文件编号为001）
    log_info "正在重命名文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 修复：获取带完整路径的排序文件列表
    local sorted_files=()
    # 方法1：使用find+stat按修改时间排序
    while IFS= read -r file; do
        [[ -n "$file" ]] && sorted_files+=("$file")
    done < <(find "$temp_folder" -type f -printf '%T@ %p\n' 2>/dev/null | sort -n | cut -d' ' -f2-)

    # 方法2：如果上面的方法失败，尝试备用方法
    if [[ ${#sorted_files[@]} -eq 0 ]]; then
        log_info "使用备用方法获取文件列表 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        while IFS= read -r file; do
            [[ -n "$file" ]] && sorted_files+=("$temp_folder/$file")
        done < <(ls -tr "$temp_folder" 2>/dev/null)
    fi

    if [[ ${#sorted_files[@]} -eq 0 ]]; then
        log_error "无法获取临时文件夹中的文件列表"
        rm -rf "$temp_folder" 2>/dev/null
        exit_animation    # 即将退出动画
        return 1
    fi

    local counter=1
    processed_files=0

    for old_path in "${sorted_files[@]}"; do
        ((processed_files++))

        # 验证文件是否存在
        if [[ ! -f "$old_path" ]]; then
            log_warn "文件不存在: ${gl_huang}$old_path${gl_bai}"
            ((failed_files++))
            continue
        fi

        # 获取原始文件名和扩展名
        local filename=$(basename "$old_path")
        local ext="${filename##*.}"
        ext="${ext,,}" # 转换为小写扩展名

        # 检查扩展名是否在支持的列表中
        local valid_extension=false
        for supported_ext in "${image_extensions[@]}"; do
            if [[ "$ext" == "$supported_ext" ]]; then
                valid_extension=true
                break
            fi
        done

        if [[ "$valid_extension" == "false" ]]; then
            log_warn "跳过不支持的文件类型: ${gl_huang}$filename${gl_bai}"
            ((failed_files++))
            continue
        fi

        # 生成新文件名（三位数编号自动补零）
        local new_filename=$(printf "%s-%03d.%s" "$prefix" "$counter" "$ext")

        # 检查目标文件是否已存在（避免覆盖）
        if [[ -e "./$new_filename" ]]; then
            log_warn "目标文件已存在，跳过: ${gl_huang}$new_filename${gl_bai}"
            ((failed_files++))
            continue
        fi

        # 执行重命名并移动
        echo -e "  ${gl_huang}[$processed_files/$moved_count]${gl_bai} ${gl_lv}$filename${gl_bai} → ${gl_zi}$new_filename${gl_bai}"

        # 修复：使用完整的源文件路径
        if mv -- "$old_path" "./$new_filename" 2>/dev/null; then
            ((counter++))
            ((success_files++))
        else
            log_error "重命名失败: ${gl_hong}$filename${gl_bai}"
            ((failed_files++))
        fi
    done

    # 清理临时文件夹（检查是否为空）
    log_info "正在清理临时文件夹 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if [[ -d "$temp_folder" ]]; then
        # 检查临时文件夹是否还有剩余文件
        local remaining_files=$(ls -A "$temp_folder" 2>/dev/null | wc -l)
        if [[ $remaining_files -gt 0 ]]; then
            log_warn "临时文件夹中还有 ${gl_huang}$remaining_files${gl_bai} 个文件未处理"
            # 可以选择将剩余文件移回原目录
            find "$temp_folder" -type f -exec mv -n -- "{}" ./ \; 2>/dev/null
        fi

        if ! rm -rf "$temp_folder" 2>/dev/null; then
            log_warn "无法删除临时文件夹: ${gl_huang}$temp_folder${gl_bai}"
        fi
    fi

    # 执行结果报告
    echo ""
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if [[ $success_files -gt 0 ]]; then
        log_ok "电脑原图壁纸排序完成！"
        echo ""
        log_info "处理统计:"
        echo -e "  ${gl_lv}✓${gl_bai} 成功重命名: ${gl_lv}$success_files${gl_bai} 个文件"

        if [[ $failed_files -gt 0 ]]; then
            echo -e "  ${gl_hong}✗${gl_bai} 处理失败: ${gl_huang}$failed_files${gl_bai} 个文件"
        fi

        echo ""
        log_info "新文件名格式: ${gl_zi}$prefix-XXX.扩展名${gl_bai}"
        log_info "起始编号: ${gl_lv}001${gl_bai}"
        log_info "排序规则: ${gl_lv}按修改时间从旧到新${gl_bai}（最旧的为001）"
    else
        log_warn "没有文件被成功重命名"

        if [[ $failed_files -gt 0 ]]; then
            log_error "所有 ${gl_hong}$failed_files${gl_bai} 个文件处理失败"
        fi
    fi
}

# 手机原图壁纸排序函数
rename_original_images_phone() {
