# 手机壁纸目录比较函数
compare_phone_directories() {
    # 定义要比较的两个目录
    local dir1="/vol1/1000/compose/random-pic-api/portrait"
    local dir2="/vol2/1000/阿里云盘/教程文件/壁纸原图/手机原图"

    # 定义目录友好名称
    local name1="已处理手机壁纸目录"
    local name2="手机壁纸原图目录"

    # 标题
    echo ""
    echo -e "${gl_zi}>>> 目录对比分析 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 显示比较的目录
    log_info "比较目录:"
    echo -e "  ${gl_bai}${name1} : ${gl_lv}${dir1}${gl_bai}"
    echo -e "  ${gl_bai}${name2} : ${gl_lv}${dir2}${gl_bai}"
    echo ""

    # 检查目录是否存在
    if [[ ! -d "$dir1" ]]; then
        log_error "目录不存在: ${gl_huang}${dir1}${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        return 1
    fi

    if [[ ! -d "$dir2" ]]; then
        log_error "目录不存在: ${gl_huang}${dir2}${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        return 1
    fi

    # 统计目录1的信息
    log_info "正在统计: ${gl_lv}${name1} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    local total_files1=$(find "$dir1" -type f 2>/dev/null | wc -l)
    local total_size_mb1=$(du -sm "$dir1" 2>/dev/null | awk '{print $1}')
    local total_size_gb1=$(echo "scale=2; $total_size_mb1 / 1024" | bc 2>/dev/null || echo "0")

    if [[ -z "$total_files1" ]]; then
        total_files1=0
    fi

    if [[ -z "$total_size_mb1" ]]; then
        total_size_mb1=0
        total_size_gb1=0
    fi

    # 统计目录2的信息
    log_info "正在统计: ${gl_lv}${name2} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    local total_files2=$(find "$dir2" -type f 2>/dev/null | wc -l)
    local total_size_mb2=$(du -sm "$dir2" 2>/dev/null | awk '{print $1}')
    local total_size_gb2=$(echo "scale=2; $total_size_mb2 / 1024" | bc 2>/dev/null || echo "0")

    if [[ -z "$total_files2" ]]; then
        total_files2=0
    fi

    if [[ -z "$total_size_mb2" ]]; then
        total_size_mb2=0
        total_size_gb2=0
    fi

    # 计算差异
    local file_diff=$((total_files1 - total_files2))
    local size_diff_mb=$(echo "$total_size_mb1 - $total_size_mb2" | bc 2>/dev/null || echo "0")
    local size_diff_gb=$(echo "scale=2; $size_diff_mb / 1024" | bc 2>/dev/null || echo "0")

    # 输出结果
    echo ""
    log_info "对比结果 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 文件数量比较
    echo -e "${gl_bai}文件数量对比:${gl_bai}"
    echo -e "  ${name1}: ${gl_lv}$total_files1${gl_bai} 个文件"
    echo -e "  ${name2}: ${gl_lv}$total_files2${gl_bai} 个文件"
    echo ""

    # 文件数量差异消息
    local file_diff_msg=""
    if [[ $total_files1 -gt $total_files2 ]]; then
        file_diff_msg="${name1} 比 ${name2} 多 $file_diff 个文件"
        echo -e "  ${gl_huang}✓ ${file_diff_msg}${gl_bai}"
    elif [[ $total_files1 -lt $total_files2 ]]; then
        file_diff=$((total_files2 - total_files1))
        file_diff_msg="${name2} 比 ${name1} 多 $file_diff 个文件"
        echo -e "  ${gl_huang}✓ ${file_diff_msg}${gl_bai}"
    else
        file_diff_msg="两个目录的文件数量相同"
        echo -e "  ${gl_lv}✓ ${file_diff_msg}${gl_bai}"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 目录大小比较
    echo -e "${gl_bai}目录大小对比:${gl_bai}"
    echo -e "  ${name1}: ${gl_lv}${total_size_mb1}${gl_bai} MB (${gl_lv}${total_size_gb1}${gl_bai} GB)"
    echo -e "  ${name2}: ${gl_lv}${total_size_mb2}${gl_bai} MB (${gl_lv}${total_size_gb2}${gl_bai} GB)"
    echo ""

    # 目录大小差异消息
    local size_diff_msg=""
    if (($(echo "$total_size_mb1 > $total_size_mb2" | bc -l 2>/dev/null || echo "0"))); then
        size_diff_msg="${name1} 比 ${name2} 大 ${size_diff_mb} MB (${size_diff_gb} GB)"
        echo -e "  ${gl_huang}✓ ${size_diff_msg}${gl_bai}"
    elif (($(echo "$total_size_mb1 < $total_size_mb2" | bc -l 2>/dev/null || echo "0"))); then
        size_diff_mb=${size_diff_mb#-}
        size_diff_gb=${size_diff_gb#-}
        size_diff_msg="${name2} 比 ${name1} 大 ${size_diff_mb} MB (${size_diff_gb} GB)"
        echo -e "  ${gl_huang}✓ ${size_diff_msg}${gl_bai}"
    else
        size_diff_msg="两个目录大小相同"
        echo -e "  ${gl_lv}✓ ${size_diff_msg}${gl_bai}"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 总结
    if [[ $total_files1 -eq 0 ]] && [[ $total_files2 -eq 0 ]]; then
        log_warn "两个目录都是空的"
    elif [[ $total_files1 -eq 0 ]]; then
        log_warn "${name1} 是空的"
    elif [[ $total_files2 -eq 0 ]]; then
        log_warn "${name2} 是空的"
    fi

    if [[ $total_files1 -eq $total_files2 ]] && [[ "$total_size_mb1" == "$total_size_mb2" ]]; then
        log_ok "目录完全一致"
    else
        if [[ $total_files1 -eq $total_files2 ]]; then
            log_ok "文件数量一致"
        fi

        if [[ "$total_size_mb1" == "$total_size_mb2" ]]; then
            log_ok "目录大小一致"
        fi
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    return 0
}

# 电脑壁纸目录比较函数
compare_pc_directories() {
    # 定义要比较的两个目录
    local dir1="/vol1/1000/compose/random-pic-api/landscape"
    local dir2="/vol2/1000/阿里云盘/教程文件/壁纸原图/电脑原图"

    # 定义目录友好名称
    local name1="已处理电脑壁纸目录"
    local name2="电脑壁纸原图目录"

    # 标题
    echo ""
    echo -e "${gl_zi}>>> 目录对比分析 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 显示比较的目录
    log_info "比较目录:"
    echo -e "  ${gl_bai}${name1} : ${gl_lv}${dir1}${gl_bai}"
    echo -e "  ${gl_bai}${name2} : ${gl_lv}${dir2}${gl_bai}"
    echo ""

    # 检查目录是否存在
    if [[ ! -d "$dir1" ]]; then
        log_error "目录不存在: ${gl_huang}${dir1}${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        return 1
    fi

    if [[ ! -d "$dir2" ]]; then
        log_error "目录不存在: ${gl_huang}${dir2}${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        return 1
    fi

    # 统计目录1的信息
    log_info "正在统计: ${gl_lv}${name1} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    local total_files1=$(find "$dir1" -type f 2>/dev/null | wc -l)
    local total_size_mb1=$(du -sm "$dir1" 2>/dev/null | awk '{print $1}')
    local total_size_gb1=$(echo "scale=2; $total_size_mb1 / 1024" | bc 2>/dev/null || echo "0")

    if [[ -z "$total_files1" ]]; then
        total_files1=0
    fi

    if [[ -z "$total_size_mb1" ]]; then
        total_size_mb1=0
        total_size_gb1=0
    fi

    # 统计目录2的信息
    log_info "正在统计: ${gl_lv}${name2} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    local total_files2=$(find "$dir2" -type f 2>/dev/null | wc -l)
    local total_size_mb2=$(du -sm "$dir2" 2>/dev/null | awk '{print $1}')
    local total_size_gb2=$(echo "scale=2; $total_size_mb2 / 1024" | bc 2>/dev/null || echo "0")

    if [[ -z "$total_files2" ]]; then
        total_files2=0
    fi

    if [[ -z "$total_size_mb2" ]]; then
        total_size_mb2=0
        total_size_gb2=0
    fi

    # 计算差异
    local file_diff=$((total_files1 - total_files2))
    local size_diff_mb=$(echo "$total_size_mb1 - $total_size_mb2" | bc 2>/dev/null || echo "0")
    local size_diff_gb=$(echo "scale=2; $size_diff_mb / 1024" | bc 2>/dev/null || echo "0")

    # 输出结果
    echo ""
    log_info "对比结果 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 文件数量比较
    echo -e "${gl_bai}文件数量对比:${gl_bai}"
    echo -e "  ${name1}: ${gl_lv}$total_files1${gl_bai} 个文件"
    echo -e "  ${name2}: ${gl_lv}$total_files2${gl_bai} 个文件"
    echo ""

    # 文件数量差异消息
    local file_diff_msg=""
    if [[ $total_files1 -gt $total_files2 ]]; then
        file_diff_msg="${name1} 比 ${name2} 多 $file_diff 个文件"
        echo -e "  ${gl_huang}✓ ${file_diff_msg}${gl_bai}"
    elif [[ $total_files1 -lt $total_files2 ]]; then
        file_diff=$((total_files2 - total_files1))
        file_diff_msg="${name2} 比 ${name1} 多 $file_diff 个文件"
        echo -e "  ${gl_huang}✓ ${file_diff_msg}${gl_bai}"
    else
        file_diff_msg="两个目录的文件数量相同"
        echo -e "  ${gl_lv}✓ ${file_diff_msg}${gl_bai}"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 目录大小比较
    echo -e "${gl_bai}目录大小对比:${gl_bai}"
    echo -e "  ${name1}: ${gl_lv}${total_size_mb1}${gl_bai} MB (${gl_lv}${total_size_gb1}${gl_bai} GB)"
    echo -e "  ${name2}: ${gl_lv}${total_size_mb2}${gl_bai} MB (${gl_lv}${total_size_gb2}${gl_bai} GB)"
    echo ""

    # 目录大小差异消息
    local size_diff_msg=""
    if (($(echo "$total_size_mb1 > $total_size_mb2" | bc -l 2>/dev/null || echo "0"))); then
        size_diff_msg="${name1} 比 ${name2} 大 ${size_diff_mb} MB (${size_diff_gb} GB)"
        echo -e "  ${gl_huang}✓ ${size_diff_msg}${gl_bai}"
    elif (($(echo "$total_size_mb1 < $total_size_mb2" | bc -l 2>/dev/null || echo "0"))); then
        size_diff_mb=${size_diff_mb#-}
        size_diff_gb=${size_diff_gb#-}
        size_diff_msg="${name2} 比 ${name1} 大 ${size_diff_mb} MB (${size_diff_gb} GB)"
        echo -e "  ${gl_huang}✓ ${size_diff_msg}${gl_bai}"
    else
        size_diff_msg="两个目录大小相同"
        echo -e "  ${gl_lv}✓ ${size_diff_msg}${gl_bai}"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 总结
    if [[ $total_files1 -eq 0 ]] && [[ $total_files2 -eq 0 ]]; then
        log_warn "两个目录都是空的"
    elif [[ $total_files1 -eq 0 ]]; then
        log_warn "${name1} 是空的"
    elif [[ $total_files2 -eq 0 ]]; then
        log_warn "${name2} 是空的"
    fi

    if [[ $total_files1 -eq $total_files2 ]] && [[ "$total_size_mb1" == "$total_size_mb2" ]]; then
        log_ok "目录完全一致"
    else
        if [[ $total_files1 -eq $total_files2 ]]; then
            log_ok "文件数量一致"
        fi

        if [[ "$total_size_mb1" == "$total_size_mb2" ]]; then
            log_ok "目录大小一致"
        fi
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    return 0
}

# 电脑壁纸整理函数
wallpaper_pc_organizer_ffmpeg() {
    install ffmpeg

    # 目录变量定义
    local PHOTOS_DIR="/vol1/1000/compose/random-pic-api/photos"       # 待处理目录
    local BACKUP_DIR="/vol2/1000/阿里云盘/教程文件/壁纸原图/电脑原图"    # 壁纸原图目录
    local LANDSCAPE_DIR="/vol1/1000/compose/random-pic-api/landscape" # 壁纸目录

    # Gitee 脚本库 URL
    local GITEE_SCRIPT_BASE_URL="https://gitee.com/meimolihan/script/raw/master/wallpaper/pc"

    # 用户确认函数
    wallpaper_confirm_action() {
        local prompt="$1"
        local default="$2" # y 或 n
        local choices="(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai})"
        [[ "$default" == "y" ]] && choices="(${gl_lv}Y${gl_bai}/${gl_hong}n${gl_bai})"

        read -r -e -p "$(echo -e "${gl_bai}${prompt} ${choices}: ")" confirm
        confirm=${confirm:-$default} # 如果用户直接回车，使用默认值

        [[ "$confirm" =~ ^[Yy]$ ]]
    }

    # 检查并进入目录
    wallpaper_check_and_cd() {
        local dir="$1"
        local err_msg="$2"

        if cd "$dir" 2>/dev/null; then
            log_info "已进入目录: ${dir}"
            return 0
        else
            log_error "$err_msg"
            return 1
        fi
    }

    # 检查是否有图片文件
    wallpaper_check_image_files() {
        shopt -s nullglob nocaseglob
        local files=("$PHOTOS_DIR"/*.{jpg,jpeg,png,webp})

        if ((${#files[@]} == 0)); then
            echo ""
            echo -e "${gl_zi}>>> 电脑壁纸整理 FF${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}待整理目录：${gl_huang}${PHOTOS_DIR}${gl_bai}"
            log_error "未找到 .jpg、.jpeg、.png、.webp 壁纸文件，脚本终止。"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
        fi

        log_info "找到 ${#files[@]} 个图片文件"
        return 0
    }

    # 备份原图函数
    wallpaper_backup_photos() {
        if ! wallpaper_confirm_action "是否备份电脑壁纸原图" "n"; then
            log_warn "已跳过原图备份"
            return 0
        fi

        # 检查源目录是否还有文件
        if [ -z "$(ls -A "$PHOTOS_DIR" 2>/dev/null)" ]; then
            log_warn "源目录已为空，无需备份"
            return 0
        fi

        log_info "正在备份原图 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 创建备份目录（如果不存在）
        mkdir -p "$BACKUP_DIR" 2>/dev/null

        # 移动文件，避免覆盖已有文件
        if mv -n "$PHOTOS_DIR"/* "$BACKUP_DIR"/ 2>/dev/null; then
            log_ok "原图备份完成"
            log_info "备份目录: ${BACKUP_DIR}"
        else
            log_error "备份过程中出现错误"
            return 1
        fi
    }

    # 显示最近文件
    wallpaper_show_recent_files() {
        local dir="$1"
        local count="${2:-6}"

        if [ -d "$dir" ]; then
            log_info "最近${count}个文件："
            ls -t "$dir" 2>/dev/null | head -n "$count"
        fi
    }

    # 使用ffmpeg分类整理图片
    wallpaper_classify_with_ffmpeg() {
        log_info "开始使用ffmpeg整理壁纸 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 确保目标目录存在
        mkdir -p "$LANDSCAPE_DIR" 2>/dev/null

        local total=0
        local success=0

        # 修复大括号扩展问题
        local extensions=("jpg" "jpeg" "png" "webp")

        # 处理所有支持的图片格式
        for ext in "${extensions[@]}"; do
            for file in "$PHOTOS_DIR"/*."$ext"; do
                # 跳过不存在的文件
                [[ -f "$file" ]] || continue
                total=$((total + 1))

                local filename=$(basename "$file")
                local name="${filename%.*}"

                # 使用ffmpeg转换为统一格式（如webp）并移动到目标目录
                local output_file="${LANDSCAPE_DIR}/${name}.webp"
                local counter=1

                # 处理文件名冲突
                while [[ -f "$output_file" ]]; do
                    output_file="${LANDSCAPE_DIR}/${name}_${counter}.webp"
                    counter=$((counter + 1))
                done

                echo -e "${gl_huang}[${total}]${gl_bai} 处理: $filename"

                if ffmpeg -i "$file" -q:v 80 "$output_file" 2>/dev/null; then
                    log_info "转换成功: $filename → $(basename "$output_file")"
                    success=$((success + 1))
                else
                    log_error "转换失败: $filename"
                fi
            done
        done

        if [[ $total -eq 0 ]]; then
            log_error "没有找到可处理的图片文件"
            exit_animation    # 即将退出动画
            return 1
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_ok "壁纸整理完成"
        log_info "总计: ${total} 个文件"
        log_info "成功: ${gl_lv}${success}${gl_bai} 个文件"
        if [[ $((total - success)) -gt 0 ]]; then
            log_warn "失败: ${gl_huang}$((total - success))${gl_bai} 个文件"
        fi
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        return 0
    }

    # ==================== 主程序 ====================

    # 1. 检查图片文件
    wallpaper_check_image_files

    clear
    echo -e "${gl_zi}>>> 开始整理电脑壁纸 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 2. 使用ffmpeg整理壁纸
    if wallpaper_classify_with_ffmpeg; then
        log_ok "壁纸整理完成"
    else
        log_error "壁纸整理失败，脚本终止"
        return 1
    fi

    # 3. 备份原图
    echo ""
    echo -e "${gl_zi}>>> 开始备份电脑壁纸原图 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    wallpaper_backup_photos

    # 4. 比较目录
    echo ""
    echo -e "${gl_zi}>>> 开始比较电脑壁纸目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    compare_pc_directories
    log_ok "目录比较完成"

    # 5. 询问是否继续
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if ! wallpaper_confirm_action "是否继续执行后续步骤" "n"; then
        log_info "脚本已退出。"
        return 0
    fi

    log_info "继续执行后续步骤 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 6. 电脑壁纸排序
    echo ""
    echo -e "${gl_zi}>>> 开始电脑壁纸排序 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if wallpaper_check_and_cd "$LANDSCAPE_DIR" "无法进入目录: $LANDSCAPE_DIR"; then
        wallpaper_show_recent_files "$LANDSCAPE_DIR" 6
        file_rename_sorter "pc" "webp"
    fi

    # 7. 电脑原图壁纸排序
    echo ""
    echo -e "${gl_zi}>>> 开始电脑原图壁纸排序 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if wallpaper_check_and_cd "$BACKUP_DIR" "无法进入目录: $BACKUP_DIR"; then
        wallpaper_show_recent_files "$BACKUP_DIR" 6
        rename_original_images_pc
    fi

    # 8. 结束
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

