                local filename=$(basename "$file")
                local name="${filename%.*}"

                # 使用ffmpeg转换为统一格式（如webp）并移动到目标目录
                local output_file="${LANDSCAPE_DIR}/${name}.webp"
                local counter=1

                # 处理文件名冲突
                while [[ -f "$output_file" ]]; do
                    output_file="${LANDSCAPE_DIR}/${name}_${counter}.webp"
                    counter=$((counter + 1))
                done

                echo -e "${gl_huang}[${total}]${gl_bai} 处理: $filename"

                if ffmpeg -i "$file" -q:v 80 "$output_file" 2>/dev/null; then
                    log_info "转换成功: $filename → $(basename "$output_file")"
                    success=$((success + 1))
                else
                    log_error "转换失败: $filename"
                fi
            done
        done

        if [[ $total -eq 0 ]]; then
            log_error "没有找到可处理的图片文件"
            return 1
        fi

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_ok "手机壁纸整理完成"
        log_info "总计: ${total} 个文件"
        log_info "成功: ${gl_lv}${success}${gl_bai} 个文件"
        if [[ $((total - success)) -gt 0 ]]; then
            log_warn "失败: ${gl_huang}$((total - success))${gl_bai} 个文件"
        fi
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        return 0
    }

    # ==================== 主程序 ====================

    # 1. 检查图片文件
    wallpaper_phone_check_image_files

    clear
    echo -e "${gl_zi}>>> 开始整理手机壁纸 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 2. 使用ffmpeg整理壁纸
    if wallpaper_phone_classify_with_ffmpeg; then
        log_ok "手机壁纸整理完成"
    else
        log_error "手机壁纸整理失败，脚本终止"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 3. 备份原图
    echo ""
    echo -e "${gl_zi}>>> 开始备份手机壁纸原图 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    wallpaper_phone_backup_photos

    # 4. 比较目录
    echo ""
    echo -e "${gl_zi}>>> 开始比较手机壁纸目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    compare_phone_directories
    log_ok "目录比较完成"

    # 5. 询问是否继续
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if ! wallpaper_phone_confirm_action "是否继续执行后续步骤" "n"; then
        log_info "脚本已退出。"
        exit_animation    # 即将退出动画
        return 0
    fi

    log_info "继续执行后续步骤 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 6. 手机壁纸排序
    echo ""
    echo -e "${gl_zi}>>> 开始手机壁纸排序 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if wallpaper_phone_check_and_cd "$LANDSCAPE_DIR" "无法进入目录: $LANDSCAPE_DIR"; then
        wallpaper_phone_show_recent_files "$LANDSCAPE_DIR" 6
        file_rename_sorter "phone" "webp"
    fi

    # 7. 手机原图壁纸排序
    echo ""
    echo -e "${gl_zi}>>> 开始手机原图壁纸排序 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if wallpaper_phone_check_and_cd "$BACKUP_DIR" "无法进入目录: $BACKUP_DIR"; then
        wallpaper_phone_show_recent_files "$BACKUP_DIR" 6
        rename_original_images_phone
    fi

    # 8. 结束
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 电脑壁纸整理函数（Python版本）
wallpaper_pc_organizer_python() {
    # 目录变量定义
    local SCRIPT_DIR="/vol1/1000/compose/random-pic-api"
    local PHOTOS_DIR="$SCRIPT_DIR/photos"             # 待处理目录
    local BACKUP_DIR="/vol2/1000/阿里云盘/教程文件/壁纸原图/电脑原图" # 壁纸原图目录
    local LANDSCAPE_DIR="$SCRIPT_DIR/landscape"       # 壁纸目录
    local PORTRAIT_DIR="$SCRIPT_DIR/portrait"         # 竖屏图片目录
    local UNCLASSIFIED_DIR="$SCRIPT_DIR/unclassified" # 未分类目录

    # Gitee 脚本库 URL
    local GITEE_SCRIPT_BASE_URL="https://gitee.com/meimolihan/script/raw/master/wallpaper/pc"

    # 分类脚本路径
    local CLASSIFY_SCRIPT="$SCRIPT_DIR/classify.py"

    # 用户确认函数
    wallpaper_pc_confirm_action() {
        local prompt="$1"
        local default="$2" # y 或 n
        local choices="(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai})"
        [[ "$default" == "y" ]] && choices="(${gl_lv}Y${gl_bai}/${gl_hong}n${gl_bai})"

        read -r -e -p "$(echo -e "${gl_bai}${prompt} ${choices}: ")" confirm
        confirm=${confirm:-$default} # 如果用户直接回车，使用默认值

        [[ "$confirm" =~ ^[Yy]$ ]]
    }

    # 检查并进入目录
    wallpaper_pc_check_and_cd() {
        local dir="$1"
        local err_msg="$2"

        if cd "$dir" 2>/dev/null; then
            log_info "已进入目录: ${dir}"
            return 0
        else
            log_error "$err_msg"
            exit_animation    # 即将退出动画
            return 1
        fi
    }

    # 检查是否有图片文件
    wallpaper_pc_check_image_files() {
        shopt -s nullglob nocaseglob
        local files=("$PHOTOS_DIR"/*.{jpg,jpeg,png,webp})

        if ((${#files[@]} == 0)); then
            echo ""
            echo -e "${gl_zi}>>> 电脑壁纸整理 PY${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}待整理目录：${gl_huang}${PHOTOS_DIR}${gl_bai}"
            log_error "未找到 .jpg、.jpeg、.png、.webp 壁纸文件，脚本终止。"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
        fi

        log_info "找到 ${#files[@]} 个图片文件"
        return 0
    }

    # 备份原图函数
    wallpaper_pc_backup_photos() {
        if ! wallpaper_pc_confirm_action "是否备份电脑壁纸原图" "n"; then
            log_warn "已跳过原图备份"
            return 0
        fi

        # 检查源目录是否还有文件
        if [ -z "$(ls -A "$PHOTOS_DIR" 2>/dev/null)" ]; then
            log_warn "源目录已为空，无需备份"
            return 0
        fi

        log_info "正在备份原图 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 创建备份目录（如果不存在）
        mkdir -p "$BACKUP_DIR" 2>/dev/null

        # 移动文件，避免覆盖已有文件
        if mv -n "$PHOTOS_DIR"/* "$BACKUP_DIR"/ 2>/dev/null; then
            log_ok "原图备份完成"
            log_info "备份目录: ${BACKUP_DIR}"
        else
            log_error "备份过程中出现错误"
            exit_animation    # 即将退出动画
            return 1
        fi
    }

    # 执行远程脚本
    wallpaper_pc_execute_remote_script() {
        local script_name="$1"
        local script_url="${GITEE_SCRIPT_BASE_URL}/${script_name}"

        log_info "正在执行: ${GITEE_SCRIPT_BASE_URL}/${script_name}"

        if bash <(curl -sL "$script_url"); then
            log_ok "${GITEE_SCRIPT_BASE_URL}/${script_name} 执行完成"
            return 0
        else
            log_error "${GITEE_SCRIPT_BASE_URL}/${script_name} 执行失败"
            exit_animation    # 即将退出动画
            return 1
        fi
    }

    # 显示最近文件
    wallpaper_pc_show_recent_files() {
        local dir="$1"
        local count="${2:-6}"

        if [ -d "$dir" ]; then
            log_info "最近${count}个文件："
            ls -t "$dir" 2>/dev/null | head -n "$count"
        fi
    }

    # 使用Python分类整理图片
    wallpaper_pc_classify_with_python() {
        log_info "开始使用Python整理壁纸 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

        # 检查Python脚本是否存在
        if [[ ! -f "$CLASSIFY_SCRIPT" ]]; then
            log_error "Python分类脚本不存在: $CLASSIFY_SCRIPT"
            exit_animation    # 即将退出动画
            return 1
        fi

        # 进入目录
        if ! wallpaper_pc_check_and_cd "$SCRIPT_DIR" "无法进入目录: $SCRIPT_DIR"; then
            exit_animation    # 即将退出动画
            return 1
        fi

        # 获取原始文件列表
        log_info "原始图片文件:"
        shopt -s nullglob nocaseglob
        local files=("$PHOTOS_DIR"/*.{jpg,jpeg,png,webp})
        local file_count=${#files[@]}

        for ((i = 0; i < file_count; i++)); do
            local filename=$(basename "${files[i]}")
            echo -e "  ${gl_huang}[$((i + 1))/$file_count]${gl_bai} 待处理: ${gl_lv}$filename${gl_bai}"
        done

        if [[ $file_count -eq 0 ]]; then
            log_error "没有找到图片文件"
            exit_animation    # 即将退出动画
            return 1
        fi

        echo ""
        log_info "总计 ${file_count} 个文件待分类"
        log_info "执行分类脚本: classify.py"

        # 执行Python分类
        if python3 classify.py; then
            log_ok "Python分类完成"

            # 统计总结
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_ok "壁纸分类完成"
            log_info "总计: ${file_count} 个文件"
            if [[ $landscape_count -gt 0 ]]; then
                log_info "横屏: ${gl_lv}${landscape_count}${gl_bai} 个文件"
            fi
            if [[ $portrait_count -gt 0 ]]; then
                log_info "竖屏: ${gl_zi}${portrait_count}${gl_bai} 个文件"
            fi
            if [[ $unclassified_count -gt 0 ]]; then
                log_warn "未分类: ${gl_huang}${unclassified_count}${gl_bai} 个文件"
            fi

            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            return 0
        else
            log_error "Python分类失败: classify.py"
            exit_animation    # 即将退出动画
            return 1
        fi
    }

    # ==================== 主程序 ====================

    # 1. 检查图片文件
    wallpaper_pc_check_image_files

    clear
    echo -e "${gl_zi}>>> 开始整理电脑壁纸 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 2. 使用Python整理壁纸
    if wallpaper_pc_classify_with_python; then
        log_ok "壁纸整理完成"
    else
        log_error "壁纸整理失败，脚本终止"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 3. 备份原图
    echo ""
    echo -e "${gl_zi}>>> 开始备份电脑壁纸原图 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    wallpaper_pc_backup_photos

    # 4. 比较目录
    echo ""
    echo -e "${gl_zi}>>> 开始比较电脑壁纸目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    compare_pc_directories
    log_ok "目录比较完成"

    # 5. 询问是否继续
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if ! wallpaper_pc_confirm_action "是否继续执行后续步骤" "n"; then
        log_info "脚本已退出。"
        exit_animation    # 即将退出动画
        return 0
    fi

    log_info "继续执行后续步骤 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 6. 电脑壁纸排序
    echo ""
    echo -e "${gl_zi}>>> 开始电脑壁纸排序 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if wallpaper_pc_check_and_cd "$LANDSCAPE_DIR" "无法进入目录: $LANDSCAPE_DIR"; then
        wallpaper_pc_show_recent_files "$LANDSCAPE_DIR" 6
        file_rename_sorter "pc" "webp"
    fi

    # 7. 电脑原图壁纸排序
    echo ""
    echo -e "${gl_zi}>>> 开始电脑原图壁纸排序 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    if wallpaper_pc_check_and_cd "$BACKUP_DIR" "无法进入目录: $BACKUP_DIR"; then
        wallpaper_pc_show_recent_files "$BACKUP_DIR" 6
        rename_original_images_pc
    fi

    # 8. 结束
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

