# 上传本地壁纸文件函数
wallpaper_upload_local() {
    clear
    cd /vol1/1000/compose/random-pic-api/photos
    list_dir_colorful 0 4
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e ""
    echo -e "${gl_zi}>>> 上传本地壁纸文件 (rz)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "准备接收来自本地的文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bai}终端支持检测:${gl_bai}"
    echo -e "${gl_bai}支持的终端: ${gl_lv}MobaXterm, Xshell, SecureCRT, Tabby, WindTerm${gl_bai}"
    echo -e "${gl_huang}注意: PuTTY 不支持Zmodem协议${gl_bai}"
    echo -e "${gl_huang}注意: Windows Terminal 需安装lrzsz并配置${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    echo -e "${gl_huang}请在本地客户端选择要上传的文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    
    for i in {2..1}; do
        echo -ne "${gl_huang}将在 ${gl_lv}$i${gl_bai} 秒后弹出文件选择对话框${gl_bai}\r"
        sleep_fractional 1
    done
    echo ""
    
    if command -v rz >/dev/null 2>&1; then
        echo -e "${gl_bai}执行命令: ${gl_zi}rz${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}提示: 按${gl_lv}Ctrl+C${gl_bai}取消上传${gl_bai}"
        
        if rz; then
            log_ok "文件上传成功!"
            echo -e "${gl_bai}上传的文件:${gl_bai}"
            ls -lth | head -5
        else
            if [[ $? -eq 130 ]]; then
                log_info "上传被用户取消"
            else
                log_warn "文件上传失败，请检查终端是否支持Zmodem"
            fi
        fi
    else
        log_error "rz命令不可用，请先安装lrzsz"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    echo -e ""
    list_dir_colorful 0 4
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 函数_随机壁纸管理
random_wallpaper_menu() {
    while true; do

        if [ ! -d "/vol1/1000/compose/random-pic-api" ]; then
            echo -e ""
            echo -e "${gl_zi}>>> 随机壁纸管理${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}错误：目录 ${gl_lv}/vol1/1000/compose/random-pic-api ${gl_huang}不存在。${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -n 1 -s -r -p "$(echo -e "按任意键返回 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
            break
        fi

        install find du bc
        clear

        # 目录1：统计 .webp 数量
        dir1="/vol1/1000/compose/random-pic-api/landscape"
        webp_count1=$(find "$dir1" -maxdepth 1 -type f -iname "*.webp" | wc -l)

        # 目录2：统计 .webp .png .jpg .jpeg 总和
        dir2="/vol2/1000/阿里云盘/教程文件/壁纸原图/电脑原图"
        total_count2=0
        for ext in webp png jpg jpeg; do
            count=$(find "$dir2" -maxdepth 1 -type f -iname "*.$ext" | wc -l)
            total_count2=$((total_count2 + count))
        done

        # 目录3：统计 .webp 数量
        dir3="/vol1/1000/compose/random-pic-api/portrait"
        webp_count3=$(find "$dir3" -maxdepth 1 -type f -iname "*.webp" | wc -l)

        # 目录4：统计 .webp .png .jpg .jpeg 总和
        dir4="/vol2/1000/阿里云盘/教程文件/壁纸原图/手机原图"
        total_count4=0
        for ext in webp png jpg jpeg; do
            count=$(find "$dir4" -maxdepth 1 -type f -iname "*.$ext" | wc -l)
            total_count4=$((total_count4 + count))
        done

        # 输出结果
        list_dir_colorful 0 4
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e ""
        echo -e "${gl_huang}>>> 电脑壁纸统计${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "📁 电脑壁纸: ${gl_lv}$dir1${gl_bai}"
        echo -e "🖼️  壁纸数量: ${gl_bufan}$webp_count1${gl_bai}"
        echo -e ""
        echo -e "📁 电脑原图: ${gl_lv}$dir2${gl_bai}"
        echo -e "🖼️  壁纸数量: ${gl_bufan}$total_count2${gl_bai}"
        echo -e ""
        echo -e "${gl_huang}>>> 手机壁纸统计${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "📁 手机壁纸: ${gl_lv}$dir3${gl_bai}"
        echo -e "🖼️  壁纸数量: ${gl_bufan}$webp_count3${gl_bai}"
        echo -e ""
        echo -e "📁 手机原图: ${gl_lv}$dir4${gl_bai}"
        echo -e "🖼️  壁纸数量: ${gl_bufan}$total_count4${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e ""
        echo -e "${gl_zi}>>> 随机壁纸管理${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}电脑壁纸整理${gl_bai}(${gl_huang}PY${gl_bai})    ${gl_bufan}2.  ${gl_bai}手机壁纸整理${gl_bai}(${gl_huang}PY${gl_bai})"
        echo -e "${gl_bufan}3.  ${gl_bai}电脑壁纸整理${gl_bai}(${gl_huang}FF${gl_bai})    ${gl_bufan}4.  ${gl_bai}手机壁纸整理${gl_bai}(${gl_huang}FF${gl_bai})"
        echo -e "${gl_bufan}5.  ${gl_bai}电脑壁纸排序        ${gl_bufan}6.  ${gl_bai}手机壁纸排序"
        echo -e "${gl_bufan}7.  ${gl_bai}电脑原图排序        ${gl_bufan}8.  ${gl_bai}手机原图排序"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}11. ${gl_bai}随机壁纸文件管理    ${gl_bufan}12. ${gl_bai}lrzsz文件传输"
        echo -e "${gl_bufan}13. ${gl_bai}上传本地壁纸文件    ${gl_bufan}14. ${gl_bai}预览文件工具"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回主菜单          ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " sub_choice

        case $sub_choice in
        1)  wallpaper_pc_organizer_python ;;                # 电脑壁纸整理PY
        2)  wallpaper_phone_organizer_python ;;             # 手机壁纸整理PY
        3)  wallpaper_pc_organizer_ffmpeg ;;                # 电脑壁纸整理FF
        4)  wallpaper_phone_organizer_ffmpeg ;;             # 手机壁纸整理FF
        5)  wallpaper_pc_sorter ;;                          # 电脑壁纸排序
        6)  wallpaper_phone_sorter ;;                       # 手机壁纸排序
        7)  wallpaper_pc_original_sorter ;;                 # 电脑原图排序
        8)  wallpaper_phone_original_sorter ;;              # 手机原图排序
        11) random_wallpaper_files_simple "linux_file" ;;   # 随机壁纸文件管理
        12) file_transfer_manager ;;                        # lrzsz文件传输
        13) wallpaper_upload_local ;;                       # 上传本地壁纸文件
        14) preview_file_content ;;                         # 预览文件工具
        0) cancel_return; break ;;                          # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;                     # 感谢使用，再见！
        *) handle_invalid_input ;;                          # 添加提示信息，N 秒后继续
        esac
    done
}

###### 检查并安装Docker
check_and_install_docker() {
    if ! command -v docker &>/dev/null; then
        echo -e ""
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}Docker状态：${gl_hong}未安装${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        while true; do
            read -r -e -p "$(echo -e "${gl_bai}确定安装 ${gl_huang}Docker${gl_bai} 吗？ (${gl_lv}Y${gl_bai}/${gl_hong}n${gl_bai}): ")" docker_choice

            case "${docker_choice,,}" in # 转换为小写进行比较
            y | yes)
                echo -e ""
                if install_add_docker; then # 调用安装函数并检查结果
                    echo -e "${gl_lv}Docker安装成功！${gl_bai}"
                    break # 安装成功，跳出循环继续执行
                else
                    echo -e "${gl_hong}Docker安装失败，请检查！${gl_bai}"
                    exit_animation    # 即将退出动画
                    return 1 # 安装失败，返回1
                fi
                ;;
            n | no | "")
                echo -e "${gl_hong}已取消安装Docker，退出 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                return 1 # 用户取消，返回1
                ;;
            *)
                echo -e "${gl_hong}输入错误，请重新输入！${gl_bai}"
                ;;
            esac
        done
    fi

    # 检查 Docker 服务是否运行
    if ! docker info &>/dev/null; then
        echo -e "${gl_hong}Docker${gl_bai} 服务未运行，请先启动 ${gl_hong}Docker${gl_bai} 服务${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    return 0
}

###### Docker全局状态
show_docker_global_status() {
    # Docker全局状态
    check_and_install_docker || return 1
    clear
    local container_count=$(docker ps -a -q 2>/dev/null | wc -l)
    local image_count=$(docker images -q 2>/dev/null | wc -l)
    local network_count=$(docker network ls -q 2>/dev/null | wc -l)
    local volume_count=$(docker volume ls -q 2>/dev/null | wc -l)

    echo -e ""
    echo -e "${gl_zi}>>> Docker全局状态${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "$(check_docker_version)"
    echo -e "$(docker_status)"
    echo -e "$(check_docker_compose)"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo ""
    echo -e "${gl_huang}Docker镜像: ${gl_lv}$image_count${gl_bai} "
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    list_beautify_docker_images
    echo ""
    echo -e "${gl_huang}Docker容器: ${gl_lv}$container_count${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    list_beautify_docker_ps_full
    echo ""
    echo -e "${gl_huang}Docker卷: ${gl_lv}$volume_count${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    list_beautify_docker_volume
