}

###### Docker网络管理
docker_network_manager() {
    local menu_name="${1:-上一级选单}"
    while true; do
        check_and_install_docker || return 1
        clear
        echo -e "${gl_bufan}Docker网络列表${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo ""
        # docker network ls
        docker-network-ls-cn
        echo ""
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        list_beautify_docker_network_info

        echo ""
        echo -e "${gl_zi}>>> 网络操作${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}创建网络"
        echo -e "${gl_bufan}2.  ${gl_bai}加入网络"
        echo -e "${gl_bufan}3.  ${gl_bai}退出网络"
        echo -e "${gl_bufan}4.  ${gl_bai}删除网络"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单"
        echo -e "${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " sub_choice

        case $sub_choice in
            1)
                echo ""
                echo -e "${gl_zi}>>> 创建网络${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "设置新网络名: " dockernetwork
                [ "$dockernetwork" = "0" ] && { cancel_return "上一级选单"; continue; }     # break 或 continue 或 return ，视上下文而定
                [ -z "$dockernetwork" ] && { cancel_empty "上一级选单"; continue; }          # break 或 continue 或 return ，视上下文而定

                docker network create "$dockernetwork"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;
            2)
                echo ""
                echo -e "${gl_zi}>>> 加入网络${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "加入网络名: " dockernetwork
                [ "$dockernetwork" = "0" ] && { cancel_return "上一级选单"; continue; }     # break 或 continue 或 return ，视上下文而定
                [ -z "$dockernetwork" ] && { cancel_empty "上一级选单"; continue; }          # break 或 continue 或 return ，视上下文而定

                read -r -e -p "那些容器加入该网络（多个容器名请用空格分隔）: " dockernames
                [ "$dockernames" = "0" ] && { cancel_return "上一级选单"; continue; }       # break 或 continue 或 return ，视上下文而定
                [ -z "$dockernames" ] && { cancel_empty "上一级选单"; continue; }            # break 或 continue 或 return ，视上下文而定

                for dockername in $dockernames; do
                    docker network connect "$dockernetwork" "$dockername"
                done
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;
            3)
                echo ""
                echo -e "${gl_zi}>>> 退出网络${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "退出网络名: " dockernetwork
                [ "$dockernetwork" = "0" ] && { cancel_return "上一级选单"; continue; }     # break 或 continue 或 return ，视上下文而定
                [ -z "$dockernetwork" ] && { cancel_empty "上一级选单"; continue; }          # break 或 continue 或 return ，视上下文而定

                read -r -e -p "那些容器退出该网络（多个容器名请用空格分隔）: " dockernames
                [ "$dockernames" = "0" ] && { cancel_return "上一级选单"; continue; }       # break 或 continue 或 return ，视上下文而定
                [ -z "$dockernames" ] && { cancel_empty "上一级选单"; continue; }            # break 或 continue 或 return ，视上下文而定
                for dockername in $dockernames; do
                    docker network disconnect "$dockernetwork" "$dockername"
                done
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;
            4)
                echo ""
                echo -e "${gl_zi}>>> 删除网络${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "请输入要删除的网络名: " dockernetwork
                [ "$dockernetwork" = "0" ] && { cancel_return "上一级选单"; continue; }     # break 或 continue 或 return ，视上下文而定
                [ -z "$dockernetwork" ] && { cancel_empty "上一级选单"; continue; }          # break 或 continue 或 return ，视上下文而定

                docker network rm "$dockernetwork"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;
            0) cancel_return "$menu_name"; break ;;
            00 | 000 | 0000) exit_script ;;
            *) handle_invalid_input ;;
        esac
    done
}

