        case $sub_choice in
            1)
                echo ""
                echo -e "${gl_zi}>>> 创建新卷${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "设置新卷名: " dockerjuan
                [ "$dockerjuan" = "0" ] && { cancel_return "上一级选单"; continue; }     # break 或 continue 或 return ，视上下文而定
                [ -z "$dockerjuan" ] && { cancel_empty "上一级选单"; continue; }          # break 或 continue 或 return ，视上下文而定
                docker volume create "$dockerjuan"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;
            2)
                echo ""
                echo -e "${gl_zi}>>> 删除指定卷${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "输入删除卷名（多个卷名请用空格分隔）: " dockerjuans
                [ "$dockerjuans" = "0" ] && { cancel_return "上一级选单"; continue; }     # break 或 continue 或 return ，视上下文而定
                [ -z "$dockerjuans" ] && { cancel_empty "上一级选单"; continue; }          # break 或 continue 或 return ，视上下文而定
                for dockerjuan in $dockerjuans; do
                    docker volume rm "$dockerjuan"
                done
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;
            3)
                echo ""
                echo -e "${gl_zi}>>> 删除所有卷${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                read -r -e -p "$(echo -e "${gl_hong}注意: ${gl_bai}确定删除所有未使用的卷吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" choice
                case "$choice" in
                    [Yy])
                        docker volume prune -f
                        ;;
                    [Nn]) ;;
                    0) cancel_return; return 1 ;;   # 返回到上一级菜单
                    *) handle_y_n ;;                # 无效的输入,请重新输入!
                esac
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;
            0) cancel_return "$menu_name"; break ;;
            00 | 000 | 0000) exit_script ;;
            *) handle_invalid_input ;;
        esac
    done
}

###### 清理镜像容器网络
docker_system_prune() {
    # 清理容器和镜像网络数据卷
    check_and_install_docker || return 1
    clear
    echo -e "${gl_zi}>>> 清理镜像容器网络${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_huang}提示: ${gl_bai}将清理无用的镜像容器网络，包括停止的容器，确定清理吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" choice
    case "$choice" in
        [Yy])
            docker system prune -af --volumes
            ;;
        [Nn]) ;;
        *) handle_y_n ;;       # 无效的输入,请重新输入!
    esac
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 克隆Docker项目
clone_docker_repo() {
    echo -e ""
    echo -e "${gl_zi}>>> Git克隆Docker项目${gl_bai}"
    echo -e "${gl_bai}当前工作目录: ${gl_huang}$(pwd)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if [ -z "$(ls -A)" ]; then
        echo -e "${gl_huang}当前目录为空${gl_bai}"
    else
        ls --color=auto -xa
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 获取工作目录
    read -r -e -p "$(echo -e "${gl_bai}请输入工作目录 (回车当前目录克隆，${gl_huang}0${gl_bai}返回): ")" work_dir

    # 处理输入
    if [[ "$work_dir" == "0" ]]; then
        cancel_return "Docker 管理"
        return 1
    elif [[ -z "$work_dir" ]]; then
        work_dir="."
        echo -e "使用当前目录: ${gl_huang}$(pwd)${gl_bai}"
    elif [[ ! -d "$work_dir" ]]; then
        # 路径不存在，询问是否创建
        echo -e "${gl_huang}目录不存在: $work_dir${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}是否创建此目录?  (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" create_choice

        case "$create_choice" in
            y | Y | yes | YES)
                mkdir -p "$work_dir"
                if [ $? -eq 0 ]; then
                    echo -e "${gl_lv}目录创建成功: $work_dir${gl_bai}"
                else
                    echo -e "${gl_hong}目录创建失败: $work_dir${gl_bai}"
                    exit_animation    # 即将退出动画
                    return 1
                fi
                ;;
            *)
                echo -e "${gl_hong}已取消操作${gl_bai}"
                exit_animation    # 即将退出动画
                return 1
                ;;
        esac
    fi

    # 切换到工作目录
    cd "$work_dir" || {
        echo -e "${gl_hong}无法切换到目录: $work_dir${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    }
    # 执行克隆
    git_clone_docker_projects
}

###### 配置文件管理器
docker_compose_manager() {
    if ! command -v docker &>/dev/null; then
        echo -e ""
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}Docker状态：${gl_hong}未安装${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        while true; do
            read -r -e -p "$(echo -e "${gl_bai}确定安装 ${gl_huang}Docker${gl_bai} 吗？ (${gl_lv}Y${gl_bai}/${gl_hong}n${gl_bai}): ")" docker_choice

            case "${docker_choice,,}" in # 转换为小写进行比较
                y | yes)
                    echo -e ""
                    if install_add_docker; then # 调用安装函数并检查结果
                        echo -e "${gl_lv}Docker安装成功！${gl_bai}"
                        break # 安装成功，跳出循环继续执行
                    else
                        echo -e "${gl_hong}Docker安装失败，请检查！${gl_bai}"
                        return 1 # 或者 exit 1，取决于您的脚本结构
                    fi
                    ;;
                n | no | "")
                    echo -e "${gl_hong}已取消安装Docker，退出 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    return 1
                    ;;
                *) handle_y_n ;;       # 无效的输入,请重新输入!
            esac
        done
    fi

    # 检查 Docker 服务是否运行
    if ! docker info &>/dev/null; then
        echo -e "${gl_hong}Docker${gl_bai} 服务未运行，请先启动 ${gl_huang}Docker${gl_bai} 服务${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    # 检查 目录是否存在
    if [[ ! -d /vol1/1000/compose && ! -d /mnt/compose && ! -d /compose ]]; then
        log_error "${gl_bai} 目录 ${gl_huang}/vol1/1000/compose${gl_bai} 与 ${gl_huang}/mnt/compose${gl_bai} 与 ${gl_huang}/compose${gl_bai} 均不存在。"
        exit_animation    # 即将退出动画
        return 1
    fi

    clear

    case $(get_internal_ip | tr -d '[:space:]') in
        10.10.10.251) cd /vol1/1000/compose ;;
        10.10.10.246) cd /mnt/compose ;;
        10.10.10.239) cd /mnt/compose ;;
        *) : ;;
    esac

    if linux_file; then
        :
    else
        break_end
    fi
}

###### 卸载Docker环境
uninstall_docker_environment() {
    if ! command -v docker &>/dev/null; then
        echo -e ""
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_warn "Docker 未安装，无需卸载"
        exit_animation
        return 1
    fi
    echo -e ""
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_hong}注意: ${gl_bai}确定卸载docker环境吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" choice
    [ "$choice" = "0" ] && { cancel_return "上一级选单"; return 1; }   # break 或 continue 或 return ，视上下文而定
    case "$choice" in
        [Yy])
            clear
            echo -e "${gl_zi}>>> 正在清掉当前机器上所有 Docker 资源 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            docker ps -a -q | xargs -r docker rm -f && docker images -q | xargs -r docker rmi && docker network prune -f && docker volume prune -f
            remove docker docker-compose docker-ce docker-ce-cli containerd.io
            rm -f /etc/docker/daemon.json
            hash -r
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            ;;
        [Nn]) ;;
        *) handle_invalid_input ;;
    esac
}

