###### 备份 Compose 项目
# 日志记录函数（和你主脚本保持一致）
write_log() {
    local log_file="$1"
    local log_content="$2"
    echo -e "$log_content" >> "$log_file"
}

# 创建日志文件
init_log_file() {
    local backup_dest_dir="$1"
    local logs_dir="${backup_dest_dir}/logs"
    mkdir -p "$logs_dir"
    local timestamp=$(date +"%Y-%m-%d-%H-%M-%S")
    local log_file="${logs_dir}/${timestamp}.log"
    touch "$log_file"
    echo "$log_file"
}

# 写日志头部
write_log_header() {
    local log_file="$1"
    local start_time="$2"
    local backup_type="$3"
    write_log "$log_file" ">>> ${backup_type}"
    write_log "$log_file" ""
    write_log "$log_file" "备份时间：    ${start_time}"
    write_log "$log_file" ""
}

# 写日志尾部
write_log_footer() {
    local log_file="$1"
    local end_time="$2"
    local log_file_path="$3"
    write_log "$log_file" ""
    write_log "$log_file" "脚本结束时间：${end_time}"
    write_log "$log_file" "日志文件路径：${log_file_path}"
}

# 获取文件大小
get_human_size() {
    local file_path="$1"
    if [[ -f "$file_path" ]]; then
        local size_bytes=$(stat -c%s "$file_path" 2>/dev/null || stat -f%z "$file_path" 2>/dev/null)
        if [[ -n "$size_bytes" ]]; then
            numfmt --to=iec-i --suffix=B "$size_bytes" 2>/dev/null || echo "${size_bytes}B"
        else
            du -h "$file_path" 2>/dev/null | cut -f1
        fi
    else
        echo "未知"
    fi
}

backup_compose_project() {
    # 尝试初始化回收站
    if [[ -z "$TRASH_CMD" ]]; then
        install_trash
    fi

    cd /vol1/1000/compose

    # 固定输出目录
    local BACKUP_TEMP_DIR="/tmp"
    local BACKUP_DEST_DIR="/vol2/1000/file/myfile/compose/downloads"
    local LOG_FILE=""
    local SCRIPT_START_TIME=$(date +"%Y-%m-%d %H:%M:%S")
    local BACKUP_TYPE=""
    
    # 确保目标目录存在
    mkdir -p "$BACKUP_DEST_DIR" || {
        echo -e "${gl_hong}错误：无法创建目标目录 $BACKUP_DEST_DIR${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    }

    while true; do
        clear
        echo -e "${gl_huang}>>> 当前${gl_bai}(${gl_lv}文件${gl_hong}/${gl_zi}目录${gl_bai})${gl_huang}列表：${gl_lv}$(pwd)${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        local list=() item i choice target fmt_idx format
        local compress_extensions=("zip" "7z" "tar" "tar.gz" "tar.bz2" "tar.xz" "tgz" "tbz2" "txz" "rar" "gz" "bz2" "xz")

        # 使用更高效的方法获取文件和目录列表
        for item in *; do
            [[ "$item" == .* ]] && continue
            [[ ! -e "$item" ]] && continue

            local is_compressed=0
            for ext in "${compress_extensions[@]}"; do
                if [[ "$item" == *".$ext" ]]; then
                    is_compressed=1
                    break
                fi
            done
            ((is_compressed == 0)) && list+=("$item")
        done

        # 添加子目录
        for item in */; do
            if [[ -d "$item" && "$item" != .*/ && "$item" != "./" ]]; then
                item="${item%/}"
                local exists=0
                for existing in "${list[@]}"; do
                    [[ "$existing" == "$item" ]] && exists=1 && break
                done
                ((exists == 0)) && list+=("$item")
            fi
        done

        # 按字母顺序排序
        if ((${#list[@]} > 0)); then
            IFS=$'\n' list=($(sort <<<"${list[*]}"))
            unset IFS
        fi

        if ((${#list[@]} == 0)); then
            echo -e "${gl_huang}当前目录无可压缩的文件/目录${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi
        
        display_horizontal_list "${list[@]}"

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e ""
        echo -e "${gl_zi}>>> Compose 项目备份模式${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}临时目录: ${gl_lv}$BACKUP_TEMP_DIR${gl_bai}"
        echo -e "${gl_bai}备份目标: ${gl_lv}$BACKUP_DEST_DIR${gl_bai}"
        echo -e "${gl_huang}温馨提示: 输入序号备份单个项目，输入 ${gl_hong}666${gl_huang} 备份全部项目${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入序号选择，或手动输入${gl_bai}(${gl_lv}文件${gl_hong}/${gl_zi}目录${gl_bai}) (${gl_huang}0 ${gl_bai}返回): ")" choice

        if [[ -z "$choice" || "$choice" == "0" ]]; then
            return
        fi

        # ========== 创建日志 ==========
        LOG_FILE=$(init_log_file "$BACKUP_DEST_DIR")
        log_ok "日志文件已创建：${LOG_FILE}"

        if [[ "$choice" == "666" ]]; then
            BACKUP_TYPE="Compose批量备份"
        else
            BACKUP_TYPE="Compose独立备份"
        fi
        write_log_header "$LOG_FILE" "$SCRIPT_START_TIME" "$BACKUP_TYPE"

        # 666 备份全部项目
        if [[ "$choice" == "666" ]]; then
            backup_all_compose_projects "$LOG_FILE" "${list[@]}"
            
            # 写入日志尾部
            local SCRIPT_END_TIME=$(date +"%Y-%m-%d %H:%M:%S")
            write_log_footer "$LOG_FILE" "$SCRIPT_END_TIME" "$LOG_FILE"
            
            echo -e ""
            log_ok "日志已保存至：${LOG_FILE}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            continue
        fi

        if [[ "$choice" =~ ^[0-9]+$ ]] && ((choice >= 1 && choice <= ${#list[@]})); then
            target="${list[$((choice - 1))]}"
        else
            target="$choice"
        fi

        [[ -e "$target" ]] || {
            echo -e "${gl_hong}错误：'$target' 不存在！${gl_bai}"
            exit_animation    # 即将退出动画
            continue
        }

        # 显示压缩格式选项
        echo -e ""
        echo -e "${gl_huang}请选择备份格式：${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}1.${gl_bai} tar.gz (推荐)   ${gl_huang}2.${gl_bai} zip (通用)"
        echo -e "${gl_huang}3.${gl_bai} 7z (高压缩率)   ${gl_huang}4.${gl_bai} tar.xz (高压缩)"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        safe_read "请输入你的选择" fmt_idx "number"

        case "$fmt_idx" in
        1) format="tar.gz" ;;
        2) format="zip" ;;
        3) format="7z" ;;
        4) format="tar.xz" ;;
        *)
            echo -e "${gl_hong}无效序号！${gl_bai}"
            echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            read -r -n1 -s
            continue
            ;;
        esac

        # 执行单个项目备份
        backup_single_compose_project "$target" "$format" "$BACKUP_TEMP_DIR" "$BACKUP_DEST_DIR" "$LOG_FILE" "false"
        
        # 写入日志尾部
        local SCRIPT_END_TIME=$(date +"%Y-%m-%d %H:%M:%S")
        write_log_footer "$LOG_FILE" "$SCRIPT_END_TIME" "$LOG_FILE"

        echo -e ""
        log_ok "日志已保存至：${LOG_FILE}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    done
}

###### 备份单个 Compose 项目
backup_single_compose_project() {
    local target="$1"
    local format="$2"
    local BACKUP_TEMP_DIR="$3"
    local BACKUP_DEST_DIR="$4"
    local log_file="$5"
    local is_batch_backup="${6:-false}"
    
    local target_name=$(basename "$target")
    local backup_name="${target_name}.${format}"
    local temp_backup_path="$BACKUP_TEMP_DIR/$backup_name"
    local final_backup_path="$BACKUP_DEST_DIR/$backup_name"
    local source_abs_path=$(cd "$(dirname "$target")" && pwd)/$(basename "$target")

    echo -e ""
    echo -e "${gl_huang}>>> 开始备份: ${gl_lv}$target_name   ${gl_huang}格式: ${gl_lv}$format${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 在当前目录压缩，然后移动到临时目录
    compress_file "$target" "$format" "."
    
    local compress_result=$?
    local compress_output="${target_name}.${format}"

    # 检查压缩是否成功
    if [[ $compress_result -ne 0 ]] || [[ ! -f "$compress_output" ]]; then
        echo -e "${gl_hong}备份失败：压缩过程出错${gl_bai}"
        
        # 写入失败日志
        if [[ "$is_batch_backup" == "true" ]]; then
            write_log "$log_file" "  - $target_name"
            write_log "$log_file" "源文件目录：      $source_abs_path"
            write_log "$log_file" "状态：        备份失败"
            write_log "$log_file" ""
        else
            write_log "$log_file" "源文件目录：      $source_abs_path"
            write_log "$log_file" "状态：        备份失败"
        fi
        
        return 1
    fi

    # 先移动到临时目录（重命名）
    if ! mv "$compress_output" "$temp_backup_path" 2>/dev/null; then
        echo -e "${gl_hong}移动临时文件失败${gl_bai}"
        rm -f "$compress_output" 2>/dev/null
        
        # 写入失败日志
        if [[ "$is_batch_backup" == "true" ]]; then
            write_log "$log_file" "  - $target_name"
            write_log "$log_file" "源文件目录：      $source_abs_path"
            write_log "$log_file" "状态：        移动临时文件失败"
            write_log "$log_file" ""
        else
            write_log "$log_file" "源文件目录：      $source_abs_path"
            write_log "$log_file" "状态：        移动临时文件失败"
        fi
        
        exit_animation
        return 1
    fi

    # 移动备份文件到目标目录（强制覆盖）
    echo -e "${gl_bai}正在移动备份文件到目标目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    
    if mv -f "$temp_backup_path" "$final_backup_path" 2>/dev/null; then
        local file_size=$(get_human_size "$final_backup_path")
        echo -e "${gl_lv}备份完成！${gl_bai}"
        echo -e "${gl_bai}备份文件: ${gl_huang}$final_backup_path${gl_bai}"
        echo -e "${gl_bai}文件大小: ${gl_lv}$file_size${gl_bai}"
        
        # 写入成功日志
        if [[ "$is_batch_backup" == "true" ]]; then
            write_log "$log_file" "  - $target_name"
            write_log "$log_file" "源文件目录：      $source_abs_path"
            write_log "$log_file" "备份文件路径：$final_backup_path"
            write_log "$log_file" "压缩后大小：  $file_size"
            write_log "$log_file" ""
        else
            write_log "$log_file" "源文件目录：      $source_abs_path"
            write_log "$log_file" "备份文件路径：$final_backup_path"
            write_log "$log_file" "压缩后大小：  $file_size"
        fi
        
        return 0
    else
        echo -e "${gl_hong}移动备份文件失败！${gl_bai}"
        echo -e "${gl_bai}临时文件保留在: $temp_backup_path${gl_bai}"
        
        # 写入失败日志
        if [[ "$is_batch_backup" == "true" ]]; then
            write_log "$log_file" "  - $target_name"
            write_log "$log_file" "源文件目录：      $source_abs_path"
            write_log "$log_file" "状态：        移动目标文件失败"
            write_log "$log_file" ""
        else
            write_log "$log_file" "源文件目录：      $source_abs_path"
            write_log "$log_file" "状态：        移动目标文件失败"
        fi
        
        return 1
    fi
}

###### 备份全部 Compose 项目
backup_all_compose_projects() {
    local log_file="$1"
    shift
    local projects=("$@")
    
    echo -e ""
    echo -e "${gl_zi}>>> 批量备份全部项目${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 显示压缩格式选项
    echo -e "${gl_huang}请选择备份格式：${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_huang}1.${gl_bai} tar.gz (推荐)   ${gl_huang}2.${gl_bai} zip (通用)"
    echo -e "${gl_huang}3.${gl_bai} 7z (高压缩率)   ${gl_huang}4.${gl_bai} tar.xz (高压缩)"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    local fmt_idx format
    safe_read "请输入你的选择: " fmt_idx "number"

    case "$fmt_idx" in
    1) format="tar.gz" ;;
    2) format="zip" ;;
    3) format="7z" ;;
    4) format="tar.xz" ;;
    *) handle_invalid_input ;;      # 无效的输入,请重新输入!
    esac

    echo -e ""
    echo -e "${gl_huang}开始批量备份，共 ${gl_huang}${#projects[@]}${gl_bai} 个项目 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bai}备份格式: ${gl_lv}$format${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 记录批量列表
    write_log "$log_file" "批量备份项目列表："
    write_log "$log_file" ""

    local success_count=0
    local fail_count=0
    local BACKUP_TEMP_DIR="/tmp"
    local BACKUP_DEST_DIR="/vol2/1000/file/myfile/compose/downloads"

    for target in "${projects[@]}"; do
        if backup_single_compose_project "$target" "$format" "$BACKUP_TEMP_DIR" "$BACKUP_DEST_DIR" "$log_file" "true"; then
            ((success_count++))
        else
            ((fail_count++))
        fi
    done

    echo -e ""
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_lv}批量备份完成！${gl_bai}"
    echo -e "${gl_bai}成功: ${gl_lv}$success_count${gl_bai} 个，失败: ${gl_hong}$fail_count${gl_bai} 个${gl_bai}"
    echo -e "${gl_bai}备份目录: ${gl_huang}$BACKUP_DEST_DIR${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
}

###### 推送Compose项目
git_project_manager() {
    cd /vol1/1000/compose
    local base_path="${1:-$(pwd)}"
    if [[ ! -d $base_path ]]; then
        echo -e ""
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_error "路径 $base_path 不存在"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    while true; do
        clear
        echo -e "${gl_zi}>>> Git 项目列表${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}当前工作目录: ${gl_huang}$(pwd)${gl_bai}"
        echo -e "${gl_bai}内网 IP 地址: ${gl_huang}$(get_internal_ip)${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 获取目录数组
        local projects
        if ! show_directory_list "$base_path" 4 false true projects; then
            log_info "没有找到Git项目 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        fi

        # projects 现在是一个数组
        local count=${#projects[@]}

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}提示: 输入序号直接推送该项目，输入 ${gl_hong}666${gl_huang} 推送所有仓库${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入序号进入项目（${gl_huang}0${gl_bai}返回）: ")" choice

        case $choice in
        0) cancel_return; return 0 ;;
        666)
            # 推送所有仓库
            push_all_repos "$base_path" "日常更新" "HD-Icons hd-Icons"
            ;;
        q | quit | exit) return 1 ;;
        *)
            [[ $choice =~ ^[0-9]+$ ]] || {
                handle_invalid_input
                continue
            }
            ((choice >= 1 && choice <= count)) || {
                handle_invalid_input
                continue
            }
            local selected_project="${projects[$((choice - 1))]}"
            local full_path="$base_path/$selected_project"
            
            # 进入项目目录并直接推送
            cd "$full_path" || {
                log_error "无法进入目录 $full_path"
                continue
            }
            log_ok "已选择项目：$selected_project，开始推送 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            git_safe_push
            cd "$base_path"
            ;;
        esac
    done
}

# ============================================
# 飞牛 fnOS BBR 拥塞控制管理函数
# ============================================

# 开启 BBR 函数
fnos_enable_bbr() {
    is_fnos_system || return 1  # 非FnOS退出
    clear
    fnos_check_bbr
    echo -e ""
    echo -e "${gl_zi}>>> FnOS 开启 BBR 加速配置工具${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    local current_cc
    current_cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null)
    
    if [[ "$current_cc" == "bbr" ]]; then
        read -r -e -p "$(echo -e "${gl_bai}是否重新配置?${gl_bai}(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" reconfig
        case "$reconfig" in
            [Yy]) ;;
            [Nn]|"") 
                log_info "操作已取消"
                return 0
                ;;
            *) handle_y_n ;;        # 无效的输入,请输入(y或N)。
        esac
    else
        log_info "当前算法: ${gl_huang}${current_cc}${gl_bai}"
    fi
    
    echo ""
    
    # 检查系统支持
    echo -e "${gl_huang}>>> 检查系统支持${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 检查内核版本 (BBR 需要 Linux 4.9+)
    local kernel_version
    kernel_version=$(uname -r | cut -d. -f1,2)
    local major_version
    major_version=$(echo "$kernel_version" | cut -d. -f1)
    local minor_version
    minor_version=$(echo "$kernel_version" | cut -d. -f2)
    
    log_info "内核版本: ${gl_huang}$(uname -r)${gl_bai}"
    
    if [[ "$major_version" -lt 4 ]] || [[ "$major_version" -eq 4 && "$minor_version" -lt 9 ]]; then
        log_error "内核版本过低，需要 Linux 4.9+ 才能支持 BBR"
        log_info "当前版本: ${gl_huang}${kernel_version}${gl_bai}"
        return 1
    fi
    
    log_ok "内核版本支持 BBR"
    
    # 检查可用算法
    local available_cc
    available_cc=$(sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null)
    
    if [[ "$available_cc" == *"bbr"* ]]; then
        log_ok "系统已编译 BBR 模块: ${gl_lv}可用${gl_bai}"
    else
        log_warn "BBR 模块可能未加载，尝试自动加载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        modprobe tcp_bbr 2>/dev/null || true
        
        # 重新检查
        available_cc=$(sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null)
        if [[ "$available_cc" == *"bbr"* ]]; then
            log_ok "BBR 模块加载成功"
        else
            log_error "无法加载 BBR 模块，请检查内核配置"
            return 1
        fi
    fi
    
    echo ""
    
    # 用户确认开启
    echo -e "${gl_huang}>>> 确认开启 BBR${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}即将执行以下操作:${gl_hui}"
    echo -e "  • 备份当前 /etc/sysctl.conf 配置"
    echo -e "  • 设置 TCP 拥塞控制算法为 BBR"
    echo -e "  • 设置默认队列规则为 fq"
    echo -e "  • 应用配置并验证${gl_bai}"
    echo ""
    echo -e "${gl_hong}警告: 修改网络参数可能影响当前连接${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确认开启 BBR 加速?${gl_bai}(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_enable
    
    case "$confirm_enable" in
        [Yy])
            log_info "开始配置 BBR ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            ;;
        [Nn]|"")
            log_info "操作已取消"
            return 0
            ;;
        *) handle_y_n ;;       # 无效的输入,请重新输入!
    esac
    
    echo ""
    
    # 配置 BBR
    echo -e "${gl_huang}>>> 配置 BBR 参数${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 备份原配置
    local TIMESTAMP
    TIMESTAMP=$(date +%Y%m%d_%H%M%S)
    local BACKUP_FILE="/root/sysctl_backup_${TIMESTAMP}.conf"
    
    if [[ -f "/etc/sysctl.conf" ]]; then
        cp /etc/sysctl.conf "$BACKUP_FILE"
        log_ok "已备份原配置: ${gl_huang}${BACKUP_FILE}${gl_bai}"
    fi
    
    # 检查是否已有 BBR 配置
    if grep -q "tcp_congestion_control=bbr" /etc/sysctl.conf 2>/dev/null; then
        log_warn "检测到已有 BBR 配置，将更新配置"
        
        # 删除旧配置（避免重复）
        sed -i '/^net\.core\.default_qdisc=fq$/d' /etc/sysctl.conf
        sed -i '/^net\.ipv4\.tcp_congestion_control=bbr$/d' /etc/sysctl.conf
        sed -i '/^net\.core\.default_qdisc=fq_codel$/d' /etc/sysctl.conf
    fi
    
    # 添加 BBR 配置
    echo -e "\n# BBR TCP Congestion Control Configuration" >> /etc/sysctl.conf
    echo "net.core.default_qdisc=fq" >> /etc/sysctl.conf
    echo "net.ipv4.tcp_congestion_control=bbr" >> /etc/sysctl.conf
    
    log_ok "BBR 配置已写入 /etc/sysctl.conf"
    
    echo ""
    
    # 应用配置
    echo -e "${gl_huang}>>> 应用配置${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    if sysctl -p 2>/dev/null; then
        log_ok "配置应用成功"
    else
        log_warn "部分配置应用可能失败，请手动检查"
    fi
    
    # 验证结果
    echo ""
    echo -e "${gl_huang}>>> 验证配置结果${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    local new_cc
    new_cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null)
    local new_qdisc
    new_qdisc=$(sysctl -n net.core.default_qdisc 2>/dev/null)
    
    echo -e "${gl_lan}TCP 拥塞控制算法:${gl_bai} ${gl_lv}${new_cc}${gl_bai}"
    echo -e "${gl_lan}默认队列规则 (qdisc):${gl_bai} ${gl_lv}${new_qdisc}${gl_bai}"
    
    if [[ "$new_cc" == "bbr" ]]; then
        echo ""
        echo -e "${gl_lv}✅ BBR 启用成功！${gl_bai}"
        echo -e "${gl_bai}提示: BBR 可以优化网络传输，突破部分运营商限速${gl_bai}"
        echo -e "${gl_bai}建议重启系统以确保配置完全生效${gl_bai}"
    else
        log_error "BBR 启用失败，当前算法: ${gl_hong}${new_cc}${gl_bai}"
        log_info "请检查系统日志或手动加载模块: ${gl_hui}modprobe tcp_bbr${gl_bai}"
        return 1
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
    return 0
}

# 关闭 BBR 函数
fnos_disable_bbr() {
    is_fnos_system || return 1  # 非FnOS退出
    clear
    fnos_check_bbr
    echo -e ""
    echo -e "${gl_zi}>>> 飞牛 fnOS 关闭 BBR 工具${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    local current_cc
    current_cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null)

    if [[ "$current_cc" != "bbr" ]]; then
        log_warn "当前未启用 BBR 算法"
        read -r -e -p "$(echo -e "${gl_bai}是否仍要清理 BBR 相关配置?${gl_bai}(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" clean_anyway
        case "$clean_anyway" in
            [Yy]) ;;
            [Nn]|"") 
                log_info "操作已取消"
                return 0
                ;;
            *) handle_y_n ;;        # 无效的输入,请输入(y或N)。
        esac
    fi
    
    # 确认操作
    echo -e "${gl_hong}警告: 关闭 BBR 后网络传输性能可能下降${gl_bai}"
    echo -e "${gl_bai}系统将恢复为默认的 cubic 或 reno 算法${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确认关闭 BBR?${gl_bai}(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_disable
    
    case "$confirm_disable" in
        [Yy])
            log_info "开始关闭 BBR ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            ;;
        [Nn]|"")
            log_info "操作已取消"
            return 0
            ;;
         *) handle_y_n ;;        # 无效的输入,请输入(y或N)。
    esac
    
    echo ""
    
    # 备份配置
    echo -e "${gl_huang}>>> 备份当前配置${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    local TIMESTAMP
    TIMESTAMP=$(date +%Y%m%d_%H%M%S)
    local BACKUP_FILE="/root/sysctl_backup_disable_bbr_${TIMESTAMP}.conf"
    
    if [[ -f "/etc/sysctl.conf" ]]; then
        cp /etc/sysctl.conf "$BACKUP_FILE"
        log_ok "已备份配置: ${gl_huang}${BACKUP_FILE}${gl_bai}"
    fi
    
    # 移除 BBR 配置
    echo ""
    echo -e "${gl_huang}>>> 移除 BBR 配置${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 检查并删除 BBR 相关行
    if grep -q "tcp_congestion_control=bbr" /etc/sysctl.conf 2>/dev/null; then
        # 使用 sed 直接删除，更简洁可靠
        sed -i '/^net\.ipv4\.tcp_congestion_control=bbr$/d' /etc/sysctl.conf
        sed -i '/^net\.core\.default_qdisc=fq$/d' /etc/sysctl.conf
        sed -i '/^# BBR TCP Congestion Control Configuration$/d' /etc/sysctl.conf
        
        log_ok "已删除 BBR 配置行"
    else
        log_warn "未在 /etc/sysctl.conf 中找到 BBR 配置"
    fi
    
    # 清理可能残留的空行（超过2行的连续空行）
    sed -i '/^$/{ N; /^\n$/d }' /etc/sysctl.conf 2>/dev/null || true
    
    echo ""
    
    # 恢复默认算法
    echo -e "${gl_huang}>>> 恢复默认算法${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 临时立即生效（使用 cubic 作为默认）
    sysctl -w net.ipv4.tcp_congestion_control=cubic 2>/dev/null || \
    sysctl -w net.ipv4.tcp_congestion_control=reno 2>/dev/null || true
    
    # 恢复默认 qdisc
    sysctl -w net.core.default_qdisc=fq_codel 2>/dev/null || \
    sysctl -w net.core.default_qdisc=pfifo_fast 2>/dev/null || true
    
    # 重新加载配置
    sysctl -p 2>/dev/null || true
    
    log_ok "已恢复默认网络配置"
    
    echo ""
    
    # 验证结果
    echo -e "${gl_huang}>>> 验证关闭结果${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    local new_cc
    new_cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null)
    local new_qdisc
    new_qdisc=$(sysctl -n net.core.default_qdisc 2>/dev/null)
    
    echo -e "${gl_lan}当前 TCP 拥塞控制算法:${gl_bai} ${gl_huang}${new_cc}${gl_bai}"
    echo -e "${gl_lan}当前队列规则 (qdisc):${gl_bai} ${gl_huang}${new_qdisc}${gl_bai}"
    
    if [[ "$new_cc" != "bbr" ]]; then
        echo ""
        echo -e "${gl_lv}✅ BBR 已成功关闭${gl_bai}"
        echo -e "${gl_bai}当前使用算法: ${gl_huang}${new_cc}${gl_bai}"
        echo ""
        echo -e "${gl_bai}如需重新启用 BBR，请运行: ${gl_lv}fnos_enable_bbr${gl_bai}"
    else
        log_warn "BBR 仍在运行，可能需要重启系统才能完全关闭"
        echo -e "${gl_bai}手动恢复命令:${gl_hui}"
        echo -e "   echo 'net.ipv4.tcp_congestion_control=cubic' >> /etc/sysctl.conf"
        echo -e "   sysctl -p${gl_bai}"
    fi
    
    echo ""
    echo -e "${gl_lan}备份文件位于:${gl_bai} ${gl_huang}${BACKUP_FILE}${gl_bai}"
    echo -e "${gl_bai}如需恢复之前的配置，可手动执行:${gl_hui}"
    echo -e "   cp ${BACKUP_FILE} /etc/sysctl.conf && sysctl -p${gl_bai}"
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
    return 0
}

# BBR 状态检查函数（快速查看）
fnos_check_bbr() {
    echo -e "${gl_huang}>>> BBR 状态检查${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    local current_cc
    current_cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null)
    local current_qdisc
    current_qdisc=$(sysctl -n net.core.default_qdisc 2>/dev/null)
    local available_cc
    available_cc=$(sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null)
    
    echo -e "${gl_lan}当前 TCP 拥塞控制算法:${gl_bai} ${gl_huang}${current_cc}${gl_bai}"
    echo -e "${gl_lan}当前队列规则 (qdisc):${gl_bai} ${gl_huang}${current_qdisc}${gl_bai}"
    echo -e "${gl_lan}可用拥塞控制算法:${gl_bai} ${gl_hui}${available_cc}${gl_bai}"
    echo -e "${gl_lan}内核版本:${gl_bai} ${gl_hui}$(uname -r)${gl_bai}"
    
    if [[ "$current_cc" == "bbr" ]]; then
        echo ""
        echo -e "${gl_lv}✅ BBR 当前已启用${gl_bai}"
    else
        echo ""
        echo -e "${gl_hong}❌ BBR 当前未启用${gl_bai}"
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
}

