# 检查 Linux 版本
check_linux_distro() {
    # 获取发行版名称和版本
    if [ -f "/etc/os-release" ]; then
        . /etc/os-release
        if [ -n "$PRETTY_NAME" ]; then
            distro_info="$PRETTY_NAME"
        elif [ -n "$NAME" ] && [ -n "$VERSION_ID" ]; then
            distro_info="$NAME $VERSION_ID"
        elif [ -n "$NAME" ]; then
            distro_info="$NAME"
        else
            distro_info="未知Linux发行版"
        fi
    elif [ -f "/etc/redhat-release" ]; then
        distro_info=$(cat /etc/redhat-release)
    elif [ -f "/etc/lsb-release" ]; then
        . /etc/lsb-release
        if [ -n "$DISTRIB_DESCRIPTION" ]; then
            distro_info="$DISTRIB_DESCRIPTION"
        elif [ -n "$DISTRIB_ID" ] && [ -n "$DISTRIB_RELEASE" ]; then
            distro_info="$DISTRIB_ID $DISTRIB_RELEASE"
        else
            distro_info="Ubuntu/Debian"
        fi
    else
        distro_info=$(uname -o 2>/dev/null || echo "Linux")
    fi

    # 获取内核版本
    kernel_version=$(uname -r)

    echo -e "${gl_bufan}系统 ${gl_bai}版本：${gl_lv}$distro_info${gl_bai}"
    echo -e "${gl_bufan}内核 ${gl_bai}版本：${gl_lv}$kernel_version${gl_bai}"
}

