        echo -e "${gl_bufan}Nginx已停止${gl_bai}"
    else
        echo -e "${gl_bufan}${gl_hong}Nginx停止失败${gl_bai}"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

