###### 查看 80 端口占用
check_port_80_usage() {
    echo -e ""
    echo -e "${gl_zi}>>> 当前 ${gl_huang}80${gl_bai} 端口占用情况 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    local res=$(ss -tulnp | grep -E ':(80)\s')

    if [[ -n "$res" ]]; then
        echo -e "$res"
    else
        log_ok "80 端口当前未被占用"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
