###### 搜索监听80端口的配置
search_nginx_port_80_config() {
    clear
    echo -e "${gl_zi}>>> 搜索监听80端口的配置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if ! nginx -t &>/dev/null; then
        echo -e "${gl_hong}Nginx 配置存在错误，无法读取完整配置${gl_bai}"
        echo -e "${gl_huang}请先修复配置错误后再试${gl_bai}"
    else
        echo -e "${gl_huang}当前 Nginx 监听 80 端口的 server 块并列出对应行${gl_bai}"
        echo ""
        nginx -T 2>/dev/null | grep -E 'listen\s+80\b' || echo "未找到监听 80 端口的 server 块"
    fi
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    grep -Rl "listen 80" /etc/nginx/ 2>/dev/null || echo "未在配置文件目录中找到相关文件"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

