        8) { check_directory_empty "/etc/nginx/html" "管理html目录" "true" || continue; clear; cd /etc/nginx/html && linux_file "." "管理html目录" "html 文件管理"; } ;;
        9) show_nginx_listening_ports ;;                                     # 查看nginx监听端口
        10) ngx_log_auto_perm ;;                                             # 自动修复日志权限
        11) search_config_files || continue ;;                               # 搜索配置文件
        12) config_file_manager ;;                                           # 配置文件管理器
        13) monitor_nginx_access_logs ;;                                     # 访问日志实时监控
        14) monitor_nginx_error_logs ;;                                      # 错误日志实时监控
        15) show_ssl_certificate_paths ;;                                    # 查看证书路径
        16) check_ssl_certificate_expiry ;;                                  # 查看证书过期时间
        17) gateway_menu ;;                                                  # 切换网关
        18) extract_nginx_links_simple "/etc/nginx/conf.d" ;;                # 查看所有nginx服务
        19) bash <(curl -sL https://gitee.com/meimolihan/script/raw/master/sh/nginx/create_nginx_conf.sh) ;;     # 反代网站脚本Web
        20) bash <(curl -sL https://gitee.com/meimolihan/script/raw/master/sh/nginx/create_nginx_html_conf.sh) ;; # 反代网站脚本HTML
        21) linux_ldnmp ;;                                                   # LDNMP建站
        22) view_cert_expiry ;;                                              # 查看所有证书过期时间
        66) install_nginx ;;                                                 # 安装Nginx
        99) uninstall_nginx || continue ;;                                   # 卸载Nginx
        0) cancel_return "主菜单"; mobufan ;;                                # 返回到上一级菜单
        00 | 000 | 0000) exit_script ;;                                      # 感谢使用，再见！
        *) handle_invalid_input ;;                                           # 无效的输入,请重新输入!
        esac
    done
}

###### 函数_Git推送更新
git_safe_push() {
    local target_dir
    target_dir=$(pwd)

    check_and_install git || return 1
    check_git_repository "推送当前项目更新" "." "true" 2 || return 1

    # 1. 检查 Git 配置
    if [[ -z $(git config user.name) || -z $(git config user.email) ]]; then
        log_error "Git 用户名或邮箱未配置，请先配置。"
        echo -e "       ${gl_huang}git config --global user.name \"Your Name\"${gl_bai}"
        echo -e "       ${gl_huang}git config --global user.email \"your.email@example.com\"${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
        return 2
    fi

    echo -e ""
    echo -e "${gl_zi}>>> 推送项目更新 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}当前工作目录: ${gl_huang}$(pwd)${gl_bai}"
    repo_dir=$(basename "$(pwd)")
    echo -e "${gl_bai}当前项目名称: ${gl_huang}${repo_dir} ${gl_bai}仓库${gl_bai}"
    echo -e "${gl_bai}当前分支: ${gl_lv}$(git branch --show-current 2>/dev/null)${gl_bai}"
    
    # 检查远程仓库
    if ! git remote | grep -q .; then
        log_error "没有配置远程仓库"
        echo -e "       ${gl_huang}请先添加远程仓库: git remote add origin <repository-url>${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
        return 1
    fi
    
    echo -e "${gl_bai}远程仓库: ${gl_lv}$(git remote -v | head -1)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 检查当前状态
    log_info "检查当前 Git 状态 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bai}状态:${gl_bai}"
    git status --short 2>/dev/null || echo -e "  ${gl_huang}无法获取 Git 状态${gl_bai}"
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 1. 检查是否有任何更改（包括已暂存和未暂存）
    local status_output
    status_output=$(git status --porcelain 2>/dev/null)
    
    if [[ -z "$status_output" ]]; then
        # 2. 没有本地更改，检查是否有未推送的提交
        local ahead_count=0
        if git rev-parse @{u} >/dev/null 2>&1; then
            ahead_count=$(git rev-list --count @{u}..HEAD 2>/dev/null || echo 0)
        fi
        
        if [[ "$ahead_count" -gt 0 ]]; then
            log_info "有 ${gl_huang}${ahead_count}${gl_lan} 个已提交但未推送的更改"
        else
            log_ok "无变更，无需提交"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            return 0
        fi
    else
        # 3. 有本地更改，分析更改类型
        local has_staged_changes=false
        local has_unstaged_changes=false
        local has_untracked_files=false
        
        # 逐行分析状态
        while IFS= read -r line; do
            if [[ -z "$line" ]]; then
                continue
            fi
            
            # 获取状态标记
            local staged="${line:0:1}"
            local unstaged="${line:1:1}"
            
            # 检查是否有已暂存的更改
            if [[ "$staged" != " " ]] && [[ "$staged" != "?" ]]; then
                has_staged_changes=true
            fi
            
            # 检查是否有未暂存的更改
            if [[ "$unstaged" != " " ]] && [[ "$unstaged" != "?" ]]; then
                has_unstaged_changes=true
            fi
            
            # 检查是否有未跟踪的文件
            if [[ "$staged" == "?" ]] && [[ "$unstaged" == "?" ]]; then
                has_untracked_files=true
            fi
        done <<< "$status_output"
        
        # 4. 处理不同类型的更改
        if [[ "$has_unstaged_changes" == true ]] || [[ "$has_untracked_files" == true ]]; then
            log_info "正在添加所有未跟踪/修改的文件到暂存区 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            git add .
            
            if [[ $? -ne 0 ]]; then
                log_error "添加文件失败"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                return 3
            fi
            
            # 重新检查是否有已暂存的更改
            has_staged_changes=true
        fi
        
        # 5. 提交更改
        if [[ "$has_staged_changes" == true ]]; then
            # 显示将要提交的更改
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_info "将要提交的更改:${gl_bai}"
            git status --short
            
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_info "正在提交更改 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            git commit -m "update $(date '+%Y-%m-%d %H:%M:%S')"
            
            if [[ $? -ne 0 ]]; then
                log_error "提交失败，请检查 Git 状态。"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                return 4
            fi
        fi
    fi
    
    # 6. 检查是否有未推送的提交
    local ahead_count=0
    if git rev-parse @{u} >/dev/null 2>&1; then
        ahead_count=$(git rev-list --count @{u}..HEAD 2>/dev/null || echo 0)
    fi
    
    # 7. 推送更改
    if [[ "$ahead_count" -gt 0 ]]; then
        log_info "正在推送到远程仓库 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        git push
        if [[ $? -ne 0 ]]; then
            log_error "推送失败，请检查网络连接或远程仓库配置。"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            return 5
        fi
        
        log_ok "推送成功！"
    else
        log_ok "部署成功！"
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
    return 0
}

###### 函数_Git拉取更新
git_safe_pull() {
    local remote=${1:-origin}
    local branch=${2:-}
    local local_commit remote_commit base_commit

    check_and_install git || return 1
    check_git_repository "拉取当前项目更新" "." "true" 2 || return 1

    # 1. 若未传分支参数，则读取当前分支
    if [[ -z $branch ]]; then
        branch=$(git symbolic-ref --short HEAD 2>/dev/null) || {
            log_error "无法获取当前分支信息，请确保你在某个分支上。"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            return 2
        }
    fi

    # 获取上游分支信息
    local upstream_branch=$(git rev-parse --abbrev-ref "@{upstream}" 2>/dev/null)
    
    echo -e ""
    echo -e "${gl_zi}>>> 拉取当前项目更新${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 显示仓库信息
    echo -e "${gl_bai}当前工作目录: ${gl_huang}$(pwd)${gl_bai}"
    repo_dir=$(basename "$(pwd)")
    echo -e "${gl_bai}当前项目名称: ${gl_huang}${repo_dir} ${gl_bai}仓库${gl_bai}"
    echo -e "${gl_bai}当前分支: ${gl_lv}${branch}${gl_bai}"
    
    if [[ -n "$upstream_branch" ]]; then
        echo -e "${gl_bai}上游分支: ${gl_lv}${upstream_branch}${gl_bai}"
    else
        echo -e "${gl_bai}上游分支: ${gl_huang}未设置${gl_bai}"
    fi
    
    echo -e "${gl_bai}远程名称: ${gl_lv}${remote}${gl_bai}"
    
    # 显示远程信息
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "检查远程仓库信息 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    
    if git remote get-url "$remote" &>/dev/null; then
        echo -e "${gl_bai}远程仓库URL: ${gl_lv}$(git remote get-url "$remote")${gl_bai}"
    else
        echo -e "${gl_bai}远程仓库URL: ${gl_huang}未配置${gl_bai}"
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "当前工作目录内容:${gl_bai}"
    ls --color=auto -lha | head -20
    echo -e "${gl_huang}(显示前20个文件/目录)${gl_bai}"
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 检查工作目录状态
    log_info "检查工作目录状态 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    local status_output=$(git status --short 2>/dev/null)
    if [[ -n "$status_output" ]]; then
        echo -e "${gl_bai}当前有未提交的更改:${gl_bai}"
        echo -e "${status_output}" | while IFS= read -r line; do
            echo -e "  ${gl_huang}${line}${gl_bai}"
        done
        
        read -r -e -p "$(echo -e "${gl_huang}有未提交的更改，是否继续拉取? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" continue_pull
        
        if [[ ! "$continue_pull" =~ ^[Yy]$ ]]; then
            log_warn "已取消拉取操作"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            return 0
        fi
    else
        log_ok "工作目录干净，可以安全拉取"
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 2. 拉取最新远程引用
    log_info "正在拉取最新的远程信息 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bai}执行: git fetch ${gl_huang}${remote}${gl_bai}"
    
    if git fetch "$remote"; then
        log_ok "远程信息获取成功"
        
        # 显示获取到的分支信息
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_info "远程分支更新:${gl_bai}"
        git branch -r | head -10 | while IFS= read -r remote_branch; do
            echo -e "  ${gl_lv}${remote_branch}${gl_bai}"
        done
        echo -e "${gl_huang}(显示前10个远程分支)${gl_bai}"
    else
        log_error "git fetch 失败。"
        echo -e "${gl_bai}可能原因:${gl_bai}"
        echo -e "  ${gl_huang}1. 网络连接问题${gl_bai}"
        echo -e "  ${gl_huang}2. 远程仓库不存在${gl_bai}"
        echo -e "  ${gl_huang}3. 权限不足${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
        return 3
    fi

    # 3. 获取三段式提交哈希
    local_commit=$(git rev-parse @) || {
        log_error "无法获取本地提交哈希"
        return 4
    }
    
    remote_commit=$(git rev-parse "@{u}" 2>/dev/null) || {
        log_error "本地分支未关联远程分支"
        echo -e "${gl_bai}请执行以下命令设置上游分支:${gl_bai}"
        echo -e "  ${gl_huang}git branch --set-upstream-to=${remote}/${branch} ${branch}${gl_bai}"
        echo -e "${gl_bai}或者手动设置跟踪分支:${gl_bai}"
        echo -e "  ${gl_huang}git branch -u ${remote}/${branch}${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
        return 5
    }
    
    # shellcheck disable=SC1083
    base_commit=$(git merge-base @ @{u}) || {
        log_error "无法计算合并基础"
        return 6
    }
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "版本对比信息:${gl_bai}"
    echo -e "${gl_bai}本地提交: ${gl_lv}$(git log --oneline -1 @ 2>/dev/null || echo "未知")${gl_bai}"
    echo -e "${gl_bai}远程提交: ${gl_lv}$(git log --oneline -1 "@{u}" 2>/dev/null || echo "未知")${gl_bai}"
    echo -e "${gl_bai}合并基础: ${gl_lv}$(git log --oneline -1 "$base_commit" 2>/dev/null || echo "未知")${gl_bai}"

    # 4. 比对并处理
    if [[ $local_commit == "$remote_commit" ]]; then
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_ok "当前分支已经是最新版本，无需更新。"
        
        # 显示最近提交
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_info "最近的提交记录:${gl_bai}"
        git log --oneline -5
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
        return 0
    fi

    if [[ $local_commit == "$base_commit" ]]; then
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_warn "检测到远程有更新，正在拉取最新代码 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        
        # 显示将要拉取的提交
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_info "将要拉取的更新:${gl_bai}"
        git log --oneline "$local_commit".."$remote_commit" 2>/dev/null || echo -e "  ${gl_huang}无法获取更新日志${gl_bai}"
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}执行: git pull --ff-only ${gl_huang}${remote} ${branch}${gl_bai}"
        
        if git pull --ff-only "$remote" "$branch"; then
            log_ok "更新成功！"
            
            # 显示更新后的最新提交
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_info "更新后的最新提交:${gl_bai}"
            git log --oneline -3
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            # 检查是否需要合并或处理
            if [[ -n "$(git status --porcelain 2>/dev/null)" ]]; then
                log_warn "注意: 拉取后工作目录有未提交的更改"
                git status --short
            fi
            
            break_end
            return 0
        else
            log_error "更新失败，请检查错误信息。"
            
            # 显示可能的冲突
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_info "可能的冲突文件:${gl_bai}"
            git status --short | grep -E "^AA|^UU|^DD" || echo -e "  ${gl_huang}未检测到冲突文件${gl_bai}"
            
            echo -e "${gl_bai}解决冲突后，可以执行:${gl_bai}"
            echo -e "  ${gl_huang}git add .${gl_bai}   # 添加解决后的文件"
            echo -e "  ${gl_huang}git commit${gl_bai}  # 提交合并结果"
            
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            return 7
        fi
    else
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_warn "本地分支与远程分支存在分歧（可能有未推送的提交），请手动解决冲突后再更新。"
        
        # 显示本地和远程的差异
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_info "本地有未推送的提交:${gl_bai}"
        git log --oneline "@{u}".."$local_commit" 2>/dev/null || echo -e "  ${gl_huang}无法获取未推送的提交${gl_bai}"
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_info "远程有未拉取的提交:${gl_bai}"
        git log --oneline "$local_commit".."@{u}" 2>/dev/null || echo -e "  ${gl_huang}无法获取远程提交${gl_bai}"
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}建议的操作:${gl_bai}"
        echo -e "  ${gl_huang}1. 先推送本地提交: git push${gl_bai}"
        echo -e "  ${gl_huang}2. 再拉取远程更新: git pull${gl_bai}"
        echo -e "  ${gl_huang}3. 或者合并远程分支: git pull --no-ff${gl_bai}"
        
        break_end
        return 8
    fi
}

######  Git 个人 Docker 项目管理
# show_git_project_menu /vol1/1000/compose "个人Docker项目管理"
show_git_project_menu() {
    local base_path="${1:-$(pwd)}"
    local title="$2"

    # 检查当前目录是否为空，如果为空则显示提示并返回错误
    check_directory_empty "$base_path" "$title" "true" || return 1

    while true; do
        clear
        echo -e "${gl_zi}>>> Git 项目列表${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}当前工作目录: ${gl_huang}$(pwd)${gl_bai}"
        echo -e "${gl_bai}内网 IP 地址: ${gl_huang}$(get_internal_ip)${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 获取目录数组
        local projects
        if ! show_directory_list "$base_path" 4 false true projects; then
            return 1
        fi

        # projects 现在是一个数组
        local count=${#projects[@]}

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入序号进入项目（${gl_huang}0${gl_bai}返回）: ")" choice

        case $choice in
        0) cancel_return; return 0 ;;
        q | quit | exit) return 1 ;;
        *)
            [[ $choice =~ ^[0-9]+$ ]] || {
                handle_invalid_input
                continue
            }
            ((choice >= 1 && choice <= count)) || {
                handle_invalid_input
                continue
            }
            local selected_project="${projects[$((choice - 1))]}"
            local full_path="$base_path/$selected_project"
            cd "$full_path" || {
                log_error "无法进入目录 $full_path"
                continue
            }
            log_ok "已选择项目：$selected_project"
            # 调用你原有的 Git 管理菜单
            linux_git_menu
            cd "$base_path"
            ;;
        esac
    done
}

###### 更改当前仓库标签
update_git_tag() {
    local old_tag=${1:-v1.0.0}   # 第 1 个参数：旧标签，缺省 v1.0.0
    local new_tag=${2:-$old_tag} # 第 2 个参数：新标签，缺省沿用旧标签

    check_and_install git || return 1
    check_git_repository "更改当前仓库标签" "." "true" 2 || return 1

    clear
    echo -e "${gl_zi}>>> 更改当前仓库标签${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    log_info "正在添加所有更改并提交 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    git add .
    git commit -m "update"
    git pull --rebase

    # 打印当前所有标签
    log_info "当前仓库已有标签："
    git tag -l | sed 's/^/  - /' || log_info "（暂无标签）"

    # 删除本地标签
    if git tag -l | grep -qx "$old_tag"; then
        log_info "正在删除本地标签 ${old_tag} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        git tag -d "$old_tag" && log_ok "本地标签已删除。" || log_warn "本地标签删除失败。"
    else
        log_warn "本地不存在标签 ${old_tag}，跳过删除。"
    fi

    # 删除远程标签
    log_info "正在删除远程标签 ${old_tag} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    git push origin ":refs/tags/${old_tag}" 2>/dev/null || true

    # 创建并推送新标签
    log_info "正在创建新标签 ${new_tag} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    git tag -a "$new_tag" -m "Recreate tags for the latest submission"
    log_ok "标签创建完成！"

    log_info "正在推送新标签到远程仓库 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    git push origin "$new_tag"
    log_ok "标签推送完成！"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 推送所有仓库更改
push_all_repos() {
    local start_dir="${1:-$(pwd)}"  # 起始目录
    local commit_msg="${2:-update}" # 提交消息
    local exclude_dirs="${3:-}"     # 排除目录（可选）

    # 检查当前目录是否为空，如果为空则显示提示并返回错误
    check_directory_empty "$start_dir" "正在推送所有仓库更改" "true" || return 1

    clear
    echo -e "${gl_zi}>>> 正在推送所有仓库更改 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "目标目录：${gl_lv}$start_dir${gl_bai}"

    cd "$start_dir" || {
        log_error "无法进入目录：$start_dir"
        exit_animation    # 即将退出动画
        return 1
    }

    # 构建find命令，排除指定目录
    local find_cmd="find . -type d -name \".git\""
    if [ -n "$exclude_dirs" ]; then
        for dir in $exclude_dirs; do
            find_cmd="$find_cmd -not -path \"*/$dir/*\""
        done
    fi

    eval "$find_cmd" | while read -r git_dir; do
        repo_dir=$(dirname "$git_dir")

        # 快速检查是否是有效的Git仓库
        if [ ! -f "$git_dir/config" ]; then
            continue # 跳过无效仓库
        fi

        echo
        echo -e "${gl_huang}正在处理仓库：${gl_lv}$(basename "$repo_dir")${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 使用git -C选项，无需cd
        (
            # 检查是否有未提交的更改
            if git -C "$repo_dir" status --porcelain | grep -q '.'; then
                log_info "检测到更改，正在提交 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                git -C "$repo_dir" add .
                git -C "$repo_dir" commit -m "$commit_msg"
            else
                log_info "工作区干净，无需提交"
            fi

            # 拉取并推送
            git -C "$repo_dir" pull --rebase 2>/dev/null || true
            git -C "$repo_dir" push 2>/dev/null || {
                log_error "推送失败：$(basename "$repo_dir")"
                false
            }
        )

        if [ $? -eq 0 ]; then
            log_ok "推送完成 ${gl_lv}$(basename "$repo_dir")${gl_bai}"
        else
            log_error "推送失败 ${gl_lv}$(basename "$repo_dir")${gl_bai}"
        fi
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 拉取所有仓库更新
pull_all_repos() {
    local scan_dir="${1:-.}"    # 默认扫描当前目录
    local exclude_file="${2:-}" # 排除文件路径（可选）
    local exclude_args=()

    # 检查当前目录是否为空，如果为空则显示提示并返回错误
    check_directory_empty "$scan_dir" "拉取所有仓库更新" "true" || return 1

    # 如果提供了排除文件，就转成 find 的排除参数
    if [[ -n "$exclude_file" && -f "$exclude_file" ]]; then
        while IFS= read -r pattern; do
            [[ -z "$pattern" || "$pattern" =~ ^[[:space:]]*# ]] && continue
            exclude_args+=(-not -path "*/$pattern/*")
        done <"$exclude_file"
    fi

    clear
    echo -e "${gl_zi}>>> 正在拉取所有仓库更新 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "目标目录：$(readlink -f "$scan_dir")"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    find "$scan_dir" -type d -name '.git' "${exclude_args[@]}" -print0 |
        while IFS= read -r -d '' git_dir; do
            repo_dir=$(dirname "$git_dir")
            repo_name=$(basename "$repo_dir") # 只取仓库名
            echo
            log_info "检测到 Git 仓库：${gl_huang}$repo_name${gl_bai}"
            (
                cd "$repo_dir" || exit 1
                log_info "正在拉取远程更新 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                git pull
                log_ok "拉取完成：$repo_name"
            )
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        done

    log_ok "子目录中的所有仓库，拉取更新操作已完成。"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 修改为ssh连接
configure_git_ssh() {
    check_git_repository "Git SSH 配置工具" "." "true" 2 || return 1
    check_and_install git || return 1
    clear
    echo -e "${gl_zi}>>> Git SSH 配置工具${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_info "此脚本将自动将当前目录设置为 Git 安全目录，并将远程仓库的连接方式修改为 SSH。"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 将当前目录添加到 Git 安全目录
    log_info "正在将当前目录添加到 Git 安全目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if git config --global --add safe.directory "$(pwd)"; then
        log_ok "当前目录已添加到 Git 安全目录。"
    else
        log_error "添加到安全目录失败。"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查当前目录是否是一个 Git 仓库
    if ! git rev-parse --git-dir >/dev/null 2>&1; then
        log_error "当前目录不是一个 Git 仓库。"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    log_ok "当前目录是一个 Git 仓库。"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 获取当前远程仓库信息
    remote_info=$(git remote -v)
    if [[ -z "$remote_info" ]]; then
        log_error "当前 Git 仓库没有配置远程仓库。"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    log_info "当前远程仓库信息："
    echo -e "${gl_hui}$remote_info${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    log_info "正在将远程仓库修改为 SSH 连接 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    local changed=0
    while IFS= read -r line; do
        remote_name=$(echo "$line" | awk '{print $1}')
        remote_url=$(echo "$line" | awk '{print $2}')

        # 检测是否是 Gitee 或 GitHub 的 HTTPS 链接
        if [[ "$remote_url" =~ ^https://(gitee|github)\.com/ ]]; then
            # 转换为 SSH 格式
            # shellcheck disable=SC2001
            ssh_url=$(echo "$remote_url" | sed -e 's|^https://\(.*\)\.com/|git@\1.com:|')
            log_info "将远程仓库 ${remote_name} 的 URL 从 ${remote_url} 修改为 ${ssh_url}"
            if git remote set-url "$remote_name" "$ssh_url"; then
                log_ok "远程仓库 ${remote_name} 修改成功。"
                changed=1
            else
                log_error "远程仓库 ${remote_name} 修改失败。"
            fi
        else
            log_info "远程仓库 ${remote_name} 的 URL 已经是 SSH 格式，无需修改。"
        fi
    done <<<"$remote_info"

    if [[ $changed -eq 1 ]]; then
        log_ok "远程仓库已更新为 SSH 连接。"
    else
        log_info "没有需要修改的远程仓库。"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

