    if ! git rev-parse --git-dir >/dev/null 2>&1; then
        log_error "当前目录不是一个 Git 仓库。"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    log_ok "当前目录是一个 Git 仓库。"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 获取当前远程仓库信息
    remote_info=$(git remote -v)
    if [[ -z "$remote_info" ]]; then
        log_error "当前 Git 仓库没有配置远程仓库。"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi

    log_info "当前远程仓库信息："
    echo -e "${gl_hui}$remote_info${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    log_info "正在将远程仓库修改为 HTTPS 连接 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    local changed=0
    while IFS= read -r line; do
        remote_name=$(echo "$line" | awk '{print $1}')
        remote_url=$(echo "$line" | awk '{print $2}')

        # 检测是否是 Gitee 或 GitHub 的 SSH 链接
        if [[ "$remote_url" =~ ^git@(gitee|github)\.com: ]]; then
            # 转换为 HTTPS 格式
            # shellcheck disable=SC2001
            https_url=$(echo "$remote_url" | sed -e 's|^git@\([^:]*\)\(:\)\(.*\)$|https://\1/\3|')
            log_info "将远程仓库 ${remote_name} 的 URL 从 ${remote_url} 修改为 ${https_url}"
            if git remote set-url "$remote_name" "$https_url"; then
                log_ok "远程仓库 ${remote_name} 修改成功。"
                changed=1
            else
                log_error "远程仓库 ${remote_name} 修改失败。"
            fi
        else
            log_info "远程仓库 ${remote_name} 的 URL 已经是 HTTPS 格式，无需修改。"
        fi
    done <<<"$remote_info"

    if [[ $changed -eq 1 ]]; then
        log_ok "远程仓库已更新为 HTTPS 连接。"
    else
        log_info "没有需要修改的远程仓库。"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 函数_修复Git安全目录权限
fix_git_safe_directories() {
    echo -e ""
    echo -e "${gl_zi}>>> 修复 Git 仓库安全目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 预设目录选项
    local preset_dirs=(
        "/compose"
        "/mnt/compose"
        "/vol1/1000/compose"
        "/vol2/1000/compose"
    )

    # 获取当前所有安全目录列表
    local safe_dirs_list=$(git config --global --get-all safe.directory 2>/dev/null)

    # 扫描所有Git仓库
    log_info "正在扫描所有 Git 仓库 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    local all_git_repos=()

    # 扫描预设目录下的所有Git仓库
    for preset_dir in "${preset_dirs[@]}"; do
        if [[ -d "$preset_dir" ]]; then
            while IFS= read -r git_dir; do
                [[ -z "$git_dir" ]] && continue
                local repo_dir=$(dirname "$git_dir")
                all_git_repos+=("$repo_dir")
            done < <(find "$preset_dir" -name ".git" -type d 2>/dev/null)
        fi
    done

    # 去重Git仓库列表
    local unique_git_repos=()
    for repo in "${all_git_repos[@]}"; do
        local exists=false
        for existing in "${unique_git_repos[@]}"; do
            if [[ "$existing" == "$repo" ]]; then
                exists=true
                break
            fi
        done
        if ! $exists; then
            unique_git_repos+=("$repo")
        fi
    done
    all_git_repos=("${unique_git_repos[@]}")

    if [[ ${#all_git_repos[@]} -eq 0 ]]; then
        echo -e "${gl_huang}未扫描到 Git 仓库${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        return
    fi

    # 显示扫描结果 - 只显示Git仓库，用颜色标记是否已是安全目录
    echo -e "${gl_bai}扫描到以下 Git 仓库:${gl_bai}"
    for repo in "${all_git_repos[@]}"; do
        local repo_name=$(basename "$repo")
        # 检查是否已是安全目录
        if echo "$safe_dirs_list" | grep -Fxq "$repo"; then
            # 已是安全目录 - 绿色
            echo -e "  ${gl_lv}●${gl_bai} ${gl_lv}${repo_name}${gl_bai} ${gl_lv}[已是安全目录]${gl_bai}"
        else
            # 不是安全目录 - 红色
            echo -e "  ${gl_hong}●${gl_bai} ${gl_hong}${repo_name}${gl_bai} ${gl_hong}[未添加]${gl_bai}"
        fi
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    sleep_fractional 1

    # 显示目录选择菜单 - 只显示包含Git仓库的目录
    clear
    echo -e ""
    echo -e "${gl_huang}>>> 请选择要处理的目录:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 构建菜单选项数组（只包含有Git仓库的目录）
    local menu_options=()
    local option_paths=()

    # 1. 首先添加所有包含Git仓库的预设目录
    for preset_dir in "${preset_dirs[@]}"; do
        if [[ -d "$preset_dir" ]]; then
            # 检查此预设目录下是否有Git仓库
            local has_git=false
            for repo in "${all_git_repos[@]}"; do
                if [[ "$repo" == "$preset_dir"* ]]; then
                    has_git=true
                    break
                fi
            done

            if $has_git; then
                # 统计该目录下的Git仓库数量
                local git_count=0
                for repo in "${all_git_repos[@]}"; do
                    if [[ "$repo" == "$preset_dir"* ]]; then
                        ((git_count++))
                    fi
                done

                # 检查是否所有仓库都已是安全目录
                local all_safe=true
                for repo in "${all_git_repos[@]}"; do
                    if [[ "$repo" == "$preset_dir"* ]]; then
                        if ! echo "$safe_dirs_list" | grep -Fxq "$repo"; then
                            all_safe=false
                            break
                        fi
                    fi
                done

                if $all_safe; then
                    menu_options+=("${gl_huang}$preset_dir ${gl_bai}[${gl_lv}${git_count}${gl_bai}个仓库] [${gl_lv}全部已添加${gl_bai}]${gl_bai}")
                else
                    menu_options+=("${gl_hong}$preset_dir ${gl_bai}[${gl_lv}${git_count}${gl_bai}个仓库] [${gl_huang}待修复${gl_bai}]${gl_bai}")
                fi
                option_paths+=("$preset_dir")
            fi
        fi
    done

    # 2. 添加单个Git仓库选项
    for repo in "${all_git_repos[@]}"; do
        local repo_name=$(basename "$repo")
        # 检查是否已是安全目录
        if echo "$safe_dirs_list" | grep -Fxq "$repo"; then
            menu_options+=("${gl_huang}$repo_name ${gl_bai}[${gl_lv}已是安全目录${gl_bai}]${gl_bai}")
        else
            menu_options+=("${gl_hong}$repo_name ${gl_bai}[${gl_hong}未添加${gl_bai}]${gl_bai}")
        fi
        option_paths+=("$repo")
    done

    # 3. 添加手动输入选项
    menu_options+=("手动指定路径")
    option_paths+=("MANUAL_INPUT")

    # 显示菜单
    for i in "${!menu_options[@]}"; do
        echo -e "${gl_bufan}$((i + 1)).${gl_bai} ${menu_options[i]}"
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    local max_choice=${#menu_options[@]}

    # 读取用户选择
    read -r -e -p "$(echo -e "${gl_bai}请输入你的选择 (${gl_lv}1${gl_bai}-${gl_huang}$max_choice${gl_bai}) (${gl_huang}0${gl_bai}返回): ")" dir_choice

    # 处理选择
    local SCAN_DIR=""

    if [[ "$dir_choice" =~ ^[0-9]+$ ]]; then
        if [[ $dir_choice -eq 0 ]]; then
            return
        elif [[ $dir_choice -le $max_choice ]]; then
            local selected_path="${option_paths[$((dir_choice - 1))]}"
            if [[ "$selected_path" == "MANUAL_INPUT" ]]; then
                read -r -e -p "$(echo -e "${gl_bai}请输入自定义路径: ")" SCAN_DIR
            else
                SCAN_DIR="$selected_path"
            fi
        else
            log_error "无效选择"
            return
        fi
    else
        SCAN_DIR="$dir_choice"
    fi

    # 检查是否为空
    if [[ -z "$SCAN_DIR" ]]; then
        log_warn "路径不能为空"
        return
    fi

    # 检查目录是否存在
    if [[ ! -d "$SCAN_DIR" ]]; then
        log_warn "目录不存在: $SCAN_DIR"
        return
    fi

    echo -e "${gl_bai}扫描目录: ${gl_huang}$SCAN_DIR${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 开始修复Git安全目录
    echo -e "${gl_bai}开始修复Git仓库的安全目录权限 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo ""

    local processed_count=0
    local skipped_count=0

    # 确定要处理的Git仓库列表
    local target_repos=()

    if [[ -d "$SCAN_DIR/.git" ]]; then
        # 单个Git仓库
        target_repos+=("$SCAN_DIR")
    else
        # 目录，查找其中所有Git仓库
        for repo in "${all_git_repos[@]}"; do
            if [[ "$repo" == "$SCAN_DIR"* ]] || [[ "$SCAN_DIR" == "$repo"* ]]; then
                target_repos+=("$repo")
            fi
        done

        # 如果没找到，尝试深度搜索
        if [[ ${#target_repos[@]} -eq 0 ]]; then
            while IFS= read -r git_dir; do
                [[ -z "$git_dir" ]] && continue
                target_repos+=("$(dirname "$git_dir")")
            done < <(find "$SCAN_DIR" -name ".git" -type d 2>/dev/null)
        fi
    fi

    # 去重
    local unique_targets=()
    for repo in "${target_repos[@]}"; do
        local exists=false
        for existing in "${unique_targets[@]}"; do
            if [[ "$existing" == "$repo" ]]; then
                exists=true
                break
            fi
        done
        if ! $exists; then
            unique_targets+=("$repo")
        fi
    done
    target_repos=("${unique_targets[@]}")

    if [[ ${#target_repos[@]} -eq 0 ]]; then
        echo -e "${gl_huang}在 $SCAN_DIR 中没有找到 Git 仓库${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        return
    fi

    echo -e "${gl_bai}找到 ${#target_repos[@]} 个 Git 仓库:${gl_bai}"
    echo ""

    # 刷新安全目录列表
    safe_dirs_list=$(git config --global --get-all safe.directory 2>/dev/null)

    # 处理每个Git仓库
    for i in "${!target_repos[@]}"; do
        local repo_dir="${target_repos[i]}"
        local repo_name=$(basename "$repo_dir")

        echo -e "正在处理 [${gl_huang}$((i + 1))/${#target_repos[@]}${gl_bai}]: ${gl_huang}$repo_name${gl_bai}"
        echo -e "  路径: ${gl_bai}$repo_dir${gl_bai}"

        # 检查是否已是安全目录
        if echo "$safe_dirs_list" | grep -Fxq "$repo_dir"; then
            echo -e "  ${gl_lv}✓${gl_bai} ${gl_lv}已是安全目录，跳过${gl_bai}"
            ((skipped_count++))
        else
            # 添加为安全目录
            if git config --global --add safe.directory "$repo_dir" 2>/dev/null; then
                echo -e "  ${gl_lv}✓${gl_bai} ${gl_lv}已添加为安全目录${gl_bai}"
                ((processed_count++))
                # 更新列表
                safe_dirs_list=$(git config --global --get-all safe.directory 2>/dev/null)
            else
                echo -e "  ${gl_hong}✗${gl_bai} ${gl_hong}添加失败${gl_bai}"
            fi
        fi

        echo ""
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}处理完成！${gl_bai}"
    echo -e "${gl_bai}找到 Git 仓库: ${gl_huang}${#target_repos[@]}${gl_bai}"
    echo -e "${gl_bai}本次添加: ${gl_lv}$processed_count${gl_bai}"
    echo -e "${gl_bai}跳过(已是): ${gl_lv}$skipped_count${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 显示当前所有安全目录（去重）
    echo -e "${gl_bai}当前所有安全目录:${gl_bai}"
    git config --global --get-all safe.directory 2>/dev/null | sort -u | while read -r safe_dir; do
        echo -e "  ${gl_lv}•${gl_bai} $safe_dir"
    done

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 返回主菜单
    read -n 1 -s -r -p "$(echo -e "按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
    echo

    return 0
}

