###### 克隆仓库
clone_repository() {
    check_and_install git || return 1
    clear
    echo -e ""
    echo -e "${gl_bai}当前完整工作目录: ${gl_huang}$(pwd)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    ls --color=auto -x
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    echo -e ""
    echo -e "${gl_huang}>>> 当前目录序号列表: ${gl_huang}$(pwd)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}当前目录下的子目录: ${gl_bai}(${gl_bufan}序号选择目录${gl_bai})${gl_bai}"
    local dir_list=()
    local current_path="$(pwd)"

    if ! show_directory_list "$current_path" 4 false true dir_list; then
        echo -e "${gl_huang}当前目录没有可用的子目录${gl_bai}"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}请输入${gl_bufan}序号${gl_bai}/${gl_huang}路径${gl_bai}/${gl_hong}回车${gl_bai}使用当前目录${gl_bai}/${gl_huang}0${gl_bai}返回: ")" work_input

    if [[ "$work_input" == "0" ]]; then
        cancel_return
        return 1
    elif [[ -z "$work_input" ]]; then
        local work_dir="."
        echo -e ""
        echo -e "使用当前目录: ${gl_huang}$(pwd)${gl_bai}"
    elif [[ "$work_input" =~ ^[0-9]+$ ]]; then
        if [[ ${#dir_list[@]} -gt 0 ]] && ((work_input >= 1 && work_input <= ${#dir_list[@]})); then
            local selected_dir="${dir_list[$((work_input - 1))]}"
            local work_dir="./$selected_dir"
            echo -e "选择子目录: ${gl_huang}$work_dir${gl_bai}"
        else
            echo -e "${gl_hong}无效的序号: $work_input${gl_bai}"
            return 1
        fi
    else
        local work_dir="$work_input"
        echo -e "使用指定目录: ${gl_huang}$work_dir${gl_bai}"
    fi

    if [[ ! -d "$work_dir" ]]; then
        echo -e ""
        echo -e "${gl_huang}目录不存在: $work_dir${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}是否创建此目录?  (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" create_choice
        case "$create_choice" in
        y | Y | yes | YES)
            mkdir -p "$work_dir"
            if [ $? -eq 0 ]; then
                echo -e "${gl_lv}目录创建成功: $work_dir${gl_bai}"
            else
                echo -e "${gl_hong}目录创建失败: $work_dir${gl_bai}"
                return 1
            fi
            ;;
        *) handle_invalid_input ;;      # 无效的输入,请重新输入!
        esac
    fi

    cd "$work_dir" && clone_custom_repo
}

