    echo -e "${gl_bai}当前工作目录: ${gl_huang}$(pwd)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    ls --color=auto -x
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请输入工作目录 (回车当前目录克隆，${gl_huang}0${gl_bai}返回): ")" work_dir

    if [[ "$work_dir" == "0" ]]; then
        cancel_return
        return 1
    elif [[ -z "$work_dir" ]]; then
        work_dir="."
        echo -e "使用当前目录: ${gl_huang}$(pwd)${gl_bai}"
    elif [[ ! -d "$work_dir" ]]; then
        echo -e "${gl_huang}目录不存在: $work_dir${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}是否创建此目录?  (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" create_choice

        case "$create_choice" in
        y | Y | yes | YES)
            mkdir -p "$work_dir"
            if [ $? -eq 0 ]; then
                echo -e "${gl_lv}目录创建成功: $work_dir${gl_bai}"
            else
                echo -e "${gl_hong}目录创建失败: $work_dir${gl_bai}"
                return 1
            fi
            ;;
        *) handle_invalid_input ;;      # 无效的输入,请重新输入!
        esac
    fi

    cd "$work_dir" || {
        echo -e "${gl_hong}无法切换到目录: $work_dir${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    }
    git_clone_docker_projects
}

###### 卸载Git
uninstall_git() {
    if ! command -v git &>/dev/null; then
        echo -e ""
        log_warn "Git 未安装，无需卸载"
        exit_animation    # 即将退出动画
        return 1
    fi

    echo -e ""
    echo -e "${gl_zi}>>> 正在卸载： ${gl_huang}Git ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}确定要卸载 Git 吗？ (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")"
    if [[ ! $REPLY =~ ^[Yy]$ ]]; then
        echo -e "${gl_huang}已取消卸载操作${gl_bai}"
        exit_animation    # 即将退出动画 
        return 1
    fi

    clear
    echo -e ""
    remove git
    break_end
}


###### Git 历史彻底清理工具
# 功能：删除所有历史提交，清理仓库垃圾，同步远程
git_nuke_history() {
    echo -e ""
    echo -e "${gl_zi}>>> Git 历史清理工具${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 检查是否在 git 仓库中
    if ! git rev-parse --git-dir > /dev/null 2>&1; then
        log_error "当前目录不是 Git 仓库"
        return 1
    fi

    # 获取当前分支
    local CURRENT_BRANCH
    CURRENT_BRANCH=$(git branch --show-current)
    if [ -z "$CURRENT_BRANCH" ]; then
        log_error "无法获取当前分支（可能处于 detached HEAD 状态）"
        return 1
    fi

    log_info "当前分支: $CURRENT_BRANCH"

    # 获取远程信息
    local REMOTE_NAME
    REMOTE_NAME=$(git remote | head -n 1)
    if [ -z "$REMOTE_NAME" ]; then
        log_error "没有配置远程仓库"
        return 1
    fi

    log_info "远程仓库: $REMOTE_NAME"

    # 检查是否有未提交的更改
    if ! git diff-index --quiet HEAD -- 2>/dev/null || [ -n "$(git status --porcelain)" ]; then
        log_warn "检测到未提交的更改"
        read -r -e -p "$(echo -e "${gl_bai}是否自动暂存并提交所有更改？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}/${gl_huang}0${gl_bai}返回): ")" auto_commit
        [ "$auto_commit" = "0" ] && { cancel_return "Git 历史清理工具"; return 1; }
        if [[ "$auto_commit" =~ ^[Yy]$ ]]; then
            log_info "正在暂存所有更改 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            git add -A
            git commit -m "WIP: 清理历史前的临时提交" || true
        else
            log_warn "请先处理未提交的更改后再运行此脚本"
            return 1
        fi
    fi

    # 确认操作（极度危险）
    echo ""
    log_warn "⚠️  警告：此操作将永久删除所有 Git 历史记录！"
    log_warn "⚠️  包括：提交记录、标签、分支历史、所有日志"
    log_warn "⚠️  此操作不可逆，请确保已备份重要数据"
    echo ""
    read -r -e -p "$(echo -e "${gl_bai}请输入 '${gl_hong}NUKE${gl_bai}' 以确认执行清理操作 (${gl_huang}0${gl_bai}返回): ")" confirm
    [ "$confirm" = "0" ] && { cancel_return "Git 历史清理工具"; return 1; }

    if [ "$confirm" != "NUKE" ]; then
        log_warn "操作已取消"
        return 0
    fi

    # 再次确认远程分支
    echo ""
    read -r -e -p "$(echo -e "${gl_bai}确认要强制推送到远程 '${gl_bai}$REMOTE_NAME/$CURRENT_BRANCH${gl_bai}' ？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" remote_confirm
    if [[ "$remote_confirm" =~ ^[Yy]$ ]]; then
        local DO_PUSH=true
    else
        local DO_PUSH=false
        log_warn "远程推送已取消，仅清理本地仓库"
    fi

    echo ""
    echo -e "${gl_zi}>>> 开始执行清理流程 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # 记录清理前的大小
    log_info "[1/6] 分析当前仓库状态 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    local BEFORE_SIZE
    BEFORE_SIZE=$(du -sh .git 2>/dev/null | cut -f1)
    echo -e "   清理前 .git 目录大小: ${gl_huang}$BEFORE_SIZE${gl_bai}"

    # 创建孤立分支
    log_info "[2/6] 创建孤立分支 (orphan branch) ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    git checkout --orphan __temp_clean_branch__
    if [ $? -ne 0 ]; then
        log_error "创建孤立分支失败"
        git checkout "$CURRENT_BRANCH" 2>/dev/null || true
        return 1
    fi

    # 提交当前代码
    log_info "[3/6] 创建新的初始提交 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    git add -A
    git commit -m "Initial commit: 清理历史后的全新开始

    - 删除了所有历史提交记录
    - 清理了仓库垃圾数据
    - 重置于 $(date '+%Y-%m-%d %H:%M:%S')"

    if [ $? -ne 0 ]; then
        log_error "创建提交失败"
        git checkout "$CURRENT_BRANCH" 2>/dev/null || true
        git branch -D __temp_clean_branch__ 2>/dev/null
        return 1
    fi

    # 删除旧分支，重命名新分支
    log_info "[4/6] 替换原分支 '$CURRENT_BRANCH' ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    git branch -D "$CURRENT_BRANCH" 2>/dev/null || true
    git branch -m "$CURRENT_BRANCH"

    # 强制推送到远程
    if [ "$DO_PUSH" = true ]; then
        log_info "[5/6] 强制推送到远程仓库. ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}.."
        git push -f "$REMOTE_NAME" "$CURRENT_BRANCH"
        if [ $? -ne 0 ]; then
            log_error "推送到远程失败"
            log_warn "本地分支已清理，但远程未同步"
        else
            log_ok "   ✓ 远程仓库已同步清理"
        fi
    else
        log_warn "[5/6] 跳过远程推送（用户取消）"
    fi

    # 深度清理本地仓库
    log_info "[6/6] 深度清理本地垃圾数据. ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}.."

    # 清理 reflog（引用日志）
    git reflog expire --expire=now --all

    # 激进式垃圾回收
    git gc --aggressive --prune=now

    # 显示清理结果
    echo ""
    log_ok "         清理完成！"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo ""

    local AFTER_SIZE
    AFTER_SIZE=$(du -sh .git 2>/dev/null | cut -f1)
    echo -e "仓库大小变化:"
    echo -e "  清理前: ${gl_huang}$BEFORE_SIZE${gl_bai}"
    echo -e "  清理后: ${gl_lv}$AFTER_SIZE${gl_bai}"
    echo ""

    echo -e "当前状态:"
    echo -e "  分支: ${gl_lv}$(git branch --show-current)${gl_bai}"
    echo -e "  提交数: ${gl_lv}$(git rev-list --count HEAD)${gl_bai} (应为 1)"
    echo -e "  最新提交: ${gl_lv}$(git log -1 --oneline)${gl_bai}"
    echo ""

    # 显示对象统计
    echo -e "对象统计:"
    git count-objects -vH 2>/dev/null | sed 's/^/  /' || log_warn "获取对象统计信息失败"
    echo ""

    if [ "$DO_PUSH" = true ]; then
        log_warn "提醒：其他协作者需要重新克隆仓库，或执行:"
        echo -e "  ${gl_lan}git fetch origin${gl_bai}"
        echo -e "  ${gl_lan}git reset --hard origin/$CURRENT_BRANCH${gl_bai}"
    fi

    break_end
    return 0
}

# Git 缓存清理函数
# 功能：应用.gitignore规则，清理git缓存中不必要的文件
# 参数：无
# 返回：0=成功，1=用户取消
git_clean_cache() {
    local choice
    
    # 显示标题
    echo -e "${gl_zi}>>> Git缓存清理 (强制应用.gitignore)${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 显示操作说明
    echo -e "${gl_lan}[信息]${gl_bai} 此操作将执行以下步骤:"
    echo -e "  ${gl_bufan}1.${gl_bai} 清除所有缓存（保留本地文件）"
    echo -e "  ${gl_bufan}2.${gl_bai} 重新添加所有文件（忽略规则将生效）"
    echo -e "  ${gl_bufan}3.${gl_bai} 提交更改"
    echo -e "  ${gl_bufan}4.${gl_bai} 推送到远程仓库"
    echo -e ""
    echo -e "${gl_huang}[警告]${gl_bai} 此操作会重置git跟踪状态，"
    echo -e "      确保当前目录是有效的git仓库。"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 交互式确认
    while true; do
        read -r -e -p "$(echo -e "${gl_bai}确定要执行Git缓存清理吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}/${gl_huang}0${gl_bai}返回): ")" choice
        
        case "$choice" in
            [Yy])
                # 用户确认执行
                echo -e ""
                break
                ;;
            [Nn0])
                # 用户取消操作
                if [ "$choice" = "0" ]; then
                    cancel_return "Git操作选单"
                else
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    echo -e "${gl_huang}[信息]${gl_bai} 已取消Git缓存清理操作"
                    sleep 1
                fi
                return 1
                ;;
            *)
                # 无效输入
                handle_y_n
                ;;
        esac
    done
    
    # 步骤1: 清除所有缓存
    log_info "正在清除所有缓存（保留本地文件） ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if git rm -r --cached .; then
        log_ok "缓存清除完成"
    else
        log_error "缓存清除失败，请检查当前目录是否为git仓库"
        break_end
        return 1
    fi
    
    echo -e ""
    
    # 步骤2: 重新添加所有文件
    log_info "正在重新添加所有文件（忽略规则生效） ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if git add .; then
        log_ok "文件重新添加完成"
    else
        log_error "文件添加失败"
        break_end
        return 1
    fi
    
    echo -e ""
    
    # 步骤3: 提交更改
    log_info "正在提交更改..."
    if git commit -m "🎯 应用 .gitignore 规则，清理不必要的跟踪文件"; then
        log_ok "提交完成"
    else
        log_warn "提交失败或无更改可提交"
    fi
    
    echo -e ""
    
    # 步骤4: 推送到远程仓库
    log_info "正在推送到远程仓库 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if git push origin main; then
        log_ok "推送成功"
    else
        # 尝试推送当前分支
        current_branch=$(git branch --show-current 2>/dev/null)
        if [ -n "$current_branch" ]; then
            log_info "尝试推送到当前分支: $current_branch"
            if git push origin "$current_branch"; then
                log_ok "推送成功（分支: $current_branch）"
            else
                log_error "推送失败，请手动检查远程仓库设置"
            fi
        else
            log_error "推送失败，无法确定当前分支"
        fi
    fi
    
    echo -e ""
    log_ok "Git缓存清理操作已完成"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 等待用户确认
    break_end
    
    return 0
}

###### 函数：显示 Git脚本
linux_git_menu() {
