}

###### 回收站管理菜单
manage_trash_menu() {
    # 在菜单开始前加载配置
    load_trash_config

    # 检查是否需要自动配置
    local user_shell=$(basename "$SHELL")
    local config_file=""

    case "$user_shell" in
    bash) config_file="$HOME/.bashrc" ;;
    zsh) config_file="$HOME/.zshrc" ;;
    esac

    # 检查是否已经配置了rm重定向
    local rm_configured=false
    if [[ -n "$config_file" ]] && grep -q "alias rm=" "$config_file" 2>/dev/null; then
        rm_configured=true
    fi

    # 如果未配置，提示用户自动配置
    if [[ "$rm_configured" == "false" ]]; then
        clear
        echo -e "${gl_zi}>>> 回收站管理${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_hong}检测到您的系统尚未配置回收站功能${gl_bai}"
        echo -e "${gl_huang}自动配置将执行以下操作：${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "   ${gl_bufan}1. ${gl_bai}安装回收站工具（如未安装）"
        echo -e "   ${gl_bufan}2. ${gl_bai}初始化回收站功能"
        echo -e "   ${gl_bufan}3. ${gl_bai}配置 ${gl_huang}rm${gl_bai} 命令重定向到回收站"
        echo -e "   ${gl_bufan}4. ${gl_bai}更新 ${gl_huang}shell${gl_bai} 配置文件"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_hong}注意：配置后，使用 ${gl_huang}rm${gl_hong} 命令删除的文件将进入回收站而非永久删除${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "$(echo -e "${gl_bai}是否自动配置回收站? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" -n1 -r
        echo
        if [[ $REPLY =~ ^[Yy]$ ]]; then
            auto_setup_trash
            echo
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}按任意键进入回收站管理菜单 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
            read -r -n1 -s
        fi
    fi

    while true; do
        clear
        echo -e "${gl_zi}>>> 回收站管理${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 显示回收站状态
        if [[ -n "$TRASH_CMD" ]]; then
            echo -e "${gl_bufan}回收站状态: ${gl_lv}已启用 (${gl_huang}$TRASH_CMD)${gl_bai}"
        else
            echo -e "${gl_bufan}回收站状态: ${gl_hui}未启用${gl_bai}"
        fi

        # 显示rm重定向状态
        check_rm_redirect_silent
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 默认显示回收站内容和统计信息
        show_trash_contents_and_stats

        # 显示菜单选项
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}关闭回收站            ${gl_bufan}2.  ${gl_bai}开启回收站"
        echo -e "${gl_bufan}3.  ${gl_bai}清空回收站            ${gl_bufan}4.  ${gl_bai}恢复回收站"
        echo -e "${gl_bufan}5.  ${gl_bai}刷新回收站            ${gl_bufan}6.  ${gl_bai}测试回收站"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lv}66. ${gl_bai}初始化回收站          ${gl_hong}99. ${gl_bai}卸载回收站"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单        ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " sub_choice
        case $sub_choice in
        1) disable_trash ;;                                 # 关闭回收站
        2) enable_trash ;;                                  # 开启回收站
        3) empty_trash ;;                                   # 清空回收站
        4) restore_trash_interactive ;;                     # 恢复回收站
        5) refresh_trash ;;                                 # 刷新回收站
        6) test_trash_function ;;                           # 测试回收站
        66) one_click_auto_setup ;;                         # 初始化回收站
        99) uninstall_trash_tool ;;                         # 卸载回收站
        0) cancel_return; break ;;                          # 返回到上一级菜单
        00 | 000 | 0000) save_trash_config; exit_script ;;  # 退出前保存配置
        *) handle_invalid_input ;;                          # 无效的输入,请重新输入!
        esac
    done
}

######## 压缩文件/目录 - 独立函数
compress_file() {
    local target="$1"
    local format="$2"
    local output_dir="${3:-.}"
    local archive_name="${target}.${format}"
    local cmd=()

    [[ -e "$target" ]] || {
        echo -e "${gl_hong}错误：'$target' 不存在！${gl_bai}"
        return 1
    }

    [[ -d "$output_dir" ]] || {
        echo -e "${gl_huang}创建目录：$output_dir${gl_bai}"
        mkdir -p "$output_dir"
    }

    # 如果目标目录不是当前目录，则构造完整路径
    if [[ "$output_dir" != "." ]]; then
        archive_name="$output_dir/$(basename "$target").${format}"
    fi

    log_info "${gl_bufan}正在压缩：${gl_lv}$target ${gl_bai}→ ${gl_huang}$archive_name${gl_bai}"

    case "$format" in
    zip)
        command -v zip &>/dev/null || {
            echo -e "${gl_hong}错误：zip 命令未安装！${gl_bai}"
            return 1
        }
        if [[ -d "$target" ]]; then
            cmd=("zip" "-r" "-q")
        else
            cmd=("zip" "-q")
        fi
        "${cmd[@]}" "$archive_name" "$target"
        ;;
    7z)
        command -v 7z &>/dev/null || {
            echo -e "${gl_hong}错误：7z 命令未安装！${gl_bai}"
            return 1
        }
        if [[ -d "$target" ]]; then
            cmd=("7z" "a")
        else
            cmd=("7z" "a")
        fi
        "${cmd[@]}" "$archive_name" "$target"
        ;;
    tar)
        cmd=("tar" "-cf")
        "${cmd[@]}" "$archive_name" "$target"
        ;;
    tar.gz)
        cmd=("tar" "-zcf")
        "${cmd[@]}" "$archive_name" "$target"
        ;;
    tar.bz2)
        cmd=("tar" "-jcf")
        "${cmd[@]}" "$archive_name" "$target"
        ;;
    tar.xz)
        cmd=("tar" "-Jcf")
        "${cmd[@]}" "$archive_name" "$target"
        ;;
    *)
        echo -e "${gl_hong}不支持的压缩格式：$format${gl_bai}"
        return 1
        ;;
    esac

    if [[ $? -eq 0 ]]; then
        log_ok "压缩完成！文件大小：${gl_huang}$(du -h "$archive_name" | cut -f1)${gl_bai}"
        return 0
    else
        log_error "压缩失败！${gl_bai}"
        return 1
    fi
}

######## 交互式删除文件/目录
interactive_delete() {
    # 尝试初始化回收站
    echo -e ""

    if [[ -z "$TRASH_CMD" ]]; then
        install_trash
    fi

    while true; do
        # 检查当前目录是否为空，如果为空则显示提示并返回错误
        check_directory_empty "." "删除模式" "true" || return

        clear

        # 新代码：调用 list_files
        if ! list_files "." 0 4; then
            exit_animation    # 即将退出动画
            return 1
        fi

        # 检查数组是否为空
        if [[ ${#LIST_FILES_ARRAY[@]} -eq 0 ]] || [[ "$LIST_FILES_COUNT" -eq 0 ]]; then
            exit_animation    # 即将退出动画
            return 1
        fi
        local list=("${LIST_FILES_ARRAY[@]}")

        echo -e ""
        echo -e "${gl_zi}>>> 删除模式${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入序号 (多选用空格分隔) (${gl_huang}0 ${gl_bai}返回, ${gl_hong}c${gl_bai} 清空目录): ")" -e raw

        # 重要：只在用户输入0或留空时才返回主菜单
        [ -z "$raw" ] && { cancel_empty "上一级选单"; return 1; }        # break 或 continue 或 return ，视上下文而定
        [ "$raw" = "0" ] && { cancel_return "上一级选单"; return 1; }   # break 或 continue 或 return ，视上下文而定

        # ---- 处理清空目录选项 ----
        if [[ $raw == "c" || $raw == "C" ]]; then
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_hong}⚠ 警告：您选择了清空当前目录！${gl_bai}"
            echo -e "${gl_huang}当前目录 ${gl_lv}$(pwd) ${gl_bai}下共有 ${gl_lv}${#list[@]}${gl_bai} 个文件/目录"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            # 显示将要删除的所有项目
            echo -e "${gl_huang}将要删除以下所有内容：${gl_bai}"
            for item in "${list[@]}"; do
                if [[ -d "$item" ]]; then
                    echo -e "  ${gl_bai}目录: ${gl_zi}$item${gl_bai}"
                else
                    echo -e "  ${gl_bai}文件: ${gl_lv}$item${gl_bai}"
                fi
            done
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

            # 二次确认
            read -r -e -p "$(echo -e "${gl_bai}确认要清空当前目录吗？(输入 ${gl_hong}yes${gl_bai} 确认): ")" confirm_response

            if [[ $confirm_response == "yes" ]]; then
                local ok=0 fail=0

                for item in "${list[@]}"; do
                    if [[ -n "$TRASH_CMD" ]]; then
                        if delete_file_with_trash "$item"; then
                            ((ok++))
                        else
                            ((fail++))
                        fi
                    else
                        # 如果没有回收站，使用原来的删除逻辑
                        if delete_file_with_trash "$item"; then
                            ((ok++))
                        else
                            ((fail++))
                        fi
                    fi
                done

                if [[ -n "$TRASH_CMD" ]]; then
                    if ((ok > 0)); then
                        echo -e "${gl_lv}✓ 成功移动 ${gl_huang}$ok${gl_bai} 项到回收站${gl_bai}"
                    fi
                    if ((fail > 0)); then
                        echo -e "${gl_hong}✗ $fail 项移动失败${gl_bai}"
                    fi
                else
                    if ((ok > 0)); then
                        echo -e "${gl_lv}✓ 成功删除 ${gl_huang}$ok${gl_bai} 项${gl_bai}"
                    fi
                    if ((fail > 0)); then
                        echo -e "${gl_hong}✗ $fail 项删除失败${gl_bai}"
                    fi
                fi
            else
                echo -e "${gl_huang}已取消清空目录操作${gl_bai}"
            fi

            # 删除完成后直接按任意键继续
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            continue
        fi

        # ---- 解析用户输入 ----
        local to_del=() tok idx
        read -r -a tokens <<<"$raw"

        for tok in "${tokens[@]}"; do
            [[ -z "$tok" ]] && continue

            # 1) 纯数字 → 直接按"序号"处理
            if [[ $tok =~ ^[0-9]+$ ]] && ((tok >= 1 && tok <= ${#list[@]})); then
                local selected_item="${list[$((tok - 1))]}"
                [[ -e "$selected_item" ]] && to_del+=("$selected_item")
                continue
            fi

            # 2) 非数字 → 先当 glob 试
            local glob_result=()
            shopt -s nullglob
            glob_result=($tok) # 故意不加双引号，让 bash 展开
            shopt -u nullglob

            if ((${#glob_result[@]})); then
                for item in "${glob_result[@]}"; do
                    [[ "$item" == ./* ]] && item="${item#./}"
                    [[ -e "$item" ]] && to_del+=("$item")
                done
                continue
            fi

            # 3) 既不是数字，glob 也没展开，再看是不是字面路径
            if [[ -e "$tok" ]]; then
                to_del+=("$tok")
            else
                echo -e "${gl_hong}跳过无效输入或文件不存在: $tok${gl_bai}"
            fi
        done
        ((${#to_del[@]} == 0)) && {
            echo -e "${gl_huang}没有有效的文件可删除${gl_bai}"
            exit_animation    # 即将退出动画
            continue
        }

        # ---- 二次确认 ----
        echo
        echo -e "${gl_huang}>>> 即将删除以下 ${gl_bufan}${#to_del[@]}${gl_bai} ${gl_huang}项："
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        for item in "${to_del[@]}"; do
            echo -e "  ${gl_lv}$item${gl_bai}"
        done

        local confirm_response
        if [[ -n "$TRASH_CMD" ]]; then
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}确认移动到回收站? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_response
        else
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "$(echo -e "${gl_bai}确认永久删除? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm_response
        fi

        [[ $confirm_response =~ ^[Yy]$ ]] || {
            echo -e "${gl_huang}操作已取消${gl_bai}"
            exit_animation    # 即将退出动画
            continue
        }

        # ---- 执行删除 ----
        local ok=0 fail=0
        for item in "${to_del[@]}"; do
            if [[ -n "$TRASH_CMD" ]]; then
                if delete_file_with_trash "$item"; then
                    ((ok++))
                else
                    ((fail++))
                fi
            else
                # 如果没有回收站，使用原来的删除逻辑
                if delete_file_with_trash "$item"; then
                    ((ok++))
                else
                    ((fail++))
                fi
            fi
        done

        if [[ -n "$TRASH_CMD" ]]; then
            if ((ok > 0)); then
                echo -e "${gl_lv}✓ 成功移动 ${gl_huang}$ok${gl_bai} 项到回收站${gl_bai}"
            fi
            if ((fail > 0)); then
                echo -e "${gl_hong}✗ $fail 项移动失败${gl_bai}"
            fi
        else
            if ((ok > 0)); then
                echo -e "${gl_lv}✓ 成功删除 ${gl_huang}$ok${gl_bai} 项${gl_bai}"
            fi
            if ((fail > 0)); then
                echo -e "${gl_hong}✗ $fail 项删除失败${gl_bai}"
            fi
        fi

        # 删除完成后直接按任意键继续
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    done
}

###### 解压文件 - 独立函数
extract_file() {
    local archive="$1" output_dir="${2:-.}" auto_yes="${3:-false}"

    [[ -f "$archive" ]] || {
        echo -e "${gl_hong}错误：'$archive' 不存在！${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    }

    [[ -d "$output_dir" ]] || {
        echo -e "${gl_huang}创建目录：$output_dir${gl_bai}"
        mkdir -p "$output_dir"
    }

    local cmd=() confirm
    case "$archive" in
    *.zip)
        if [[ "$auto_yes" == "true" ]]; then
            cmd=("unzip" "-o" "-q") # 自动覆盖所有文件
        else
            cmd=("unzip" "-q") # 交互式处理重复文件
        fi
        command -v unzip &>/dev/null || {
            echo -e "${gl_hong}错误：unzip 命令未安装！${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        }
        ;;
    *.7z)
        cmd=("7z" "x" "-y")
        command -v 7z &>/dev/null || {
            echo -e "${gl_hong}错误：7z 命令未安装！${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        }
        ;;
    *.tar) cmd=("tar" "-xf") ;;
    *.tar.gz | *.tgz) cmd=("tar" "-zxf") ;;
    *.rar)
        if command -v unrar &>/dev/null; then
            cmd=("unrar" "x" "-inul")
        elif command -v rar &>/dev/null; then
            cmd=("rar" "x" "-inul")
        else
            echo -e "${gl_hong}错误：unrar 或 rar 命令未安装！${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        fi
        ;;
    *.gz | *.img.gz)
        [[ "$auto_yes" != "true" ]] && {
            local target_file="$output_dir/$(basename "${archive%.gz}")"
            [[ -f "$target_file" ]] && {
                safe_read "$(echo -e "${gl_bai}解压.img.gz文件将覆盖 $target_file，是否继续？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm "any"
                [[ $confirm =~ ^[Yy]$ ]] || {
                    echo -e "${gl_huang}已取消${gl_bai}"
                    exit_animation    # 即将退出动画
                    return 0
                }
            }
        }
        ;;
    # 移除 *.bz2
    # 移除 *.xz
    *)
        echo -e "${gl_hong}不支持的压缩格式：$archive${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
        ;;
    esac

    echo -e "${gl_huang}正在解压：${gl_lv}$archive → $output_dir${gl_bai}"

    # 处理解压过程中的重复文件
    if [[ "$archive" == *.zip && "$auto_yes" != "true" ]]; then
        echo -e "${gl_huang}如果遇到重复文件，请选择操作：${gl_bai}"
        echo -e "${gl_huang}  [y] 覆盖当前文件${gl_bai}"
        echo -e "${gl_huang}  [n] 跳过当前文件${gl_bai}"
        echo -e "${gl_huang}  [A] 覆盖所有重复文件${gl_bai}"
        echo -e "${gl_huang}  [N] 跳过所有重复文件${gl_bai}"
        echo -e "${gl_huang}  [r] 重命名当前文件${gl_bai}"
    fi

    local result=0
    case "$archive" in
    *.zip)
        "${cmd[@]}" "$archive" -d "$output_dir"
        result=$?
        ;;
    *.7z)
        "${cmd[@]}" "$archive" "-o$output_dir"
        result=$?
        ;;
    *.tar | *.tar.gz | *.tgz)
        "${cmd[@]}" "$archive" -C "$output_dir"
        result=$?
        ;;
    *.rar)
        "${cmd[@]}" "$archive" "$output_dir/"
        result=$?
        ;;
    *.gz | *.img.gz)
        # 特殊的.img.gz文件处理
        local target_file="$output_dir/$(basename "${archive%.gz}")"
        local archive_name=$(basename "$archive")
        echo -e "${gl_huang}解压到: ${gl_lv}$target_file${gl_bai}"
        
        # 如果输出目录不是当前目录，复制文件过去
        if [[ "$output_dir" != "." ]] && [[ "$output_dir" != "$PWD" ]]; then
            cp "$archive" "$output_dir/" 2>/dev/null
        fi
        
        # 保存当前目录
        local current_dir="$PWD"
        if [[ "$output_dir" != "." ]] && [[ "$output_dir" != "$PWD" ]]; then
            cd "$output_dir" || {
                echo -e "${gl_hong}无法进入目录: $output_dir${gl_bai}"
                exit_animation    # 即将退出动画
                return 1
            }
        fi
        
        # 先验证文件是否是有效的gzip文件
        if gzip -t "$archive_name" 2>/dev/null; then
            echo -e "${gl_lv}验证: 文件是有效的gzip格式${gl_bai}"
        else
            echo -e "${gl_huang}警告：gzip -t 验证失败，但继续尝试解压${gl_bai}"
        fi
        
        # 方法1: 使用 gzip -kd (保留原文件并解压)
        echo -e "${gl_bai}使用方法: ${gl_lv}gzip -kd${gl_bai}"
        local gzip_output
        gzip_output=$(gzip -kd "$archive_name" 2>&1)
        local gzip_exit=$?
        
        # 检查是否真的解压成功了（即使有警告）
        local extracted_file="${archive_name%.gz}"
        if [[ -f "$extracted_file" ]] && [[ -s "$extracted_file" ]]; then
            # 即使gzip返回非0，只要文件存在且非空，就算成功
            echo -e "${gl_lv}✓ gzip -kd 解压成功${gl_bai}"
            echo -e "${gl_hui}gzip输出: $gzip_output${gl_bai}"
            
            # 验证解压后的文件
            local extracted_size=$(du -h "$extracted_file" 2>/dev/null | cut -f1 || echo "未知")
            local file_type=$(file -b "$extracted_file" 2>/dev/null | head -c 100 || echo "未知")
            echo -e "${gl_lv}解压成功！${gl_bai}"
            echo -e "${gl_lv}文件大小: ${gl_bai}$extracted_size"
            echo -e "${gl_lv}文件类型: ${gl_bai}$file_type"
            
            result=0
        elif [[ "$gzip_exit" -eq 0 ]]; then
            # gzip返回0，但文件不存在或为空
            echo -e "${gl_hong}gzip返回成功但未生成有效文件${gl_bai}"
            result=1
        else
            # gzip -kd 失败，尝试其他方法
            echo -e "${gl_hui}gzip输出: $gzip_output${gl_bai}"
            
            # 方法2: 尝试 gzip -d (不保留原文件)
            echo -e "${gl_bai}尝试备用方法: ${gl_lv}gzip -d${gl_bai}"
            if gzip -d "$archive_name" 2>&1; then
                if [[ -f "$extracted_file" ]] && [[ -s "$extracted_file" ]]; then
                    echo -e "${gl_lv}✓ gzip -d 解压成功${gl_bai}"
                    
                    local extracted_size=$(du -h "$extracted_file" 2>/dev/null | cut -f1 || echo "未知")
                    local file_type=$(file -b "$extracted_file" 2>/dev/null | head -c 100 || echo "未知")
                    echo -e "${gl_lv}解压成功！${gl_bai}"
                    echo -e "${gl_lv}文件大小: ${gl_bai}$extracted_size"
                    echo -e "${gl_lv}文件类型: ${gl_bai}$file_type"
                    
                    result=0
                else
                    echo -e "${gl_hong}gzip -d 未生成有效文件${gl_bai}"
                    result=1
                fi
            else
                # 方法3: 尝试流式解压
                echo -e "${gl_bai}尝试流式解压 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                
                local decompress_success=false
                local methods=("gzip -dc" "gunzip -c" "zcat" "cat | gzip -d")
                
                for method in "${methods[@]}"; do
                    echo -e "${gl_bai}尝试: ${gl_huang}$method${gl_bai}"
                    if eval "$method \"$archive_name\" > \"$extracted_file\"" 2>/dev/null; then
                        if [[ -f "$extracted_file" ]] && [[ -s "$extracted_file" ]]; then
                            decompress_success=true
                            echo -e "${gl_lv}✓ $method 解压成功${gl_bai}"
                            break
                        fi
                    fi
                    [[ -f "$extracted_file" ]] && rm -f "$extracted_file" 2>/dev/null
                done
                
                if [[ "$decompress_success" == true ]]; then
                    result=0
                    local extracted_size=$(du -h "$extracted_file" 2>/dev/null | cut -f1 || echo "未知")
                    local file_type=$(file -b "$extracted_file" 2>/dev/null | head -c 100 || echo "未知")
                    echo -e "${gl_lv}解压成功！${gl_bai}"
                    echo -e "${gl_lv}文件大小: ${gl_bai}$extracted_size"
                    echo -e "${gl_lv}文件类型: ${gl_bai}$file_type"
                else
                    echo -e "${gl_hong}所有解压方法都失败${gl_bai}"
                    echo -e "${gl_huang}可能的原因：${gl_bai}"
                    echo -e "1. 文件已损坏"
                    echo -e "2. 磁盘空间不足"
                    echo -e "3. 文件权限问题"
                    result=1
                fi
            fi
        fi
        
        # 如果我们在其他目录操作，清理复制的文件
        if [[ "$current_dir" != "$PWD" ]]; then
            # 删除复制的.gz文件
            [[ -f "$archive_name" ]] && rm -f "$archive_name"
            # 返回原始目录
            cd "$current_dir" 2>/dev/null
        fi
        ;;
    esac

    if [[ $result -eq 0 ]]; then
        echo -e "${gl_lv}解压完成！${gl_bai}"
    else
        echo -e "${gl_hong}解压失败！${gl_bai}"
    fi
    return $result
}

###### 交互式压缩 - 优化版本
# 横向排列显示优化函数
display_horizontal_list() {
    local list=("${@}")                       # 获取数组参数
    local items_per_line="${display_cols:-3}" # 默认3列，可通过环境变量覆盖
    local min_spacing="${display_spacing:-2}" # 最小间距，默认2个字符
    local max_length=0
    local count=0

    # 计算最长项目名的长度
    for item in "${list[@]}"; do
        local len=${#item}
        ((len > max_length)) && max_length=$len
    done

    # 根据终端宽度动态调整列数和间距
    local term_width=$(tput cols 2>/dev/null || echo 80)
    local col_spacing=$((min_spacing + 2)) # 基础间距

    # 动态计算最佳列数和间距
    if ((term_width > 0)); then
        # 尝试计算适合的列数（最大不超过10列）
        local max_cols=10
        local found_optimal=false

        for ((cols = 10; cols >= 1; cols--)); do
            # 每列的宽度 = 项目最大长度 + 序号宽度(4) + 间距
            local col_width=$((max_length + 4 + col_spacing))
            local total_width=$((col_width * cols))

            if ((total_width <= term_width)); then
                items_per_line=$cols
                found_optimal=true
                break
            fi
        done

        # 如果没找到合适的列数，使用最小列数并调整间距
        if [[ "$found_optimal" == false ]]; then
            items_per_line=1
            col_spacing=2
        fi

        # 进一步优化：如果剩余空间较多，增加间距
        local col_width=$((max_length + 4 + col_spacing))
        local total_width=$((col_width * items_per_line))
        local remaining=$((term_width - total_width))

        if ((remaining > 0 && items_per_line > 1)); then
            # 将剩余空间均匀分配到各列间距
            local extra_space=$((remaining / (items_per_line - 1)))
            col_spacing=$((col_spacing + extra_space))
        fi
    fi

    # 显示横向列表
    for i in "${!list[@]}"; do
        count=$((count + 1))
        local item="${list[i]}"
        local item_display="${item}"

        # 如果是目录，添加斜杠
        [[ -d "$item" ]] && item_display="${item}"

        # 计算该项的显示宽度
        local item_width=$((max_length + col_spacing))

        # 显示项目（序号+项目名）
        if [[ -d "$item" ]]; then
            printf "${gl_bufan}%2d.${gl_bai} ${gl_zi}%-${item_width}s${gl_bai}" "$count" "${item_display}"
        elif [[ -f "$item" ]]; then
            printf "${gl_bufan}%2d.${gl_bai} ${gl_lv}%-${item_width}s${gl_bai}" "$count" "${item_display}"
        else
            printf "${gl_bufan}%2d.${gl_bai} ${gl_bai}%-${item_width}s" "$count" "${item_display}"
        fi

        # 每行显示指定数量的项目后换行
        if ((count % items_per_line == 0)); then
            echo ""
        fi
    done

    # 如果最后一行不满，确保换行
    ((count % items_per_line != 0)) && echo ""

    # 返回实际使用的列数和间距，供外部使用
    DISPLAY_COLS_USED=$items_per_line
    DISPLAY_SPACING_USED=$col_spacing
}

interactive_compress() {
    # 尝试初始化回收站
    if [[ -z "$TRASH_CMD" ]]; then
        install_trash
    fi

    while true; do
        clear
        echo -e "${gl_huang}>>> 当前${gl_bai}(${gl_lv}文件${gl_hong}/${gl_zi}目录${gl_bai})${gl_huang}列表：${gl_lv}$(pwd)${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"


        local list=() item i choice target fmt_idx format
        # 移除了 bz2 和 xz
        local compress_extensions=("zip" "7z" "tar" "tar.gz" "tgz" "rar" "gz")

        # 使用更高效的方法获取文件和目录列表
        for item in *; do
            # 排除隐藏文件
            [[ "$item" == .* ]] && continue

            # 检查是否存在
            [[ ! -e "$item" ]] && continue

            # 检查是否是压缩文件（排除已经压缩的文件）
            local is_compressed=0
            for ext in "${compress_extensions[@]}"; do
                if [[ "$item" == *".$ext" ]]; then
                    is_compressed=1
                    break
                fi
            done

            # 如果不是压缩文件则添加到列表
            ((is_compressed == 0)) && list+=("$item")
        done

        # 添加子目录
        for item in */; do
            if [[ -d "$item" && "$item" != .*/ && "$item" != "./" ]]; then
                item="${item%/}"
                # 检查是否已在列表中
                local exists=0
                for existing in "${list[@]}"; do
                    [[ "$existing" == "$item" ]] && exists=1 && break
                done
                ((exists == 0)) && list+=("$item")
            fi
        done

        # 按字母顺序排序
        if ((${#list[@]} > 0)); then
            IFS=$'\n' list=($(sort <<<"${list[*]}"))
            unset IFS
        fi

        if ((${#list[@]} == 0)); then
            echo -e "${gl_huang}当前目录无可压缩的文件/目录${gl_bai}"
            exit_animation    # 即将退出动画
            return
        fi
        
        # 使用优化后的显示函数
        display_horizontal_list "${list[@]}"

        echo -e ""
        echo -e "${gl_zi}>>> 压缩模式${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入序号选择，或手动输入${gl_bai}(${gl_lv}文件${gl_hong}/${gl_zi}目录${gl_bai}) (${gl_huang}0 ${gl_bai}返回): ")" choice

        # 只在用户输入0或留空时才返回主菜单
        if [[ -z "$choice" || "$choice" == "0" ]]; then
            return
        fi

        if [[ "$choice" =~ ^[0-9]+$ ]] && ((choice >= 1 && choice <= ${#list[@]})); then
            target="${list[$((choice - 1))]}"
        else
            target="$choice"
        fi

        [[ -e "$target" ]] || {
            echo -e "${gl_hong}错误：'$target' 不存在！${gl_bai}"
            echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            read -r -n1 -s
            continue
        }

        # 显示压缩格式选项
        echo -e ""
        echo -e "${gl_huang}请选择压缩格式：${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}1.${gl_bai} zip (通用)      ${gl_huang}2.${gl_bai} 7z (高压缩率)"
        echo -e "${gl_huang}3.${gl_bai} tar.gz (平衡)  ${gl_huang}4.${gl_bai} tar (仅打包)"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        safe_read "请输入你的选择: " fmt_idx "number"

        case "$fmt_idx" in
        1) format="zip" ;;
        2) format="7z" ;;
        3) format="tar.gz" ;;
        4) format="tar" ;;
        *)
            echo -e "${gl_hong}无效序号！${gl_bai}"
            echo -e "${gl_bai}按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            read -r -n1 -s
            continue
            ;;
        esac

        # 询问输出目录
        local output_dir
        read -r -e -p "$(echo -e "${gl_bai}输出目录 (${gl_huang}留空为当前目录${gl_bai}): ")" output_dir
        output_dir="${output_dir:-.}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e ""

        # 调用压缩函数
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        compress_file "$target" "$format" "$output_dir"

        # 压缩完成后直接按任意键继续
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    done
}

###### 交互式解压 - 优化版本
interactive_extract() {
    clear
    echo -e "${gl_zi}>>> 解压模式${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    local list=() file i choice archive dest
    # 移除了 bz2 和 xz
    local extensions=("zip" "7z" "tar" "tar.gz" "tgz" "rar" "gz")
    
    # 清空数组
    list=()
    
    # 获取压缩包文件 - 使用更安全的方法
    for ext in "${extensions[@]}"; do
        # 使用null分隔符处理文件名中的空格
        while IFS= read -r -d '' file; do
            [[ -n "$file" && -f "$file" ]] && {
                # 去重检查
                local exists=false
                for item in "${list[@]}"; do
                    [[ "$item" == "$file" ]] && { exists=true; break; }
                done
                [[ "$exists" == false ]] && list+=("$file")
            }
        done < <(find . -maxdepth 1 -type f -name "*.$ext" -print0 2>/dev/null)
    done

    # 如果没有压缩包文件，显示提示
    if ((${#list[@]} == 0)); then
        log_warn "当前目录无压缩包文件"

        # 检查是否有可能是压缩文件但没有扩展名的文件
        log_warn "正在检查无扩展名的压缩文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        local file_count=0
        
        # 使用find命令安全地遍历文件
        while IFS= read -r -d '' file; do
            [[ -f "$file" ]] && {
                if file "$file" 2>/dev/null | grep -qi "compressed\|archive\|zip\|gzip\|tar"; then
                    echo -e "${gl_huang}发现可能的压缩文件: $file${gl_bai}"
                    # 去重检查
                    local exists=false
                    for item in "${list[@]}"; do
                        [[ "$item" == "$file" ]] && { exists=true; break; }
                    done
                    [[ "$exists" == false ]] && {
                        list+=("$file")
                        ((file_count++))
                    }
                fi
            }
        done < <(find . -maxdepth 1 -type f ! -name "*.*" -print0 2>/dev/null)

        if ((file_count == 0)); then
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}按任意键返回 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
            read -r -n1 -s
            return
        fi
    fi

    # 对列表进行排序
    if ((${#list[@]} > 0)); then
        IFS=$'\n' list=($(sort <<<"${list[*]}"))
        unset IFS
    fi

    echo -e "当前工作目录 ${gl_huang}$(pwd) ${gl_lv}可用的压缩包：${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # 横向排列显示
    local count=0
    local items_per_line=2
    local max_length=0

    # 计算最长文件名的长度
    for file in "${list[@]}"; do
        local len=${#file}
        ((len > max_length)) && max_length=$len
    done

    # 动态调整每行显示数量
    local term_width=$(tput cols 2>/dev/null || echo 80)
    if ((term_width > 120)); then
        items_per_line=4
    elif ((term_width > 80)); then
        items_per_line=3
    fi

    max_length=$((max_length + 4))

    for i in "${!list[@]}"; do
        count=$((count + 1))

        # 根据压缩格式显示不同颜色
        local file_ext="${list[i]##*.}"
        case "$file_ext" in
        zip | 7z)
            printf "${gl_huang}%2d.${gl_bai} ${gl_lv}%-${max_length}s${gl_bai}" "$count" "${list[i]}"
            ;;
        tar* | tgz)
            printf "${gl_huang}%2d.${gl_bai} ${gl_zi}%-${max_length}s${gl_bai}" "$count" "${list[i]}"
            ;;
        gz)
            printf "${gl_huang}%2d.${gl_bai} ${gl_lan}%-${max_length}s${gl_bai}" "$count" "${list[i]}"
            ;;
        *)
            printf "${gl_huang}%2d.${gl_bai} ${gl_bai}%-${max_length}s" "$count" "${list[i]}"
            ;;
        esac

        # 每行显示指定数量的项目后换行
        if ((count % items_per_line == 0)); then
            echo ""
        fi
    done

    # 如果最后一行不满，确保换行
    ((count % items_per_line != 0)) && echo ""

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    read -r -e -p "$(echo -e "${gl_bai}请输入序号选择，或手动输入文件名(${gl_huang}0 ${gl_bai}返回): ")" choice

    [[ -z "$choice" ]] && {
        echo -e "${gl_huang}已取消${gl_bai}"
        return
    }

    if [[ "$choice" =~ ^[0-9]+$ ]] && ((choice >= 1 && choice <= ${#list[@]})); then
        archive="${list[$((choice - 1))]}"
    else
        archive="$choice"
    fi

    [[ -f "$archive" ]] || {
        echo -e "${gl_hong}错误：'$archive' 不存在！${gl_bai}"
        return
    }

    # 询问解压目录
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}解压到目录 (${gl_huang}留空为当前目录${gl_bai}): ")" dest
    dest="${dest:-.}"

    # 如果目录不存在则创建
    if [[ ! -d "$dest" ]]; then
        echo -e "${gl_huang}目录 '$dest' 不存在，是否创建？(${gl_lv}y${gl_huang}/${gl_bai}N${gl_huang})${gl_bai}"
        read -r -n1 -s create_dir
        if [[ $create_dir =~ ^[Yy]$ ]]; then
            mkdir -p "$dest" && echo -e "${gl_lv}目录已创建${gl_bai}" || {
                echo -e "${gl_hong}创建目录失败！${gl_bai}"
                return
            }
        else
            dest="."
        fi
    fi

    # 调用解压函数
    extract_file "$archive" "$dest" "false"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 快速解压当前目录下的压缩文件
quick_extract() {
    echo -e "${gl_zi}>>> 快速解压模式${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_bai}当前工作目录: ${gl_huang}$(pwd)${gl_bai}"

    # 显示当前目录下的所有压缩文件
    local list=() file i choice archive dest

    # 获取压缩包文件（移除了 bz2 和 xz）
    local extensions=("zip" "7z" "tar" "tar.gz" "tgz" "rar" "gz")
    for ext in "${extensions[@]}"; do
        for file in *."$ext"; do
            if [[ -f "$file" ]]; then
                list+=("$file")
            fi
        done
    done

    if ((${#list[@]} == 0)); then
        echo -e "${gl_huang}当前目录无压缩包文件${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    fi

    # 如果有多个压缩文件，让用户选择
    if ((${#list[@]} > 1)); then
        echo -e "${gl_bufan}发现多个压缩文件：${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 横向排列显示
        local count=0
        local items_per_line=4
        local max_length=0

        for file in "${list[@]}"; do
            local len=${#file}
            if [ "$len" -gt "$max_length" ]; then
                max_length=$len
            fi
        done

        max_length=$((max_length + 4))

        for i in "${!list[@]}"; do
            count=$((count + 1))
            printf "${gl_huang}%2d.${gl_bai} %-${max_length}s" "$count" "${list[i]}"
            if [ $((count % items_per_line)) -eq 0 ]; then
                echo ""
            fi
        done

        if [ $((count % items_per_line)) -ne 0 ]; then
            echo ""
        fi
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        read -r -e -p "请选择要解压的文件序号（留空取消）: " choice
        [[ -z "$choice" ]] && {
            echo -e "${gl_huang}已取消${gl_bai}"
            return
        }

        if [[ "$choice" =~ ^[0-9]+$ ]] && ((choice >= 1 && choice <= ${#list[@]})); then
            archive="${list[$((choice - 1))]}"
        else
            echo -e "${gl_hong}无效序号！${gl_bai}"
            return
        fi
    else
        # 如果只有一个压缩文件，直接使用
        archive="${list[0]}"
        echo -e "${gl_lv}发现压缩文件: $archive${gl_bai}"
        echo -e "${gl_huang}将自动解压此文件${gl_bai}"
    fi

    [[ -f "$archive" ]] || {
        echo -e "${gl_hong}错误：'$archive' 不存在！${gl_bai}"
        return
    }

    # 询问解压目录
    read -r -e -p "请输入解压目标目录（留空则当前目录）: " dest
    dest=${dest:-.}

    # 调用解压函数
    extract_file "$archive" "$dest" "false"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# 解压指定文件
extract_specific() {
    local archive="$1"
    local dest="${2:-.}"

    if [[ -z "$archive" ]]; then
        echo -e "${gl_hong}错误：请指定要解压的文件${gl_bai}"
        return 1
    fi

    [[ -f "$archive" ]] || {
        echo -e "${gl_hong}错误：'$archive' 不存在！${gl_bai}"
        return 1
    }

    echo -e "${gl_lv}正在解压: $archive → $dest${gl_bai}"
    extract_file "$archive" "$dest" "false"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

###### 函数_解压压缩工具
compress_tool() {

    # 变量定义
    local install_only=false compress_file="" extract_file="" compress_format=""
    local output_dir="" auto_yes=false system_type=""

    # 设置 Tab 补全
    setup_completion() {
        local current_word="${COMP_WORDS[COMP_CWORD]}"
        local previous_word="${COMP_WORDS[COMP_CWORD - 1]}"

        case "${previous_word}" in
        --compress | --extract)
            # 文件和目录补全
            COMPREPLY=($(compgen -f -- "${current_word}"))
            ;;
        --format)
            # 压缩格式补全
            local formats=("zip" "7z" "tar.gz" "tar")
            COMPREPLY=($(compgen -W "${formats[*]}" -- "${current_word}"))
            ;;
        --output)
            # 目录补全
            COMPREPLY=($(compgen -d -- "${current_word}"))
            ;;
        *)
            # 选项补全
            local options=("--install-only" "--compress" "--extract" "--format" "--output" "--auto-yes" "-h" "--help")
            COMPREPLY=($(compgen -W "${options[*]}" -- "${current_word}"))
            ;;
        esac
    }

    # 注册补全函数（仅在直接调用时）
    if [[ "${BASH_SOURCE[0]}" == "${0}" ]]; then
        complete -F setup_completion compress_tool
    fi

    # 检测系统类型
    _detect_system() {
        if [[ -f /etc/os-release ]]; then
            source /etc/os-release
            echo "$ID"
        elif command -v lsb_release &>/dev/null; then
            lsb_release -si | tr '[:upper:]' '[:lower:]'
        else
            echo "unknown"
        fi
    }

    # 批量压缩当前目录下的所有子文件夹
    batch_compress_dirs() {
        clear
        echo -e "${gl_zi}>>> 批量压缩子目录${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}当前工作目录: ${gl_huang}$(pwd)${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        local dirs=()
        local dir

        # 获取所有子目录
        for dir in */; do
            [[ -d "$dir" ]] && dirs+=("${dir%/}")
        done

        if ((${#dirs[@]} == 0)); then
            echo -e "${gl_hong}当前目录下没有子文件夹！${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bai}按任意键返回 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
            read -r -n1 -s
            return
        fi

        echo -e "${gl_lv}发现以下子目录：${gl_bai}"
        local count=0
        for dir in "${dirs[@]}"; do
            ((count++))
            echo -e "${gl_huang}$count.${gl_bai} $dir"
        done
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 选择压缩格式
        echo -e "${gl_bai}请选择压缩格式：${gl_bai}"
        echo -e "${gl_huang}1.${gl_bai} zip        ${gl_huang}2.${gl_bai} tar.gz"
        echo -e "${gl_huang}3.${gl_bai} 7z         ${gl_huang}4.${gl_bai} tar"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        local format_choice compress_format compress_ext
        read -r -e -p "$(echo -e "${gl_bai}请输入格式序号(${gl_huang}默认1${gl_bai}): ")" format_choice
        format_choice="${format_choice:-1}"

        case "$format_choice" in
            1) compress_format="zip"; compress_ext="zip" ;;
            2) compress_format="tar.gz"; compress_ext="tar.gz" ;;
            3) compress_format="7z"; compress_ext="7z" ;;
            4) compress_format="tar"; compress_ext="tar" ;;
            *) compress_format="zip"; compress_ext="zip" ;;
        esac

        echo -e "${gl_lv}已选择格式: $compress_format${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 确认压缩
        read -r -e -p "$(echo -e "${gl_huang}确认压缩以上 ${gl_lv}$count${gl_huang} 个目录为 ${gl_lv}.$compress_ext${gl_huang} 格式? (${gl_lv}y${gl_huang}/${gl_bai}N${gl_huang})${gl_bai}: ")" confirm
        [[ ! "$confirm" =~ ^[Yy]$ ]] && {
            echo -e "${gl_huang}已取消${gl_bai}"
            return
        }

        # 执行批量压缩
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        local success=0 failed=0
        for dir in "${dirs[@]}"; do
            local output_name="${dir}.${compress_ext}"
            echo -e "${gl_bai}正在压缩: ${gl_huang}$dir${gl_bai} → ${gl_lv}$output_name${gl_bai}"
            
            case "$compress_format" in
                "zip")
                    zip -r "$output_name" "$dir" >/dev/null 2>&1 && ((success++)) || ((failed++))
                    ;;
                "tar")
                    tar -cvf "$output_name" "$dir" >/dev/null 2>&1 && ((success++)) || ((failed++))
                    ;;
                "tar.gz")
                    tar -czvf "$output_name" "$dir" >/dev/null 2>&1 && ((success++)) || ((failed++))
                    ;;
                "7z")
                    7z a "$output_name" "$dir" >/dev/null 2>&1 && ((success++)) || ((failed++))
                    ;;
            esac
        done

        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lv}压缩完成！成功: $success, 失败: $failed${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
    }

    # 交互式菜单
    interactive_menu() {
        while true; do
            # 检查当前目录是否为空，如果为空则显示提示并返回错误
            check_directory_empty "." "Linux压缩/解压工具" "true" || return

            clear
            echo -e ""
            echo -e "${gl_zi}安装依赖中 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            install zip 7zip gzip
            clear
            list_dir_colorful 0 4 # 当前目录列表
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e ""
            echo -e "${gl_zi}>>> Linux压缩/解压工具${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_bufan}1.  ${gl_bai}压缩文件/目录         ${gl_bufan}2.  ${gl_bai}解压文件"
            echo -e "${gl_bufan}3.  ${gl_bai}进入指定目录          ${gl_bufan}4.  ${gl_bai}返回上一级目录"
            echo -e "${gl_bufan}5.  ${gl_bai}文件管理工具          ${gl_bufan}6.  ${gl_bai}文件下载工具"
            echo -e "${gl_bufan}7.  ${gl_bai}安全删除工具          ${gl_bufan}8.  ${gl_bai}文件回收站"
            echo -e "${gl_bufan}9.  ${gl_bai}批量压缩子目录        ${gl_bufan}10. ${gl_bai}批量解压模式"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单        ${gl_hong}00. ${gl_bai}退出脚本"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            read -r -e -p "请输入你的选择: " choice
            case $choice in

            1)  interactive_compress ;;                             # 压缩文件/目录
            2)  interactive_extract ;;                              # 解压文件
            1)  enter_directory "Linux压缩/解压工具" ;;              # 进入指定目录
            4)  cd .. ;;                                            # 返回上一级目录
            5)  linux_file "." "文件管理工具" "Linux压缩/解压工具";;  # 文件管理工具
            6)  download_file ;;                                    # 文件下载工具
            7)  interactive_delete ;;                               # 安全删除工具
            8)  manage_trash_menu ;;                                # 文件回收站
            9)  batch_compress_dirs ;;                              # 批量压缩子目录（新增）
            10) batch_extract_all ;;                                # 批量解压模式
            0) cancel_return; return 0 ;;                           # 返回到上一级菜单
            00 | 000 | 0000) exit_script ;;                         # 感谢使用，再见！
            *) handle_invalid_input ;;                              # 无效的输入,请重新输入!
            esac
        done
    }

    # 参数解析
    while [[ $# -gt 0 ]]; do
        case $1 in
        --install-only)
            install_only=true
            shift
            ;;
        --compress)
            compress_file="$2"
            shift 2
            ;;
        --extract)
            extract_file="$2"
            shift 2
            ;;
        --format)
            compress_format="$2"
            shift 2
            ;;
        --output)
            output_dir="$2"
            shift 2
            ;;
        --auto-yes)
            auto_yes=true
            shift
            ;;
        *)
            echo -e "${gl_hong}未知参数: $1${gl_bai}"
            return 1
            ;;
        esac
    done

    # 交互模式：显示菜单
    interactive_menu
}

######## 函数_打包Docker镜像
docker_image_pack() {
    set -euo pipefail # 严格错误处理
    clear
    # 1. 列出镜像
    echo -e "${gl_huang}本地镜像列表：${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    docker images --format "table {{.Repository}}:{{.Tag}}\t{{.ID}}\t{{.Size}}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    # ---------- 2. 获取镜像 ----------
    while true; do
        echo -e ""
        echo -e "${gl_zi}>>> 打包指定镜像${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -erp "$(echo -e "${gl_bai}请输入打包的镜像名称和版本（格式 ${gl_lv}nginx:tag${gl_bai})(${gl_huang}0${gl_bai}返回）：") " IMG

        [ "$IMG" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
        [ -z "$IMG" ] && { cancel_empty "上一级选单"; return 1; }         # break 或 continue 或 return ，视上下文而定

        docker image inspect "$IMG" &>/dev/null && break || echo -e "${gl_hong}镜像 '$IMG' 不存在！${gl_bai}"
    done

    # ---------- 3. 获取打包格式 ----------
    while true; do
        read -r -erp "$(echo -e "${gl_bai}选择打包格式 ${gl_huang}1${gl_bai} .tar  ${gl_huang}2${gl_bai} .tar.gz（输入 ${gl_huang}1${gl_bai} 或 ${gl_huang}2${gl_bai}，${gl_huang}0${gl_bai}返回）：") " FMT
        [ "$FMT" = "0" ] && {
            set +euo pipefail
            return 0
        }
        case "$FMT" in 1)
            EXT="tar"
            break
            ;;
        2)
            EXT="tar.gz"
            break
            ;;
        *) echo -e "${gl_hong}输入错误！${gl_bai}" ;; esac
    done

    # ---------- 4. 获取文件名 ----------
    while true; do
        read -r -erp "$(echo -e "${gl_bai}请输入打包文件名（${gl_huang}不含扩展名${gl_bai}，${gl_huang}0${gl_bai}返回）：") " FNAME
        [ "$FNAME" = "0" ] && {
            set +euo pipefail
            return 0
        }
        [ -z "$FNAME" ] && {
            echo -e "${gl_hong}文件名不能为空！${gl_bai}"
            return
        }
        [[ "$FNAME" =~ [^a-zA-Z0-9._-] ]] && {
            echo -e "${gl_hong}文件名含非法字符！${gl_bai}"
            return
        }
        [ -f "${FNAME}.${EXT}" ] && {
            read -r -erp "$(echo -e "${gl_huang}文件已存在，是否覆盖？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" OVER
            [[ "$OVER" =~ [yY] ]] && break || continue
        } || break
    done

    OUT="${FNAME}.${EXT}"

    # 5. 打包
    echo -e "${gl_bai}正在打包 ${gl_lv}→${gl_bai} ${gl_huang}${OUT}${gl_bai}"
    if [[ "$EXT" == "tar.gz" ]]; then
        docker save "$IMG" | gzip -c >"$OUT"
    else
        docker save -o "$OUT" "$IMG"
    fi

    FILE_PATH=$(realpath "$OUT")
    FILE_SIZE=$(du -h "$OUT" | cut -f1)

    # 6. 静默校验
    echo -e "${gl_bai}正在静默校验 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    if [[ "$EXT" == "tar.gz" ]]; then
        if gzip -t "$OUT" && gunzip -kc "$OUT" | docker load | grep -q "Loaded image:"; then
            LOADED=$(gunzip -kc "$OUT" | docker load | awk '/Loaded image:/ {print $3}')
            echo -e "${gl_lv}校验通过：${OUT} 完整无损${gl_bai}"
            echo -e "${gl_lv}检验后镜像名称与版本：${LOADED}${gl_bai}"
        else
            echo -e "${gl_hong}校验失败：${OUT} 文件损坏${gl_bai}"
            set +euo pipefail
            return 1
        fi
    else
        if docker load -i "$OUT" | grep -q "Loaded image:"; then
            LOADED=$(docker load -i "$OUT" | awk '/Loaded image:/ {print $3}')
            echo -e "${gl_lv}校验通过：${OUT} 完整无损${gl_bai}"
            echo -e "${gl_lv}检验后镜像名称与版本：${LOADED}${gl_bai}"
        else
            echo -e "${gl_hong}校验失败：${OUT} 文件损坏${gl_bai}"
            set +euo pipefail
            return 1
        fi
    fi

    # 7. 完成提示
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_lv}打包完成！${gl_bai}"
    echo -e "  ${gl_bai}文件存放位置：${gl_lv}${FILE_PATH}${gl_bai}"
    echo -e "  ${gl_bai}文件大小：${gl_lv}${FILE_SIZE}${gl_bai}"
    echo -e "  ${gl_bai}如需加载镜像，请执行：${gl_bai}"
    echo -e "  ${gl_lv}docker load -i ${OUT}${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

    set +euo pipefail
    break_end
}

###### 文件下载（中文文件名+原生断点续传+耗时统计）
download_single() {
    local url="$1"
    [[ -z "$url" ]] && return 1 # 保险

    # ---------- 1. 文件名处理 ----------
    local raw_name=$(echo "$url" | sed 's/^.*\///' | sed 's/?.*$//')
    local filename=$(printf '%b' "${raw_name//%/\\x}" 2>/dev/null || echo "$raw_name")
    [[ -z "$filename" || "$filename" == "/" ]] && filename="downloaded_file"
    filename=$(echo "$filename" | tr -d '\000-\037' | tr '/' '_' | tr ':' '_' | tr '()[]{}<>' '_' | tr '*?&' '_')

    echo -e ""
    echo -e ""
    echo -e "${gl_huang}>>> 下载文件默认名称为: ${gl_lv}$filename${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    read -r -e -p "$(echo -e "${gl_bai}是否修改文件名？(${gl_huang}回车${gl_bai}使用默认名称): ")" new_filename
    [[ -n "$new_filename" ]] && filename="$new_filename"

    # ---------- 2. 探测文件大小 ----------
    echo -e "${gl_bai}检测文件信息 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    local expected_size=0
    if command -v curl &>/dev/null; then
        expected_size=$(curl -s -L -I "$url" 2>/dev/null | grep -i 'content-length' | awk '{print $2}' | tr -d '\r' | tail -1)
    elif command -v wget &>/dev/null; then
        expected_size=$(wget --spider -S "$url" 2>&1 | grep -i 'content-length' | awk '{print $2}' | tail -1)
    fi
    [[ -n "$expected_size" && "$expected_size" -gt 0 ]] &&
        echo -e "${gl_bai}检测到文件大小: ${gl_lv}$(numfmt --to=iec "$expected_size")${gl_bai}" ||
        echo -e "${gl_huang}无法获取文件大小，将进行完整下载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    # ---------- 3. 选择下载工具 ----------
    local download_tool=""
    if command -v wget &>/dev/null; then
        download_tool="wget"
        echo -e ""
        echo -e "${gl_huang}使用 wget 下载${gl_bai}"
    elif command -v curl &>/dev/null; then
        download_tool="curl"
        echo -e ""
        echo -e "${gl_huang}使用 curl 下载${gl_bai}"
    else
        echo -e ""
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_hong}错误：未找到可用的下载工具 (wget/curl)${gl_bai}"
        read -n 1 -p "$(echo -e "按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} ")"
        return 1
    fi

    # ---------- 4. 断点续传 + 耗时 ----------
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    local existing_size=0
    if [[ -f "$filename" ]]; then
        existing_size=$(stat -c%s "$filename" 2>/dev/null || echo 0)
        if [[ "$expected_size" -gt 0 && "$existing_size" -eq "$expected_size" ]]; then
            echo -e "${gl_lv}✓ 文件已存在且完整，无需下载。${gl_bai}"
            echo -e "${gl_lv}文件路径: ${gl_bai}$(realpath "$filename" 2>/dev/null || echo "$filename")"
            return 0
        elif [[ "$existing_size" -gt 0 ]]; then
            echo -e "${gl_huang}检测到已下载: ${gl_lv}$(numfmt --to=iec "$existing_size")${gl_huang}，将尝试断点续传 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        fi
    fi

    # 耗时格式化
    fmt_time() {
        local sec=$1
        local h=$((sec / 3600))
        local m=$(((sec % 3600) / 60))
        local s=$((sec % 60))
        printf "%02d:%02d:%02d" "$h" "$m" "$s"
    }
    local start_ts=$(date +%s)
    echo -e "${gl_lv}开始下载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"

    local exit_code=0
    case $download_tool in
    wget)
        wget -c -T 30 --progress=bar:force:noscroll -O "$filename" "$url"
        exit_code=$?
        ;;
    curl)
        curl -L -C - --progress-bar -o "$filename" "$url"
        exit_code=$?
        ;;
    esac

    local end_ts=$(date +%s)
    local elapsed=$((end_ts - start_ts))
    echo -e "${gl_lv}下载耗时：${gl_bai}$(fmt_time "$elapsed")"

    # ---------- 5. 结果检查 ----------
    [[ $exit_code -ne 0 ]] && echo -e "${gl_hong}下载失败！错误代码: $exit_code${gl_bai}" && return 1
    local actual_size=$(stat -c%s "$filename" 2>/dev/null || echo 0)
    if [[ "$expected_size" -gt 0 && "$actual_size" -ne "$expected_size" ]]; then
        echo -e "${gl_hong}文件大小不匹配，下载不完整！${gl_bai}"
        echo -e "${gl_hong}实际: ${gl_lv}$(numfmt --to=iec "$actual_size")${gl_hong}，期望: ${gl_lv}$(numfmt --to=iec "$expected_size")${gl_bai}"
        read -n 1 -p "$(echo -e "${gl_hong}按任意键退出 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
        return 1
    fi
    echo -e "${gl_lv}✓ 下载成功！文件大小完整。${gl_bai}"

    # ---------- 6. 打印文件信息 ----------
    echo -e ""
    echo -e "${gl_huang}>>> 下载文件信息：${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    if [[ -f "$filename" ]]; then
        local file_path=$(realpath "$filename" 2>/dev/null || echo "$filename")
        local file_size_human
        file_size_human=$(stat -c %s "$filename" 2>/dev/null | numfmt --to=iec 2>/dev/null || echo "未知")
        local file_bytes=$(stat -c%s "$filename" 2>/dev/null || echo 0)
        local file_type=$(file -b "$filename" 2>/dev/null || echo "未知")
        local mod_time=$(stat -c "%y" "$filename" 2>/dev/null | cut -d'.' -f1 || echo "未知")
        local md5sum=$(md5sum "$filename" 2>/dev/null | cut -d' ' -f1 || echo "计算失败")

        echo -e "${gl_bai}文件路径: ${gl_lv}$file_path${gl_bai}"
        echo -e "${gl_bai}文件大小: ${gl_lv}$file_size_human (${file_bytes} 字节)${gl_bai}"
        [[ "$expected_size" -gt 0 ]] && echo -e "${gl_bai}完整性: ${gl_lv}✓ 完整${gl_bai}"
        echo -e "${gl_bai}文件类型: ${gl_lv}$file_type${gl_bai}"
        echo -e "${gl_bai}修改时间: ${gl_lv}$mod_time${gl_bai}"
        echo -e "${gl_bai}MD5 校验: ${gl_lv}$md5sum${gl_bai}"
    else
        echo -e "${gl_hong}错误：无法找到下载的文件${gl_bai}"
    fi
    return 0
}

#============================================================
# 主入口：循环交互，真正“返回继续下载”
#============================================================
download_file() {
    # 如果命令行带参数，直接下载一次就返回
    if [[ -n "$1" ]]; then
        download_single "$1"
        return
    fi

    # 交互模式
    while true; do
        clear
        if [ -z "$(ls -A)" ]; then
            echo -e "${gl_huang}>>> 当前目录文件列表：${gl_bai}(${gl_lv}$(pwd)${gl_bai})"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            echo -e "${gl_huang}当前目录为空${gl_bai}"
        else
            list_dir_colorful 0 4
        fi
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e ""
        echo -e "${gl_zi}>>> 文件下载${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入下载链接（${gl_huang}0${gl_bai}返回）：")" url
        [ "$url" = "0" ] && { cancel_return; return 1; }
        [[ -z "$url" ]] && echo -e "${gl_hong}错误：链接不能为空！${gl_bai}" && read -n 1 -p "$(echo -e "按任意键继续 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} ")" && continue
        url=$(echo "$url" | sed 's|https://https://|https://|g')

        # 新增：检查链接是否以http或https开头
        if [[ ! "$url" =~ ^https?:// ]]; then
            echo -e "${gl_hong}错误：链接必须以http://或https://开头！${gl_bai}"
            exit_animation    # 即将退出动画
            continue
        fi

        # 真正干活
        download_single "$url"

        # 无论成功失败，都会停在这里等用户按键，然后循环回到“请输入下载链接”
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lv}✓ 下载成功！${gl_bai}"
        read -r -n 1 -p "$(echo -e "${gl_bai}按任意键继续下载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}")"
    done
}

