istoreos_network_info() {
    # 获取网络信息
    local gateway=$(uci get network.lan.gateway 2>/dev/null)
    local ipaddr=$(uci get network.lan.ipaddr 2>/dev/null)
    local dns=$(uci get network.lan.dns 2>/dev/null)
    
    # 获取系统信息
    local hostname=$(uname -n)
    local kernel_release=$(uname -r)
    local machine=$(uname -m)

    # 初始化 OpenClash 环境
    command -v OpenClash_init_env &>/dev/null && ! OpenClash_init_env && return 1
    
    # 定义颜色变量
    local GREEN="${gl_lv}"
    local WHITE="${gl_bai}"
    
    # 计算固定列宽
    local first_col_width=20
    local second_col_width=25
    
    # 第一行
    printf "主机名称：${GREEN}%s${WHITE}" "$hostname"
    local hostname_len=${#hostname}
    local padding1=$((first_col_width - hostname_len - 6))  # 6是"主机名称：  "的长度
    printf "%*s" $padding1 ""
    printf "内核版本：${GREEN}%s${WHITE}\n" "$kernel_release"
    
    # 第二行
    printf "硬件架构：${GREEN}%s${WHITE}" "$machine"
    local machine_len=${#machine}
    local padding2=$((first_col_width - machine_len - 6))  # 6是"硬件架构：  "的长度
    printf "%*s" $padding2 ""
    printf "默认 DNS：${GREEN}%s${WHITE}\n" "${dns:-未配置}"
    
    # 第三行
    printf "包管理器：${GREEN}%s${WHITE}" "$OPENCLASH_PKG_MANAGER"
    local pkg_mgr_len=${#OPENCLASH_PKG_MANAGER}
    local padding3=$((first_col_width - pkg_mgr_len - 6))  # 6是"包管理器：  "的长度
    printf "%*s" $padding3 ""
    printf "IPV4网址：${GREEN}%s${WHITE}\n" "${ipaddr:-未配置}"
    
    # 第四行
    printf "防 火 墙：${GREEN}%s${WHITE}" "$OPENCLASH_FIREWALL_TYPE"
    local firewall_len=${#OPENCLASH_FIREWALL_TYPE}
    local padding4=$((first_col_width - firewall_len - 6))  # 6是" 防 火 墙：  "的长度
    printf "%*s" $padding4 ""
    printf "默认网关：${GREEN}%s${WHITE}\n" "${gateway:-未配置}"
}

print_disk_info() {
    is_istoreos_system || return 1  # 非iStoreOS系统退出
    echo ""
    echo -e "${gl_zi}>>> iStoreOS磁盘信息${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    local disk_dev="/dev/sda"
    
    # 获取磁盘总容量
    local total_size=$(fdisk -l 2>/dev/null | grep -E "^Disk ${disk_dev}:" | awk '{print $3, $4}' | tr -d ',')
    
    # 获取磁盘型号
    local disk_model=$(fdisk -l 2>/dev/null | grep "Disk model:" | sed 's/Disk model: //')
    
    # 获取扇区大小
    local sector_size=$(fdisk -l 2>/dev/null | grep "Sector size" | awk '{print $4}')
    
    # 获取分区表类型
    local disklabel=$(fdisk -l 2>/dev/null | grep "Disklabel type:" | awk '{print $3}')
    
    echo "磁盘设备：${disk_dev}"
    echo "总容量：${total_size:-未知}"
    echo "磁盘型号：${disk_model:-未知}"
    echo "扇区大小：${sector_size:-512} bytes"
    echo "分区表类型：${disklabel:-未知}"
    echo ""
    echo "分区信息："
    
    # 打印表头
    printf "%-12s %-10s %-10s %-10s %-8s %s\n" "设备" "起始" "结束" "扇区数" "大小" "类型"
    
    # 获取分区信息并格式化输出
    fdisk -l 2>/dev/null | grep "^/dev/sda" | while read line; do
        local dev=$(echo "$line" | awk '{print $1}')
        local start=$(echo "$line" | awk '{print $2}')
        local end=$(echo "$line" | awk '{print $3}')
        local sectors=$(echo "$line" | awk '{print $4}')
        local size=$(echo "$line" | awk '{print $5}')
        local type=$(echo "$line" | awk '{print $6, $7, $8}' | sed 's/ *$//')
        
        printf "%-12s %-10s %-10s %-10s %-8s %s\n" "$dev" "$start" "$end" "$sectors" "$size" "$type"
    done
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# iStoreOS 系统清理（快速/深度）
# istoreos_clean        # 快速清理（默认）
# istoreos_clean fast   # 快速清理（显式）
# istoreos_clean deep   # 深度清理
istoreos_clean() {
    is_istoreos_system || return 1  # 非iStoreOS系统退出
    local mode="${1:-fast}"  # 默认快速模式，传入 deep 启用深度模式
    
    # 显示模式标题
    if [ "$mode" = "deep" ]; then
        echo ""
        echo -e "${gl_zi}>>> 深度清理中 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    else
        echo ""
        echo -e "${gl_zi}>>> 快速清理系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # ========== 基础清理（快速+深度共用）==========
    
    # 软件包缓存
    rm -rf /tmp/opkg-* /var/opkg-lists/* 2>/dev/null
    
    # 日志
    > /var/log/messages 2>/dev/null
    > /var/log/daemon.log 2>/dev/null
    
    # 临时文件
    rm -rf /tmp/luci-* /tmp/sessions/* 2>/dev/null
    
    # DNS
    /etc/init.d/dnsmasq restart 2>/dev/null
    
    # 内存
    sync && echo 3 > /proc/sys/vm/drop_caches 2>/dev/null
    
    # ========== 深度清理额外操作 ==========
    if [ "$mode" = "deep" ]; then
        # Docker 清理
        if command -v docker &>/dev/null; then
            echo -e "${gl_huang}清理 Docker ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            docker system prune -af --volumes 2>/dev/null
        fi
        
        # 用户缓存和历史
        rm -rf /root/.cache/* 2>/dev/null
        > /root/.ash_history 2>/dev/null
        
        # 额外日志清理
        rm -rf /var/log/*.gz /var/log.* 2>/dev/null
        > /var/log/syslog 2>/dev/null
        > /var/log/cloudflared.log 2>/dev/null
        
        # 旧临时文件（3天未访问）
        find /tmp -atime +3 -type f -delete 2>/dev/null
        
        echo -e "${gl_lv}深度清理完成！${gl_bai}"
    else
        echo -e "${gl_lv}快速清理完成！${gl_bai}"
    fi
    
    # 显示结果
    echo ""
    echo -e "${gl_lan}【磁盘使用情况】${gl_bai}"
    df -h / | tail -1
    echo ""
    echo -e "${gl_lan}【内存使用情况】${gl_bai}"
    free | grep Mem
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

# iStoreOS 系统重置函数
istoreos_system_reset() {
    is_istoreos_system || return 1  # 非iStoreOS系统退出
    clear
    echo -e "${gl_zi}>>> iStoreOS 系统重置工具${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    log_warn "此操作将重置 iStoreOS 系统到初始状态！"
    echo ""
    echo -e "${gl_bai}重置将执行以下操作：${gl_bai}"
    echo -e "1. 清除所有已安装的软件包（除核心系统外）"
    echo -e "2. 恢复默认系统设置"
    echo -e "3. 删除所有用户配置文件"
    echo -e "4. 保留网络配置（如需完全重置请手动清除）"
    echo ""
    log_error "注意：操作不可逆！请务必备份重要数据！"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 获取用户确认
    read -r -e -p "$(echo -e "${gl_bai}您确定要重置系统吗? (输入 ${gl_hong}YES${gl_bai} 确认/${gl_huang}0${gl_bai}返回): ")" user_confirm
    
    [ "$user_confirm" = "0" ] && { 
        cancel_return "iStoreOS 管理"
        return 0
    }
    
    if [ "$user_confirm" = "YES" ]; then
        echo ""
        log_ok "正在执行系统重置 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo ""
        log_warn "系统将在10秒后重启并执行重置操作"
        log_warn "按 Ctrl+C 取消操作"
        echo ""
        
        # 倒计时
        for i in {10..1}; do
            echo -e "${gl_huang}${i}${gl_bai} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} "
            sleep_fractional 1
        done
        echo -e "${gl_hong}0${gl_bai}"
        echo ""
        
        log_info "开始执行 firstboot 命令 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo ""
        
        # 执行重置命令
        if firstboot -y && echo y | firstboot; then
            log_ok "重置命令执行成功！"
            log_warn "系统即将重启 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            sleep_fractional 2
            log_ok "正在重启系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            reboot
        else
            log_error "重置命令执行失败，请检查系统状态"
            break_end
            return 1
        fi
    else
        log_warn "操作已取消"
        break_end
        return 0
    fi
}

###### iStoreOS网络模式
istoreos_network_mode() {
    is_istoreos_system || return 1  # 非iStoreOS系统退出
    echo ""
    echo -e "${gl_zi}>>> iStoreOS设置向导${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    quickstart
}

# 系统备份函数
# 用法: wukongdaily_backup_system [备份目录]
# 参数: 备份目录(可选)，不传参则进入交互模式
wukongdaily_backup_system() {
    # 默认路径定义
    local DEFAULT_BACKUP_DIR="/mnt/backup/istoreos/wukong_backup"
    local backup_path
    
    # 先检查是否有参数传入
    if [ $# -gt 0 ]; then
        # 有参数传入，使用参数作为备份路径
        backup_path="$1"
        log_info "使用命令行参数指定的备份路径: ${gl_huang}${backup_path}${gl_bai}"
    else
        # 没有参数，进入交互式输入
        echo -e ""
        echo -e "${gl_zi}>>> 悟空系统备份${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}默认备份目录: ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_bai}"
        echo -e "${gl_lv}直接回车将使用默认目录，或输入自定义路径${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}请输入备份目录(${gl_huang}0${gl_bai}返回): ")" user_input

        [ "$user_input" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
        
        if [ -z "$user_input" ]; then
            backup_path="$DEFAULT_BACKUP_DIR"
            log_info "使用默认备份路径: ${gl_huang}${backup_path}${gl_bai}"
        else
            backup_path="$user_input"
        fi
    fi
    
    # 创建备份目录
    log_info "正在创建备份目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    mkdir -p "$backup_path" 2>/dev/null
    if [ $? -ne 0 ]; then
        log_error "无法创建目录 '${gl_huang}${backup_path}${gl_hong}'，请检查权限或路径是否正确 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 生成时间戳
    current_date=$(date "+%Y-%m-%d_%H-%M")
    log_info "备份时间: ${gl_huang}${current_date}${gl_bai}"
    
    # 创建带时间戳的子目录
    local full_path="$backup_path/${current_date}"
    mkdir -p "$full_path"
    
    if [ $? -ne 0 ]; then
        log_error "无法创建备份子目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 进入备份目录
    cd "$full_path" || {
        log_error "无法进入目录: ${gl_huang}${full_path}${gl_hong} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    }
    
    # 检查源目录是否存在
    if [ ! -d "/overlay" ]; then
        log_error "源目录 /overlay 不存在 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 执行备份
    log_info "正在备份系统文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    tar --strip-components=1 -czvf backup.tar.gz -C / overlay
    
    if [ $? -eq 0 ]; then
        log_ok "备份完成${gl_hong}!${gl_huang}!${gl_lv}!${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_info "系统备份文件已保存至: ${gl_huang}${full_path}/backup.tar.gz${gl_bai}"
        log_info "请及时下载保存到电脑，供恢复时使用"
        
        # 显示备份文件信息
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lan}备份文件信息:${gl_bai}"
        ls -lh "$full_path/backup.tar.gz"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
        return 0
    else
        log_error "备份失败，请检查源目录 /overlay 是否有读取权限 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
        return 1
    fi
}

# 系统恢复函数
# 用法: wukongdaily_restore_system [备份文件路径]
# 参数: 备份文件路径(可选)，不传参则进入交互模式
wukongdaily_restore_system() {
    is_istoreos_system || return 1  # 非iStoreOS系统退出
    # 默认备份目录
    local DEFAULT_BACKUP_DIR="/mnt/backup/istoreos/wukong_backup"
    local DEFAULT_RESTORE_FILE="/tmp/upload/backup.tar.gz"
    local file_path
    local restore_list=()
    
    echo -e ""
    echo -e "${gl_zi}>>> 悟空系统恢复${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 检查是否有参数传入
    if [ $# -gt 0 ]; then
        # 有参数传入
        local param="$1"
        
        # 判断参数是序号还是路径
        if [[ "$param" =~ ^[0-9]+$ ]]; then
            # 参数是数字，表示要使用扫描到的备份列表中的序号
            log_info "使用序号参数: ${gl_huang}${param}${gl_bai}"
            
            # 扫描备份目录
            if [ -d "$DEFAULT_BACKUP_DIR" ]; then
                # 查找所有备份文件并按时间排序
                restore_list=($(find "$DEFAULT_BACKUP_DIR" -name "backup.tar.gz" -type f 2>/dev/null | sort -r))
                
                if [ ${#restore_list[@]} -eq 0 ]; then
                    log_error "在目录 ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_hong} 中未找到备份文件"
                    exit_animation    # 即将退出动画
                    return 1
                fi
                
                # 检查序号是否有效
                if [ "$param" -ge 1 ] && [ "$param" -le ${#restore_list[@]} ]; then
                    local index=$((param - 1))
                    file_path="${restore_list[$index]}"
                    log_info "使用序号选择的备份文件: ${gl_huang}${file_path}${gl_bai}"
                else
                    log_error "无效的序号 ${gl_huang}${param}${gl_hong}，可用范围: 1-${#restore_list[@]}"
                    exit_animation    # 即将退出动画
                    return 1
                fi
            else
                log_error "备份目录不存在: ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_hong}"
                exit_animation    # 即将退出动画
                return 1
            fi
        else
            # 参数是路径
            file_path="$param"
            log_info "使用命令行参数指定的备份文件: ${gl_huang}${file_path}${gl_bai}"
        fi
    else
        # 没有参数，直接显示备份文件列表
        if [ -d "$DEFAULT_BACKUP_DIR" ]; then
            # 扫描备份目录
            log_info "正在扫描备份目录: ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_bai}"
            
            # 查找所有备份文件并按时间排序（最新的在前面）
            restore_list=($(find "$DEFAULT_BACKUP_DIR" -name "backup.tar.gz" -type f 2>/dev/null | sort -r))
            
            if [ ${#restore_list[@]} -eq 0 ]; then
                # 没有找到备份文件，提示上传
                echo -e "${gl_bai}在目录 ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_bai} 中未找到备份文件${gl_bai}"
                echo -e "${gl_hui}您可以使用以下方式准备备份文件:${gl_bai}"
                echo -e "  ${gl_bufan}1. ${gl_bai}将 backup.tar.gz 上传到 ${gl_huang}/tmp/upload/${gl_bai} 目录"
                echo -e "  ${gl_bufan}2. ${gl_bai}将备份文件放置到 ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_bai} 目录"
                echo -e "  ${gl_bufan}3. ${gl_bai}通过 URL 下载备份文件"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                
                read -r -e -p "$(echo -e "${gl_bai}请输入备份文件路径(${gl_huang}0${gl_bai}返回): ")" file_path
                
                [ "$file_path" = "0" ] && { cancel_return "上一级选单"; return 1; }   # break 或 continue 或 return ，视上下文而定
                
                if [ -z "$file_path" ]; then
                    file_path="$DEFAULT_RESTORE_FILE"
                    log_info "使用默认路径: ${gl_huang}${file_path}${gl_bai}"
                fi
            else
                # 显示备份文件列表
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_lan}可用的备份文件列表:${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                
                for i in "${!restore_list[@]}"; do
                    local idx=$((i+1))
                    local backup_file="${restore_list[$i]}"
                    local file_size=$(ls -lh "$backup_file" 2>/dev/null | awk '{print $5}')
                    local mod_time=$(stat -c "%y" "$backup_file" 2>/dev/null | cut -d' ' -f1,2 | cut -d'.' -f1)
                    local backup_dir=$(dirname "$backup_file")
                    local backup_name=$(basename "$backup_dir")
                    
                    echo -e "${gl_bufan}${idx}. ${gl_bai}${backup_name}/backup.tar.gz"
                    echo -e "   ${gl_hui}大小: ${gl_huang}${file_size}${gl_hui} 修改时间: ${gl_huang}${mod_time}${gl_bai}"
                    echo ""
                done
                
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "共找到 ${#restore_list[@]} 个备份文件"
                echo -e "${gl_hui}您也可以输入完整路径指定其他备份文件${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                
                # 让用户选择备份文件
                while true; do
                    read -r -e -p "$(echo -e "${gl_bai}请输入备份文件序号(${gl_huang}1-${#restore_list[@]}${gl_bai})或路径(${gl_huang}0${gl_bai}返回): ")" user_input
                    
                    [ "$user_input" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
                    
                    if [ -z "$user_input" ]; then
                        log_error "请输入序号或路径"
                        exit_animation    # 即将退出动画
                        continue
                    fi
                    
                    # 检查是否是数字（序号）
                    if [[ "$user_input" =~ ^[0-9]+$ ]]; then
                        if [ "$user_input" -ge 1 ] && [ "$user_input" -le ${#restore_list[@]} ]; then
                            local index=$((user_input - 1))
                            file_path="${restore_list[$index]}"
                            log_info "已选择备份: ${gl_huang}${file_path}${gl_bai}"
                            break
                        else
                            log_error "序号超出范围，请输入 1-${#restore_list[@]}"
                        fi
                    else
                        # 用户输入了路径
                        file_path="$user_input"
                        
                        # 检查路径是否存在
                        if [ ! -f "$file_path" ]; then
                            log_error "文件不存在: ${gl_huang}${file_path}${gl_hong}"
                            exit_animation    # 即将退出动画
                            continue
                        fi
                        
                        log_info "使用手动输入的路径: ${gl_huang}${file_path}${gl_bai}"
                        break
                    fi
                done
            fi
        else
            # 备份目录不存在，提示用户
            echo -e "${gl_bai}备份目录 ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_bai} 不存在${gl_bai}"
            echo -e "${gl_hui}您可以使用以下方式准备备份文件:${gl_bai}"
            echo -e "  ${gl_bufan}1. ${gl_bai}将 backup.tar.gz 上传到 ${gl_huang}/tmp/upload/${gl_bai} 目录"
            echo -e "  ${gl_bufan}2. ${gl_bai}输入完整的备份文件路径"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            read -r -e -p "$(echo -e "${gl_bai}请输入备份文件路径(${gl_huang}0${gl_bai}返回): ")" file_path
            
            [ "$file_path" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
            
            if [ -z "$file_path" ]; then
                file_path="$DEFAULT_RESTORE_FILE"
                log_info "使用默认路径: ${gl_huang}${file_path}${gl_bai}"
            fi
        fi
    fi
    
    # 检查文件是否存在
    if [ ! -f "$file_path" ]; then
        log_error "备份文件不存在: ${gl_huang}${file_path}${gl_hong}"
        log_error "请确保文件路径正确并重试 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 检查文件大小
    if [ ! -s "$file_path" ]; then
        log_error "备份文件为空或损坏: ${gl_huang}${file_path} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        log_error "请检查文件是否完整并重试 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        return 1
    fi
    
    # 显示文件信息
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_lan}备份文件信息:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    ls -lh "$file_path"
    echo -e "${gl_bai}文件路径: ${gl_huang}${file_path}${gl_bai}"
    echo -e "${gl_bai}修改时间: ${gl_huang}$(stat -c "%y" "$file_path" 2>/dev/null | cut -d'.' -f1)${gl_bai}"
    
    # 计算文件校验和
    if command -v md5sum >/dev/null 2>&1; then
        echo -n -e "${gl_bai}MD5校验: ${gl_huang}"
        md5sum "$file_path" | awk '{print $1}' | head -c 16
        echo " ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 确认恢复操作
    read -r -e -p "$(echo -e "${gl_bai}确认要恢复系统吗? 此操作将覆盖当前系统配置(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    
    case "$confirm" in
        [Yy])
            # 根据设备型号检查文件传输功能
            local model_info
            if [ -f /tmp/sysinfo/model ]; then
                model_info=$(cat /tmp/sysinfo/model)
                log_info "设备型号: ${gl_huang}${model_info}${gl_bai}"
                
                # 特定型号需要检查iStoreOS风格化
                case "$model_info" in
                    *2500* | *3000* | *6000*)
                        log_info "检测到特定型号设备，检查文件传输功能 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                        wukongdaily_check_style_installed
                        ;;
                esac
            fi
            
            # 执行恢复操作
            log_info "正在恢复系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            if tar -xzvf "$file_path" -C /; then
                log_ok "✅ 恢复已完成"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                
                # 确认重启
                read -r -e -p "$(echo -e "${gl_bai}立即重启系统以应用更改? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" reboot_confirm
                
                case "$reboot_confirm" in
                    [Yy])
                        log_info "系统正在重启 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                        sleep_fractional 2
                        reboot
                        ;;
                    [Nn])
                        log_ok "系统恢复完成，请手动重启以应用更改"
                        ;;
                    *)
                        log_warn "无效输入，跳过重启操作"
                        ;;
                esac
            else
                log_error "恢复失败，请检查备份文件是否完整"
                exit_animation    # 即将退出动画
                return 1
            fi
            ;;
        [Nn])
            log_info "已取消恢复操作"
            return 1
            ;;
        *) handle_invalid_input ;;
    esac
}

# 管理备份文件函数
# 用法: wukongdaily_manage_backup_files [备份目录]
# 参数: 备份目录(可选)，不传参则进入交互模式
wukongdaily_manage_backup_files() {
    is_istoreos_system || return 1  # 非iStoreOS系统退出
    # 默认路径定义
    local DEFAULT_BACKUP_DIR="/mnt/backup/istoreos/wukong_backup"
    local backup_dir
    
    clear
    echo -e "${gl_zi}>>> 管理悟空备份文件${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 选择备份目录
    if [ $# -gt 0 ]; then
        backup_dir="$1"
        log_info "使用命令行参数指定的备份目录: ${gl_huang}${backup_dir}${gl_bai}"
    else
        read -r -e -p "$(echo -e "${gl_bai}请输入备份目录(${gl_bai}默认: ${gl_lv}${DEFAULT_BACKUP_DIR}${gl_bai}/${gl_huang}0${gl_bai}返回): ")" user_input
        
        [ "$user_input" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
        
        if [ -z "$user_input" ]; then
            backup_dir="$DEFAULT_BACKUP_DIR"
        else
            backup_dir="$user_input"
        fi
    fi
    
    # 检查目录是否存在
    if [ ! -d "$backup_dir" ]; then
        log_error "备份目录不存在: ${gl_huang}${backup_dir}${gl_hong}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    while true; do
        
        # 查找所有备份文件
        backup_list=($(find "$backup_dir" -name "backup.tar.gz" -type f 2>/dev/null | sort -r))
        
        if [ ${#backup_list[@]} -eq 0 ]; then
            log_error "未找到备份文件"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        fi
        
        # 显示备份文件列表
        echo -e "${gl_lan}可用备份文件列表: ${gl_huang}${backup_dir}${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        for i in "${!backup_list[@]}"; do
            local idx=$((i+1))
            local file="${backup_list[$i]}"
            local file_size=$(ls -lh "$file" 2>/dev/null | awk '{print $5}')
            local mod_time=$(stat -c "%y" "$file" 2>/dev/null | cut -d'.' -f1 2>/dev/null || echo "未知")
            
            echo -e "${gl_bufan}${idx}. ${gl_bai}$(basename $(dirname "$file"))/backup.tar.gz"
            echo -e "   ${gl_hui}大小: ${gl_huang}${file_size}${gl_hui} 修改时间: ${gl_huang}${mod_time}${gl_bai}"
        done
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1. ${gl_bai}查看备份文件信息"
        echo -e "${gl_bufan}2. ${gl_bai}删除备份文件"
        echo -e "${gl_bufan}3. ${gl_bai}使用备份文件恢复"
        echo -e "${gl_bufan}4. ${gl_bai}切换到其他备份目录"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        read -r -e -p "$(echo -e "${gl_bai}请选择操作(${gl_huang}0${gl_bai}返回): ")" choice
        
        case "$choice" in
            0)
                return 0
                ;;
            1)
                # 查看备份文件信息
                read -r -e -p "$(echo -e "${gl_bai}请输入要查看的备份编号: ")" file_idx
                if [[ "$file_idx" =~ ^[0-9]+$ ]] && [ "$file_idx" -ge 1 ] && [ "$file_idx" -le ${#backup_list[@]} ]; then
                    local idx=$((file_idx-1))
                    local selected_file="${backup_list[$idx]}"
                    
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    echo -e "${gl_lan}备份文件详细信息:${gl_bai}"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    ls -lh "$selected_file"
                    echo -e "${gl_bai}完整路径: ${gl_huang}${selected_file}${gl_bai}"
                    echo -e "${gl_bai}创建时间: ${gl_huang}$(stat -c %y "$selected_file" 2>/dev/null)${gl_bai}"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                else
                    log_error "无效的备份编号"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                fi
                ;;
            2)
                # 删除备份文件
                read -r -e -p "$(echo -e "${gl_bai}请输入要删除的备份编号(${gl_huang}a${gl_bai}删除所有): ")" file_idx
                
                if [ "$file_idx" = "a" ] || [ "$file_idx" = "A" ]; then
                    # 删除所有备份
                    read -r -e -p "$(echo -e "${gl_hong}确定要删除所有备份文件吗? (${gl_lv}y${gl_hong}/${gl_hong}N${gl_hong}): ")" confirm
                    if [[ "$confirm" =~ ^[Yy]$ ]]; then
                        for file in "${backup_list[@]}"; do
                            rm -rf "$(dirname "$file")"
                            echo -e "${gl_hui}已删除: ${gl_huang}$(dirname "$file")${gl_bai}"
                        done
                        log_ok "已删除所有备份文件"
                    fi
                elif [[ "$file_idx" =~ ^[0-9]+$ ]] && [ "$file_idx" -ge 1 ] && [ "$file_idx" -le ${#backup_list[@]} ]; then
                    # 删除单个备份
                    local idx=$((file_idx-1))
                    local selected_file="${backup_list[$idx]}"
                    local backup_dir_path="$(dirname "$selected_file")"
                    
                    echo -e "${gl_bai}将要删除备份: ${gl_huang}${backup_dir_path}${gl_bai}"
                    read -r -e -p "$(echo -e "${gl_hong}确定要删除吗? (${gl_lv}y${gl_hong}/${gl_hong}N${gl_hong}): ")" confirm
                    
                    if [[ "$confirm" =~ ^[Yy]$ ]]; then
                        rm -rf "$backup_dir_path"
                        if [ $? -eq 0 ]; then
                            log_ok "已删除备份: ${gl_huang}${backup_dir_path}${gl_bai}"
                            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                            break_end
                        else
                            log_error "删除失败"
                            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                            break_end
                        fi
                    fi
                else
                    log_error "无效的选择"
                fi
                ;;
            3)
                # 使用备份文件恢复
                read -r -e -p "$(echo -e "${gl_bai}请输入要恢复的备份编号: ")" file_idx
                if [[ "$file_idx" =~ ^[0-9]+$ ]] && [ "$file_idx" -ge 1 ] && [ "$file_idx" -le ${#backup_list[@]} ]; then
                    local idx=$((file_idx-1))
                    local selected_file="${backup_list[$idx]}"
                    
                    read -r -e -p "$(echo -e "${gl_hong}确定要使用此备份恢复系统吗? (${gl_lv}y${gl_hong}/${gl_hong}N${gl_hong}): ")" confirm
                    
                    if [[ "$confirm" =~ ^[Yy]$ ]]; then
                        wukongdaily_restore_system "$selected_file"
                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        break_end
                    fi
                else
                    log_error "无效的备份编号"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                fi
                ;;
            4)
                # 切换备份目录
                read -r -e -p "$(echo -e "${gl_bai}请输入新的备份目录: ")" new_backup_dir
                if [ -n "$new_backup_dir" ]; then
                    backup_dir="$new_backup_dir"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                fi
                ;;
            *) handle_invalid_input ;;
        esac
    done
}

# URL系统恢复函数
# 用法: wukongdaily_restore_from_url [URL地址]
# 参数: URL地址(可选)，不传参则进入交互模式
wukongdaily_restore_from_url() {
    is_istoreos_system || return 1  # 非iStoreOS系统退出
    local backup_url
    local download_path="/tmp/url_backup.tar.gz"
    
    echo -e ""
    echo -e "${gl_zi}>>> 悟空URL系统恢复${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 检查是否有参数传入
    if [ $# -gt 0 ]; then
        # 有参数传入，使用参数作为备份URL
        backup_url="$1"
        log_info "使用命令行参数指定的备份URL: ${gl_huang}${backup_url}${gl_bai}"
    else
        # 没有参数，进入交互式输入
        echo -e "${gl_lan}支持的URL格式:${gl_bai}"
        echo -e "  ${gl_hui}• http:// 或 https:// 开头的网络地址${gl_bai}"
        echo -e "  ${gl_hui}• 本地文件路径${gl_bai}"
        echo -e "  ${gl_lv}• http://10.10.10.251:5000/file/myfile/istoreos/backup/wukong_backup/2026-03-23_03-15/backup.tar.gz${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        read -r -e -p "$(echo -e "${gl_bai}请输入备份文件URL或路径(${gl_huang}0${gl_bai}返回): ")" backup_url
        
        [ "$backup_url" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
        
        if [ -z "$backup_url" ]; then
            log_error "未输入URL或路径"
            return 1
        fi
    fi
    
    # 判断是URL还是本地文件
    if [[ "$backup_url" =~ ^https?:// ]]; then
        # 网络URL下载
        log_info "正在从网络下载备份文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        log_info "URL: ${gl_huang}${backup_url}${gl_bai}"
        
        # 检查是否安装wget或curl
        if command -v wget >/dev/null 2>&1; then
            wget --show-progress -O "$download_path" "$backup_url"
        elif command -v curl >/dev/null 2>&1; then
            curl -L -o "$download_path" "$backup_url"
        else
            log_error "未找到wget或curl，请先安装其中任意一个下载工具"
            exit_animation    # 即将退出动画
            return 1
        fi
        
        if [ $? -ne 0 ]; then
            log_error "下载失败，请检查URL和网络连接"
            exit_animation    # 即将退出动画
            return 1
        fi
        
        log_ok "下载完成: ${gl_huang}${download_path}${gl_bai}"
        
    elif [ -f "$backup_url" ]; then
        # 本地文件
        download_path="$backup_url"
        log_info "使用本地文件: ${gl_huang}${download_path}${gl_bai}"
    else
        log_error "不是有效的URL或文件不存在: ${gl_huang}${backup_url}${gl_hong}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 检查下载的文件
    if [ ! -f "$download_path" ]; then
        log_error "备份文件不存在: ${gl_huang}${download_path}${gl_hong}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    if [ ! -s "$download_path" ]; then
        log_error "备份文件为空或损坏 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 显示文件信息
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_lan}备份文件信息:${gl_bai}"
    ls -lh "$download_path"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 确认恢复操作
    read -r -e -p "$(echo -e "${gl_bai}确认要使用此备份恢复系统吗? 此操作将覆盖当前系统配置(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    
    case "$confirm" in
        [Yy])
            # 根据设备型号检查文件传输功能
            local model_info
            if [ -f /tmp/sysinfo/model ]; then
                model_info=$(cat /tmp/sysinfo/model)
                log_info "设备型号: ${gl_huang}${model_info}${gl_bai}"
                
                case "$model_info" in
                    *2500* | *3000* | *6000*)
                        log_info "检测到特定型号设备，检查文件传输功能 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                        wukongdaily_check_style_installed
                        ;;
                esac
            else
                log_warn "无法获取设备型号信息"
            fi
            
            # 执行恢复操作
            log_info "正在恢复系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            if tar -xzvf "$download_path" -C /; then
                log_ok "✅ 恢复已完成"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                
                # 清理下载的临时文件
                if [[ "$backup_url" =~ ^https?:// ]] && [ "$download_path" != "$backup_url" ]; then
                    rm -f "$download_path"
                    log_info "已清理临时下载文件"
                fi
                
                # 确认重启
                read -r -e -p "$(echo -e "${gl_bai}立即重启系统以应用更改? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" reboot_confirm
                
                case "$reboot_confirm" in
                    [Yy])
                        log_info "系统正在重启 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                        sleep_fractional 2
                        reboot
                        ;;
                    [Nn])
                        log_ok "系统恢复完成，请手动重启以应用更改"
                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        break_end
                        ;;
                    *)
                        log_warn "无效输入，跳过重启操作"
                        ;;
                esac
            else
                log_error "恢复失败，请检查备份文件是否完整"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                return 1
            fi
            ;;
        [Nn])
            log_info "已取消恢复操作"
            # 清理下载的临时文件
            if [[ "$backup_url" =~ ^https?:// ]] && [ "$download_path" != "$backup_url" ]; then
                rm -f "$download_path"
                log_info "已清理临时下载文件"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
            fi
            return 1
            ;;
        *)
            log_error "无效的选择，请输入 ${gl_bai}(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai})"
            # 清理下载的临时文件
            if [[ "$backup_url" =~ ^https?:// ]] && [ "$download_path" != "$backup_url" ]; then
                rm -f "$download_path"
                log_info "已清理临时下载文件"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
            fi
            return 1
            ;;
    esac
}

# 菜单显示函数
# 用法: wukongdaily_backup_restore_menu
wukongdaily_backup_restore_menu() {
    is_istoreos_system || return 1  # 非iStoreOS系统退出
    while true; do
        clear
        local backup_dir="/mnt/backup/istoreos/wukong_backup"

        # 创建备份目录（如果不存在）
        if [ ! -d "$backup_dir" ]; then
            mkdir -p "$backup_dir"
            chmod 755 "$backup_dir"
            cd "$backup_dir"
        fi

        # 查找所有备份文件
        backup_list=($(find "$backup_dir" -name "backup.tar.gz" -type f 2>/dev/null | sort -r))
        
        # 显示备份文件列表

        echo -e "${gl_huang}>>> 可用悟空备份文件列表: ${gl_huang}${backup_dir}${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        if [ ${#backup_list[@]} -eq 0 ]; then
            log_error "未找到备份文件"
        fi
        
        for i in "${!backup_list[@]}"; do
            local idx=$((i+1))
            local file="${backup_list[$i]}"
            local file_size=$(ls -lh "$file" 2>/dev/null | awk '{print $5}')
            local mod_time=$(stat -c "%y" "$file" 2>/dev/null | cut -d'.' -f1 2>/dev/null || echo "未知")
            
            echo -e "${gl_bufan}${idx}. ${gl_bai}$(basename $(dirname "$file"))/backup.tar.gz"
            echo -e "   ${gl_hui}大小: ${gl_huang}${file_size}${gl_hui} 修改时间: ${gl_huang}${mod_time}${gl_bai}"
        done
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e ""
        echo -e "${gl_zi}>>> 悟空备份恢复工具${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}悟空系统备份               ${gl_bufan}2.  ${gl_bai}悟空系统恢复"
        echo -e "${gl_bufan}3.  ${gl_bai}管理悟空备份文件           ${gl_bufan}4.  ${gl_bai}悟空URL系统恢复"
        echo -e "${gl_bufan}5.  ${gl_bai}上传备份文件               ${gl_bufan}6.  ${gl_bai}下载备份文件"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单             ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " choice
        
        case $choice in
            1) wukongdaily_backup_system ;;                                         # 悟空系统备份
            2) wukongdaily_restore_system ;;                                        # 悟空系统恢复
            3) wukongdaily_manage_backup_files ;;                                   # 悟空管理备份文件
            4) wukongdaily_restore_from_url ;;                                      # 悟空URL系统恢复
            5) cd "$backup_dir" && rz_upload_file; continue ;;                      # 上传备份文件
            6) cd "$backup_dir" && rz_download_files_to_local; continue ;;          # 下载备份文件
            0) cancel_return "iStoreOS 管理"; return 0 ;;                           # 返回上一级选单
            00|000|0000) exit_script ;;                                             # 退出脚本
            *) handle_invalid_input ;;
        esac
    done
}

# 系统备份函数
# 用法: istoreos_backup_system [备份目录]
# 参数: 备份目录(可选)，不传参则进入交互模式
istoreos_backup_system() {
    # 默认路径定义
    local DEFAULT_BACKUP_DIR="/mnt/backup/istoreos/istoreos_backup"
    local backup_path
    
    # 先检查是否有参数传入
    if [ $# -gt 0 ]; then
        # 有参数传入，使用参数作为备份路径
        backup_path="$1"
        log_info "使用命令行参数指定的备份路径: ${gl_huang}${backup_path}${gl_bai}"
    else
        # 没有参数，进入交互式输入
        echo -e ""
        echo -e "${gl_zi}>>> 官方系统备份${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bai}默认备份目录: ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_bai}"
        echo -e "${gl_lv}直接回车将使用默认目录，或输入自定义路径${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        read -r -e -p "$(echo -e "${gl_bai}请输入备份目录(${gl_huang}0${gl_bai}返回): ")" user_input
        
        [ "$user_input" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
        
        if [ -z "$user_input" ]; then
            backup_path="$DEFAULT_BACKUP_DIR"
            log_info "使用默认备份路径: ${gl_huang}${backup_path}${gl_bai}"
        else
            backup_path="$user_input"
        fi
    fi
    
    # 创建备份目录
    log_info "正在创建备份目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    mkdir -p "$backup_path" 2>/dev/null
    if [ $? -ne 0 ]; then
        log_error "无法创建目录 '${gl_huang}${backup_path}${gl_hong}'，请检查权限或路径是否正确 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 生成时间戳
    current_date=$(date "+%Y-%m-%d_%H-%M")
    log_info "备份时间: ${gl_huang}${current_date}${gl_bai}"
    
    # 创建带时间戳的子目录
    local full_path="$backup_path/${current_date}"
    mkdir -p "$full_path"
    
    if [ $? -ne 0 ]; then
        log_error "无法创建备份子目录 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 进入备份目录
    cd "$full_path" || {
        log_error "无法进入目录: ${gl_huang}${full_path}${gl_hong} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    }
    
    # 检查 sysupgrade 命令是否可用
    if ! command -v sysupgrade >/dev/null 2>&1; then
        log_error "sysupgrade 命令不可用，请检查系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 执行备份
    log_info "正在使用 sysupgrade 创建系统配置备份 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 创建备份文件名
    local backup_file="backup.tar.gz"
    
    # 执行 sysupgrade 备份
    echo -e "${gl_hui}正在执行: ${gl_huang}sysupgrade -b $backup_file${gl_bai}"
    sysupgrade -b "$backup_file"
    
    if [ $? -eq 0 ]; then
        log_ok "✅ sysupgrade 备份完成${gl_hong}!${gl_huang}!${gl_lv}!${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        log_info "系统配置备份已保存至: ${gl_huang}${full_path}/${backup_file}${gl_bai}"
        log_info "备份格式: ${gl_huang}sysupgrade 官方备份格式${gl_bai}"
        log_info "包含内容: ${gl_huang}配置文件、已安装软件包列表${gl_bai}"
        log_info "请及时下载保存到电脑，供恢复时使用"
        
        # 显示备份文件信息
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lan}备份文件信息:${gl_bai}"
        ls -lh "$full_path/$backup_file"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        # 显示备份中包含的内容
        log_info "查看备份内容列表:"
        echo -e "${gl_hui}$(sysupgrade -l 2>/dev/null | head -20)${gl_bai}"
        if [ $(sysupgrade -l 2>/dev/null | wc -l) -gt 20 ]; then
            echo -e "{gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}更多内容请运行 ${gl_lv}'sysupgrade -l' ${gl_bai}查看${gl_bai}"
        fi
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        # 创建恢复说明文件
        cat > "$full_path/RESTORE_README.txt" << EOF
=========================================
iStoreOS 系统备份恢复说明
=========================================
备份时间: $current_date
备份工具: sysupgrade
备份文件: $backup_file

【备份内容】
此备份包含以下内容：
1. 系统配置文件 (在 sysupgrade.conf 中定义)
2. 已安装软件包列表
3. 网络设置、防火墙规则等

【恢复方法】
方法1: 通过固件升级恢复
   sysupgrade -f $backup_file /路径/到/固件.bin

方法2: 直接恢复配置
   sysupgrade -r $backup_file

方法3: 通过本工具恢复
   在备份恢复菜单中选择相应功能

【注意事项】
1. 恢复配置会覆盖当前系统设置
2. 建议在恢复前备份当前配置
3. 部分配置可能需要重启生效

【下载保存】
请将此备份下载到电脑保存，以防意外丢失：
scp root@路由器IP:$full_path/$backup_file .
EOF
        log_info "恢复说明已保存至: ${gl_huang}${full_path}/RESTORE_README.txt${gl_bai}"
        
        break_end
        return 0
    else
        log_error "备份失败，请检查 sysupgrade 是否正常工作 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        break_end
        return 1
    fi
}

# 系统恢复函数
# 用法: istoreos_restore_system [备份文件路径]
# 参数: 备份文件路径(可选)，不传参则进入交互模式
istoreos_restore_system() {
    # 默认备份目录
    local DEFAULT_BACKUP_DIR="/mnt/backup/istoreos/istoreos_backup"
    local DEFAULT_RESTORE_FILE="/tmp/upload/backup.tar.gz"
    local file_path
    local restore_list=()
    
    echo -e ""
    echo -e "${gl_zi}>>> 官方系统恢复${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 检查是否有参数传入
    if [ $# -gt 0 ]; then
        # 有参数传入
        local param="$1"
        
        # 判断参数是序号还是路径
        if [[ "$param" =~ ^[0-9]+$ ]]; then
            # 参数是数字，表示要使用扫描到的备份列表中的序号
            log_info "使用序号参数: ${gl_huang}${param}${gl_bai}"
            
            # 扫描备份目录
            if [ -d "$DEFAULT_BACKUP_DIR" ]; then
                # 查找所有备份文件并按时间排序
                restore_list=($(find "$DEFAULT_BACKUP_DIR" -name "backup.tar.gz" -type f 2>/dev/null | sort -r))
                
                if [ ${#restore_list[@]} -eq 0 ]; then
                    log_error "在目录 ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_hong} 中未找到备份文件"
                    exit_animation
                    return 1
                fi
                
                # 检查序号是否有效
                if [ "$param" -ge 1 ] && [ "$param" -le ${#restore_list[@]} ]; then
                    local index=$((param - 1))
                    file_path="${restore_list[$index]}"
                    log_info "使用序号选择的备份文件: ${gl_huang}${file_path}${gl_bai}"
                else
                    log_error "无效的序号 ${gl_huang}${param}${gl_hong}，可用范围: 1-${#restore_list[@]}"
                    exit_animation
                    return 1
                fi
            else
                log_error "备份目录不存在: ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_hong}"
                exit_animation    # 即将退出动画
                return 1
            fi
        else
            # 参数是路径
            file_path="$param"
            log_info "使用命令行参数指定的备份文件: ${gl_huang}${file_path}${gl_bai}"
        fi
    else
        # 没有参数，直接显示备份文件列表
        if [ -d "$DEFAULT_BACKUP_DIR" ]; then
            # 扫描备份目录
            log_info "正在扫描备份目录: ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_bai}"
            
            # 查找所有备份文件并按时间排序（最新的在前面）
            restore_list=($(find "$DEFAULT_BACKUP_DIR" -name "backup.tar.gz" -type f 2>/dev/null | sort -r))
            
            if [ ${#restore_list[@]} -eq 0 ]; then
                # 没有找到备份文件，提示上传
                echo -e "${gl_bai}在目录 ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_bai} 中未找到备份文件${gl_bai}"
                echo -e "${gl_hui}您可以使用以下方式准备备份文件:${gl_bai}"
                echo -e "  ${gl_bufan}1. ${gl_bai}将 backup.tar.gz 上传到 ${gl_huang}/tmp/upload/${gl_bai} 目录"
                echo -e "  ${gl_bufan}2. ${gl_bai}将备份文件放置到 ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_bai} 目录"
                echo -e "  ${gl_bufan}3. ${gl_bai}通过 URL 下载备份文件"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                
                read -r -e -p "$(echo -e "${gl_bai}请输入备份文件路径(${gl_huang}0${gl_bai}返回): ")" file_path
                
                [ "$file_path" = "0" ] && { cancel_return "上一级选单"; return 1; }     # break 或 continue 或 return ，视上下文而定
                
                if [ -z "$file_path" ]; then
                    file_path="$DEFAULT_RESTORE_FILE"
                    log_info "使用默认路径: ${gl_huang}${file_path}${gl_bai}"
                fi
            else
                # 显示备份文件列表
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "${gl_lan}可用的备份文件列表:${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                
                for i in "${!restore_list[@]}"; do
                    local idx=$((i+1))
                    local backup_file="${restore_list[$i]}"
                    local file_size=$(ls -lh "$backup_file" 2>/dev/null | awk '{print $5}')
                    local mod_time=$(stat -c "%y" "$backup_file" 2>/dev/null | cut -d' ' -f1,2 | cut -d'.' -f1)
                    local backup_dir=$(dirname "$backup_file")
                    local backup_name=$(basename "$backup_dir")
                    
                    echo -e "${gl_bufan}${idx}. ${gl_bai}${backup_name}/backup.tar.gz"
                    echo -e "   ${gl_hui}大小: ${gl_huang}${file_size}${gl_hui} 修改时间: ${gl_huang}${mod_time}${gl_bai}"
                    echo ""
                done
                
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                echo -e "共找到 ${#restore_list[@]} 个备份文件"
                echo -e "${gl_hui}您也可以输入完整路径指定其他备份文件${gl_bai}"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                
                # 让用户选择备份文件
                while true; do
                    read -r -e -p "$(echo -e "${gl_bai}请输入备份文件序号(${gl_huang}1-${#restore_list[@]}${gl_bai})或路径(${gl_huang}0${gl_bai}返回): ")" user_input
                    
                    [ "$user_input" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
                    
                    if [ -z "$user_input" ]; then
                        log_error "请输入序号或路径"
                        exit_animation    # 即将退出动画
                        continue
                    fi
                    
                    # 检查是否是数字（序号）
                    if [[ "$user_input" =~ ^[0-9]+$ ]]; then
                        if [ "$user_input" -ge 1 ] && [ "$user_input" -le ${#restore_list[@]} ]; then
                            local index=$((user_input - 1))
                            file_path="${restore_list[$index]}"
                            log_info "已选择备份: ${gl_huang}${file_path}${gl_bai}"
                            break
                        else
                            log_error "序号超出范围，请输入 1-${#restore_list[@]}"
                        fi
                    else
                        # 用户输入了路径
                        file_path="$user_input"
                        
                        # 检查路径是否存在
                        if [ ! -f "$file_path" ]; then
                            log_error "文件不存在: ${gl_huang}${file_path}${gl_hong}"
                            exit_animation    # 即将退出动画
                            continue
                        fi
                        
                        log_info "使用手动输入的路径: ${gl_huang}${file_path}${gl_bai}"
                        exit_animation    # 即将退出动画
                        break
                    fi
                done
            fi
        else
            # 备份目录不存在，提示用户
            echo -e "${gl_bai}备份目录 ${gl_huang}${DEFAULT_BACKUP_DIR}${gl_bai} 不存在${gl_bai}"
            echo -e "${gl_hui}您可以使用以下方式准备备份文件:${gl_bai}"
            echo -e "  ${gl_bufan}1. ${gl_bai}将 backup.tar.gz 上传到 ${gl_huang}/tmp/upload/${gl_bai} 目录"
            echo -e "  ${gl_bufan}2. ${gl_bai}输入完整的备份文件路径"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            read -r -e -p "$(echo -e "${gl_bai}请输入备份文件路径(${gl_huang}0${gl_bai}返回): ")" file_path
            
            [ "$file_path" = "0" ] && { cancel_return "上一级选单"; return 1; }     # break 或 continue 或 return ，视上下文而定
            
            if [ -z "$file_path" ]; then
                file_path="$DEFAULT_RESTORE_FILE"
                log_info "使用默认路径: ${gl_huang}${file_path}${gl_bai}"
            fi
        fi
    fi
    
    # 检查文件是否存在
    if [ ! -f "$file_path" ]; then
        log_error "备份文件不存在: ${gl_huang}${file_path}${gl_hong}"
        log_error "请确保文件路径正确并重试 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 检查文件大小
    if [ ! -s "$file_path" ]; then
        log_error "备份文件为空或损坏: ${gl_huang}${file_path} ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        log_error "请检查文件是否完整并重试 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 检查是否是有效的 sysupgrade 备份
    if ! tar -tzf "$file_path" 2>/dev/null | grep -q "sysupgrade.tgz\|etc/backup/"; then
        echo -e "${gl_hong}警告: 备份文件可能不是 sysupgrade 格式${gl_bai}"
        echo -e "${gl_hui}此备份可能无法通过 sysupgrade 正确恢复${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}是否继续? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" continue_restore
        if [[ ! "$continue_restore" =~ ^[Yy]$ ]]; then
            exit_animation    # 即将退出动画
            return 1
        fi
    fi
    
    # 显示文件信息
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_lan}官方备份文件信息:${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    ls -lh "$file_path"
    echo -e "${gl_bai}文件路径: ${gl_huang}${file_path}${gl_bai}"
    echo -e "${gl_bai}修改时间: ${gl_huang}$(stat -c "%y" "$file_path" 2>/dev/null | cut -d'.' -f1)${gl_bai}"
    
    # 计算文件校验和
    if command -v md5sum >/dev/null 2>&1; then
        echo -n -e "${gl_bai}MD5校验: ${gl_huang}"
        md5sum "$file_path" | awk '{print $1}' | head -c 16
        echo " ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 选择恢复模式
    echo -e "${gl_lan}恢复模式选择:${gl_bai}"
    echo -e "${gl_bufan}1. ${gl_bai}标准恢复模式 (sysupgrade -r) - 推荐"
    echo -e "${gl_bufan}2. ${gl_bai}手动提取模式 (tar -xzf) - 兼容旧格式"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    read -r -e -p "$(echo -e "${gl_bai}请选择恢复模式(${gl_huang}1${gl_bai}): ")" restore_mode
    restore_mode="${restore_mode:-1}"
    
    # 确认恢复操作
    read -r -e -p "$(echo -e "${gl_bai}确认要恢复系统吗? 此操作将覆盖当前系统配置(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    
    case "$confirm" in
        [Yy])
            # 根据设备型号检查文件传输功能
            local model_info
            if [ -f /tmp/sysinfo/model ]; then
                model_info=$(cat /tmp/sysinfo/model)
                log_info "设备型号: ${gl_huang}${model_info}${gl_bai}"
                
                # 特定型号需要检查iStoreOS风格化
                case "$model_info" in
                    *2500* | *3000* | *6000*)
                        log_info "检测到特定型号设备，检查文件传输功能 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                        istoreos_check_style_installed
                        ;;
                esac
            fi
            
            # 执行恢复操作
            log_info "正在恢复系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            if [ "$restore_mode" = "1" ]; then
                # 使用 sysupgrade 标准恢复
                log_info "使用 sysupgrade 标准恢复模式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                echo -e "${gl_hui}正在执行: ${gl_huang}sysupgrade -r \"$file_path\"${gl_bai}"
                sysupgrade -r "$file_path"
                restore_result=$?
            else
                # 使用手动提取模式
                log_info "使用手动提取恢复模式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                echo -e "${gl_hui}正在执行: ${gl_huang}tar -xzvf \"$file_path\" -C /${gl_bai}"
                tar -xzvf "$file_path" -C /
                restore_result=$?
            fi
            
            if [ $restore_result -eq 0 ]; then
                log_ok "✅ 恢复已完成"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                
                # 确认重启
                read -r -e -p "$(echo -e "${gl_bai}立即重启系统以应用更改? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" reboot_confirm
                
                case "$reboot_confirm" in
                    [Yy])
                        log_info "系统正在重启 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                        sleep_fractional 2
                        reboot
                        ;;
                    [Nn])
                        log_ok "系统恢复完成，请手动重启以应用更改"
                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        break_end
                        ;;
                    *)
                        log_warn "无效输入，跳过重启操作"
                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        break_end
                        ;;
                esac
            else
                log_error "恢复失败，请检查备份文件是否完整"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                return 1
            fi
            ;;
        [Nn])
            log_info "已取消恢复操作"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            return 1
            ;;
        *)
            log_error "无效的选择，请输入 ${gl_bai}(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai})"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            break_end
            return 1
            ;;
    esac
}

# 管理备份文件函数
# 用法: istoreos_manage_backup_files [备份目录]
# 参数: 备份目录(可选)，不传参则进入交互模式
istoreos_manage_backup_files() {
    # 默认路径定义
    local DEFAULT_BACKUP_DIR="/mnt/backup/istoreos/istoreos_backup"
    local backup_dir
    
    clear
    echo -e "${gl_zi}>>> 管理官方备份文件${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 选择备份目录
    if [ $# -gt 0 ]; then
        backup_dir="$1"
        log_info "使用命令行参数指定的备份目录: ${gl_huang}${backup_dir}${gl_bai}"
    else
        read -r -e -p "$(echo -e "${gl_bai}请输入备份目录(${gl_bai}默认: ${gl_lv}${DEFAULT_BACKUP_DIR}${gl_bai}/${gl_huang}0${gl_bai}返回): ")" user_input
        
        [ "$user_input" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
        
        if [ -z "$user_input" ]; then
            backup_dir="$DEFAULT_BACKUP_DIR"
        else
            backup_dir="$user_input"
        fi
    fi
    
    # 检查目录是否存在
    if [ ! -d "$backup_dir" ]; then
        log_error "备份目录不存在: ${gl_huang}${backup_dir}${gl_hong}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    while true; do
        
        # 查找所有备份文件
        backup_list=($(find "$backup_dir" -name "backup.tar.gz" -type f 2>/dev/null | sort -r))
        
        if [ ${#backup_list[@]} -eq 0 ]; then
            log_error "未找到备份文件"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            exit_animation    # 即将退出动画
            return 1
        fi
        
        # 显示备份文件列表
        echo -e "${gl_lan}可用备份文件列表: ${gl_huang}${backup_dir}${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        for i in "${!backup_list[@]}"; do
            local idx=$((i+1))
            local file="${backup_list[$i]}"
            local file_size=$(ls -lh "$file" 2>/dev/null | awk '{print $5}')
            local mod_time=$(stat -c "%y" "$file" 2>/dev/null | cut -d'.' -f1 2>/dev/null || echo "未知")
            
            echo -e "${gl_bufan}${idx}. ${gl_bai}$(basename $(dirname "$file"))/backup.tar.gz"
            echo -e "   ${gl_hui}大小: ${gl_huang}${file_size}${gl_hui} 修改时间: ${gl_huang}${mod_time}${gl_bai}"
        done
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1. ${gl_bai}查看备份文件信息"
        echo -e "${gl_bufan}2. ${gl_bai}删除备份文件"
        echo -e "${gl_bufan}3. ${gl_bai}使用备份文件恢复"
        echo -e "${gl_bufan}4. ${gl_bai}切换到其他备份目录"
        echo -e "${gl_bufan}5. ${gl_bai}验证备份文件完整性"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        read -r -e -p "$(echo -e "${gl_bai}请选择操作(${gl_huang}0${gl_bai}返回): ")" choice
        
        case "$choice" in
            0) cancel_return; return 0 ;;    # 返回到上一级菜单
            1)
                # 查看备份文件信息
                read -r -e -p "$(echo -e "${gl_bai}请输入要查看的备份编号: ")" file_idx
                if [[ "$file_idx" =~ ^[0-9]+$ ]] && [ "$file_idx" -ge 1 ] && [ "$file_idx" -le ${#backup_list[@]} ]; then
                    local idx=$((file_idx-1))
                    local selected_file="${backup_list[$idx]}"
                    
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    echo -e "${gl_lan}备份文件详细信息:${gl_bai}"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    ls -lh "$selected_file"
                    echo -e "${gl_bai}完整路径: ${gl_huang}${selected_file}${gl_bai}"
                    echo -e "${gl_bai}创建时间: ${gl_huang}$(stat -c %y "$selected_file" 2>/dev/null)${gl_bai}"
                    
                    # 检查是否是 sysupgrade 备份
                    if tar -tzf "$selected_file" 2>/dev/null | grep -q "sysupgrade.tgz\|etc/backup/"; then
                        echo -e "${gl_bai}备份格式: ${gl_huang}sysupgrade 官方格式${gl_bai}"
                    else
                        echo -e "${gl_bai}备份格式: ${gl_hong}自定义格式${gl_bai}"
                    fi
                    
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                else
                    log_error "无效的备份编号"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                fi
                ;;
            2)
                # 删除备份文件
                read -r -e -p "$(echo -e "${gl_bai}请输入要删除的备份编号(${gl_huang}a${gl_bai}删除所有): ")" file_idx
                
                if [ "$file_idx" = "a" ] || [ "$file_idx" = "A" ]; then
                    # 删除所有备份
                    read -r -e -p "$(echo -e "${gl_hong}确定要删除所有备份文件吗? (${gl_lv}y${gl_hong}/${gl_hong}N${gl_hong}): ")" confirm
                    if [[ "$confirm" =~ ^[Yy]$ ]]; then
                        for file in "${backup_list[@]}"; do
                            rm -rf "$(dirname "$file")"
                            echo -e "${gl_hui}已删除: ${gl_huang}$(dirname "$file")${gl_bai}"
                        done
                        log_ok "已删除所有备份文件"
                    fi
                elif [[ "$file_idx" =~ ^[0-9]+$ ]] && [ "$file_idx" -ge 1 ] && [ "$file_idx" -le ${#backup_list[@]} ]; then
                    # 删除单个备份
                    local idx=$((file_idx-1))
                    local selected_file="${backup_list[$idx]}"
                    local backup_dir_path="$(dirname "$selected_file")"
                    
                    echo -e "${gl_bai}将要删除备份: ${gl_huang}${backup_dir_path}${gl_bai}"
                    read -r -e -p "$(echo -e "${gl_hong}确定要删除吗? (${gl_lv}y${gl_hong}/${gl_hong}N${gl_hong}): ")" confirm
                    
                    if [[ "$confirm" =~ ^[Yy]$ ]]; then
                        rm -rf "$backup_dir_path"
                        if [ $? -eq 0 ]; then
                            log_ok "已删除备份: ${gl_huang}${backup_dir_path}${gl_bai}"
                            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                            break_end
                        else
                            log_error "删除失败"
                            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                            break_end
                        fi
                    fi
                else
                    log_error "无效的选择"
                fi
                ;;
            3)
                # 使用备份文件恢复
                read -r -e -p "$(echo -e "${gl_bai}请输入要恢复的备份编号: ")" file_idx
                if [[ "$file_idx" =~ ^[0-9]+$ ]] && [ "$file_idx" -ge 1 ] && [ "$file_idx" -le ${#backup_list[@]} ]; then
                    local idx=$((file_idx-1))
                    local selected_file="${backup_list[$idx]}"
                    
                    read -r -e -p "$(echo -e "${gl_hong}确定要使用此备份恢复系统吗? (${gl_lv}y${gl_hong}/${gl_hong}N${gl_hong}): ")" confirm
                    
                    if [[ "$confirm" =~ ^[Yy]$ ]]; then
                        istoreos_restore_system "$selected_file"
                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        break_end
                    fi
                else
                    log_error "无效的备份编号"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                fi
                ;;
            4)
                # 切换备份目录
                read -r -e -p "$(echo -e "${gl_bai}请输入新的备份目录: ")" new_backup_dir
                if [ -n "$new_backup_dir" ]; then
                    backup_dir="$new_backup_dir"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                fi
                ;;
            5)
                # 验证备份文件完整性
                read -r -e -p "$(echo -e "${gl_bai}请输入要验证的备份编号: ")" file_idx
                if [[ "$file_idx" =~ ^[0-9]+$ ]] && [ "$file_idx" -ge 1 ] && [ "$file_idx" -le ${#backup_list[@]} ]; then
                    local idx=$((file_idx-1))
                    local selected_file="${backup_list[$idx]}"
                    
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    echo -e "${gl_lan}验证备份文件完整性:${gl_bai}"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    
                    # 检查 tar 包是否完整
                    if tar -tzf "$selected_file" >/dev/null 2>&1; then
                        echo -e "${gl_ok}✅ tar 包完整性检查通过${gl_bai}"
                        
                        # 检查是否是 sysupgrade 备份
                        if tar -tzf "$selected_file" 2>/dev/null | grep -q "sysupgrade.tgz\|etc/backup/"; then
                            echo -e "${gl_ok}✅ 是有效的 sysupgrade 备份${gl_bai}"
                        else
                            echo -e "${gl_hong}⚠️ 不是标准的 sysupgrade 备份${gl_bai}"
                        fi
                        
                        # 显示文件数量
                        local file_count=$(tar -tzf "$selected_file" 2>/dev/null | wc -l)
                        echo -e "${gl_bai}备份包含 ${gl_huang}${file_count}${gl_bai} 个文件"
                    else
                        echo -e "${gl_hong}❌ 备份文件损坏或格式不正确${gl_bai}"
                    fi
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                else
                    log_error "无效的备份编号"
                    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                    break_end
                fi
                ;;
            *)
                log_error "无效的选择"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                ;;
        esac
    done
}

# URL系统恢复函数
# 用法: istoreos_restore_from_url [URL地址]
# 参数: URL地址(可选)，不传参则进入交互模式
istoreos_restore_from_url() {
    local backup_url
    local download_path="/tmp/url_backup.tar.gz"
    
    echo -e ""
    echo -e "${gl_zi}>>> 官方URL系统恢复${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 检查是否有参数传入
    if [ $# -gt 0 ]; then
        # 有参数传入，使用参数作为备份URL
        backup_url="$1"
        log_info "使用命令行参数指定的备份URL: ${gl_huang}${backup_url}${gl_bai}"
    else
        # 没有参数，进入交互式输入
        echo -e "${gl_lan}支持的URL格式:${gl_bai}"
        echo -e "  ${gl_hui}• http:// 或 https:// 开头的网络地址${gl_bai}"
        echo -e "  ${gl_hui}• 本地文件路径${gl_bai}"
        echo -e "  ${gl_lv}• http://10.10.10.251:5000/file/myfile/istoreos/backup/istoreos_backup/2026-03-23_03-14/backup.tar.gz${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        
        read -r -e -p "$(echo -e "${gl_bai}请输入备份文件URL或路径(${gl_huang}0${gl_bai}返回): ")" backup_url
        
        [ "$backup_url" = "0" ] && { cancel_return "上一级选单"; return 1; }    # break 或 continue 或 return ，视上下文而定
        
        if [ -z "$backup_url" ]; then
            log_error "未输入URL或路径"
            return 1
        fi
    fi
    
    # 判断是URL还是本地文件
    if [[ "$backup_url" =~ ^https?:// ]]; then
        # 网络URL下载
        log_info "正在从网络下载备份文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        log_info "URL: ${gl_huang}${backup_url}${gl_bai}"
        
        # 检查是否安装wget或curl
        if command -v wget >/dev/null 2>&1; then
            wget --show-progress -O "$download_path" "$backup_url"
        elif command -v curl >/dev/null 2>&1; then
            curl -L -o "$download_path" "$backup_url"
        else
            log_error "未找到wget或curl，请先安装其中任意一个下载工具"
            exit_animation    # 即将退出动画
            return 1
        fi
        
        if [ $? -ne 0 ]; then
            log_error "下载失败，请检查URL和网络连接"
            exit_animation    # 即将退出动画
            return 1
        fi
        
        log_ok "下载完成: ${gl_huang}${download_path}${gl_bai}"
        
    elif [ -f "$backup_url" ]; then
        # 本地文件
        download_path="$backup_url"
        log_info "使用本地文件: ${gl_huang}${download_path}${gl_bai}"
    else
        log_error "不是有效的URL或文件不存在: ${gl_huang}${backup_url}${gl_hong}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 检查下载的文件
    if [ ! -f "$download_path" ]; then
        log_error "备份文件不存在: ${gl_huang}${download_path}${gl_hong}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    if [ ! -s "$download_path" ]; then
        log_error "备份文件为空或损坏 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        log_error "请检查文件是否完整并重试 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        exit_animation    # 即将退出动画
        return 1
    fi
    
    # 显示文件信息
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    echo -e "${gl_lan}备份文件信息:${gl_bai}"
    ls -lh "$download_path"
    echo -e "${gl_bai}文件路径: ${gl_huang}${download_path}${gl_bai}"
    echo -e "${gl_bai}修改时间: ${gl_huang}$(stat -c "%y" "$download_path" 2>/dev/null | cut -d'.' -f1)${gl_bai}"
    
    # 检查是否是有效的 sysupgrade 备份
    if ! tar -tzf "$download_path" 2>/dev/null | grep -q "sysupgrade.tgz\|etc/backup/"; then
        echo -e "${gl_hong}警告: 备份文件可能不是 sysupgrade 格式${gl_bai}"
        echo -e "${gl_hui}此备份可能无法通过 sysupgrade 正确恢复${gl_bai}"
    else
        echo -e "${gl_ok}✅ 是有效的 sysupgrade 备份${gl_bai}"
    fi
    
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 选择恢复模式
    echo -e "${gl_lan}恢复模式选择:${gl_bai}"
    echo -e "${gl_bufan}1. ${gl_bai}标准恢复模式 (sysupgrade -r) - 推荐"
    echo -e "${gl_bufan}2. ${gl_bai}手动提取模式 (tar -xzf) - 兼容旧格式"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    read -r -e -p "$(echo -e "${gl_bai}请选择恢复模式(${gl_huang}1${gl_bai}): ")" restore_mode
    restore_mode="${restore_mode:-1}"
    
    # 确认恢复操作
    read -r -e -p "$(echo -e "${gl_bai}确认要使用此备份恢复系统吗? 此操作将覆盖当前系统配置(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
    
    case "$confirm" in
        [Yy])
            # 根据设备型号检查文件传输功能
            local model_info
            if [ -f /tmp/sysinfo/model ]; then
                model_info=$(cat /tmp/sysinfo/model)
                log_info "设备型号: ${gl_huang}${model_info}${gl_bai}"
                
                case "$model_info" in
                    *2500* | *3000* | *6000*)
                        log_info "检测到特定型号设备，检查文件传输功能 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                        istoreos_check_style_installed
                        ;;
                esac
            else
                log_warn "无法获取设备型号信息"
            fi
            
            # 执行恢复操作
            log_info "正在恢复系统 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            
            if [ "$restore_mode" = "1" ]; then
                # 使用 sysupgrade 标准恢复
                log_info "使用 sysupgrade 标准恢复模式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                echo -e "${gl_hui}正在执行: ${gl_huang}sysupgrade -r \"$download_path\"${gl_bai}"
                sysupgrade -r "$download_path"
                restore_result=$?
            else
                # 使用手动提取模式
                log_info "使用手动提取恢复模式 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                echo -e "${gl_hui}正在执行: ${gl_huang}tar -xzvf \"$download_path\" -C /${gl_bai}"
                tar -xzvf "$download_path" -C /
                restore_result=$?
            fi
            
            if [ $restore_result -eq 0 ]; then
                log_ok "✅ 恢复已完成"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                
                # 清理下载的临时文件
                if [[ "$backup_url" =~ ^https?:// ]] && [ "$download_path" != "$backup_url" ]; then
                    rm -f "$download_path"
                    log_info "已清理临时下载文件"
                fi
                
                # 确认重启
                read -r -e -p "$(echo -e "${gl_bai}立即重启系统以应用更改? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" reboot_confirm
                
                case "$reboot_confirm" in
                    [Yy])
                        log_info "系统正在重启 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                        sleep_fractional 2
                        reboot
                        ;;
                    [Nn])
                        log_ok "系统恢复完成，请手动重启以应用更改"
                        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                        break_end
                        ;;
                    *)
                        log_warn "无效输入，跳过重启操作"
                        ;;
                esac
            else
                log_error "恢复失败，请检查备份文件是否完整"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
                return 1
            fi
            ;;
        [Nn])
            log_info "已取消恢复操作"
            # 清理下载的临时文件
            if [[ "$backup_url" =~ ^https?:// ]] && [ "$download_path" != "$backup_url" ]; then
                rm -f "$download_path"
                log_info "已清理临时下载文件"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
            fi
            return 1
            ;;
        *)
            log_error "无效的选择，请输入 ${gl_bai}(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai})"
            # 清理下载的临时文件
            if [[ "$backup_url" =~ ^https?:// ]] && [ "$download_path" != "$backup_url" ]; then
                rm -f "$download_path"
                log_info "已清理临时下载文件"
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                break_end
            fi
            return 1
            ;;
    esac
}

# 菜单显示函数
# 用法: istoreos_backup_restore_menu
istoreos_backup_restore_menu() {
    while true; do
        is_istoreos_system || return 1  # 非iStoreOS系统退出
        clear
        local backup_dir="/mnt/backup/istoreos/istoreos_backup"

        # 创建备份目录（如果不存在）
        if [ ! -d "$backup_dir" ]; then
            mkdir -p "$backup_dir"
            chmod 755 "$backup_dir"
            cd "$backup_dir"
        fi

        # 查找所有备份文件
        backup_list=($(find "$backup_dir" -name "backup.tar.gz" -type f 2>/dev/null | sort -r))
        
        # 显示备份文件列表
        echo -e "${gl_huang}>>> 可用官方备份文件列表: ${gl_lv}${backup_dir}${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        if [ ${#backup_list[@]} -eq 0 ]; then
            log_error "未找到备份文件"
        else
            for i in "${!backup_list[@]}"; do
                local idx=$((i+1))
                local file="${backup_list[$i]}"
                local file_size=$(ls -lh "$file" 2>/dev/null | awk '{print $5}')
                local mod_time=$(stat -c "%y" "$file" 2>/dev/null | cut -d'.' -f1 2>/dev/null || echo "未知")
                
                echo -e "${gl_bufan}${idx}. ${gl_bai}$(basename $(dirname "$file"))/backup.tar.gz"
                echo -e "   ${gl_hui}大小: ${gl_huang}${file_size}${gl_hui} 修改时间: ${gl_huang}${mod_time}${gl_bai}"
            done
        fi
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e ""
        echo -e "${gl_zi}>>> 官方备份恢复工具${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}官方系统备份             ${gl_bufan}2.  ${gl_bai}官方系统恢复"
        echo -e "${gl_bufan}3.  ${gl_bai}管理官方备份文件         ${gl_bufan}4.  ${gl_bai}官方URL系统恢复"
        echo -e "${gl_bufan}5.  ${gl_bai}上传备份文件             ${gl_bufan}6.  ${gl_bai}下载备份文件"
        # echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        # echo -e "${gl_hui}备份格式: ${gl_huang}sysupgrade 官方格式${gl_bai}"
        # echo -e "${gl_hui}恢复方式: ${gl_huang}sysupgrade -r${gl_bai} 或 ${gl_huang}手动提取${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_huang}0.  ${gl_bai}返回上一级选单           ${gl_hong}00. ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "请输入你的选择: " choice
        
        case $choice in
            1) istoreos_backup_system ;;                                            # 官方系统备份
            2) istoreos_restore_system ;;                                           # 官方系统恢复
            3) istoreos_manage_backup_files ;;                                      # 管理官方备份文件
            4) istoreos_restore_from_url ;;                                         # 官方URL系统恢复
            5) cd "$backup_dir" && rz_upload_file; continue ;;                      # 上传备份文件
            6) cd "$backup_dir" && rz_download_files_to_local; continue ;;          # 下载备份文件
            0) cancel_return "iStoreOS 管理"; return 0 ;;                           # 返回上一级选单
            00|000|0000) exit_script ;;                                             # 退出脚本
            *) handle_invalid_input ;;
        esac
    done
}

###### 手动升级 iStoreOS 系统固件
# 传参：istoreos_system_update /mnt/backup
istoreos_system_update() {
    is_istoreos_system || return 1  # 非iStoreOS系统退出
    # 函数局部变量
    local firmware_url
    local firmware_path
    local download_path="/tmp"  # 默认下载路径
    
    # 检查是否有传入自定义路径参数
    if [ -n "$1" ] && [ -d "$1" ]; then
        download_path="$1"
        echo -e "${gl_lv}使用自定义下载路径: ${download_path}${gl_bai}"
    fi
    
    while true; do
        clear
        echo -e "${gl_zi}>>> iStoreOS 手动固件升级${gl_bai}"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 调用美化显示函数（显示全部信息：true ，显示基础信息：false）
        display_storage_info "$download_path" false

        echo ""
        # 1. 固件下载地址输入
        log_info "请输入固件下载地址（按回车使用默认地址：${gl_lv}https://fw20.koolcenter.com/iStoreOS/x86_64_efi/istoreos-24.10.5-2026032011-x86-64-squashfs-combined-efi.img.gz${gl_bai}）"
        read -r -e -p "$(echo -e "${gl_bai}请输入下载地址 (${gl_huang}0${gl_bai}返回): ")" firmware_url
        
        # 检查是否返回
        [ "$firmware_url" = "0" ] && { cancel_return "上一级选单"; break; }     # break 或 continue 或 return ，视上下文而定
        
        # 设置默认固件地址
        if [ -z "$firmware_url" ]; then
            firmware_url="https://fw20.koolcenter.com/iStoreOS/x86_64_efi/istoreos-24.10.5-2026032011-x86-64-squashfs-combined-efi.img.gz"
            echo -e "${gl_huang}使用默认固件地址: $firmware_url${gl_bai}"
        fi
        
        echo ""
        
        # 2. 切换到下载路径
        local current_dir="$(pwd)"
        cd "$download_path" || {
            echo -e "${gl_hong}错误: 无法进入下载路径 ${download_path}${gl_bai}"
            exit_animation    # 即将退出动画
            cd "$current_dir"
            break
        }
        
        # 3. 调用下载函数（修改下载函数以支持自定义路径）
        log_info "开始下载固件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if ! download_single "$firmware_url" "$download_path"; then
            log_error "固件下载失败，请检查网络连接和下载地址"
            echo ""
            echo -e "${gl_bai}是否重新下载? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): " -n
            read -r -n 1 -s redo
            echo ""
            
            cd "$current_dir"
            if [[ "$redo" =~ [Yy] ]]; then
                echo -e "${gl_bai}按任意键重新下载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                read -r -n 1 -s
                continue
            else
                echo -e "${gl_bai}按任意键返回 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                read -r -n 1 -s
                break
            fi
        fi
        
        # 4. 获取下载后的文件名
        firmware_path=""
        if [[ -f "downloaded_file" ]]; then
            firmware_path="${download_path}/downloaded_file"
        else
            # 尝试从URL提取文件名
            local raw_name=$(echo "$firmware_url" | sed 's/^.*\///' | sed 's/?.*$//')
            local filename=$(printf '%b' "${raw_name//%/\\x}" 2>/dev/null || echo "$raw_name")
            [[ -z "$filename" || "$filename" == "/" ]] && filename="downloaded_file"
            filename=$(echo "$filename" | tr -d '\000-\037' | tr '/' '_' | tr ':' '_' | tr '()[]{}<>' '_' | tr '*?&' '_')
            
            if [[ -f "$filename" ]]; then
                firmware_path="${download_path}/${filename}"
            else
                echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
                log_error "无法确定下载的固件文件位置"
                echo ""
                read -r -e -p "$(echo -e "${gl_bai}请输入下载的固件文件路径: ")" firmware_path
                if [[ ! -f "$firmware_path" ]]; then
                    log_error "指定的文件不存在: ${firmware_path}"
                    cd "$current_dir"
                    echo -e "${gl_bai}按任意键返回 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                    read -r -n 1 -s
                    break
                fi
            fi
        fi
        
        cd "$current_dir"  # 返回到原始目录
        
        echo ""
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lv}✓ 固件下载完成: ${gl_huang}$firmware_path${gl_bai}"
        
        # 5. 检查是否为 .img.gz 文件并进行解压
        local extracted_firmware=""
        if [[ "$firmware_path" == *.img.gz ]]; then
            echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
            log_info "检测到固件为 .img.gz 格式，是否需要解压? ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
            
            read -r -e -p "$(echo -e "${gl_bai}是否解压固件文件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" extract_confirm
            case "$extract_confirm" in
                [Yy])
                    echo -e "${gl_bai}开始解压固件文件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    
                    # 获取解压后的文件路径
                    local base_name=$(basename "${firmware_path%.gz}")
                    local output_dir=$(dirname "$firmware_path")
                    extracted_firmware="${output_dir}/${base_name}"
                    
                    # 检查目标文件是否已存在
                    if [[ -f "$extracted_firmware" ]]; then
                        read -r -e -p "$(echo -e "${gl_bai}解压文件 ${gl_huang}$extracted_firmware${gl_bai} 已存在，是否覆盖? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" overwrite_confirm
                        case "$overwrite_confirm" in
                            [Yy])
                                rm -f "$extracted_firmware"
                                echo -e "${gl_huang}已删除已存在的文件${gl_bai}"
                                ;;
                            *)
                                echo -e "${gl_huang}跳过解压操作，使用原始固件文件${gl_bai}"
                                extracted_firmware=""
                                ;;
                        esac
                    fi
                    
                    if [[ -n "$extracted_firmware" ]] && [[ ! -f "$extracted_firmware" ]]; then
                        # 调用解压函数
                        if extract_file "$firmware_path" "$output_dir" "true"; then
                            if [[ -f "$extracted_firmware" ]]; then
                                echo -e "${gl_lv}✓ 固件解压完成: ${gl_huang}$extracted_firmware${gl_bai}"
                                
                                # 询问是否删除原始压缩文件
                                read -r -e -p "$(echo -e "${gl_bai}是否删除原始压缩文件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" delete_gz_confirm
                                case "$delete_gz_confirm" in
                                    [Yy])
                                        rm -f "$firmware_path"
                                        echo -e "${gl_huang}已删除原始压缩文件${gl_bai}"
                                        firmware_path="$extracted_firmware"
                                        ;;
                                    [Nn]|"")
                                        echo -e "${gl_lv}保留原始压缩文件${gl_bai}"
                                        firmware_path="$extracted_firmware"  # 使用解压后的文件
                                        ;;
                                esac
                            else
                                echo -e "${gl_hong}解压文件未找到，继续使用原始固件文件${gl_bai}"
                            fi
                        else
                            echo -e "${gl_hong}固件解压失败，继续使用原始固件文件${gl_bai}"
                        fi
                    fi
                    ;;
                [Nn]|"")
                    echo -e "${gl_huang}跳过解压，使用原始固件文件${gl_bai}"
                    ;;
                *)
                    echo -e "${gl_huang}无效输入，跳过解压${gl_bai}"
                    ;;
            esac
        else
            echo -e "${gl_bai}固件格式: ${gl_huang}${firmware_path##*.}${gl_bai} (跳过解压步骤)"
        fi
        
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        echo -e "${gl_lv}✓ 准备就绪: ${gl_huang}$firmware_path${gl_bai}"
        
        # 6. 验证固件
        log_info "开始验证固件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        if ! sysupgrade -T "$firmware_path"; then
            log_error "固件验证失败，文件可能损坏或不兼容"
            echo ""
            read -r -e -p "$(echo -e "${gl_bai}是否删除固件并重新下载? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" redo_confirm
            case "$redo_confirm" in
                [Yy])
                    # 删除固件文件
                    rm -f "$firmware_path"
                    # 如果存在解压后的文件，也删除
                    if [[ -n "$extracted_firmware" ]] && [[ -f "$extracted_firmware" ]]; then
                        rm -f "$extracted_firmware"
                    fi
                    echo -e "${gl_bai}已删除损坏的固件 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                    echo -e "${gl_bai}按任意键重新下载 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                    read -r -n 1 -s
                    continue
                    ;;
                0) cancel_return "上一级选单"; break ;;
                *)
                    log_info "已保留固件文件: ${firmware_path}"
                    echo -e "${gl_bai}按任意键返回 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                    read -r -n 1 -s
                    break
                    ;;
            esac
        fi
        
        log_ok "固件验证通过"
        echo ""
        
        # 7. 确认升级
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
        read -r -e -p "$(echo -e "${gl_bai}固件验证完成，是否执行升级? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" upgrade_confirm
        case "$upgrade_confirm" in
            [Yy])
                log_warn "开始执行升级，系统将重启 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                echo -e "${gl_bai}升级中 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                sleep_fractional 2
                
                # 执行系统升级
                if ! sysupgrade "$firmware_path"; then
                    log_error "升级命令执行失败"
                    echo -e "${gl_bai}按任意键返回 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
                    read -r -n 1 -s
                else
                    # 如果升级命令成功执行，通常不会执行到这里
                    log_ok "升级命令已发送，系统即将重启 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
                fi
                break
                ;;
            [Nn]|"")
                log_info "已取消升级操作"
                echo ""
                read -r -e -p "$(echo -e "${gl_bai}是否删除已下载的固件? (${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" delete_confirm
                case "$delete_confirm" in
                    [Yy])
                        rm -f "$firmware_path"
                        # 如果存在解压后的文件，也删除
                        if [[ -n "$extracted_firmware" ]] && [[ -f "$extracted_firmware" ]]; then
                            rm -f "$extracted_firmware"
                        fi
                        log_ok "已删除固件文件"
                        ;;
                    [Nn]|"")
                        log_info "已保留固件文件: ${firmware_path}"
                        ;;
                    *) handle_y_n ;;        # 无效的输入,请输入(y或N)。
                esac
                ;;
            0) cancel_return "上一级选单"; break ;;
            *) handle_y_n; continue ;;
        esac
        
        echo ""
        echo -e "${gl_bai}按任意键返回 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai} \c"
        read -r -n 1 -s
        break
    done
}

###### 编辑计划任务
istoreos_configure_editor() {
    is_istoreos_system || return 1  # 非iStoreOS系统退出
    if ! grep -q "EDITOR=nano" ~/.bashrc; then
        echo 'export EDITOR=nano' >> ~/.bashrc
    fi
    source ~/.bashrc
    crontab -e
}

###### 删除计划任务
remove_crontab_confirm() {
    is_istoreos_system || return 1  # 非iStoreOS系统退出
    echo -e ""
    echo -e "${gl_zi}>>> 删除Crontab任务${gl_bai}"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    
    # 先显示当前任务
    if crontab -l 2>/dev/null; then
        
        read -r -e -p "$(echo -e "${gl_bai}确定要删除所有crontab任务吗？(${gl_lv}y${gl_bai}/${gl_hong}N${gl_bai}): ")" confirm
        
        case "$confirm" in
            [Yy])
                crontab -r
                log_ok "已删除所有crontab任务"
                ;;
            [Nn])
                log_warn "已取消删除操作"
                ;;
            0) cancel_return "上一级选单"; break ;;
            *) handle_y_n ;;        # 无效的输入,请输入(y或N)。
        esac
    else
        log_warn "当前用户没有crontab任务可删除"
    fi

    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}

