${gl_zi}|   ${gl_lan}|   ${gl_huang}|   ${gl_lv}|   ${gl_hong}|${gl_bai}\n\
${gl_zi}|   ${gl_lan}|   ${gl_huang}|   ${gl_lv}|   ${gl_hong}└── ${gl_hong}星期 (0-7, 0和7都代表周日)${gl_bai}\n\
${gl_zi}|   ${gl_lan}|   ${gl_huang}|   ${gl_lv}└────── ${gl_lv}月份 (1-12)${gl_bai}\n\
${gl_zi}|  ${gl_lan} |   ${gl_huang}└────────── ${gl_huang}日期 (1-31)${gl_bai}\n\
${gl_zi}|   ${gl_lan}└────────────── ${gl_lan}小时 (0-23)${gl_bai}\n\
${gl_zi}└────────────────── ${gl_zi}分钟 (0-59)${gl_bai}"
    echo -e ""
    echo -e "${gl_bai}时间格式: ${gl_lv}* * * * * command${gl_bai}"
    echo -e "${gl_bai}  分 时 日 月 周  ${gl_hong}* 表示所有值${gl_bai}"
    echo -e ""
    echo -e "${gl_bai}特殊字符:"
    echo -e "${gl_lv}  *${gl_bai} 所有值 ${gl_lv},${gl_bai} 列表分隔 ${gl_lv}-${gl_bai} 范围 ${gl_lv}/${gl_bai} 步长"
    echo -e ""
    echo -e "${gl_bai}示例:"
    echo -e "${gl_lv}  0 2 * * *${gl_bai} 每天凌晨2点执行"
    echo -e "${gl_lv}  */5 * * * *${gl_bai} 每5分钟执行"
    echo -e "${gl_lv}  0 8 * * 1${gl_bai} 每周一上午8点执行"
    echo -e ""
    echo -e "${gl_bai}常用命令:"
    echo -e "${gl_lv}  crontab -e${gl_bai} 编辑任务"
    echo -e "${gl_lv}  crontab -l${gl_bai} 列出任务"
    echo -e "${gl_lv}  crontab -r${gl_bai} 删除所有任务"
    echo -e "${gl_lv}  crontab -i${gl_bai} 交互式删除"
    echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"
    break_end
}


