        echo -e "${gl_bufan}11. ${gl_bai}iStoreOS查看PCI设备 ${gl_bufan}12. ${gl_bai}iStoreOS系统清理"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 3. 系统维护与高级功能
        echo -e "${gl_bufan}13. ${gl_bai}iStoreOS系统重置    ${gl_bufan}14. ${gl_bai}iStoreOS固件升级"
        echo -e "${gl_bufan}15. ${gl_bai}官方备份与恢复      ${gl_bufan}16. ${gl_bai}悟空备份与恢复"
        echo -e "${gl_bufan}17. ${gl_bai}iStoreOS文件管理    ${gl_bufan}18. ${gl_bai}OpenClash安装管理"
        echo -e "${gl_bufan}————————————————————————————————————————————————${gl_bai}"

        # 4. 计划任务管理
