        7)  istoreos_restart_network ;;                         # iStoreOS重启网络
        8)  istoreos_show_port ;;                               # iStoreOS查看端口
        9)  istoreos_show_logread ;;                            # iStoreOS系统日志
        10) print_disk_info ;;                                  # iStoreOS磁盘信息
        11) istoreos_show_lspci ;;                              # iStoreOS查看PCI设备
        12) istoreos_clean ;;                                   # iStoreOS系统清理
        13) istoreos_system_reset ;;                            # iStoreOS系统重置
        14) istoreos_system_update ;;                           # iStoreOS固件升级
        15) istoreos_backup_restore_menu ;;                     # 官方备份与恢复
        16) wukongdaily_backup_restore_menu ;;                  # 悟空备份与恢复
        17) is_istoreos_system || continue && linux_file "." "iStoreOS 文件管理" "iStoreOS 管理";; # iStoreOS文件管理
        18) OpenClash_menu ;;                                   # OpenClash安装管理
        19) istoreos_show_crontab ;;                            # 查看计划任务
        20) istoreos_configure_editor ;;                        # 编辑计划任务
        21) remove_crontab_confirm ;;                           # 删除计划任务
        22) show_crontab_help ;;                                # 查看计划任务帮助
        0)  cancel_return "主菜单"; break ;;                    # 返回上一级选单
        00) exit_script ;;                                      # 感谢使用，再见！
        *) handle_invalid_input ;;                              # 无效的输入,请重新输入!
        esac
    done
}


mobufan_sh() {
    while true; do
        clear
        echo -e "${gl_zi}>>> mobufan 脚本工具箱 ${gl_huang}v$sh_v${gl_bai}"
        echo -e "${gl_bufan}命令行输入${gl_huang}m${gl_bufan}快速启动脚本${gl_bai}"
        echo -e "${gl_bufan}命令行输入${gl_huang}m h${gl_bufan}快捷键说明${gl_bai}"
        echo -e "${gl_bufan}————————————————————————${gl_bai}"
        echo -e "${gl_bufan}1.  ${gl_bai}系统信息"
        echo -e "${gl_bufan}2.  ${gl_bai}系统更新"
        echo -e "${gl_bufan}3.  ${gl_bai}系统清理"
        echo -e "${gl_bufan}4.  ${gl_bai}基础工具"
        echo -e "${gl_bufan}5.  ${gl_bai}BBR 管理"
        echo -e "${gl_bufan}6.  ${gl_bai}容器管理"
        echo -e "${gl_bufan}7.  ${gl_bai}应用市场"
        echo -e "${gl_bufan}8.  ${gl_bai}系统工具"
        echo -e "${gl_bufan}9.  ${gl_bai}安全防御"
        echo -e "${gl_bufan}————————————————————————${gl_bai}"
        echo -e "${gl_huang}10. ${gl_bai}PVE 管理"
        echo -e "${gl_bufan}11. ${gl_bai}FnOS管理"
        echo -e "${gl_bufan}12. ${gl_bai}iStoreOS"
        echo -e "${gl_bufan}13. ${gl_bai}Web 管理"
        echo -e "${gl_bufan}14. ${gl_bai}Git 管理"
        echo -e "${gl_bufan}15. ${gl_bai}测试项目"
        echo -e "${gl_bufan}16. ${gl_bai}后台工作"
        echo -e "${gl_bufan}————————————————————————${gl_bai}"
        echo -e "${gl_lv}00. ${gl_bai}脚本更新"
        echo -e "${gl_hong}0.  ${gl_bai}退出脚本"
        echo -e "${gl_bufan}————————————————————————${gl_bai}"
        mobufan_sh_update
        read -r -e -p "请输入你的选择: " choice

        case $choice in
        1)  linux_info ;;                   # 系统信息
        2)  linux_update ;;                 # 系统更新
        3)  linux_clean ;;                  # 系统清理
        4)  linux_tools ;;                  # 基础工具
        5)  linux_bbr ;;                    # BBR 管理
        6)  linux_docker ;;                 # 容器管理
        7)  linux_panel ;;                  # 应用市场
        8)  linux_Settings ;;               # 系统工具
        9)  web_security "$@" ;;            # 安全防御
        10) linux_pve_menu "$@" ;;          # PVE 管理
        11) linux_fnos_menu ;;              # FnOS管理
        12) linux_istoreos_menu ;;          # iStoreOS
        13) linux_nginx_menu "$@" ;;        # Web 管理
        14) linux_git_menu ;;               # Git 管理
        15) temp_dir_menu "" "主菜单" ;;     # 测试项目
        16) linux_work ;;                   # 后台工作
        00) mobufan_update ;;               # 更新脚本
        66 | 666) update_mobufan_script ;;  # 立即更新脚本
        6666) update_mobufan_script ;;      # 立即更新脚本
        66666) update_mobufan_script ;;     # 立即更新脚本 
        666666) update_mobufan_script ;;    # 立即更新脚本
        0) exit_script ;;                   # 感谢使用，再见！
        *) handle_invalid_input ;;          # 无效的输入,请重新输入!
        esac
    done
}

