if [ "$#" -eq 0 ]; then
    # 如果没有参数，运行交互式逻辑
    mobufan_sh
else
    # 如果有参数，执行相应函数
    case $1 in
    install | add | 安装)
        shift
        install "$@"
        ;;
    查看安装)
        shift
        check_and_install "$@"
        ;;
    u | up)
        echo -e "${gl_bai}正在强制更新 ${gl_bufan}mobufan.sh${gl_bai} 脚本 ${gl_hong}.${gl_huang}.${gl_lv}.${gl_bai}"
        bash <(curl -fsSL https://gitee.com/meimolihan/sh/raw/master/install/mobufan.sh)
        ;;
    f | file | 文件管理)
        shift
        echo -e "${gl_bai}当前工作目录: ${gl_huang}$(pwd)${gl_bai}"
        linux_file "$@"
        ;;
    h | 说明)
        linux_m_info
        ;;
    qx | 文件权限)
        # 修改文件权限（非文件夹）
        file_chmod
        ;;
    ss | ssnr | 搜索)
        # 文件内容搜索（非文件夹）
        search_here "${@:2}"
        ;;
    fss | 文件搜索)
        # 文件搜索
        search_file_here "${@:2}"
        ;;
    zip | gz | rar)
        # 文件解压/压缩小工具
        clear
        compress_tool
        ;;
    sc | 删除 | 安全删除)
        interactive_delete
        ;;
    fnos | 飞牛)
        # FnOS容器
        # Compose容器管理
        clear
        cd /vol1/1000/compose
        if show_compose_project_menu; then
            :
        else
            break_end
        fi
        ;;
    git)
        linux_git_menu "${@:2}"
        ;;
    push | 推送)
        linux_git_menu 1
        ;;
    pull | 拉取)
        linux_git_menu 2
        ;;
    tool | 工具箱)
        linux_git_menu 3
        ;;
    gitee-ssh)
        linux_git_menu 4
        ;;
    gitgub-ssh)
        linux_git_menu 5
        ;;
    gitee-new)
        linux_git_menu 6
        ;;
    gitgub-new)
        linux_git_menu 7
        ;;
    fy | f2b | 安全防御)
        clear
        web_security "$@"
        ;;
    jy | 解压)
        clear
        interactive_extract
        ;;
    ys | 压缩)
        clear
        interactive_compress
        ;;
    xz | 下载)
        clear
        download_file "$2" # 只把第2个参数传进去，其余忽略
        # 用法: m xz [URL]  或直接  m xz 进入主菜单
        ;;
    remove | del | uninstall | 卸载)
        shift
        remove "$@"
        ;;
    update | 更新)
        linux_update
        ;;
    clean | 清理)
        linux_clean
        ;;
    dd | 重装)
        linux_dd_xitong
        ;;
    bbr3 | bbrv3)
        bbrv3
        ;;
    nhyh | 内核优化)
        linux_Kernel_optimize
        ;;
    trash | hsz | 回收站)
        manage_trash_menu
        ;;
    backup | bf | 备份)
        linux_backup
        ;;
    ssh | 远程连接)
        linux_ssh_manager
        ;;
    rsync | 远程同步)
        remote_rsync_manager
        ;;
    local_rsync_run)
        shift
        local_run_task "$@"
        ;;
    remote_rsync_run)
        shift
        run_task "$@"
        ;;
    disk | 硬盘管理)
        linux_disk_manager
        ;;
    wp | wordpress)
        shift
        ldnmp_wp "$@"
        ;;
    fd | rp | 反代)
        shift
        ldnmp_Proxy "$@"
        find_container_by_host_port "$port"
        if [ -z "$docker_name" ]; then
            close_port "$port"
            echo "已阻止IP+端口访问该服务"
        else
            ip_address
            block_container_port "$docker_name" "$ipv4_address"
        fi
        ;;
    loadbalance | 负载均衡)
        ldnmp_Proxy_backend
        ;;
    stream | L4负载均衡)
        ldnmp_Proxy_backend_stream
        ;;
    swap)
        shift
        add_swap "$@"
        ;;
    time | 时区)
        shift
        set_timedate "$@"
        ;;
    iptables_open)
        iptables_open
        ;;
    frps)
        frps_panel
        ;;
    frpc)
        frpc_panel
        ;;
    打开端口 | dkdk)
        shift
        open_port "$@"
        ;;
    关闭端口 | gbdk)
        shift
        close_port "$@"
        ;;
    放行IP | fxip)
        shift
        allow_ip "$@"
        ;;
    阻止IP | zzip)
        shift
        block_ip "$@"
        ;;
    防火墙 | fhq)
        linux_iptables_panel
        ;;
    命令收藏夹 | fav)
        linux_fav
        ;;
    status | 状态)
        shift
        status "$@"
        ;;
    start | 启动)
        shift
        start "$@"
        ;;
    stop | 停止)
        shift
        stop "$@"
        ;;
    restart | 重启)
        shift
        restart "$@"
        ;;
    enable | autostart | 开机启动)
        shift
        enable "$@"
        ;;
    ssl)
        shift
        if [ "$1" = "ps" ]; then
            ssl_ps
        elif [ -z "$1" ]; then
            add_ssl
        elif [ -n "$1" ]; then
            add_ssl "$1"
        else
            linux_m_info
        fi
        ;;
    docker)
        shift
        case $1 in
        install | 安装)
            install_docker
            ;;
        ps | 容器)
            docker_ps
            ;;
        img | 镜像)
            docker_image
            ;;
        *)
            linux_m_info
            ;;
        esac
        ;;
    urlload)
        shift
        clear
        docker_download_load "$@"
        ;;
    web)
        shift
        if [ "$1" = "cache" ]; then
            web_cache
        elif [ "$1" = "sec" ]; then
            web_security "$@"
        elif [ "$1" = "opt" ]; then
            web_optimization
        elif [ -z "$1" ]; then
            ldnmp_web_status
        else
            linux_m_info
        fi
        ;;
    app)
        shift
        linux_panel "$@"
        ;;
    sshkey)
        shift
        case "$1" in
        "")
            # SSHKey 交互菜单
            linux_sshkey_panel
            ;;
        github)
            shift
            # 从 GitHub 导入 SSH 公钥
            fetch_github_ssh_keys "$1"
            ;;
        http://* | https://*)
            # 从 URL 导入 SSH 公钥
            fetch_remote_ssh_keys "$1"
            ;;
        ssh-rsa* | ssh-ed25519* | ssh-ecdsa*)
            # 公钥直接导入
            import_sshkey "$1"
            ;;
        *)
            echo "错误：未知参数 '$1'"
            echo "用法："
            echo "  m sshkey                  进入交互菜单"
            echo "  m sshkey \"<pubkey>\"     直接导入 SSH 公钥"
            echo "  m sshkey <url>            从 URL 导入 SSH 公钥"
            echo "  m sshkey github <user>    从 GitHub 导入 SSH 公钥"
            ;;
        esac
        ;;
    info)
        linux_info
        ;;
    *)
        linux_m_info
        ;;
    esac
fi
